async def execute_tool(
    name: str,
    arguments: dict,
    container: AuditContainer,
    findings: list[dict],
    display=None,
) -> str:
    """Dispatch and execute a tool call. Always returns a string."""
    try:
        match name:
            case "inspect_scope":
                return await _inspect_scope(container, arguments)
            case "list_files":
                return await _list_files(container, arguments)
            case "read_file":
                return await _read_file(container, arguments)
            case "search_code":
                return await _search_code(container, arguments)
            case "source_slice":
                return await _source_slice(container, arguments)
            case "write_file":
                return await _write_file(container, arguments)
            case "request_toolset":
                return _request_toolset(arguments)
            case "read_campaign":
                return await _read_campaign(container, arguments)
            case "update_campaign":
                return await _update_campaign(container, arguments)
            case "review_campaign_progress":
                return await _review_campaign_progress(container, arguments)
            case "build_campaign_brief":
                return await _build_campaign_brief(container, arguments)
            case "attack_search":
                return await _attack_search(container, arguments)
            case "map_protocol_graph":
                return await _map_protocol_graph(container, arguments)
            case "map_live_reachability":
                return await _map_live_reachability(container, arguments)
            case "inventory_live_targets":
                return await _inventory_live_targets(container, arguments)
            case "build_attack_graph":
                return await _build_attack_graph(container, arguments)
            case "review_attack_surface_coverage":
                return await _review_attack_surface_coverage(container, arguments)
            case "plan_attack_campaign":
                return await _plan_attack_campaign(container, arguments)
            case "create_experiment":
                return await _create_experiment(container, arguments)
            case "prepare_fork_exploit_workbench":
                return await _prepare_fork_exploit_workbench(container, arguments)
            case "run_experiment":
                return await _run_experiment(container, arguments)
            case "run_sequence_minimization":
                return await _run_sequence_minimization(container, arguments)
            case "run_campaign_fuzz":
                return await _run_campaign_fuzz(container, arguments)
            case "diagnose_build":
                return await _diagnose_build(container, arguments)
            case "snapshot_state":
                return await _snapshot_state(container, arguments)
            case "compare_snapshots":
                return await _compare_snapshots(container, arguments)
            case "evaluate_objective":
                return await _evaluate_objective(container, arguments)
            case "record_fork_context":
                return await _record_fork_context(container, arguments)
            case "estimate_amm_economics":
                return await _estimate_amm_economics(container, arguments)
            case "estimate_flash_loan":
                return await _estimate_flash_loan(container, arguments)
            case "estimate_lending_health":
                return await _estimate_lending_health(container, arguments)
            case "summarize_trace":
                return await _summarize_trace(container, arguments)
            case "extract_call_sequence":
                return await _extract_call_sequence(container, arguments)
            case "map_action_space":
                return await _map_action_space(container, arguments)
            case "extract_state_transition_model":
                return await _extract_state_transition_model(container, arguments)
            case "compose_sequence_experiment":
                return await _compose_sequence_experiment(container, arguments)
            case "complete_sequence_experiment":
                return await _complete_sequence_experiment(container, arguments)
            case "repair_experiment":
                return await _repair_experiment(container, arguments)
            case "compose_invariant_harness":
                return await _compose_invariant_harness(container, arguments)
            case "synthesize_args":
                return await _synthesize_args(container, arguments)
            case "mutate_hypothesis":
                return await _mutate_hypothesis(container, arguments)
            case "run_command":
                return await _run_command(container, arguments)
            case "web_search":
                return await _web_search(arguments)
            case "fetch_url":
                return await _fetch_url(arguments)
            case "review_finding_evidence":
                return await _review_finding_evidence(container, arguments)
            case "review_report_quality":
                return await _review_report_quality(container, arguments)
            case "submit_finding":
                return await _submit_finding_checked(
                    container,
                    arguments,
                    findings,
                    display,
                )
            case (
                "trace_onchain_tx" | "simulate_call" | "state_diff"
                | "enumerate_callers" | "get_asset_transfers" | "get_token_prices"
                | "get_token_info" | "simulate_asset_changes" | "simulate_execution"
                | "simulate_sequence" | "get_contract_source" | "observed_tx_miner"
            ):
                # Host-side Alchemy/Etherscan tools: resolve+inject the target
                # chain (or short-circuit with a structured chain error) first.
                return await _dispatch_host_live_tool(name, container, arguments)
            case _:
                return f"Unknown tool: {name}"
    except Exception as e:
        # Structured, actionable failure so the model can self-correct in one
        # turn. Echo argument KEYS only (never values) to preserve probe/key
        # redaction; the exception message is generated by the tool, not an echo
        # of the arguments.
        return json.dumps({
            "error": "tool_failed",
            "tool": name,
            "error_type": type(e).__name__,
            "arg_keys": sorted(arguments) if isinstance(arguments, dict) else [],
            "message": str(e),
        }, indent=2, sort_keys=True)


def _request_toolset(args: dict) -> str:
    requested = str(args.get("toolset") or "").strip().lower()
    reason = str(args.get("reason") or "").strip()
    if requested not in {*REQUESTABLE_TOOLSETS, "all"}:
        return json.dumps({
            "error": (
                "unknown toolset; expected one of "
                + ", ".join([*REQUESTABLE_TOOLSETS, "all"])
            ),
            "requested_toolset": requested,
            "available_toolsets": list(REQUESTABLE_TOOLSETS) + ["all"],
        }, indent=2, sort_keys=True)
    activated = sorted(expand_toolsets({requested}) - {"core"})
    return json.dumps({
        "requested_toolset": requested,
        "activated_toolsets": activated,
        "available_tools": tool_names_for_toolsets({requested}),
        "reason": reason,
        "message": (
            "Toolset request accepted. The requested specialized tools will be "
            "available on the next turn."
        ),
    }, indent=2, sort_keys=True)


