def _compact_trace_value(value: object, *, depth: int = 0) -> object:
    if depth >= 3:
        return _truncate_response_text(value, 160)
    if isinstance(value, dict):
        compact = {}
        for key, item in value.items():
            if item in (None, "", [], {}):
                continue
            compact[str(key)] = _compact_trace_value(item, depth=depth + 1)
            if len(compact) >= 24:
                compact["omitted_keys"] = max(0, len(value) - 24)
                break
        return compact
    if isinstance(value, list):
        compact_items = [
            _compact_trace_value(item, depth=depth + 1)
            for item in value[:12]
        ]
        if len(value) > 12:
            compact_items.append({"omitted_items": len(value) - 12})
        return compact_items
    if isinstance(value, str):
        return _truncate_response_text(value, 240)
    if isinstance(value, (int, float, bool)) or value is None:
        return value
    return _truncate_response_text(value, 160)


async def _append_campaign_trace(
    container: AuditContainer,
    event: dict,
) -> None:
    entry = {
        "at": datetime.now(timezone.utc).isoformat(),
        **{
            str(key): _compact_trace_value(value)
            for key, value in event.items()
            if value not in (None, "", [], {})
        },
    }
    line = json.dumps(entry, sort_keys=True, separators=(",", ":"))
    try:
        raw = await container.read_file(_CAMPAIGN_TRACE_PATH)
    except FileNotFoundError:
        lines: list[str] = []
    else:
        lines = [item for item in raw.splitlines() if item.strip()]
    lines = lines[-(_CAMPAIGN_TRACE_MAX_EVENTS - 1):]
    lines.append(line)
    await container.write_file(_CAMPAIGN_TRACE_PATH, "\n".join(lines) + "\n")


def _coverage_gap_dedupe_key(item: dict) -> str:
    params = []
    for param in item.get("parameters") or []:
        if isinstance(param, dict):
            params.append(str(param.get("raw") or param.get("type") or param.get("name") or ""))
        else:
            params.append(str(param))
    signature = ",".join(part for part in params if part)
    return "|".join([
        _coverage_normalize_text(str(item.get("contract") or "")),
        _coverage_normalize_text(str(item.get("function") or "")),
        _coverage_normalize_text(signature),
        _coverage_normalize_text(_coverage_gap_action_key(item)),
    ])


async def _progress_coverage_gaps(
    container: AuditContainer,
    state: dict,
) -> list[dict]:
    gaps = []
    decided_action_keys = _campaign_decided_action_keys(state)
    for path in _progress_evidence_paths(
        state,
        "/workspace/campaign/coverage-reviews/",
    ):
        payload = await _load_campaign_json_if_exists(container, path)
        if not payload:
            continue
        summary = payload.get("summary") or {}
        high_gaps = int(summary.get("high_attention_gaps", 0) or 0)
        hypothesized = int(summary.get("hypothesized_not_experimented", 0) or 0)
        if not high_gaps and not hypothesized:
            continue
        stale_or_decided = 0
        duplicate_high_gaps = 0
        seen_gap_keys = set()
        filtered_high_gaps = []
        for item in payload.get("high_attention_gaps", []):
            if not isinstance(item, dict):
                continue
            action_key = _coverage_gap_action_key(item)
            if action_key and action_key in decided_action_keys:
                stale_or_decided += 1
                continue
            dedupe_key = _coverage_gap_dedupe_key(item)
            if dedupe_key and dedupe_key in seen_gap_keys:
                duplicate_high_gaps += 1
                continue
            if dedupe_key:
                seen_gap_keys.add(dedupe_key)
            filtered_high_gaps.append(item)
        filtered_high_gaps = sorted(
            filtered_high_gaps,
            key=lambda item: (
                -_coverage_gap_priority_score(item),
                _coverage_gap_action_key(item),
            ),
        )
        if not filtered_high_gaps and not hypothesized:
            continue
        compact_summary = dict(summary)
        compact_summary.update({
            "raw_high_attention_gaps": high_gaps,
            "high_attention_gaps": len(filtered_high_gaps),
            "stale_or_decided_high_attention_gaps": stale_or_decided,
            "duplicate_high_attention_gaps": duplicate_high_gaps,
        })
        gaps.append({
            "id": payload.get("id"),
            "title": payload.get("title"),
            "path": path,
            "action_space": payload.get("action_space"),
            "summary": compact_summary,
            "top_high_attention_gaps": [
                _compact_coverage_gap(item)
                for item in filtered_high_gaps[:5]
            ],
            "suggested_action": (
                "turn the strongest coverage gap into a hypothesis and a sequence "
                "experiment with explicit actions, use an invariant harness, or "
                "reject it with a decision"
            ),
        })
    return gaps


async def _progress_sequence_minimizations_without_review(
    container: AuditContainer,
    state: dict,
) -> list[dict]:
    reviewed = set()
    for path in _progress_evidence_paths(state, "/workspace/campaign/finding-reviews/"):
        payload = await _load_campaign_json_if_exists(container, path)
        if payload:
            reviewed.update(_reviewed_sequence_minimization_keys(payload))

    pending = []
    for path in _progress_evidence_paths(state, "/workspace/campaign/minimizations/"):
        normalized = posixpath.normpath(path)
        if (
            posixpath.dirname(normalized) != "/workspace/campaign/minimizations"
            or not normalized.endswith(".json")
        ):
            continue
        payload = await _load_campaign_json_if_exists(container, normalized)
        if not payload:
            continue
        try:
            summary = _sequence_minimization_evidence_summary(normalized, payload)
        except (TypeError, ValueError):
            continue
        minimization_id = str(summary.get("id") or "").strip()
        if minimization_id in reviewed or normalized in reviewed:
            continue
        if not summary.get("baseline_preserved"):
            continue
        if int(summary.get("preserved_variants", 0) or 0) <= 0:
            continue
        pending.append({
            "id": summary.get("id"),
            "title": payload.get("title"),
            "path": normalized,
            "sequence_id": summary.get("sequence_id"),
            "sequence_path": summary.get("sequence_path"),
            "summary": {
                "baseline_preserved": summary.get("baseline_preserved"),
                "preserved_variants": summary.get("preserved_variants"),
                "minimal_preserved_variant": summary.get("minimal_preserved_variant"),
                "best_variant_id": summary.get("best_variant_id"),
                "setup_checks_executed": summary.get("setup_checks_executed"),
                "setup_checks_retained": summary.get("setup_checks_retained"),
                "untested_plan_variants": summary.get("untested_plan_variants"),
                "unplanned_requested_variants": summary.get(
                    "unplanned_requested_variants"
                ),
                "retained_setup_assumptions": (
                    summary.get("retained_setup_assumptions") or []
                )[:6],
                "reduced_setup_assumptions": (
                    summary.get("reduced_setup_assumptions") or []
                )[:6],
            },
            "suggested_action": (
                "call review_finding_evidence with this sequence_minimization "
                "if the reduced replay supports a candidate finding, otherwise "
                "mutate or reject the hypothesis"
            ),
            "created_at": payload.get("created_at"),
            "related_ids": payload.get("related_ids") or [],
        })
    return sorted(
        pending,
        key=lambda item: str(item.get("created_at") or ""),
        reverse=True,
    )


_SEQUENCE_CONTEXT_BLOCKER_TERMS = (
    "missing_target_binding",
    "target binding",
    "missing deployment",
    "deployment context",
    "deployment metadata",
    "deployed address",
    "chain binding",
    "fork context",
    "live context",
    "source context",
    "no deployed",
)


def _sequence_quality_needs_context(experiment: dict, sequence_quality: dict) -> bool:
    del experiment
    text = re.sub(
        r"\s+",
        " ",
        json.dumps(sequence_quality, sort_keys=True, default=str),
    ).lower()
    if not text:
        return False
    return any(term in text for term in _SEQUENCE_CONTEXT_BLOCKER_TERMS)


def _progress_unrun_experiments(state: dict) -> list[dict]:
    items = []
    for experiment in state["sections"].get("experiment", []):
        if experiment.get("status", "open") not in {"open", "testing"}:
            continue
        experiment_id = str(experiment.get("id") or "")
        results = _entries_referencing(state, "result", experiment_id)
        sequence_quality = experiment.get("sequence_quality") or {}
        if (
            isinstance(sequence_quality, dict)
            and sequence_quality
            and (
                not sequence_quality.get("runnable")
                or sequence_quality.get("requires_manual_assertions")
            )
        ):
            proof_readiness = sequence_quality.get("proof_readiness")
            executable_calls = int(
                sequence_quality.get("executable_sequence_calls") or 0
            )
            context_blocked = _sequence_quality_needs_context(
                experiment,
                sequence_quality,
            )
            branch_status = "needs_concretization"
            if context_blocked:
                branch_status = "needs_context"
                suggested_action = (
                    "the scaffold is missing target, deployment, chain, or "
                    "source context rather than just calldata/probe detail: "
                    "use source_slice, record_fork_context, inventory_live_targets, "
                    "observed_tx_miner, or a parking/rejection decision before "
                    "complete_sequence_experiment"
                )
            elif proof_readiness == "partial" and executable_calls > 0:
                # An executable subset exists: a partial probe can test
                # preconditions now without waiting for full materialization.
                branch_status = "needs_partial_probe"
                suggested_action = (
                    "this branch has an executable subset: run a partial probe to "
                    "exercise preconditions only — complete_sequence_experiment "
                    "mode=partial_probe (or run_experiment run_kind=partial_probe "
                    "on the generated test_partial_probe_* test). A partial probe "
                    "is setup/precondition evidence only: it can guide mutation "
                    "but never validates impact and is not rejection evidence. "
                    "Then concretize the remaining steps and add an objective "
                    "assertion before claiming a finding"
                )
            elif proof_readiness == "partial":
                suggested_action = (
                    "no step is executable yet, but the path is not falsified: "
                    "synthesize concrete args (synthesize_args), pull a "
                    "source_slice/callback payload to bind the core calls, then "
                    "complete_sequence_experiment. If the harness cannot express "
                    "the path yet, park it with attack_search action=decision "
                    "decision_status=unproven_due_to_harness_limit rather than "
                    "treating it as rejection evidence"
                )
            elif proof_readiness == "blocked":
                suggested_action = (
                    "no useful core call is currently executable. Distinguish the "
                    "cause: if evidence falsifies the path, reject it with a "
                    "decision; if only the harness cannot express it yet (missing "
                    "calldata/signature/protocol setup), park it with attack_search "
                    "action=decision decision_status=unproven_due_to_harness_limit "
                    "and state what future tool/evidence would reopen it"
                )
            else:
                suggested_action = (
                    "complete concrete target bindings, typed calls, calldata, "
                    "and objective assertions before run_experiment"
                )
            items.append({
                **_entry_summary(experiment, section="experiment"),
                "status": branch_status,
                "suggested_action": suggested_action,
                "sequence_quality": {
                    "proof_readiness": proof_readiness,
                    "executable_sequence_calls": sequence_quality.get(
                        "executable_sequence_calls",
                    ),
                    "partial_sequence_calls": sequence_quality.get(
                        "partial_sequence_calls",
                    ),
                    "blocked_sequence_calls": sequence_quality.get(
                        "blocked_sequence_calls",
                    ),
                    "harness_limit_blockers": sequence_quality.get(
                        "harness_limit_blockers",
                    ) or [],
                    "non_executable_steps": sequence_quality.get(
                        "non_executable_steps",
                    ) or [],
                    "context_blocked": context_blocked,
                },
            })
            continue
        if any(result.get("status") in {"blocked", "inconclusive"} for result in results):
            continue
        objective_runs = [
            result for result in results
            if _attack_search_result_satisfies_experiment_run(result)
        ]
        if objective_runs:
            continue
        suggested_action = (
            "run the experiment with run_experiment or mark it blocked/rejected with a decision"
        )
        if results:
            kinds = sorted(dict.fromkeys(
                str((_attack_search_result_classification(result) or {}).get("run_kind") or "unknown")
                for result in results
            ))
            suggested_action = (
                "linked results are setup-only "
                f"({', '.join(kinds)}); run a harness/PoC/fuzz command or "
                "reject the experiment with a decision"
            )
        items.append({
            **_entry_summary(experiment, section="experiment"),
            "suggested_action": suggested_action,
        })
    return items


# Advisory tools (progress review, resume brief) surface process gaps and
# suggestions. They are not the scheduler: attack_search stays authoritative for
# the required next_action and branch transitions, so their model-visible output
# carries this note to keep planning signals from competing with the controller.
_CONTROLLER_AUTHORITY_NOTE = (
    "Advisory gaps and suggestions only. attack_search is authoritative for the "
    "required next_action and branch transitions; sync it before acting."
)


async def _review_campaign_progress(container: AuditContainer, args: dict) -> str:
    max_items = min(max(int(args.get("max_items", 25)), 1), 100)
    state = await _load_campaign_state(container)

    missing_foundation = _progress_missing_foundation(state)
    hypotheses_without_experiments = _progress_hypotheses_without_experiments(state)
    experiments_without_results = _progress_unrun_experiments(state)
    blocked_results = await _progress_blocked_results(container, state)
    failed_evaluations = await _progress_evaluations(container, state)
    sequence_minimizations_without_review = (
        await _progress_sequence_minimizations_without_review(container, state)
    )
    candidate_fuzz_failures = await _progress_candidate_fuzz_runs(container, state)
    action_spaces_without_coverage = await _progress_action_spaces_without_coverage(
        container,
        state,
    )
    coverage_high_attention_gaps = await _progress_coverage_gaps(container, state)
    latest_campaign_plans = await _progress_campaign_plans(container, state)
    ready_finding_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/finding-reviews/",
        kind="finding_evidence",
    )
    ready_report_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/report-reviews/",
        kind="report_quality",
    )

    review_id = _next_campaign_id(state, "progress_review")
    title = str(args.get("title") or "Campaign progress review").strip()
    review = {
        "id": review_id,
        "title": title,
        "focus": args.get("focus", ""),
        "created_at": datetime.now(timezone.utc).isoformat(),
        "counts": {
            section: len(state["sections"].get(section, []))
            for section in _CAMPAIGN_SECTIONS
        },
        "counters": state.get("counters", {}),
        "missing_foundation": missing_foundation[:max_items],
        "hypotheses_without_experiments": hypotheses_without_experiments[:max_items],
        "experiments_without_results": experiments_without_results[:max_items],
        "blocked_results_without_decisions": blocked_results[:max_items],
        "failed_evaluations": failed_evaluations[:max_items],
        "sequence_minimizations_without_review": (
            sequence_minimizations_without_review[:max_items]
        ),
        "candidate_fuzz_failures": candidate_fuzz_failures[:max_items],
        "action_spaces_without_coverage": action_spaces_without_coverage[:max_items],
        "coverage_high_attention_gaps": coverage_high_attention_gaps[:max_items],
        "latest_campaign_plans": latest_campaign_plans[:max_items],
        "ready_finding_reviews": ready_finding_reviews[:max_items],
        "ready_report_reviews": ready_report_reviews[:max_items],
        "open_questions": [
            _entry_summary(item, section="open_question")
            for item in state["sections"].get("open_question", [])
            if item.get("status", "open") in {"open", "blocked", "inconclusive"}
        ][:max_items],
    }
    review["next_actions"] = _progress_next_actions(review)
    review["summary"] = {
        "missing_foundation": len(missing_foundation),
        "hypotheses_without_experiments": len(hypotheses_without_experiments),
        "experiments_without_results": len(experiments_without_results),
        "blocked_results_without_decisions": len(blocked_results),
        "failed_evaluations": len(failed_evaluations),
        "sequence_minimizations_without_review": len(sequence_minimizations_without_review),
        "candidate_fuzz_failures": len(candidate_fuzz_failures),
        "action_spaces_without_coverage": len(action_spaces_without_coverage),
        "coverage_high_attention_gaps": len(coverage_high_attention_gaps),
        "latest_campaign_plans": len(latest_campaign_plans),
        "ready_finding_reviews": len(ready_finding_reviews),
        "ready_report_reviews": len(ready_report_reviews),
        "open_questions": len(review["open_questions"]),
    }

    review_path = f"/workspace/campaign/progress-reviews/{review_id}.json"
    await container.write_file(
        review_path,
        json.dumps(review, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Campaign progress review: {title}",
            content=(
                f"Progress review: {review_id}\n"
                f"Path: {review_path}\n"
                f"Missing foundation: {review['summary']['missing_foundation']}\n"
                "Hypotheses without experiments: "
                f"{review['summary']['hypotheses_without_experiments']}\n"
                f"Experiments without results: {review['summary']['experiments_without_results']}\n"
                f"Failed evaluations: {review['summary']['failed_evaluations']}\n"
                f"Candidate fuzz failures: {review['summary']['candidate_fuzz_failures']}\n"
                "Action spaces without coverage: "
                f"{review['summary']['action_spaces_without_coverage']}\n"
                "Coverage high-attention gaps: "
                f"{review['summary']['coverage_high_attention_gaps']}\n"
                f"Campaign plans: {review['summary']['latest_campaign_plans']}\n"
                f"Ready report reviews: {review['summary']['ready_report_reviews']}"
            ),
            evidence=[review_path],
            related_ids=[],
            status="observed",
        )

    await _append_campaign_trace(
        container,
        {
            "event": "progress_review",
            "review_id": review_id,
            "path": review_path,
            "result_id": result_id or None,
            "summary": review["summary"],
            "next_actions": review["next_actions"][:5],
        },
    )

    response = {
        "review_id": review_id,
        "path": review_path,
        "trace_path": _CAMPAIGN_TRACE_PATH,
        "result_id": result_id or None,
        "controller_note": _CONTROLLER_AUTHORITY_NOTE,
        "summary": review["summary"],
        "next_actions": review["next_actions"],
        "missing_foundation": review["missing_foundation"],
        "hypotheses_without_experiments": review["hypotheses_without_experiments"],
        "experiments_without_results": review["experiments_without_results"],
        "blocked_results_without_decisions": review["blocked_results_without_decisions"],
        "failed_evaluations": review["failed_evaluations"],
        "sequence_minimizations_without_review": review[
            "sequence_minimizations_without_review"
        ],
        "candidate_fuzz_failures": review["candidate_fuzz_failures"],
        "action_spaces_without_coverage": review["action_spaces_without_coverage"],
        "coverage_high_attention_gaps": review["coverage_high_attention_gaps"],
        "latest_campaign_plans": review["latest_campaign_plans"],
        "ready_finding_reviews": review["ready_finding_reviews"],
        "ready_report_reviews": review["ready_report_reviews"],
    }
    return json.dumps(response, indent=2, sort_keys=True)


async def _build_campaign_brief(container: AuditContainer, args: dict) -> str:
    max_items = min(max(int(args.get("max_items", 8)), 1), 30)
    state = await _load_campaign_state(container)

    missing_foundation = _progress_missing_foundation(state)
    hypotheses_without_experiments = _progress_hypotheses_without_experiments(state)
    experiments_without_results = _progress_unrun_experiments(state)
    blocked_results = await _progress_blocked_results(container, state)
    failed_evaluations = await _progress_evaluations(container, state)
    sequence_minimizations_without_review = (
        await _progress_sequence_minimizations_without_review(container, state)
    )
    candidate_fuzz_failures = await _progress_candidate_fuzz_runs(container, state)
    action_spaces_without_coverage = await _progress_action_spaces_without_coverage(
        container,
        state,
    )
    coverage_high_attention_gaps = await _progress_coverage_gaps(container, state)
    latest_campaign_plans = await _progress_campaign_plans(container, state)
    ready_finding_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/finding-reviews/",
        kind="finding_evidence",
    )
    ready_report_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/report-reviews/",
        kind="report_quality",
    )

    active_work = {
        "missing_foundation": missing_foundation[:max_items],
        "hypotheses_without_experiments": hypotheses_without_experiments[:max_items],
        "experiments_without_results": experiments_without_results[:max_items],
        "blocked_results_without_decisions": blocked_results[:max_items],
        "failed_evaluations": failed_evaluations[:max_items],
        "sequence_minimizations_without_review": (
            sequence_minimizations_without_review[:max_items]
        ),
        "candidate_fuzz_failures": candidate_fuzz_failures[:max_items],
        "action_spaces_without_coverage": action_spaces_without_coverage[:max_items],
        "coverage_high_attention_gaps": coverage_high_attention_gaps[:max_items],
    }
    progress_like = {
        **active_work,
        "latest_campaign_plans": latest_campaign_plans[:max_items],
        "ready_finding_reviews": ready_finding_reviews[:max_items],
        "ready_report_reviews": ready_report_reviews[:max_items],
    }
    progress_like["next_actions"] = _progress_next_actions(progress_like)

    brief_id = _next_campaign_id(state, "campaign_brief")
    title = str(args.get("title") or "Campaign resume brief").strip()
    brief_path = "/workspace/campaign/brief.json"
    markdown_path = "/workspace/campaign/brief.md"
    brief = {
        "id": brief_id,
        "title": title,
        "focus": str(args.get("focus") or "").strip(),
        "created_at": datetime.now(timezone.utc).isoformat(),
        "paths": {
            "json": brief_path,
            "markdown": markdown_path,
        },
        "counts": {
            section: len(state["sections"].get(section, []))
            for section in _CAMPAIGN_SECTIONS
        },
        "counters": state.get("counters", {}),
        "foundations": {
            "protocol_model": _brief_state_entries(
                state,
                "protocol_model",
                max_items=max_items,
            ),
            "trust_boundary": _brief_state_entries(
                state,
                "trust_boundary",
                max_items=max_items,
            ),
            "value_flow": _brief_state_entries(
                state,
                "value_flow",
                max_items=max_items,
            ),
            "invariant": _brief_state_entries(
                state,
                "invariant",
                max_items=max_items,
            ),
            "open_questions": _brief_state_entries(
                state,
                "open_question",
                statuses={"open", "blocked", "inconclusive"},
                max_items=max_items,
            ),
        },
        "active_work": active_work,
        "ready_to_submit": {
            "finding_reviews": ready_finding_reviews[:max_items],
            "report_reviews": ready_report_reviews[:max_items],
        },
        "latest_artifacts": {
            "plans": latest_campaign_plans[:max_items],
            "progress_reviews": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/progress-reviews/",
                max_items=max_items,
            ),
            "protocol_graphs": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/protocol-graphs/",
                max_items=max_items,
            ),
            "action_spaces": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/action-spaces/",
                max_items=max_items,
            ),
            "coverage_reviews": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/coverage-reviews/",
                max_items=max_items,
            ),
            "fork_contexts": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/fork-contexts/",
                max_items=max_items,
            ),
            "economics": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/economics/",
                max_items=max_items,
            ),
            "fuzz_runs": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/fuzz-runs/",
                max_items=max_items,
            ),
            "sequence_minimizations": await _brief_latest_artifacts(
                container,
                state,
                "/workspace/campaign/minimizations/",
                max_items=max_items,
            ),
        },
        "progress_next_actions": progress_like["next_actions"],
    }
    brief["suggested_next"] = _brief_suggest_next(brief)

    await container.write_file(
        brief_path,
        json.dumps(brief, indent=2, sort_keys=True) + "\n",
    )
    await container.write_file(markdown_path, _brief_markdown(brief))
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Campaign resume brief: {title}",
            content=(
                f"Campaign brief: {brief_id}\n"
                f"JSON: {brief_path}\n"
                f"Markdown: {markdown_path}\n"
                f"Suggested next tool: {brief['suggested_next']['tool']}\n"
                f"Rationale: {brief['suggested_next']['rationale']}"
            ),
            evidence=[brief_path, markdown_path],
            related_ids=[brief_id],
            status="observed",
        )

    response = {
        "brief_id": brief_id,
        "path": brief_path,
        "markdown_path": markdown_path,
        "result_id": result_id or None,
        "controller_note": _CONTROLLER_AUTHORITY_NOTE,
        "suggested_next": brief["suggested_next"],
        "summary": {
            "missing_foundation": len(missing_foundation),
            "hypotheses_without_experiments": len(hypotheses_without_experiments),
            "experiments_without_results": len(experiments_without_results),
            "failed_evaluations": len(failed_evaluations),
            "sequence_minimizations_without_review": (
                len(sequence_minimizations_without_review)
            ),
            "candidate_fuzz_failures": len(candidate_fuzz_failures),
            "coverage_high_attention_gaps": len(coverage_high_attention_gaps),
            "ready_report_reviews": len(ready_report_reviews),
            "plans": len(latest_campaign_plans),
        },
    }
    return json.dumps(response, indent=2, sort_keys=True)


# ── Deterministic attack-search controller ─────────────────────────────────


_ATTACK_SEARCH_DIR = "/workspace/campaign/attack-search"
_ATTACK_SEARCH_CURRENT_PATH = f"{_ATTACK_SEARCH_DIR}/current.json"
_ATTACK_SEARCH_STATUSES = {
    "needs_context",
    "needs_mapping",
    "needs_coverage",
    "needs_hypothesis",
    "needs_harness",
    "needs_inventory",
    "needs_concretization",
    "needs_partial_probe",
    "needs_run",
    "running",
    "needs_poc_repair",
    "blocked_compile",
    "blocked_revert",
    "blocked_setup",
    "needs_reduction",
    "needs_evidence",
    "objective_failed",
    "needs_mutation",
    "needs_finding_review",
    "needs_report_review",
    "ready_to_submit",
    "parked_harness_limit",
    "parked_low_roi",
    "parked_needs_dependency",
    "parked_needs_live_context",
    "unproven_due_to_harness_limit",
    "validated",
    "rejected",
    "superseded",
}
# Non-terminal "not worth current budget yet" statuses. These normally come from
# an explicit action=advance (the agent's scheduling judgment). The controller may
# also derive parked_needs_live_context for source-only/generic attack-graph
# branches after live reachability was attempted but still did not bind a deployed
# target. Parked branches sort below all active work, survive re-sync, record no
# decision, and supersede no sibling. The agent un-parks one with action=advance
# after resolving the missing context, or terminates it with action=decision.
_ATTACK_SEARCH_PARKED_STATUSES = {
    "parked_harness_limit",
    "parked_low_roi",
    "parked_needs_dependency",
    "parked_needs_live_context",
}
# Claim/evidence-adjacent statuses whose precedence stays strict: they are never
# reordered by the expected-value/proof-cost scheduler, so a finding that is
# close to submission always wins over exploration no matter how attractive the
# exploration looks.
_ATTACK_SEARCH_STRICT_STATUSES = {
    "ready_to_submit",
    "needs_report_review",
    "needs_finding_review",
    "needs_evidence",
    "needs_reduction",
}
_ATTACK_SEARCH_TERMINAL_STATUSES = {"validated", "rejected", "superseded"}
# unproven_due_to_harness_limit is intentionally NOT in the terminal set: a
# branch reaches it only through action=decision (which sets terminal_decision),
# so it is terminal-ish for the current search pass without ever being summarized
# as a validated/rejected outcome. parked_harness_limit is fully non-terminal.
_ATTACK_SEARCH_DECISION_STATUSES = {
    "rejected",
    "blocked",
    "blocked_setup",
    "blocked_compile",
    "blocked_revert",
    "objective_failed",
    "unproven_due_to_harness_limit",
    "superseded",
}
_ATTACK_SEARCH_POC_REPAIR_FAILURE_KINDS = frozenset({
    "timeout",
    "compile_error",
    "missing_or_invalid_binding",
    "fork_or_token_setup",
    "assertion_failure",
    "runtime_revert",
    "unclassified_blocked_run",
})
_OBJECTIVE_EVIDENCE_PREFIXES = (
    "/workspace/campaign/evaluations/",
    "/workspace/campaign/comparisons/",
    "/workspace/campaign/snapshots/",
    "/workspace/campaign/traces/",
    "/workspace/campaign/minimizations/",
    "/workspace/campaign/finding-reviews/",
    "/workspace/campaign/report-reviews/",
)
_ATTACK_SEARCH_STATUS_ORDER = {
    "ready_to_submit": 0,
    "needs_report_review": 1,
    "needs_finding_review": 2,
    "needs_evidence": 3,
    "needs_reduction": 4,
    "objective_failed": 5,
    "needs_mutation": 6,
    "blocked_revert": 7,
    "blocked_compile": 8,
    "blocked_setup": 9,
    "needs_poc_repair": 10,
    "needs_context": 11,
    "needs_mapping": 12,
    "needs_coverage": 13,
    "needs_inventory": 14,
    "needs_concretization": 15,
    "needs_partial_probe": 16,
    "needs_run": 17,
    "running": 18,
    "needs_hypothesis": 19,
    "needs_harness": 20,
    # Parked statuses sort below every active proof status so they never
    # monopolize the loop, but stay above terminal validated/rejected work. The
    # tiered sort key (parked tier) is what actually pins them below active work;
    # these ranks only order parked branches among themselves and order the
    # terminal tier.
    "parked_harness_limit": 21,
    "parked_low_roi": 22,
    "parked_needs_dependency": 23,
    "parked_needs_live_context": 24,
    "unproven_due_to_harness_limit": 25,
    "validated": 90,
    "rejected": 91,
    "superseded": 92,
}
_ATTACK_SEARCH_PRIORITY_ORDER = {
    "critical": 0,
    "high": 1,
    "medium": 2,
    "low": 3,
}
_ATTACK_SEARCH_MODES = {"discover", "validate", "exploit_hypothesis"}


def _attack_search_store(state: dict) -> dict:
    store = state.setdefault("attack_search", {})
    store.setdefault("search_counter", 0)
    store.setdefault("history", [])
    return store


def _attack_search_new_id(store: dict) -> str:
    store["search_counter"] = int(store.get("search_counter", 0) or 0) + 1
    return f"search-{store['search_counter']:03d}"


def _attack_search_next_branch_id(search: dict) -> str:
    search["branch_counter"] = int(search.get("branch_counter", 0) or 0) + 1
    return f"br-{search['branch_counter']:03d}"


def _attack_search_current(
    state: dict,
    args: dict,
    *,
    reset: bool,
) -> dict:
    store = _attack_search_store(state)
    current = store.get("current")
    if reset or not isinstance(current, dict):
        search_id = _attack_search_new_id(store)
        now = datetime.now(timezone.utc).isoformat()
        mode = str(args.get("mode") or "discover").strip()
        if mode not in _ATTACK_SEARCH_MODES:
            mode = "discover"
        current = {
            "id": search_id,
            "schema_version": 1,
            "title": str(args.get("title") or "Attack search").strip(),
            "mode": mode,
            "focus": str(args.get("focus") or "").strip(),
            "created_at": now,
            "updated_at": now,
            "branch_counter": 0,
            "selected_branch_id": "",
            "branches": [],
            "summary": {},
            "next_action": {},
            "paths": {
                "current": _ATTACK_SEARCH_CURRENT_PATH,
                "history": f"{_ATTACK_SEARCH_DIR}/{search_id}.json",
            },
            "rules": {
                "outer_loop": (
                    "State -> Map -> Plan -> Experiment -> Evidence -> "
                    "Mutate or Report"
                ),
                "submission_gate": (
                    "High and critical findings require objective or minimized "
                    "replay evidence plus ready evidence/report reviews."
                ),
                "branch_policy": (
                    "Each nonterminal branch has exactly one required next tool "
                    "family. Do not report a branch while it is still in "
                    "needs_context, needs_harness, needs_inventory, "
                    "needs_concretization, needs_partial_probe, needs_poc_repair, "
                    "needs_run, a parked_* status, or needs_evidence. A partial "
                    "probe is setup/precondition evidence only; PoC repair is "
                    "mechanical blocker work, not exploit evidence; parking "
                    "(parked_harness_"
                    "limit, parked_low_roi, parked_needs_dependency, "
                    "parked_needs_live_context) preserves a plausible branch "
                    "below active work without rejecting it."
                ),
            },
        }
        store["current"] = current
    else:
        if args.get("title"):
            current["title"] = str(args.get("title") or "").strip()
        if args.get("focus") is not None:
            current["focus"] = str(args.get("focus") or "").strip()
        if args.get("mode") in _ATTACK_SEARCH_MODES:
            current["mode"] = str(args.get("mode"))
    return current


def _attack_search_priority(priority: object) -> str:
    value = str(priority or "medium").strip().lower()
    return value if value in _CAMPAIGN_PRIORITIES else "medium"


def _attack_search_status(status: object, fallback: str = "needs_context") -> str:
    value = str(status or fallback).strip().lower()
    return value if value in _ATTACK_SEARCH_STATUSES else fallback


def _attack_search_branch_terminal(branch: dict) -> bool:
    return (
        branch.get("status") in _ATTACK_SEARCH_TERMINAL_STATUSES
        or bool(branch.get("terminal_decision"))
    )


def _attack_search_candidate(
    *,
    key: str,
    source: str,
    title: str,
    status: str,
    next_tool: str,
    required_toolsets: list[str],
    priority: str = "medium",
    priority_score: int = 0,
    source_ids: list[str] | None = None,
    source_artifacts: list[str] | None = None,
    related_ids: list[str] | None = None,
    evidence: list[str] | None = None,
    instructions: str = "",
    required_evidence: list[str] | None = None,
    stop_condition: str = "",
    action_keys: list[str] | None = None,
    action_family_keys: list[str] | None = None,
    clone_family_keys: list[str] | None = None,
    attack_keys: list[str] | None = None,
    target_binding: dict | None = None,
    inventory_context: dict | None = None,
    target_actions: list[dict] | None = None,
    normalized_target_keys: list[str] | None = None,
    root_mechanism: str = "",
    invariant_id: str | None = None,
    invariant_kind: str | None = None,
    invariant_statement: str | None = None,
    state_transition_model: str | None = None,
    generic_invariant: bool = False,
    parking_reason: str | None = None,
    recommended_budget: str | None = None,
    required_args: dict | None = None,
    readiness: dict | None = None,
    failure_diagnosis: dict | None = None,
) -> dict:
    candidate = {
        "key": key,
        "source": source,
        "title": title,
        "status": _attack_search_status(status),
        "priority": _attack_search_priority(priority),
        "priority_score": priority_score,
        "next_tool": next_tool,
        "required_toolsets": sorted(dict.fromkeys(required_toolsets)),
        "source_ids": [str(item) for item in (source_ids or []) if item],
        "source_artifacts": [str(item) for item in (source_artifacts or []) if item],
        "related_ids": [str(item) for item in (related_ids or []) if item],
        "evidence": [str(item) for item in (evidence or []) if item],
        "instructions": instructions,
        "required_evidence": [
            str(item) for item in (required_evidence or []) if str(item).strip()
        ],
        "stop_condition": stop_condition,
    }
    if action_keys:
        candidate["action_keys"] = [
            str(item) for item in action_keys if str(item).strip()
        ]
    if action_family_keys:
        candidate["action_family_keys"] = [
            str(item) for item in action_family_keys if str(item).strip()
        ]
    if clone_family_keys:
        candidate["clone_family_keys"] = [
            str(item) for item in clone_family_keys if str(item).strip()
        ]
    if attack_keys:
        candidate["attack_keys"] = [
            str(item) for item in attack_keys if str(item).strip()
        ]
    if target_binding:
        candidate["target_binding"] = target_binding
    if inventory_context:
        candidate["inventory_context"] = inventory_context
    if target_actions:
        candidate["target_actions"] = target_actions
    if normalized_target_keys:
        candidate["normalized_target_keys"] = [
            str(item) for item in normalized_target_keys if str(item).strip()
        ]
    if root_mechanism:
        candidate["root_mechanism"] = root_mechanism
    # State-transition-model (generic invariant) annotations. They ride on the
    # candidate so _attack_search_merge_candidates' branch.update carries them
    # to the branch, where _attack_search_branch_state_model_fields surfaces
    # them in the compact branch, next_action, and durable dossier.
    if generic_invariant:
        candidate["generic_invariant"] = True
    if invariant_id:
        candidate["invariant_id"] = str(invariant_id)
    if invariant_kind:
        candidate["invariant_kind"] = str(invariant_kind)
    if invariant_statement:
        candidate["invariant_statement"] = str(invariant_statement)
    if state_transition_model:
        candidate["state_transition_model"] = str(state_transition_model)
    if parking_reason:
        candidate["parking_reason"] = str(parking_reason)
    if recommended_budget:
        candidate["recommended_budget"] = str(recommended_budget)
    if required_args:
        candidate["required_args"] = required_args
    if readiness:
        candidate["readiness"] = readiness
    if failure_diagnosis:
        candidate["failure_diagnosis"] = failure_diagnosis
    return candidate


def _attack_candidate_inventory_targets(candidate: dict, *, limit: int = 20) -> list[dict]:
    targets = []
    seen = set()

    def add(
        *,
        label: object,
        contract: object = "",
        address: object = "",
        kind: str = "candidate",
        selectors: list[str] | None = None,
    ) -> None:
        normalized = _solidity_address_literal(address)
        if not normalized:
            return
        key = normalized.lower()
        if key in seen:
            return
        seen.add(key)
        targets.append({
            "label": str(label or contract or f"target_{len(targets) + 1}").strip(),
            "contract": str(contract or label or "").strip() or None,
            "kind": kind,
            "address": normalized,
            "selectors": [
                str(selector)
                for selector in (selectors or [])
                if selector is not None and str(selector).strip()
            ][:20],
        })

    add(
        label=candidate.get("contract") or "candidate",
        contract=candidate.get("contract"),
        address=candidate.get("target_address"),
        kind=str(candidate.get("candidate_kind") or "candidate"),
        selectors=[str(candidate.get("signature") or "")],
    )
    for action in candidate.get("actions") or []:
        if not isinstance(action, dict):
            continue
        add(
            label=action.get("contract") or action.get("action_key") or "action",
            contract=action.get("contract"),
            address=action.get("target") or action.get("target_address"),
            kind="action",
            selectors=[_action_signature(action)],
        )
    market_inventory = candidate.get("market_inventory") or {}
    if isinstance(market_inventory, dict):
        for key in ("collateral_market", "borrow_market", "controller"):
            value = market_inventory.get(key)
            add(
                label=key,
                contract=key,
                address=value,
                kind="market_inventory",
            )
        for index, market in enumerate(market_inventory.get("candidate_markets") or [], start=1):
            if not isinstance(market, dict):
                continue
            add(
                label=market.get("contract") or f"candidate_market_{index}",
                contract=market.get("contract"),
                address=market.get("address"),
                kind="candidate_market",
            )
    return targets[:limit]


async def _live_inventory_entries_by_address(
    container: AuditContainer,
    paths: list[str],
    *,
    limit: int = 12,
) -> dict[str, list[dict]]:
    entries: dict[str, list[dict]] = {}
    for path in paths[-limit:]:
        payload = await _load_campaign_json_if_exists(container, path)
        if not payload:
            continue
        for target in payload.get("targets") or []:
            if not isinstance(target, dict):
                continue
            address = _solidity_address_literal(target.get("address"))
            if not address:
                continue
            entry = dict(target)
            entry["inventory_path"] = path
            entry["inventory_id"] = payload.get("id")
            entries.setdefault(address.lower(), []).append(entry)
    return entries


def _inventory_target_label(target: dict) -> str:
    return str(
        target.get("label")
        or target.get("contract")
        or target.get("kind")
        or target.get("address")
        or "target"
    ).strip()


def _inventory_context_score(binding: dict, values: dict, probe: dict) -> int:
    kind = str(binding.get("kind") or "")
    score = {
        "active_proxy": 8,
        "deployed_economic_contract": 7,
        "deployed_configured_contract": 4,
        "deployed_contract": 2,
        "deployed_implementation_or_template": -10,
        "no_code": -16,
        "unknown_code": -6,
        "unprobed": 0,
    }.get(kind, 0)
    economic_keys = _nonzero_probe_keys(
        values,
        (
            "native_balance",
            "total_supply",
            "total_assets",
            "get_cash",
            "total_borrows",
            "total_reserves",
        ),
    )
    score += min(6, len(economic_keys) * 2)
    if probe.get("rpc_available") is False:
        score -= 2
    return score


def _candidate_inventory_context(
    candidate: dict,
    inventory_targets: list[dict],
    inventory_entries: dict[str, list[dict]],
) -> dict:
    if not inventory_targets:
        return {}
    matched = []
    missing = []
    hard_blockers = []
    soft_blockers = []
    score_delta = 0
    paths = []
    economically_significant = 0
    recommended_call_targets = []
    related_live_targets = []
    for target in inventory_targets:
        if not isinstance(target, dict):
            continue
        address = _solidity_address_literal(target.get("address"))
        if not address:
            continue
        entries = inventory_entries.get(address.lower()) or []
        if not entries:
            missing.append({
                "label": _inventory_target_label(target),
                "address": address,
            })
            continue
        entry = entries[-1]
        probe = entry.get("probe") or {}
        values = probe.get("values") or {}
        binding = entry.get("target_binding") or _live_target_binding(
            probe,
            target=entry,
        )
        kind = str(binding.get("kind") or "")
        if binding.get("economically_significant_hint"):
            economically_significant += 1
        recommended = _solidity_address_literal(binding.get("recommended_call_target"))
        if recommended:
            recommended_call_targets.append({
                "from": address,
                "to": recommended,
                "label": _inventory_target_label(target),
                "reason": binding.get("normalization_reason"),
            })
        for related in binding.get("related_live_targets") or []:
            if not isinstance(related, dict):
                continue
            related_address = _solidity_address_literal(related.get("address"))
            if not related_address:
                continue
            related_live_targets.append({
                "from": address,
                "to": related_address,
                "relation": related.get("relation"),
                "source": related.get("source"),
                "audit_relevance": related.get("audit_relevance"),
            })
        score_delta += _inventory_context_score(binding, values, probe)
        path = str(entry.get("inventory_path") or "")
        if path and path not in paths:
            paths.append(path)
        compact = {
            "label": _inventory_target_label(target),
            "address": address,
            "kind": target.get("kind"),
            "contract": target.get("contract"),
            "inventory_id": entry.get("inventory_id"),
            "inventory_path": path,
            "target_binding": binding,
            "recommended_call_target": recommended or None,
            "code_present": probe.get("code_present"),
            "rpc_available": probe.get("rpc_available"),
            "values": _compact_inventory_values(values),
        }
        matched.append({
            key: value for key, value in compact.items()
            if value not in (None, "", [], {})
        })
        if kind in {"no_code", "deployed_implementation_or_template"}:
            hard_blockers.append({
                "label": _inventory_target_label(target),
                "address": address,
                "target_binding": kind,
            })
        elif kind == "unknown_code" or probe.get("rpc_available") is False:
            soft_blockers.append({
                "label": _inventory_target_label(target),
                "address": address,
                "target_binding": kind or "unknown",
            })
    if not matched and not missing:
        return {}
    return {
        "score_delta": score_delta,
        "matched_targets": matched[:8],
        "missing_targets": missing[:8],
        "hard_blockers": hard_blockers[:8],
        "soft_blockers": soft_blockers[:8],
        "recommended_call_targets": recommended_call_targets[:8],
        "related_live_targets": related_live_targets[:12],
        "economically_significant_targets": economically_significant,
        "inventory_paths": paths[:8],
        "summary": {
            "targets": len(inventory_targets),
            "matched": len(matched),
            "missing": len(missing),
            "hard_blockers": len(hard_blockers),
            "soft_blockers": len(soft_blockers),
            "recommended_call_targets": len(recommended_call_targets),
            "related_live_targets": len(related_live_targets),
            "score_delta": score_delta,
        },
    }


def _inventory_context_instruction(context: dict) -> str:
    if not context:
        return ""
    if context.get("hard_blockers"):
        blockers = "; ".join(
            f"{item.get('label')}={item.get('target_binding')}"
            for item in context.get("hard_blockers") or []
        )
        related = context.get("recommended_call_targets") or []
        mutation_note = ""
        if related:
            mutation_note = (
                " A related live call target was discovered; mutate/rebind to "
                f"{related[0].get('to')} instead of repeating sibling actions "
                "against the blocked address."
            )
        return (
            "Latest live inventory currently blocks this target "
            f"({blockers}). Record an attack_search decision or mutate to a "
            "different deployed target unless there is specific evidence that "
            "the inventory binding is wrong."
            f"{mutation_note}"
        )
    if context.get("economically_significant_targets"):
        return (
            "Latest live inventory confirms economically significant deployed "
            "target state; bind these values into the fork setup and objective."
        )
    if context.get("soft_blockers"):
        return (
            "Latest live inventory has unresolved code/RPC uncertainty; refresh "
            "or manually confirm live binding before spending on a fork harness."
        )
    return ""


def _inventory_targets_satisfied(
    targets: list[dict],
    inventory_addresses: set[str],
) -> bool:
    required = {
        str(target.get("address") or "").strip().lower()
        for target in targets
        if _solidity_address_literal(target.get("address"))
    }
    return bool(required) and required.issubset(inventory_addresses)


def _candidate_alias_actions(
    candidate: dict,
    *,
    original_address: str,
    alias_address: str,
) -> list[dict]:
    aliased = []
    original_key = original_address.lower()
    for action in candidate.get("actions") or []:
        if not isinstance(action, dict):
            continue
        copied = dict(action)
        for field in ("target", "target_address", "address"):
            value = _solidity_address_literal(copied.get(field))
            if value and value.lower() == original_key:
                copied[field] = alias_address
        copied["normalized_from_target"] = original_address
        copied["normalized_call_target"] = alias_address
        aliased.append(copied)
    return aliased


def _candidate_alias_inventory_target(
    candidate: dict,
    related: dict,
    *,
    index: int,
) -> dict:
    address = _solidity_address_literal(related.get("to") or related.get("address"))
    label = str(
        related.get("relation")
        or related.get("audit_relevance")
        or f"related_target_{index}"
    ).strip()
    contract = str(candidate.get("contract") or label).strip()
    return {
        "label": f"{contract} {label}".strip(),
        "contract": contract,
        "kind": str(related.get("relation") or "related_live_target"),
        "address": address,
        "selectors": [str(candidate.get("signature") or "")],
    }


def _infer_experiment_run_kind(
    *,
    command: str,
    output: str,
    sequence_payload: dict | None = None,
) -> str:
    text = f"{command}\n{output}".lower()
    command_text = command.lower()
    if re.search(r"\bforge\s+build\b", command_text) or re.search(
        r"\b(solc|npm|yarn|pnpm)\s+(build|compile)\b",
        command_text,
    ):
        return "build"
    if any(
        token in command_text
        for token in (
            "slither",
            "mythril",
            "semgrep",
            "solhint",
            "forge inspect",
            "forge tree",
            "forge selectors",
        )
    ):
        return "static_analysis"
    stripped = command_text.strip()
    if stripped.startswith((
        "rg ",
        "grep ",
        "find ",
        "ls ",
        "cat ",
        "sed ",
        "awk ",
        "jq ",
    )):
        return "inventory"
    if re.search(r"\bcast\s+(call|storage|balance|code|chain-id|block|logs)\b", command_text):
        return "live_config_probe"
    if any(token in command_text for token in ("echidna", "medusa")):
        return "fuzz_run"
    # A generated partial-probe test only exercises preconditions and the
    # executable subset (the objective assertion is withheld), so it is setup
    # evidence even though it runs through forge test against a sequence payload.
    # Classify it before the forge-test/sequence-payload branch so a probe run is
    # never mistaken for an objective poc_run.
    if "test_partial_probe" in command_text:
        return "partial_probe"
    if "forge test" in command_text:
        if any(token in text for token in ("invariant", "--fuzz", "fuzz_runs", "counterexample")):
            return "fuzz_run"
        if sequence_payload:
            return "poc_run"
        return "harness_run"
    if sequence_payload:
        return "poc_run"
    if any(token in text for token in ("[pass]", "suite result:", "test result:")):
        return "harness_run"
    return "setup_probe"


def _command_invokes_forge_test(command: str) -> bool:
    return bool(re.search(r"(?:^|\s)forge\s+test(?:\s|$)", command.lower()))


def _forge_test_executed_tests(output: str) -> bool:
    text = output or ""
    if re.search(r"(?im)^\s*(?:\[PASS\]|\[FAIL\]|PASS\s+test\w*|FAIL\s+test\w*)\b", text):
        return True
    if re.search(r"(?i)\b(?:suite|test)\s+result\s*:", text):
        return True
    if re.search(r"(?i)\bRan\s+[1-9]\d*\s+tests?\b", text):
        return True
    if re.search(r"(?i)\b[1-9]\d*\s+passed\b", text):
        return True
    if re.search(r"(?i)\b[1-9]\d*\s+failed\b", text):
        return True
    return False


def _forge_test_completed_without_tests(command: str, output: str) -> bool:
    return _command_invokes_forge_test(command) and not _forge_test_executed_tests(output)


def _classify_experiment_run(
    *,
    command: str,
    output: str,
    exit_code: int,
    explicit_run_kind: str = "auto",
    sequence_payload: dict | None = None,
) -> dict:
    requested = str(explicit_run_kind or "auto").strip().lower()
    run_kind = (
        _infer_experiment_run_kind(
            command=command,
            output=output,
            sequence_payload=sequence_payload,
        )
        if requested == "auto"
        else requested
    )
    if exit_code != 0:
        evidence_grade = "blocked"
        satisfies_experiment_run = False
        requires_objective_reduction = False
        reason = "command did not complete successfully"
    elif _forge_test_completed_without_tests(command, output):
        evidence_grade = "blocked"
        satisfies_experiment_run = False
        requires_objective_reduction = False
        reason = (
            "forge test completed with exit code 0 but did not execute any tests; "
            "fix the match path/profile/workspace before treating it as evidence"
        )
    elif run_kind in _EXPERIMENT_SETUP_RUN_KINDS:
        evidence_grade = "setup"
        satisfies_experiment_run = False
        requires_objective_reduction = False
        reason = (
            "setup/build/static/config evidence is useful context but does not "
            "execute an exploit or invariant objective"
        )
    elif run_kind in _EXPERIMENT_OBJECTIVE_RUN_KINDS:
        evidence_grade = "objective_candidate"
        satisfies_experiment_run = True
        requires_objective_reduction = True
        reason = (
            "harness/PoC/fuzz execution can support the branch only after "
            "objective deltas, trace, or minimized replay evidence are reduced"
        )
    else:
        evidence_grade = "setup"
        satisfies_experiment_run = False
        requires_objective_reduction = False
        reason = "unrecognized successful command is treated as setup evidence"
    classification = {
        "run_kind": run_kind,
        "evidence_grade": evidence_grade,
        "requires_objective_reduction": requires_objective_reduction,
        "satisfies_experiment_run": satisfies_experiment_run,
        "reason": reason,
    }
    # Carry the executed sequence's objective-probe strength so the evidence
    # gates can tell a generic_probe delta guard (after != before) apart from a
    # real objective assertion. Only meaningful for a run tied to a sequence
    # payload; absent otherwise.
    if isinstance(sequence_payload, dict):
        objective_probe = sequence_payload.get("objective_probe")
        if isinstance(objective_probe, dict):
            probe_strength = str(objective_probe.get("strength") or "").strip()
            if probe_strength:
                classification["probe_strength"] = probe_strength
    return classification


def _parse_result_command(content: str) -> str:
    for line in content.splitlines():
        if line.startswith("Command:"):
            return line.split(":", 1)[1].strip()
    return ""


def _parse_result_exit_code(content: str, status: str) -> int:
    match = re.search(r"^Exit code:\s*(-?\d+)\s*$", content, re.MULTILINE)
    if match:
        return int(match.group(1))
    if re.search(r"^Outcome:\s*completed with exit code 0\s*$", content, re.MULTILINE):
        return 0
    return 1 if status in {"blocked", "inconclusive"} else 0


def _attack_search_result_classification(result: dict) -> dict:
    classification = result.get("run_classification")
    if isinstance(classification, dict) and classification.get("run_kind"):
        return classification
    content = str(result.get("content") or "")
    command = _parse_result_command(content)
    return _classify_experiment_run(
        command=command,
        output=content,
        exit_code=_parse_result_exit_code(content, str(result.get("status") or "")),
        explicit_run_kind="auto",
        sequence_payload=None,
    )


def _attack_search_result_satisfies_experiment_run(result: dict) -> bool:
    if any(path.startswith(_OBJECTIVE_EVIDENCE_PREFIXES) for path in _entry_evidence(result)):
        return True
    return bool(
        _attack_search_result_classification(result).get("satisfies_experiment_run")
    )


def _attack_search_result_is_experiment_run(result: dict) -> bool:
    related_ids = _entry_related_ids(result)
    if any(item.startswith("exp-") for item in related_ids):
        return _attack_search_result_satisfies_experiment_run(result)
    evidence = _entry_evidence(result)
    content = str(result.get("content") or "")
    if any(path.startswith("/workspace/campaign/results/") for path in evidence):
        return (
            content.startswith("Command:")
            and "Log:" in content
            and _attack_search_result_satisfies_experiment_run(result)
        )
    return False


def _attack_graph_candidate_experiments(
    state: dict,
    candidate: dict,
) -> list[dict]:
    tokens = [
        str(candidate.get("candidate_id") or "").strip(),
        str(candidate.get("attack_key") or "").strip(),
    ]
    tokens = [token for token in tokens if token]
    if not tokens and candidate.get("action_key"):
        tokens = [str(candidate.get("action_key")).strip()]
    if not tokens:
        return []
    matches = []
    for experiment in state["sections"].get("experiment", []):
        if _entry_is_fork_workbench(experiment):
            continue
        haystack = "\n".join([
            str(experiment.get("title") or ""),
            str(experiment.get("content") or ""),
            " ".join(_entry_related_ids(experiment)),
            " ".join(str(item) for item in experiment.get("attack_keys") or []),
            *(_entry_evidence(experiment)),
        ])
        if any(token in haystack for token in tokens):
            matches.append(experiment)
    return matches


def _entry_is_fork_workbench(entry: dict) -> bool:
    content = str(entry.get("content") or "")
    if "Template: fork_workbench" in content:
        return True
    return any(
        str(path).startswith("/workspace/campaign/fork-workbenches/")
        for path in _entry_evidence(entry)
    )


def _attack_graph_candidate_workbenches(
    state: dict,
    candidate: dict,
) -> list[dict]:
    tokens = [
        str(candidate.get("candidate_id") or "").strip(),
        str(candidate.get("attack_key") or "").strip(),
    ]
    tokens = [token for token in tokens if token]
    if not tokens:
        return []
    matches = []
    for experiment in state["sections"].get("experiment", []):
        if not _entry_is_fork_workbench(experiment):
            continue
        haystack = "\n".join([
            str(experiment.get("title") or ""),
            str(experiment.get("content") or ""),
            " ".join(_entry_related_ids(experiment)),
            " ".join(str(item) for item in experiment.get("attack_keys") or []),
            " ".join(str(item) for item in experiment.get("action_keys") or []),
            *(_entry_evidence(experiment)),
        ])
        if any(token in haystack for token in tokens):
            matches.append(experiment)
    return matches


def _attack_candidate_action_keys(candidate: dict) -> list[str]:
    keys = []
    if candidate.get("action_key"):
        keys.append(str(candidate.get("action_key")))
    for action in candidate.get("actions") or []:
        if not isinstance(action, dict):
            continue
        action_key = str(action.get("action_key") or "").strip()
        if not action_key:
            contract = str(action.get("contract") or "").strip()
            function = str(action.get("function") or "").strip()
            if contract and function:
                action_key = f"{contract}::{function}"
        if action_key:
            keys.append(action_key)
    return sorted(dict.fromkeys(keys))


async def _workbench_compose_args_from_entry(
    container: AuditContainer,
    entry: dict | None,
) -> dict:
    if not entry:
        return {}
    candidate_paths = [
        path for path in _entry_evidence(entry)
        if (
            path.startswith("/workspace/campaign/fork-workbenches/")
            and path.endswith("/workbench.json")
        )
    ]
    if not candidate_paths:
        match = re.search(
            r"^Workbench:\s*(/workspace/campaign/fork-workbenches/[^\s]+/workbench\.json)\s*$",
            str(entry.get("content") or ""),
            flags=re.MULTILINE,
        )
        if match:
            candidate_paths.append(match.group(1))
    for path in candidate_paths:
        payload = await _load_campaign_json_if_exists(container, path)
        if not isinstance(payload, dict):
            continue
        compose_args = payload.get("compose_sequence_experiment_args") or {}
        if isinstance(compose_args, dict):
            return compose_args
    return {}


def _attack_search_has_objective_evidence(state: dict, result: dict) -> bool:
    result_id = str(result.get("id") or "")
    related_ids = set(_entry_related_ids(result))
    related_ids.add(result_id)
    for path in _entry_evidence(result):
        if path.startswith(_OBJECTIVE_EVIDENCE_PREFIXES):
            return True
    for entry in state["sections"].get("result", []):
        if entry is result:
            continue
        entry_refs = set(_entry_related_ids(entry))
        text = "\n".join([
            str(entry.get("content") or ""),
            *(_entry_evidence(entry)),
        ])
        if not related_ids.intersection(entry_refs) and not any(
            item and item in text for item in related_ids
        ):
            continue
        if any(path.startswith(_OBJECTIVE_EVIDENCE_PREFIXES) for path in _entry_evidence(entry)):
            return True
    return False


def _attack_search_results_without_objective(state: dict) -> list[dict]:
    missing = []
    for result in state["sections"].get("result", []):
        status = str(result.get("status") or "")
        if status not in {"observed", "testing"}:
            continue
        if not _attack_search_result_is_experiment_run(result):
            continue
        classification = _attack_search_result_classification(result)
        if not classification.get("requires_objective_reduction"):
            continue
        if _attack_search_has_objective_evidence(state, result):
            continue
        missing.append({
            **_entry_summary(result, section="result"),
            "evidence": _entry_evidence(result),
            "related_ids": _entry_related_ids(result),
            "run_classification": classification,
            "suggested_action": (
                "summarize the trace/log, snapshot before and after state, "
                "compare snapshots, and evaluate the objective before treating "
                "the run as validated evidence"
            ),
        })
    return missing


def _action_space_invalid_for_attack_search(action_space: dict | None) -> bool:
    if not isinstance(action_space, dict):
        return False
    if action_space.get("status") == "invalid_empty_source":
        return True
    source = action_space.get("source") or {}
    try:
        requested = int(source.get("files_requested", 0) or 0)
        scanned = int(source.get("files_scanned", 0) or 0)
    except (TypeError, ValueError):
        return False
    return requested > 0 and scanned == 0


# Cap on curiosity/diversity frontier branches surfaced per attack_search run.
# Kept small (1-3) so the queue is nudged, never flooded: the frontier preserves
# many low-label branches in the artifact, but only a handful are promoted to
# live exploratory branches at a time.
_ATTACK_SEARCH_FRONTIER_BRANCH_CAP = 3


def _attack_search_frontier_branch_from_entry(
    entry: dict,
    *,
    attack_graph_id: str,
    attack_graph_path: str,
    live_context_unbound: bool = False,
) -> dict:
    """Build one exploratory frontier branch from a preserved attack-graph
    frontier entry.

    Frontier branches are curiosity leads, not findings: their status routes the
    agent to gather the missing context (live reachability, inspection, or a
    workbench) and then either form a concrete hypothesis or record a decision.
    The downstream submission gates still require a runnable fork PoC plus live
    exposure before any high/critical claim, so a frontier branch can never
    short-circuit into a finding.
    """
    attack_key = str(entry.get("attack_key") or "").strip()
    action_key = str(entry.get("action_key") or "").strip()
    contract = entry.get("contract")
    function = entry.get("function")
    affordances = [str(item) for item in entry.get("affordances") or []]
    structural = bool(
        set(affordances)
        & (_ATTACK_GRAPH_STATE_MUTATOR_AFFORDANCES | _ATTACK_GRAPH_BOUNDARY_AFFORDANCES)
    )
    blockers = [str(item) for item in entry.get("blockers") or []]
    exposure = str(entry.get("exposure") or "").strip().lower()
    has_live_blocker = exposure == "source_only" or any(
        ("live" in blocker.lower() or "target address" in blocker.lower())
        for blocker in blockers
    )
    # Status by blocker. Before live mapping, a branch that still needs live
    # reachability / target binding routes through needs_mapping. After an empty
    # live-reachability artifact, park it instead of burning turns on repeated
    # mapping/blocked decisions.
    if has_live_blocker and live_context_unbound:
        status, next_tool, toolsets = (
            "parked_needs_live_context",
            "record_fork_context or update_campaign",
            ["core"],
        )
        gather = (
            "Record deployment/fork context or mutate to a concretely bound "
            "branch before harness work; otherwise "
        )
    elif has_live_blocker:
        status, next_tool, toolsets = "needs_mapping", "map_live_reachability", ["map"]
        gather = "Map live reachability for it and bind a deployed target, then "
    elif structural:
        status, next_tool, toolsets = (
            "needs_harness",
            "prepare_fork_exploit_workbench",
            ["experiment"],
        )
        gather = "Prepare a fork workbench against the bound target, then "
    else:
        status, next_tool, toolsets = (
            "needs_context",
            "inspect_scope then update_campaign",
            ["core"],
        )
        gather = "Inspect the action and its callers, then "
    # Priority stays medium/low so a curiosity lead never outranks real work on
    # priority alone; the diversity bonus does the (bounded) lifting instead.
    priority = "medium" if structural else "low"
    target_action = {
        key: value
        for key, value in {
            "key": action_key or (
                f"{contract}::{function}" if contract and function else None
            ),
            "action_key": action_key or None,
            "contract": contract,
            "function": function,
            "affordances": affordances,
            "direction_hint": entry.get("direction_hint"),
        }.items()
        if value not in (None, "", [], {})
    }
    candidate = _attack_search_candidate(
        key=f"frontier:{attack_key or action_key or entry.get('title') or 'unlabeled'}",
        source=_ATTACK_SEARCH_FRONTIER_SOURCE,
        title=str(
            entry.get("title")
            or f"Frontier lead: {action_key or contract or 'unlabeled action'}"
        ),
        status=status,
        next_tool=next_tool,
        required_toolsets=toolsets,
        priority=priority,
        # Keep raw expected value low; the capped diversity bonus is what keeps a
        # frontier branch competitive among exploratory work.
        priority_score=2,
        source_ids=[
            item
            for item in (attack_graph_id, entry.get("candidate_id"), action_key)
            if item
        ],
        source_artifacts=[attack_graph_path],
        instructions=(
            "Exploratory frontier branch: the attack-graph frontier preserved this "
            "low-label / unlabeled action that the economic ranking did not surface. "
            f"{gather}either record a concrete hypothesis (update_campaign) or a "
            "decision explaining why it is not viable. It is a planning lead, not a "
            "finding."
        ),
        required_evidence=[
            "live reachability / target binding or inspection notes for the action",
            "a recorded hypothesis or decision (frontier branch is exploratory "
            "context, not a finding)",
        ],
        stop_condition=(
            "Frontier/curiosity branch is exploratory only: never submit a finding "
            "from it without live exposure and objective replay evidence. Convert it "
            "into a concrete hypothesis or record a decision."
        ),
        action_keys=[action_key] if action_key else [],
        attack_keys=[attack_key] if attack_key else [],
        target_actions=[target_action] if target_action else [],
        root_mechanism=str(entry.get("mechanism") or ""),
        invariant_id=entry.get("invariant_id"),
        state_transition_model=entry.get("state_transition_model"),
        generic_invariant=bool(
            entry.get("candidate_kind") == "generic_invariant"
            or entry.get("mechanism") == "generic_state_transition"
        ),
        parking_reason=(
            "live reachability did not bind a deployed target address"
            if status == "parked_needs_live_context" else None
        ),
        recommended_budget=(
            "revisit after deployment metadata, chain binding, or fork context"
            if status == "parked_needs_live_context" else None
        ),
    )
    candidate["frontier_source"] = {
        key: value
        for key, value in {
            "attack_graph_id": attack_graph_id,
            "attack_graph_path": attack_graph_path,
            "frontier_reason": entry.get("frontier_reason"),
            "attack_key": attack_key or None,
            "candidate_kind": entry.get("candidate_kind"),
        }.items()
        if value not in (None, "", [], {})
    }
    if exposure:
        candidate["exposure"] = exposure
    return candidate


def _attack_search_frontier_candidates(
    latest_attack_graph: dict | None,
    attack_graph_path: str,
    *,
    existing_attack_keys: set[str],
    decided_attack_keys: set[str],
    live_context_unbound: bool = False,
    cap: int = _ATTACK_SEARCH_FRONTIER_BRANCH_CAP,
) -> list[dict]:
    """Promote a small, capped number of preserved attack-graph frontier entries
    into exploratory branches.

    Only the reason buckets (``omitted_by_score`` / ``omitted_by_truncation``)
    hold full entries; the semantic buckets hold compact references, so they are
    used only to *rank* which full entries are most novelty-critical (unlabeled
    state mutators / unusual external boundaries first). Entries already
    represented by a live candidate or already decided are skipped.
    """
    frontier = (latest_attack_graph or {}).get("frontier")
    if not isinstance(frontier, dict) or not frontier:
        return []
    attack_graph_id = str((latest_attack_graph or {}).get("id") or "")

    novelty_critical_keys: set[str] = set()
    for bucket in ("unlabeled_state_mutators", "unusual_external_boundaries"):
        for reference in frontier.get(bucket) or []:
            if isinstance(reference, dict) and reference.get("attack_key"):
                novelty_critical_keys.add(str(reference["attack_key"]))

    full_entries: list[dict] = []
    seen: set[str] = set()
    for bucket in ("omitted_by_score", "omitted_by_truncation"):
        for entry in frontier.get(bucket) or []:
            if not isinstance(entry, dict):
                continue
            attack_key = str(entry.get("attack_key") or "").strip()
            dedupe = (
                attack_key
                or str(entry.get("action_key") or "").strip()
                or str(entry.get("title") or "").strip()
            )
            if not dedupe or dedupe in seen:
                continue
            if attack_key and (
                attack_key in existing_attack_keys or attack_key in decided_attack_keys
            ):
                continue
            seen.add(dedupe)
            full_entries.append(entry)
    if not full_entries:
        return []

    def rank(entry: dict) -> tuple[int, int, int, str]:
        attack_key = str(entry.get("attack_key") or "")
        affordances = {str(item) for item in entry.get("affordances") or []}
        structural = bool(
            affordances
            & (
                _ATTACK_GRAPH_STATE_MUTATOR_AFFORDANCES
                | _ATTACK_GRAPH_BOUNDARY_AFFORDANCES
            )
        )
        try:
            priority_score = int(entry.get("priority_score") or 0)
        except (TypeError, ValueError):
            priority_score = 0
        # Novelty-critical first, then structural, then the most-omitted (lowest
        # score), then a stable tiebreak so selection is deterministic.
        return (
            0 if attack_key in novelty_critical_keys else 1,
            0 if structural else 1,
            priority_score,
            attack_key or str(entry.get("action_key") or ""),
        )

    full_entries.sort(key=rank)
    return [
        _attack_search_frontier_branch_from_entry(
            entry,
            attack_graph_id=attack_graph_id,
            attack_graph_path=attack_graph_path,
            live_context_unbound=live_context_unbound,
        )
        for entry in full_entries[: max(0, cap)]
    ]


def _live_reachability_has_deployed_context(live_reachability: dict | None) -> bool:
    """True only when reachability mapped an actual deployed/exposed target."""
    if not isinstance(live_reachability, dict):
        return False
    summary = live_reachability.get("summary")
    if isinstance(summary, dict):
        for key in (
            "exposed_actions",
            "live_deployed_profiles",
            "code_present",
            "profiles_with_actions",
            "source_artifact_actions",
        ):
            try:
                if int(summary.get(key) or 0) > 0:
                    return True
            except (TypeError, ValueError):
                continue
        bindings = summary.get("target_bindings")
        if isinstance(bindings, dict) and bindings:
            return True
    for key in ("actions", "exposures", "profiles"):
        values = live_reachability.get(key)
        if not isinstance(values, list):
            continue
        for item in values:
            if not isinstance(item, dict):
                continue
            if item.get("target_address") or item.get("address"):
                return True
            exposure = str(item.get("exposure") or "").strip()
            live_status = str(item.get("live_status") or "").strip()
            if exposure in {"exposed", "source_public_live_unknown"} and live_status in {
                "",
                "deployed",
            }:
                return True
    return False


def _attack_graph_candidate_needs_live_context(candidate: dict, actions: list) -> bool:
    """True when a candidate still lacks target/live binding and must not be
    materialized as a fork sequence yet."""
    if candidate.get("target_address") or candidate.get("target_binding"):
        return False
    reachability = str(candidate.get("reachability") or "").strip().lower()
    exposure = str(candidate.get("exposure") or "").strip().lower()
    blockers = [str(item).lower() for item in candidate.get("blockers") or []]
    if reachability == "needs_live_context" or exposure == "source_only":
        return True
    if any("live" in blocker or "target address" in blocker for blocker in blockers):
        return True
    for action in actions if isinstance(actions, list) else []:
        if not isinstance(action, dict):
            continue
        if action.get("target") or action.get("target_address"):
            continue
        action_exposure = str(action.get("live_exposure") or "").strip().lower()
        action_status = str(action.get("live_status") or "").strip().lower()
        action_blockers = [
            str(item).lower() for item in action.get("live_blockers") or []
        ]
        if action_exposure == "source_only" or action_status in {
            "unprobed",
            "needs_live_context",
        }:
            return True
        if any("live" in blocker or "target address" in blocker for blocker in action_blockers):
            return True
    return False


async def _attack_search_candidates(
    container: AuditContainer,
    state: dict,
    *,
    focus: str,
) -> list[dict]:
    candidates: dict[str, dict] = {}

    def add(candidate: dict) -> None:
        candidates.setdefault(candidate["key"], candidate)

    missing_foundation = _progress_missing_foundation(state)
    if missing_foundation:
        sections = ", ".join(item["section"] for item in missing_foundation)
        add(_attack_search_candidate(
            key="foundation:missing",
            source="missing_foundation",
            title=f"Record missing campaign foundation: {sections}",
            status="needs_context",
            next_tool="update_campaign",
            required_toolsets=["core"],
            priority="high",
            priority_score=20,
            instructions=(
                "Record the missing protocol model, value flow/trust boundary, "
                "and invariant/open-question artifacts before deeper exploit "
                "search. Record a hypothesis only if it is concrete and "
                "evidence-backed."
            ),
            required_evidence=[
                "campaign artifacts with concrete source references",
                "at least one invariant tied to fund loss/state lock, or an open question blocking that invariant",
            ],
            stop_condition="Continue only after the missing foundation artifacts exist.",
        ))
        return list(candidates.values())

    protocol_graph_paths = _progress_evidence_paths(
        state,
        "/workspace/campaign/protocol-graphs/",
    )
    action_space_paths = _progress_evidence_paths(
        state,
        "/workspace/campaign/action-spaces/",
    )
    latest_action_space = (
        await _load_campaign_json_if_exists(container, action_space_paths[-1])
        if action_space_paths else None
    )
    if _action_space_invalid_for_attack_search(latest_action_space):
        source = latest_action_space.get("source") or {}
        add(_attack_search_candidate(
            key=f"repair:action_space:{latest_action_space.get('id') or action_space_paths[-1]}",
            source="invalid_action_space",
            title="Repair invalid action-space source map",
            status="needs_mapping",
            next_tool="map_action_space",
            required_toolsets=["map"],
            priority="high",
            priority_score=21,
            source_ids=[latest_action_space.get("id")],
            source_artifacts=[action_space_paths[-1]],
            instructions=(
                "The latest action-space artifact scanned zero readable source "
                "files. Re-run map_action_space with corrected source root or "
                "file paths before live reachability, attack graph, coverage, "
                "or harness work."
            ),
            required_evidence=[
                "a replacement /workspace/campaign/action-spaces/*.json with files_scanned > 0",
            ],
            stop_condition="Do not proceed to reachability or harnessing from an empty action grammar.",
            required_args={
                "map_action_space": {
                    "path": source.get("path") or "/audit",
                    "include_tests": bool(source.get("include_tests", False)),
                },
            },
        ))
        return list(candidates.values())
    if not protocol_graph_paths:
        add(_attack_search_candidate(
            key="map:protocol_graph",
            source="missing_map",
            title="Build protocol graph before branch selection",
            status="needs_mapping",
            next_tool="map_protocol_graph",
            required_toolsets=["map"],
            priority="high",
            priority_score=18,
            instructions=(
                "Map value-flow, trust-boundary, oracle, router, callback, and "
                "external-dependency edges for the active source root."
            ),
            required_evidence=["/workspace/campaign/protocol-graphs/*.json"],
            stop_condition="Do not choose a complex route before protocol graph context exists.",
        ))
    if not action_space_paths:
        add(_attack_search_candidate(
            key="map:action_space",
            source="missing_map",
            title="Map callable action space before experiment design",
            status="needs_mapping",
            next_tool="map_action_space",
            required_toolsets=["map"],
            priority="high",
            priority_score=17,
            instructions=(
                "Extract public/external actions, observations, role gates, "
                "state mutation hints, and value-moving affordances."
            ),
            required_evidence=["/workspace/campaign/action-spaces/*.json"],
            stop_condition="Do not write a harness until the callable action grammar is known.",
        ))

    live_reachability_paths = _progress_evidence_paths(
        state,
        "/workspace/campaign/live-reachability/",
    )
    latest_live_reachability = (
        await _load_campaign_json_if_exists(container, live_reachability_paths[-1])
        if live_reachability_paths else None
    )
    live_reachability_has_deployed_context = _live_reachability_has_deployed_context(
        latest_live_reachability
    )
    live_inventory_paths = _progress_evidence_paths(
        state,
        "/workspace/campaign/live-inventory/",
    )
    live_inventory_entries = await _live_inventory_entries_by_address(
        container,
        live_inventory_paths,
    )
    live_inventory_addresses = set(live_inventory_entries)
    attack_graph_paths = _progress_evidence_paths(
        state,
        "/workspace/campaign/attack-graphs/",
    )
    # When a state-transition model exists alongside an action space, nudge the
    # attack-graph build to consume it so its generic invariants become scheduled
    # branches. We never recommend extracting a model that does not exist yet.
    state_transition_model_paths = _progress_evidence_paths(
        state,
        "/workspace/campaign/state-transition-models/",
    )
    latest_state_transition_model = (
        state_transition_model_paths[-1] if state_transition_model_paths else ""
    )
    state_transition_model_hint = (
        " A state-transition model is available; pass it via "
        "state_transition_model so its generic invariants become candidate "
        "branches."
        if latest_state_transition_model and action_space_paths else ""
    )
    # Load the latest attack graph once (reused by the candidate-chain loop
    # below) and the latest state-transition model so we can tell whether the
    # graph already consumed the model and whether the model carries any
    # invariants worth scheduling.
    latest_attack_graph = (
        await _load_campaign_json_if_exists(container, attack_graph_paths[-1])
        if attack_graph_paths else None
    )
    latest_state_transition_model_obj = (
        await _load_campaign_json_if_exists(container, latest_state_transition_model)
        if latest_state_transition_model else None
    )
    state_transition_model_has_invariants = bool(
        (latest_state_transition_model_obj or {}).get("candidate_invariants")
    )
    latest_state_transition_model_id = (
        latest_state_transition_model.rsplit("/", 1)[-1][: -len(".json")]
        if latest_state_transition_model.endswith(".json")
        else ""
    )
    graph_state_transition_ref = (
        latest_attack_graph.get("state_transition_model")
        if isinstance(latest_attack_graph, dict)
        else None
    )
    latest_attack_graph_uses_model = bool(
        isinstance(graph_state_transition_ref, dict)
        and (
            str(graph_state_transition_ref.get("path") or "")
            == latest_state_transition_model
            or (
                latest_state_transition_model_id
                and str(graph_state_transition_ref.get("model_id") or "")
                == latest_state_transition_model_id
            )
        )
    )
    # Condition A: once a callable action space exists but no state-transition
    # model has been extracted yet, recommend extraction so generic invariants
    # are built before the attack graph overfits to known economic lenses. We
    # gate strictly on the model artifact not existing, so a not_found/empty
    # extraction (which still writes a model artifact) cannot make this loop.
    if action_space_paths and not state_transition_model_paths:
        add(_attack_search_candidate(
            key="map:state_transition_model",
            source="missing_state_transition_model",
            title="Extract a generic state-transition model before attack-graph lenses",
            status="needs_mapping",
            next_tool="extract_state_transition_model",
            required_toolsets=["map"],
            priority="medium",
            priority_score=14,
            source_artifacts=[action_space_paths[-1], *protocol_graph_paths[:1]],
            instructions=(
                "Build generic invariants before overfitting to known lenses. "
                "Extract a state-transition model (tracked state, mutating "
                "entrypoints, candidate invariants) from the active source root "
                "or the latest action space, then pass it to build_attack_graph "
                "so its invariants become scheduled candidate branches. This is "
                "planning context, not evidence."
            ),
            required_evidence=["/workspace/campaign/state-transition-models/*.json"],
            stop_condition=(
                "Treat invariants as hypotheses to falsify with objective "
                "experiments; live binding is still required for any high/"
                "critical claim."
            ),
            required_args={
                "extract_state_transition_model": {
                    "action_space": action_space_paths[-1],
                    **(
                        {"protocol_graph": protocol_graph_paths[-1]}
                        if protocol_graph_paths else {}
                    ),
                },
            },
        ))
    if protocol_graph_paths and action_space_paths and not live_reachability_paths:
        add(_attack_search_candidate(
            key="map:live_reachability",
            source="missing_live_reachability",
            title="Map deployed/live reachability before deeper branch selection",
            status="needs_mapping",
            next_tool="map_live_reachability",
            required_toolsets=["map"],
            priority="high",
            priority_score=16,
            source_artifacts=[*protocol_graph_paths[:2], *action_space_paths[:2]],
            instructions=(
                "Bind source actions to deployed profiles, proxy/code probes, "
                "roles, and live gates so source-only possibilities do not "
                "become false-positive branches."
            ),
            required_evidence=["/workspace/campaign/live-reachability/*.json"],
            stop_condition="Do not claim high/critical impact without live exposure context.",
        ))
    if (
        protocol_graph_paths
        and action_space_paths
        and (not live_reachability_paths or not live_reachability_has_deployed_context)
        and not attack_graph_paths
    ):
        # A source-only attack graph is a valid planning artifact before live
        # reachability exists, and after live reachability was attempted but did
        # not bind deployed context. It preserves the full source-derived branch
        # frontier for novelty discovery; it does not replace live mapping, which
        # stays the higher-priority next action when deployment/RPC context is
        # available, and it never relaxes the live-evidence submission gates.
        live_context_note = (
            "Live reachability was attempted but did not bind a deployed target. "
            if live_reachability_paths else
            "Live reachability is not mapped yet. "
        )
        add(_attack_search_candidate(
            key="map:attack_graph:source_only",
            source="missing_attack_graph_source_only",
            title="Build a source-only attack graph as a planning artifact",
            status="needs_mapping",
            next_tool="build_attack_graph",
            required_toolsets=["map"],
            priority="medium",
            priority_score=13,
            source_artifacts=[
                action_space_paths[-1],
                *protocol_graph_paths[:1],
                *(live_reachability_paths[-1:] if live_reachability_paths else []),
            ],
            instructions=(
                live_context_note
                + "Build a source-only attack "
                "graph (mode=source_only) so the full source-derived branch "
                "frontier is preserved for novelty discovery while live context "
                "is pending. This is a planning artifact only: high/critical "
                "submission still requires live exposure and objective fork-replay "
                "evidence, so map live reachability whenever RPC or deployment "
                "context is available." + state_transition_model_hint
            ),
            required_evidence=["/workspace/campaign/attack-graphs/*.json"],
            stop_condition=(
                "Treat source-only candidates as planning skeletons; do not submit "
                "high/critical findings without live exposure and fork evidence."
            ),
            required_args={
                "build_attack_graph": {
                    "mode": "source_only",
                    "action_space": action_space_paths[-1],
                    **(
                        {"state_transition_model": latest_state_transition_model}
                        if latest_state_transition_model else {}
                    ),
                },
            },
        ))
    if (
        action_space_paths
        and live_reachability_paths
        and not attack_graph_paths
        and live_reachability_has_deployed_context
    ):
        add(_attack_search_candidate(
            key="map:attack_graph",
            source="missing_attack_graph",
            title="Build reachability-aware attack graph",
            status="needs_mapping",
            next_tool="build_attack_graph",
            required_toolsets=["map"],
            priority="high",
            priority_score=15,
            source_artifacts=[action_space_paths[-1], live_reachability_paths[-1]],
            instructions=(
                "Combine action-space and live-reachability artifacts into "
                "ranked transaction-chain skeletons before composing harnesses."
                + state_transition_model_hint
            ),
            required_evidence=["/workspace/campaign/attack-graphs/*.json"],
            stop_condition="Use the graph candidates as experiment skeletons, not findings.",
            required_args=(
                {
                    "build_attack_graph": {
                        "action_space": action_space_paths[-1],
                        "live_reachability": live_reachability_paths[-1],
                        "state_transition_model": latest_state_transition_model,
                    },
                }
                if latest_state_transition_model else None
            ),
        ))
    # Condition B: a state-transition model with invariants exists, an attack
    # graph exists, but the latest graph did not consume the model -- so its
    # generic invariants are not yet scheduled branches. Recommend a rebuild
    # that passes the model. This fires only until a model-aware graph exists,
    # so it cannot loop, and it stays out of the first-build cases above (which
    # require no attack graph yet).
    if (
        action_space_paths
        and attack_graph_paths
        and latest_state_transition_model
        and state_transition_model_has_invariants
        and not latest_attack_graph_uses_model
    ):
        rebuild_mode = (
            "auto"
            if live_reachability_paths and live_reachability_has_deployed_context
            else "source_only"
        )
        add(_attack_search_candidate(
            key="map:attack_graph:state_transition_model",
            source="attack_graph_without_state_transition_model",
            title="Rebuild attack graph to consume the state-transition model",
            status="needs_mapping",
            next_tool="build_attack_graph",
            required_toolsets=["map"],
            priority="medium",
            priority_score=13,
            source_artifacts=[
                action_space_paths[-1],
                latest_state_transition_model,
                attack_graph_paths[-1],
                *(live_reachability_paths[-1:] if live_reachability_paths else []),
            ],
            instructions=(
                "A state-transition model with candidate invariants is available "
                "but the latest attack graph did not consume it, so its generic "
                "invariants are not yet scheduled branches. Rebuild the attack "
                "graph with state_transition_model set (preserve_frontier=true to "
                "keep the existing branch frontier) so each candidate invariant "
                "becomes a generic_state_transition branch."
                + (
                    " Map live reachability first if you want the invariants "
                    "bound to deployed targets."
                    if not live_reachability_paths else ""
                )
            ),
            required_evidence=[
                "/workspace/campaign/attack-graphs/*.json recording a "
                "state_transition_model locator",
            ],
            stop_condition=(
                "Generic invariant branches are planning skeletons; high/critical "
                "submission still requires live exposure and objective fork evidence."
            ),
            required_args={
                "build_attack_graph": {
                    "mode": rebuild_mode,
                    "action_space": action_space_paths[-1],
                    "state_transition_model": latest_state_transition_model,
                    "preserve_frontier": True,
                    **(
                        {"live_reachability": live_reachability_paths[-1]}
                        if live_reachability_paths else {}
                    ),
                },
            },
        ))

    decided_attack_keys = set(
        (state.get("attack_search") or {}).get("decided_attack_keys") or []
    )
    decided_action_family_keys = set(
        (state.get("attack_search") or {}).get("decided_action_family_keys") or []
    )
    decided_clone_family_keys = set(
        (state.get("attack_search") or {}).get("decided_clone_family_keys") or []
    )
    if attack_graph_paths:
        for candidate in (latest_attack_graph or {}).get("candidate_chains") or []:
            if not isinstance(candidate, dict):
                continue
            attack_key = str(candidate.get("attack_key") or "").strip()
            if attack_key and attack_key in decided_attack_keys:
                continue
            actions = candidate.get("actions") or []
            action_keys = _attack_candidate_action_keys(candidate)
            action_family_keys = sorted(_attack_candidate_action_family_key_set(candidate))
            clone_family_keys = sorted(_attack_candidate_clone_family_key_set(candidate))
            if action_family_keys and decided_action_family_keys.intersection(
                action_family_keys
            ):
                continue
            if clone_family_keys and decided_clone_family_keys.intersection(
                clone_family_keys
            ):
                continue
            unresolved_live_context = _attack_graph_candidate_needs_live_context(
                candidate,
                actions,
            )
            candidate_id = str(candidate.get("candidate_id") or "").strip()
            # State-transition-model (generic invariant) candidates carry their
            # invariant + model locator so the branch dossier/next_action can
            # surface them and the routing can prefer live-context mapping.
            candidate_source = (
                candidate.get("source")
                if isinstance(candidate.get("source"), dict)
                else {}
            )
            candidate_invariant = (
                candidate.get("invariant")
                if isinstance(candidate.get("invariant"), dict)
                else {}
            )
            is_generic_invariant_candidate = bool(
                candidate.get("candidate_kind") == "generic_invariant"
                or candidate_source.get("kind") == "state_transition_model"
            )
            invariant_id = str(
                candidate_invariant.get("id")
                or candidate_source.get("invariant_id")
                or ""
            ).strip()
            invariant_kind = str(candidate_invariant.get("kind") or "").strip()
            invariant_statement = str(candidate_invariant.get("statement") or "").strip()
            state_transition_model_ref = str(
                candidate_source.get("state_transition_model") or ""
            ).strip()
            workbench_mechanism_hint = _candidate_explicit_fork_workbench_mechanism(candidate)
            materialized_experiments = _attack_graph_candidate_experiments(
                state,
                candidate,
            )
            materialized_experiment = (
                materialized_experiments[-1] if materialized_experiments else None
            )
            workbenches = _attack_graph_candidate_workbenches(state, candidate)
            workbench = workbenches[-1] if workbenches else None
            workbench_compose_args = (
                await _workbench_compose_args_from_entry(container, workbench)
                if workbench else {}
            )
            inventory_targets = _attack_candidate_inventory_targets(candidate)
            inventory_context = _candidate_inventory_context(
                candidate,
                inventory_targets,
                live_inventory_entries,
            )
            inventory_satisfied = _inventory_targets_satisfied(
                inventory_targets,
                live_inventory_addresses,
            )
            inventory_blocks_target = bool(
                inventory_satisfied and inventory_context.get("hard_blockers")
            )
            if materialized_experiment and unresolved_live_context:
                branch_status = "parked_needs_live_context"
                branch_next_tool = "record_fork_context or update_campaign"
            elif materialized_experiment:
                sequence_quality = materialized_experiment.get("sequence_quality") or {}
                if (
                    isinstance(sequence_quality, dict)
                    and sequence_quality
                    and (
                        not sequence_quality.get("runnable")
                        or sequence_quality.get("requires_manual_assertions")
                    )
                ):
                    if _sequence_quality_needs_context(
                        materialized_experiment,
                        sequence_quality,
                    ):
                        branch_status = "needs_context"
                        branch_next_tool = (
                            "source_slice, record_fork_context, inventory_live_targets, "
                            "or attack_search action=decision"
                        )
                    # An executable subset (proof_readiness=partial with at least
                    # one executable call) can be probed for preconditions now;
                    # otherwise the whole scaffold still needs concretization.
                    elif (
                        sequence_quality.get("proof_readiness") == "partial"
                        and int(
                            sequence_quality.get("executable_sequence_calls") or 0
                        ) > 0
                    ):
                        branch_status = "needs_partial_probe"
                        branch_next_tool = "complete_sequence_experiment"
                    else:
                        branch_status = "needs_concretization"
                        branch_next_tool = "complete_sequence_experiment"
                else:
                    branch_status = "needs_run"
                    branch_next_tool = "run_experiment"
            elif workbench:
                branch_status = "needs_harness"
                branch_next_tool = "compose_sequence_experiment"
            elif inventory_targets and not inventory_satisfied:
                branch_status = "needs_inventory"
                branch_next_tool = "inventory_live_targets"
            elif unresolved_live_context:
                # Source-only candidates have no live context yet: mapping live
                # reachability is the next step only until the agent has tried it.
                # An empty live-reachability artifact must not unlock harness work;
                # preserve the branch below active work until deployment/fork
                # context is available.
                if live_reachability_paths and not live_reachability_has_deployed_context:
                    branch_status = "parked_needs_live_context"
                    branch_next_tool = "record_fork_context or update_campaign"
                else:
                    branch_status = "needs_mapping"
                    branch_next_tool = "map_live_reachability"
            else:
                branch_status = "needs_harness"
                branch_next_tool = "prepare_fork_exploit_workbench"
            if inventory_blocks_target:
                branch_next_tool = "attack_search action=decision or mutate_hypothesis"
            linked_context = materialized_experiment or workbench
            branch_evidence = (
                linked_context.get("evidence") or []
                if linked_context
                else live_inventory_paths[-2:]
                if inventory_satisfied
                else []
            )
            branch_related = (
                [linked_context.get("id")]
                if linked_context
                else []
            )
            materialized_workspace = ""
            if materialized_experiment:
                match = re.search(
                    r"^Workspace:\s*(.+)$",
                    str(materialized_experiment.get("content") or ""),
                    flags=re.MULTILINE,
                )
                if match:
                    materialized_workspace = match.group(1).strip()
            prepare_workbench_args = {
                "title": f"Fork workbench for {candidate.get('title')}",
                "attack_graph": attack_graph_paths[-1],
                "candidate_id": candidate_id or attack_key or candidate.get("action_key"),
            }
            if workbench_mechanism_hint:
                prepare_workbench_args["mechanism"] = workbench_mechanism_hint
            # Once the scaffold exists, completion is the deterministic next step:
            # bind targets, apply synthesized args, and add objective probes via
            # complete_sequence_experiment instead of hand-writing the file.
            complete_sequence_args = {}
            if (
                materialized_experiment
                and materialized_experiment.get("id")
                and branch_status in {"needs_partial_probe", "needs_concretization"}
            ):
                complete_args = {"sequence": str(materialized_experiment.get("id"))}
                if candidate.get("target_address"):
                    complete_args["target_addresses"] = {
                        str(candidate.get("contract") or "target"): candidate.get(
                            "target_address"
                        )
                    }
                if branch_status == "needs_partial_probe":
                    complete_args["mode"] = "partial_probe"
                complete_sequence_args = {
                    "complete_sequence_experiment": complete_args
                }
            try:
                base_priority_score = int(candidate.get("priority_score", 0) or 0)
            except (TypeError, ValueError):
                base_priority_score = 0
            priority_score = (
                base_priority_score
                + int((inventory_context or {}).get("score_delta", 0) or 0)
            )
            priority = (
                _plan_priority(priority_score)
                if inventory_context.get("matched_targets")
                else _attack_search_priority(candidate.get("priority"))
            )
            inventory_note = _inventory_context_instruction(inventory_context)
            base_instructions = (
                (
                    "Latest live inventory invalidates this candidate's exact "
                    "target binding. Do not write another harness for this "
                    "branch until you either prove the inventory is wrong, "
                    "mutate to a different live deployed target, or record a "
                    "decision explaining why this branch is not viable."
                )
                if inventory_blocks_target
                else (
                    "This source-only/generic invariant branch still lacks live "
                    "target or fork context. Preserve it as planning context and "
                    "do not prepare, compose, complete, or run a speculative "
                    "sequence until deployment evidence binds the target address "
                    "and chain. Record the missing deployment context or mutate "
                    "to a branch with concrete live binding."
                )
                if branch_status == "parked_needs_live_context"
                else (
                    "The materialized sequence is missing target, deployment, "
                    "chain, or source context. Gather that context with "
                    "source_slice, record_fork_context, inventory_live_targets, "
                    "or observed_tx_miner, or record a branch decision. Do not "
                    "call complete_sequence_experiment until the missing context "
                    "is bound enough for deterministic target/argument/probe "
                    "completion."
                )
                if branch_status == "needs_context" and materialized_experiment
                else (
                    "Complete the already materialized attack-graph sequence at "
                    f"{materialized_workspace or 'the linked experiment workspace'} "
                    "with complete_sequence_experiment: bind targets, apply "
                    "synthesized args, and add objective probes (it rewrites "
                    "sequence.json and recomputes scaffold_quality). Then run it. "
                    "If blockers show the path is gated or dormant and there is "
                    "no concrete bypass hypothesis, record a decision instead of "
                    "writing a speculative PoC."
                )
                if materialized_experiment
                else (
                    "Use the linked fork workbench to materialize this "
                    "candidate with compose_sequence_experiment. Carry its "
                    "mechanism setup, blocker checks, snapshot probes, and "
                    "objective templates into the sequence scaffold before "
                    "running. If blockers show the path is gated or dormant "
                    "and there is no concrete bypass hypothesis, record a "
                    "decision instead of writing a speculative PoC."
                )
                if workbench
                else (
                    "Run live inventory for the candidate's exact deployed "
                    "targets before preparing a fork workbench. Use the "
                    "inventory to bind assets, controllers, authority, "
                    "proxy state, and dormant targets; reject or mutate the "
                    "branch if the live state invalidates the candidate."
                )
                if branch_status == "needs_inventory"
                else (
                    "This generic state-transition invariant has no live "
                    "context yet. Map live reachability for its entrypoints "
                    "and bind a deployed target, then prepare a fork workbench "
                    "to falsify the invariant with an objective experiment. If "
                    "no deployment/RPC context exists, record a decision or "
                    "park the branch as needs_live_context instead of writing a "
                    "speculative PoC."
                )
                if branch_status == "needs_mapping"
                else (
                    "Prepare a mechanism-aware fork workbench for this "
                    "candidate before writing the sequence scaffold. The "
                    "workbench should identify live setup, blockers, "
                    "snapshot probes, and objective templates so the later "
                    "PoC tests a concrete economic claim rather than a "
                    "placeholder transaction."
                )
            )
            instructions = (
                f"{base_instructions} {inventory_note}"
                if inventory_note else base_instructions
            )
            add(_attack_search_candidate(
                key=f"attack_graph:{attack_key or candidate.get('action_key')}",
                source=(
                    "attack_graph_state_model"
                    if is_generic_invariant_candidate
                    else "attack_graph_candidate"
                ),
                title=str(candidate.get("title") or "Attack graph candidate"),
                status=branch_status,
                next_tool=branch_next_tool,
                required_toolsets=(
                    ["core"]
                    if inventory_blocks_target
                    else ["core"]
                    if branch_status in _ATTACK_SEARCH_PARKED_STATUSES
                    else ["core"]
                    if branch_status == "needs_context"
                    else ["experiment"]
                    if branch_status == "needs_concretization"
                    else ["map"]
                    if branch_status in {"needs_inventory", "needs_mapping"}
                    else ["experiment"]
                ),
                priority=priority,
                priority_score=priority_score,
                source_ids=[
                    (latest_attack_graph or {}).get("id"),
                    candidate_id,
                    candidate.get("action_key"),
                ],
                source_artifacts=[
                    attack_graph_paths[-1],
                    candidate.get("source", {}).get("action_space") if isinstance(candidate.get("source"), dict) else None,
                    candidate.get("source", {}).get("live_reachability") if isinstance(candidate.get("source"), dict) else None,
                    *(live_inventory_paths[-2:] if inventory_satisfied else []),
                ],
                instructions=instructions,
                required_evidence=(
                    ["/workspace/campaign/live-inventory/*.json"]
                    if branch_status == "needs_inventory"
                    else ["/workspace/campaign/live-reachability/*.json"]
                    if branch_status == "needs_mapping"
                    else [
                        "deployment, chain, or fork-context evidence binding the target",
                        "explicit mutation to a concretely bound branch before harness work",
                    ]
                    if branch_status == "parked_needs_live_context"
                    else [
                        "explicit decision or mutation linked to live inventory blockers",
                    ]
                    if inventory_blocks_target
                    else [
                        (
                            "completed generated sequence scaffold"
                            if materialized_experiment
                            else "sequence experiment generated from fork workbench"
                            if workbench
                            else "fork workbench generated from attack_graph/candidate_id"
                        ),
                        "objective replay and live exposure evidence",
                    ]
                ),
                stop_condition="If live exposure or objective impact fails, reject or mutate the branch.",
                related_ids=branch_related,
                evidence=branch_evidence,
                action_keys=action_keys,
                action_family_keys=action_family_keys,
                clone_family_keys=clone_family_keys,
                attack_keys=[attack_key] if attack_key else [],
                target_binding=candidate.get("target_binding"),
                inventory_context=inventory_context,
                target_actions=actions if isinstance(actions, list) else [],
                normalized_target_keys=[
                    *[
                        str(item.get("to") or "").lower()
                        for item in inventory_context.get("recommended_call_targets") or []
                        if _solidity_address_literal(item.get("to"))
                    ],
                    *[
                        str(item.get("to") or "").lower()
                        for item in inventory_context.get("related_live_targets") or []
                        if (
                            item.get("audit_relevance") == "call_target_candidate"
                            and _solidity_address_literal(item.get("to"))
                        )
                    ],
                ],
                root_mechanism=str(candidate.get("mechanism") or ""),
                invariant_id=invariant_id,
                invariant_kind=invariant_kind,
                invariant_statement=invariant_statement,
                state_transition_model=state_transition_model_ref,
                generic_invariant=is_generic_invariant_candidate,
                parking_reason=(
                    "live reachability did not bind a deployed target address"
                    if branch_status == "parked_needs_live_context" else None
                ),
                recommended_budget=(
                    "revisit after deployment metadata, chain binding, or fork context"
                    if branch_status == "parked_needs_live_context" else None
                ),
                required_args={
                    "inventory_live_targets": {
                        "title": f"Live inventory for {candidate.get('title')}",
                        "targets": inventory_targets,
                        "related_ids": [
                            item for item in (
                                (latest_attack_graph or {}).get("id"),
                                candidate_id,
                                attack_key,
                                candidate.get("action_key"),
                            )
                            if item
                        ],
                    },
                    "prepare_fork_exploit_workbench": prepare_workbench_args,
                    "compose_sequence_experiment": {
                        **{
                            "title": candidate.get("title"),
                            "objective": candidate.get("objective"),
                            "attack_graph": attack_graph_paths[-1],
                            "candidate_id": candidate_id or attack_key or candidate.get("action_key"),
                            "action_space": (
                                candidate.get("source", {}).get("action_space")
                                if isinstance(candidate.get("source"), dict)
                                else ""
                            ),
                            "protocol_graph": (
                                candidate.get("source", {}).get("protocol_graph")
                                if isinstance(candidate.get("source"), dict)
                                else ""
                            ),
                            "actions": actions if isinstance(actions, list) else [],
                            "observations": [],
                            "target_addresses": {
                                str(candidate.get("contract") or "target"): candidate.get("target_address")
                            } if candidate.get("target_address") else {},
                        },
                        **workbench_compose_args,
                    },
                    **complete_sequence_args,
                },
            ))
            for alias_index, related in enumerate(
                inventory_context.get("recommended_call_targets") or [],
                start=1,
            ):
                alias_address = _solidity_address_literal(related.get("to"))
                original_address = _solidity_address_literal(related.get("from"))
                if not alias_address or not original_address:
                    continue
                alias_target = _candidate_alias_inventory_target(
                    candidate,
                    related,
                    index=alias_index,
                )
                alias_inventory_targets = [alias_target]
                alias_inventory_context = _candidate_inventory_context(
                    candidate,
                    alias_inventory_targets,
                    live_inventory_entries,
                )
                alias_inventory_satisfied = _inventory_targets_satisfied(
                    alias_inventory_targets,
                    live_inventory_addresses,
                )
                alias_inventory_blocks = bool(
                    alias_inventory_satisfied
                    and alias_inventory_context.get("hard_blockers")
                )
                alias_actions = _candidate_alias_actions(
                    candidate,
                    original_address=original_address,
                    alias_address=alias_address,
                )
                if alias_inventory_blocks:
                    alias_status = "needs_inventory"
                    alias_next_tool = "attack_search action=decision or mutate_hypothesis"
                    alias_toolsets = ["core"]
                elif alias_inventory_satisfied:
                    alias_status = "needs_harness"
                    alias_next_tool = "prepare_fork_exploit_workbench"
                    alias_toolsets = ["experiment"]
                else:
                    alias_status = "needs_inventory"
                    alias_next_tool = "inventory_live_targets"
                    alias_toolsets = ["map"]
                alias_prepare_args = dict(prepare_workbench_args)
                alias_prepare_args["target_addresses"] = {
                    str(candidate.get("contract") or "target"): alias_address
                }
                alias_priority_score = (
                    base_priority_score
                    + 6
                    + int((alias_inventory_context or {}).get("score_delta", 0) or 0)
                )
                alias_priority = (
                    _plan_priority(alias_priority_score)
                    if alias_inventory_context.get("matched_targets")
                    else _attack_search_priority(candidate.get("priority"))
                )
                add(_attack_search_candidate(
                    key=(
                        "attack_graph_alias:"
                        f"{attack_key or candidate.get('action_key')}:"
                        f"{alias_address.lower()}"
                    ),
                    source="attack_graph_related_live_target",
                    title=(
                        f"Rebind {candidate.get('title') or 'attack graph candidate'} "
                        f"to related live target {alias_address}"
                    ),
                    status=alias_status,
                    next_tool=alias_next_tool,
                    required_toolsets=alias_toolsets,
                    priority=alias_priority,
                    priority_score=alias_priority_score,
                    source_ids=[
                        (latest_attack_graph or {}).get("id"),
                        candidate_id,
                        candidate.get("action_key"),
                    ],
                    source_artifacts=[
                        attack_graph_paths[-1],
                        *(live_inventory_paths[-2:] if alias_inventory_satisfied else []),
                    ],
                    instructions=(
                        "A live inventory probe found a related deployed call target "
                        f"for the original address {original_address}: {alias_address}. "
                        "Treat the related target as an audit target, verify its live "
                        "inventory, then prepare a fork workbench against this address. "
                        "If this alias is also dormant, gated, or economically empty, "
                        "record a decision instead of cycling through sibling source actions."
                    ),
                    required_evidence=(
                        ["/workspace/campaign/live-inventory/*.json"]
                        if alias_status == "needs_inventory"
                        else [
                            "fork workbench generated against the related live target",
                            "objective replay and live exposure evidence",
                        ]
                    ),
                    stop_condition=(
                        "Continue only if the related target is live/deployed and "
                        "the fork objective proves economic or security impact."
                    ),
                    related_ids=branch_related,
                    evidence=live_inventory_paths[-2:] if alias_inventory_satisfied else [],
                    action_keys=action_keys,
                    attack_keys=[
                        (
                            f"{attack_key}:related:{alias_address.lower()}"
                            if attack_key
                            else f"related:{alias_address.lower()}"
                        ),
                    ],
                    target_binding={
                        "original_address": original_address,
                        "recommended_call_target": alias_address,
                        "normalization_reason": related.get("reason"),
                        "binding_kind": "related_live_target",
                    },
                    inventory_context=alias_inventory_context,
                    target_actions=alias_actions,
                    normalized_target_keys=[alias_address.lower()],
                    root_mechanism=str(candidate.get("mechanism") or ""),
                    required_args={
                        "inventory_live_targets": {
                            "title": (
                                f"Live inventory for related target "
                                f"{candidate.get('title')}"
                            ),
                            "targets": alias_inventory_targets,
                            "related_ids": [
                                item for item in (
                                    (latest_attack_graph or {}).get("id"),
                                    candidate_id,
                                    attack_key,
                                    candidate.get("action_key"),
                                )
                                if item
                            ],
                        },
                        "prepare_fork_exploit_workbench": alias_prepare_args,
                        "compose_sequence_experiment": {
                            "title": candidate.get("title"),
                            "objective": candidate.get("objective"),
                            "attack_graph": attack_graph_paths[-1],
                            "candidate_id": candidate_id or attack_key or candidate.get("action_key"),
                            "action_space": (
                                candidate.get("source", {}).get("action_space")
                                if isinstance(candidate.get("source"), dict)
                                else ""
                            ),
                            "protocol_graph": (
                                candidate.get("source", {}).get("protocol_graph")
                                if isinstance(candidate.get("source"), dict)
                                else ""
                            ),
                            "actions": alias_actions,
                            "observations": [],
                            "target_addresses": {
                                str(candidate.get("contract") or "target"): alias_address
                            },
                        },
                    },
                ))

        # Curiosity/diversity frontier branches. The attack-graph artifact
        # preserves many low-label/unlabeled branches in its frontier; promote a
        # capped handful (1-3) into exploratory branches so the scheduler keeps
        # an unusual lead or two visible without flooding the queue or
        # displacing the ranked candidate chains. They never carry their own
        # attack_key if it already belongs to a live or decided candidate.
        frontier_existing_attack_keys = {
            str(attack_key)
            for cand in candidates.values()
            for attack_key in cand.get("attack_keys") or []
        }
        for frontier_candidate in _attack_search_frontier_candidates(
            latest_attack_graph,
            attack_graph_paths[-1],
            existing_attack_keys=frontier_existing_attack_keys,
            decided_attack_keys=decided_attack_keys,
            live_context_unbound=bool(
                live_reachability_paths and not live_reachability_has_deployed_context
            ),
        ):
            add(frontier_candidate)

    action_spaces_without_coverage = await _progress_action_spaces_without_coverage(
        container,
        state,
    )
    for item in action_spaces_without_coverage:
        add(_attack_search_candidate(
            key=f"coverage:missing:{item.get('id') or item.get('path')}",
            source="action_space_without_coverage",
            title=f"Review attack-surface coverage for {item.get('id') or item.get('path')}",
            status="needs_coverage",
            next_tool="review_attack_surface_coverage",
            required_toolsets=["map"],
            priority="medium",
            priority_score=12,
            source_ids=[item.get("id")] if item.get("id") else [],
            source_artifacts=[item.get("path")],
            instructions=(
                "Compare mapped actions against current hypotheses, experiments, "
                "results, and decisions to find untested high-value levers."
            ),
            required_evidence=["/workspace/campaign/coverage-reviews/*.json"],
            stop_condition="Turn meaningful gaps into hypotheses or reject them explicitly.",
        ))

    coverage_gaps = await _progress_coverage_gaps(container, state)
    coverage_live_context_unbound = bool(
        live_reachability_paths and not live_reachability_has_deployed_context
    )
    for item in coverage_gaps:
        top_gaps = item.get("top_high_attention_gaps") or []
        for gap in top_gaps:
            affordances = ", ".join(gap.get("affordances") or []) or "no affordance labels"
            action_key = str(gap.get("key") or "").strip()
            source_slice_args = {
                key: value
                for key, value in {
                    "path": gap.get("file"),
                    "function": gap.get("function"),
                }.items()
                if value
            }
            branch_status = "needs_context"
            branch_next_tool = "source_slice then update_campaign or attack_search decision"
            branch_toolsets = ["core"]
            if coverage_live_context_unbound:
                context_prefix = (
                    "Live reachability was attempted but did not bind a deployed "
                    "target, so this coverage gap is source-review work only. "
                )
            else:
                context_prefix = (
                    "Coverage identifies an unreviewed surface, not an exploit "
                    "path. Treat it as source/context work first. "
                )
            branch_instructions = (
                context_prefix
                + "Read the selected function and immediate value/authority "
                "context, then record a concrete hypothesis, open question, "
                "rejection, or parking decision. Do not compose a sequence or "
                "invariant harness until source review establishes an "
                "attacker-controlled lever, value/right/invariant at risk, "
                "setup precondition, measurable objective, and any needed "
                "deployment/fork binding. "
                f"Selected gap: {action_key or 'unknown'} ({affordances})."
            )
            branch_required_evidence = [
                "source_slice or equivalent source-review artifact",
                "concrete hypothesis, open_question, rejection, or parking decision",
                "deployment/chain/fork context before harness work when live binding matters",
            ]
            branch_required_args = (
                {"source_slice": source_slice_args}
                if source_slice_args else None
            )
            add(_attack_search_candidate(
                key=f"coverage:action:{action_key or item.get('id')}",
                source="coverage_high_attention_gap",
                title=f"Source-review coverage gap: {action_key or item.get('id')}",
                status=branch_status,
                next_tool=branch_next_tool,
                required_toolsets=branch_toolsets,
                priority="high",
                priority_score=14 + int(gap.get("priority_score", 0) or 0),
                source_ids=[item.get("id")] if item.get("id") else [],
                source_artifacts=[
                    item.get("path"),
                    item.get("action_space"),
                ],
                instructions=branch_instructions,
                required_evidence=branch_required_evidence,
                stop_condition="If the gap is expected, gated, or dormant behavior, record a rejection decision.",
                action_keys=[action_key] if action_key else [],
                target_actions=[{
                    "key": action_key,
                    "contract": gap.get("contract"),
                    "function": gap.get("function"),
                    "file": gap.get("file"),
                    "line": gap.get("line"),
                    "affordances": gap.get("affordances") or [],
                }],
                required_args=branch_required_args,
            ))
        if top_gaps:
            continue
        coarse_status = "needs_context"
        coarse_next_tool = "source_slice then update_campaign or attack_search decision"
        coarse_toolsets = ["core"]
        if coverage_live_context_unbound:
            coarse_prefix = (
                "Live reachability was attempted but did not bind a deployed "
                "target, so pick the strongest remaining high-attention gap for "
                "source review only. "
            )
        else:
            coarse_prefix = (
                "Pick the strongest high-attention gap and source-review it "
                "before creating a hypothesis. "
            )
        coarse_instructions = (
            coarse_prefix
            + "Record a concrete hypothesis, open question, rejection, or "
            "parking decision; do not compose a sequence or invariant harness "
            "until source review and needed deployment context make the branch "
            "experiment-ready."
        )
        coarse_required_evidence = [
            "source-review artifact for a selected gap",
            "concrete hypothesis, open_question, rejection, or parking decision",
            "deployment/chain/fork context before harness work when live binding matters",
        ]
        add(_attack_search_candidate(
            key=f"coverage:gaps:{item.get('action_space') or item.get('id') or item.get('path')}",
            source="coverage_high_attention_gap",
            title=f"Source-review coverage gaps for {item.get('action_space') or item.get('id')}",
            status=coarse_status,
            next_tool=coarse_next_tool,
            required_toolsets=coarse_toolsets,
            priority="high" if item.get("summary", {}).get("high_attention_gaps") else "medium",
            priority_score=14,
            source_ids=[item.get("id")] if item.get("id") else [],
            source_artifacts=[
                item.get("path"),
                item.get("action_space"),
            ],
            instructions=coarse_instructions,
            required_evidence=coarse_required_evidence,
            stop_condition="If the gap is expected behavior, record a rejection decision.",
        ))

    for entry in _progress_hypotheses_without_experiments(state):
        readiness = entry.get("readiness") or {}
        missing_readiness = [
            str(item)
            for item in readiness.get("missing") or []
            if str(item).strip()
        ]
        if coverage_live_context_unbound:
            hypothesis_status = "parked_needs_live_context"
            hypothesis_next_tool = "record_fork_context or update_campaign"
            hypothesis_toolsets = ["core"]
            hypothesis_instructions = (
                "This hypothesis is source-only and live reachability was already "
                "attempted without binding a deployed target. Preserve it below "
                "active source-review work until deployment evidence, chain "
                "binding, or fork context exists; otherwise record a source "
                "decision or mutate to a concretely bound branch."
            )
            hypothesis_required_evidence = [
                "deployment, chain, or fork-context evidence binding the target",
                "source decision or mutation to a concretely bound branch",
            ]
            hypothesis_required_args = None
            hypothesis_parking_reason = (
                "live reachability did not bind a deployed target address"
            )
            hypothesis_recommended_budget = (
                "revisit after deployment metadata, chain binding, or fork context"
            )
        elif not readiness.get("ready"):
            missing_text = (
                ", ".join(missing_readiness)
                if missing_readiness else "experiment-readiness fields"
            )
            hypothesis_status = "needs_context"
            hypothesis_next_tool = (
                "source_slice, observed_tx_miner, record_fork_context, or update_campaign"
            )
            hypothesis_toolsets = ["core"]
            hypothesis_instructions = (
                "This hypothesis is not experiment-ready. Resolve the missing "
                f"context first ({missing_text}) by reading source, binding "
                "deployment/fork context, or recording an open_question. Mutate "
                "to a concrete hypothesis or reject/park it; do not compose a "
                "sequence or invariant harness until the branch names an "
                "attacker-controlled lever, target action, value/right/invariant "
                "at risk, setup precondition, measurable objective, and source "
                "or deployment evidence."
            )
            hypothesis_required_evidence = [
                "source_slice, deployment/fork context, or observed transaction evidence",
                "mutated concrete hypothesis, open_question, rejection, or parking decision",
            ]
            hypothesis_required_args = None
            hypothesis_parking_reason = None
            hypothesis_recommended_budget = None
        else:
            hypothesis_status = "needs_harness"
            hypothesis_next_tool = (
                "compose_sequence_experiment with explicit actions or "
                "compose_invariant_harness with handler actions"
            )
            hypothesis_toolsets = ["experiment"]
            hypothesis_instructions = (
                "Convert the hypothesis into a Foundry/fork sequence or "
                "property harness with concrete setup, actions, observations, "
                "and success condition. Do not call compose_sequence_experiment "
                "until you have selected at least one concrete action from the "
                "action-space or source review. Do not call "
                "compose_invariant_harness until you have selected at least one "
                "concrete handler action with bounds/args and expected_effect."
            )
            hypothesis_required_evidence = [
                "/workspace/experiments/*/sequence.json or invariant harness"
            ]
            hypothesis_required_args = None
            hypothesis_parking_reason = None
            hypothesis_recommended_budget = None
        add(_attack_search_candidate(
            key=f"hypothesis:{entry.get('id')}",
            source="hypothesis_without_experiment",
            title=(
                f"Turn hypothesis into executable harness: {entry.get('title')}"
                if hypothesis_status == "needs_harness"
                else f"Concretize hypothesis before harness: {entry.get('title')}"
            ),
            status=hypothesis_status,
            next_tool=hypothesis_next_tool,
            required_toolsets=hypothesis_toolsets,
            priority=_attack_search_priority(entry.get("priority")),
            priority_score=13,
            source_ids=[entry.get("id")],
            source_artifacts=[*(entry.get("evidence") or []), *action_space_paths, *protocol_graph_paths],
            related_ids=[entry.get("id")],
            instructions=hypothesis_instructions,
            required_evidence=hypothesis_required_evidence,
            stop_condition=(
                "If no realistic unprivileged setup exists, use attack_search "
                "action=decision or mutate the hypothesis."
            ),
            parking_reason=hypothesis_parking_reason,
            recommended_budget=hypothesis_recommended_budget,
            required_args=hypothesis_required_args,
            readiness=readiness,
        ))

    for entry in _progress_unrun_experiments(state):
        entry_status = entry.get("status")
        needs_context = entry_status == "needs_context"
        needs_partial_probe = entry_status == "needs_partial_probe"
        needs_concretization = entry_status == "needs_concretization"
        experiment_id = str(entry.get("id") or "")
        # needs_concretization/needs_partial_probe are only set for sequence
        # experiments (those with sequence_quality), so complete_sequence_experiment
        # can always load and rewrite the scaffold deterministically -- no need to
        # hand-write_file. A partial-probe branch routes the same completion tool
        # with mode=partial_probe so it materializes the test_partial_probe_* test.
        sequence_completion = needs_partial_probe or needs_concretization
        completion_args = None
        if sequence_completion and experiment_id:
            complete_args = {"sequence": experiment_id}
            if needs_partial_probe:
                complete_args["mode"] = "partial_probe"
            completion_args = {"complete_sequence_experiment": complete_args}
        if needs_context:
            branch_title = f"Bind context before completing sequence: {entry.get('title')}"
            branch_status = "needs_context"
            branch_next_tool = (
                "source_slice, record_fork_context, inventory_live_targets, "
                "or attack_search action=decision"
            )
            branch_required_evidence = [
                "source/deployment/fork context that binds the target path",
                "or a parking/rejection decision explaining why it cannot be bound",
            ]
            branch_followup = (
                "Do not call complete_sequence_experiment yet. The sequence is "
                "missing target, deployment, chain, or source context rather "
                "than just concrete args/probes; gather that context or record "
                "a branch decision first."
            )
        elif needs_partial_probe:
            branch_title = f"Partial-probe executable subset: {entry.get('title')}"
            branch_status = "needs_partial_probe"
            branch_next_tool = "complete_sequence_experiment"
            branch_required_evidence = [
                "partial probe result (setup/precondition evidence only)",
                "then updated sequence.json with scaffold_quality.runnable=true",
            ]
            branch_followup = (
                "Call complete_sequence_experiment with sequence="
                f"{experiment_id or 'exp-NNN'} mode=partial_probe to materialize "
                "the test_partial_probe_* test over the executable subset, then "
                "run it with run_experiment run_kind=partial_probe. Treat the "
                "result as precondition/setup evidence only: it guides mutation "
                "but cannot validate impact. Then bind the remaining steps and add "
                "an objective assertion (mode=full) before claiming a finding."
            )
        elif needs_concretization:
            branch_title = f"Complete concrete sequence scaffold: {entry.get('title')}"
            branch_status = "needs_concretization"
            branch_next_tool = "complete_sequence_experiment"
            branch_required_evidence = [
                "updated sequence.json with scaffold_quality.runnable=true",
            ]
            branch_followup = (
                "Call complete_sequence_experiment with sequence="
                f"{experiment_id or 'exp-NNN'} to bind targets, apply "
                "synthesized args, and add objective probes; it rewrites "
                "sequence.json and recomputes scaffold_quality. Do not call "
                "run_experiment while sequence_quality.runnable is false, and "
                "record a decision if the path cannot be concretized."
            )
        else:
            branch_title = f"Run open experiment: {entry.get('title')}"
            branch_status = "needs_run"
            branch_next_tool = "run_experiment"
            branch_required_evidence = ["/workspace/campaign/results/*.log"]
            branch_followup = (
                "Use run_kind=build/static_analysis/setup_probe for "
                "setup-only commands and "
                "run_kind=harness_run/poc_run/fuzz_run for objective "
                "commands. If it fails, preserve the full log and "
                "repair compile/setup/revert blockers before claiming "
                "impact."
            )
        add(_attack_search_candidate(
            key=f"experiment:{entry.get('id')}:unrun",
            source="experiment_without_result",
            title=branch_title,
            status=branch_status,
            next_tool=branch_next_tool,
            required_toolsets=["core"] if needs_context else ["experiment"],
            priority=_attack_search_priority(entry.get("priority")),
            priority_score=15,
            source_ids=[entry.get("id")],
            related_ids=[entry.get("id")],
            evidence=entry.get("evidence") or [],
            required_args=completion_args,
            instructions=(
                f"{entry.get('suggested_action') or 'Run the experiment command.'} "
                + branch_followup
            ),
            required_evidence=branch_required_evidence,
            stop_condition="A passing test is not enough; objective evidence is still required.",
        ))

    for item in _attack_search_results_without_objective(state):
        add(_attack_search_candidate(
            key=f"result:{item.get('id')}:needs_objective",
            source="result_without_objective",
            title=f"Convert run result into objective evidence: {item.get('title')}",
            status="needs_evidence",
            next_tool="summarize_trace then snapshot_state/compare_snapshots/evaluate_objective",
            required_toolsets=["evidence"],
            priority=_attack_search_priority(item.get("priority")),
            priority_score=16,
            source_ids=[item.get("id")],
            source_artifacts=item.get("evidence") or [],
            related_ids=[item.get("id"), *(item.get("related_ids") or [])],
            evidence=item.get("evidence") or [],
            instructions=(
                "Reduce the run into trace summary and measurable before/after "
                "state deltas. Evaluate attacker profit, protocol loss, bad debt, "
                "or unauthorized state transition before review/report."
            ),
            required_evidence=[
                "/workspace/campaign/traces/*.json",
                "/workspace/campaign/snapshots/*.json",
                "/workspace/campaign/comparisons/*.json",
                "/workspace/campaign/evaluations/*.json",
            ],
            stop_condition="If objective deltas do not prove impact, mutate or reject the branch.",
        ))

    blocked_results = await _progress_blocked_results(container, state)
    for entry in blocked_results:
        diagnosis = entry.get("failure_diagnosis") or {}
        kind = str(diagnosis.get("kind") or "").lower()
        repairable = not kind or kind in _ATTACK_SEARCH_POC_REPAIR_FAILURE_KINDS
        status = "needs_poc_repair" if repairable else "blocked_setup"
        if not repairable:
            if "compile" in kind:
                status = "blocked_compile"
            elif "revert" in kind or "failure" in kind:
                status = "blocked_revert"
        related_ids = [
            entry.get("id"),
            *(entry.get("related_ids") or []),
        ]
        experiment_ids = [
            str(item) for item in related_ids
            if re.fullmatch(r"exp-\d{3,}", str(item or ""))
        ]
        diagnostic_refs = [
            str(path) for path in entry.get("evidence") or []
            if str(path).endswith((".followup.json", ".log"))
        ]
        required_args = {}
        if experiment_ids:
            repair_args = {"experiment": experiment_ids[0]}
            if diagnostic_refs:
                repair_args["diagnostic"] = diagnostic_refs[0]
            required_args["repair_experiment"] = repair_args
            if kind == "compile_error":
                diagnose_args = {"experiment": experiment_ids[0]}
                log_refs = [path for path in diagnostic_refs if path.endswith(".log")]
                if log_refs:
                    diagnose_args["log_path"] = log_refs[0]
                required_args["diagnose_build"] = diagnose_args
        if kind == "compile_error":
            next_tool = "diagnose_build then repair_experiment or run_experiment"
            toolsets = ["experiment"]
        elif kind in {"missing_or_invalid_binding", "fork_or_token_setup"}:
            next_tool = (
                "record_fork_context, complete_sequence_experiment, "
                "repair_experiment, or run_experiment"
            )
            toolsets = ["experiment"]
        elif kind in {"runtime_revert", "assertion_failure", "unclassified_blocked_run"}:
            next_tool = (
                "summarize_trace or compare_snapshots, then repair_experiment, "
                "run_experiment, or mutate_hypothesis"
            )
            toolsets = ["experiment", "evidence"]
        elif kind == "timeout":
            next_tool = "repair_experiment or run_experiment with a narrower command"
            toolsets = ["experiment"]
        else:
            next_tool = "run_experiment or attack_search action=decision"
            toolsets = ["experiment"]
        add(_attack_search_candidate(
            key=f"result:{entry.get('id')}:blocked",
            source="blocked_result",
            title=f"Resolve blocked experiment result: {entry.get('title')}",
            status=status,
            next_tool=next_tool,
            required_toolsets=toolsets,
            priority=_attack_search_priority(entry.get("priority")),
            priority_score=18 if repairable else 11,
            source_ids=[entry.get("id")],
            source_artifacts=entry.get("evidence") or [],
            related_ids=related_ids,
            instructions=(
                "This result blocked before it produced objective exploit evidence. "
                "Treat the diagnosis as a PoC/harness repair prompt, not proof that "
                "the hypothesis is false. Fix the earliest concrete compile, target "
                "binding, fork/setup, revert, assertion, or timeout blocker and rerun "
                "the same experiment before widening scope. "
                + (
                    entry.get("suggested_action")
                    or "Repair the blocked run or record an explicit branch decision."
                )
            ),
            required_evidence=[
                "focused repair, diagnosis, or context artifact for the first blocker",
                "rerun log after the repair, preserving the new failure mode",
                "or decision/mutation artifact explaining why the branch is no longer viable",
            ],
            stop_condition=(
                "After one focused repair/resync, if the same blocker remains or the "
                "run proves a protocol-level failed assumption, record a decision or "
                "mutate the branch instead of starting a fresh unrelated PoC."
            ),
            required_args=required_args,
            failure_diagnosis=diagnosis,
        ))

    failed_evaluations = await _progress_evaluations(container, state)
    for item in failed_evaluations:
        add(_attack_search_candidate(
            key=f"evaluation:{item.get('id')}:failed",
            source="failed_objective",
            title=f"Objective failed or unmatched: {item.get('title')}",
            status="objective_failed",
            next_tool="mutate_hypothesis or attack_search action=decision",
            required_toolsets=["experiment", "evidence"],
            priority="high",
            priority_score=10,
            source_ids=[item.get("id")],
            source_artifacts=[item.get("path")],
            related_ids=[item.get("id"), *(item.get("related_ids") or [])],
            instructions=(
                "Interpret why the objective failed. Mutate parameters, setup, "
                "route, or invariant only if the failure leaves a plausible path; "
                "otherwise use attack_search action=decision to reject the branch."
            ),
            required_evidence=[
                "mutation artifact with changed assumption",
                "or rejection decision linked to failed evaluation",
            ],
            stop_condition="Do not report a branch with failed or unmatched objectives.",
        ))

    candidate_fuzz_failures = await _progress_candidate_fuzz_runs(container, state)
    for item in candidate_fuzz_failures:
        add(_attack_search_candidate(
            key=f"fuzz:{item.get('id')}:reduce",
            source="candidate_fuzz_failure",
            title=f"Reduce fuzz/invariant candidate failure: {item.get('title')}",
            status="needs_reduction",
            next_tool="summarize_trace or extract_call_sequence",
            required_toolsets=["experiment", "evidence"],
            priority="high",
            priority_score=12,
            source_ids=[item.get("id")],
            source_artifacts=[item.get("path"), item.get("log_path")],
            related_ids=[item.get("id"), *(item.get("related_ids") or [])],
            instructions=(
                "Extract the failing sequence and replay it as a concrete "
                "experiment with objective evidence."
            ),
            required_evidence=[
                "/workspace/campaign/sequences/*.json or trace summary",
                "replay log and objective evaluation",
            ],
            stop_condition="Reject harness-only failures that do not imply protocol impact.",
        ))

    sequence_minimizations = await _progress_sequence_minimizations_without_review(
        container,
        state,
    )
    for item in sequence_minimizations:
        add(_attack_search_candidate(
            key=f"minimization:{item.get('id')}:review",
            source="unreviewed_sequence_minimization",
            title=f"Review minimized replay evidence: {item.get('title')}",
            status="needs_finding_review",
            next_tool="review_finding_evidence",
            required_toolsets=["report"],
            priority="high",
            priority_score=9,
            source_ids=[item.get("id")],
            source_artifacts=[item.get("path")],
            related_ids=[item.get("id"), *(item.get("related_ids") or [])],
            instructions=(
                "Promote preserved minimized replay evidence into a finding "
                "evidence review only if it proves the objective and setup "
                "assumptions remain realistic."
            ),
            required_evidence=["/workspace/campaign/finding-reviews/*.json"],
            stop_condition="Mutate or reject if minimization preserved only a harness marker.",
        ))

    ready_finding_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/finding-reviews/",
        kind="finding_evidence",
    )
    for item in ready_finding_reviews:
        add(_attack_search_candidate(
            key=f"finding_review:{item.get('id')}:report",
            source="ready_finding_review",
            title=f"Run report-quality review for {item.get('title')}",
            status="needs_report_review",
            next_tool="review_report_quality",
            required_toolsets=["report"],
            priority=_attack_search_priority(item.get("severity")),
            priority_score=8,
            source_ids=[item.get("id")],
            source_artifacts=[item.get("path")],
            related_ids=[item.get("id")],
            instructions=(
                "Turn ready evidence into a bug-bounty-quality report draft "
                "with reproduction, impact, economics, assumptions, and remediation."
            ),
            required_evidence=["/workspace/campaign/report-reviews/*.json"],
            stop_condition="Do not submit until report_quality is ready.",
        ))

    ready_report_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/report-reviews/",
        kind="report_quality",
    )
    for item in ready_report_reviews:
        add(_attack_search_candidate(
            key=f"report_review:{item.get('id')}:submit",
            source="ready_report_review",
            title=f"Submit ready reviewed finding: {item.get('title')}",
            status="ready_to_submit",
            next_tool="submit_finding",
            required_toolsets=["report"],
            priority=_attack_search_priority(item.get("severity")),
            priority_score=25,
            source_ids=[item.get("id")],
            source_artifacts=[item.get("path")],
            related_ids=[item.get("id")],
            instructions=(
                "Submit only if the candidate is still in scope and the report "
                "review is ready. Link campaign ids, evidence review, report "
                "review, objective evaluation, and reproducible test output."
            ),
            required_evidence=["structured submitted finding"],
            stop_condition="If evidence changed, rerun review_report_quality first.",
        ))

    if not candidates:
        latest_plans = await _progress_campaign_plans(container, state)
        if latest_plans:
            top = latest_plans[0].get("top_branch") or {}
            add(_attack_search_candidate(
                key=f"plan:{latest_plans[0].get('id')}:top",
                source="latest_campaign_plan",
                title=f"Execute top campaign plan branch: {top.get('title') or latest_plans[0].get('title')}",
                status="needs_hypothesis",
                next_tool=top.get("recommended_next_tool") or "plan_attack_campaign",
                required_toolsets=["map", "experiment", "evidence"],
                priority=_attack_search_priority(top.get("priority")),
                priority_score=5,
                source_ids=[latest_plans[0].get("id"), top.get("id")],
                source_artifacts=[latest_plans[0].get("path")],
                instructions=(
                    "Execute the latest planner branch, then resync attack_search "
                    "so the deterministic state machine can advance."
                ),
                required_evidence=["artifact produced by the recommended next tool"],
                stop_condition="Refresh plan_attack_campaign if campaign state changed materially.",
            ))
        else:
            add(_attack_search_candidate(
                key="plan:refresh",
                source="needs_plan",
                title="Refresh campaign plan or map another subsystem",
                status="needs_hypothesis",
                next_tool="plan_attack_campaign",
                required_toolsets=["core"],
                priority="medium",
                priority_score=1,
                instructions=(
                    "No active process gaps were detected. Refresh the campaign "
                    "plan, deepen parameter/order exploration, or map another "
                    "high-value subsystem."
                ),
                required_evidence=["/workspace/campaign/plans/*.json or explicit decision"],
                stop_condition="Stop only after coverage and evidence show no viable branches remain.",
            ))

    return list(candidates.values())


def _attack_search_branch_status_rank(branch: dict) -> int:
    status = _attack_search_status(branch.get("status"))
    rank = _ATTACK_SEARCH_STATUS_ORDER.get(status, 50)
    if branch.get("source") in {"blocked_result", "failed_objective"}:
        if status == "needs_poc_repair":
            return rank
        return max(rank, _ATTACK_SEARCH_STATUS_ORDER["needs_harness"] + 1)
    if (
        branch.get("source") in {
            "attack_graph_candidate",
            "attack_graph_related_live_target",
            "attack_graph_state_model",
        }
        and status in {"needs_harness", "needs_inventory"}
    ):
        return min(rank, _ATTACK_SEARCH_STATUS_ORDER["needs_coverage"])
    return rank


# ── Expected-value / proof-cost branch scheduling ──────────────────────────
#
# Branch ordering used to be status -> priority -> priority_score. That keeps
# the controller disciplined but lets it over-focus a hard-to-prove branch while
# cheaper, higher-value branches wait. The scheduler below adds a budget-aware
# score for exploratory / proof-construction branches:
#
#   scheduling_score = expected_value_score
#                      - proof_cost_score
#                      - blocker_penalty
#                      + next_step_value
#
# It only reorders the exploratory and parked tiers; claim/evidence-adjacent
# (strict) statuses keep their strict precedence. All inputs are read from the
# branch dict, so the function is pure and deterministic — the sort key and the
# persisted score stamp both derive from it and can never disagree.

# Affordances that move or mint value. A value-moving entrypoint is where
# loss-of-funds impact lives, so its presence lifts a branch's expected value.
_VALUE_MOVING_AFFORDANCES = frozenset({
    "value_in_or_mint",
    "value_out_or_burn",
    "credit_or_liquidation",
    "market_or_router",
    "accepts_native_value",
    "cross_domain_or_message",
})

# Statuses whose appearance in a branch's transition history counts as a prior
# stall for the repeated-failure penalty. This is "how many times has this
# branch already failed/blocked/parked", distinct from its current status.
_ATTACK_SEARCH_FAILED_HISTORY_STATUSES = frozenset({
    "blocked_compile",
    "blocked_revert",
    "blocked_setup",
    "needs_poc_repair",
    "objective_failed",
    "needs_mutation",
    "parked_harness_limit",
    "parked_low_roi",
    "parked_needs_dependency",
    "parked_needs_live_context",
    "unproven_due_to_harness_limit",
})

# Structural proof cost implied by the branch's current status: roughly how much
# harness/proof work stands between here and bankable objective evidence. A
# fresh run is cheap; a compile/setup block or a failed objective is expensive.
_ATTACK_SEARCH_STATUS_PROOF_COST = {
    "ready_to_submit": 0,
    "needs_report_review": 0,
    "needs_finding_review": 0,
    "needs_evidence": 1,
    "needs_reduction": 1,
    "needs_run": 1,
    "running": 1,
    "needs_poc_repair": 2,
    "needs_partial_probe": 2,
    "needs_context": 2,
    "needs_mapping": 2,
    "needs_coverage": 2,
    "needs_inventory": 3,
    "needs_hypothesis": 3,
    "needs_concretization": 4,
    "needs_harness": 4,
    "needs_mutation": 5,
    "objective_failed": 5,
    "blocked_revert": 5,
    "blocked_compile": 6,
    "blocked_setup": 6,
    "parked_harness_limit": 6,
    "parked_low_roi": 6,
    "parked_needs_dependency": 6,
    "parked_needs_live_context": 6,
    "unproven_due_to_harness_limit": 6,
}

# Tokens that signal calldata/signature/callback/proof synthesis is required —
# a real, recurring source of proof cost in this harness.
_ATTACK_SEARCH_COMPLEX_ARG_TOKENS = (
    "signature",
    "permit",
    "callback",
    "calldata",
    "flash",
    "merkle",
    "proof",
    "selector",
    "delegatecall",
    "reentr",
)

# ── Curiosity / diversity budget ───────────────────────────────────────────
#
# A small, bounded novelty score lifts unusual, low-label "frontier" branches
# inside the exploratory tier so the scheduler does not over-focus the familiar,
# easy-to-prove DeFi patterns. It is strictly subordinate to evidence ordering:
# the bonus is capped, applies only to the exploratory tier, and never touches
# the strict (claim/evidence) tier or parked/terminal branches. Curiosity helps
# exploration; it never turns the controller into random search and never
# relaxes the submission gates.
_ATTACK_SEARCH_DIVERSITY_BONUS_CAP = 6
# Source tag for controller-created frontier branches (see
# _attack_search_frontier_candidates). Also a strong novelty signal.
_ATTACK_SEARCH_FRONTIER_SOURCE = "attack_graph_frontier"
# Branch sources that represent an untested/open coverage gap.
_ATTACK_SEARCH_OPEN_GAP_SOURCES = frozenset({
    "coverage_high_attention_gap",
    "action_space_without_coverage",
})
# Generic, non-DeFi mechanism labels. Their presence means the mechanism
# classifier found no recognized economic pattern — a novelty signal, since the
# branch is a bland state transition the lexical heuristics did not tag.
_ATTACK_SEARCH_GENERIC_MECHANISMS = frozenset({
    "generic_state_transition",
    "generic_execution",
})
# Lexical tokens that name a recognized DeFi/vuln pattern. If a branch's text
# matches none of these yet it still mutates state or crosses a boundary, the
# action is structurally interesting but lexically unlabeled — exactly the kind
# of novelty the frontier preserves.
_ATTACK_SEARCH_KNOWN_PATTERN_TOKENS = (
    "reentr",
    "oracle",
    "price",
    "flash",
    "liquidat",
    "collateral",
    "vault",
    "lending",
    "borrow",
    "amm",
    "swap",
    "router",
    "bridge",
    "stake",
    "staking",
    "rounding",
    "slippage",
    "permit",
    "signature",
    "approve",
    "allowance",
    "mint",
    "burn",
    "interest",
    "debt",
    "share",
)


def _attack_search_branch_has_live_exposure(branch: dict) -> bool:
    binding = branch.get("target_binding")
    if isinstance(binding, dict) and (
        binding.get("live_deployed")
        or binding.get("economically_significant_hint")
        or str(binding.get("economic_priority") or "").lower() in {"high", "critical"}
    ):
        return True
    inventory_context = branch.get("inventory_context")
    if isinstance(inventory_context, dict) and int(
        inventory_context.get("economically_significant_targets", 0) or 0
    ) > 0:
        return True
    return False


def _attack_search_branch_has_value_affordance(branch: dict) -> bool:
    for action in branch.get("target_actions") or []:
        if not isinstance(action, dict):
            continue
        for affordance in action.get("affordances") or []:
            if str(affordance) in _VALUE_MOVING_AFFORDANCES:
                return True
    return False


def _attack_search_branch_failed_history(branch: dict) -> int:
    count = 0
    for event in branch.get("history") or []:
        if not isinstance(event, dict):
            continue
        target = str(event.get("to") or event.get("status") or "")
        if target in _ATTACK_SEARCH_FAILED_HISTORY_STATUSES:
            count += 1
    return count


def _attack_search_branch_needs_complex_args(branch: dict) -> bool:
    parts = [
        str(branch.get("instructions") or ""),
        str(branch.get("root_mechanism") or ""),
        str(branch.get("next_tool") or ""),
        _attack_search_branch_objective(branch),
    ]
    for action in branch.get("target_actions") or []:
        if isinstance(action, dict):
            parts.extend(str(item) for item in action.get("affordances") or [])
    haystack = " ".join(parts).lower()
    return any(token in haystack for token in _ATTACK_SEARCH_COMPLEX_ARG_TOKENS)


def _attack_search_branch_affordance_set(branch: dict) -> set[str]:
    """All affordance labels attached to a branch's target actions."""
    labels: set[str] = set()
    for action in branch.get("target_actions") or []:
        if isinstance(action, dict):
            labels.update(str(item) for item in action.get("affordances") or [])
    return labels


def _attack_search_branch_structural_affordances(branch: dict) -> list[str]:
    """Sorted structural (state-mutation / external-boundary) affordances on a
    branch. These are the labels that make a low-economic-signal action still
    worth a curiosity look. The affordance taxonomy lives in the attack-graph
    section (``_ATTACK_GRAPH_*_AFFORDANCES``); referencing it here keeps a single
    source of truth."""
    structural = _ATTACK_GRAPH_STATE_MUTATOR_AFFORDANCES | _ATTACK_GRAPH_BOUNDARY_AFFORDANCES
    return sorted(_attack_search_branch_affordance_set(branch) & structural)


def _attack_search_branch_exposure(branch: dict) -> str:
    """Best-known live-exposure label for a branch (``source_only`` etc.).

    Prefers an explicit branch ``exposure`` (set on controller-created frontier
    branches), then falls back to any ``live_exposure`` carried by a source-only
    candidate action."""
    exposure = str(branch.get("exposure") or "").strip().lower()
    if exposure:
        return exposure
    for action in branch.get("target_actions") or []:
        if isinstance(action, dict):
            live_exposure = str(action.get("live_exposure") or "").strip().lower()
            if live_exposure:
                return live_exposure
    return ""


def _attack_search_branch_mechanism(branch: dict) -> str:
    return str(branch.get("root_mechanism") or branch.get("mechanism") or "").strip().lower()


def _attack_search_branch_has_core_call(branch: dict) -> bool:
    """True when the branch names a concrete callable (action key or
    contract/function) — i.e. there is something to actually go probe."""
    if branch.get("action_keys"):
        return True
    for action in branch.get("target_actions") or []:
        if not isinstance(action, dict):
            continue
        if (
            action.get("action_key")
            or action.get("key")
            or (action.get("contract") and action.get("function"))
            or action.get("function")
        ):
            return True
    return False


def _attack_search_branch_has_source_reference(branch: dict) -> bool:
    """True when the branch points at a concrete artifact or source location."""
    if branch.get("source_artifacts") or branch.get("source_ids"):
        return True
    if branch.get("frontier_source"):
        return True
    for action in branch.get("target_actions") or []:
        if not isinstance(action, dict):
            continue
        if action.get("file"):
            return True
        source = action.get("source")
        if isinstance(source, dict) and (source.get("file") or source.get("signature")):
            return True
    return False


def _attack_search_branch_matches_known_pattern(branch: dict) -> bool:
    """True when the branch's text lexically names a recognized DeFi/vuln
    pattern. The absence of a match (with structural affordances present) is a
    novelty signal: the action is interesting but unlabeled."""
    parts = [
        str(branch.get("title") or ""),
        str(branch.get("root_mechanism") or branch.get("mechanism") or ""),
        _attack_search_branch_objective(branch),
    ]
    haystack = " ".join(parts).lower()
    return any(token in haystack for token in _ATTACK_SEARCH_KNOWN_PATTERN_TOKENS)


def _attack_search_novelty_score(branch: dict) -> tuple[int, list[str]]:
    """Bounded novelty score for a branch plus the reasons behind it.

    Pure and deterministic. Positive signals reward unusual, low-label,
    source-only / frontier branches — the ones the lexical economic heuristics
    tend to skip — so the scheduler keeps a few of them visible. Negative
    signals discount branches that have already repeatedly stalled or carry no
    concrete call/source to investigate. The score is only ever consumed as a
    small, capped diversity bonus for exploratory branches
    (:func:`_attack_search_scheduling`); it never reorders the strict
    claim/evidence tier and never relaxes the submission gates.
    """
    score = 0
    reasons: list[str] = []

    source = str(branch.get("source") or "")
    if source == _ATTACK_SEARCH_FRONTIER_SOURCE or branch.get("frontier_source"):
        score += 3
        reasons.append("attack_graph_frontier branch")

    if _attack_search_branch_exposure(branch) == "source_only":
        score += 2
        reasons.append("source_only exposure (live context unmapped)")

    mechanism = _attack_search_branch_mechanism(branch)
    if mechanism in _ATTACK_SEARCH_GENERIC_MECHANISMS:
        score += 2
        reasons.append(f"generic mechanism ({mechanism})")

    affordances = _attack_search_branch_affordance_set(branch)
    structural = affordances & (
        _ATTACK_GRAPH_STATE_MUTATOR_AFFORDANCES | _ATTACK_GRAPH_BOUNDARY_AFFORDANCES
    )
    known_defi = affordances & (
        _ATTACK_GRAPH_VALUE_AFFORDANCES | _ATTACK_GRAPH_OTHER_MEANINGFUL_AFFORDANCES
    )
    if structural and not known_defi:
        score += 2
        reasons.append("structural affordances without recognized DeFi labels")

    if source in _ATTACK_SEARCH_OPEN_GAP_SOURCES:
        score += 1
        reasons.append("low historical coverage / open gap")

    if structural and not _attack_search_branch_matches_known_pattern(branch):
        score += 2
        reasons.append("state mutation / external boundary, no lexical pattern match")

    if _attack_search_branch_failed_history(branch) > 0:
        score -= 2
        reasons.append("discounted: repeatedly failed/parked")
    if not (
        _attack_search_branch_has_core_call(branch)
        or _attack_search_branch_has_source_reference(branch)
    ):
        score -= 2
        reasons.append("discounted: no concrete call or source reference")

    return score, reasons


def _attack_search_scheduling(branch: dict) -> dict:
    """Conservative expected-value / proof-cost scheduling scores for a branch.

    Pure and deterministic. ``scheduling_score`` is
    ``expected_value_score - proof_cost_score - blocker_penalty +
    next_step_value + diversity_bonus`` and may go negative for an expensive,
    repeatedly-stalled branch; the component scores are non-negative. The
    ``diversity_bonus`` is a small, capped curiosity nudge applied only to the
    exploratory tier (never to strict/parked/terminal branches), so unusual,
    low-label frontier branches stay visible without ever outranking
    claim/evidence work.
    """
    status = _attack_search_status(branch.get("status"))
    priority = _attack_search_priority(branch.get("priority"))
    try:
        priority_score = int(branch.get("priority_score", 0) or 0)
    except (TypeError, ValueError):
        priority_score = 0
    # Clamp the aggregate so a malformed huge value cannot swamp every branch.
    priority_score = max(-40, min(priority_score, 80))

    # Expected value: lean on the already-reranked priority_score (it folds in
    # the live-inventory rerank), then nudge for severity, live exposure,
    # value-moving affordances, and a concrete objective.
    expected_value = priority_score
    expected_value += {"critical": 6, "high": 4, "medium": 2, "low": 0}[priority]
    if _attack_search_branch_has_live_exposure(branch):
        expected_value += 6
    if _attack_search_branch_has_value_affordance(branch):
        expected_value += 4
    if _attack_search_branch_objective(branch):
        expected_value += 3
    expected_value = max(0, expected_value)

    # Proof cost: structural difficulty of getting from here to objective
    # evidence — current status, inventory hard/missing blockers, harness-limit
    # blockers on a materialized sequence, and calldata/signature synthesis.
    proof_cost = _ATTACK_SEARCH_STATUS_PROOF_COST.get(status, 3)
    inventory_context = branch.get("inventory_context")
    if isinstance(inventory_context, dict):
        if inventory_context.get("hard_blockers"):
            proof_cost += 5
        if inventory_context.get("missing_targets"):
            proof_cost += 2
    sequence_quality = branch.get("sequence_quality")
    if isinstance(sequence_quality, dict):
        readiness = str(sequence_quality.get("proof_readiness") or "")
        if readiness == "blocked":
            proof_cost += 4
        elif readiness == "partial":
            proof_cost += 2
        proof_cost += min(4, len(sequence_quality.get("harness_limit_blockers") or []))
    if _attack_search_branch_needs_complex_args(branch):
        proof_cost += 2
    proof_cost = max(0, min(proof_cost, 30))

    # Repeated-failure penalty: grows with how often this branch has already
    # stalled (failed/blocked/parked transitions in its history).
    blocker_penalty = min(24, 4 * _attack_search_branch_failed_history(branch))

    # Next-step value: banked evidence plus proximity to bankable evidence. A
    # branch one run from a result, or one decision from freeing its slot, stays
    # competitive rather than rotting at the bottom of the queue.
    next_step_value = 0
    evidence = branch.get("evidence")
    if isinstance(evidence, list):
        next_step_value += min(8, 2 * len(evidence))
    if status in {"needs_run", "running", "needs_partial_probe"}:
        next_step_value += 3
    elif status in {"objective_failed", "needs_mutation"}:
        next_step_value += 3
    elif status == "needs_poc_repair":
        next_step_value += 4
    next_step_value = max(0, min(next_step_value, 16))

    # Curiosity / diversity budget: a small, capped novelty bonus that applies
    # ONLY to the exploratory tier. Strict (claim/evidence) work is never lifted
    # by it, and parked/terminal branches stay below active work, so the bonus
    # can shuffle which exploratory branch leads but never override evidence
    # ordering. Novelty itself is computed for every branch (for visibility), but
    # only spent as scheduling weight where the tier allows it.
    novelty_score, novelty_reasons = _attack_search_novelty_score(branch)
    curiosity_eligible = (
        _attack_search_branch_tier(branch) == _ATTACK_SEARCH_TIER_EXPLORATORY
    )
    diversity_bonus = (
        max(0, min(novelty_score, _ATTACK_SEARCH_DIVERSITY_BONUS_CAP))
        if curiosity_eligible
        else 0
    )
    positive_reasons = [
        reason for reason in novelty_reasons if not reason.startswith("discounted")
    ]
    diversity_reason = "; ".join(positive_reasons)
    scheduling_notes: list[str] = []
    if curiosity_eligible and diversity_bonus:
        scheduling_notes.append(
            f"curiosity/diversity bonus +{diversity_bonus} (novelty_score={novelty_score})"
        )
        scheduling_notes.extend(novelty_reasons)
    elif novelty_score > 0:
        scheduling_notes.append(
            f"novelty_score={novelty_score} not applied (branch is not exploratory)"
        )

    scheduling = (
        expected_value - proof_cost - blocker_penalty + next_step_value + diversity_bonus
    )
    return {
        "expected_value_score": int(expected_value),
        "proof_cost_score": int(proof_cost),
        "blocker_penalty": int(blocker_penalty),
        "next_step_value": int(next_step_value),
        "novelty_score": int(novelty_score),
        "diversity_bonus": int(diversity_bonus),
        "curiosity_budget_eligible": bool(curiosity_eligible),
        "diversity_reason": diversity_reason,
        "scheduling_notes": scheduling_notes,
        "scheduling_score": int(scheduling),
    }


def _attack_search_score_branch(branch: dict) -> None:
    """Stamp the scheduling scores onto a branch for the response/persistence.

    The sort key recomputes the same scores, so stamping is purely so the
    model-visible compact branch and the saved current.json carry them. Does
    not touch agent-supplied parking_reason/recommended_budget.
    """
    if isinstance(branch, dict):
        branch.update(_attack_search_scheduling(branch))


# Scheduling tiers. The tier is the first sort element, so it strictly dominates
# the scheduling score: strict (claim/evidence) work is never reordered by an
# exploration heuristic, and parked branches always sit below active work.
_ATTACK_SEARCH_TIER_STRICT = 0
_ATTACK_SEARCH_TIER_EXPLORATORY = 1
_ATTACK_SEARCH_TIER_PARKED = 2
_ATTACK_SEARCH_TIER_TERMINAL = 3
_ATTACK_SEARCH_TIER_LABELS = {
    _ATTACK_SEARCH_TIER_STRICT: "strict_evidence",
    _ATTACK_SEARCH_TIER_EXPLORATORY: "exploratory",
    _ATTACK_SEARCH_TIER_PARKED: "parked",
    _ATTACK_SEARCH_TIER_TERMINAL: "terminal",
}


def _attack_search_branch_tier(branch: dict) -> int:
    if _attack_search_branch_terminal(branch):
        return _ATTACK_SEARCH_TIER_TERMINAL
    status = _attack_search_status(branch.get("status"))
    if status in _ATTACK_SEARCH_PARKED_STATUSES:
        return _ATTACK_SEARCH_TIER_PARKED
    if status in _ATTACK_SEARCH_STRICT_STATUSES:
        return _ATTACK_SEARCH_TIER_STRICT
    return _ATTACK_SEARCH_TIER_EXPLORATORY


def _attack_search_branch_sort_key(
    branch: dict,
) -> tuple[int, int, int, int, int, str]:
    tier = _attack_search_branch_tier(branch)
    priority = _ATTACK_SEARCH_PRIORITY_ORDER.get(
        _attack_search_priority(branch.get("priority")),
        9,
    )
    status_rank = _attack_search_branch_status_rank(branch)
    priority_score = -int(branch.get("priority_score", 0) or 0)
    # Strict and terminal tiers keep deterministic status-rank precedence (a
    # ready-to-submit or needs-evidence branch must never be reordered by an
    # exploration heuristic). Exploratory and parked tiers schedule by
    # expected-value/proof-cost so cheap, high-value branches rise and
    # expensive, repeatedly-stalled ones sink. The status-rank/priority tail
    # keeps the old behavior as a tie-breaker when scheduling scores match, so
    # branches with no scheduling signal preserve their historical order.
    if tier in (_ATTACK_SEARCH_TIER_STRICT, _ATTACK_SEARCH_TIER_TERMINAL):
        scheduling_component = 0
    else:
        scheduling_component = -_attack_search_scheduling(branch)["scheduling_score"]
    return (
        tier,
        scheduling_component,
        status_rank,
        priority,
        priority_score,
        str(branch.get("id") or ""),
    )


def _attack_search_branch_selection_summary(branch: dict) -> dict:
    scheduling = _attack_search_scheduling(branch)
    tier = _attack_search_branch_tier(branch)
    status = _attack_search_status(branch.get("status"))
    summary = {
        "branch_id": branch.get("id"),
        "status": status,
        "source": branch.get("source"),
        "next_tool": branch.get("next_tool"),
        "tier": _ATTACK_SEARCH_TIER_LABELS.get(tier, str(tier)),
        "status_rank": _attack_search_branch_status_rank(branch),
        "priority": _attack_search_priority(branch.get("priority")),
        "priority_score": int(branch.get("priority_score", 0) or 0),
        "scheduling_score": scheduling["scheduling_score"],
        "expected_value_score": scheduling["expected_value_score"],
        "proof_cost_score": scheduling["proof_cost_score"],
        "blocker_penalty": scheduling["blocker_penalty"],
        "next_step_value": scheduling["next_step_value"],
    }
    if scheduling.get("diversity_bonus"):
        summary["diversity_bonus"] = scheduling["diversity_bonus"]
    return {
        key: value
        for key, value in summary.items()
        if value not in (None, "", [], {})
    }


def _attack_search_not_selected_reason(selected: dict, alternative: dict) -> str:
    selected_key = _attack_search_branch_sort_key(selected)
    alternative_key = _attack_search_branch_sort_key(alternative)
    if alternative_key < selected_key:
        return (
            "would rank ahead by scheduler, but the current selected_branch_id is "
            "pinned until action=advance, action=decision, or branch completion"
        )
    selected_tier = _attack_search_branch_tier(selected)
    alternative_tier = _attack_search_branch_tier(alternative)
    if alternative_tier > selected_tier:
        return (
            "lower scheduling tier "
            f"({_ATTACK_SEARCH_TIER_LABELS.get(alternative_tier, alternative_tier)} "
            "vs "
            f"{_ATTACK_SEARCH_TIER_LABELS.get(selected_tier, selected_tier)})"
        )
    selected_sched = _attack_search_scheduling(selected)["scheduling_score"]
    alternative_sched = _attack_search_scheduling(alternative)["scheduling_score"]
    if alternative_sched < selected_sched:
        return (
            "lower scheduling_score "
            f"({alternative_sched} vs {selected_sched})"
        )
    selected_rank = _attack_search_branch_status_rank(selected)
    alternative_rank = _attack_search_branch_status_rank(alternative)
    if alternative_rank > selected_rank:
        return (
            "lower status precedence "
            f"({alternative_rank} vs {selected_rank}) after scheduling tie"
        )
    return "sorted after the selected branch by priority, priority_score, or branch id"


def _attack_search_selected_reason(selected: dict, ranked: list[dict]) -> str:
    if ranked and ranked[0] is not selected:
        return (
            "explicit selected_branch_id is still active; controller preserves it "
            "until action=advance, action=decision, or branch completion"
        )
    tier = _attack_search_branch_tier(selected)
    if tier == _ATTACK_SEARCH_TIER_STRICT:
        return "selected from strict evidence/submission tier by status precedence"
    if tier == _ATTACK_SEARCH_TIER_PARKED:
        return "selected only because no active non-parked branches outranked it"
    if tier == _ATTACK_SEARCH_TIER_TERMINAL:
        return "terminal branch surfaced only because no active branch remains"
    return "selected as highest-ranked active exploratory branch by scheduling score"


def _attack_search_selection_rationale(
    selected: dict,
    active_branches: list[dict],
) -> dict:
    ranked = sorted(active_branches, key=_attack_search_branch_sort_key)
    alternatives = []
    for branch in ranked:
        if branch is selected:
            continue
        summary = _attack_search_branch_selection_summary(branch)
        summary["reason_not_selected"] = _attack_search_not_selected_reason(
            selected,
            branch,
        )
        alternatives.append(summary)
        if len(alternatives) >= 3:
            break
    return {
        "selected": _attack_search_branch_selection_summary(selected),
        "selected_reason": _attack_search_selected_reason(selected, ranked),
        "top_alternatives": alternatives,
    }


def _attack_search_merge_candidates(search: dict, candidates: list[dict]) -> None:
    now = datetime.now(timezone.utc).isoformat()
    existing = {
        str(branch.get("key") or ""): branch
        for branch in search.get("branches", [])
        if branch.get("key")
    }
    candidate_keys = {candidate["key"] for candidate in candidates}
    merged = []

    for candidate in candidates:
        branch = existing.get(candidate["key"])
        if branch is None:
            branch = {
                "id": _attack_search_next_branch_id(search),
                "created_at": now,
                "history": [],
            }
            branch["history"].append({
                "at": now,
                "event": "created",
                "status": candidate["status"],
                "reason": candidate["source"],
            })
        elif _attack_search_branch_terminal(branch):
            merged.append(branch)
            continue

        previous_status = branch.get("status")
        preserved_history = branch.get("history") or []
        preserved_created = branch.get("created_at") or now
        preserved_selected = branch.get("selected", False)
        preserved_evidence = branch.get("evidence") or []
        preserved_related_ids = branch.get("related_ids") or []
        branch.update(candidate)
        branch["created_at"] = preserved_created
        branch["updated_at"] = now
        branch["selected"] = preserved_selected
        branch["history"] = preserved_history
        branch["evidence"] = sorted(dict.fromkeys([
            *preserved_evidence,
            *(candidate.get("evidence") or []),
        ]))
        branch["related_ids"] = sorted(dict.fromkeys([
            *preserved_related_ids,
            *(candidate.get("related_ids") or []),
        ]))
        # Parking is usually an agent judgment ("not worth current budget until
        # better calldata/signature/protocol/dependency/live-context setup
        # exists"). The controller also derives parked_needs_live_context when a
        # source-only/generic branch still lacks a deployed target after live
        # reachability was attempted. In both cases a re-sync must not silently
        # un-park it. Keep the parked status while refreshing the rest of the
        # branch from the live candidate; the agent un-parks explicitly with
        # action=advance (or terminates with decision).
        if (
            previous_status in _ATTACK_SEARCH_PARKED_STATUSES
            and not _attack_search_branch_terminal(branch)
        ):
            branch["status"] = previous_status
        if previous_status and previous_status != branch.get("status"):
            branch["history"].append({
                "at": now,
                "event": "status_changed",
                "from": previous_status,
                "to": branch.get("status"),
                "reason": "sync",
            })
        merged.append(branch)

    for branch in search.get("branches", []):
        key = str(branch.get("key") or "")
        if key in candidate_keys:
            continue
        if _attack_search_branch_terminal(branch):
            merged.append(branch)
            continue
        previous_status = branch.get("status")
        branch["status"] = "superseded"
        branch["updated_at"] = now
        branch.setdefault("history", []).append({
            "at": now,
            "event": "status_changed",
            "from": previous_status,
            "to": "superseded",
            "reason": "no longer appears in synced campaign gaps",
        })
        merged.append(branch)

    search["branches"] = sorted(merged, key=_attack_search_branch_sort_key)


def _attack_search_find_branch(search: dict, branch_id: str) -> dict | None:
    for branch in search.get("branches", []):
        if branch.get("id") == branch_id:
            return branch
    return None


def _attack_search_select(search: dict, branch_id: str) -> str | None:
    branch = _attack_search_find_branch(search, branch_id)
    if not branch:
        return f"no branch with id '{branch_id}'"
    for item in search.get("branches", []):
        item["selected"] = item.get("id") == branch_id
    search["selected_branch_id"] = branch_id
    return None


def _attack_search_branch_action_key_set(branch: dict) -> set[str]:
    keys = {
        str(item).strip()
        for item in branch.get("action_keys") or []
        if str(item).strip()
    }
    for action in branch.get("target_actions") or []:
        if not isinstance(action, dict):
            continue
        action_key = str(action.get("key") or action.get("action_key") or "").strip()
        if not action_key:
            contract = str(action.get("contract") or "").strip()
            function = str(action.get("function") or "").strip()
            if contract and function:
                action_key = f"{contract}::{function}"
        if action_key:
            keys.add(action_key)
    required_args = branch.get("required_args") or {}
    for tool_args in required_args.values():
        if not isinstance(tool_args, dict):
            continue
        for action in tool_args.get("actions") or []:
            if not isinstance(action, dict):
                continue
            action_key = str(action.get("action_key") or "").strip()
            if not action_key:
                contract = str(action.get("contract") or "").strip()
                function = str(action.get("function") or "").strip()
                if contract and function:
                    action_key = f"{contract}::{function}"
            if action_key:
                keys.add(action_key)
    return keys


def _attack_search_branch_target_set(
    branch: dict,
    *,
    include_related: bool = True,
) -> set[str]:
    targets = set()

    def add(value: object) -> None:
        address = _solidity_address_literal(value)
        if address:
            targets.add(address.lower())

    target_binding = branch.get("target_binding") or {}
    if isinstance(target_binding, dict):
        add(target_binding.get("original_address"))
        add(target_binding.get("target_address"))
        if include_related:
            add(target_binding.get("recommended_call_target"))
            for related in target_binding.get("related_live_targets") or []:
                if isinstance(related, dict):
                    add(related.get("address"))
    if include_related:
        for value in branch.get("normalized_target_keys") or []:
            add(value)
        inventory_context = branch.get("inventory_context") or {}
        if isinstance(inventory_context, dict):
            for related in inventory_context.get("recommended_call_targets") or []:
                if isinstance(related, dict):
                    add(related.get("to"))
            for related in inventory_context.get("related_live_targets") or []:
                if isinstance(related, dict):
                    add(related.get("to"))
    for action in branch.get("target_actions") or []:
        if isinstance(action, dict):
            add(action.get("target") or action.get("target_address") or action.get("address"))
    required_args = branch.get("required_args") or {}
    for tool_args in required_args.values():
        if not isinstance(tool_args, dict):
            continue
        for value in (tool_args.get("target_addresses") or {}).values():
            add(value)
        for action in tool_args.get("actions") or []:
            if isinstance(action, dict):
                add(action.get("target") or action.get("target_address") or action.get("address"))
    for attack_key in branch.get("attack_keys") or []:
        for match in re.findall(r"0x[a-fA-F0-9]{40}", str(attack_key)):
            add(match)
    return targets


_ACTION_FAMILY_VARIANT_TOKENS = {
    "all",
    "behalf",
    "on",
    "self",
    "to",
}


def _action_family_tokenize(value: str) -> list[str]:
    spaced = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", value)
    spaced = re.sub(r"[^A-Za-z0-9]+", " ", spaced)
    tokens = []
    for token in spaced.lower().split():
        if token in _ACTION_FAMILY_VARIANT_TOKENS:
            continue
        if token.endswith("ies") and len(token) > 4:
            token = token[:-3] + "y"
        elif token.endswith("s") and len(token) > 4:
            token = token[:-1]
        if token:
            tokens.append(token)
    return tokens


def _action_family_from_action_key(action_key: str) -> str:
    contract, _, function = action_key.partition("::")
    contract_tokens = _action_family_tokenize(contract)
    function_tokens = _action_family_tokenize(function or contract)
    if not contract_tokens or not function_tokens:
        return _coverage_normalize_text(action_key).replace(" ", "_")
    return f"{'_'.join(contract_tokens)}::{'_'.join(function_tokens)}"


def _target_action_family_keys(
    *,
    action_keys: set[str],
    targets: set[str],
) -> set[str]:
    families = {
        _action_family_from_action_key(action_key)
        for action_key in action_keys
        if str(action_key).strip()
    }
    if not families:
        return set()
    if not targets:
        return set()
    return {f"{target}:{family}" for target in targets for family in families}


def _attack_search_branch_action_family_key_set(branch: dict) -> set[str]:
    stored = {
        str(item).strip()
        for item in branch.get("action_family_keys") or []
        if str(item).strip()
    }
    if stored:
        return stored
    return _target_action_family_keys(
        action_keys=_attack_search_branch_action_key_set(branch),
        targets=_attack_search_branch_target_set(branch, include_related=False),
    )


def _attack_candidate_action_family_key_set(candidate: dict) -> set[str]:
    targets = {
        str(value).lower()
        for value in _attack_candidate_target_addresses(candidate).values()
        if _solidity_address_literal(value)
    }
    return _target_action_family_keys(
        action_keys=set(_attack_candidate_action_keys(candidate)),
        targets=targets,
    )


def _attack_search_branch_clone_family_key_set(branch: dict) -> set[str]:
    stored = {
        str(item).strip()
        for item in branch.get("clone_family_keys") or []
        if str(item).strip()
    }
    if stored:
        return stored
    keys = set()
    for action in branch.get("target_actions") or []:
        if isinstance(action, dict):
            key = str(action.get("clone_family_key") or "").strip()
            if key:
                keys.add(key)
    return keys


def _candidate_clone_fingerprint(candidate: dict) -> str:
    for key in ("clone_fingerprint", "code_hash", "profile_src", "source_hash"):
        value = str(candidate.get(key) or "").strip()
        if value:
            return _coverage_normalize_text(value).replace(" ", "_")
    target_binding = candidate.get("target_binding") or {}
    if isinstance(target_binding, dict):
        for key in ("code_hash", "implementation_code_hash", "source_hash"):
            value = str(target_binding.get(key) or "").strip()
            if value:
                return _coverage_normalize_text(value).replace(" ", "_")
    return ""


def _attack_candidate_clone_family_key_set(candidate: dict) -> set[str]:
    stored = {
        str(item).strip()
        for item in candidate.get("clone_family_keys") or []
        if str(item).strip()
    }
    if stored:
        return stored
    fingerprint = _candidate_clone_fingerprint(candidate)
    if not fingerprint:
        return set()
    action_keys = set(_attack_candidate_action_keys(candidate))
    if not action_keys:
        return set()
    reachability = str((candidate.get("reachability") or {}).get("kind") or "unknown")
    return {
        f"{fingerprint}:{reachability}:{_action_family_from_action_key(action_key)}"
        for action_key in action_keys
    }


_TARGET_LEVEL_INVALIDITY_TERMS = (
    "no code",
    "no deployed bytecode",
    "dormant",
    "wrong address",
    "wrong target",
    "wrong proxy",
    "implementation",
    "template",
    "empty reserve",
    "empty reserves",
    "no economic state",
    "uninitialized",
    "not initialized",
    "zero supply",
    "zero total supply",
    "total supply 0",
    "no collateral",
    "collateral 0",
    "zero reserve",
    "zero reserves",
    "not live",
    "not the live",
    "target binding",
)


def _attack_search_target_level_invalidity(
    branch: dict,
    *,
    decision_text: str,
    failed_assumption: str,
) -> bool:
    inventory_context = branch.get("inventory_context") or {}
    if isinstance(inventory_context, dict) and inventory_context.get("hard_blockers"):
        return True
    target_binding = branch.get("target_binding") or {}
    if isinstance(target_binding, dict):
        kind = str(
            target_binding.get("kind")
            or target_binding.get("binding_kind")
            or ""
        )
        if kind in {"no_code", "deployed_implementation_or_template"}:
            return True
    text = _coverage_normalize_text(f"{decision_text} {failed_assumption}")
    if not text:
        return False
    return any(term in text for term in _TARGET_LEVEL_INVALIDITY_TERMS)


_MECHANISM_LEVEL_DECISION_TERMS = (
    "same authorization",
    "authorization gate",
    "same gate",
    "same modifier",
    "same mechanism",
    "same blocker",
    "same role check",
    "role check",
    "msg sender",
    "self claim",
    "self only",
    "only caller",
    "no unauthorized",
    "no attacker profit",
    "no profit",
    "no balance delta",
    "claimer unauthorized",
    "only emission manager",
)


_COVERAGE_FAMILY_DECISION_TERMS = (
    "same helper",
    "helper family",
    "library helper",
    "governance library",
    "same test",
    "test wrapper",
    "mock",
    "fixture",
    "interface-only",
    "interface only",
    "certora",
    "spec harness",
    "deploy script",
    "deployment helper",
    "generated wrapper",
    "same coverage family",
)


def _attack_search_mechanism_level_decision(
    *,
    decision_text: str,
    failed_assumption: str,
    impact_assessment: str,
) -> bool:
    text = _coverage_normalize_text(
        f"{decision_text} {failed_assumption} {impact_assessment}"
    )
    if not text:
        return False
    return any(term in text for term in _MECHANISM_LEVEL_DECISION_TERMS)


def _attack_search_coverage_family_decision(
    *,
    decision_text: str,
    failed_assumption: str,
    impact_assessment: str,
) -> bool:
    text = _coverage_normalize_text(
        f"{decision_text} {failed_assumption} {impact_assessment}"
    )
    if not text:
        return False
    return any(term in text for term in _COVERAGE_FAMILY_DECISION_TERMS)


def _attack_search_branch_action_contracts(branch: dict) -> set[str]:
    return {
        _coverage_normalize_text(str(action.get("contract") or ""))
        for action in branch.get("target_actions") or []
        if isinstance(action, dict) and str(action.get("contract") or "").strip()
    }


def _attack_search_branch_action_files(branch: dict) -> set[str]:
    return {
        posixpath.normpath(str(action.get("file") or ""))
        for action in branch.get("target_actions") or []
        if isinstance(action, dict) and str(action.get("file") or "").strip()
    }


def _attack_search_supersede_subsumed_siblings(
    search: dict,
    decided_branch: dict,
    *,
    action_keys: set[str],
    action_family_keys: set[str],
    clone_family_keys: set[str],
    target_level_invalidity: bool,
    mechanism_level_decision: bool,
    coverage_family_decision: bool,
    decision_id: str,
    evidence: list[str],
    related_ids: list[str],
    now: str,
) -> None:
    if decided_branch.get("source") == "coverage_high_attention_gap":
        if not action_keys and not coverage_family_decision:
            return
        decided_contracts = _attack_search_branch_action_contracts(decided_branch)
        decided_files = _attack_search_branch_action_files(decided_branch)
        for branch in search.get("branches", []):
            if branch is decided_branch or _attack_search_branch_terminal(branch):
                continue
            if branch.get("source") != "coverage_high_attention_gap":
                continue
            if _attack_search_status(branch.get("status")) not in {
                "needs_context",
                "needs_hypothesis",
            }:
                continue
            branch_action_keys = _attack_search_branch_action_key_set(branch)
            branch_family_keys = _attack_search_branch_action_family_key_set(branch)
            branch_contracts = _attack_search_branch_action_contracts(branch)
            branch_files = _attack_search_branch_action_files(branch)
            supersede_reason = ""
            if branch_action_keys and branch_action_keys.issubset(action_keys):
                supersede_reason = "same_coverage_action"
            elif coverage_family_decision and (
                branch_contracts.intersection(decided_contracts)
                or branch_files.intersection(decided_files)
                or branch_family_keys.intersection(action_family_keys)
            ):
                supersede_reason = "same_coverage_family"
            if not supersede_reason:
                continue
            previous = branch.get("status")
            branch["status"] = "superseded"
            branch["terminal_decision"] = True
            branch["decision_id"] = decision_id
            if supersede_reason == "same_coverage_family":
                reason_text = (
                    "the same helper/mock/interface or repeated coverage family "
                    "was already decided."
                )
            else:
                reason_text = (
                    "the same coverage action path was already decided."
                )
            branch["decision"] = f"Superseded by {decision_id}: {reason_text}"
            branch["updated_at"] = now
            branch["evidence"] = sorted(dict.fromkeys([
                *(branch.get("evidence") or []),
                decision_id,
                *evidence,
            ]))
            branch["related_ids"] = sorted(dict.fromkeys([
                *(branch.get("related_ids") or []),
                decision_id,
                *related_ids,
            ]))
            branch.setdefault("history", []).append({
                "at": now,
                "event": "decision",
                "from": previous,
                "to": "superseded",
                "decision_id": decision_id,
                "decision_status": "superseded",
                "decision": branch["decision"],
                "evidence": evidence,
                "related_ids": related_ids,
            })
        return
    if decided_branch.get("source") not in {
        "attack_graph_candidate",
        "attack_graph_related_live_target",
        "attack_graph_state_model",
    }:
        return
    if (
        not action_keys
        and not target_level_invalidity
        and not (mechanism_level_decision and action_family_keys)
        and not (mechanism_level_decision and clone_family_keys)
    ):
        return
    decided_targets = _attack_search_branch_target_set(
        decided_branch,
        include_related=False,
    )
    if not decided_targets and not (mechanism_level_decision and clone_family_keys):
        return
    for branch in search.get("branches", []):
        if branch is decided_branch or _attack_search_branch_terminal(branch):
            continue
        if branch.get("source") not in {
            "attack_graph_candidate",
            "attack_graph_related_live_target",
            "attack_graph_state_model",
        }:
            continue
        if _attack_search_status(branch.get("status")) not in {
            "needs_inventory",
            "needs_harness",
            "needs_concretization",
            "needs_partial_probe",
            "needs_run",
        }:
            continue
        branch_targets = _attack_search_branch_target_set(
            branch,
            include_related=False,
        )
        same_target = bool(branch_targets and branch_targets.intersection(decided_targets))
        branch_action_keys = _attack_search_branch_action_key_set(branch)
        supersede_reason = "target_invalidated" if target_level_invalidity else ""
        if supersede_reason and not same_target:
            supersede_reason = ""
        if not supersede_reason and same_target:
            if branch_action_keys and branch_action_keys.issubset(action_keys):
                supersede_reason = "same_target_action_path"
            elif mechanism_level_decision:
                branch_family_keys = _attack_search_branch_action_family_key_set(branch)
                if branch_family_keys.intersection(action_family_keys):
                    supersede_reason = "same_target_action_family"
        if not supersede_reason and mechanism_level_decision and clone_family_keys:
            branch_clone_family_keys = _attack_search_branch_clone_family_key_set(branch)
            if branch_clone_family_keys.intersection(clone_family_keys):
                supersede_reason = "same_clone_family"
        if not supersede_reason:
            continue
        previous = branch.get("status")
        branch["status"] = "superseded"
        branch["terminal_decision"] = True
        branch["decision_id"] = decision_id
        if supersede_reason == "target_invalidated":
            reason_text = "the same live target binding was invalidated for this target."
        elif supersede_reason == "same_clone_family":
            reason_text = (
                "the same live clone/code family and action mechanism was "
                "already decided."
            )
        elif supersede_reason == "same_target_action_family":
            reason_text = (
                "the same live target/action family was already decided by a "
                "mechanism-level review."
            )
        else:
            reason_text = (
                "the parent attack-graph branch already decided the same "
                "target/action path."
            )
        branch["decision"] = f"Superseded by {decision_id}: {reason_text}"
        branch["updated_at"] = now
        branch["evidence"] = sorted(dict.fromkeys([
            *(branch.get("evidence") or []),
            decision_id,
            *evidence,
        ]))
        branch["related_ids"] = sorted(dict.fromkeys([
            *(branch.get("related_ids") or []),
            decision_id,
            *related_ids,
        ]))
        branch.setdefault("history", []).append({
            "at": now,
            "event": "decision",
            "from": previous,
            "to": "superseded",
            "decision_id": decision_id,
            "decision_status": "superseded",
            "decision": branch["decision"],
            "evidence": evidence,
            "related_ids": related_ids,
        })


def _attack_search_advance(search: dict, args: dict) -> str | None:
    branch_id = str(args.get("branch_id") or "").strip()
    if not branch_id:
        return "branch_id is required for action=advance"
    branch = _attack_search_find_branch(search, branch_id)
    if not branch:
        return f"no branch with id '{branch_id}'"
    status = _attack_search_status(args.get("status"), "")
    if not status:
        return "status is required for action=advance"
    notes = str(args.get("notes") or "").strip()
    is_parking = status in _ATTACK_SEARCH_PARKED_STATUSES
    if is_parking and not notes:
        # Parking is a budget judgment, not a derived gap. Force the agent to
        # state why, so the audit trail records the blocker and what would
        # reopen the branch (and so it is never a silent dead-drop).
        return (
            f"notes is required when parking a branch (status={status}); name "
            "the blocker and what evidence or tool would un-park it"
        )
    now = datetime.now(timezone.utc).isoformat()
    previous = branch.get("status")
    evidence = [str(item) for item in (args.get("evidence") or []) if item]
    related_ids = [str(item) for item in (args.get("related_ids") or []) if item]
    branch["status"] = status
    branch["updated_at"] = now
    branch["evidence"] = sorted(dict.fromkeys([*(branch.get("evidence") or []), *evidence]))
    branch["related_ids"] = sorted(dict.fromkeys([
        *(branch.get("related_ids") or []),
        *related_ids,
    ]))
    if is_parking:
        branch["parking_reason"] = str(args.get("parking_reason") or "").strip() or notes
        recommended_budget = args.get("recommended_budget")
        if recommended_budget not in (None, ""):
            branch["recommended_budget"] = str(recommended_budget).strip()
    else:
        # Un-parking (or any non-parking advance) clears the stale park metadata.
        branch.pop("parking_reason", None)
        branch.pop("recommended_budget", None)
    branch.setdefault("history", []).append({
        "at": now,
        "event": "advanced",
        "from": previous,
        "to": status,
        "notes": notes,
        "evidence": evidence,
        "related_ids": related_ids,
    })
    return None


async def _attack_search_decision(
    container: AuditContainer,
    state: dict,
    search: dict,
    args: dict,
) -> str | None:
    branch_id = str(args.get("branch_id") or search.get("selected_branch_id") or "").strip()
    branch = _attack_search_find_branch(search, branch_id) if branch_id else None
    if not branch:
        active = [
            item for item in search.get("branches", [])
            if not _attack_search_branch_terminal(item)
        ]
        if active:
            branch = sorted(active, key=_attack_search_branch_sort_key)[0]
            branch_id = str(branch.get("id") or "")
    if not branch:
        return "no active branch to decide"

    raw_status = str(
        args.get("decision_status") or args.get("status") or "rejected"
    ).strip().lower()
    if raw_status not in _ATTACK_SEARCH_DECISION_STATUSES:
        return (
            "decision_status must be one of "
            + ", ".join(sorted(_ATTACK_SEARCH_DECISION_STATUSES))
        )
    branch_status = "blocked_setup" if raw_status == "blocked" else raw_status
    decision = str(args.get("decision") or args.get("notes") or "").strip()
    if not decision:
        return "decision or notes is required for action=decision"
    failed_assumption = str(args.get("failed_assumption") or "").strip()
    impact_assessment = str(args.get("impact_assessment") or "").strip()
    next_focus = str(args.get("next_focus") or "").strip()
    evidence = [str(item) for item in (args.get("evidence") or []) if item]
    related_ids = [str(item) for item in (args.get("related_ids") or []) if item]
    branch_related = [
        *[str(item) for item in branch.get("source_ids") or [] if item],
        *[str(item) for item in branch.get("related_ids") or [] if item],
        *related_ids,
    ]
    branch_related = sorted(dict.fromkeys(branch_related))
    action_keys = sorted(dict.fromkeys([
        *[str(item) for item in branch.get("action_keys") or [] if item],
        *[
            str(item.get("key") or item.get("action_key") or "")
            for item in branch.get("target_actions") or []
            if isinstance(item, dict) and (item.get("key") or item.get("action_key"))
        ],
    ]))
    action_family_keys = sorted(_attack_search_branch_action_family_key_set(branch))
    clone_family_keys = sorted(_attack_search_branch_clone_family_key_set(branch))
    attack_keys = sorted(dict.fromkeys([
        *[str(item) for item in branch.get("attack_keys") or [] if item],
        *([str(branch.get("attack_key"))] if branch.get("attack_key") else []),
    ]))
    mechanism_level_decision = _attack_search_mechanism_level_decision(
        decision_text=decision,
        failed_assumption=failed_assumption,
        impact_assessment=impact_assessment,
    )
    coverage_family_decision = _attack_search_coverage_family_decision(
        decision_text=decision,
        failed_assumption=failed_assumption,
        impact_assessment=impact_assessment,
    )

    now = datetime.now(timezone.utc).isoformat()
    decision_id = _next_campaign_id(state, "decision")
    decision_evidence = sorted(dict.fromkeys([
        *[str(item) for item in branch.get("evidence") or [] if item],
        *evidence,
    ]))
    content_parts = [
        f"Attack-search branch: {branch_id}",
        f"Branch title: {branch.get('title') or ''}",
        f"Decision status: {raw_status}",
    ]
    if failed_assumption:
        content_parts.append(f"Failed assumption: {failed_assumption}")
    content_parts.extend(["", "Decision:", decision])
    if impact_assessment:
        content_parts.extend(["", "Impact assessment:", impact_assessment])
    if next_focus:
        content_parts.extend(["", "Next focus:", next_focus])
    state["sections"]["decision"].append({
        "id": decision_id,
        "created_at": now,
        "updated_at": now,
        "title": f"Branch {branch_id} decision: {branch.get('title') or raw_status}",
        "content": "\n".join(content_parts).strip(),
        "status": "observed",
        "priority": branch.get("priority"),
        "evidence": decision_evidence,
        "related_ids": sorted(dict.fromkeys([search["id"], branch_id, *branch_related])),
        "action_keys": action_keys,
        "action_family_keys": action_family_keys,
        "clone_family_keys": clone_family_keys,
        "attack_keys": attack_keys,
    })
    if action_keys:
        decided = set(state.setdefault("attack_search", {}).get("decided_action_keys") or [])
        decided.update(action_keys)
        state["attack_search"]["decided_action_keys"] = sorted(decided)
    if mechanism_level_decision and action_family_keys:
        decided = set(
            state.setdefault("attack_search", {}).get("decided_action_family_keys")
            or []
        )
        decided.update(action_family_keys)
        state["attack_search"]["decided_action_family_keys"] = sorted(decided)
    if mechanism_level_decision and clone_family_keys:
        decided = set(
            state.setdefault("attack_search", {}).get("decided_clone_family_keys")
            or []
        )
        decided.update(clone_family_keys)
        state["attack_search"]["decided_clone_family_keys"] = sorted(decided)
    if attack_keys:
        decided = set(state.setdefault("attack_search", {}).get("decided_attack_keys") or [])
        decided.update(attack_keys)
        state["attack_search"]["decided_attack_keys"] = sorted(decided)

    if args.get("update_related", True):
        related_status = {
            "rejected": "rejected",
            "superseded": "superseded",
            "blocked": "blocked",
            "blocked_setup": "blocked",
            "blocked_compile": "blocked",
            "blocked_revert": "blocked",
            "objective_failed": "inconclusive",
            # Harness-limited parking is not a rejection: the linked hypothesis/
            # experiment is blocked by harness expressiveness, not falsified.
            "unproven_due_to_harness_limit": "blocked",
        }[raw_status]
        for section in ("hypothesis", "experiment"):
            for entry in state["sections"].get(section, []):
                if str(entry.get("id") or "") not in branch_related:
                    continue
                entry["status"] = related_status
                entry["updated_at"] = now
                entry["evidence"] = _merge_unique_strings(
                    entry.get("evidence"),
                    [decision_id, *decision_evidence],
                )
                entry["related_ids"] = _merge_unique_strings(
                    entry.get("related_ids"),
                    [decision_id, branch_id, *branch_related],
                )
                entry["content"] = (
                    f"{str(entry.get('content') or '').rstrip()}\n\n"
                    f"Decision {decision_id}: {decision}"
                ).strip()

    previous = branch.get("status")
    branch["status"] = branch_status
    branch["terminal_decision"] = True
    branch["decision_id"] = decision_id
    branch["decision"] = decision
    branch["failed_assumption"] = failed_assumption or None
    branch["impact_assessment"] = impact_assessment or None
    branch["next_focus"] = next_focus or None
    branch["action_keys"] = action_keys
    branch["action_family_keys"] = action_family_keys
    branch["clone_family_keys"] = clone_family_keys
    branch["attack_keys"] = attack_keys
    branch["updated_at"] = now
    branch["evidence"] = sorted(dict.fromkeys([
        *(branch.get("evidence") or []),
        decision_id,
        *evidence,
    ]))
    branch["related_ids"] = sorted(dict.fromkeys([
        *(branch.get("related_ids") or []),
        decision_id,
        *related_ids,
    ]))
    branch.setdefault("history", []).append({
        "at": now,
        "event": "decision",
        "from": previous,
        "to": branch_status,
        "decision_id": decision_id,
        "decision_status": raw_status,
        "decision": decision,
        "failed_assumption": failed_assumption,
        "impact_assessment": impact_assessment,
        "next_focus": next_focus,
        "evidence": evidence,
        "related_ids": related_ids,
    })
    # unproven_due_to_harness_limit is deliberately absent: a harness limit on
    # one branch says nothing about its siblings, so parking it must never
    # supersede adjacent work the way an evidence rejection does.
    if raw_status in {
        "rejected",
        "superseded",
        "objective_failed",
        "blocked",
        "blocked_setup",
        "blocked_revert",
    }:
        _attack_search_supersede_subsumed_siblings(
            search,
            branch,
            action_keys=set(action_keys),
            action_family_keys=set(action_family_keys),
            clone_family_keys=set(clone_family_keys),
            target_level_invalidity=_attack_search_target_level_invalidity(
                branch,
                decision_text=decision,
                failed_assumption=failed_assumption,
            ),
            mechanism_level_decision=mechanism_level_decision,
            coverage_family_decision=coverage_family_decision,
            decision_id=decision_id,
            evidence=evidence,
            related_ids=related_ids,
            now=now,
        )
    for item in search.get("branches", []):
        item["selected"] = False
    search["selected_branch_id"] = ""
    search["last_decision_id"] = decision_id
    return None


def _attack_search_next_action(search: dict) -> dict:
    branches = [
        branch for branch in search.get("branches", [])
        if not _attack_search_branch_terminal(branch)
    ]
    selected = _attack_search_find_branch(
        search,
        str(search.get("selected_branch_id") or ""),
    )
    if selected and selected in branches:
        branch = selected
    elif branches:
        branch = sorted(branches, key=_attack_search_branch_sort_key)[0]
        search["selected_branch_id"] = branch.get("id", "")
        for item in search.get("branches", []):
            item["selected"] = item is branch
    else:
        return {
            "branch_id": None,
            "status": "complete",
            "tool": "attack_search",
            "required_toolsets": [],
            "instructions": (
                "No active attack-search branches remain. Start a fresh focus, "
                "map another subsystem, or end only after coverage and evidence "
                "support that decision."
            ),
            "required_evidence": [],
            "must_follow": True,
        }
    next_action = {
        "branch_id": branch.get("id"),
        "branch_title": branch.get("title"),
        "status": branch.get("status"),
        "tool": branch.get("next_tool"),
        "required_toolsets": branch.get("required_toolsets") or [],
        "instructions": branch.get("instructions"),
        "required_evidence": branch.get("required_evidence") or [],
        "stop_condition": branch.get("stop_condition"),
        "source": branch.get("source"),
        "source_ids": branch.get("source_ids") or [],
        "source_artifacts": branch.get("source_artifacts") or [],
        "related_ids": branch.get("related_ids") or [],
        "action_keys": branch.get("action_keys") or [],
        "clone_family_keys": branch.get("clone_family_keys") or [],
        "attack_keys": branch.get("attack_keys") or [],
        "target_binding": branch.get("target_binding"),
        "inventory_context": branch.get("inventory_context"),
        "target_actions": branch.get("target_actions") or [],
        "required_args": branch.get("required_args") or {},
        "must_follow": True,
    }
    # Pass through structured next-tool hints when a branch carries them. The
    # executor's controller guard prefers these exact tool names over scanning
    # the free-text ``tool`` field, so a branch can pin the required tool(s)
    # unambiguously (a list of expected tools, or an ordered pipeline of steps).
    expected_tools = branch.get("expected_tools")
    if isinstance(expected_tools, list) and expected_tools:
        next_action["expected_tools"] = [
            str(item) for item in expected_tools if str(item).strip()
        ]
    pipeline = branch.get("pipeline")
    if isinstance(pipeline, list) and pipeline:
        next_action["pipeline"] = pipeline
    # Carry the scheduling scores so the agent sees why this branch was chosen
    # (and, for a parked branch, why it was deprioritized and at what budget).
    for field in (
        "scheduling_score",
        "expected_value_score",
        "proof_cost_score",
        "blocker_penalty",
        "next_step_value",
        "parking_reason",
        "recommended_budget",
    ):
        value = branch.get(field)
        if value not in (None, ""):
            next_action[field] = value
    # Carry the curiosity/diversity annotations when the branch is actually novel
    # so the agent sees why an unusual frontier branch surfaced.
    next_action.update(_attack_search_branch_novelty_fields(branch))
    next_action.update(_attack_search_branch_state_model_fields(branch))
    failure_diagnosis = _compact_failure_diagnosis(branch.get("failure_diagnosis"))
    if failure_diagnosis:
        next_action["failure_diagnosis"] = failure_diagnosis
    rationale = _attack_search_selection_rationale(branch, branches)
    if rationale:
        next_action["selection_rationale"] = rationale
    return next_action


def _attack_search_summary(search: dict) -> dict:
    branches = search.get("branches") or []
    by_status: dict[str, int] = {}
    by_source: dict[str, int] = {}
    for branch in branches:
        status = str(branch.get("status") or "unknown")
        source = str(branch.get("source") or "unknown")
        by_status[status] = by_status.get(status, 0) + 1
        by_source[source] = by_source.get(source, 0) + 1
    return {
        "branches": len(branches),
        "active": sum(
            1 for branch in branches
            if not _attack_search_branch_terminal(branch)
        ),
        "terminal": sum(
            1 for branch in branches
            if _attack_search_branch_terminal(branch)
        ),
        "by_status": by_status,
        "by_source": by_source,
    }


def _truncate_response_text(value: object, limit: int = 600) -> str:
    text = str(value or "")
    if len(text) <= limit:
        return text
    return text[: limit - 3].rstrip() + "..."


def _compact_failure_diagnosis(diagnosis: object) -> dict:
    if not isinstance(diagnosis, dict):
        return {}
    compact = {
        "kind": diagnosis.get("kind"),
        "confidence": diagnosis.get("confidence"),
        "summary": _truncate_response_text(diagnosis.get("summary"), 300),
        "recommended_next_tool": diagnosis.get("recommended_next_tool"),
        "suggested_repairs": [
            _truncate_response_text(item, 220)
            for item in (diagnosis.get("suggested_repairs") or [])[:4]
            if str(item).strip()
        ],
        "compile_repair_hints": [
            _truncate_response_text(item, 220)
            for item in (diagnosis.get("compile_repair_hints") or [])[:4]
            if str(item).strip()
        ],
        "evidence_lines": [
            _truncate_response_text(item, 220)
            for item in (diagnosis.get("evidence_lines") or [])[:5]
            if str(item).strip()
        ],
    }
    return {
        key: value
        for key, value in compact.items()
        if value not in (None, "", [], {})
    }


def _compact_target_action(action: dict) -> dict:
    if not isinstance(action, dict):
        return {}
    return {
        key: value
        for key, value in {
            "key": action.get("key") or action.get("action_key"),
            "contract": action.get("contract"),
            "function": action.get("function"),
            "target": action.get("target") or action.get("target_address"),
            "normalized_from_target": action.get("normalized_from_target"),
            "normalized_call_target": action.get("normalized_call_target"),
            "file": action.get("file"),
            "line": action.get("line"),
            "affordances": (action.get("affordances") or [])[:8],
            "modifiers": (action.get("modifiers") or [])[:6],
        }.items()
        if value not in (None, "", [], {})
    }


def _attack_search_branch_novelty_fields(branch: dict) -> dict:
    """Compact curiosity/diversity annotations for a branch's model-visible views.

    Returns the novelty fields only when the branch is actually novel — a
    controller-created frontier branch, or any branch with a positive novelty
    score — so ordinary claim/evidence branches stay free of curiosity noise.
    Empty/falsey values are dropped. Shared by the compact branch, the
    next_action, and the durable branch dossier so all three agree.
    """
    raw_score = branch.get("novelty_score")
    novelty_score = int(raw_score) if isinstance(raw_score, (int, float)) else 0
    frontier_source = branch.get("frontier_source")
    if not frontier_source and novelty_score <= 0:
        return {}
    fields: dict = {}
    if novelty_score > 0:
        fields["novelty_score"] = novelty_score
    if branch.get("diversity_bonus"):
        fields["diversity_bonus"] = int(branch.get("diversity_bonus") or 0)
    if branch.get("curiosity_budget_eligible"):
        fields["curiosity_budget_eligible"] = True
    if branch.get("diversity_reason"):
        fields["diversity_reason"] = _truncate_response_text(
            branch.get("diversity_reason"), 300
        )
    if frontier_source:
        fields["frontier_source"] = frontier_source
    notes = [
        str(note)
        for note in branch.get("scheduling_notes") or []
        if str(note).strip()
    ]
    if notes:
        fields["scheduling_notes"] = notes[:6]
    structural = _attack_search_branch_structural_affordances(branch)
    if structural:
        fields["structural_affordances"] = structural
    return fields


def _attack_search_branch_state_model_fields(branch: dict) -> dict:
    """Compact state-transition-model annotations for a branch's model-visible
    views.

    Returns the generic-invariant fields (the ``generic_invariant`` flag, the
    generic ``mechanism``, the invariant id/kind/statement, and the
    state-transition-model artifact path) only for a branch derived from a
    state-transition model, so ordinary claim/evidence branches stay free of
    them. Empty values are dropped. Shared by the compact branch, the
    next_action, and the durable branch dossier so all three agree.
    """
    if not branch.get("generic_invariant"):
        return {}
    fields: dict = {"generic_invariant": True}
    mechanism = str(branch.get("root_mechanism") or "").strip()
    if mechanism:
        fields["mechanism"] = mechanism
    invariant_id = str(branch.get("invariant_id") or "").strip()
    if invariant_id:
        fields["invariant_id"] = invariant_id
    invariant_kind = str(branch.get("invariant_kind") or "").strip()
    if invariant_kind:
        fields["invariant_kind"] = invariant_kind
    invariant_statement = str(branch.get("invariant_statement") or "").strip()
    if invariant_statement:
        fields["invariant_statement"] = _truncate_response_text(
            invariant_statement, 400
        )
    state_transition_model = str(branch.get("state_transition_model") or "").strip()
    if state_transition_model:
        fields["state_transition_model"] = state_transition_model
    return fields


def _compact_attack_branch(branch: dict, *, terminal: bool = False) -> dict:
    history = branch.get("history") or []
    last_event = history[-1] if history else {}
    compact = {
        "id": branch.get("id"),
        "key": branch.get("key"),
        "title": branch.get("title"),
        "status": branch.get("status"),
        "source": branch.get("source"),
        "next_tool": branch.get("next_tool"),
        "instructions": _truncate_response_text(branch.get("instructions"), 800),
        "stop_condition": _truncate_response_text(branch.get("stop_condition"), 500),
        "priority": branch.get("priority"),
        "priority_score": branch.get("priority_score"),
        "scheduling_score": branch.get("scheduling_score"),
        "expected_value_score": branch.get("expected_value_score"),
        "proof_cost_score": branch.get("proof_cost_score"),
        "blocker_penalty": branch.get("blocker_penalty"),
        "next_step_value": branch.get("next_step_value"),
        "parking_reason": _truncate_response_text(branch.get("parking_reason"), 400)
        if branch.get("parking_reason")
        else None,
        "recommended_budget": branch.get("recommended_budget"),
        "selected": branch.get("selected"),
        "required_toolsets": branch.get("required_toolsets") or [],
        "required_evidence": (branch.get("required_evidence") or [])[:5],
        "source_ids": (branch.get("source_ids") or [])[:8],
        "source_artifacts": (branch.get("source_artifacts") or [])[:5],
        "related_ids": (branch.get("related_ids") or [])[:8],
        "evidence": (branch.get("evidence") or [])[:12],
        "action_keys": (branch.get("action_keys") or [])[:12],
        "clone_family_keys": (branch.get("clone_family_keys") or [])[:12],
        "attack_keys": (branch.get("attack_keys") or [])[:8],
        "target_binding": branch.get("target_binding"),
        "inventory_context": branch.get("inventory_context"),
        "readiness": branch.get("readiness"),
        "failure_diagnosis": _compact_failure_diagnosis(
            branch.get("failure_diagnosis")
        ),
        "required_args": branch.get("required_args") or {},
        "target_actions": [
            _compact_target_action(item)
            for item in (branch.get("target_actions") or [])[:5]
            if isinstance(item, dict)
        ],
        "history_summary": {
            "events": len(history),
            "last_event": {
                key: last_event.get(key)
                for key in ("at", "event", "from", "to", "status", "reason")
                if last_event.get(key) not in (None, "", [], {})
            },
        },
    }
    if terminal or branch.get("terminal_decision"):
        compact.update({
            "terminal_decision": bool(branch.get("terminal_decision")),
            "decision_id": branch.get("decision_id"),
            "decision": _truncate_response_text(branch.get("decision"), 800),
            "failed_assumption": _truncate_response_text(
                branch.get("failed_assumption"),
                500,
            ),
            "impact_assessment": _truncate_response_text(
                branch.get("impact_assessment"),
                500,
            ),
            "next_focus": _truncate_response_text(branch.get("next_focus"), 500),
        })
    compact.update(_attack_search_branch_novelty_fields(branch))
    compact.update(_attack_search_branch_state_model_fields(branch))
    return {
        key: value
        for key, value in compact.items()
        if value not in (None, "", [], {})
    }


def _compact_attack_next_action(next_action: dict) -> dict:
    compact = dict(next_action or {})
    if compact.get("instructions"):
        compact["instructions"] = _truncate_response_text(compact["instructions"], 800)
    if compact.get("stop_condition"):
        compact["stop_condition"] = _truncate_response_text(compact["stop_condition"], 500)
    if compact.get("parking_reason"):
        compact["parking_reason"] = _truncate_response_text(compact["parking_reason"], 400)
    if compact.get("failure_diagnosis"):
        compact["failure_diagnosis"] = _compact_failure_diagnosis(
            compact["failure_diagnosis"]
        )
    compact["target_actions"] = [
        _compact_target_action(item)
        for item in (compact.get("target_actions") or [])[:5]
        if isinstance(item, dict)
    ]
    compact["source_artifacts"] = (compact.get("source_artifacts") or [])[:5]
    compact["source_ids"] = (compact.get("source_ids") or [])[:8]
    compact["action_keys"] = (compact.get("action_keys") or [])[:12]
    compact["clone_family_keys"] = (compact.get("clone_family_keys") or [])[:12]
    compact["attack_keys"] = (compact.get("attack_keys") or [])[:8]
    # dossier_path is attached by _write_attack_search_branch_dossier and points
    # the agent at the durable branch dossier; carry it into the compacted
    # response so a recovering agent can reach the dossier in one read.
    if next_action and next_action.get("dossier_path"):
        compact["dossier_path"] = next_action["dossier_path"]
    return compact


# Branch dossiers are durable, self-contained snapshots of the selected
# attack_search branch. The compact next_action / active_branches lists in the
# response are aggressively truncated to keep the model-visible payload small;
# the dossier is the full-fidelity copy on disk so a compacted context can
# recover the current branch (hypothesis, target actions, evidence, required
# args, last blocker, next tool) with a single artifact read.
_BRANCH_DOSSIER_DIR = "/workspace/campaign/branch-dossiers"

# Branch statuses that signal a stall the agent must clear before progressing;
# used to surface the most recent blocker in a dossier.
_ATTACK_SEARCH_BLOCKER_STATUSES = {
    "blocked_compile",
    "blocked_revert",
    "blocked_setup",
    "needs_poc_repair",
    "objective_failed",
    "needs_mutation",
    "parked_harness_limit",
    "parked_low_roi",
    "parked_needs_dependency",
    "parked_needs_live_context",
    "unproven_due_to_harness_limit",
    "rejected",
}


def _attack_search_branch_objective(branch: dict) -> str:
    """Derive a branch's hypothesis/objective from its richest available source.

    Branches do not carry a single canonical objective field, so prefer the
    compose-sequence objective the controller staged, then any target-action
    objective, then the root mechanism. Returns "" when none is present (the
    caller then drops the field).
    """
    required_args = branch.get("required_args")
    if isinstance(required_args, dict):
        compose = required_args.get("compose_sequence_experiment")
        if isinstance(compose, dict):
            objective = str(compose.get("objective") or "").strip()
            if objective:
                return objective
    for action in branch.get("target_actions") or []:
        if isinstance(action, dict):
            objective = str(action.get("objective") or "").strip()
            if objective:
                return objective
    return str(branch.get("root_mechanism") or "").strip()


def _attack_search_branch_last_blocker(branch: dict) -> str:
    """Summarize the most actionable blocker recorded against a branch.

    Prefers live-inventory blockers (the most concrete signal), then falls back
    to the most recent history event whose target status reads as a stall.
    """
    inventory_context = branch.get("inventory_context")
    if isinstance(inventory_context, dict):
        for key, prefix in (
            ("hard_blockers", "live inventory blocks"),
            ("soft_blockers", "live inventory uncertain"),
        ):
            items = inventory_context.get(key) or []
            rendered = "; ".join(
                f"{item.get('label')}={item.get('target_binding')}"
                for item in items
                if isinstance(item, dict)
            )
            if rendered:
                return f"{prefix}: {rendered}"[:400]
    for event in reversed(branch.get("history") or []):
        if not isinstance(event, dict):
            continue
        to_status = str(event.get("to") or "")
        is_blocker = (
            to_status in _ATTACK_SEARCH_BLOCKER_STATUSES
            or event.get("event") == "decision"
        )
        if not is_blocker:
            continue
        reason = str(event.get("reason") or "").strip()
        detail = reason or to_status
        if detail:
            return f"{event.get('event') or 'status_changed'}: {detail}"[:400]
    return ""


def _attack_search_branch_dossier(search: dict, branch: dict) -> dict:
    """Build a durable, self-contained dossier for one attack_search branch.

    Captures everything an agent needs to resume the branch after the
    originating turns have been compacted out of context: the locator, the
    hypothesis/objective, target actions, source artifacts, evidence, required
    args, the last recorded blocker, the next tool, and a bounded history
    summary. Empty fields are dropped to keep the artifact compact.
    """
    history = branch.get("history") or []
    recent_history = [
        {
            key: event.get(key)
            for key in ("at", "event", "from", "to", "status", "reason")
            if event.get(key) not in (None, "", [], {})
        }
        for event in history[-5:]
        if isinstance(event, dict)
    ]
    target_actions = [
        _compact_target_action(item)
        for item in (branch.get("target_actions") or [])
        if isinstance(item, dict)
    ]
    target_actions = [item for item in target_actions if item]
    dossier = {
        "branch_id": branch.get("id"),
        "key": branch.get("key"),
        "title": branch.get("title"),
        "status": branch.get("status"),
        "source": branch.get("source"),
        "priority": branch.get("priority"),
        "priority_score": branch.get("priority_score"),
        "hypothesis_or_objective": _attack_search_branch_objective(branch),
        "next_tool": branch.get("next_tool"),
        "instructions": _truncate_response_text(branch.get("instructions"), 1200),
        "stop_condition": _truncate_response_text(branch.get("stop_condition"), 600),
        "required_toolsets": branch.get("required_toolsets") or [],
        "required_evidence": branch.get("required_evidence") or [],
        "target_actions": target_actions,
        "source_artifacts": branch.get("source_artifacts") or [],
        "source_ids": branch.get("source_ids") or [],
        "related_ids": branch.get("related_ids") or [],
        "evidence": branch.get("evidence") or [],
        "action_keys": branch.get("action_keys") or [],
        "attack_keys": branch.get("attack_keys") or [],
        "clone_family_keys": branch.get("clone_family_keys") or [],
        "target_binding": branch.get("target_binding"),
        "inventory_context": branch.get("inventory_context"),
        "required_args": branch.get("required_args") or {},
        "failure_diagnosis": _compact_failure_diagnosis(
            branch.get("failure_diagnosis")
        ),
        "last_blocker": _attack_search_branch_last_blocker(branch),
        "history_summary": {
            "events": len(history),
            "recent": recent_history,
        },
        "search_id": search.get("id"),
        "focus": search.get("focus"),
        "current_path": _ATTACK_SEARCH_CURRENT_PATH,
        "history_path": (search.get("paths") or {}).get("history"),
    }
    # Curiosity/diversity annotations (novelty_score, diversity_reason,
    # frontier_source, structural affordances) for a novel/frontier branch so a
    # recovering agent sees why the unusual branch is on the queue.
    dossier.update(_attack_search_branch_novelty_fields(branch))
    dossier.update(_attack_search_branch_state_model_fields(branch))
    next_action = search.get("next_action") or {}
    if next_action.get("branch_id") == branch.get("id"):
        selection_rationale = next_action.get("selection_rationale")
        if isinstance(selection_rationale, dict) and selection_rationale:
            dossier["selection_rationale"] = selection_rationale
    return {
        key: value
        for key, value in dossier.items()
        if value not in (None, "", [], {})
    }


async def _write_attack_search_branch_dossier(
    container: AuditContainer,
    search: dict,
) -> str:
    """Persist a dossier for the search's selected/next branch.

    Writes ``/workspace/campaign/branch-dossiers/<branch_id>.json`` and records
    ``dossier_path`` on ``search["next_action"]`` so the path travels with the
    saved state and the compacted response. Returns "" (and writes nothing) when
    there is no concrete next branch, e.g. the search is complete.
    """
    next_action = search.get("next_action") or {}
    branch_id = str(next_action.get("branch_id") or "")
    if not branch_id:
        return ""
    branch = _attack_search_find_branch(search, branch_id)
    if branch is None:
        return ""
    dossier = _attack_search_branch_dossier(search, branch)
    dossier_path = f"{_BRANCH_DOSSIER_DIR}/{branch_id}.json"
    await container.write_file(
        dossier_path,
        json.dumps(dossier, indent=2, sort_keys=True) + "\n",
    )
    next_action["dossier_path"] = dossier_path
    return dossier_path


async def _save_attack_search(
    container: AuditContainer,
    state: dict,
    search: dict,
) -> None:
    search["updated_at"] = datetime.now(timezone.utc).isoformat()
    # Stamp expected-value/proof-cost scheduling scores onto every branch before
    # summary/next_action/persistence so the model-visible compact branches and
    # the saved current.json carry them. The sort key recomputes the same scores,
    # so the stamp and the ordering never disagree.
    for branch in search.get("branches") or []:
        _attack_search_score_branch(branch)
    search["summary"] = _attack_search_summary(search)
    search["next_action"] = _attack_search_next_action(search)
    # Persist the selected branch's full-fidelity dossier and stamp its path onto
    # next_action before the search is written, so current.json/history.json and
    # the response all carry dossier_path.
    await _write_attack_search_branch_dossier(container, search)
    history_path = search.setdefault("paths", {}).setdefault(
        "history",
        f"{_ATTACK_SEARCH_DIR}/{search['id']}.json",
    )
    search["paths"]["current"] = _ATTACK_SEARCH_CURRENT_PATH
    await container.write_file(
        history_path,
        json.dumps(search, indent=2, sort_keys=True) + "\n",
    )
    await container.write_file(
        _ATTACK_SEARCH_CURRENT_PATH,
        json.dumps(search, indent=2, sort_keys=True) + "\n",
    )
    state.setdefault("attack_search", {})["current"] = search
    history = state["attack_search"].setdefault("history", [])
    if history_path not in history:
        history.append(history_path)
    await _save_campaign_state(container, state)


async def _attack_search(container: AuditContainer, args: dict) -> str:
    action = str(args.get("action") or "sync").strip().lower()
    if action not in {"start", "sync", "status", "select", "advance", "decision"}:
        return "Error: action must be start, sync, status, select, advance, or decision"
    try:
        evidence = _require_list(args.get("evidence"), "evidence")
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"
    args = {**args, "evidence": evidence, "related_ids": related_ids}

    state = await _load_campaign_state(container)
    search = _attack_search_current(
        state,
        args,
        reset=bool(args.get("reset", False)) or action == "start",
    )
    focus = str(args.get("focus") or search.get("focus") or "").strip()
    if focus:
        search["focus"] = focus

    error = None
    if action in {"start", "sync"}:
        candidates = await _attack_search_candidates(container, state, focus=focus)
        _attack_search_merge_candidates(search, candidates)
    elif action == "select":
        branch_id = str(args.get("branch_id") or "").strip()
        if not branch_id:
            error = "branch_id is required for action=select"
        else:
            error = _attack_search_select(search, branch_id)
    elif action == "advance":
        error = _attack_search_advance(search, args)
    elif action == "decision":
        error = await _attack_search_decision(container, state, search, args)

    if error:
        return f"Error: {error}"

    max_branches = min(max(int(args.get("max_branches", 12)), 1), 40)
    await _save_attack_search(container, state, search)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Attack search: {search['title']}",
            content=(
                f"Attack search: {search['id']}\n"
                f"Current: {_ATTACK_SEARCH_CURRENT_PATH}\n"
                f"History: {search['paths']['history']}\n"
                f"Action: {action}\n"
                f"Active branches: {search['summary']['active']}\n"
                f"Next tool: {search['next_action'].get('tool')}"
            ),
            evidence=[_ATTACK_SEARCH_CURRENT_PATH, search["paths"]["history"]],
            related_ids=[search["id"]],
            status="observed",
        )

    await _append_campaign_trace(
        container,
        {
            "event": "attack_search",
            "action": action,
            "search_id": search["id"],
            "result_id": result_id or None,
            "decision_id": search.get("last_decision_id") if action == "decision" else None,
            "summary": search.get("summary") or {},
            "next_action": {
                "branch_id": search.get("next_action", {}).get("branch_id"),
                "status": search.get("next_action", {}).get("status"),
                "tool": search.get("next_action", {}).get("tool"),
                "source": search.get("next_action", {}).get("source"),
                "action_keys": search.get("next_action", {}).get("action_keys") or [],
                "clone_family_keys": (
                    search.get("next_action", {}).get("clone_family_keys") or []
                ),
                "attack_keys": search.get("next_action", {}).get("attack_keys") or [],
            },
        },
    )

    active_branches = [
        branch for branch in search.get("branches", [])
        if not _attack_search_branch_terminal(branch)
    ]
    terminal_branches = [
        branch for branch in search.get("branches", [])
        if _attack_search_branch_terminal(branch)
    ]
    include_terminal = (
        action in {"advance", "decision", "status"}
        or bool(args.get("include_terminal", False))
    )
    response = {
        "search_id": search["id"],
        "path": _ATTACK_SEARCH_CURRENT_PATH,
        "history_path": search["paths"]["history"],
        "trace_path": _CAMPAIGN_TRACE_PATH,
        "result_id": result_id or None,
        "decision_id": search.get("last_decision_id") if action == "decision" else None,
        "action": action,
        "mode": search.get("mode"),
        "focus": search.get("focus"),
        "summary": search["summary"],
        "next_action": _compact_attack_next_action(search["next_action"]),
        "active_branches": [
            _compact_attack_branch(branch)
            for branch in active_branches[:max_branches]
        ],
        "terminal_branches": [
            _compact_attack_branch(branch, terminal=True)
            for branch in (
                terminal_branches[:max_branches] if include_terminal else []
            )
        ],
        "omitted_from_response": {
            "active_branches": max(0, len(active_branches) - max_branches),
            "terminal_branches": (
                max(0, len(terminal_branches) - max_branches)
                if include_terminal
                else len(terminal_branches)
            ),
            "note": "Open history_path for full branch history and decisions.",
        },
        "controller_instructions": [
            "Execute next_action.tool before pursuing another branch.",
            "After each material tool result, call attack_search with action=sync.",
            "Use action=decision for explicit rejection/blocking/objective-failed conclusions; sync infers state from campaign artifacts.",
            "Use action=advance only for exceptional manual status transitions that are not campaign decisions.",
            "Do not submit high/critical findings unless the branch reaches ready_to_submit or validated evidence is linked.",
        ],
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _slugify(value: str, fallback: str = "experiment") -> str:
    slug = re.sub(r"[^a-zA-Z0-9]+", "-", value.lower()).strip("-")
    return slug[:60] or fallback


_DEFAULT_SOLIDITY_PRAGMA = ">=0.8.0 <0.9.0"


def _normalize_solidity_pragma(value: object) -> str:
    text = str(value or _DEFAULT_SOLIDITY_PRAGMA).strip()
    text = re.sub(r"^\s*pragma\s+solidity\s+", "", text).strip()
    text = text[:-1].strip() if text.endswith(";") else text
    if re.fullmatch(r"[~^<>=0-9 .|]+", text):
        return text
    return _DEFAULT_SOLIDITY_PRAGMA


def _normalize_experiment_target_dir(path: str) -> str:
    normalized = posixpath.normpath(path or "/workspace/experiments")
    if normalized == "/workspace/experiments":
        return normalized
    if normalized.startswith("/workspace/experiments/"):
        return normalized
    if normalized.startswith("/audit/"):
        return normalized
    raise ValueError(
        "experiment target_dir must be under /workspace/experiments "
        "or under /audit/"
    )


def _experiment_readme(
    *,
    artifact_id: str,
    title: str,
    template: str,
    notes: str,
    related_ids: list[str],
    write_scaffold_contract: bool = True,
) -> str:
    related = ", ".join(related_ids) if related_ids else "none"
    notes = notes.strip() or "TODO: define setup, sequence, and success condition."
    scaffold_note = (
        "Starter Solidity scaffold written; replace TODOs before running it as evidence."
        if write_scaffold_contract and template != "blank"
        else "No starter Solidity scaffold was written; create a custom test before running objective evidence."
    )
    return f"""# {title}

Experiment id: `{artifact_id}`
Template: `{template}`
Related campaign artifacts: {related}
Scaffold: {scaffold_note}

## Objective

TODO: State the invariant or assumption this experiment tries to falsify.

## Setup

TODO: List actors, balances, mocks, fork block, protocol state, and deployment steps.

## Transaction Sequence

TODO: List every attacker/victim/protocol action in order.

## Success Condition

TODO: Define the observable result: profit, bad debt, excess redemption,
unauthorized mint/release, permanent lock, or invariant violation.

## Notes

{notes}

## Evidence Log

Record command outputs with `run_experiment` so results are linked back to this id.

## Fork RPC endpoints

You do not export `ETH_RPC_URL` by hand. `run_experiment` (and
`run_sequence_minimization`) derive chain-specific endpoints from this
experiment's fork context / chain binding (or an explicit `rpc_url`,
`network`/`chain_id`, or `fork_context` arg) and inject them per run:

- `ETH_RPC_URL` — the primary fork chain, for `vm.envString("ETH_RPC_URL")`.
- `RPC_URL_<chain_id>` / `RPC_URL_<NETWORK>` — one per chain, e.g.
  `RPC_URL_8453` / `RPC_URL_BASE_MAINNET`. Read these in multi-chain tests, e.g.
  `vm.createSelectFork(vm.envString("RPC_URL_8453"))`.

For a multi-chain experiment, declare `primary_chain` and `required_chains` (and
per-target `network`/`chain_id`) in `sequence.json` so every chain is injected
and the primary one backs `ETH_RPC_URL`.

## Runbook

1. Use build/static commands only for setup triage; classify those runs with `run_kind=build`, `run_kind=static_analysis`, or `run_kind=setup_probe`.
2. Write or fill a Foundry test/invariant that emits or asserts the objective marker: attacker profit, protocol loss, bad debt, unauthorized state transition, or permanent lock.
3. Run the objective-capable command with `run_experiment` using `run_kind=harness_run`, `run_kind=poc_run`, or `run_kind=fuzz_run`.
4. If compilation/setup fails, repair the earliest blocker and rerun the same objective command before mutating the hypothesis.
5. If the objective does not move, record an `attack_search` decision or mutate to a concrete adjacent assumption.
"""


