def _experiment_files(
    *,
    artifact_id: str,
    title: str,
    template: str,
    notes: str,
    related_ids: list[str],
    write_scaffold_contract: bool = True,
    solidity_pragma: str = _DEFAULT_SOLIDITY_PRAGMA,
) -> dict[str, str]:
    files = {
        "README.md": _experiment_readme(
            artifact_id=artifact_id,
            title=title,
            template=template,
            notes=notes,
            related_ids=related_ids,
            write_scaffold_contract=write_scaffold_contract,
        )
    }
    if template != "blank" and write_scaffold_contract:
        files["ReentbotProExperiment.t.sol"] = _foundry_template_contract(
            template,
            title,
            solidity_pragma=solidity_pragma,
        )
    return files


_REPLAY_INLINE_LOG_RE = re.compile(
    r"^\s*(?P<label>(?:before|after)\b[^:]{0,180}):\s*"
    r"(?P<value>-?\d+|0x[0-9a-fA-F]+)\s*$",
    re.IGNORECASE,
)


def _strip_ansi(text: str) -> str:
    return re.sub(r"\x1b\[[0-9;?]*[A-Za-z]", "", text)


def _experiment_workspace_from_state(state: dict, experiment_id: str) -> str:
    if not experiment_id:
        return ""
    for experiment in state.get("sections", {}).get("experiment", []):
        if experiment.get("id") != experiment_id:
            continue
        for line in str(experiment.get("content") or "").splitlines():
            if line.startswith("Workspace: "):
                return line.split("Workspace: ", 1)[1].strip()
    return ""


async def _load_sequence_payload_for_experiment(
    container: AuditContainer,
    state: dict,
    experiment_id: str,
) -> tuple[str, dict | None]:
    workspace = _experiment_workspace_from_state(state, experiment_id)
    if not workspace:
        return "", None
    path = posixpath.join(workspace, "sequence.json")
    try:
        raw = await container.read_file(path)
        return path, json.loads(raw)
    except (FileNotFoundError, json.JSONDecodeError):
        return "", None


def _replay_target_address(value: object) -> str:
    if isinstance(value, dict):
        value = value.get("address") or value.get("target")
    return str(value or "").strip()


def _replay_sequence_snapshot_templates(
    sequence_payload: dict | None,
    *,
    related_ids: list[str],
    title: str,
) -> dict:
    if not sequence_payload:
        return {}
    target_addresses = sequence_payload.get("target_addresses") or {}
    fork_context = sequence_payload.get("fork") or {}
    eth_balances = []
    calls = []
    erc20_balances = []

    if isinstance(target_addresses, dict):
        for label, raw_address in sorted(target_addresses.items()):
            address = _replay_target_address(raw_address)
            if address:
                eth_balances.append({
                    "label": f"{label} native",
                    "address": address,
                })

    observations = sequence_payload.get("observations") or []
    if isinstance(observations, list) and isinstance(target_addresses, dict):
        for observation in observations:
            if not isinstance(observation, dict):
                continue
            contract, function, returns = _sequence_observation_function(observation)
            if not contract or not function:
                continue
            target = _replay_target_address(target_addresses.get(contract))
            if not target:
                continue
            if returns and returns.strip().lower() not in {"uint", "uint256"}:
                continue
            calls.append({
                "label": observation.get("label") or function,
                "target": target,
                "signature": f"{function}()(uint256)",
            })

    tokens = []
    for index, token in enumerate((fork_context.get("tokens") or [])[:5], start=1):
        if not isinstance(token, dict):
            continue
        address = _replay_target_address(
            token.get("address") or token.get("token") or token.get("asset")
        )
        if not address:
            continue
        tokens.append({
            "label": _context_label(token, f"token_{index}"),
            "address": address,
        })
    for token in tokens:
        target_items = sorted(target_addresses.items()) if isinstance(
            target_addresses,
            dict,
        ) else []
        for target_label, raw_address in target_items:
            account = _replay_target_address(raw_address)
            if not account:
                continue
            erc20_balances.append({
                "token_label": token["label"],
                "token": token["address"],
                "account_label": str(target_label),
                "account": account,
            })

    base = {
        "eth_balances": eth_balances,
        "erc20_balances": erc20_balances,
        "storage_slots": [],
        "calls": calls,
        "related_ids": related_ids,
    }
    return {
        "before": {
            "title": f"Before {title}",
            **base,
        },
        "after": {
            "title": f"After {title}",
            **base,
        },
    }


def _replay_inline_snapshot_entries(output: str) -> list[dict]:
    entries = []
    for line_number, raw_line in enumerate(_strip_ansi(output).splitlines(), start=1):
        match = _REPLAY_INLINE_LOG_RE.match(raw_line)
        if not match:
            continue
        label = match.group("label").strip()
        phase, _separator, metric = label.partition(" ")
        metric = metric.strip() or phase
        entries.append({
            "line": line_number,
            "phase": phase.lower(),
            "metric": metric,
            "value": match.group("value").strip(),
        })
    return entries


def _replay_inline_comparison(entries: list[dict]) -> dict:
    grouped: dict[str, dict[str, dict]] = {}
    for entry in entries:
        grouped.setdefault(entry["metric"], {})[entry["phase"]] = entry

    changed = []
    paired = []
    incomplete = []
    for metric, phases in sorted(grouped.items()):
        before = phases.get("before")
        after = phases.get("after")
        if not before or not after:
            incomplete.append({"metric": metric, "phases": sorted(phases)})
            continue
        item = {
            "metric": metric,
            "before": before["value"],
            "after": after["value"],
            "before_line": before["line"],
            "after_line": after["line"],
        }
        before_int = _parse_int_value(before["value"])
        after_int = _parse_int_value(after["value"])
        if before_int is not None and after_int is not None:
            item["delta"] = after_int - before_int
        paired.append(item)
        if before["value"] != after["value"]:
            changed.append(item)
    return {
        "summary": {
            "entries": len(entries),
            "paired_metrics": len(paired),
            "changed": len(changed),
            "incomplete": len(incomplete),
        },
        "changed": changed[:50],
        "paired": paired[:50],
        "incomplete": incomplete[:25],
    }


def _replay_objective_templates(inline_comparison: dict) -> list[dict]:
    objectives = []
    for item in inline_comparison.get("changed") or []:
        metric = str(item.get("metric") or "").strip()
        if not metric:
            continue
        lowered = metric.lower()
        role = None
        direction = "nonzero"
        if "attacker" in lowered:
            role = "attacker"
            direction = "increase"
        elif any(label in lowered for label in ("vault", "pool", "protocol")):
            role = "protocol"
        objectives.append({
            "label": metric,
            "match": metric,
            "direction": direction,
            "decimals": 0,
            "unit": "raw",
            "role": role,
        })
        if len(objectives) >= 10:
            break
    return objectives


def _failure_matching_lines(output: str, needles: tuple[str, ...], *, limit: int = 5) -> list[str]:
    matches = []
    lowered_needles = tuple(item.lower() for item in needles)
    for raw_line in _strip_ansi(output).splitlines():
        line = raw_line.strip()
        if not line:
            continue
        lowered = line.lower()
        if any(needle in lowered for needle in lowered_needles):
            matches.append(_truncate(line, 240))
        if len(matches) >= limit:
            break
    return matches


def _compile_repair_hints(output: str) -> list[str]:
    text = _strip_ansi(output).lower()
    hints = []
    if "forge-std/test.sol" in text or "source not found" in text:
        hints.append(
            "resolve forge-std/remappings or run the generated test from the target project root before changing the hypothesis"
        )
    if "invalid checksum" in text or "correct checksummed address" in text:
        hints.append(
            "repair address literal checksum casing; run_experiment auto_repair can apply this once for generated Foundry harnesses"
        )
    if "requires different compiler version" in text or "pragma" in text:
        hints.append(
            "regenerate the harness with a solidity_pragma compatible with the target profile before editing protocol logic"
        )
    if (
        "undeclared identifier" in text
        or "identifier not found" in text
        or "not found or not visible" in text
    ):
        hints.append(
            "repair generated interface names, helper imports, and placeholder argument variables before mutating the attack branch"
        )
    if "typeerror" in text or "invalid type" in text:
        hints.append(
            "align generated argument placeholder types with the action-space parameter metadata and simplify complex calldata first"
        )
    return _dedupe_text(hints)


def _experiment_failure_diagnosis(
    *,
    output: str,
    exit_code: int,
    outcome: str,
    sequence_payload: dict | None,
) -> dict | None:
    if exit_code == 0:
        return None
    diagnostics = [
        {
            "kind": "timeout",
            "needles": ("timed out", "timeout"),
            "summary": "The experiment timed out before producing stable evidence.",
            "repairs": [
                "narrow the matched test, reduce fuzz runs or loop bounds, and rerun the same command",
                "split setup, execution, and assertion into smaller tests before mutating the hypothesis",
            ],
            "next_tool": "run_experiment",
        },
        {
            "kind": "compile_error",
            "needles": (
                "compiler run failed",
                "compilation failed",
                "parsererror",
                "typeerror",
                "declarationerror",
                "undeclared identifier",
                "source not found",
                "member not found",
            ),
            "summary": "The harness or project failed before execution, so no exploit evidence was produced.",
            "repairs": [
                "fix imports, interfaces, target bindings, and generated helper types before changing the hypothesis",
                "rerun the exact command after the compile fix and compare the new failure mode",
            ],
            "next_tool": "run_experiment",
        },
        {
            "kind": "missing_or_invalid_binding",
            "needles": (
                "address(0)",
                "zero address",
                "call to non-contract",
                "bind target",
                "target address",
            ),
            "summary": "The run appears blocked by an unbound or invalid target/fork address.",
            "repairs": [
                "verify target_addresses, fork context contracts, deployed code, and _bindTargets before mutating the exploit idea",
                "record or update fork_context if the sequence needs live deployed addresses",
            ],
            "next_tool": "record_fork_context or compose_sequence_experiment with explicit actions",
        },
        {
            "kind": "fork_or_token_setup",
            "needles": (
                "eth_rpc_url",
                "createfork",
                "createselectfork",
                "insufficient allowance",
                "insufficient balance",
                "transfer amount exceeds balance",
                "allowance below",
                "seed below",
                "fork token",
            ),
            "summary": "The run appears blocked by fork selection, token balance, or approval setup.",
            "repairs": [
                "confirm RPC/fork block, seed amounts, token decimals, and spender scope before changing the attack sequence",
                "reduce only one setup assumption at a time after the baseline objective marker is stable",
            ],
            "next_tool": "record_fork_context or run_experiment",
        },
        {
            "kind": "assertion_failure",
            "needles": (
                "assertion failed",
                "assertion violated",
                "assertgt",
                "assertge",
                "assertlt",
                "assertle",
                "asserteq",
                "not satisfied",
            ),
            "summary": "The harness executed but an assertion did not match the observed state.",
            "repairs": [
                "compare before/after snapshots and decide whether the assertion, setup, or hypothesis is wrong",
                "if the objective direction is wrong, evaluate the nearest adjacent invariant before widening scope",
            ],
            "next_tool": "compare_snapshots or evaluate_objective",
        },
        {
            "kind": "runtime_revert",
            "needles": (
                "[fail. reason:",
                "evmerror: revert",
                "execution reverted",
                "revert",
                "panic:",
            ),
            "summary": "The sequence reached execution but reverted before proving the objective.",
            "repairs": [
                "summarize the trace, identify the first protocol revert, and compare actor/order/amount/msg.value against the intended path",
                "repair setup if the revert is a precondition failure; mutate the hypothesis only after the revert is understood",
            ],
            "next_tool": "summarize_trace",
        },
    ]
    if exit_code in {124, -1}:
        selected = diagnostics[0]
        evidence = [outcome]
    else:
        selected = None
        evidence = []
        for diagnostic in diagnostics[1:]:
            evidence = _failure_matching_lines(output, diagnostic["needles"])
            if evidence:
                selected = diagnostic
                break
        if selected is None:
            selected = {
                "kind": "unclassified_blocked_run",
                "summary": "The command exited nonzero, but no common failure signature was recognized.",
                "repairs": [
                    "read the full log, summarize the trace if execution started, then record the failed assumption or rerun with narrower output",
                    "avoid mutating the hypothesis until the first blocker is identified",
                ],
                "next_tool": "summarize_trace or update_campaign decision",
            }
            evidence = _failure_matching_lines(
                output,
                ("fail", "error", "revert", "exception", "panic"),
            )

    confidence = "high" if selected["kind"] in {
        "timeout",
        "compile_error",
        "runtime_revert",
        "assertion_failure",
    } and evidence else "medium" if evidence else "low"
    compile_repair_hints = (
        _compile_repair_hints(output)
        if selected["kind"] == "compile_error"
        else []
    )
    return {
        "kind": selected["kind"],
        "confidence": confidence,
        "summary": selected["summary"],
        "exit_code": exit_code,
        "outcome": outcome,
        "sequence_id": (sequence_payload or {}).get("id"),
        "evidence_lines": evidence[:5],
        "compile_repair_hints": compile_repair_hints,
        "suggested_repairs": selected["repairs"],
        "recommended_next_tool": selected["next_tool"],
        "notes": [
            "This diagnosis is a repair prompt, not evidence that the hypothesis is false.",
            "Fix the earliest concrete blocker before widening or abandoning the attack branch.",
        ],
    }


def _replay_assertion_variable(prefix: str, metric: str) -> str:
    suffix = _solidity_identifier(metric, "Metric")
    return f"{prefix}{suffix[:1].upper()}{suffix[1:]}"


def _replay_assertion_suggestions(inline_comparison: dict) -> list[dict]:
    suggestions = []
    for item in inline_comparison.get("changed") or []:
        metric = str(item.get("metric") or "").strip()
        if not metric or "delta" not in item:
            continue
        before_value = _parse_int_value(str(item.get("before") or ""))
        after_value = _parse_int_value(str(item.get("after") or ""))
        delta = item.get("delta")
        if not isinstance(delta, int) or before_value is None or after_value is None:
            continue
        signed = before_value < 0 or after_value < 0
        value_type = "int256" if signed else "uint256"
        before_var = _replay_assertion_variable("before", metric)
        after_var = _replay_assertion_variable("after", metric)
        comment_metric = _safe_comment(metric)
        observed = (
            f"        // Observed {comment_metric}: before={before_value}, "
            f"after={after_value}, delta={delta}. Replace TODO reads with live scaffold reads."
        )
        before_line = (
            f"        {value_type} {before_var} = "
            f"/* TODO: read before {comment_metric} */ {before_value};"
        )
        after_line = (
            f"        {value_type} {after_var} = "
            f"/* TODO: read after {comment_metric} */ {after_value};"
        )
        if delta > 0:
            direction = "increase"
            direction_assertion = (
                f'        assertGt({after_var}, {before_var}, "{comment_metric} should increase");'
            )
            delta_assertion = (
                f'        assertEq({after_var} - {before_var}, {abs(delta)}, '
                f'"{comment_metric} delta changed");'
            )
        elif delta < 0:
            direction = "decrease"
            direction_assertion = (
                f'        assertLt({after_var}, {before_var}, "{comment_metric} should decrease");'
            )
            delta_assertion = (
                f'        assertEq({before_var} - {after_var}, {abs(delta)}, '
                f'"{comment_metric} delta changed");'
            )
        else:
            direction = "unchanged"
            direction_assertion = (
                f'        assertEq({after_var}, {before_var}, "{comment_metric} should remain unchanged");'
            )
            delta_assertion = ""
        snippet = "\n".join(
            line for line in (
                observed,
                before_line,
                after_line,
                direction_assertion,
                delta_assertion,
            )
            if line
        )
        suggestions.append({
            "metric": metric,
            "before": str(item.get("before")),
            "after": str(item.get("after")),
            "delta": delta,
            "direction": direction,
            "before_line": item.get("before_line"),
            "after_line": item.get("after_line"),
            "foundry_assertion_snippet": snippet,
            "notes": (
                "Replace TODO reads with the scaffold's live before/after state reads; "
                "do not treat the observed literals as proof by themselves."
            ),
        })
        if len(suggestions) >= 10:
            break
    return suggestions


def _replay_followup_from_run(
    *,
    output: str,
    exit_code: int,
    outcome: str,
    result_id: str,
    log_path: str,
    title: str,
    related_ids: list[str],
    sequence_path: str,
    sequence_payload: dict | None,
) -> dict | None:
    entries = _replay_inline_snapshot_entries(output)
    snapshot_inputs = _replay_sequence_snapshot_templates(
        sequence_payload,
        related_ids=related_ids,
        title=title,
    )
    inline_comparison = _replay_inline_comparison(entries)
    objectives = _replay_objective_templates(inline_comparison)
    assertion_suggestions = _replay_assertion_suggestions(inline_comparison)
    failure_diagnosis = _experiment_failure_diagnosis(
        output=output,
        exit_code=exit_code,
        outcome=outcome,
        sequence_payload=sequence_payload,
    )
    minimization_plan = (
        (sequence_payload or {}).get("sequence_minimization_plan")
        if sequence_payload else None
    )
    minimization_run_template = (
        (sequence_payload or {}).get("sequence_minimization_run_template")
        if sequence_payload else None
    )
    if not isinstance(minimization_plan, dict):
        minimization_plan = None
    if not isinstance(minimization_run_template, dict):
        minimization_run_template = None
    minimization_variants = (minimization_plan or {}).get("variants") or []
    if not isinstance(minimization_variants, list):
        minimization_variants = []
    has_snapshot_inputs = bool(
        snapshot_inputs
        and any(
            snapshot_inputs["before"].get(key)
            for key in ("eth_balances", "erc20_balances", "calls")
        )
    )
    if not entries and not has_snapshot_inputs and not failure_diagnosis:
        return None

    recommended_tools = []
    if failure_diagnosis and failure_diagnosis.get("recommended_next_tool"):
        recommended_tools.append(str(failure_diagnosis["recommended_next_tool"]))
    if has_snapshot_inputs:
        recommended_tools.extend(["snapshot_state", "compare_snapshots"])
    if objectives:
        recommended_tools.append("evaluate_objective")
    if entries:
        recommended_tools.append("summarize_trace")
    if minimization_variants:
        recommended_tools.append("run_sequence_minimization")

    return {
        "result_id": result_id,
        "log_path": log_path,
        "sequence_path": sequence_path or None,
        "summary": {
            "inline_snapshot_entries": len(entries),
            "snapshot_state_templates": 2 if has_snapshot_inputs else 0,
            "objective_templates": len(objectives),
            "assertion_suggestions": len(assertion_suggestions),
            "minimization_variants": len(minimization_variants),
            "has_failure_diagnosis": bool(failure_diagnosis),
            "failure_kind": (
                failure_diagnosis.get("kind") if failure_diagnosis else None
            ),
        },
        "recommended_tools": _dedupe_text(recommended_tools),
        "failure_diagnosis": failure_diagnosis,
        "inline_snapshots": entries[:80],
        "inline_comparison": inline_comparison,
        "objective_assertion_suggestions": assertion_suggestions,
        "sequence_minimization_plan": (
            {
                "strategy": minimization_plan.get("strategy"),
                "assertion_target": minimization_plan.get("assertion_target"),
                "variants": minimization_variants[:12],
                "setup_reduction": minimization_plan.get("setup_reduction"),
                "stop_conditions": minimization_plan.get("stop_conditions") or [],
            }
            if minimization_plan else None
        ),
        "sequence_minimization_run_template": minimization_run_template,
        "snapshot_state_inputs": snapshot_inputs,
        "compare_snapshots_input": (
            {
                "before": "<before_snapshot_id>",
                "after": "<after_snapshot_id>",
                "related_ids": related_ids,
            }
            if has_snapshot_inputs else None
        ),
        "evaluate_objective_input": (
            {
                "comparison": "<comparison_id>",
                "objectives": objectives,
                "related_ids": related_ids,
            }
            if objectives else None
        ),
        "notes": [
            (
                "Inline Foundry logs are useful triage, but bug-bounty evidence "
                "should still use concrete assertions or saved state snapshots "
                "when possible."
            ),
            (
                "Review decimals, units, actor addresses, and expected direction "
                "before using generated objective templates."
            ),
            (
                "Assertion snippets intentionally keep TODO reads visible; replace "
                "them with real scaffold reads before relying on minimization or report evidence."
            ),
        ],
    }


async def _create_experiment(container: AuditContainer, args: dict) -> str:
    title = args.get("title", "").strip()
    if not title:
        return "Error: 'title' is required"

    template = args.get("template", "blank")
    if template not in _EXPERIMENT_TEMPLATES:
        return f"Error: unknown experiment template '{template}'"
    priority = args.get("priority")
    if priority is not None and priority not in _CAMPAIGN_PRIORITIES:
        return f"Error: unknown campaign priority '{priority}'"

    try:
        target_dir = _normalize_experiment_target_dir(
            args.get("target_dir", "/workspace/experiments")
        )
    except ValueError as exc:
        return f"Error: {exc}"

    state = await _load_campaign_state(container)
    artifact_id = _next_campaign_id(state, "experiment")
    experiment_dir = posixpath.join(
        target_dir,
        f"{artifact_id}-{_slugify(title)}",
    )
    related_ids = [
        item for item in (
            args.get("hypothesis_id", "").strip(),
            args.get("invariant_id", "").strip(),
        )
        if item
    ]
    notes = args.get("notes", "")
    write_scaffold_contract = bool(args.get("write_scaffold_contract", True))
    solidity_pragma = _normalize_solidity_pragma(args.get("solidity_pragma"))
    files = _experiment_files(
        artifact_id=artifact_id,
        title=title,
        template=template,
        notes=notes,
        related_ids=related_ids,
        write_scaffold_contract=write_scaffold_contract,
        solidity_pragma=solidity_pragma,
    )

    written_paths = []
    for filename, content in files.items():
        path = posixpath.join(experiment_dir, filename)
        await container.write_file(path, content)
        written_paths.append(path)

    now = datetime.now(timezone.utc).isoformat()
    state["sections"]["experiment"].append({
        "id": artifact_id,
        "created_at": now,
        "updated_at": now,
        "title": title,
        "content": (
            f"Template: {template}\n"
            f"Workspace: {experiment_dir}\n\n"
            f"Scaffold contract: {str(write_scaffold_contract and template != 'blank').lower()}\n"
            f"Solidity pragma: {solidity_pragma}\n\n"
            f"{notes.strip() or 'Experiment scaffold created; fill in target-specific logic.'}"
        ),
        "status": "open",
        "priority": priority,
        "evidence": written_paths,
        "related_ids": related_ids,
    })
    await _save_campaign_state(container, state)

    return (
        f"Created experiment {artifact_id}: {title}\n"
        f"Workspace: {experiment_dir}\n"
        "Files:\n- " + "\n- ".join(written_paths)
    )


def _experiment_timeout(command: str, requested_timeout: object | None) -> int:
    if requested_timeout is not None:
        try:
            return min(max(int(requested_timeout), 1), 1800)
        except (TypeError, ValueError):
            return 600

    command_text = command.lower()
    if re.search(r"\bforge\s+build\b", command_text) or re.search(
        r"\b(solc|npm|yarn|pnpm)\s+(build|compile)\b",
        command_text,
    ):
        return 600
    if any(
        token in command_text
        for token in (
            "slither",
            "mythril",
            "semgrep",
            "solhint",
            "forge inspect",
            "forge tree",
            "forge selectors",
            "forge test",
        )
    ):
        return 300
    if any(token in command_text for token in ("echidna", "medusa")):
        return 900
    if re.search(r"\bcast\s+(call|storage|balance|code|chain-id|block|logs)\b", command_text):
        return 120
    if re.search(r"\b(python3?|node|deno|ruby|perl|bash|sh)\b", command_text):
        return 90
    return 180


def _foundry_checksum_repairs(output: str, working_dir: str) -> list[dict]:
    lines = _strip_ansi(output).splitlines()
    repairs = []
    for index, line in enumerate(lines):
        correct = re.search(
            r'Correct checksummed address:\s*"?(0x[0-9a-fA-F]{40})"?',
            line,
        )
        if not correct:
            continue
        location = None
        for candidate in lines[max(0, index - 8): min(len(lines), index + 8)]:
            match = re.search(r"-->\s+([^:\s]+):(\d+):(\d+)", candidate)
            if match:
                location = match
                break
        if not location:
            continue
        source_path = location.group(1)
        if not source_path.startswith("/"):
            source_path = posixpath.normpath(posixpath.join(working_dir, source_path))
        repairs.append({
            "path": source_path,
            "line": int(location.group(2)),
            "column": int(location.group(3)),
            "correct": correct.group(1),
        })
    return repairs


def _foundry_repair_path_allowed(path: str) -> bool:
    normalized = posixpath.normpath(path)
    basename = posixpath.basename(normalized)
    if normalized.startswith("/workspace/experiments/"):
        return True
    return (
        normalized.startswith(("/audit/test/", "/audit/tests/"))
        and basename.startswith("ReentbotPro")
        and basename.endswith(".t.sol")
    )


async def _apply_foundry_checksum_repairs(
    container: AuditContainer,
    output: str,
    working_dir: str,
) -> list[dict]:
    applied = []
    for repair in _foundry_checksum_repairs(output, working_dir):
        path = repair["path"]
        if not _foundry_repair_path_allowed(path):
            continue
        try:
            content = await container.read_file(path)
        except FileNotFoundError:
            continue
        lines = content.splitlines(keepends=True)
        line_index = int(repair["line"]) - 1
        if line_index < 0 or line_index >= len(lines):
            continue
        line = lines[line_index]
        correct = repair["correct"]
        address_matches = list(re.finditer(r"0x[0-9a-fA-F]{40}", line))
        selected = None
        for match in address_matches:
            if match.group(0).lower() == correct.lower():
                selected = match
                break
        if selected is None and len(address_matches) == 1:
            selected = address_matches[0]
        if selected is None or selected.group(0) == correct:
            continue
        lines[line_index] = line[:selected.start()] + correct + line[selected.end():]
        await container.write_file(path, "".join(lines))
        applied.append({
            "path": path,
            "line": repair["line"],
            "from": selected.group(0),
            "to": correct,
        })
    return applied


def _candidate_target_local_poc_paths(command: str, working_dir: str) -> list[str]:
    candidates = []
    try:
        tokens = shlex.split(command)
    except ValueError:
        tokens = command.split()
    for index, token in enumerate(tokens):
        values = [token]
        if token in {"--match-path", "--mc", "--match-contract"} and index + 1 < len(tokens):
            values.append(tokens[index + 1])
        for value in values:
            if ".t.sol" not in value:
                continue
            path = value.strip().strip("'\"")
            path = path.split(":", 1)[0]
            if not path.endswith(".t.sol"):
                continue
            if not path.startswith("/"):
                path = posixpath.normpath(posixpath.join(working_dir, path))
            else:
                path = posixpath.normpath(path)
            if path.startswith(("/audit/test/", "/audit/tests/")):
                candidates.append(path)
    return _unique_strings(candidates)


async def _mirror_target_local_pocs(
    container: AuditContainer,
    *,
    command: str,
    working_dir: str,
    result_id: str,
) -> list[str]:
    mirrored = []
    for source_path in _candidate_target_local_poc_paths(command, working_dir):
        try:
            content = await container.read_file(source_path)
        except FileNotFoundError:
            continue
        basename = posixpath.basename(source_path)
        destination = (
            f"/workspace/experiments/generated-pocs/{result_id}/{basename}"
        )
        await container.write_file(destination, content)
        mirrored.append(destination)
    return mirrored


async def _run_experiment(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    command = args.get("command", "")
    if not command:
        return "Error: 'command' is required"
    requested_run_kind = str(args.get("run_kind") or "auto").strip().lower()
    if requested_run_kind not in _EXPERIMENT_RUN_KINDS:
        return (
            "Error: run_kind must be one of "
            + ", ".join(sorted(_EXPERIMENT_RUN_KINDS))
        )
    try:
        auto_repair = _coerce_bool_arg(
            args.get("auto_repair"),
            "auto_repair",
            default=True,
        )
    except ValueError as exc:
        return f"Error: {exc}"

    working_dir = args.get("working_dir", "/audit")
    timeout = _experiment_timeout(command, args.get("timeout"))

    # Derive the experiment's fork RPC endpoint(s) up front so the command runs
    # against the correct chain-specific endpoint(s), injected per-exec, instead
    # of a single global ETH_RPC_URL baked into the container at startup. The
    # sequence payload is loaded here (when an experiment_id is given) for its
    # chain metadata and reused by the result-recording path below.
    experiment_id = args.get("experiment_id", "").strip()
    sequence_path = ""
    sequence_payload: dict | None = None
    if experiment_id:
        sequence_state = await _load_campaign_state(container)
        sequence_path, sequence_payload = await _load_sequence_payload_for_experiment(
            container,
            sequence_state,
            experiment_id,
        )
    fork_context = await _resolve_fork_context_arg(container, args.get("fork_context"))
    rpc_plan = await _resolve_experiment_rpc_endpoints(
        container,
        args,
        sequence_payload=sequence_payload,
        fork_context=fork_context,
        command=command,
        environ=environ,
        config=config,
    )
    if rpc_plan["error"]:
        return rpc_plan["error"]
    rpc_env = rpc_plan["env"] or None
    rpc_metadata = rpc_plan["metadata"]
    rpc_summary_line = _experiment_rpc_summary_line(rpc_metadata)

    wrapped = f"timeout --kill-after=5 {timeout}s bash -c {shlex.quote(command)}"
    exit_code, output = await container.exec(
        wrapped,
        working_dir=working_dir,
        timeout=timeout + 10,
        extra_env=rpc_env,
    )
    analysis_output = output
    full_output = output
    auto_repairs = []
    if exit_code != 0 and auto_repair and re.search(r"\bforge\b", command):
        auto_repairs = await _apply_foundry_checksum_repairs(
            container,
            output,
            working_dir,
        )
        if auto_repairs:
            rerun_exit_code, rerun_output = await container.exec(
                wrapped,
                working_dir=working_dir,
                timeout=timeout + 10,
                extra_env=rpc_env,
            )
            repair_summary = "\n".join(
                f"- {item['path']}:{item['line']} {item['from']} -> {item['to']}"
                for item in auto_repairs
            )
            full_output = (
                "[auto-repair] Applied invalid checksum address repairs and reran command.\n"
                f"{repair_summary}\n\n"
                "[first run]\n"
                f"{output}\n\n"
                "[rerun after auto-repair]\n"
                f"{rerun_output}"
            )
            exit_code = rerun_exit_code
            output = rerun_output
            analysis_output = rerun_output

    if exit_code == 124:
        outcome = f"timed out after {timeout}s (killed)"
        status = "blocked"
    elif exit_code == -1:
        outcome = f"timed out after {timeout}s"
        status = "blocked"
    elif exit_code == 0:
        outcome = "completed with exit code 0"
        status = "observed"
    else:
        outcome = f"completed with exit code {exit_code}"
        status = "blocked"

    record_result = args.get("record_result", True)
    result_id = ""
    log_path = ""
    if record_result:
        state = await _load_campaign_state(container)
        result_id = _next_campaign_id(state, "result")
        log_path = f"/workspace/campaign/results/{result_id}.log"

        related_ids = [
            item for item in (
                args.get("experiment_id", "").strip(),
                args.get("hypothesis_id", "").strip(),
            )
            if item
        ]
        title = args.get("title", "").strip() or f"Experiment run: {command[:80]}"
        interpretation = args.get("interpretation", "").strip()
        # sequence_path / sequence_payload were loaded up front (for chain
        # metadata) and are reused here for the replay follow-up.
        mirrored_pocs = await _mirror_target_local_pocs(
            container,
            command=command,
            working_dir=working_dir,
            result_id=result_id,
        )
        followup = _replay_followup_from_run(
            output=analysis_output,
            exit_code=exit_code,
            outcome=outcome,
            result_id=result_id,
            log_path=log_path,
            title=title,
            related_ids=related_ids,
            sequence_path=sequence_path,
            sequence_payload=sequence_payload,
        )
        followup_path = ""
        followup_label = "Replay follow-up" if sequence_payload else "Experiment follow-up"
        if followup:
            followup_path = f"/workspace/campaign/results/{result_id}.followup.json"
            await container.write_file(
                followup_path,
                json.dumps(followup, indent=2, sort_keys=True) + "\n",
            )
        run_classification = _classify_experiment_run(
            command=command,
            output=output,
            exit_code=exit_code,
            explicit_run_kind=requested_run_kind,
            sequence_payload=sequence_payload,
        )
        if (
            exit_code == 0
            and status == "observed"
            and run_classification["evidence_grade"] == "blocked"
        ):
            status = "blocked"
        rpc_log_block = f"{rpc_summary_line}\n" if rpc_summary_line else ""
        full_log = (
            f"Command: {command}\n"
            f"Working directory: {working_dir}\n"
            f"Timeout: {timeout}s\n"
            f"Outcome: {outcome}\n"
            f"Run kind: {run_classification['run_kind']}\n"
            f"Evidence grade: {run_classification['evidence_grade']}\n"
            "Requires objective reduction: "
            f"{str(run_classification['requires_objective_reduction']).lower()}\n"
            "Satisfies experiment run: "
            f"{str(run_classification['satisfies_experiment_run']).lower()}\n"
            f"{rpc_log_block}\n"
            f"{full_output}"
        )
        await container.write_file(log_path, full_log)
        content = (
            f"Command: {command}\n"
            f"Working directory: {working_dir}\n"
            f"Outcome: {outcome}\n"
            f"Exit code: {exit_code}\n"
            f"Log: {log_path}\n"
            f"Run kind: {run_classification['run_kind']}\n"
            f"Evidence grade: {run_classification['evidence_grade']}\n"
            "Satisfies experiment run: "
            f"{str(run_classification['satisfies_experiment_run']).lower()}\n"
            "Objective reduction required: "
            f"{str(run_classification['requires_objective_reduction']).lower()}\n"
            f"Classification reason: {run_classification['reason']}"
        )
        if followup_path:
            content += (
                f"\n{followup_label}: {followup_path}\n"
                "Suggested next tools: "
                + ", ".join(followup.get("recommended_tools") or [])
            )
            failure_diagnosis = followup.get("failure_diagnosis") or {}
            if failure_diagnosis:
                content += (
                    "\nFailure diagnosis: "
                    f"{failure_diagnosis.get('kind')} - "
                    f"{failure_diagnosis.get('summary')}"
                )
        if rpc_summary_line:
            content += f"\n{rpc_summary_line}"
        if interpretation:
            content += f"\n\nInitial interpretation:\n{interpretation}"
        if auto_repairs:
            content += (
                "\n\nAuto-repair applied before final run:\n"
                + "\n".join(
                    f"- {item['path']}:{item['line']} {item['from']} -> {item['to']}"
                    for item in auto_repairs
                )
            )
        if mirrored_pocs:
            content += (
                "\n\nMirrored generated PoC evidence:\n"
                + "\n".join(f"- {path}" for path in mirrored_pocs)
            )

        now = datetime.now(timezone.utc).isoformat()
        state["sections"]["result"].append({
            "id": result_id,
            "created_at": now,
            "updated_at": now,
            "title": title,
            "content": content,
            "status": status,
            "priority": None,
            "evidence": [
                log_path,
                *mirrored_pocs,
                *([followup_path] if followup_path else []),
            ],
            "related_ids": related_ids,
            "run_classification": run_classification,
            "rpc_endpoints": rpc_metadata,
        })
        await _save_campaign_state(container, state)

    result = full_output if auto_repairs else output
    if exit_code == 124:
        result = f"Command timed out after {timeout}s (killed)"
    elif exit_code == -1:
        result = f"Command timed out after {timeout}s"
    elif exit_code != 0:
        result += f"\n[exit code: {exit_code}]"
    result = _truncate(result)

    if rpc_summary_line:
        result += f"\n\n{rpc_summary_line}"
    if record_result:
        result += f"\n\nRecorded campaign result: {result_id} ({status})"
        result += (
            f"\nRun classification: {run_classification['run_kind']} / "
            f"{run_classification['evidence_grade']} "
            "(satisfies_experiment_run="
            f"{str(run_classification['satisfies_experiment_run']).lower()})"
        )
        result += f"\nFull log: {log_path}"
        if mirrored_pocs:
            result += "\nMirrored generated PoC: " + ", ".join(mirrored_pocs)
        if followup_path:
            result += f"\n{followup_label}: {followup_path}"
    return result


# ── Build/setup diagnostics ──────────────────────────────────────────────
#
# diagnose_build runs or parses a build/test-list command and turns raw solc/
# Foundry/Hardhat output into a small, structured list of blockers so the agent
# acts on a classified failure instead of re-reading a noisy log. It writes only
# a campaign artifact (never mutates an experiment's source or sequence.json);
# the submission gates still require a runnable PoC for high/critical findings.

_DIAGNOSE_LOG_ALLOWED_PREFIXES = ("/workspace/", "/audit/", "/output/")

# External-package markers in an unresolved import → a missing *dependency*
# (install/remapping problem) rather than a local missing_import (path/typo).
_DIAGNOSE_EXTERNAL_DEP_HINTS = (
    "@openzeppelin",
    "openzeppelin",
    "forge-std",
    "ds-test",
    "solmate",
    "solady",
    "@uniswap",
    "@aave",
    "@chainlink",
    "@layerzero",
    "node_modules",
    "/lib/",
)

# A line is only treated as a diagnostic header when it looks like a compiler/
# build error, never an echoed source line (solc prints the offending source
# under the error, which would otherwise false-positive on words like "import").
_DIAGNOSE_HEADER_RE = re.compile(
    r"(?i)("
    r"\berror\s*\(\d+\)\s*:|"
    r"\b(?:parser|declaration|type|syntax|fatal|unimplementedfeature)error\b|"
    r"\berror\s+hh\d+\b|"
    r"^\s*error:|"
    r"\bcompiler run failed\b|"
    r"\bcompilation failed\b|"
    r"requires different compiler version|"
    r"file import callback not supported|"
    r"cannot find module|module not found|npm err|"
    r"no tests to run|no tests match|no test contracts|did not match any tests|"
    r"failed to resolve|no solc version|could not find a compiler version|"
    r"couldn't install solc|unable to satisfy"
    r")"
)

# "unknown" is only emitted for a clearly compiler-shaped error we could not map
# to a specific kind — not for bare "Error:"/"Compiler run failed:" separators.
_DIAGNOSE_CODED_ERROR_RE = re.compile(
    r"(?i)\berror\s*\(\d+\)|\berror\s+hh\d+|"
    r"\b(?:parser|declaration|type|syntax|fatal)error\b"
)

_DIAGNOSE_LOCATION_RE = re.compile(r"-->\s+(\S[^:]*?):(\d+)(?::\d+)?")
_DIAGNOSE_INLINE_LOCATION_RE = re.compile(r"\b([\w./@-]+\.sol):(\d+)(?::\d+)?")
_DIAGNOSE_SYMBOL_RE = re.compile(r'"([^"]{1,120})"')

_DIAGNOSE_BUILD_SUCCESS_MARKERS = (
    "compiler run successful",
    "compilation finished successfully",
    "compiled successfully",
    "build successful",
    "build succeeded",
    "nothing to compile",
    "no files changed, compilation skipped",
)

_DIAGNOSE_SUGGESTED_NEXT = {
    "missing_dependency": "install_dependency",
    "compiler_version": "install_dependency",
    "missing_import": "repair_experiment",
    "pragma_mismatch": "repair_experiment",
    "duplicate_symbol": "repair_experiment",
    "undeclared_identifier": "repair_experiment",
    "type_error": "repair_experiment",
    "wrong_interface": "repair_experiment",
    "test_discovery": "repair_experiment",
    "unknown": "repair_experiment",
}


def _diagnose_log_path_allowed(path: str) -> bool:
    normalized = posixpath.normpath(str(path or ""))
    return normalized.startswith(_DIAGNOSE_LOG_ALLOWED_PREFIXES)


def _diagnose_path_is_external(line: str) -> bool:
    low = line.lower()
    return any(hint in low for hint in _DIAGNOSE_EXTERNAL_DEP_HINTS)


def _diagnose_build_line_kind(line: str) -> tuple[str, str] | None:
    """Classify a single build-log line into (kind, repair_hint) or None.

    Only lines that look like a compiler/build diagnostic header are considered,
    so echoed source lines never produce spurious diagnostics. Specific
    signatures are checked before general ones.
    """
    if not _DIAGNOSE_HEADER_RE.search(line):
        return None
    low = line.lower()
    if "already declared" in low:
        return (
            "duplicate_symbol",
            "remove the duplicate declaration/import or alias the conflicting symbol",
        )
    if (
        ("member" in low and "not found" in low)
        or "no matching declaration" in low
        or "wrong argument count" in low
        or "not unique after argument-dependent lookup" in low
        or "does not have a member" in low
    ):
        return (
            "wrong_interface",
            "align the interface/ABI signature, member names, and argument count "
            "with the real target contract",
        )
    if "undeclared identifier" in low or "identifier not found or not visible" in low:
        return (
            "undeclared_identifier",
            "declare/import the identifier or fix the generated placeholder "
            "variable or interface name",
        )
    if "requires different compiler version" in low or (
        "pragma" in low and "mismatch" in low
    ):
        return (
            "pragma_mismatch",
            "regenerate the harness with a solidity_pragma compatible with the "
            "target's pragma, or align the project pragma",
        )
    if (
        ("failed to resolve" in low and "version" in low)
        or "no solc version" in low
        or "could not find a compiler version" in low
        or "couldn't install solc" in low
        or "unable to satisfy" in low
        or "no matching solc" in low
    ):
        return (
            "compiler_version",
            "install or select a solc version that satisfies every pragma "
            "(Foundry: set solc/solc_version in foundry.toml)",
        )
    if (
        "file import callback not supported" in low
        or "cannot find module" in low
        or "module not found" in low
        or "npm err" in low
        or ("not found" in low and _diagnose_path_is_external(line))
    ):
        return (
            "missing_dependency",
            "install the missing dependency or fix remappings "
            "(forge install / npm install / remappings.txt)",
        )
    if (
        "not found" in low and ("source" in low or "file" in low or "import" in low)
    ) or "file not found" in low:
        return (
            "missing_import",
            "fix the import path or create the referenced file; verify remappings "
            "resolve it",
        )
    if (
        "no tests to run" in low
        or "no tests match" in low
        or "no test contracts" in low
        or "did not match any tests" in low
    ):
        return (
            "test_discovery",
            "fix the match filter, profile, or test path so the intended test is "
            "discovered and executed",
        )
    if (
        "typeerror" in low
        or "not implicitly convertible" in low
        or "is not convertible" in low
        or "invalid type" in low
        or "expected type" in low
    ):
        return (
            "type_error",
            "fix the type mismatch: cast or adjust the expression/argument to the "
            "expected Solidity type",
        )
    if _DIAGNOSE_CODED_ERROR_RE.search(line):
        return (
            "unknown",
            "read the full build log and fix the earliest concrete blocker before "
            "mutating the hypothesis",
        )
    return None


def _diagnose_find_location(lines: list[str], idx: int, bound: int) -> dict:
    """Find the file/line a solc error points at, searching only this block."""
    for offset in range(idx, min(bound, idx + 8)):
        match = _DIAGNOSE_LOCATION_RE.search(lines[offset])
        if match:
            return {"file": match.group(1).strip(), "line": int(match.group(2))}
    inline = _DIAGNOSE_INLINE_LOCATION_RE.search(lines[idx])
    if inline:
        return {"file": inline.group(1).strip(), "line": int(inline.group(2))}
    return {}


def _diagnose_extract_symbol(line: str) -> str:
    match = _DIAGNOSE_SYMBOL_RE.search(line)
    return match.group(1).strip() if match else ""


def _classify_build_output(output: str, *, max_diagnostics: int = 40) -> list[dict]:
    """Parse build/test-list output into structured blocker diagnostics."""
    lines = _strip_ansi(output or "").splitlines()
    headers: list[tuple[int, str, str]] = []
    for idx, raw in enumerate(lines):
        line = raw.strip()
        if not line:
            continue
        kind = _diagnose_build_line_kind(line)
        if kind:
            headers.append((idx, kind[0], kind[1]))
    diagnostics: list[dict] = []
    seen: set[tuple] = set()
    for position, (idx, kind, repair_hint) in enumerate(headers):
        next_idx = headers[position + 1][0] if position + 1 < len(headers) else len(lines)
        location = _diagnose_find_location(lines, idx, next_idx)
        message = _truncate(lines[idx].strip(), 240)
        diagnostic = {
            "kind": kind,
            "file": location.get("file", ""),
            "line": location.get("line"),
            "symbol": _diagnose_extract_symbol(lines[idx]),
            "message": message,
            "repair_hint": repair_hint,
        }
        key = (kind, diagnostic["file"], diagnostic["line"], message[:80])
        if key in seen:
            continue
        seen.add(key)
        diagnostics.append(diagnostic)
        if len(diagnostics) >= max_diagnostics:
            break
    return diagnostics


def _build_output_indicates_success(output: str) -> bool:
    low = _strip_ansi(output or "").lower()
    return any(marker in low for marker in _DIAGNOSE_BUILD_SUCCESS_MARKERS)


def _diagnose_first_error_line(output: str) -> str:
    stripped = _strip_ansi(output or "")
    for raw in stripped.splitlines():
        line = raw.strip()
        if line and _DIAGNOSE_HEADER_RE.search(line):
            return _truncate(line, 240)
    for raw in stripped.splitlines():
        line = raw.strip()
        if line and any(
            token in line.lower()
            for token in ("error", "fail", "revert", "exception", "panic")
        ):
            return _truncate(line, 240)
    return ""


def _infer_build_system(command: str, output: str, *, source: str = "") -> str:
    if source in {"profile", "experiment", "auto"}:
        return "foundry"
    text = f"{command}\n{output}".lower()
    foundry = bool(re.search(r"\b(forge|foundry|forge-std|solc)\b", text)) or (
        "foundry.toml" in text
    )
    hardhat = bool(re.search(r"\bhardhat\b|npx hardhat", text))
    solc_style = bool(re.search(r"error\s*\(\d+\)", text)) or any(
        token in text
        for token in ("parsererror", "declarationerror", "typeerror", "compiler run failed")
    )
    if hardhat and (foundry or solc_style):
        return "mixed"
    if hardhat:
        return "hardhat"
    if foundry or solc_style:
        return "foundry"
    return "unknown"


def _diagnose_unknown_build_system_response(path: str) -> str:
    return json.dumps(
        {
            "status": "unknown",
            "build_system": "unknown",
            "command": None,
            "exit_code": None,
            "diagnostics": [],
            "first_error": None,
            "suggested_next": "repair_experiment",
            "message": (
                f"no foundry.toml found under {path} and no command, log, "
                "log_path, experiment, or profile was provided; pass an explicit "
                "command, a log/log_path to parse, or an experiment id to diagnose"
            ),
        },
        indent=2,
        sort_keys=True,
    )


async def _diagnose_resolve_experiment_dir(
    container: AuditContainer,
    experiment: str,
) -> str:
    """Resolve an experiment ref to a build working directory.

    Raises ValueError with an actionable message when it cannot be resolved.
    Reads campaign state only; it never rewrites the experiment.
    """
    ref = str(experiment or "").strip()
    if re.fullmatch(r"exp-\d{3,}", ref):
        state = await _load_campaign_state(container)
        workspace = _experiment_workspace_from_state(state, ref)
        if workspace:
            return workspace
        try:
            path, _payload = await _load_sequence_payload_for_experiment(
                container, state, ref
            )
        except Exception:
            path = ""
        if path:
            return posixpath.dirname(path)
        raise ValueError(
            f"{ref} has no recorded workspace; pass an explicit command or "
            "experiment directory"
        )
    if ref.startswith("/"):
        normalized = posixpath.normpath(ref)
        if not normalized.startswith("/workspace/experiments/"):
            raise ValueError("experiment paths must be under /workspace/experiments/")
        if normalized.endswith(".json"):
            return posixpath.dirname(normalized)
        return normalized
    raise ValueError(
        "experiment must be an exp-NNN id or an absolute path under "
        "/workspace/experiments/"
    )


async def _diagnose_build(container: AuditContainer, args: dict) -> str:
    path = str(args.get("path") or "/audit").strip() or "/audit"
    try:
        timeout = _coerce_bounded_int_arg(
            args.get("timeout"), "timeout", default=120, minimum=1, maximum=600
        )
        record_result = _coerce_bool_arg(
            args.get("record_result"), "record_result", default=True
        )
    except ValueError as exc:
        return f"Error: {exc}"

    command_arg = str(args.get("command") or "").strip()
    profile_arg = str(args.get("profile") or "").strip()
    experiment_arg = str(args.get("experiment") or "").strip()
    log_arg = args.get("log")
    log_path_arg = str(args.get("log_path") or "").strip()

    source = ""
    command = ""
    working_dir = path
    exit_code: int | None = None
    output = ""
    ran = False

    if isinstance(log_arg, str) and log_arg.strip():
        output = log_arg
        source = "log"
    elif log_path_arg:
        if not _diagnose_log_path_allowed(log_path_arg):
            return json.dumps(
                {
                    "error": "log_path_not_allowed",
                    "log_path": log_path_arg,
                    "message": "log_path must be under /workspace, /audit, or /output",
                },
                indent=2,
                sort_keys=True,
            )
        try:
            output = await container.read_file(log_path_arg)
        except Exception as exc:
            return json.dumps(
                {
                    "error": "log_path_unreadable",
                    "log_path": log_path_arg,
                    "message": str(exc),
                },
                indent=2,
                sort_keys=True,
            )
        source = "log_path"
    else:
        if command_arg:
            command = command_arg
            source = "command"
        elif experiment_arg:
            try:
                working_dir = await _diagnose_resolve_experiment_dir(
                    container, experiment_arg
                )
            except ValueError as exc:
                return json.dumps(
                    {
                        "error": "experiment_unresolved",
                        "experiment": experiment_arg,
                        "message": str(exc),
                    },
                    indent=2,
                    sort_keys=True,
                )
            command = "forge build"
            source = "experiment"
        elif profile_arg:
            command = f"FOUNDRY_PROFILE={shlex.quote(profile_arg)} forge build"
            source = "profile"
        else:
            root = await _foundry_project_root(container, path)
            if not root:
                return _diagnose_unknown_build_system_response(path)
            working_dir = root
            command = "forge build --skip test"
            source = "auto"
        wrapped = f"timeout --kill-after=5 {timeout}s bash -c {shlex.quote(command)}"
        exit_code, output = await container.exec(
            wrapped,
            working_dir=working_dir,
            timeout=timeout + 10,
        )
        ran = True

    build_system = _infer_build_system(command, output, source=source)
    diagnostics = _classify_build_output(output)
    classified = [item for item in diagnostics if item["kind"] != "unknown"]
    timed_out = ran and exit_code in {124, -1}

    if not ran:
        status = (
            "observed"
            if (diagnostics or _build_output_indicates_success(output))
            else "unknown"
        )
    elif timed_out:
        status = "blocked"
    elif classified:
        status = "observed"
    elif exit_code == 0:
        status = "observed"
    else:
        status = "blocked"

    # Make sure first_error/suggested_next stay meaningful when a run failed
    # without a recognizable compiler signature (timeout or opaque failure).
    if not diagnostics and ran and (timed_out or (exit_code not in {0, None})):
        if timed_out:
            message = f"build/test command timed out after {timeout}s"
            repair_hint = (
                "narrow the build to one package/contract, raise timeout, or split "
                "setup from the failing target"
            )
        else:
            message = (
                _diagnose_first_error_line(output)
                or f"build failed with exit code {exit_code}"
            )
            repair_hint = (
                "read the full build log and fix the earliest concrete blocker "
                "before mutating the hypothesis"
            )
        diagnostics = [
            {
                "kind": "unknown",
                "file": "",
                "line": None,
                "symbol": "",
                "message": _truncate(message, 240),
                "repair_hint": repair_hint,
            }
        ]

    first_error = diagnostics[0] if diagnostics else None
    if first_error is not None:
        suggested_next = _DIAGNOSE_SUGGESTED_NEXT.get(
            first_error["kind"], "repair_experiment"
        )
        if (
            experiment_arg
            and first_error["kind"] in {"wrong_interface", "undeclared_identifier"}
        ):
            suggested_next = "complete_sequence_experiment"
    elif status == "observed":
        # No blocker and the build/log is clean — go run the actual harness.
        suggested_next = "run_experiment"
    else:
        # Parsed a log we could not classify (status unknown): keep repairing.
        suggested_next = "repair_experiment"

    state = await _load_campaign_state(container)
    bdiag_id = _next_campaign_id(state, "build_diagnostic")
    created_at = datetime.now(timezone.utc).isoformat()
    artifact_path = f"/workspace/campaign/build-diagnostics/{bdiag_id}.json"
    log_path_out = f"/workspace/campaign/build-diagnostics/{bdiag_id}.log"

    raw_output = _strip_ansi(output or "")
    full_log = (
        f"diagnose_build: {bdiag_id}\n"
        f"Source: {source}\n"
        f"Command: {command or '(parsed log, not run)'}\n"
        f"Working directory: {working_dir}\n"
        f"Exit code: {exit_code if exit_code is not None else '(unknown)'}\n"
        f"Build system: {build_system}\n"
        f"Status: {status}\n\n"
        f"{raw_output}"
    )
    # sha/bytes/line_count all describe the bounded .log artifact actually written.
    encoded_log = full_log.encode("utf-8", "replace")
    log_sha256 = hashlib.sha256(encoded_log).hexdigest()
    log_bytes = len(encoded_log)
    log_line_count = len(full_log.splitlines())

    artifact = {
        "id": bdiag_id,
        "created_at": created_at,
        "status": status,
        "build_system": build_system,
        "source": source,
        "command": command,
        "working_dir": working_dir,
        "exit_code": exit_code,
        "diagnostics": diagnostics,
        "first_error": first_error,
        "suggested_next": suggested_next,
        "log_path": log_path_out,
        "log_sha256": log_sha256,
        "log_line_count": log_line_count,
        "log_bytes": log_bytes,
    }
    await container.write_file(log_path_out, full_log)
    await container.write_file(
        artifact_path,
        json.dumps(artifact, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if record_result:
        if status == "unknown":
            result_status = "inconclusive"
        elif status == "blocked":
            result_status = "blocked"
        else:
            result_status = "observed"
        related = [
            item for item in (experiment_arg,) if re.fullmatch(r"exp-\d{3,}", item)
        ]
        kinds = ", ".join(dict.fromkeys(item["kind"] for item in diagnostics)) or "none"
        result_id = await _record_result_artifact(
            container,
            title=f"Build diagnosis: {build_system} ({status})",
            content=(
                f"Build diagnostic: {bdiag_id}\n"
                f"Source: {source}\n"
                f"Command: {command or '(parsed log)'}\n"
                f"Build system: {build_system}\n"
                f"Status: {status}\n"
                f"Exit code: {exit_code if exit_code is not None else '(unknown)'}\n"
                f"Diagnostics: {len(diagnostics)} ({kinds})\n"
                f"First error: {first_error['kind'] if first_error else 'none'}\n"
                f"Suggested next: {suggested_next}\n"
                f"Artifact: {artifact_path}\n"
                f"Log: {log_path_out}"
            ),
            evidence=[artifact_path, log_path_out],
            related_ids=[bdiag_id, *related],
            status=result_status,
        )

    response = {
        "build_diagnostic_id": bdiag_id,
        "status": status,
        "build_system": build_system,
        "command": command or None,
        "exit_code": exit_code,
        "diagnostics": diagnostics,
        "first_error": first_error,
        "suggested_next": suggested_next,
        "path": artifact_path,
        "log_path": log_path_out,
        "log_sha256": log_sha256,
        "log_line_count": log_line_count,
        "result_id": result_id or None,
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _sequence_json_path_from_ref(ref: str) -> str:
    value = ref.strip()
    if not value:
        raise ValueError("sequence is required")
    if not value.startswith("/"):
        raise ValueError(
            "sequence must be an experiment id like exp-001, an experiment "
            "directory, or an absolute sequence.json path"
        )
    normalized = posixpath.normpath(value)
    if not normalized.startswith("/workspace/experiments/"):
        raise ValueError(
            "absolute sequence paths must be under /workspace/experiments/"
        )
    if normalized.endswith("/sequence.json"):
        return normalized
    if normalized.endswith(".json"):
        if posixpath.basename(normalized) != "sequence.json":
            raise ValueError("absolute sequence JSON path must end with sequence.json")
        return normalized
    return posixpath.join(normalized, "sequence.json")


async def _load_sequence_payload_ref(
    container: AuditContainer,
    ref: str,
) -> tuple[str, dict]:
    value = str(ref or "").strip()
    if not value:
        raise ValueError("sequence is required")
    if re.fullmatch(r"exp-\d{3,}", value):
        state = await _load_campaign_state(container)
        path, payload = await _load_sequence_payload_for_experiment(
            container,
            state,
            value,
        )
        if path and payload:
            return path, payload
        raise ValueError(f"experiment {value} has no readable sequence.json")

    path = _sequence_json_path_from_ref(value)
    raw = await container.read_file(path)
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"sequence {path} is not valid JSON") from exc
    if not isinstance(payload, dict):
        raise ValueError(f"sequence {path} must be a JSON object")
    return path, payload


def _minimization_marker_list(run: dict, key: str) -> list[str]:
    values = [str(item) for item in _require_list(run.get(key), key)]
    return [item for item in values if item]


def _minimization_run_spec(run: dict, *, name: str) -> dict:
    spec = _require_dict(run, name)
    command = str(spec.get("command") or "").strip()
    if not command:
        raise ValueError(f"{name} requires command")
    expected_markers = _minimization_marker_list(spec, "expected_markers")
    if not expected_markers:
        raise ValueError(f"{name} requires at least one expected_marker")
    forbidden_markers = _minimization_marker_list(spec, "forbidden_markers")
    return {
        "variant_id": str(
            spec.get("variant_id")
            or spec.get("id")
            or name
        ).strip(),
        "command": command,
        "working_dir": str(spec.get("working_dir") or "").strip(),
        "timeout": spec.get("timeout"),
        "expected_markers": expected_markers,
        "forbidden_markers": forbidden_markers,
        "require_exit_zero": bool(spec.get("require_exit_zero", True)),
        "notes": str(spec.get("notes") or "").strip(),
    }


def _setup_check_key(kind: str, target: str) -> str:
    return f"{kind.strip().lower()}::{target.strip().lower()}"


def _minimization_setup_check_spec(run: dict, *, name: str) -> dict:
    raw = _require_dict(run, name)
    spec = _minimization_run_spec(raw, name=name)
    kind = str(raw.get("kind") or raw.get("setup_kind") or "setup").strip()
    target = str(
        raw.get("target")
        or raw.get("setup_target")
        or raw.get("assumption")
        or kind
    ).strip()
    check_id = str(
        raw.get("check_id")
        or raw.get("id")
        or raw.get("variant_id")
        or f"{kind}-{target}"
    ).strip()
    spec.update({
        "check_id": _slugify(check_id) or f"setup-{len(kind) + len(target)}",
        "kind": kind,
        "target": target,
        "change": str(raw.get("change") or raw.get("reduction") or "").strip(),
        "retain_if": str(raw.get("retain_if") or "").strip(),
    })
    return spec


def _minimization_plan_variants(sequence_payload: dict) -> dict[str, dict]:
    plan = sequence_payload.get("sequence_minimization_plan") or {}
    if not isinstance(plan, dict):
        return {}
    variants = plan.get("variants") or []
    if not isinstance(variants, list):
        return {}
    result = {}
    for variant in variants:
        if not isinstance(variant, dict):
            continue
        variant_id = str(variant.get("id") or "").strip()
        if variant_id:
            result[variant_id] = variant
    return result


def _minimization_plan_setup_items(sequence_payload: dict) -> dict[str, dict]:
    plan = sequence_payload.get("sequence_minimization_plan") or {}
    if not isinstance(plan, dict):
        return {}
    setup_reduction = plan.get("setup_reduction") or {}
    if not isinstance(setup_reduction, dict):
        return {}
    items = setup_reduction.get("challenge_items") or []
    if not isinstance(items, list):
        return {}
    result = {}
    for item in items:
        if not isinstance(item, dict):
            continue
        kind = str(item.get("kind") or "").strip()
        target = str(item.get("target") or "").strip()
        if kind or target:
            result[_setup_check_key(kind, target)] = item
    return result


def _minimization_outcome(exit_code: int, timeout: int) -> tuple[str, str]:
    if exit_code == 124:
        return "timed_out", f"timed out after {timeout}s (killed)"
    if exit_code == -1:
        return "timed_out", f"timed out after {timeout}s"
    if exit_code == 0:
        return "completed", "completed with exit code 0"
    return "completed", f"completed with exit code {exit_code}"


def _minimization_preservation(
    *,
    output: str,
    exit_code: int,
    spec: dict,
) -> dict:
    expected = spec.get("expected_markers") or []
    forbidden = spec.get("forbidden_markers") or []
    missing_expected = [marker for marker in expected if marker not in output]
    forbidden_present = [marker for marker in forbidden if marker in output]
    exit_ok = exit_code == 0 if spec.get("require_exit_zero", True) else exit_code != -1
    preserved = exit_ok and not missing_expected and not forbidden_present
    if preserved:
        status = "preserved"
    elif not exit_ok:
        status = "blocked"
    else:
        status = "rejected"
    return {
        "status": status,
        "preserved": preserved,
        "exit_ok": exit_ok,
        "missing_expected_markers": missing_expected,
        "forbidden_markers_present": forbidden_present,
    }


async def _run_minimization_spec(
    container: AuditContainer,
    *,
    spec: dict,
    run_id: str,
    minimization_id: str,
    sequence_path: str,
    default_working_dir: str,
    default_timeout: int,
    planned_variant: dict | None = None,
    extra_env: dict[str, str] | None = None,
) -> dict:
    working_dir = spec.get("working_dir") or default_working_dir
    timeout = min(int(spec.get("timeout") or default_timeout), 1800)
    command = spec["command"]
    wrapped = f"timeout --kill-after=5 {timeout}s bash -c {shlex.quote(command)}"
    exit_code, output = await container.exec(
        wrapped,
        working_dir=working_dir,
        timeout=timeout + 10,
        extra_env=extra_env,
    )
    outcome, outcome_text = _minimization_outcome(exit_code, timeout)
    preservation = _minimization_preservation(
        output=output,
        exit_code=exit_code,
        spec=spec,
    )
    safe_run_id = _slugify(run_id) or "run"
    log_path = f"/workspace/campaign/minimizations/{minimization_id}/{safe_run_id}.log"
    await container.write_file(
        log_path,
        (
            f"Sequence: {sequence_path}\n"
            f"Run: {run_id}\n"
            f"Command: {command}\n"
            f"Working directory: {working_dir}\n"
            f"Timeout: {timeout}s\n"
            f"Outcome: {outcome_text}\n"
            f"Preservation status: {preservation['status']}\n\n"
            f"{output}"
        ),
    )
    return {
        "id": run_id,
        "kind": (planned_variant or {}).get("kind") or (
            "baseline" if run_id == "baseline" else "manual_variant"
        ),
        "command": command,
        "working_dir": working_dir,
        "timeout": timeout,
        "exit_code": exit_code,
        "outcome": outcome,
        "outcome_text": outcome_text,
        "log_path": log_path,
        "expected_markers": spec.get("expected_markers") or [],
        "forbidden_markers": spec.get("forbidden_markers") or [],
        "notes": spec.get("notes") or "",
        "planned_variant": planned_variant,
        **preservation,
    }


def _minimization_skipped_variant(spec: dict, planned_variant: dict | None) -> dict:
    run_id = spec.get("variant_id") or "variant"
    return {
        "id": run_id,
        "kind": (planned_variant or {}).get("kind") or "manual_variant",
        "command": spec.get("command"),
        "status": "skipped",
        "preserved": False,
        "reason": "baseline did not preserve expected markers",
        "planned_variant": planned_variant,
    }


def _setup_check_label(item: dict) -> str:
    kind = str(item.get("kind") or "setup").strip()
    target = str(item.get("target") or "").strip()
    change = str(item.get("change") or "").strip()
    label = f"{kind}: {target}" if target else kind
    if change:
        label = f"{label} ({change})"
    return label


async def _run_setup_check_spec(
    container: AuditContainer,
    *,
    spec: dict,
    minimization_id: str,
    sequence_path: str,
    default_working_dir: str,
    default_timeout: int,
    planned_setup: dict | None = None,
    extra_env: dict[str, str] | None = None,
) -> dict:
    run_id = spec.get("check_id") or "setup-check"
    run = await _run_minimization_spec(
        container,
        spec=spec,
        run_id=run_id,
        minimization_id=minimization_id,
        sequence_path=sequence_path,
        default_working_dir=default_working_dir,
        default_timeout=default_timeout,
        planned_variant={"kind": spec.get("kind") or "setup"},
        extra_env=extra_env,
    )
    run.update({
        "kind": spec.get("kind") or "setup",
        "target": spec.get("target") or "",
        "change": spec.get("change") or "",
        "retain_if": (
            spec.get("retain_if")
            or (planned_setup or {}).get("retain_if")
            or ""
        ),
        "planned_setup": planned_setup,
        "setup_outcome": "reduced" if run.get("preserved") else "retained",
    })
    return run


def _minimization_skipped_setup_check(
    spec: dict,
    planned_setup: dict | None,
) -> dict:
    run_id = spec.get("check_id") or "setup-check"
    return {
        "id": run_id,
        "kind": spec.get("kind") or "setup",
        "target": spec.get("target") or "",
        "change": spec.get("change") or "",
        "command": spec.get("command"),
        "status": "skipped",
        "preserved": False,
        "reason": "baseline did not preserve expected markers",
        "retain_if": (
            spec.get("retain_if")
            or (planned_setup or {}).get("retain_if")
            or ""
        ),
        "planned_setup": planned_setup,
        "setup_outcome": "unproven",
    }


def _setup_check_summaries(
    setup_checks: list[dict],
    *,
    preserved: bool,
) -> list[dict]:
    return [
        {
            "id": item.get("id"),
            "kind": item.get("kind"),
            "target": item.get("target"),
            "change": item.get("change"),
            "status": item.get("status"),
            "log_path": item.get("log_path"),
            "label": _setup_check_label(item),
        }
        for item in setup_checks
        if bool(item.get("preserved")) is preserved
    ]


def _setup_reduction_summary(setup_checks: list[dict]) -> dict:
    executed = [
        item for item in setup_checks
        if item.get("status") != "skipped"
    ]
    preserved = [
        item for item in setup_checks
        if item.get("preserved")
    ]
    retained = [
        item for item in executed
        if not item.get("preserved")
    ]
    return {
        "planned": len(setup_checks),
        "executed": len(executed),
        "preserved": len(preserved),
        "retained": len(retained),
        "skipped": sum(1 for item in setup_checks if item.get("status") == "skipped"),
        "reduced_setup": _setup_check_summaries(preserved, preserved=True),
        "retained_setup": _setup_check_summaries(retained, preserved=False),
    }


def _minimization_best_variant(baseline: dict, variants: list[dict]) -> dict | None:
    preserved = [item for item in variants if item.get("preserved")]
    if not preserved:
        return baseline if baseline.get("preserved") else None

    def sort_key(item: dict) -> tuple[int, int, str]:
        planned = item.get("planned_variant") or {}
        steps = planned.get("steps")
        step_count = len(steps) if isinstance(steps, list) else 10_000
        return step_count, 0 if item.get("status") == "preserved" else 1, item["id"]

    return sorted(preserved, key=sort_key)[0]


def _minimization_summary(
    baseline: dict,
    variants: list[dict],
    setup_checks: list[dict] | None = None,
) -> dict:
    executed_variants = [
        item for item in variants
        if item.get("status") != "skipped"
    ]
    preserved_variants = [
        item for item in variants
        if item.get("preserved")
    ]
    best = _minimization_best_variant(baseline, variants)
    summary = {
        "baseline_preserved": bool(baseline.get("preserved")),
        "planned_variants": len(variants),
        "executed_variants": len(executed_variants),
        "preserved_variants": len(preserved_variants),
        "rejected_variants": sum(
            1 for item in variants if item.get("status") == "rejected"
        ),
        "blocked_variants": sum(
            1 for item in variants if item.get("status") == "blocked"
        ),
        "skipped_variants": sum(
            1 for item in variants if item.get("status") == "skipped"
        ),
        "minimal_preserved_variant": best.get("id") if best else None,
    }
    if setup_checks is not None:
        setup_summary = _setup_reduction_summary(setup_checks)
        summary.update({
            "setup_checks_planned": setup_summary["planned"],
            "setup_checks_executed": setup_summary["executed"],
            "setup_checks_preserved": setup_summary["preserved"],
            "setup_checks_retained": setup_summary["retained"],
            "setup_checks_skipped": setup_summary["skipped"],
        })
    return summary


def _minimization_run_plan_coverage(
    *,
    planned_variants: dict[str, dict],
    variants: list[dict],
    planned_setup_items: dict[str, dict],
    setup_checks: list[dict],
) -> dict:
    planned_variant_ids = set(planned_variants)
    requested_variant_ids = {
        str(item.get("id") or "").strip()
        for item in variants
        if str(item.get("id") or "").strip()
    }
    planned_setup_keys = set(planned_setup_items)
    requested_setup_keys = {
        _setup_check_key(str(item.get("kind") or ""), str(item.get("target") or ""))
        for item in setup_checks
        if str(item.get("kind") or "").strip() or str(item.get("target") or "").strip()
    }
    return {
        "planned_variants": sorted(planned_variant_ids),
        "requested_variants": sorted(requested_variant_ids),
        "untested_plan_variants": sorted(planned_variant_ids - requested_variant_ids),
        "unplanned_requested_variants": sorted(requested_variant_ids - planned_variant_ids),
        "planned_setup_checks": sorted(planned_setup_keys),
        "requested_setup_checks": sorted(requested_setup_keys),
        "untested_setup_checks": sorted(planned_setup_keys - requested_setup_keys),
        "unplanned_setup_checks": sorted(requested_setup_keys - planned_setup_keys),
    }


async def _run_sequence_minimization(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    try:
        sequence_path, sequence_payload = await _load_sequence_payload_ref(
            container,
            str(args.get("sequence") or ""),
        )
        baseline_spec = _minimization_run_spec(
            args.get("baseline"),
            name="baseline",
        )
        variant_specs = [
            _minimization_run_spec(item, name=f"variants[{index}]")
            for index, item in enumerate(_require_list(args.get("variants"), "variants"))
        ]
        setup_check_specs = [
            _minimization_setup_check_spec(item, name=f"setup_checks[{index}]")
            for index, item in enumerate(
                _require_list(args.get("setup_checks"), "setup_checks")
            )
        ]
        related_ids = [
            str(item) for item in _require_list(args.get("related_ids"), "related_ids")
        ]
    except (FileNotFoundError, ValueError) as exc:
        return f"Error: {exc}"

    default_working_dir = str(args.get("working_dir") or "/audit").strip() or "/audit"
    default_timeout = min(int(args.get("timeout", 600) or 600), 1800)
    run_variants_if_baseline_fails = bool(
        args.get("run_variants_if_baseline_fails", False)
    )
    planned_variants = _minimization_plan_variants(sequence_payload)
    planned_setup_items = _minimization_plan_setup_items(sequence_payload)

    # Inject the same chain-specific fork RPC endpoint(s) run_experiment derives,
    # so minimization replays fork against the experiment's chain(s) rather than a
    # global ETH_RPC_URL. Shares the resolver; same env is reused for every run.
    fork_context = await _resolve_fork_context_arg(container, args.get("fork_context"))
    rpc_plan = await _resolve_experiment_rpc_endpoints(
        container,
        args,
        sequence_payload=sequence_payload,
        fork_context=fork_context,
        command=str(baseline_spec.get("command") or ""),
        environ=environ,
        config=config,
    )
    if rpc_plan["error"]:
        return rpc_plan["error"]
    rpc_env = rpc_plan["env"] or None

    state = await _load_campaign_state(container)
    minimization_id = _next_campaign_id(state, "sequence_minimization")
    title = str(args.get("title") or "").strip() or (
        f"Sequence minimization for {sequence_payload.get('id') or sequence_path}"
    )

    baseline = await _run_minimization_spec(
        container,
        spec=baseline_spec,
        run_id="baseline",
        minimization_id=minimization_id,
        sequence_path=sequence_path,
        default_working_dir=default_working_dir,
        default_timeout=default_timeout,
        extra_env=rpc_env,
    )

    variants = []
    if baseline.get("preserved") or run_variants_if_baseline_fails:
        for spec in variant_specs:
            run_id = spec.get("variant_id") or f"variant-{len(variants) + 1:03d}"
            variants.append(await _run_minimization_spec(
                container,
                spec=spec,
                run_id=run_id,
                minimization_id=minimization_id,
                sequence_path=sequence_path,
                default_working_dir=default_working_dir,
                default_timeout=default_timeout,
                planned_variant=planned_variants.get(run_id),
                extra_env=rpc_env,
            ))
    else:
        for spec in variant_specs:
            run_id = spec.get("variant_id") or f"variant-{len(variants) + 1:03d}"
            variants.append(_minimization_skipped_variant(
                spec,
                planned_variants.get(run_id),
            ))

    setup_checks = []
    if baseline.get("preserved") or run_variants_if_baseline_fails:
        for spec in setup_check_specs:
            planned_setup = planned_setup_items.get(
                _setup_check_key(spec.get("kind") or "", spec.get("target") or "")
            )
            setup_checks.append(await _run_setup_check_spec(
                container,
                spec=spec,
                minimization_id=minimization_id,
                sequence_path=sequence_path,
                default_working_dir=default_working_dir,
                default_timeout=default_timeout,
                planned_setup=planned_setup,
                extra_env=rpc_env,
            ))
    else:
        for spec in setup_check_specs:
            planned_setup = planned_setup_items.get(
                _setup_check_key(spec.get("kind") or "", spec.get("target") or "")
            )
            setup_checks.append(_minimization_skipped_setup_check(
                spec,
                planned_setup,
            ))

    setup_summary = _setup_reduction_summary(setup_checks)
    summary = _minimization_summary(baseline, variants, setup_checks)
    plan_coverage = _minimization_run_plan_coverage(
        planned_variants=planned_variants,
        variants=variants,
        planned_setup_items=planned_setup_items,
        setup_checks=setup_checks,
    )
    summary.update({
        "available_plan_variants": len(plan_coverage["planned_variants"]),
        "requested_plan_variants": len(plan_coverage["requested_variants"]),
        "untested_plan_variants": len(plan_coverage["untested_plan_variants"]),
        "unplanned_requested_variants": len(
            plan_coverage["unplanned_requested_variants"]
        ),
        "available_setup_checks": len(plan_coverage["planned_setup_checks"]),
        "requested_setup_checks": len(plan_coverage["requested_setup_checks"]),
        "untested_setup_checks": len(plan_coverage["untested_setup_checks"]),
        "unplanned_setup_checks": len(plan_coverage["unplanned_setup_checks"]),
    })
    best_variant = _minimization_best_variant(baseline, variants)
    if str(sequence_payload.get("id") or ""):
        related_ids = _dedupe_text([sequence_payload["id"], *related_ids])

    minimization = {
        "id": minimization_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "sequence_path": sequence_path,
        "sequence_id": sequence_payload.get("id"),
        "strategy": (
            (sequence_payload.get("sequence_minimization_plan") or {}).get("strategy")
            if isinstance(sequence_payload.get("sequence_minimization_plan"), dict)
            else None
        ),
        "related_ids": related_ids,
        "summary": summary,
        "baseline": baseline,
        "variants": variants,
        "setup_checks": setup_checks,
        "setup_reduction_summary": setup_summary,
        "plan_coverage": plan_coverage,
        "best_variant": best_variant,
        "notes": [
            "A preserved variant only means the explicit markers survived this command.",
            "A preserved setup check only means the selected setup reduction preserved the explicit markers.",
            "Use compare_snapshots/evaluate_objective or concrete assertions before treating it as bounty evidence.",
        ],
    }
    minimization_path = f"/workspace/campaign/minimizations/{minimization_id}.json"
    await container.write_file(
        minimization_path,
        json.dumps(minimization, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Sequence minimization: {title}",
            content=(
                f"Sequence minimization: {minimization_id}\n"
                f"Path: {minimization_path}\n"
                f"Sequence: {sequence_path}\n"
                f"Baseline preserved: {summary['baseline_preserved']}\n"
                f"Executed variants: {summary['executed_variants']}\n"
                f"Preserved variants: {summary['preserved_variants']}\n"
                f"Minimal preserved variant: {summary['minimal_preserved_variant'] or 'none'}\n"
                f"Untested planned variants: {summary['untested_plan_variants']}\n"
                f"Setup checks executed: {summary['setup_checks_executed']}\n"
                f"Setup checks retained: {summary['setup_checks_retained']}"
            ),
            evidence=[
                minimization_path,
                baseline["log_path"],
                *[
                    item["log_path"]
                    for item in variants
                    if item.get("log_path")
                ],
                *[
                    item["log_path"]
                    for item in setup_checks
                    if item.get("log_path")
                ],
            ],
            related_ids=related_ids,
            status="observed" if baseline.get("preserved") else "blocked",
        )

    response = {
        "minimization_id": minimization_id,
        "path": minimization_path,
        "result_id": result_id or None,
        "summary": summary,
        "setup_reduction_summary": setup_summary,
        "plan_coverage": plan_coverage,
        "best_variant": best_variant,
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _fuzz_output_snippets(
    output: str,
    *,
    max_snippets: int,
    context_lines: int = 4,
) -> list[dict]:
    marker_re = re.compile(
        "|".join(re.escape(marker) for marker in _FUZZ_FAILURE_MARKERS),
        re.IGNORECASE,
    )
    lines = output.splitlines()
    snippets = []
    covered: set[int] = set()
    for index, line in enumerate(lines):
        if len(snippets) >= max_snippets:
            break
        if not marker_re.search(line):
            continue
        if index in covered:
            continue
        start = max(index - context_lines, 0)
        end = min(index + context_lines + 1, len(lines))
        covered.update(range(start, end))
        context = "\n".join(lines[start:end])
        snippets.append({
            "line": index + 1,
            "marker": _brief_text(line, max_chars=180),
            "context": _truncate(context, 2_000),
        })
    return snippets


def _fuzz_outcome(exit_code: int, output: str, timeout: int) -> tuple[str, str]:
    if exit_code == 124:
        return "timed_out", f"timed out after {timeout}s (killed)"
    if exit_code == -1:
        return "timed_out", f"timed out after {timeout}s"
    marker_re = re.compile(
        "|".join(re.escape(marker) for marker in _FUZZ_FAILURE_MARKERS),
        re.IGNORECASE,
    )
    if exit_code != 0 and marker_re.search(output):
        return "candidate_failure", f"completed with exit code {exit_code}"
    if exit_code == 0:
        return "no_counterexample", "completed with exit code 0"
    return "command_failed", f"completed with exit code {exit_code}"


def _fuzz_next_actions(outcome: str) -> list[str]:
    if outcome == "candidate_failure":
        return [
            "Call summarize_trace on the fuzz log if the output contains a useful Foundry trace.",
            "Call extract_call_sequence if the log contains a replayable sequence.",
            "Reduce the sequence into compose_sequence_experiment with explicit actions, then capture snapshots and evaluate_objective.",
        ]
    if outcome == "no_counterexample":
        return [
            "Record what invariant was not falsified and mutate the hypothesis or broaden the handler action space.",
            "Refresh plan_attack_campaign if this was the active top branch.",
        ]
    if outcome == "timed_out":
        return [
            "Reduce fuzz depth, target one handler/action set, or increase timeout only if the run is still informative.",
            "Record a blocked result or mutate the harness assumption if it is not converging.",
        ]
    return [
        "Inspect the command failure before interpreting the run as security evidence.",
        "Fix build/harness issues or record a blocked result with the failing log.",
    ]


async def _run_campaign_fuzz(container: AuditContainer, args: dict) -> str:
    command = str(args.get("command") or "").strip()
    if not command:
        return "Error: 'command' is required"

    working_dir = args.get("working_dir", "/audit")
    timeout = min(max(int(args.get("timeout", 900)), 1), 1800)
    max_snippets = min(max(int(args.get("max_snippets", 8)), 1), 25)
    wrapped = f"timeout --kill-after=5 {timeout}s bash -c {shlex.quote(command)}"
    exit_code, output = await container.exec(
        wrapped,
        working_dir=working_dir,
        timeout=timeout + 10,
    )

    outcome, outcome_detail = _fuzz_outcome(exit_code, output, timeout)
    snippets = _fuzz_output_snippets(
        output,
        max_snippets=max_snippets,
    )
    related_ids = [
        item for item in (
            str(args.get("experiment_id") or "").strip(),
            str(args.get("hypothesis_id") or "").strip(),
            str(args.get("invariant_id") or "").strip(),
        )
        if item
    ]

    state = await _load_campaign_state(container)
    fuzz_id = _next_campaign_id(state, "fuzz_run")
    title = str(args.get("title") or "").strip() or f"Fuzz campaign: {command[:80]}"
    run_path = f"/workspace/campaign/fuzz-runs/{fuzz_id}.json"
    log_path = f"/workspace/campaign/fuzz-runs/{fuzz_id}.log"
    created_at = datetime.now(timezone.utc).isoformat()
    full_log = (
        f"Command: {command}\n"
        f"Working directory: {working_dir}\n"
        f"Timeout: {timeout}s\n"
        f"Outcome: {outcome_detail}\n"
        f"Classification: {outcome}\n\n"
        f"{output}"
    )
    summary = {
        "exit_code": exit_code,
        "outcome": outcome,
        "candidate_failure": outcome == "candidate_failure",
        "snippets": len(snippets),
        "log_bytes": len(full_log.encode()),
    }
    run = {
        "id": fuzz_id,
        "title": title,
        "created_at": created_at,
        "command": command,
        "working_dir": working_dir,
        "timeout": timeout,
        "exit_code": exit_code,
        "outcome": outcome,
        "outcome_detail": outcome_detail,
        "summary": summary,
        "log_path": log_path,
        "failure_snippets": snippets,
        "related_ids": related_ids,
        "next_actions": _fuzz_next_actions(outcome),
    }
    await container.write_file(log_path, full_log)
    await container.write_file(
        run_path,
        json.dumps(run, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        status = "blocked" if outcome in {"timed_out", "command_failed"} else "observed"
        result_id = await _record_result_artifact(
            container,
            title=f"Fuzz campaign run: {title}",
            content=(
                f"Fuzz run: {fuzz_id}\n"
                f"Command: {command}\n"
                f"Outcome: {outcome}\n"
                f"Log: {log_path}\n"
                f"Run artifact: {run_path}\n"
                f"Failure snippets: {len(snippets)}"
            ),
            evidence=[run_path, log_path],
            related_ids=[fuzz_id, *related_ids],
            status=status,
        )

    response = {
        "fuzz_run_id": fuzz_id,
        "path": run_path,
        "log_path": log_path,
        "result_id": result_id or None,
        "summary": summary,
        "next_actions": run["next_actions"],
        "failure_snippets": snippets,
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _cast_rpc_arg(rpc_url: str | None) -> str:
    return f" --rpc-url {shlex.quote(rpc_url)}" if rpc_url else ""


async def _run_probe(container: AuditContainer, command: str) -> dict:
    exit_code, output = await container.exec(command, timeout=30)
    text = output.strip()
    probe = {
        "command": command,
        "exit_code": exit_code,
        "ok": exit_code == 0,
    }
    if exit_code == 0:
        probe["value"] = text
    else:
        probe["error"] = text
    return probe


def _require_list(value, name: str) -> list:
    if value is None:
        return []
    if not isinstance(value, list):
        raise ValueError(f"{name} must be a list")
    return value


def _require_dict(value, name: str) -> dict:
    if not isinstance(value, dict):
        raise ValueError(f"{name} entries must be objects")
    return value


def _coerce_bool_arg(value: object, name: str, *, default: bool) -> bool:
    if value is None:
        return default
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        normalized = value.strip().lower()
        if normalized in {"true", "1", "yes", "y", "on"}:
            return True
        if normalized in {"false", "0", "no", "n", "off"}:
            return False
    raise ValueError(f"{name} must be a boolean")


def _coerce_bounded_int_arg(
    value: object,
    name: str,
    *,
    default: int,
    minimum: int,
    maximum: int,
) -> int:
    if value is None or value == "":
        return default
    try:
        number = int(value)
    except (TypeError, ValueError) as exc:
        raise ValueError(f"{name} must be an integer") from exc
    return min(max(number, minimum), maximum)


def _snapshot_probe_key(kind: str, probe: dict) -> str:
    match kind:
        case "eth_balances":
            return f"eth:{probe.get('label') or ''}:{probe.get('address')}"
        case "erc20_balances":
            return (
                "erc20:"
                f"{probe.get('token_label') or ''}:{probe.get('token')}:"
                f"{probe.get('account_label') or ''}:{probe.get('account')}"
            )
        case "storage_slots":
            return (
                "storage:"
                f"{probe.get('label') or ''}:{probe.get('contract')}:"
                f"{probe.get('slot')}"
            )
        case "calls":
            args = ",".join(probe.get("args") or [])
            return (
                "call:"
                f"{probe.get('label') or ''}:{probe.get('target')}:"
                f"{probe.get('signature')}:{args}"
            )
        case _:
            return f"{kind}:{probe.get('label') or probe.get('command')}"


def _parse_int_value(value: str | None) -> int | None:
    if value is None:
        return None
    text = value.strip()
    if not text:
        return None
    if "\n" in text:
        return None
    try:
        return int(text, 0)
    except ValueError:
        return None


async def _record_result_artifact(
    container: AuditContainer,
    *,
    title: str,
    content: str,
    evidence: list[str],
    related_ids: list[str],
    status: str = "observed",
) -> str:
    state = await _load_campaign_state(container)
    result_id = _next_campaign_id(state, "result")
    now = datetime.now(timezone.utc).isoformat()
    state["sections"]["result"].append({
        "id": result_id,
        "created_at": now,
        "updated_at": now,
        "title": title,
        "content": content,
        "status": status,
        "priority": None,
        "evidence": evidence,
        "related_ids": related_ids,
    })
    await _save_campaign_state(container, state)
    return result_id


_FORK_CONTEXT_COLLECTIONS = (
    "contracts",
    "tokens",
    "pools",
    "routers",
    "oracles",
    "flash_loan_providers",
    "actors",
)
_FORK_ADDRESS_COLLECTIONS = (
    "contracts",
    "tokens",
    "pools",
    "routers",
    "oracles",
    "flash_loan_providers",
)
_FORK_PROBE_COLLECTIONS = (
    "pools",
    "routers",
    "oracles",
    "flash_loan_providers",
)
_FORK_CONTEXT_DISPLAY_COLLECTIONS = (
    ("contracts", "Contracts"),
    ("tokens", "Tokens"),
    ("pools", "Pools"),
    ("routers", "Routers"),
    ("oracles", "Oracles"),
    ("flash_loan_providers", "Flash-loan providers"),
    ("actors", "Actors"),
)
_FORK_PROBE_DISPLAY_COLLECTIONS = (
    ("pools", "Pools"),
    ("routers", "Routers"),
    ("oracles", "Oracles"),
    ("flash_loan_providers", "Flash-loan providers"),
)


def _context_label(item: dict, fallback: str) -> str:
    for key in ("label", "name", "symbol", "role", "kind"):
        text = str(item.get(key) or "").strip()
        if text:
            return text
    return fallback


def _context_address(item: dict) -> str:
    for key in ("address", "target", "pair", "provider", "asset", "token"):
        text = str(item.get(key) or "").strip()
        if text:
            return text
    return ""


def _fork_context_items(args: dict, name: str) -> list[dict]:
    return [
        _require_dict(item, name)
        for item in _require_list(args.get(name), name)
    ]


def _fork_context_target_addresses(context: dict) -> dict[str, str]:
    targets = {}
    for collection in _FORK_ADDRESS_COLLECTIONS:
        for index, item in enumerate(context.get(collection, []), start=1):
            address = _context_address(item)
            if not address:
                continue
            label = _context_label(item, f"{collection}_{index}")
            targets[label] = address
    return targets


def _redact_rpc_from_probe(probe: dict, rpc_url: str) -> dict:
    if not rpc_url:
        return dict(probe)
    redacted = dict(probe)
    command = str(redacted.get("command") or "")
    if command:
        redacted["command"] = command.replace(rpc_url, "<rpc_url>")
    return redacted


async def _run_fork_context_probe(
    container: AuditContainer,
    command: str,
    *,
    rpc_url: str,
) -> dict:
    return _redact_rpc_from_probe(await _run_probe(container, command), rpc_url)


def _compact_code_probe(probe: dict) -> dict:
    compact = {
        "command": probe.get("command"),
        "exit_code": probe.get("exit_code"),
        "ok": probe.get("ok"),
    }
    if not probe.get("ok"):
        compact["error"] = str(probe.get("error") or "")[:500]
        compact["code_present"] = False
        return compact
    code = str(probe.get("value") or "").strip()
    compact["code_present"] = bool(code and code != "0x")
    if code.startswith("0x") and len(code) >= 2:
        compact["code_bytes"] = max(0, (len(code) - 2) // 2)
    compact["code_prefix"] = code[:66]
    return compact


async def _probe_fork_code_targets(
    container: AuditContainer,
    context: dict,
    *,
    rpc_url: str,
) -> list[dict]:
    rpc_arg = _cast_rpc_arg(rpc_url)
    probes = []
    for collection in _FORK_ADDRESS_COLLECTIONS:
        for index, item in enumerate(context.get(collection, []), start=1):
            address = _context_address(item)
            if not address:
                continue
            raw_probe = await _run_fork_context_probe(
                container,
                f"cast code {shlex.quote(address)}{rpc_arg}",
                rpc_url=rpc_url,
            )
            probes.append({
                "collection": collection,
                "label": _context_label(item, f"{collection}_{index}"),
                "address": address,
                "probe": _compact_code_probe(raw_probe),
            })
    return probes


async def _probe_fork_tokens(
    container: AuditContainer,
    tokens: list[dict],
    *,
    rpc_url: str,
) -> list[dict]:
    rpc_arg = _cast_rpc_arg(rpc_url)
    probes = []
    for index, item in enumerate(tokens, start=1):
        address = _context_address(item)
        if not address:
            continue
        decimals_probe = await _run_fork_context_probe(
            container,
            (
                f"cast call {shlex.quote(address)} "
                f"{shlex.quote('decimals()(uint8)')}{rpc_arg}"
            ),
            rpc_url=rpc_url,
        )
        symbol_probe = await _run_fork_context_probe(
            container,
            (
                f"cast call {shlex.quote(address)} "
                f"{shlex.quote('symbol()(string)')}{rpc_arg}"
            ),
            rpc_url=rpc_url,
        )
        probes.append({
            "label": _context_label(item, f"token_{index}"),
            "address": address,
            "decimals": {
                **decimals_probe,
                "parsed": _parse_int_value(decimals_probe.get("value")),
            },
            "symbol": symbol_probe,
        })
    return probes


async def _probe_fork_actor_balances(
    container: AuditContainer,
    actors: list[dict],
    *,
    rpc_url: str,
) -> list[dict]:
    rpc_arg = _cast_rpc_arg(rpc_url)
    probes = []
    for index, item in enumerate(actors, start=1):
        address = _context_address(item)
        if not address:
            continue
        probe = await _run_fork_context_probe(
            container,
            f"cast balance {shlex.quote(address)}{rpc_arg}",
            rpc_url=rpc_url,
        )
        probes.append({
            "label": _context_label(item, f"actor_{index}"),
            "address": address,
            "balance": {
                **probe,
                "parsed_wei": _parse_int_value(probe.get("value")),
            },
        })
    return probes


async def _fork_context_validation(
    container: AuditContainer,
    context: dict,
    *,
    endpoint: ResolvedRpcEndpoint,
    probe_token_metadata: bool,
) -> dict:
    rpc_url = endpoint.url or ""
    rpc_arg = _cast_rpc_arg(rpc_url)
    validation = {
        "requested": True,
        "executed": True,
        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
        "chain_id": await _run_fork_context_probe(
            container,
            f"cast chain-id{rpc_arg}",
            rpc_url=rpc_url,
        ),
        "block_number": await _run_fork_context_probe(
            container,
            f"cast block-number{rpc_arg}",
            rpc_url=rpc_url,
        ),
        "code": await _probe_fork_code_targets(
            container,
            context,
            rpc_url=rpc_url,
        ),
        "actor_balances": await _probe_fork_actor_balances(
            container,
            context.get("actors", []),
            rpc_url=rpc_url,
        ),
    }
    validation["chain_id"]["parsed"] = _parse_int_value(validation["chain_id"].get("value"))
    validation["block_number"]["parsed"] = _parse_int_value(
        validation["block_number"].get("value")
    )
    if probe_token_metadata:
        validation["token_metadata"] = await _probe_fork_tokens(
            container,
            context.get("tokens", []),
            rpc_url=rpc_url,
        )
    else:
        validation["token_metadata"] = []
    return validation


async def _record_fork_context(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    title = str(args.get("title") or "").strip()
    if not title:
        return "Error: 'title' is required"

    try:
        related_ids = [
            str(item) for item in _require_list(args.get("related_ids"), "related_ids")
        ]
        assumptions = [
            str(item) for item in _require_list(args.get("assumptions"), "assumptions")
        ]
        context = {
            name: _fork_context_items(args, name)
            for name in _FORK_CONTEXT_COLLECTIONS
        }
    except ValueError as exc:
        return f"Error: {exc}"

    state = await _load_campaign_state(container)
    context_id = _next_campaign_id(state, "fork_context")
    validate = bool(args.get("validate", False))
    probe_token_metadata = bool(args.get("probe_token_metadata", True))
    target_addresses = _fork_context_target_addresses(context)

    # Resolve a chain-aware endpoint: explicit rpc_url/network/chain_id args win,
    # else infer the chain from this context's deployed targets via the chain
    # registry. A bare cast default chain is never assumed.
    addr_refs, name_refs = _fork_context_chain_targets(context)
    endpoint = await _resolve_tool_rpc_endpoint(
        container,
        args,
        target_addresses=addr_refs,
        target_names=name_refs,
        environ=environ,
        config=config,
    )
    chain_evidence = None
    if endpoint.source == "chain_registry":
        chain_evidence = {
            "source": "chain_registry",
            "chains": await _tool_chain_candidates(
                container, addresses=addr_refs, names=name_refs
            ),
        }

    rpc_endpoint_summary = _rpc_endpoint_summary(endpoint)
    if validate and endpoint.url:
        validation = await _fork_context_validation(
            container,
            context,
            endpoint=endpoint,
            probe_token_metadata=probe_token_metadata,
        )
    elif validate:
        # Validation was asked for but no endpoint could be resolved — record the
        # blocker explicitly rather than silently probing cast's default chain.
        validation = {
            "requested": True,
            "executed": False,
            "error": _unresolved_rpc_error(endpoint),
            "rpc_endpoint": rpc_endpoint_summary,
            "code": [],
            "token_metadata": [],
            "actor_balances": [],
        }
        if validation["error"] == "chain_ambiguous":
            validation["candidates"] = await _tool_chain_candidates(
                container, addresses=addr_refs, names=name_refs
            )
    else:
        validation = {
            "requested": False,
            "executed": False,
            "rpc_endpoint": rpc_endpoint_summary,
            "code": [],
            "token_metadata": [],
            "actor_balances": [],
        }

    code_probes = validation.get("code", [])
    code_present = sum(
        1 for item in code_probes if item.get("probe", {}).get("code_present")
    )
    code_missing = sum(
        1
        for item in code_probes
        if item.get("probe", {}).get("ok")
        and not item.get("probe", {}).get("code_present")
    )
    # Keep the agent's declared chain verbatim for display continuity; fall back
    # to the registry-inferred chain only when no explicit network/chain_id was
    # given. Downstream resolution canonicalizes either form.
    network_arg = _coerce_nonempty(args.get("network"))
    chain_id_arg = args.get("chain_id")
    stored_network = network_arg or endpoint.network or ""
    if chain_id_arg not in (None, ""):
        stored_chain_id = chain_id_arg
    elif endpoint.chain_id is not None:
        stored_chain_id = endpoint.chain_id
    else:
        stored_chain_id = ""
    fork_context = {
        "id": context_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "network": stored_network,
        "chain_id": stored_chain_id,
        "fork_block": args.get("fork_block", ""),
        "rpc_endpoint": rpc_endpoint_summary,
        "notes": args.get("notes", ""),
        "assumptions": assumptions,
        "related_ids": related_ids,
        **context,
        "target_addresses": target_addresses,
        "validation": validation,
        "summary": {
            **{
                collection: len(context[collection])
                for collection in _FORK_CONTEXT_COLLECTIONS
            },
            "target_addresses": len(target_addresses),
            "validated": validate and endpoint.url is not None,
            "code_probes": len(code_probes),
            "code_present": code_present,
            "code_missing": code_missing,
        },
    }
    if chain_evidence:
        fork_context["chain_evidence"] = chain_evidence
    context_path = f"/workspace/campaign/fork-contexts/{context_id}.json"
    await container.write_file(
        context_path,
        json.dumps(fork_context, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Fork context: {title}",
            content=(
                f"Fork context: {context_id}\n"
                f"Path: {context_path}\n"
                f"Network: {fork_context['network'] or 'unknown'}\n"
                f"Fork block: {fork_context['fork_block'] or 'unknown'}\n"
                f"Targets: {len(target_addresses)}\n"
                f"Validation: {'enabled' if validate else 'not requested'}\n"
                f"Code probes present/missing: {code_present}/{code_missing}"
            ),
            evidence=[context_path],
            related_ids=related_ids,
            status="observed",
        )

    response = {
        "context_id": context_id,
        "path": context_path,
        "result_id": result_id or None,
        "network": fork_context["network"],
        "chain_id": fork_context["chain_id"],
        "rpc_endpoint": rpc_endpoint_summary,
        "summary": fork_context["summary"],
        "target_addresses": target_addresses,
        "validation": validation,
    }
    if chain_evidence:
        response["chain_evidence"] = chain_evidence
    return json.dumps(response, indent=2, sort_keys=True)


def _fork_context_path(identifier: str) -> str:
    value = identifier.strip()
    if not value:
        raise ValueError("fork_context cannot be empty")
    if value.startswith("/"):
        normalized = posixpath.normpath(value)
        if not normalized.startswith("/workspace/campaign/fork-contexts/"):
            raise ValueError(
                "absolute fork_context paths must be under "
                "/workspace/campaign/fork-contexts/"
            )
        return normalized
    if not re.fullmatch(r"fc-\d{3,}", value):
        raise ValueError("fork_context must be an id like fc-001 or an absolute path")
    return f"/workspace/campaign/fork-contexts/{value}.json"


async def _load_fork_context(
    container: AuditContainer,
    identifier: str,
) -> tuple[str, dict]:
    path = _fork_context_path(identifier)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"fork_context {path} is not valid JSON") from exc


# ── Chain / deployment registry + tool-side RPC resolution ────────────────
#
# The agent starts with no chain bound (no manual --chain for normal use).
# These helpers infer chain/deployment context from the target repo, persist a
# compact, durable campaign registry artifact, and give tools a single shared,
# campaign-aware RPC resolver. The pure chain-name/id/explorer normalization
# lives in config; this layer adds repo scanning, the artifact contract, and
# the precedence that blends explicit args, fork context, the registry, and
# run-level defaults — without ever collapsing a multi-chain scope into one
# global default chain.

_CHAIN_REGISTRY_DIR = "/workspace/campaign/chain-registry"
_CHAIN_REGISTRY_PATH = f"{_CHAIN_REGISTRY_DIR}/registry.json"

# A path segment that is a bare chain id, e.g. Foundry broadcast/<script>/<id>/.
_CHAIN_NUMERIC_SEGMENT_RE = re.compile(r"\A[1-9][0-9]{0,18}\Z")
_DEPLOY_ADDRESS_RE = re.compile(r"0x[a-fA-F0-9]{40}")
_CHAIN_URL_RE = re.compile(r"https?://[a-z0-9.\-/]+", re.IGNORECASE)

# Bounded repo scan: deployment files to read and docs/config to text-scan.
_CHAIN_SCAN_MAX_FILES = 40
_CHAIN_DOC_FILES = (
    "README.md",
    "README",
    "readme.md",
    "package.json",
    "hardhat.config.js",
    "hardhat.config.ts",
    "docs/README.md",
    "docs/deployments.md",
)


def _coerce_nonempty(value) -> str | None:
    """Return a stripped non-empty string for ``value``, else None."""
    if value is None:
        return None
    text = value if isinstance(value, str) else str(value)
    stripped = text.strip()
    return stripped or None


def _canonical_chain(
    network=None, chain_id=None, *, strict: bool = False
) -> tuple[str | None, int | None]:
    """Normalize a chain hint to ``(alchemy_network|None, chain_id|None)``.

    ``strict=True`` is for inference from arbitrary repo tokens — it refuses to
    bind a chain for unrecognized names; the permissive default suits explicit,
    agent-supplied hints.
    """
    hint = normalize_chain_hint(network, chain_id=chain_id, strict=strict)
    if hint:
        return hint
    return None, None


def _has_chain_signal(network=None, chain_id=None, *, strict: bool = False) -> bool:
    """True when a hint carries any resolvable chain signal."""
    net, cid = _canonical_chain(network, chain_id, strict=strict)
    return bool(net) or cid is not None


def _chain_hint_from_path(path: str) -> dict | None:
    """Infer a chain hint from a deployment/broadcast path, or None.

    Recognizes Foundry ``broadcast/<script>/<chainid>/`` layouts and
    Hardhat-style ``deployments/<network>/`` or ``deployments/<network>.json``
    layouts. Returns a hint dict (network/chain_id/confidence/evidence) when a
    chain can be resolved, else None.
    """
    text = (path or "").strip()
    if not text:
        return None
    parts = [segment for segment in text.replace("\\", "/").split("/") if segment]
    lowered = [segment.lower() for segment in parts]

    # Foundry broadcast: a numeric chain-id segment after a `broadcast` dir.
    if "broadcast" in lowered:
        start = lowered.index("broadcast")
        for segment in parts[start + 1:]:
            if _CHAIN_NUMERIC_SEGMENT_RE.match(segment):
                net, cid = _canonical_chain(None, segment, strict=True)
                if cid is not None:
                    return {
                        "network": net,
                        "chain_id": cid,
                        "confidence": 0.9,
                        "evidence": [f"{text} (broadcast chainid path)"],
                    }

    # Hardhat / generic deployments: deployments/<network>[/...|.json].
    for marker in ("deployments", "deployment", "deploys"):
        if marker in lowered:
            start = lowered.index(marker)
            if start + 1 < len(parts):
                token = parts[start + 1]
                stem = token[:-5] if token.lower().endswith(".json") else token
                net, cid = _canonical_chain(stem, None, strict=True)
                if net or cid is not None:
                    return {
                        "network": net,
                        "chain_id": cid,
                        "confidence": 0.85,
                        "evidence": [f"{text} ({marker}/{stem} path)"],
                    }
    return None


def _dedupe_deployments(deployments: list[dict]) -> list[dict]:
    """Drop duplicate ``(name, address)`` deployment records, keep order."""
    seen: set[tuple] = set()
    out: list[dict] = []
    for dep in deployments or []:
        key = ((dep.get("name") or None), (dep.get("address") or "").lower())
        if key in seen:
            continue
        seen.add(key)
        out.append(dep)
    return out


def _deployments_from_obj(value, source: str, depth: int = 0) -> list[dict]:
    """Best-effort ``{name,address,source,confidence}`` list from JSON.

    Handles Hardhat single-deployment files (``{"address": "0x..."}``) and
    address maps (``{"Vault": "0x...", "Token": "0x..."}``), recursing one or
    two levels for chain-grouped maps.
    """
    out: list[dict] = []
    if isinstance(value, str):
        text = value.strip()
        if _DEPLOY_ADDRESS_RE.fullmatch(text):
            out.append(
                {"name": None, "address": text, "source": source, "confidence": 0.8}
            )
        return out
    if isinstance(value, dict):
        addr = value.get("address")
        if isinstance(addr, str) and _DEPLOY_ADDRESS_RE.fullmatch(addr.strip()):
            name = value.get("contractName") or value.get("name")
            out.append(
                {
                    "name": name,
                    "address": addr.strip(),
                    "source": source,
                    "confidence": 0.85,
                }
            )
        for key, sub in value.items():
            if key in ("address", "contractName", "name"):
                continue
            if isinstance(sub, str) and _DEPLOY_ADDRESS_RE.fullmatch(sub.strip()):
                out.append(
                    {
                        "name": key,
                        "address": sub.strip(),
                        "source": source,
                        "confidence": 0.8,
                    }
                )
            elif isinstance(sub, dict) and depth < 2:
                for item in _deployments_from_obj(sub, source=source, depth=depth + 1):
                    if item.get("name") is None:
                        item["name"] = key
                    out.append(item)
    return _dedupe_deployments(out)


def _chain_hints_from_json_obj(obj, source: str) -> list[dict]:
    """Chain hints from a parsed deployment/config JSON object.

    Recognizes (a) top-level keys that name a chain (``{"base": {...},
    "arbitrum": {...}}`` or ``{"8453": {...}}``) and (b) an explicit
    ``chainId``/``network`` field on the object. An unresolved key whose value
    is an address map is recorded as an ambiguous hint rather than dropped.
    """
    hints: list[dict] = []
    if not isinstance(obj, dict):
        return hints

    for key, value in obj.items():
        if key in ("address", "chainId", "chain_id", "network", "chain", "chainName"):
            continue
        net, cid = _canonical_chain(key, None, strict=True)
        if net or cid is not None:
            hints.append(
                {
                    "network": net,
                    "chain_id": cid,
                    "confidence": 0.8,
                    "evidence": [f"{source}: key '{key}'"],
                    "deployments": _deployments_from_obj(value, source=source),
                }
            )
        elif isinstance(value, dict) and _deployments_from_obj(value, source=source):
            # A nested map of addresses under a key we could not resolve to a
            # known chain — keep it ambiguous so a plausible branch is recorded,
            # not silently dropped (a bare contract-name->address entry is not a
            # chain grouping and is intentionally ignored here).
            hints.append(
                {
                    "network": None,
                    "chain_id": None,
                    "token": str(key),
                    "confidence": 0.3,
                    "evidence": [f"{source}: unresolved group key '{key}'"],
                    "deployments": _deployments_from_obj(value, source=source),
                }
            )

    field_net = obj.get("network") or obj.get("chain") or obj.get("chainName")
    field_cid = obj.get("chainId") or obj.get("chain_id")
    if field_net is not None or field_cid is not None:
        net, cid = _canonical_chain(field_net, field_cid, strict=True)
        if net or cid is not None:
            hints.append(
                {
                    "network": net,
                    "chain_id": cid,
                    "confidence": 0.85,
                    "evidence": [f"{source}: chainId/network field"],
                    "deployments": _deployments_from_obj(obj, source=source),
                }
            )
    return hints


def _chain_hints_from_text(text: str, source: str) -> list[dict]:
    """Chain hints from free text via block-explorer links."""
    hints: list[dict] = []
    if not text:
        return hints
    seen: set[tuple] = set()
    for match in _CHAIN_URL_RE.findall(text):
        explorer = chain_from_explorer_url(match)
        if not explorer:
            continue
        net, cid = explorer
        key = (net, cid)
        if key in seen:
            continue
        seen.add(key)
        hints.append(
            {
                "network": net,
                "chain_id": cid,
                "confidence": 0.7,
                "evidence": [f"{source}: explorer link"],
            }
        )
    return hints


def _build_chain_registry(
    hints: list[dict],
    *,
    chain_registry_id: str,
    scanned: list[str] | None = None,
    notes: list[str] | None = None,
) -> dict:
    """Aggregate raw hints into the durable chain-registry artifact shape.

    Resolved hints merge into one entry per chain (max confidence, unioned
    evidence and deployments). Hints with no resolvable chain become
    ``ambiguous`` entries. Multi-chain deployments are represented as multiple
    chain entries, never collapsed.
    """
    chains_by_key: dict = {}
    order: list = []
    ambiguous: list[dict] = []
    for hint in hints or []:
        net = hint.get("network")
        cid = hint.get("chain_id")
        if not net and cid is None:
            entry = {
                key: hint[key]
                for key in ("token", "confidence", "evidence", "deployments")
                if hint.get(key)
            }
            ambiguous.append(entry)
            continue
        key = cid if cid is not None else net
        entry = chains_by_key.get(key)
        if entry is None:
            entry = {
                "network": net,
                "chain_id": cid,
                "confidence": float(hint.get("confidence", 0.5)),
                "evidence": [],
                "deployments": [],
            }
            chains_by_key[key] = entry
            order.append(key)
        else:
            entry["confidence"] = max(
                entry["confidence"], float(hint.get("confidence", 0.5))
            )
            if net and not entry.get("network"):
                entry["network"] = net
            if cid is not None and entry.get("chain_id") is None:
                entry["chain_id"] = cid
        for evidence in hint.get("evidence", []) or []:
            if evidence not in entry["evidence"]:
                entry["evidence"].append(evidence)
        entry["deployments"].extend(hint.get("deployments", []) or [])

    chains: list[dict] = []
    for key in order:
        entry = chains_by_key[key]
        entry["deployments"] = _dedupe_deployments(entry["deployments"])
        entry["confidence"] = round(float(entry["confidence"]), 3)
        chains.append(entry)
    chains.sort(
        key=lambda chain: (
            -(chain.get("confidence") or 0.0),
            str(chain.get("network") or ""),
            chain.get("chain_id") or 0,
        )
    )

    registry = {
        "chain_registry_id": chain_registry_id,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "chains": chains,
        "ambiguous": ambiguous,
        "notes": list(notes or []),
    }
    if scanned is not None:
        registry["scanned"] = scanned
    return registry


async def _safe_read(container: AuditContainer, path: str, *, max_bytes: int = 200_000) -> str:
    """Read a file, returning "" on any error; truncates very large files."""
    try:
        content = await container.read_file(path)
    except (FileNotFoundError, ValueError, OSError, UnicodeError):
        return ""
    if not isinstance(content, str):
        return ""
    return content[:max_bytes] if len(content) > max_bytes else content


async def _find_deployment_files(container: AuditContainer, root: str) -> list[str]:
    """List deployment/broadcast JSON files under the target tree (bounded)."""
    safe_root = shlex.quote(root)
    exit_code, output = await container.exec(
        f"find {safe_root} -maxdepth 6 -type f "
        r"\( -path '*/deployments/*' -o -path '*/broadcast/*' "
        r"-o -path '*/deploys/*' \) -name '*.json' "
        "! -path '*/node_modules/*' ! -path '*/.git/*' "
        "! -path '*/lib/*' "
        "| sort 2>/dev/null | head -200",
        timeout=30,
    )
    if exit_code != 0:
        return []
    files: list[str] = []
    for line in output.splitlines():
        candidate = line.strip()
        if candidate and candidate.lower().endswith(".json"):
            files.append(candidate)
    return files


async def _collect_chain_hints(
    container: AuditContainer,
    root: str,
    *,
    foundry_raw: str = "",
) -> tuple[list[dict], list[str], list[str]]:
    """Scan the target repo for chain/deployment hints.

    Returns ``(hints, notes, scanned_paths)``. Best-effort and conservative: it
    reads deployment/broadcast JSON (path + content), text-scans a small set of
    docs/config files for explorer links, and scans the already-read
    ``foundry.toml``. It never raises and never fabricates a binding.
    """
    hints: list[dict] = []
    notes: list[str] = []
    scanned: list[str] = []

    deployment_files = await _find_deployment_files(container, root)
    for path in deployment_files[:_CHAIN_SCAN_MAX_FILES]:
        path_hint = _chain_hint_from_path(path)
        content = await _safe_read(container, path)
        obj = None
        if content:
            scanned.append(path)
            try:
                obj = json.loads(content)
            except (ValueError, TypeError):
                obj = None
        if path_hint is not None:
            # Attach addresses discovered in this file to its path-derived chain.
            if obj is not None:
                stem = posixpath.splitext(posixpath.basename(path))[0]
                name_default = (
                    stem if stem and not _has_chain_signal(stem, strict=True) else None
                )
                path_deployments = _deployments_from_obj(obj, source=path)
                if name_default:
                    for dep in path_deployments:
                        if dep.get("name") is None:
                            dep["name"] = name_default
                path_hint.setdefault("deployments", [])
                path_hint["deployments"].extend(path_deployments)
            hints.append(path_hint)
        if obj is not None:
            hints.extend(_chain_hints_from_json_obj(obj, source=path))
    if len(deployment_files) > _CHAIN_SCAN_MAX_FILES:
        notes.append(
            f"chain scan limited to first {_CHAIN_SCAN_MAX_FILES} of "
            f"{len(deployment_files)} deployment files"
        )

    for rel in _CHAIN_DOC_FILES:
        path = posixpath.join(root, rel)
        content = await _safe_read(container, path)
        if not content:
            continue
        scanned.append(path)
        hints.extend(_chain_hints_from_text(content, source=rel))
        if rel.lower().endswith(".json"):
            try:
                obj = json.loads(content)
            except (ValueError, TypeError):
                obj = None
            if obj is not None:
                hints.extend(_chain_hints_from_json_obj(obj, source=rel))

    if foundry_raw:
        hints.extend(_chain_hints_from_text(foundry_raw, source="foundry.toml"))

    return hints, notes, sorted(dict.fromkeys(scanned))


def _next_chain_registry_id(previous: dict | None) -> str:
    """Allocate the next ``chainreg-NNN`` id from the prior registry (if any)."""
    prefix = _CAMPAIGN_ID_PREFIXES["chain_registry"]
    last = 0
    if isinstance(previous, dict):
        match = re.search(r"-(\d+)\Z", str(previous.get("chain_registry_id") or ""))
        if match:
            last = int(match.group(1))
    return f"{prefix}-{last + 1:03d}"


async def _write_chain_registry(container: AuditContainer, registry: dict) -> str:
    """Persist the chain registry artifact and return its path."""
    await container.write_file(
        _CHAIN_REGISTRY_PATH,
        json.dumps(registry, indent=2, sort_keys=True) + "\n",
    )
    return _CHAIN_REGISTRY_PATH


async def _latest_chain_registry(container: AuditContainer) -> dict | None:
    """Return the latest chain-registry artifact dict, or None.

    Best-effort: returns None when the artifact is absent or unreadable so
    callers degrade cleanly when no chain context has been inferred yet.
    """
    if container is None:
        return None
    raw = await _safe_read(container, _CHAIN_REGISTRY_PATH)
    if not raw:
        return None
    try:
        data = json.loads(raw)
    except (ValueError, TypeError):
        return None
    return data if isinstance(data, dict) else None


def _chain_registry_brief(registry: dict) -> dict:
    """Compact, model-visible summary of the chain registry (no bulk detail)."""
    chains = registry.get("chains", []) or []
    return {
        "path": _CHAIN_REGISTRY_PATH,
        "chain_registry_id": registry.get("chain_registry_id"),
        "chains": [
            {
                "network": chain.get("network"),
                "chain_id": chain.get("chain_id"),
                "confidence": chain.get("confidence"),
                "deployments": len(chain.get("deployments", []) or []),
            }
            for chain in chains[:8]
        ],
        "chain_count": len(chains),
        "ambiguous": len(registry.get("ambiguous", []) or []),
        "multi_chain": len(chains) > 1,
    }


def _chain_hints_for_address_or_contract(
    registry: dict | None,
    *,
    address: str | None = None,
    contract: str | None = None,
    name: str | None = None,
) -> list[dict]:
    """Return registry chains that host a target address or contract name.

    Returns one candidate per matching chain, so a contract deployed on several
    chains yields several candidates — the caller decides how to disambiguate
    rather than this helper choosing arbitrarily.
    """
    if not isinstance(registry, dict):
        return []
    wanted_addr = (address or "").strip().lower() or None
    wanted_names = {
        str(item).strip().lower()
        for item in (contract, name)
        if item and str(item).strip()
    }
    candidates: list[dict] = []
    for chain in registry.get("chains", []) or []:
        if not isinstance(chain, dict):
            continue
        matched = None
        for dep in chain.get("deployments", []) or []:
            dep_addr = (dep.get("address") or "").strip().lower()
            dep_name = (dep.get("name") or "").strip().lower()
            if wanted_addr and dep_addr == wanted_addr:
                matched = dep
                break
            if wanted_names and dep_name in wanted_names:
                matched = dep
                break
        if matched is not None:
            candidates.append(
                {
                    "network": chain.get("network"),
                    "chain_id": chain.get("chain_id"),
                    "confidence": chain.get("confidence"),
                    "deployment": matched,
                }
            )
    return candidates


def _distinct_chain_keys(candidates: list[dict]) -> list[tuple[str | None, int | None]]:
    """Collapse candidates to the distinct ``(network, chain_id)`` chains."""
    keys: set = set()
    distinct: list[tuple[str | None, int | None]] = []
    for candidate in candidates or []:
        net, cid = _canonical_chain(
            candidate.get("network"), candidate.get("chain_id")
        )
        key = cid if cid is not None else net
        if key is None or key in keys:
            continue
        keys.add(key)
        distinct.append((net, cid))
    return distinct


async def _latest_fork_context(container: AuditContainer) -> dict | None:
    """Return the most recent recorded fork-context artifact dict, or None."""
    if container is None:
        return None
    try:
        state = await _load_campaign_state(container)
    except Exception:
        return None
    count = int((state.get("counters") or {}).get("fork_context", 0) or 0)
    prefix = _CAMPAIGN_ID_PREFIXES.get("fork_context")
    if not prefix or count <= 0:
        return None
    for index in range(count, max(0, count - 10), -1):
        path = f"/workspace/campaign/fork-contexts/{prefix}-{index:03d}.json"
        content = await _safe_read(container, path)
        if not content:
            continue
        try:
            data = json.loads(content)
        except (ValueError, TypeError):
            continue
        if isinstance(data, dict):
            return data
    return None


def _tool_environ(environ: dict[str, str] | None):
    return environ if environ is not None else os.environ


def _tool_config(config: dict | None) -> dict:
    if config is not None:
        return config
    try:
        return load_local_config()
    except Exception:
        return {}


def _rpc_endpoint_summary(endpoint: ResolvedRpcEndpoint | None) -> dict:
    """Model-visible RPC provenance with no raw URL.

    Returns provider/network/chain_id/source/override/assumed_default_mainnet
    plus ``configured`` (whether a usable endpoint URL was resolved).
    """
    if endpoint is None:
        return {
            "provider": "none",
            "network": None,
            "chain_id": None,
            "source": "none",
            "override": False,
            "assumed_default_mainnet": False,
            "configured": False,
        }
    return {
        "provider": endpoint.provider,
        "network": endpoint.network,
        "chain_id": endpoint.chain_id,
        "source": endpoint.source,
        "override": endpoint.is_override,
        "assumed_default_mainnet": endpoint.assumed_default_mainnet,
        "configured": endpoint.url is not None,
    }


async def _resolve_tool_rpc_endpoint(
    container: AuditContainer,
    args: dict,
    *,
    fork_context: dict | None = None,
    target_address: str | None = None,
    target_name: str | None = None,
    target_addresses: list | None = None,
    target_names: list | None = None,
    allow_default_mainnet: bool = False,
    registry: dict | None = None,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> ResolvedRpcEndpoint:
    """Resolve an RPC endpoint for a tool call, campaign-aware and chain-safe.

    Precedence:
      1. ``args['rpc_url']`` explicit override
      2. ``args['network']`` / ``args['chain_id']``
      3. explicit ``fork_context`` network/chain_id
      4. unambiguous target/deployment binding from the latest chain registry
      5. latest recorded fork context for the branch/target
      6. ``REENTBOT_DEFAULT_NETWORK`` / ``REENTBOT_DEFAULT_CHAIN_ID`` (or config)
      7. ``ALCHEMY_API_KEY`` + the resolved chain (and per-chain config rpc_urls)
      8. explicit ``ETH_RPC_URL`` fallback (a chain-agnostic global, deliberately
         demoted below a correctly resolved chain)
      9. nothing, unless ``allow_default_mainnet`` opts into assumed mainnet

    A target that the registry maps to multiple chains is never resolved
    arbitrarily — it returns ``provider="none"`` with source
    ``"ambiguous_chain_registry"``; use
    :func:`_resolve_tool_rpc_endpoints_for_chains` when candidates are wanted.

    ``target_address``/``target_name`` bind a single primary target; pass
    ``target_addresses``/``target_names`` (lists) to bind across several targets
    of one artifact (e.g. every probe in a snapshot). Precise address matches
    take priority over name matches, so an exact address is never made ambiguous
    by an unrelated same-named deployment on another chain; targets that resolve
    to more than one distinct chain still yield ``"ambiguous_chain_registry"``.

    ``registry`` overrides the chain registry used for that target binding;
    when None the latest recorded registry is loaded (the default).
    """
    args = args or {}
    env = _tool_environ(environ)
    cfg = _tool_config(config)

    # 1: explicit per-call rpc_url override delegates to the canonical resolver.
    explicit_url = _coerce_nonempty(args.get("rpc_url"))
    if explicit_url:
        return resolve_rpc_endpoint(
            rpc_url=explicit_url,
            network=args.get("network"),
            chain_id=args.get("chain_id"),
            environ=env,
            config=cfg,
        )

    network: str | None = None
    chain_id: int | None = None
    source: str | None = None

    # 2: explicit network / chain_id args.
    if _has_chain_signal(args.get("network"), args.get("chain_id")):
        network, chain_id = _canonical_chain(args.get("network"), args.get("chain_id"))
        source = "args"

    # 3: an explicit fork context handed to the caller.
    if network is None and chain_id is None and isinstance(fork_context, dict):
        if _has_chain_signal(fork_context.get("network"), fork_context.get("chain_id")):
            network, chain_id = _canonical_chain(
                fork_context.get("network"), fork_context.get("chain_id")
            )
            source = "fork_context"

    # 4: unambiguous target/deployment binding from the chain registry.
    if network is None and chain_id is None:
        addr_refs = [
            value
            for value in [target_address, *(target_addresses or [])]
            if _coerce_nonempty(value)
        ]
        name_refs = [
            value
            for value in [target_name, *(target_names or [])]
            if _coerce_nonempty(value)
        ]
        if addr_refs or name_refs:
            if registry is None:
                registry = await _latest_chain_registry(container)
            # Precise address matches bind first; names are consulted only when
            # no address matches, so an exact address is never made ambiguous by
            # an unrelated same-named deployment on another chain.
            candidates = []
            for addr in addr_refs:
                candidates += _chain_hints_for_address_or_contract(
                    registry, address=addr
                )
            if not candidates:
                for name in name_refs:
                    candidates += _chain_hints_for_address_or_contract(
                        registry, name=name, contract=name
                    )
            distinct = _distinct_chain_keys(candidates)
            if len(distinct) == 1:
                network, chain_id = distinct[0]
                source = "chain_registry"
            elif len(distinct) > 1:
                # Multiple chains host these targets — never choose arbitrarily.
                return ResolvedRpcEndpoint(
                    url=None,
                    provider="none",
                    network=None,
                    chain_id=None,
                    source="ambiguous_chain_registry",
                )

    # 5: latest recorded fork context for the branch/target.
    if network is None and chain_id is None:
        latest = await _latest_fork_context(container)
        if latest and _has_chain_signal(latest.get("network"), latest.get("chain_id")):
            network, chain_id = _canonical_chain(
                latest.get("network"), latest.get("chain_id")
            )
            source = "latest_fork_context"

    # 6: run-level default chain hint (env first, then config) — a weak fallback.
    if network is None and chain_id is None:
        default_net, default_cid, default_src = resolve_default_chain_hint(
            environ=env, config=cfg
        )
        if default_net or default_cid is not None:
            network, chain_id, source = default_net, default_cid, default_src

    # 7: derive the endpoint for the resolved chain (per-chain config + Alchemy),
    #    with ETH_RPC_URL stripped so a chain-agnostic global cannot jump ahead of
    #    a correctly resolved chain, and without an assumed mainnet.
    tool_env = {key: value for key, value in env.items() if key != "ETH_RPC_URL"}
    endpoint = resolve_rpc_endpoint(
        network=network,
        chain_id=chain_id,
        allow_default_mainnet=False,
        environ=tool_env,
        config=cfg,
    )
    if endpoint.url is not None:
        if source and source != endpoint.source:
            endpoint = dataclasses.replace(endpoint, source=source)
        return endpoint

    # 8: explicit ETH_RPC_URL fallback (demoted below a resolved-chain endpoint).
    eth_rpc = _coerce_nonempty(env.get("ETH_RPC_URL"))
    if eth_rpc:
        fallback = resolve_rpc_endpoint(
            rpc_url=eth_rpc, network=network, chain_id=chain_id, environ={}, config=cfg
        )
        return dataclasses.replace(fallback, source="ETH_RPC_URL")

    # 9: nothing resolvable — only assume mainnet when the caller opts in.
    if allow_default_mainnet:
        return resolve_rpc_endpoint(
            allow_default_mainnet=True, environ=tool_env, config=cfg
        )
    return ResolvedRpcEndpoint(
        url=None,
        provider="none",
        network=network,
        chain_id=chain_id,
        source="none",
    )


async def _resolve_tool_rpc_endpoints_for_chains(
    container: AuditContainer,
    chain_refs: list,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> dict:
    """Resolve one endpoint per explicitly-named chain (for multi-chain work).

    ``chain_refs`` accepts dicts (``{"network": ..., "chain_id": ...}``) or bare
    network/chain-id values. Keys in the returned mapping are the chain id as a
    string when known, else the canonical network. Unresolvable refs are
    skipped. Because the caller names the chains, this never reports ambiguity.
    """
    env = _tool_environ(environ)
    cfg = _tool_config(config)
    tool_env = {key: value for key, value in env.items() if key != "ETH_RPC_URL"}
    resolved: dict = {}
    for ref in chain_refs or []:
        if isinstance(ref, dict):
            net, cid = _canonical_chain(ref.get("network"), ref.get("chain_id"))
        else:
            net, cid = _canonical_chain(ref, None)
        if net is None and cid is None:
            continue
        key = str(cid) if cid is not None else net
        resolved[key] = resolve_rpc_endpoint(
            network=net,
            chain_id=cid,
            allow_default_mainnet=False,
            environ=tool_env,
            config=cfg,
        )
    return resolved


def _unresolved_rpc_error(endpoint: ResolvedRpcEndpoint) -> str:
    """Classify a non-resolving endpoint as chain_ambiguous or rpc_not_configured."""
    if endpoint.source == "ambiguous_chain_registry":
        return "chain_ambiguous"
    return "rpc_not_configured"


async def _resolve_fork_context_arg(
    container: AuditContainer, value
) -> dict | None:
    """Load a ``fork_context`` argument into a chain-bearing dict, or None.

    Accepts an already-parsed dict, a recorded fork-context id (``fc-001``), or a
    fork-context path under the campaign tree. Returns None (not an error) when
    the value is empty or unreadable so the resolver simply falls through to its
    other precedence sources.
    """
    if isinstance(value, dict):
        return value
    ident = _coerce_nonempty(value)
    if not ident:
        return None
    try:
        _path, data = await _load_fork_context(container, ident)
    except (FileNotFoundError, ValueError):
        return None
    return data if isinstance(data, dict) else None


async def _tool_chain_candidates(
    container: AuditContainer,
    *,
    addresses: list | None = None,
    names: list | None = None,
) -> list[dict]:
    """Distinct candidate chains hosting any of the given addresses/names.

    Used to populate the ``candidates`` list of a ``chain_ambiguous`` error so
    the agent can disambiguate by passing an explicit chain. Address matches are
    preferred over name matches, mirroring :func:`_resolve_tool_rpc_endpoint`.
    """
    registry = await _latest_chain_registry(container)
    candidates: list[dict] = []
    for addr in addresses or []:
        if _coerce_nonempty(addr):
            candidates += _chain_hints_for_address_or_contract(registry, address=addr)
    if not candidates:
        for name in names or []:
            if _coerce_nonempty(name):
                candidates += _chain_hints_for_address_or_contract(
                    registry, name=name, contract=name
                )
    return [
        {"network": net, "chain_id": cid}
        for net, cid in _distinct_chain_keys(candidates)
    ]


async def _chain_unresolved_response(
    container: AuditContainer,
    *,
    tool: str,
    endpoint: ResolvedRpcEndpoint,
    addresses: list | None = None,
    names: list | None = None,
    message: str | None = None,
    extra: dict | None = None,
) -> str:
    """Build a structured error for a tool that could not resolve a chain.

    Returns ``chain_ambiguous`` (with candidate chains) when targets span
    several chains, else ``rpc_not_configured``. The compact ``rpc_endpoint``
    provenance is included; no raw URL is ever returned.
    """
    error = _unresolved_rpc_error(endpoint)
    payload: dict = {
        "error": error,
        "tool": tool,
        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
    }
    if message:
        payload["message"] = message
    if extra:
        payload.update(extra)
    if error == "chain_ambiguous":
        payload["candidates"] = await _tool_chain_candidates(
            container, addresses=addresses, names=names
        )
    return json.dumps(payload, indent=2, sort_keys=True)


# ── Host-side live-tool chain resolution ─────────────────────────────────
#
# The host-side Alchemy/Etherscan tools (host_tools.py) build their own per-chain
# request from a bare key, so they need a resolved *chain* (network + chain id),
# not an RPC URL. These helpers resolve that chain from the same campaign signals
# as the run-experiment / live-probe resolvers above — explicit args, an explicit
# or recorded fork context, an unambiguous chain-registry target binding, then the
# run default — and inject it into the tool's args at dispatch time. When no chain
# can be inferred the call short-circuits with a structured chain_not_inferred /
# chain_ambiguous error before any request is made, so a host tool never silently
# falls back to Ethereum mainnet.


@dataclasses.dataclass(frozen=True)
class _HostToolChain:
    """Outcome of resolving a host-side live tool's target chain.

    ``status`` is ``"resolved"`` (network/chain_id are usable), ``"ambiguous"``
    (the target maps to several chains, listed in ``candidates``), or
    ``"not_inferred"`` (no chain signal anywhere). ``source`` records which
    precedence step bound the chain, for provenance/telemetry.
    """

    network: str | None = None
    chain_id: int | None = None
    source: str = "none"
    status: str = "not_inferred"
    candidates: tuple = ()


async def _resolve_host_tool_chain(
    container: AuditContainer,
    *,
    fork_context: dict | None = None,
    target_addresses: list | None = None,
    target_names: list | None = None,
    run_default_network: str | None = None,
    registry: dict | None = None,
) -> _HostToolChain:
    """Resolve a host-side live tool's *inferred* target chain (no RPC URL).

    Explicit per-call ``network``/``chain_id`` is handled by the caller
    (:func:`_prepare_host_tool_chain`); this resolves the inferred chain by the
    same precedence the run-experiment / live-probe resolvers use:

      1. an explicit ``fork_context`` argument's network/chain_id
      2. an unambiguous target-address/name binding in the latest chain registry
      3. the latest recorded fork context
      4. the run-level default network (CLI/config), if any

    A target the registry maps to several chains yields ``status="ambiguous"``
    with the candidate chains, never an arbitrary pick. When nothing resolves the
    status is ``"not_inferred"`` so the tool reports ``chain_not_inferred`` rather
    than silently using Ethereum mainnet.
    """
    # 1: an explicit fork_context argument handed to the tool.
    if isinstance(fork_context, dict) and _has_chain_signal(
        fork_context.get("network"), fork_context.get("chain_id")
    ):
        net, cid = _canonical_chain(
            fork_context.get("network"), fork_context.get("chain_id")
        )
        return _HostToolChain(net, cid, "fork_context", "resolved")

    # 2: unambiguous target/deployment binding from the chain registry. Precise
    #    address matches bind before names, mirroring _resolve_tool_rpc_endpoint.
    addr_refs = [value for value in (target_addresses or []) if _coerce_nonempty(value)]
    name_refs = [value for value in (target_names or []) if _coerce_nonempty(value)]
    if addr_refs or name_refs:
        if registry is None:
            registry = await _latest_chain_registry(container)
        candidates: list[dict] = []
        for addr in addr_refs:
            candidates += _chain_hints_for_address_or_contract(registry, address=addr)
        if not candidates:
            for name in name_refs:
                candidates += _chain_hints_for_address_or_contract(
                    registry, name=name, contract=name
                )
        distinct = _distinct_chain_keys(candidates)
        if len(distinct) == 1:
            net, cid = distinct[0]
            return _HostToolChain(net, cid, "chain_registry", "resolved")
        if len(distinct) > 1:
            return _HostToolChain(
                None,
                None,
                "ambiguous_chain_registry",
                "ambiguous",
                tuple({"network": net, "chain_id": cid} for net, cid in distinct),
            )

    # 3: the latest recorded fork context for the branch/target.
    latest = await _latest_fork_context(container)
    if latest and _has_chain_signal(latest.get("network"), latest.get("chain_id")):
        net, cid = _canonical_chain(latest.get("network"), latest.get("chain_id"))
        return _HostToolChain(net, cid, "latest_fork_context", "resolved")

    # 4: the run-level default chain (a deliberately weak fallback).
    if _has_chain_signal(run_default_network):
        net, cid = _canonical_chain(run_default_network)
        return _HostToolChain(net, cid, "run_default", "resolved")

    return _HostToolChain(None, None, "none", "not_inferred")


def _host_tool_chain_targets(tool: str, args: dict) -> list[str]:
    """Target addresses a host tool's args bind to, for chain-registry lookup.

    Only on-chain *target* contracts (``to``/``address``) are collected — caller
    (``from``) addresses are excluded so an EOA sender never forces a spurious
    multi-chain ambiguity, and tx-hash-only tools (trace_onchain_tx, state_diff)
    bind no address.
    """
    out: list[str] = []

    def _add(value) -> None:
        text = _coerce_nonempty(value)
        if text and text not in out:
            out.append(text)

    if tool in ("get_contract_source", "get_token_info", "observed_tx_miner"):
        _add(args.get("address"))
    elif tool == "enumerate_callers":
        _add(args.get("address"))
        _add(args.get("to_address"))
    elif tool in ("simulate_call", "simulate_asset_changes", "simulate_execution"):
        _add(args.get("to"))
    elif tool == "get_asset_transfers":
        _add(args.get("address"))
        _add(args.get("to_address"))
        _add(args.get("from_address"))
    elif tool == "get_token_prices":
        for value in args.get("addresses") or []:
            _add(value)
        for token in args.get("tokens") or []:
            if isinstance(token, dict):
                _add(token.get("address"))
    elif tool == "simulate_sequence":
        for entry in args.get("transactions") or []:
            if isinstance(entry, dict):
                _add(entry.get("to"))
    return out


def _host_tool_requires_default_chain(tool: str, args: dict) -> bool:
    """Whether a host tool needs a resolved default chain to run.

    Almost always True. The exception is ``get_token_prices`` when every
    requested token already carries its own network and no bare ``addresses[]``
    are given: that call is fully chain-specified per entry, so it must not be
    blocked for lack of a single default chain.
    """
    if tool != "get_token_prices":
        return True
    addresses = args.get("addresses")
    if isinstance(addresses, list) and any(_coerce_nonempty(a) for a in addresses):
        return True
    tokens = args.get("tokens")
    if not isinstance(tokens, list) or not tokens:
        return True
    for token in tokens:
        if not isinstance(token, dict) or not _coerce_nonempty(token.get("address")):
            return True
        if not _has_chain_signal(token.get("network"), token.get("chain_id")):
            return True
    return False


def _host_tool_credential_configured(tool: str) -> bool:
    """True when the credential a host tool needs is configured for this run.

    ``get_contract_source`` needs the Etherscan key; the Alchemy tools need the
    Alchemy key. When the credential is missing the tool reports its own
    ``*_not_configured`` error (a more fundamental blocker), so we skip chain
    inference and never surface ``chain_not_inferred`` in its place.

    ``alchemy_key_configured``/``etherscan_key_configured`` are bound by the
    host_tools import at the foot of this module.
    """
    if tool == "get_contract_source":
        return etherscan_key_configured()
    return alchemy_key_configured()


def _host_chain_unresolved_response(tool: str, resolution: _HostToolChain) -> str:
    """Structured ``chain_not_inferred`` / ``chain_ambiguous`` error for a host tool."""
    if resolution.status == "ambiguous":
        payload: dict = {
            "error": "chain_ambiguous",
            "tool": tool,
            "status": "unavailable",
            "message": (
                "Target is associated with multiple chains; pass network/chain_id "
                "or bind the branch to a fork_context."
            ),
            "candidates": list(resolution.candidates),
        }
    else:
        payload = {
            "error": "chain_not_inferred",
            "tool": tool,
            "status": "unavailable",
            "message": (
                "No target chain was inferred. Pass network/chain_id, record a "
                "fork_context, or rely on a chain-registry target binding."
            ),
        }
    return json.dumps(payload, indent=2, sort_keys=True)


async def _prepare_host_tool_chain(
    container: AuditContainer, tool: str, args: dict
) -> tuple[dict, str | None]:
    """Resolve and inject the target chain for a host-side live tool.

    Returns ``(prepared_args, error)``. On success ``error`` is None and
    ``prepared_args`` carries a resolved ``network`` (and ``chain_id``) so the
    tool builds the right Alchemy/Etherscan request. When the tool needs a chain
    but none can be inferred, ``error`` is a ready-to-return ``chain_not_inferred``
    / ``chain_ambiguous`` JSON string and the host tool is never called — so no
    request is made and Ethereum mainnet is never silently queried.

    ``alchemy_runtime_default_network`` is bound by the host_tools import at the
    foot of this module.
    """
    prepared = dict(args or {})

    # If the tool's own credential is missing, let it report *_not_configured (a
    # more fundamental blocker) rather than chain_not_inferred.
    if not _host_tool_credential_configured(tool):
        return prepared, None

    # An explicit per-call chain always wins. Normalize a recognized network/
    # chain_id; pass an unrecognized one through unchanged so the tool reports
    # invalid_network itself — never silently override the agent's explicit choice.
    if (
        _coerce_nonempty(prepared.get("network")) is not None
        or _coerce_nonempty(prepared.get("chain_id")) is not None
    ):
        net, cid = _canonical_chain(prepared.get("network"), prepared.get("chain_id"))
        if net:
            prepared["network"] = net
        if cid is not None:
            prepared.setdefault("chain_id", cid)
        return prepared, None

    # A call already chain-specified per entry (get_token_prices tokens[]) needs
    # no single default chain; let it run.
    if not _host_tool_requires_default_chain(tool, prepared):
        return prepared, None

    fork_context = await _resolve_fork_context_arg(
        container, prepared.get("fork_context")
    )
    resolution = await _resolve_host_tool_chain(
        container,
        fork_context=fork_context,
        target_addresses=_host_tool_chain_targets(tool, prepared),
        run_default_network=alchemy_runtime_default_network(),
    )
    if resolution.status == "resolved":
        if resolution.network:
            prepared["network"] = resolution.network
        if resolution.chain_id is not None:
            prepared.setdefault("chain_id", resolution.chain_id)
        return prepared, None
    return prepared, _host_chain_unresolved_response(tool, resolution)


async def _dispatch_host_live_tool(
    name: str, container: AuditContainer, arguments: dict
) -> str:
    """Resolve the target chain, then dispatch to the named host-side live tool.

    A resolved chain is injected into the tool's args; an unresolved or ambiguous
    chain short-circuits with a structured error before any host request is made.
    """
    handler = _HOST_LIVE_TOOL_HANDLERS.get(name)
    if handler is None:
        return f"Unknown tool: {name}"
    prepared, error = await _prepare_host_tool_chain(container, name, arguments or {})
    if error is not None:
        return error
    return await handler(container, prepared)


# ── Multi-chain live-probe grouping ──────────────────────────────────────
#
# The large live-probe tools (map_live_reachability, inventory_live_targets)
# work over many targets that can live on different chains. Rather than
# collapsing them onto one global endpoint, they group targets by their
# resolved chain and derive a per-chain Alchemy endpoint, returning ambiguity
# instead of guessing. The single-target resolver above stays the source of
# truth for precedence; these helpers reuse its registry/canonicalization
# pieces and apply the same precedence while *grouping* instead of collapsing.


def _chain_group_key(network: str | None, chain_id: int | None) -> str | None:
    """Stable per-chain grouping key: the chain id when known, else network."""
    if chain_id is not None:
        return str(chain_id)
    if network:
        return network
    return None


def _chain_matches(
    candidates: list[tuple[str | None, int | None]],
    network: str | None,
    chain_id: int | None,
) -> bool:
    """True when ``(network, chain_id)`` names one of the candidate chains."""
    want = _chain_group_key(*_canonical_chain(network, chain_id))
    return any(
        _chain_group_key(cand_net, cand_cid) == want
        for cand_net, cand_cid in candidates
    )


def _candidate_chain_dicts(
    candidates: list[tuple[str | None, int | None]],
) -> list[dict]:
    return [{"network": net, "chain_id": cid} for net, cid in candidates]


async def _resolve_chain_registry_arg(
    container: AuditContainer, value: object
) -> dict | None:
    """Load an explicit ``chain_registry`` id/path, else the latest registry.

    An absolute campaign path is loaded directly; anything else (including a
    ``chainreg-NNN`` id, which maps to the single canonical registry artifact)
    falls back to the latest recorded registry. Best-effort: returns None when
    no chain registry has been inferred yet.
    """
    ident = _coerce_nonempty(value)
    if ident and ident.startswith("/workspace/campaign/"):
        payload = await _load_campaign_json_if_exists(container, ident)
        if isinstance(payload, dict):
            return payload
    return await _latest_chain_registry(container)


# ── Experiment fork RPC endpoint resolution ──────────────────────────────
#
# run_experiment runs Foundry/fork commands that need chain-specific RPC
# endpoints. Rather than depend on one global ETH_RPC_URL baked into the
# container at startup, it derives the endpoint(s) the run needs — from explicit
# args, the experiment's sequence/workbench chain metadata, a deployment chain
# binding, the latest fork context, or run defaults — and injects them as
# per-exec env vars. Single-chain experiments still get ETH_RPC_URL (for the
# generated `vm.envString("ETH_RPC_URL")` fork tests); multi-chain experiments
# additionally get RPC_URL_<chain_id> / RPC_URL_<NETWORK> per declared chain.
# The single-target resolver above stays the source of truth for precedence;
# this layer reuses it and only adds the multi-chain grouping a fork experiment
# may declare.

# Command-level markers showing a run intends to use an RPC endpoint even with
# no chain metadata bound (e.g. an ad hoc `forge test --fork-url $ETH_RPC_URL`).
_RPC_COMMAND_MARKERS: tuple[str, ...] = (
    "eth_rpc_url",
    "rpc_url_",
    "--fork-url",
    "--rpc-url",
    "createselectfork",
    "createfork",
)


def _command_needs_rpc(command: str) -> bool:
    """True when a command string references an RPC endpoint or fork flag."""
    text = (command or "").lower()
    return any(marker in text for marker in _RPC_COMMAND_MARKERS)


def _network_env_token(network: str | None) -> str | None:
    """``RPC_URL_<NETWORK>`` suffix: uppercased, non-alphanumerics → ``_``.

    e.g. ``base-mainnet`` -> ``BASE_MAINNET`` (env var ``RPC_URL_BASE_MAINNET``).
    """
    if not network:
        return None
    token = re.sub(r"[^0-9A-Za-z]+", "_", str(network)).strip("_").upper()
    return token or None


def _parse_chain_ref(value: object) -> tuple[str | None, int | None] | None:
    """Canonical ``(network, chain_id)`` for a declared chain ref, or None.

    Accepts a ``{"network": ..., "chain_id": ...}`` dict, a bare network
    name/subdomain, or a chain id (int or numeric string). Uses *strict*
    canonicalization: only a recognized alias/subdomain/chain id binds a chain,
    so a local-fork label (e.g. ``"local-mainnet-fork"``) or other non-chain
    metadata string stays unbound rather than producing a bogus endpoint.
    """
    if value is None:
        return None
    if isinstance(value, dict):
        net, cid = _canonical_chain(
            value.get("network"), value.get("chain_id"), strict=True
        )
    else:
        net, cid = _canonical_chain(value, None, strict=True)
        if net is None and cid is None:
            net, cid = _canonical_chain(None, value, strict=True)
    if net is None and cid is None:
        return None
    return (net, cid)


def _ordered_distinct_chain_refs(refs) -> list[tuple[str | None, int | None]]:
    """Distinct chain refs in first-seen order (keyed by chain id, else network)."""
    out: list[tuple[str | None, int | None]] = []
    seen: set[str] = set()
    for ref in refs:
        if not ref:
            continue
        key = _chain_group_key(ref[0], ref[1])
        if key is None or key in seen:
            continue
        seen.add(key)
        out.append(ref)
    return out


def _sequence_target_chain_refs(
    target_addresses: object,
) -> tuple[list[str], list[tuple[str | None, int | None]]]:
    """Addresses + distinct explicit chain refs from a ``target_addresses`` map.

    Supports both the plain-string form (``{"Vault": "0x..."}``) and the object
    form (``{"Vault": {"address": "0x...", "network": ..., "chain_id": ...}}``).
    Plain strings contribute an address but no chain binding, so existing
    string-only payloads keep working unchanged.
    """
    addresses: list[str] = []
    refs: list[tuple[str | None, int | None]] = []
    if not isinstance(target_addresses, dict):
        return addresses, refs
    for _label, value in sorted(target_addresses.items()):
        address = _replay_target_address(value)
        if address:
            addresses.append(address)
        if isinstance(value, dict):
            ref = _parse_chain_ref(value)
            if ref:
                refs.append(ref)
    return addresses, _ordered_distinct_chain_refs(refs)


def _experiment_metadata_chains(sequence_payload: dict | None) -> dict:
    """Chain intent declared in an experiment's sequence/workbench payload.

    Returns ``{"primary", "required", "addresses", "target_chains", "fork"}``:
    ``primary``/``fork`` are single refs (or None); ``required``/``target_chains``
    are ordered-distinct ref lists; ``addresses`` is every target address (both
    payload shapes) for registry-based chain binding.
    """
    payload = sequence_payload if isinstance(sequence_payload, dict) else {}
    primary = _parse_chain_ref(payload.get("primary_chain"))
    required = _ordered_distinct_chain_refs(
        _parse_chain_ref(item) for item in (payload.get("required_chains") or [])
    )
    addresses, target_chains = _sequence_target_chain_refs(
        payload.get("target_addresses")
    )
    fork = payload.get("fork")
    fork_ref = _parse_chain_ref(fork) if isinstance(fork, dict) else None
    return {
        "primary": primary,
        "required": required,
        "addresses": addresses,
        "target_chains": target_chains,
        "fork": fork_ref,
    }


def _build_experiment_rpc_env(
    primary: ResolvedRpcEndpoint | None,
    endpoints: list[ResolvedRpcEndpoint],
) -> dict[str, str]:
    """Per-exec RPC env vars for the resolved experiment endpoints.

    Each resolved chain contributes ``RPC_URL_<chain_id>`` and
    ``RPC_URL_<NETWORK>``; the primary chain additionally sets ``ETH_RPC_URL``
    for backward-compatible single-chain fork tests. URLs (which may carry an
    API key) are injected only into the container exec, never into stored
    artifacts or compact summaries.
    """
    env: dict[str, str] = {}

    def _add(endpoint: ResolvedRpcEndpoint | None) -> None:
        if endpoint is None or not endpoint.url:
            return
        if endpoint.chain_id is not None:
            env.setdefault(f"RPC_URL_{endpoint.chain_id}", endpoint.url)
        token = _network_env_token(endpoint.network)
        if token:
            env.setdefault(f"RPC_URL_{token}", endpoint.url)

    for endpoint in endpoints:
        _add(endpoint)
    if primary is not None and primary.url:
        env["ETH_RPC_URL"] = primary.url
        _add(primary)
    return env


def _experiment_rpc_plan(
    *,
    primary: ResolvedRpcEndpoint | None,
    endpoints: list[ResolvedRpcEndpoint],
) -> dict:
    """Success plan: injected env + URL-free provenance metadata."""
    resolved = [e for e in endpoints if e is not None]
    env = _build_experiment_rpc_env(primary, resolved)
    return {
        "error": None,
        "env": env,
        "primary": primary,
        "all": resolved,
        "metadata": {
            "primary": _rpc_endpoint_summary(primary) if primary else None,
            "all": [_rpc_endpoint_summary(e) for e in resolved],
            "env_vars": sorted(env.keys()),
        },
    }


def _experiment_rpc_error_plan(
    *,
    error: str,
    message: str,
    candidates: list[dict] | None = None,
    endpoint: ResolvedRpcEndpoint | None = None,
) -> dict:
    """Error plan whose ``error`` field is a ready-to-return JSON string."""
    payload: dict = {
        "error": error,
        "tool": "run_experiment",
        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
        "message": message,
    }
    if error == "chain_ambiguous":
        payload["candidates"] = candidates or []
    return {
        "error": json.dumps(payload, indent=2, sort_keys=True),
        "env": {},
        "primary": None,
        "all": [],
        "metadata": {"primary": None, "all": [], "env_vars": []},
    }


def _experiment_rpc_summary_line(metadata: dict) -> str:
    """One compact, URL-free line naming the resolved experiment chains."""
    endpoints = metadata.get("all") or []
    if not endpoints:
        return ""

    def _label(summary: dict | None) -> str:
        if not summary:
            return "none"
        net = summary.get("network")
        cid = summary.get("chain_id")
        if net and cid is not None:
            return f"{net} ({cid})"
        return net or (str(cid) if cid is not None else "unknown")

    primary_label = _label(metadata.get("primary"))
    chains = ", ".join(_label(summary) for summary in endpoints)
    return f"RPC endpoints: primary {primary_label}; chains {chains}"


async def _resolve_experiment_single_chain(
    container: AuditContainer,
    args: dict,
    *,
    fork_context: dict | None,
    addresses: list[str],
    registry: dict | None = None,
    environ: dict[str, str] | None,
    config: dict | None,
) -> dict:
    """Resolve a single experiment chain via the canonical resolver, as a plan."""
    endpoint = await _resolve_tool_rpc_endpoint(
        container,
        args,
        fork_context=fork_context,
        target_addresses=addresses,
        registry=registry,
        environ=environ,
        config=config,
    )
    if endpoint.url is None:
        error = _unresolved_rpc_error(endpoint)
        candidates = (
            await _tool_chain_candidates(container, addresses=addresses)
            if error == "chain_ambiguous"
            else []
        )
        return _experiment_rpc_error_plan(
            error=error,
            message=(
                "run_experiment needs an RPC endpoint but none could be derived. "
                "Pass rpc_url, network/chain_id, or fork_context, bind the target "
                "to a chain, or record a fork_context."
            ),
            candidates=candidates,
            endpoint=endpoint,
        )
    return _experiment_rpc_plan(primary=endpoint, endpoints=[endpoint])


async def _resolve_experiment_rpc_endpoints(
    container: AuditContainer,
    args: dict,
    *,
    sequence_payload: dict | None = None,
    fork_context: dict | None = None,
    command: str = "",
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> dict:
    """Resolve the RPC endpoint(s) a ``run_experiment`` command needs.

    Determines required chains by precedence — explicit ``rpc_url``/``network``/
    ``chain_id`` args, an explicit ``fork_context`` arg, the experiment's
    sequence/workbench chain metadata (``primary_chain``/``required_chains``/
    chain-bound ``target_addresses``/legacy ``fork`` block), a deployment chain
    binding, the latest recorded fork context, then run defaults — and resolves a
    per-chain Alchemy endpoint for each. Single-chain runs reuse the canonical
    single-target resolver verbatim; only a metadata-declared multi-chain run
    takes the dedicated grouping path.

    Returns a plan dict ``{"error", "env", "primary", "all", "metadata"}``.
    ``error`` is None on success, else a ready-to-return ``rpc_not_configured`` /
    ``chain_ambiguous`` JSON string. ``env`` is the per-exec RPC env to inject.
    When the run shows no RPC intent at all the plan is empty (no env, no error)
    so non-fork commands run exactly as before.
    """
    args = args or {}
    env = _tool_environ(environ)
    cfg = _tool_config(config)

    meta = _experiment_metadata_chains(sequence_payload)
    addresses = meta["addresses"]

    # An explicit chain_registry override is resolved up front and reused for
    # target-address chain binding; otherwise the single-target resolver lazily
    # loads the latest recorded registry only when it needs to bind addresses.
    explicit_registry = (
        await _resolve_chain_registry_arg(container, args.get("chain_registry"))
        if _coerce_nonempty(args.get("chain_registry"))
        else None
    )

    explicit_url = _coerce_nonempty(args.get("rpc_url"))
    explicit_args_chain = _has_chain_signal(args.get("network"), args.get("chain_id"))
    fork_arg_chain = isinstance(fork_context, dict) and _has_chain_signal(
        fork_context.get("network"), fork_context.get("chain_id")
    )
    arg_primary = _parse_chain_ref(args.get("primary_chain"))

    declared_refs = _ordered_distinct_chain_refs([
        arg_primary,
        meta["primary"],
        meta["fork"],
        *meta["required"],
        *meta["target_chains"],
    ])

    intent = bool(
        explicit_url
        or explicit_args_chain
        or fork_arg_chain
        or declared_refs
        or _command_needs_rpc(command)
    )
    if not intent:
        return _experiment_rpc_plan(primary=None, endpoints=[])

    # Highest precedence: an explicit per-call chain (rpc_url / network / chain_id
    # / fork_context) names a single chain. Delegate to the single-target resolver
    # so the full precedence ladder is reused verbatim.
    if explicit_url or explicit_args_chain or fork_arg_chain:
        return await _resolve_experiment_single_chain(
            container,
            args,
            fork_context=fork_context,
            addresses=addresses,
            registry=explicit_registry,
            environ=env,
            config=cfg,
        )

    # Next: the chains the experiment's own metadata declares (a fork experiment).
    if declared_refs:
        primary_ref = arg_primary or meta["primary"] or meta["fork"]
        if primary_ref is None:
            if len(declared_refs) == 1:
                primary_ref = declared_refs[0]
            else:
                return _experiment_rpc_error_plan(
                    error="chain_ambiguous",
                    message=(
                        "run_experiment found several declared chains but no "
                        "primary chain; pass primary_chain (or network/chain_id) "
                        "to choose the ETH_RPC_URL chain."
                    ),
                    candidates=_candidate_chain_dicts(declared_refs),
                )
        ordered = _ordered_distinct_chain_refs([primary_ref, *declared_refs])
        resolved_map = await _resolve_tool_rpc_endpoints_for_chains(
            container,
            [{"network": net, "chain_id": cid} for net, cid in ordered],
            environ=env,
            config=cfg,
        )
        endpoints = [
            resolved_map.get(_chain_group_key(net, cid)) for net, cid in ordered
        ]
        endpoints = [endpoint for endpoint in endpoints if endpoint is not None]
        primary = endpoints[0] if endpoints else None
        unresolved = [endpoint for endpoint in endpoints if endpoint.url is None]
        if primary is None or primary.url is None or unresolved:
            return _experiment_rpc_error_plan(
                error="rpc_not_configured",
                message=(
                    "run_experiment could not derive endpoints for every declared "
                    "chain. Configure ALCHEMY_API_KEY (and per-chain rpc_urls) or "
                    "pass an explicit rpc_url override."
                ),
                endpoint=primary,
            )
        return _experiment_rpc_plan(primary=primary, endpoints=endpoints)

    # Fallback: only a command marker signalled intent — let the single-target
    # resolver try a deployment binding, the latest fork context, run defaults,
    # then an explicit ETH_RPC_URL.
    return await _resolve_experiment_single_chain(
        container,
        args,
        fork_context=fork_context,
        addresses=addresses,
        registry=explicit_registry,
        environ=env,
        config=cfg,
    )


def _item_registry_candidates(
    registry: dict | None, item: dict
) -> list[tuple[str | None, int | None]]:
    """Distinct registry chains hosting a probe item (address before names)."""
    address = _coerce_nonempty((item or {}).get("address"))
    names = [
        name for name in (item or {}).get("names") or [] if _coerce_nonempty(name)
    ]
    raw: list[dict] = []
    if address:
        raw += _chain_hints_for_address_or_contract(registry, address=address)
    if not raw:
        for name in names:
            raw += _chain_hints_for_address_or_contract(
                registry, name=name, contract=name
            )
    return _distinct_chain_keys(raw)


async def _plan_live_probe_chains(
    container: AuditContainer,
    args: dict,
    *,
    items: list[dict],
    registry: dict | None,
    fork_context: dict | None,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> dict:
    """Assign live-probe items to per-chain groups for multi-chain probing.

    Each item is ``{"address": str|None, "names": [str, ...]}`` and is matched
    positionally to the returned ``assignments`` list. Resolution mirrors
    :func:`_resolve_tool_rpc_endpoint` precedence but *groups* targets by chain
    instead of collapsing them, and never relies on a chain-agnostic global
    ``ETH_RPC_URL``:

    * an explicit ``rpc_url`` override is one endpoint for every item;
    * an explicit ``network``/``chain_id`` (or ``fork_context`` chain) names the
      chain for every item, except items the registry binds to a *different*
      single chain, which are reported ``chain_mismatch`` (filtered, not probed
      on the wrong chain);
    * otherwise each item's chain comes from its registry deployment binding — a
      binding to several chains is ``ambiguous`` (never chosen arbitrarily);
    * an unbound item falls back to the latest fork context, then the run-level
      default chain, else it is ``unbound``.

    Returns ``{"assignments": [...], "groups": {key: {...}}, "override": bool}``.
    Each group is ``{"network", "chain_id", "source", "endpoint"}``.
    """
    args = args or {}
    env = _tool_environ(environ)
    cfg = _tool_config(config)
    # Per-chain endpoints are derived with ETH_RPC_URL stripped: these tools span
    # chains, so a single global node URL must never stand in for the wrong one.
    tool_env = {key: value for key, value in env.items() if key != "ETH_RPC_URL"}

    assignments: list[dict] = []
    groups: dict[str, dict] = {}

    # Explicit rpc_url override: a single deliberate endpoint for every item.
    override_url = _coerce_nonempty(args.get("rpc_url"))
    if override_url:
        endpoint = resolve_rpc_endpoint(
            rpc_url=override_url,
            network=args.get("network"),
            chain_id=args.get("chain_id"),
            environ=env,
            config=cfg,
        )
        key = _chain_group_key(endpoint.network, endpoint.chain_id) or "rpc_url"
        groups[key] = {
            "network": endpoint.network,
            "chain_id": endpoint.chain_id,
            "source": endpoint.source,
            "endpoint": endpoint,
        }
        assignments = [
            {
                "status": "grouped",
                "chain_key": key,
                "network": endpoint.network,
                "chain_id": endpoint.chain_id,
            }
            for _ in items
        ]
        return {"assignments": assignments, "groups": groups, "override": True}

    # A global explicit chain (args win over a passed fork context).
    explicit_net = explicit_cid = explicit_source = None
    if _has_chain_signal(args.get("network"), args.get("chain_id")):
        explicit_net, explicit_cid = _canonical_chain(
            args.get("network"), args.get("chain_id")
        )
        explicit_source = "args"
    elif isinstance(fork_context, dict) and _has_chain_signal(
        fork_context.get("network"), fork_context.get("chain_id")
    ):
        explicit_net, explicit_cid = _canonical_chain(
            fork_context.get("network"), fork_context.get("chain_id")
        )
        explicit_source = "fork_context"
    has_explicit = explicit_net is not None or explicit_cid is not None

    # A weak run-level fallback chain (latest fork context, then run default),
    # consulted only for items with no registry binding.
    fallback_net = fallback_cid = fallback_source = None
    latest = await _latest_fork_context(container)
    if latest and _has_chain_signal(latest.get("network"), latest.get("chain_id")):
        fallback_net, fallback_cid = _canonical_chain(
            latest.get("network"), latest.get("chain_id")
        )
        fallback_source = "latest_fork_context"
    else:
        default_net, default_cid, default_source = resolve_default_chain_hint(
            environ=env, config=cfg
        )
        if default_net or default_cid is not None:
            fallback_net, fallback_cid, fallback_source = (
                default_net,
                default_cid,
                default_source,
            )

    chain_refs: dict[str, tuple] = {}

    def _register(net, cid, source) -> str | None:
        key = _chain_group_key(net, cid)
        if key is not None:
            chain_refs.setdefault(key, (net, cid, source))
        return key

    for item in items:
        candidates = _item_registry_candidates(registry, item or {})
        if has_explicit:
            if candidates and not _chain_matches(
                candidates, explicit_net, explicit_cid
            ):
                assignments.append({
                    "status": "chain_mismatch",
                    "requested_chain": {
                        "network": explicit_net,
                        "chain_id": explicit_cid,
                    },
                    "candidates": _candidate_chain_dicts(candidates),
                })
                continue
            key = _register(explicit_net, explicit_cid, explicit_source)
            assignments.append({
                "status": "grouped",
                "chain_key": key,
                "network": explicit_net,
                "chain_id": explicit_cid,
            })
        elif len(candidates) == 1:
            net, cid = candidates[0]
            key = _register(net, cid, "chain_registry")
            assignments.append({
                "status": "grouped",
                "chain_key": key,
                "network": net,
                "chain_id": cid,
            })
        elif len(candidates) > 1:
            assignments.append({
                "status": "ambiguous",
                "candidates": _candidate_chain_dicts(candidates),
            })
        elif fallback_net is not None or fallback_cid is not None:
            key = _register(fallback_net, fallback_cid, fallback_source)
            assignments.append({
                "status": "grouped",
                "chain_key": key,
                "network": fallback_net,
                "chain_id": fallback_cid,
            })
        else:
            assignments.append({"status": "unbound"})

    for key, (net, cid, source) in chain_refs.items():
        endpoint = resolve_rpc_endpoint(
            network=net,
            chain_id=cid,
            allow_default_mainnet=False,
            environ=tool_env,
            config=cfg,
        )
        # Record *why* this chain was chosen (registry/args/...), not just how
        # the URL was derived, mirroring _resolve_tool_rpc_endpoint.
        if source and source != endpoint.source:
            endpoint = dataclasses.replace(endpoint, source=source)
        groups[key] = {
            "network": net,
            "chain_id": cid,
            "source": source,
            "endpoint": endpoint,
        }

    return {"assignments": assignments, "groups": groups, "override": False}


def _summarize_live_probe_chains(
    *,
    assignments: list[dict],
    groups: dict[str, dict],
    entries: list[dict],
    meta_for,
    label_for=None,
) -> dict:
    """Build the chain grouping + ambiguity/skip lists shared by both tools.

    ``meta_for(index)`` returns a compact identifier dict for item ``index``
    (label/contract/address) used in the ambiguous/skipped lists; ``label_for``
    (default: the meta ``address``) is the single short id listed under each
    chain block. Reads each entry's ``probe.skipped`` to classify skips.

    Returns ``{"chains", "chains_probed", "ambiguous_targets", "skipped_targets"}``.
    """
    label_for = label_for or (lambda index: meta_for(index).get("address"))
    chain_blocks: dict[str, dict] = {}
    chain_order: list[str] = []
    ambiguous: list[dict] = []
    skipped: list[dict] = []
    probed_keys: set = set()

    for index, assignment in enumerate(assignments):
        status = assignment.get("status")
        probe = (entries[index].get("probe") or {}) if index < len(entries) else {}
        if probe.get("executed"):
            probed_keys.add(assignment.get("chain_key"))

        if status == "grouped":
            key = assignment.get("chain_key")
            group = groups.get(key)
            if group is not None:
                block = chain_blocks.get(key)
                if block is None:
                    endpoint = group.get("endpoint")
                    block = {
                        "key": key,
                        "network": group.get("network"),
                        "chain_id": group.get("chain_id"),
                        "source": group.get("source"),
                        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
                        "configured": bool(endpoint and endpoint.url),
                        "targets": [],
                    }
                    chain_blocks[key] = block
                    chain_order.append(key)
                block["targets"].append(label_for(index))

        if status == "ambiguous":
            ambiguous.append({
                **meta_for(index),
                "candidates": assignment.get("candidates") or [],
            })

        reason = probe.get("skipped")
        if reason and reason != "chain_ambiguous":
            record = {**meta_for(index), "reason": reason}
            if assignment.get("requested_chain"):
                record["requested_chain"] = assignment["requested_chain"]
            if assignment.get("candidates"):
                record["candidates"] = assignment["candidates"]
            if assignment.get("network") or assignment.get("chain_id") is not None:
                record["network"] = assignment.get("network")
                record["chain_id"] = assignment.get("chain_id")
            skipped.append(record)

    chains = [chain_blocks[key] for key in chain_order]
    chains_probed = [block for block in chains if block["key"] in probed_keys]
    return {
        "chains": chains,
        "chains_probed": chains_probed,
        "ambiguous_targets": ambiguous,
        "skipped_targets": skipped,
    }


def _compact_chain_block(block: dict) -> dict:
    """Compact, model-visible per-chain summary (counts, no bulk target list)."""
    return {
        "network": block.get("network"),
        "chain_id": block.get("chain_id"),
        "source": block.get("source"),
        "rpc_endpoint": block.get("rpc_endpoint"),
        "configured": block.get("configured"),
        "targets": len(block.get("targets") or []),
    }


def _fork_context_chain_targets(context: dict) -> tuple[list[str], list[str]]:
    """Collect (addresses, names) from a fork context for chain inference.

    Pulls from the deployed-contract collections only (not actors), so chain
    binding rests on real deployment addresses and contract names.
    """
    addresses: list[str] = []
    names: list[str] = []
    for collection in _FORK_ADDRESS_COLLECTIONS:
        for item in context.get(collection, []) or []:
            if not isinstance(item, dict):
                continue
            address = _context_address(item)
            if address:
                addresses.append(address)
            for key in ("name", "label", "symbol"):
                name = _coerce_nonempty(item.get(key))
                if name:
                    names.append(name)
                    break
    return addresses, names


async def _snapshot_state(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    title = args.get("title", "").strip()
    if not title:
        return "Error: 'title' is required"

    try:
        eth_balances = _require_list(args.get("eth_balances"), "eth_balances")
        erc20_balances = _require_list(args.get("erc20_balances"), "erc20_balances")
        storage_slots = _require_list(args.get("storage_slots"), "storage_slots")
        calls = _require_list(args.get("calls"), "calls")
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"
    if not any((eth_balances, erc20_balances, storage_slots, calls)):
        return "Error: snapshot_state requires at least one probe"

    # Pass 1: validate probe shapes, collect specs, and gather addresses for
    # chain inference — before any RPC resolution, so a malformed probe still
    # returns its precise error rather than a chain error.
    eth_specs: list[dict] = []
    erc20_specs: list[dict] = []
    slot_specs: list[dict] = []
    call_specs: list[dict] = []
    target_addresses: list[str] = []
    for item in eth_balances:
        try:
            item = _require_dict(item, "eth_balances")
        except ValueError as exc:
            return f"Error: {exc}"
        address = str(item.get("address", "")).strip()
        if not address:
            return "Error: eth_balances entries require 'address'"
        eth_specs.append({"label": item.get("label"), "address": address})
        target_addresses.append(address)
    for item in erc20_balances:
        try:
            item = _require_dict(item, "erc20_balances")
        except ValueError as exc:
            return f"Error: {exc}"
        token = str(item.get("token", "")).strip()
        account = str(item.get("account", "")).strip()
        if not token or not account:
            return "Error: erc20_balances entries require 'token' and 'account'"
        erc20_specs.append({
            "token": token,
            "token_label": item.get("token_label"),
            "account": account,
            "account_label": item.get("account_label"),
        })
        target_addresses.extend((token, account))
    for item in storage_slots:
        try:
            item = _require_dict(item, "storage_slots")
        except ValueError as exc:
            return f"Error: {exc}"
        contract = str(item.get("contract", "")).strip()
        slot = str(item.get("slot", "")).strip()
        if not contract or not slot:
            return "Error: storage_slots entries require 'contract' and 'slot'"
        slot_specs.append({
            "label": item.get("label"),
            "contract": contract,
            "slot": slot,
        })
        target_addresses.append(contract)
    for item in calls:
        try:
            item = _require_dict(item, "calls")
        except ValueError as exc:
            return f"Error: {exc}"
        target = str(item.get("target", "")).strip()
        signature = str(item.get("signature", "")).strip()
        raw_args = item.get("args") or []
        if not isinstance(raw_args, list):
            return "Error: calls args must be a list of strings"
        call_args = [str(arg) for arg in raw_args]
        if not target or not signature:
            return "Error: calls entries require 'target' and 'signature'"
        call_specs.append({
            "label": item.get("label"),
            "target": target,
            "signature": signature,
            "args": call_args,
        })
        target_addresses.append(target)

    # One snapshot belongs to one chain. Resolve a single endpoint from explicit
    # args, fork context, or an unambiguous deployment binding — never cast's
    # implicit default.
    fork_context = await _resolve_fork_context_arg(container, args.get("fork_context"))
    endpoint = await _resolve_tool_rpc_endpoint(
        container,
        args,
        fork_context=fork_context,
        target_addresses=target_addresses,
        environ=environ,
        config=config,
    )
    if endpoint.url is None:
        return await _chain_unresolved_response(
            container,
            tool="snapshot_state",
            endpoint=endpoint,
            addresses=target_addresses,
            message=(
                "snapshot_state requires rpc_url, network/chain_id, "
                "fork_context, or an unambiguous deployment chain binding."
            ),
        )

    state = await _load_campaign_state(container)
    snapshot_id = _next_campaign_id(state, "snapshot")
    rpc_url = endpoint.url
    rpc_arg = _cast_rpc_arg(rpc_url)
    probes: dict[str, list[dict]] = {
        "eth_balances": [],
        "erc20_balances": [],
        "storage_slots": [],
        "calls": [],
    }

    # Pass 2: run each probe against the resolved endpoint, redacting the URL
    # (which may carry an API key) from every stored command.
    for spec in eth_specs:
        probe = {"label": spec["label"], "address": spec["address"]}
        command = f"cast balance {shlex.quote(spec['address'])}{rpc_arg}"
        probe.update(_redact_rpc_from_probe(await _run_probe(container, command), rpc_url))
        probes["eth_balances"].append(probe)

    for spec in erc20_specs:
        probe = {
            "token": spec["token"],
            "token_label": spec["token_label"],
            "account": spec["account"],
            "account_label": spec["account_label"],
        }
        command = (
            f"cast call {shlex.quote(spec['token'])} "
            f"{shlex.quote('balanceOf(address)(uint256)')} "
            f"{shlex.quote(spec['account'])}{rpc_arg}"
        )
        probe.update(_redact_rpc_from_probe(await _run_probe(container, command), rpc_url))
        probes["erc20_balances"].append(probe)

    for spec in slot_specs:
        probe = {
            "label": spec["label"],
            "contract": spec["contract"],
            "slot": spec["slot"],
        }
        command = (
            f"cast storage {shlex.quote(spec['contract'])} "
            f"{shlex.quote(spec['slot'])}{rpc_arg}"
        )
        probe.update(_redact_rpc_from_probe(await _run_probe(container, command), rpc_url))
        probes["storage_slots"].append(probe)

    for spec in call_specs:
        probe = {
            "label": spec["label"],
            "target": spec["target"],
            "signature": spec["signature"],
            "args": spec["args"],
        }
        arg_text = "".join(f" {shlex.quote(arg)}" for arg in spec["args"])
        command = (
            f"cast call {shlex.quote(spec['target'])} "
            f"{shlex.quote(spec['signature'])}{arg_text}{rpc_arg}"
        )
        probe.update(_redact_rpc_from_probe(await _run_probe(container, command), rpc_url))
        probes["calls"].append(probe)

    now = datetime.now(timezone.utc).isoformat()
    snapshot = {
        "id": snapshot_id,
        "title": title,
        "created_at": now,
        "network": endpoint.network,
        "chain_id": endpoint.chain_id,
        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
        "related_ids": [str(item) for item in related_ids],
        "probes": probes,
    }
    snapshot_path = f"/workspace/campaign/snapshots/{snapshot_id}.json"
    await container.write_file(
        snapshot_path,
        json.dumps(snapshot, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"State snapshot: {title}",
            content=(
                f"Snapshot: {snapshot_id}\n"
                f"Path: {snapshot_path}\n"
                f"Probe counts: "
                f"{ {name: len(items) for name, items in probes.items()} }"
            ),
            evidence=[snapshot_path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    summary = {
        "snapshot_id": snapshot_id,
        "path": snapshot_path,
        "result_id": result_id or None,
        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
        "probe_counts": {name: len(items) for name, items in probes.items()},
        "failed_probes": sum(
            1 for items in probes.values() for item in items if not item.get("ok")
        ),
    }
    return json.dumps(summary, indent=2, sort_keys=True)


def _snapshot_path(identifier: str) -> str:
    value = identifier.strip()
    if value.startswith("/"):
        normalized = posixpath.normpath(value)
        if not normalized.startswith("/workspace/campaign/snapshots/"):
            raise ValueError(
                "absolute snapshot paths must be under "
                "/workspace/campaign/snapshots/"
            )
        return normalized
    if not re.fullmatch(r"snap-\d{3,}", value):
        raise ValueError(
            "snapshot reference must be an absolute path or id like snap-001"
        )
    return f"/workspace/campaign/snapshots/{value}.json"


async def _load_snapshot(container: AuditContainer, identifier: str) -> tuple[str, dict]:
    path = _snapshot_path(identifier)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"snapshot {path} is not valid JSON") from exc


def _flatten_snapshot(snapshot: dict) -> dict[str, dict]:
    flattened = {}
    for kind, probes in (snapshot.get("probes") or {}).items():
        if not isinstance(probes, list):
            continue
        for probe in probes:
            if not isinstance(probe, dict):
                continue
            flattened[_snapshot_probe_key(kind, probe)] = {
                "kind": kind,
                "probe": probe,
                "value": probe.get("value"),
                "ok": probe.get("ok"),
                "error": probe.get("error"),
            }
    return flattened


async def _compare_snapshots(container: AuditContainer, args: dict) -> str:
    before_ref = args.get("before", "").strip()
    after_ref = args.get("after", "").strip()
    if not before_ref:
        return "Error: 'before' is required"
    if not after_ref:
        return "Error: 'after' is required"

    try:
        before_path, before = await _load_snapshot(container, before_ref)
        after_path, after = await _load_snapshot(container, after_ref)
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except (FileNotFoundError, ValueError) as exc:
        return f"Error: {exc}"

    before_flat = _flatten_snapshot(before)
    after_flat = _flatten_snapshot(after)
    changed = []
    missing_after = []
    added_after = []

    for key in sorted(before_flat):
        if key not in after_flat:
            missing_after.append({"key": key, "before": before_flat[key]})
            continue
        before_value = before_flat[key].get("value")
        after_value = after_flat[key].get("value")
        if before_value == after_value and before_flat[key].get("ok") == after_flat[key].get("ok"):
            continue
        before_int = _parse_int_value(before_value)
        after_int = _parse_int_value(after_value)
        entry = {
            "key": key,
            "kind": before_flat[key]["kind"],
            "before": before_value,
            "after": after_value,
            "before_ok": before_flat[key].get("ok"),
            "after_ok": after_flat[key].get("ok"),
        }
        if before_int is not None and after_int is not None:
            entry["delta"] = after_int - before_int
        if before_flat[key].get("error") or after_flat[key].get("error"):
            entry["before_error"] = before_flat[key].get("error")
            entry["after_error"] = after_flat[key].get("error")
        changed.append(entry)

    for key in sorted(after_flat):
        if key not in before_flat:
            added_after.append({"key": key, "after": after_flat[key]})

    suggested_objectives = _suggest_objectives_from_changes(changed)
    state = await _load_campaign_state(container)
    comparison_id = _next_campaign_id(state, "comparison")
    title = args.get("title", "").strip() or (
        f"Compare {before.get('id', before_ref)} -> {after.get('id', after_ref)}"
    )
    comparison = {
        "id": comparison_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "before": {
            "id": before.get("id"),
            "path": before_path,
            "title": before.get("title"),
        },
        "after": {
            "id": after.get("id"),
            "path": after_path,
            "title": after.get("title"),
        },
        "changed": changed,
        "missing_after": missing_after,
        "added_after": added_after,
        "suggested_objectives": suggested_objectives,
        "summary": {
            "changed": len(changed),
            "missing_after": len(missing_after),
            "added_after": len(added_after),
            "suggested_objectives": len(suggested_objectives),
        },
    }
    comparison_path = f"/workspace/campaign/comparisons/{comparison_id}.json"
    await container.write_file(
        comparison_path,
        json.dumps(comparison, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Snapshot comparison: {title}",
            content=(
                f"Comparison: {comparison_id}\n"
                f"Path: {comparison_path}\n"
                f"Before: {before_path}\n"
                f"After: {after_path}\n"
                f"Changed probes: {len(changed)}\n"
                f"Missing-after probes: {len(missing_after)}\n"
                f"Added-after probes: {len(added_after)}"
            ),
            evidence=[comparison_path, before_path, after_path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "comparison_id": comparison_id,
        "path": comparison_path,
        "result_id": result_id or None,
        "summary": comparison["summary"],
        "changed": changed[:50],
        "suggested_objectives": suggested_objectives[:12],
        "truncated_changed": max(0, len(changed) - 50),
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _comparison_path(identifier: str) -> str:
    value = identifier.strip()
    if value.startswith("/"):
        normalized = posixpath.normpath(value)
        if not normalized.startswith("/workspace/campaign/comparisons/"):
            raise ValueError(
                "absolute comparison paths must be under "
                "/workspace/campaign/comparisons/"
            )
        return normalized
    if not re.fullmatch(r"cmp-\d{3,}", value):
        raise ValueError(
            "comparison reference must be an absolute path or id like cmp-001"
        )
    return f"/workspace/campaign/comparisons/{value}.json"


async def _load_comparison(
    container: AuditContainer,
    identifier: str,
) -> tuple[str, dict]:
    path = _comparison_path(identifier)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"comparison {path} is not valid JSON") from exc


def _decimal_from_value(value: object, default: str = "0") -> Decimal:
    text = str(value if value is not None else default).strip()
    if not text:
        text = default
    try:
        return Decimal(text)
    except InvalidOperation as exc:
        raise ValueError(f"invalid decimal value '{text}'") from exc


def _suggest_objectives_from_changes(
    changed: list[dict],
    *,
    limit: int = 12,
) -> list[dict]:
    suggestions = []
    seen = set()
    for entry in changed:
        if not isinstance(entry, dict) or "delta" not in entry:
            continue
        key = str(entry.get("key") or "").strip()
        if not key or key in seen:
            continue
        seen.add(key)
        try:
            delta = int(entry.get("delta") or 0)
        except (TypeError, ValueError):
            delta = 0
        if delta > 0:
            direction = "increase"
        elif delta < 0:
            direction = "decrease"
        else:
            direction = "unchanged"
        label = key
        role = None
        lowered = key.lower()
        if "attacker" in lowered:
            label = f"attacker delta for {key}"
            role = "attacker"
        elif any(term in lowered for term in ("vault", "pool", "reserve", "protocol")):
            label = f"protocol target delta for {key}"
            role = "protocol"
        suggestion = {
            "label": label[:160],
            "key": key,
            "direction": direction,
            "decimals": 0,
            "unit": "raw",
        }
        if role:
            suggestion["role"] = role
        suggestions.append(suggestion)
        if len(suggestions) >= limit:
            break
    return suggestions


def _objective_examples_for_comparison(comparison: dict, *, limit: int = 3) -> list[dict]:
    suggestions = comparison.get("suggested_objectives")
    if not isinstance(suggestions, list) or not suggestions:
        suggestions = _suggest_objectives_from_changes(comparison.get("changed") or [])
    return [
        item for item in suggestions[:limit]
        if isinstance(item, dict)
    ]


def _objective_matches_entry(entry: dict, objective: dict) -> bool:
    key = str(entry.get("key") or "")
    exact_key = str(objective.get("key") or "").strip()
    if exact_key:
        return key == exact_key
    match = str(objective.get("match") or "").strip().lower()
    if match:
        return match in key.lower()
    kind = str(objective.get("kind") or "").strip()
    if kind:
        return entry.get("kind") == kind
    return False


def _direction_passes(delta: Decimal, direction: str, min_delta: Decimal) -> bool:
    threshold = abs(min_delta)
    match direction:
        case "increase":
            return delta > 0 if threshold == 0 else delta >= threshold
        case "decrease":
            return delta < 0 if threshold == 0 else delta <= -threshold
        case "nonzero":
            return abs(delta) > 0 if threshold == 0 else abs(delta) >= threshold
        case "unchanged":
            return abs(delta) == 0 if threshold == 0 else abs(delta) <= threshold
        case "any":
            return True
        case _:
            raise ValueError(
                "objective direction must be increase, decrease, nonzero, "
                "unchanged, or any"
            )


def _scaled_delta(delta: int, decimals: int) -> Decimal:
    return Decimal(delta) / (Decimal(10) ** decimals)


def _evaluate_objective_entry(objective: dict, changed: list[dict]) -> dict:
    label = str(objective.get("label") or objective.get("match") or "objective")
    direction = str(objective.get("direction") or "nonzero").strip().lower()
    decimals = int(objective.get("decimals", 0) or 0)
    if decimals < 0 or decimals > 77:
        raise ValueError("objective decimals must be between 0 and 77")
    min_delta = _decimal_from_value(objective.get("min_delta"), "0")
    unit = str(objective.get("unit") or "raw")
    price_usd_raw = objective.get("price_usd")
    price_usd = (
        _decimal_from_value(price_usd_raw, "0")
        if price_usd_raw is not None
        else None
    )

    matches = []
    passed_any = False
    for entry in changed:
        if not _objective_matches_entry(entry, objective):
            continue
        if "delta" not in entry:
            matches.append({
                "key": entry.get("key"),
                "passed": False,
                "reason": "matched probe has no numeric delta",
                "before": entry.get("before"),
                "after": entry.get("after"),
            })
            continue
        delta = int(entry["delta"])
        scaled = _scaled_delta(delta, decimals)
        passed = _direction_passes(scaled, direction, min_delta)
        passed_any = passed_any or passed
        match = {
            "key": entry.get("key"),
            "kind": entry.get("kind"),
            "before": entry.get("before"),
            "after": entry.get("after"),
            "delta_raw": delta,
            "delta": str(scaled),
            "unit": unit,
            "passed": passed,
        }
        if price_usd is not None:
            match["usd_delta"] = str(scaled * price_usd)
            match["price_usd"] = str(price_usd)
        matches.append(match)

    return {
        "label": label,
        "direction": direction,
        "min_delta": str(min_delta),
        "decimals": decimals,
        "unit": unit,
        "role": objective.get("role"),
        "matched": len(matches),
        "passed": bool(matches) and passed_any,
        "matches": matches,
    }


async def _evaluate_objective(container: AuditContainer, args: dict) -> str:
    comparison_ref = args.get("comparison", "").strip()
    if not comparison_ref:
        return "Error: 'comparison' is required"
    try:
        objectives = [
            _require_dict(item, "objectives")
            for item in _require_list(args.get("objectives"), "objectives")
        ]
        related_ids = _require_list(args.get("related_ids"), "related_ids")
        comparison_path, comparison = await _load_comparison(container, comparison_ref)
    except (FileNotFoundError, ValueError) as exc:
        return f"Error: {exc}"
    if not objectives:
        examples = _objective_examples_for_comparison(comparison)
        suffix = (
            "\nSuggested objective examples:\n"
            + json.dumps(examples, indent=2, sort_keys=True)
            if examples else ""
        )
        return "Error: evaluate_objective requires at least one objective" + suffix

    changed = comparison.get("changed") or []
    if not isinstance(changed, list):
        return "Error: comparison changed field must be a list"
    try:
        evaluated = [
            _evaluate_objective_entry(objective, changed)
            for objective in objectives
        ]
    except ValueError as exc:
        return f"Error: {exc}"

    passed = sum(1 for item in evaluated if item["passed"])
    unmatched = sum(1 for item in evaluated if item["matched"] == 0)
    failed = len(evaluated) - passed
    suggested_objectives = _objective_examples_for_comparison(comparison, limit=6)
    state = await _load_campaign_state(container)
    evaluation_id = _next_campaign_id(state, "evaluation")
    title = args.get("title", "").strip() or (
        f"Objective evaluation for {comparison.get('id', comparison_ref)}"
    )
    evaluation = {
        "id": evaluation_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "comparison": {
            "id": comparison.get("id"),
            "path": comparison_path,
            "title": comparison.get("title"),
        },
        "summary": {
            "objectives": len(evaluated),
            "passed": passed,
            "failed": failed,
            "unmatched": unmatched,
        },
        "objectives": evaluated,
        "suggested_objectives": suggested_objectives if unmatched else [],
        "related_ids": [str(item) for item in related_ids],
    }
    evaluation_path = f"/workspace/campaign/evaluations/{evaluation_id}.json"
    await container.write_file(
        evaluation_path,
        json.dumps(evaluation, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Objective evaluation: {title}",
            content=(
                f"Evaluation: {evaluation_id}\n"
                f"Path: {evaluation_path}\n"
                f"Comparison: {comparison_path}\n"
                f"Objectives: {len(evaluated)}\n"
                f"Passed: {passed}\n"
                f"Failed: {failed}\n"
                f"Unmatched: {unmatched}"
            ),
            evidence=[evaluation_path, comparison_path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "evaluation_id": evaluation_id,
        "path": evaluation_path,
        "result_id": result_id or None,
        "summary": evaluation["summary"],
        "objectives": evaluated,
        "suggested_objectives": suggested_objectives if unmatched else [],
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _decimal_string(value: Decimal) -> str:
    if value == value.to_integral_value():
        return str(value.quantize(Decimal(1)))
    return format(value.normalize(), "f")


def _decimal_to_raw_amount(value: object, decimals: int) -> int:
    amount = _decimal_from_value(value, "0")
    scaled = amount * (Decimal(10) ** decimals)
    if scaled != scaled.to_integral_value():
        raise ValueError(
            f"decimal amount {value} has more precision than {decimals} decimals"
        )
    return int(scaled)


def _int_with_default(value: object, default: int) -> int:
    if value is None:
        return default
    return int(value)


def _raw_amount_from_pool(pool: dict, previous_amount_out: int | None) -> int:
    decimals = _int_with_default(pool.get("token_in_decimals"), 18)
    if decimals < 0 or decimals > 77:
        raise ValueError("token_in_decimals must be between 0 and 77")
    if pool.get("amount_in") is not None:
        return int(str(pool["amount_in"]), 0)
    if pool.get("amount_in_decimal") is not None:
        return _decimal_to_raw_amount(pool["amount_in_decimal"], decimals)
    if previous_amount_out is not None:
        return previous_amount_out
    raise ValueError("first pool requires amount_in or amount_in_decimal")


def _scaled_amount_string(value: int, decimals: int) -> str:
    if decimals < 0 or decimals > 77:
        raise ValueError("token decimals must be between 0 and 77")
    return _decimal_string(Decimal(value) / (Decimal(10) ** decimals))


def _amm_amount_out(
    *,
    amount_in: int,
    reserve_in: int,
    reserve_out: int,
    fee_bps: int,
) -> int:
    if amount_in < 0:
        raise ValueError("amount_in must be non-negative")
    if reserve_in <= 0 or reserve_out <= 0:
        raise ValueError("reserves must be positive")
    if fee_bps < 0 or fee_bps >= 10_000:
        raise ValueError("fee_bps must be between 0 and 9999")
    amount_in_with_fee = amount_in * (10_000 - fee_bps)
    return (amount_in_with_fee * reserve_out) // (
        reserve_in * 10_000 + amount_in_with_fee
    )


def _amm_price(
    *,
    reserve_in: int,
    reserve_out: int,
    token_in_decimals: int,
    token_out_decimals: int,
) -> Decimal:
    in_units = Decimal(reserve_in) / (Decimal(10) ** token_in_decimals)
    out_units = Decimal(reserve_out) / (Decimal(10) ** token_out_decimals)
    if in_units == 0:
        raise ValueError("reserve_in is zero")
    return out_units / in_units


def _amm_price_change_bps(
    *,
    reserve_in: int,
    reserve_out: int,
    amount_in: int,
    amount_out: int,
    token_in_decimals: int,
    token_out_decimals: int,
) -> Decimal:
    before = _amm_price(
        reserve_in=reserve_in,
        reserve_out=reserve_out,
        token_in_decimals=token_in_decimals,
        token_out_decimals=token_out_decimals,
    )
    after = _amm_price(
        reserve_in=reserve_in + amount_in,
        reserve_out=reserve_out - amount_out,
        token_in_decimals=token_in_decimals,
        token_out_decimals=token_out_decimals,
    )
    if before == 0:
        return Decimal(0)
    return ((after - before) / before) * Decimal(10_000)


def _amm_slippage_bps(
    *,
    amount_in: int,
    amount_out: int,
    reserve_in: int,
    reserve_out: int,
) -> Decimal:
    no_slippage_out = Decimal(amount_in) * Decimal(reserve_out) / Decimal(reserve_in)
    if no_slippage_out == 0:
        return Decimal(0)
    return (Decimal(1) - (Decimal(amount_out) / no_slippage_out)) * Decimal(10_000)


def _amm_effective_price(
    *,
    amount_in: int,
    amount_out: int,
    token_in_decimals: int,
    token_out_decimals: int,
) -> Decimal:
    in_units = Decimal(amount_in) / (Decimal(10) ** token_in_decimals)
    out_units = Decimal(amount_out) / (Decimal(10) ** token_out_decimals)
    if in_units == 0:
        return Decimal(0)
    return out_units / in_units


def _target_price_decrease_amount(
    *,
    reserve_in: int,
    reserve_out: int,
    target_bps: int,
    fee_bps: int,
    token_in_decimals: int,
    token_out_decimals: int,
) -> dict:
    if target_bps <= 0 or target_bps >= 10_000:
        raise ValueError("target_price_decrease_bps must be between 1 and 9999")
    before = _amm_price(
        reserve_in=reserve_in,
        reserve_out=reserve_out,
        token_in_decimals=token_in_decimals,
        token_out_decimals=token_out_decimals,
    )
    target_price = before * (Decimal(10_000 - target_bps) / Decimal(10_000))

    def reaches_target(amount: int) -> tuple[bool, int, Decimal]:
        output = _amm_amount_out(
            amount_in=amount,
            reserve_in=reserve_in,
            reserve_out=reserve_out,
            fee_bps=fee_bps,
        )
        after_price = _amm_price(
            reserve_in=reserve_in + amount,
            reserve_out=reserve_out - output,
            token_in_decimals=token_in_decimals,
            token_out_decimals=token_out_decimals,
        )
        return after_price <= target_price, output, after_price

    high = 1
    for _ in range(256):
        reached, _, _ = reaches_target(high)
        if reached:
            break
        high *= 2
    else:
        raise ValueError("could not find target price decrease within search bounds")

    low = 0
    best_output = 0
    best_price = before
    while low < high:
        mid = (low + high) // 2
        reached, output, after_price = reaches_target(mid)
        if reached:
            high = mid
            best_output = output
            best_price = after_price
        else:
            low = mid + 1

    reached, best_output, best_price = reaches_target(high)
    if not reached:
        raise ValueError("target price decrease search failed")
    return {
        "target_price_decrease_bps": target_bps,
        "required_amount_in_raw": high,
        "estimated_amount_out_raw": best_output,
        "target_price_out_per_in": _decimal_string(target_price),
        "estimated_price_out_per_in": _decimal_string(best_price),
    }


def _parse_reserve_output(output: str) -> tuple[int, int]:
    numbers = re.findall(r"\b\d+\b", output)
    if len(numbers) < 2:
        raise ValueError(f"could not parse getReserves output: {output.strip()}")
    return int(numbers[0]), int(numbers[1])


async def _pool_reserves(
    container: AuditContainer,
    pool: dict,
    *,
    endpoint: ResolvedRpcEndpoint | None,
) -> tuple[int, int, dict]:
    if pool.get("reserve_in") is not None and pool.get("reserve_out") is not None:
        return (
            int(str(pool["reserve_in"]), 0),
            int(str(pool["reserve_out"]), 0),
            {"source": "manual"},
        )

    pair = str(pool.get("pair") or "").strip()
    if not pair:
        raise ValueError("pool requires reserve_in/reserve_out or pair")
    token_in_index = int(pool.get("token_in_index", 0) or 0)
    if token_in_index not in (0, 1):
        raise ValueError("token_in_index must be 0 or 1")
    if endpoint is None or endpoint.url is None:
        raise ValueError("on-chain reserve lookup requires a resolvable chain")
    rpc_url = endpoint.url
    rpc_arg = _cast_rpc_arg(rpc_url)
    command = (
        f"cast call {shlex.quote(pair)} "
        f"{shlex.quote('getReserves()(uint112,uint112,uint32)')}{rpc_arg}"
    )
    exit_code, output = await container.exec(command, timeout=30)
    if exit_code != 0:
        raise ValueError(output.strip() or f"getReserves failed for {pair}")
    reserve0, reserve1 = _parse_reserve_output(output)
    meta = {
        "source": "getReserves",
        "pair": pair,
        "token_in_index": token_in_index,
        "command": command.replace(rpc_url, "<rpc_url>"),
        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
    }
    if token_in_index == 0:
        return reserve0, reserve1, meta
    return reserve1, reserve0, meta


def _usd_value(value_raw: int, decimals: int, price_usd: object | None) -> str | None:
    if price_usd is None:
        return None
    units = Decimal(value_raw) / (Decimal(10) ** decimals)
    return _decimal_string(units * _decimal_from_value(price_usd, "0"))


def _amm_sensitivity_multipliers(args: dict) -> list[Decimal]:
    values = args.get("sensitivity_multipliers")
    if values is None:
        values = ["0.25", "0.5", "1", "2"]
    multipliers = []
    seen = set()
    for value in _require_list(values, "sensitivity_multipliers"):
        multiplier = _decimal_from_value(value, "1")
        if multiplier <= 0:
            raise ValueError("sensitivity_multipliers must be positive")
        if multiplier > Decimal("100"):
            raise ValueError("sensitivity_multipliers must not exceed 100")
        key = _decimal_string(multiplier)
        if key in seen:
            continue
        seen.add(key)
        multipliers.append(multiplier)
        if len(multipliers) >= 12:
            break
    return multipliers


def _amm_route_sensitivity(estimates: list[dict], first_amount_in: int | None, args: dict) -> list[dict]:
    if not estimates or first_amount_in is None:
        return []
    token_in_decimals = int(estimates[0]["token_in_decimals"])
    token_out_decimals = int(estimates[-1]["token_out_decimals"])
    rows = []
    for multiplier in _amm_sensitivity_multipliers(args):
        amount_in = int(Decimal(first_amount_in) * multiplier)
        if first_amount_in > 0 and amount_in == 0:
            amount_in = 1
        current_amount = amount_in
        leg_outputs = []
        for leg in estimates:
            amount_out = _amm_amount_out(
                amount_in=current_amount,
                reserve_in=int(leg["reserve_in_raw"]),
                reserve_out=int(leg["reserve_out_raw"]),
                fee_bps=int(leg["fee_bps"]),
            )
            leg_outputs.append({
                "index": leg["index"],
                "amount_in_raw": current_amount,
                "amount_out_raw": amount_out,
                "amount_out": _scaled_amount_string(
                    amount_out,
                    int(leg["token_out_decimals"]),
                ),
            })
            current_amount = amount_out
        rows.append({
            "multiplier": _decimal_string(multiplier),
            "amount_in_raw": amount_in,
            "amount_in": _scaled_amount_string(amount_in, token_in_decimals),
            "final_amount_out_raw": current_amount,
            "final_amount_out": _scaled_amount_string(current_amount, token_out_decimals),
            "legs": leg_outputs,
        })
    return rows


async def _estimate_amm_economics(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    try:
        pools = [
            _require_dict(item, "pools")
            for item in _require_list(args.get("pools"), "pools")
        ]
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"
    if not pools:
        return "Error: estimate_amm_economics requires at least one pool"

    fork_context = await _resolve_fork_context_arg(container, args.get("fork_context"))
    estimates = []
    previous_amount_out: int | None = None
    first_amount_in: int | None = None

    try:
        for index, pool in enumerate(pools, start=1):
            # Manual reserves need no RPC; an on-chain getReserves() lookup
            # resolves a chain-aware endpoint from the pair's registry binding or
            # explicit args, and never falls back to an implicit default chain.
            endpoint = None
            needs_onchain = (
                pool.get("reserve_in") is None or pool.get("reserve_out") is None
            )
            pair = _coerce_nonempty(pool.get("pair"))
            if needs_onchain and pair:
                endpoint = await _resolve_tool_rpc_endpoint(
                    container,
                    args,
                    fork_context=fork_context,
                    target_address=pair,
                    environ=environ,
                    config=config,
                )
                if endpoint.url is None:
                    return await _chain_unresolved_response(
                        container,
                        tool="estimate_amm_economics",
                        endpoint=endpoint,
                        addresses=[pair],
                        extra={
                            "pool": pool.get("label") or f"pool {index}",
                            "address": pair,
                        },
                    )
            reserve_in, reserve_out, reserve_meta = await _pool_reserves(
                container,
                pool,
                endpoint=endpoint,
            )
            token_in_decimals = _int_with_default(
                pool.get("token_in_decimals"),
                18,
            )
            token_out_decimals = _int_with_default(
                pool.get("token_out_decimals"),
                18,
            )
            amount_in = _raw_amount_from_pool(pool, previous_amount_out)
            if first_amount_in is None:
                first_amount_in = amount_in
            fee_bps = int(pool.get("fee_bps", 30) or 0)
            amount_out = _amm_amount_out(
                amount_in=amount_in,
                reserve_in=reserve_in,
                reserve_out=reserve_out,
                fee_bps=fee_bps,
            )
            previous_amount_out = amount_out
            price_before = _amm_price(
                reserve_in=reserve_in,
                reserve_out=reserve_out,
                token_in_decimals=token_in_decimals,
                token_out_decimals=token_out_decimals,
            )
            price_after_bps = _amm_price_change_bps(
                reserve_in=reserve_in,
                reserve_out=reserve_out,
                amount_in=amount_in,
                amount_out=amount_out,
                token_in_decimals=token_in_decimals,
                token_out_decimals=token_out_decimals,
            )
            leg = {
                "index": index,
                "label": pool.get("label") or f"pool {index}",
                "reserve_source": reserve_meta,
                "fee_bps": fee_bps,
                "token_in": pool.get("token_in_symbol") or "token_in",
                "token_out": pool.get("token_out_symbol") or "token_out",
                "token_in_decimals": token_in_decimals,
                "token_out_decimals": token_out_decimals,
                "reserve_in_raw": reserve_in,
                "reserve_out_raw": reserve_out,
                "reserve_in": _scaled_amount_string(reserve_in, token_in_decimals),
                "reserve_out": _scaled_amount_string(reserve_out, token_out_decimals),
                "amount_in_raw": amount_in,
                "amount_out_raw": amount_out,
                "amount_in": _scaled_amount_string(amount_in, token_in_decimals),
                "amount_out": _scaled_amount_string(amount_out, token_out_decimals),
                "spot_price_out_per_in": _decimal_string(price_before),
                "effective_price_out_per_in": _decimal_string(_amm_effective_price(
                    amount_in=amount_in,
                    amount_out=amount_out,
                    token_in_decimals=token_in_decimals,
                    token_out_decimals=token_out_decimals,
                )),
                "slippage_bps": _decimal_string(_amm_slippage_bps(
                    amount_in=amount_in,
                    amount_out=amount_out,
                    reserve_in=reserve_in,
                    reserve_out=reserve_out,
                )),
                "price_change_bps": _decimal_string(price_after_bps),
                "capital_usd": _usd_value(
                    amount_in,
                    token_in_decimals,
                    pool.get("token_in_price_usd"),
                ),
                "output_usd": _usd_value(
                    amount_out,
                    token_out_decimals,
                    pool.get("token_out_price_usd"),
                ),
            }
            if pool.get("target_price_decrease_bps") is not None:
                target = _target_price_decrease_amount(
                    reserve_in=reserve_in,
                    reserve_out=reserve_out,
                    target_bps=int(pool["target_price_decrease_bps"]),
                    fee_bps=fee_bps,
                    token_in_decimals=token_in_decimals,
                    token_out_decimals=token_out_decimals,
                )
                target["required_amount_in"] = _scaled_amount_string(
                    target["required_amount_in_raw"],
                    token_in_decimals,
                )
                target["estimated_amount_out"] = _scaled_amount_string(
                    target["estimated_amount_out_raw"],
                    token_out_decimals,
                )
                leg["target_price_decrease"] = target
            estimates.append(leg)
    except ValueError as exc:
        return f"Error: {exc}"

    try:
        route_sensitivity = _amm_route_sensitivity(estimates, first_amount_in, args)
    except ValueError as exc:
        return f"Error: {exc}"

    state = await _load_campaign_state(container)
    economics_id = _next_campaign_id(state, "economics")
    title = args.get("title", "").strip() or "AMM economics estimate"
    economics = {
        "id": economics_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "assumption": (
            "Constant-product AMM estimate. This ignores MEV, gas, oracle "
            "update rules, pool fees beyond fee_bps, transfer taxes, "
            "concentrated liquidity, and protocol-specific execution limits."
        ),
        "related_ids": [str(item) for item in related_ids],
        "summary": {
            "legs": len(estimates),
            "first_amount_in_raw": first_amount_in,
            "final_amount_out_raw": previous_amount_out,
            "first_amount_in": estimates[0]["amount_in"] if estimates else None,
            "final_amount_out": estimates[-1]["amount_out"] if estimates else None,
            "final_token": estimates[-1]["token_out"] if estimates else None,
            "sensitivity_points": len(route_sensitivity),
        },
        "legs": estimates,
        "route_sensitivity": route_sensitivity,
    }
    economics_path = f"/workspace/campaign/economics/{economics_id}.json"
    await container.write_file(
        economics_path,
        json.dumps(economics, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"AMM economics estimate: {title}",
            content=(
                f"Economics estimate: {economics_id}\n"
                f"Path: {economics_path}\n"
                f"Legs: {len(estimates)}\n"
                f"First input: {economics['summary']['first_amount_in']}\n"
                f"Final output: {economics['summary']['final_amount_out']} "
                f"{economics['summary']['final_token']}\n"
                f"Sensitivity points: {len(route_sensitivity)}"
            ),
            evidence=[economics_path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "economics_id": economics_id,
        "path": economics_path,
        "result_id": result_id or None,
        "summary": economics["summary"],
        "legs": estimates,
        "route_sensitivity": route_sensitivity,
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _ceil_div(numerator: int, denominator: int) -> int:
    return (numerator + denominator - 1) // denominator


def _asset_raw_amount(asset: dict, raw_key: str, decimal_key: str, decimals: int) -> int:
    if asset.get(raw_key) is not None:
        amount = int(str(asset[raw_key]), 0)
        if amount < 0:
            raise ValueError(f"{raw_key} must be non-negative")
        return amount
    if asset.get(decimal_key) is not None:
        amount = _decimal_to_raw_amount(asset[decimal_key], decimals)
        if amount < 0:
            raise ValueError(f"{decimal_key} must be non-negative")
        return amount
    raise ValueError(f"asset requires {raw_key} or {decimal_key}")


async def _asset_available_liquidity(
    container: AuditContainer,
    asset: dict,
    *,
    decimals: int,
    endpoint: ResolvedRpcEndpoint | None,
) -> tuple[int | None, dict]:
    if asset.get("available_liquidity") is not None:
        return int(str(asset["available_liquidity"]), 0), {"source": "manual"}
    if asset.get("available_liquidity_decimal") is not None:
        return _decimal_to_raw_amount(
            asset["available_liquidity_decimal"],
            decimals,
        ), {"source": "manual"}

    provider = str(asset.get("provider") or "").strip()
    if not provider:
        return None, {"source": "not_provided"}

    kind = str(asset.get("kind") or "erc20").strip().lower()
    if kind == "native":
        token = ""
    else:
        token = str(asset.get("asset") or "").strip()
        if not token:
            return None, {"source": "not_provided"}
    if endpoint is None or endpoint.url is None:
        raise ValueError("provider balance lookup requires a resolvable chain")
    rpc_url = endpoint.url
    rpc_arg = _cast_rpc_arg(rpc_url)
    if kind == "native":
        command = f"cast balance {shlex.quote(provider)}{rpc_arg}"
    else:
        command = (
            f"cast call {shlex.quote(token)} "
            f"{shlex.quote('balanceOf(address)(uint256)')} "
            f"{shlex.quote(provider)}{rpc_arg}"
        )
    exit_code, output = await container.exec(command, timeout=30)
    if exit_code != 0:
        raise ValueError(output.strip() or "liquidity lookup failed")
    value = _parse_int_value(output.strip())
    if value is None:
        raise ValueError(f"could not parse liquidity lookup output: {output.strip()}")
    return value, {
        "source": "cast",
        "kind": kind,
        "provider": provider,
        "command": command.replace(rpc_url, "<rpc_url>"),
        "rpc_endpoint": _rpc_endpoint_summary(endpoint),
    }


async def _estimate_flash_loan(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    try:
        assets = [
            _require_dict(item, "assets")
            for item in _require_list(args.get("assets"), "assets")
        ]
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"
    if not assets:
        return "Error: estimate_flash_loan requires at least one asset"

    fork_context = await _resolve_fork_context_arg(container, args.get("fork_context"))
    estimates = []
    total_fee_usd = Decimal(0)
    total_borrow_usd = Decimal(0)
    any_usd = False

    try:
        for index, asset in enumerate(assets, start=1):
            decimals = _int_with_default(asset.get("decimals"), 18)
            if decimals < 0 or decimals > 77:
                raise ValueError("asset decimals must be between 0 and 77")
            amount = _asset_raw_amount(asset, "amount", "amount_decimal", decimals)
            fee_bps = _int_with_default(asset.get("fee_bps"), 9)
            if fee_bps < 0 or fee_bps >= 10_000:
                raise ValueError("fee_bps must be between 0 and 9999")
            fee = _ceil_div(amount * fee_bps, 10_000)
            repayment = amount + fee

            # Manual liquidity needs no RPC; a provider/token balance lookup
            # resolves a chain-aware endpoint from the provider/token registry
            # binding or explicit args — never an implicit default chain.
            label = asset.get("label") or asset.get("symbol") or f"asset {index}"
            endpoint = None
            manual_liquidity = (
                asset.get("available_liquidity") is not None
                or asset.get("available_liquidity_decimal") is not None
            )
            provider = _coerce_nonempty(asset.get("provider"))
            kind = str(asset.get("kind") or "erc20").strip().lower()
            token = _coerce_nonempty(asset.get("asset"))
            will_lookup = (
                not manual_liquidity
                and bool(provider)
                and (kind == "native" or bool(token))
            )
            if will_lookup:
                lookup_targets = (
                    [provider] if kind == "native" else [token, provider]
                )
                endpoint = await _resolve_tool_rpc_endpoint(
                    container,
                    args,
                    fork_context=fork_context,
                    target_addresses=lookup_targets,
                    environ=environ,
                    config=config,
                )
                if endpoint.url is None:
                    return await _chain_unresolved_response(
                        container,
                        tool="estimate_flash_loan",
                        endpoint=endpoint,
                        addresses=lookup_targets,
                        extra={"asset": label, "provider": provider},
                    )
            available, liquidity_source = await _asset_available_liquidity(
                container,
                asset,
                decimals=decimals,
                endpoint=endpoint,
            )
            price_usd = asset.get("price_usd")
            amount_usd = _usd_value(amount, decimals, price_usd)
            fee_usd = _usd_value(fee, decimals, price_usd)
            repayment_usd = _usd_value(repayment, decimals, price_usd)
            if fee_usd is not None:
                any_usd = True
                total_fee_usd += _decimal_from_value(fee_usd, "0")
            if amount_usd is not None:
                total_borrow_usd += _decimal_from_value(amount_usd, "0")

            estimates.append({
                "index": index,
                "label": asset.get("label") or asset.get("symbol") or f"asset {index}",
                "symbol": asset.get("symbol") or "asset",
                "kind": asset.get("kind") or "erc20",
                "asset": asset.get("asset"),
                "provider": asset.get("provider"),
                "decimals": decimals,
                "fee_bps": fee_bps,
                "amount_raw": amount,
                "amount": _scaled_amount_string(amount, decimals),
                "fee_raw": fee,
                "fee": _scaled_amount_string(fee, decimals),
                "repayment_raw": repayment,
                "repayment": _scaled_amount_string(repayment, decimals),
                "available_liquidity_raw": available,
                "available_liquidity": (
                    _scaled_amount_string(available, decimals)
                    if available is not None
                    else None
                ),
                "liquidity_source": liquidity_source,
                "liquidity_sufficient": (
                    available >= amount if available is not None else None
                ),
                "amount_usd": amount_usd,
                "fee_usd": fee_usd,
                "repayment_usd": repayment_usd,
            })
    except ValueError as exc:
        return f"Error: {exc}"

    state = await _load_campaign_state(container)
    flash_id = _next_campaign_id(state, "flash_loan")
    title = args.get("title", "").strip() or "Flash-loan estimate"
    insufficient = [
        item for item in estimates if item.get("liquidity_sufficient") is False
    ]
    unknown = [
        item for item in estimates if item.get("liquidity_sufficient") is None
    ]
    estimate = {
        "id": flash_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "assumption": (
            "Flash-loan estimate based on provided fee_bps and liquidity "
            "assumptions or point-in-time provider balances. Validate actual "
            "provider interfaces, premiums, caps, callbacks, and repayment on fork."
        ),
        "related_ids": [str(item) for item in related_ids],
        "summary": {
            "assets": len(estimates),
            "insufficient_liquidity": len(insufficient),
            "unknown_liquidity": len(unknown),
            "total_borrow_usd": _decimal_string(total_borrow_usd) if any_usd else None,
            "total_fee_usd": _decimal_string(total_fee_usd) if any_usd else None,
        },
        "assets": estimates,
    }
    estimate_path = f"/workspace/campaign/economics/{flash_id}.json"
    await container.write_file(
        estimate_path,
        json.dumps(estimate, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Flash-loan estimate: {title}",
            content=(
                f"Flash-loan estimate: {flash_id}\n"
                f"Path: {estimate_path}\n"
                f"Assets: {len(estimates)}\n"
                f"Insufficient liquidity: {len(insufficient)}\n"
                f"Unknown liquidity: {len(unknown)}\n"
                f"Total fee USD: {estimate['summary']['total_fee_usd']}"
            ),
            evidence=[estimate_path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "flash_loan_id": flash_id,
        "path": estimate_path,
        "result_id": result_id or None,
        "summary": estimate["summary"],
        "assets": estimates,
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _bps_value(value: object, default: int = 0) -> int:
    bps = _int_with_default(value, default)
    if bps < -10_000 or bps > 100_000:
        raise ValueError("basis-point values must be between -10000 and 100000")
    return bps


def _apply_bps_shift(value: Decimal, bps: int) -> Decimal:
    shifted = value * (Decimal(10_000 + bps) / Decimal(10_000))
    return max(Decimal(0), shifted)


def _position_value_usd(
    position: dict,
    *,
    value_key: str,
    amount_key: str,
    decimal_key: str,
    decimals_key: str,
    price_key: str,
) -> tuple[Decimal, dict]:
    if position.get(value_key) is not None:
        value = _decimal_from_value(position.get(value_key), "0")
        if value < 0:
            raise ValueError(f"{value_key} must be non-negative")
        return value, {"source": "manual_value_usd", "value_usd": _decimal_string(value)}

    decimals = _int_with_default(position.get(decimals_key), 18)
    if decimals < 0 or decimals > 77:
        raise ValueError(f"{decimals_key} must be between 0 and 77")
    amount = _asset_raw_amount(position, amount_key, decimal_key, decimals)
    if position.get(price_key) is None:
        raise ValueError(f"position requires {price_key} or {value_key}")
    price = _decimal_from_value(position.get(price_key), "0")
    if price < 0:
        raise ValueError(f"{price_key} must be non-negative")
    units = Decimal(amount) / (Decimal(10) ** decimals)
    value = units * price
    return value, {
        "source": "amount_times_price",
        "amount_raw": amount,
        "amount": _scaled_amount_string(amount, decimals),
        "decimals": decimals,
        "price_usd": _decimal_string(price),
    }


def _estimate_lending_position(position: dict, index: int) -> dict:
    label = str(position.get("label") or f"position {index}")
    collateral_value, collateral_source = _position_value_usd(
        position,
        value_key="collateral_value_usd",
        amount_key="collateral_amount",
        decimal_key="collateral_amount_decimal",
        decimals_key="collateral_decimals",
        price_key="collateral_price_usd",
    )
    debt_value, debt_source = _position_value_usd(
        position,
        value_key="debt_value_usd",
        amount_key="debt_amount",
        decimal_key="debt_amount_decimal",
        decimals_key="debt_decimals",
        price_key="debt_price_usd",
    )
    threshold = position.get("liquidation_threshold_bps")
    if threshold is None:
        threshold = position.get("collateral_factor_bps")
    if threshold is None:
        raise ValueError(
            "position requires liquidation_threshold_bps or collateral_factor_bps"
        )
    threshold_bps = _bps_value(threshold)
    if threshold_bps <= 0 or threshold_bps > 10_000:
        raise ValueError("liquidation_threshold_bps must be between 1 and 10000")
    liquidation_bonus_bps = _bps_value(
        position.get("liquidation_bonus_bps"),
        0,
    )
    if liquidation_bonus_bps < 0:
        raise ValueError("liquidation_bonus_bps must be non-negative")

    collateral_shift_bps = _bps_value(position.get("collateral_price_shift_bps"), 0)
    debt_shift_bps = _bps_value(position.get("debt_price_shift_bps"), 0)
    shifted_collateral = _apply_bps_shift(collateral_value, collateral_shift_bps)
    shifted_debt = _apply_bps_shift(debt_value, debt_shift_bps)
    adjusted_collateral = shifted_collateral * Decimal(threshold_bps) / Decimal(10_000)

    if shifted_debt > 0:
        health_factor = adjusted_collateral / shifted_debt
        liquidatable = health_factor < 1
        shortfall = max(Decimal(0), shifted_debt - adjusted_collateral)
        extra_borrow_capacity = max(Decimal(0), adjusted_collateral - shifted_debt)
        if adjusted_collateral > shifted_debt:
            price_drop_to_liquidation_bps = (
                (Decimal(1) - (shifted_debt / adjusted_collateral)) * Decimal(10_000)
            )
        else:
            price_drop_to_liquidation_bps = Decimal(0)
    else:
        health_factor = None
        liquidatable = False
        shortfall = Decimal(0)
        extra_borrow_capacity = adjusted_collateral
        price_drop_to_liquidation_bps = None

    liquidation_bonus_value = (
        shifted_debt * Decimal(liquidation_bonus_bps) / Decimal(10_000)
    )
    return {
        "index": index,
        "label": label,
        "collateral": collateral_source,
        "debt": debt_source,
        "liquidation_threshold_bps": threshold_bps,
        "liquidation_bonus_bps": liquidation_bonus_bps,
        "price_shifts": {
            "collateral_price_shift_bps": collateral_shift_bps,
            "debt_price_shift_bps": debt_shift_bps,
        },
        "collateral_value_usd": _decimal_string(collateral_value),
        "debt_value_usd": _decimal_string(debt_value),
        "shifted_collateral_value_usd": _decimal_string(shifted_collateral),
        "shifted_debt_value_usd": _decimal_string(shifted_debt),
        "adjusted_collateral_value_usd": _decimal_string(adjusted_collateral),
        "health_factor": (
            _decimal_string(health_factor)
            if health_factor is not None else None
        ),
        "liquidatable": liquidatable,
        "shortfall_usd": _decimal_string(shortfall),
        "extra_borrow_capacity_usd": _decimal_string(extra_borrow_capacity),
        "price_drop_to_liquidation_bps": (
            _decimal_string(price_drop_to_liquidation_bps)
            if price_drop_to_liquidation_bps is not None else None
        ),
        "rough_liquidation_bonus_usd": _decimal_string(liquidation_bonus_value),
        "notes": [
            "Ignores close factor, isolation modes, eMode, caps, interest accrual, oracle windows, and liquidation gas.",
            "Validate protocol-specific liquidation math on fork before treating this as evidence.",
        ],
    }


def _lending_health_summary(positions: list[dict]) -> dict:
    total_adjusted = sum(
        (_decimal_from_value(item["adjusted_collateral_value_usd"], "0") for item in positions),
        Decimal(0),
    )
    total_debt = sum(
        (_decimal_from_value(item["shifted_debt_value_usd"], "0") for item in positions),
        Decimal(0),
    )
    total_collateral = sum(
        (_decimal_from_value(item["shifted_collateral_value_usd"], "0") for item in positions),
        Decimal(0),
    )
    total_shortfall = sum(
        (_decimal_from_value(item["shortfall_usd"], "0") for item in positions),
        Decimal(0),
    )
    health_values = [
        _decimal_from_value(item["health_factor"], "0")
        for item in positions
        if item.get("health_factor") is not None
    ]
    aggregate_health = total_adjusted / total_debt if total_debt > 0 else None
    return {
        "positions": len(positions),
        "liquidatable_positions": sum(1 for item in positions if item["liquidatable"]),
        "min_health_factor": (
            _decimal_string(min(health_values)) if health_values else None
        ),
        "aggregate_health_factor": (
            _decimal_string(aggregate_health)
            if aggregate_health is not None else None
        ),
        "total_collateral_value_usd": _decimal_string(total_collateral),
        "total_adjusted_collateral_value_usd": _decimal_string(total_adjusted),
        "total_debt_value_usd": _decimal_string(total_debt),
        "total_shortfall_usd": _decimal_string(total_shortfall),
    }


async def _estimate_lending_health(container: AuditContainer, args: dict) -> str:
    try:
        positions_arg = [
            _require_dict(item, "positions")
            for item in _require_list(args.get("positions"), "positions")
        ]
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"
    if not positions_arg:
        return "Error: estimate_lending_health requires at least one position"

    try:
        positions = [
            _estimate_lending_position(position, index)
            for index, position in enumerate(positions_arg, start=1)
        ]
    except ValueError as exc:
        return f"Error: {exc}"

    state = await _load_campaign_state(container)
    economics_id = _next_campaign_id(state, "economics")
    title = args.get("title", "").strip() or "Lending health estimate"
    summary = _lending_health_summary(positions)
    estimate = {
        "id": economics_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "assumption": (
            "Lending health-factor estimate from explicit collateral/debt, price, "
            "threshold, and price-shift assumptions. This is not a protocol "
            "simulator; validate close factors, oracle windows, interest, caps, "
            "and liquidation flows on fork."
        ),
        "related_ids": [str(item) for item in related_ids],
        "summary": summary,
        "positions": positions,
    }
    estimate_path = f"/workspace/campaign/economics/{economics_id}.json"
    await container.write_file(
        estimate_path,
        json.dumps(estimate, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Lending health estimate: {title}",
            content=(
                f"Lending health estimate: {economics_id}\n"
                f"Path: {estimate_path}\n"
                f"Positions: {summary['positions']}\n"
                f"Liquidatable positions: {summary['liquidatable_positions']}\n"
                f"Min health factor: {summary['min_health_factor']}\n"
                f"Total shortfall USD: {summary['total_shortfall_usd']}"
            ),
            evidence=[estimate_path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "economics_id": economics_id,
        "path": estimate_path,
        "result_id": result_id or None,
        "summary": summary,
        "positions": positions,
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _normalize_trace_path(path: str) -> str:
    normalized = posixpath.normpath(path.strip())
    if not normalized.startswith("/"):
        raise ValueError("trace path must be absolute")
    if not any(normalized.startswith(prefix) for prefix in _TRACE_ALLOWED_PREFIXES):
        raise ValueError(
            "trace path must be under /workspace/campaign/results/, "
            "/workspace/campaign/fuzz-runs/, /workspace/experiments/, "
            "/audit/, or /output/"
        )
    return normalized


async def _read_limited_container_file(
    container: AuditContainer,
    path: str,
    max_bytes: int = _TRACE_MAX_BYTES,
) -> tuple[str, dict]:
    safe_path = shlex.quote(path)
    exit_code, wc_out = await container.exec(f"wc -c < {safe_path} 2>&1", timeout=10)
    if exit_code != 0:
        raise FileNotFoundError(wc_out.strip() or path)

    try:
        size = int(wc_out.strip())
    except ValueError:
        size = 0

    if size <= max_bytes:
        return await container.read_file(path), {
            "bytes": size,
            "truncated": False,
        }

    half = max_bytes // 2
    _, head = await container.exec(f"head -c {half} {safe_path}", timeout=15)
    _, tail = await container.exec(f"tail -c {half} {safe_path}", timeout=15)
    marker = (
        f"\n\n... [trace input truncated: {size} bytes, "
        f"showing first and last {half}] ...\n\n"
    )
    return head + marker + tail, {
        "bytes": size,
        "truncated": True,
        "shown_bytes": len(head) + len(tail),
    }


def _trace_line_payload(line: str) -> str:
    return re.sub(r"^[\s│├└─]+", "", line).strip()


def _trace_depth(line: str) -> int:
    prefix = line[:len(line) - len(line.lstrip(" │├└─"))]
    return prefix.count("│") + prefix.count("├") + prefix.count("└")


def _summarize_trace_text(
    text: str,
    *,
    max_items: int = 25,
    source_meta: dict | None = None,
) -> dict:
    lines = text.splitlines()
    call_counts: dict[str, int] = {}
    target_counts: dict[str, int] = {}
    notable_calls = []
    reverts = []
    failures = []
    warnings = []
    events = []
    logs = []
    max_depth = 0
    call_total = 0
    suite_status = []

    call_re = re.compile(r"(?:\[\d+\]\s+)?([^:\s\[]+)::([A-Za-z_][A-Za-z0-9_.$<>]*)\(")
    event_re = re.compile(r"\b(?:emit\s+)?([A-Za-z_][A-Za-z0-9_]*)\(")
    notable_names = {
        "transfer",
        "transferfrom",
        "approve",
        "mint",
        "burn",
        "deposit",
        "withdraw",
        "redeem",
        "borrow",
        "repay",
        "liquidate",
        "swap",
        "flashloan",
        "donate",
        "bridge",
        "claim",
        "execute",
        "callback",
        "fallback",
    }

    for index, line in enumerate(lines, start=1):
        stripped = line.strip()
        payload = _trace_line_payload(line)
        lowered = stripped.lower()
        max_depth = max(max_depth, _trace_depth(line))

        if "suite result:" in lowered or re.search(r"\[(pass|fail)\]", lowered):
            suite_status.append({"line": index, "text": stripped[:300]})

        if "[revert]" in lowered or " revert" in lowered or " reverted" in lowered:
            if len(reverts) < max_items:
                reverts.append({"line": index, "text": stripped[:500]})

        if (
            "[fail" in lowered
            or "error:" in lowered
            or "panic" in lowered
            or "assertion failed" in lowered
        ):
            if len(failures) < max_items:
                failures.append({"line": index, "text": stripped[:500]})

        if "warning:" in lowered or "[warning]" in lowered:
            if len(warnings) < max_items:
                warnings.append({"line": index, "text": stripped[:500]})

        if "emit " in payload.lower() or "::emit" in lowered:
            match = event_re.search(payload)
            if match and len(events) < max_items:
                events.append({
                    "line": index,
                    "event": match.group(1),
                    "text": stripped[:500],
                })

        if stripped.startswith("Logs:") or stripped.startswith("console::log"):
            if len(logs) < max_items:
                logs.append({"line": index, "text": stripped[:500]})

        match = call_re.search(payload)
        if not match:
            continue
        target, function = match.group(1), match.group(2)
        if target == "VM":
            continue
        call_total += 1
        key = f"{target}::{function}"
        call_counts[key] = call_counts.get(key, 0) + 1
        target_counts[target] = target_counts.get(target, 0) + 1
        clean_fn = function.lower().replace("_", "")
        if (
            any(name in clean_fn for name in notable_names)
            and len(notable_calls) < max_items
        ):
            notable_calls.append({
                "line": index,
                "call": key,
                "text": stripped[:500],
            })

    top_calls = [
        {"call": call, "count": count}
        for call, count in sorted(
            call_counts.items(),
            key=lambda item: (-item[1], item[0]),
        )[:max_items]
    ]
    top_targets = [
        {"target": target, "count": count}
        for target, count in sorted(
            target_counts.items(),
            key=lambda item: (-item[1], item[0]),
        )[:max_items]
    ]

    return {
        "source": source_meta or {},
        "line_count": len(lines),
        "max_trace_depth": max_depth,
        "calls": {
            "total": call_total,
            "unique": len(call_counts),
            "top": top_calls,
            "top_targets": top_targets,
            "notable": notable_calls,
        },
        "events": events,
        "reverts": reverts,
        "failures": failures,
        "warnings": warnings,
        "logs": logs,
        "suite_status": suite_status[:max_items],
    }


async def _summarize_trace(container: AuditContainer, args: dict) -> str:
    raw_path = args.get("path", "").strip()
    if not raw_path:
        return "Error: 'path' is required"
    try:
        path = _normalize_trace_path(raw_path)
        related_ids = _require_list(args.get("related_ids"), "related_ids")
        text, source_meta = await _read_limited_container_file(container, path)
    except (FileNotFoundError, ValueError) as exc:
        return f"Error: {exc}"

    max_items = min(max(int(args.get("max_items", 25)), 1), 100)
    state = await _load_campaign_state(container)
    trace_id = _next_campaign_id(state, "trace")
    title = args.get("title", "").strip() or f"Trace summary for {path}"
    summary = _summarize_trace_text(
        text,
        max_items=max_items,
        source_meta={
            "path": path,
            **source_meta,
        },
    )
    summary["id"] = trace_id
    summary["title"] = title
    summary["created_at"] = datetime.now(timezone.utc).isoformat()
    summary["related_ids"] = [str(item) for item in related_ids]

    summary_path = f"/workspace/campaign/traces/{trace_id}.json"
    await container.write_file(
        summary_path,
        json.dumps(summary, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Trace summary: {title}",
            content=(
                f"Trace summary: {trace_id}\n"
                f"Source: {path}\n"
                f"Summary: {summary_path}\n"
                f"Calls: {summary['calls']['total']} total, "
                f"{summary['calls']['unique']} unique\n"
                f"Reverts: {len(summary['reverts'])}\n"
                f"Failures: {len(summary['failures'])}\n"
                f"Events captured: {len(summary['events'])}"
            ),
            evidence=[summary_path, path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "trace_id": trace_id,
        "path": summary_path,
        "result_id": result_id or None,
        "source": summary["source"],
        "calls": summary["calls"],
        "events": summary["events"],
        "reverts": summary["reverts"],
        "failures": summary["failures"],
        "warnings": summary["warnings"],
        "suite_status": summary["suite_status"],
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _is_allowed_action_source_path(path: str) -> bool:
    return any(
        path == prefix.rstrip("/") or path.startswith(prefix)
        for prefix in _ACTION_SOURCE_ALLOWED_PREFIXES
    )


def _normalize_action_source_path(path: str) -> str:
    value = (path or "/audit").strip()
    if not value:
        value = "/audit"
    if not value.startswith("/"):
        value = posixpath.join("/audit", value)
    normalized = posixpath.normpath(value)
    if not _is_allowed_action_source_path(normalized):
        raise ValueError(
            "action source paths must be under /audit or /workspace/experiments"
        )
    return normalized


def _allows_nested_profile_lib(path: str, roots: set[str]) -> bool:
    normalized = path if path.startswith("/") else f"/{path}"
    for root in roots:
        root = root.rstrip("/")
        if root and normalized.startswith(f"{root}/") and "/lib/" in normalized[len(root):]:
            return True
    return False


def _is_scoped_profile_source_root(path: str) -> bool:
    normalized = _normalize_action_source_path(path)
    parts = [part for part in normalized.split("/") if part]
    if len(parts) != 3 or parts[:2] != ["audit", "src"]:
        return False
    name = parts[2].lower()
    if name in _TOP_LEVEL_ARTIFACT_DIRS or name in {"lib", "script", "scripts", "test", "tests"}:
        return False
    return True


def _is_pruned_action_source(
    path: str,
    *,
    nested_profile_lib_roots: set[str] | None = None,
) -> bool:
    normalized = path if path.startswith("/") else f"/{path}"
    parts = [part for part in normalized.split("/") if part]
    if len(parts) >= 2 and parts[:2] == ["audit", "lib"]:
        return True
    nested_profile_lib_roots = nested_profile_lib_roots or set()
    allow_nested_lib = _allows_nested_profile_lib(
        normalized,
        nested_profile_lib_roots,
    )
    for part in _ACTION_SOURCE_PRUNE_PARTS:
        if part == "/lib/" and allow_nested_lib:
            continue
        if part in normalized:
            return True
    if len(parts) >= 2 and parts[0] == "audit":
        top = parts[1].lower()
        if (
            top in _TOP_LEVEL_ARTIFACT_DIRS
            or top.endswith("_poc")
            or top.endswith("-poc")
            or top.startswith("poc_")
            or top.startswith("poc-")
        ):
            return True
    return False


def _is_test_action_source(path: str) -> bool:
    lower = path.lower()
    return (
        any(part in lower for part in _ACTION_TEST_PARTS)
        or lower.endswith(_ACTION_TEST_SUFFIXES)
    )


def _is_third_party_action_source(path: str) -> bool:
    lower = path.lower()
    return any(
        marker in lower
        for marker in (
            "/contracts/external/",
            "/external/openzeppelin/",
            "/openzeppelin/",
            "/node_modules/",
            "/forge-std/",
            "/solmate/",
            "/solady/",
            "/prb-math/",
        )
    )


async def _manifest_source_scan_roots(
    container: AuditContainer,
    root: str,
    *,
    max_roots: int,
) -> list[str]:
    normalized = _normalize_action_source_path(root)
    if normalized not in {"/audit", "/audit/src"}:
        return []
    try:
        manifest_raw = await container.read_file(_SCOPE_MANIFEST_PATH)
        manifest = json.loads(manifest_raw)
    except (FileNotFoundError, json.JSONDecodeError):
        return []
    roots = []
    seen = set()
    for profile in manifest.get("ranked_profiles") or []:
        if not isinstance(profile, dict):
            continue
        src = str(profile.get("src") or "").strip()
        if not src:
            continue
        try:
            normalized_src = _normalize_action_source_path(src)
        except ValueError:
            continue
        if normalized_src in seen:
            continue
        seen.add(normalized_src)
        roots.append(normalized_src)
        if len(roots) >= max_roots:
            break
    return roots


async def _discover_action_source_files(
    container: AuditContainer,
    *,
    root: str,
    files: list | None,
    include_tests: bool,
    max_files: int,
    max_roots: int = 12,
) -> tuple[list[str], int]:
    nested_profile_lib_roots: set[str] = set()
    if files:
        candidates = []
        for item in files:
            if not isinstance(item, str) or not item.strip():
                raise ValueError("files entries must be non-empty strings")
            candidates.append(
                await _resolve_requested_action_source_path(
                    container,
                    root=root,
                    raw=item.strip(),
                )
            )
        for candidate in candidates:
            parts = [part for part in candidate.split("/") if part]
            if len(parts) >= 3 and parts[:2] == ["audit", "src"]:
                profile_root = "/" + "/".join(parts[:3])
                if _is_scoped_profile_source_root(profile_root):
                    nested_profile_lib_roots.add(profile_root)
    else:
        manifest_roots = await _manifest_source_scan_roots(
            container,
            root,
            max_roots=max(max_roots, 1),
        )
        scan_roots = manifest_roots
        if not scan_roots:
            scan_roots = await _default_source_scan_roots(container, root)
        for scan_root in scan_roots:
            normalized_root = _normalize_action_source_path(scan_root)
            if scan_root in manifest_roots or _is_scoped_profile_source_root(normalized_root):
                nested_profile_lib_roots.add(normalized_root)
        candidates = []
        for scan_root in scan_roots:
            safe_root = shlex.quote(scan_root)
            exit_code, output = await container.exec(
                f"find {safe_root} -type f -name '*.sol' | sort 2>&1",
                timeout=30,
            )
            if exit_code != 0:
                raise ValueError(output.strip() or f"could not scan {scan_root}")
            candidates.extend(
                _normalize_action_source_path(line.strip())
                for line in output.splitlines()
                if line.strip()
            )

    filtered = []
    seen = set()
    for candidate in candidates:
        if candidate in seen:
            continue
        seen.add(candidate)
        if not candidate.endswith(".sol"):
            continue
        if _is_pruned_action_source(
            candidate,
            nested_profile_lib_roots=nested_profile_lib_roots,
        ):
            continue
        if _is_third_party_action_source(candidate):
            continue
        if not include_tests and _is_test_action_source(candidate):
            continue
        filtered.append(candidate)

    return filtered[:max_files], max(0, len(filtered) - max_files)


def _requested_action_source_path_candidates(*, root: str, raw: str) -> list[str]:
    normalized_root = _normalize_action_source_path(root)
    raw = raw.strip()
    candidates = []

    def add(value: str) -> None:
        normalized = _normalize_action_source_path(value)
        if normalized not in candidates:
            candidates.append(normalized)

    if raw.startswith("/"):
        add(raw)
        if raw.startswith("/audit/src/src/"):
            add("/audit/src/" + raw[len("/audit/src/src/"):])
        return candidates

    rel = posixpath.normpath(raw)
    if rel in {".", ""}:
        add(normalized_root)
        return candidates
    while rel.startswith("../"):
        rel = rel[3:]
    rel = rel.lstrip("/")

    add(posixpath.join(normalized_root, rel))
    add(posixpath.join("/audit", rel))
    if rel.startswith("src/"):
        add(posixpath.join("/audit/src", rel[len("src/"):]))
    elif normalized_root == "/audit":
        add(posixpath.join("/audit/src", rel))
    return candidates


async def _action_source_path_exists(
    container: AuditContainer,
    path: str,
) -> bool:
    try:
        await container.read_file(path)
    except FileNotFoundError:
        return False
    return True


async def _resolve_requested_action_source_path(
    container: AuditContainer,
    *,
    root: str,
    raw: str,
) -> str:
    candidates = _requested_action_source_path_candidates(root=root, raw=raw)
    for candidate in candidates:
        if await _action_source_path_exists(container, candidate):
            return candidate
    return candidates[0]


async def _default_source_scan_roots(
    container: AuditContainer,
    root: str,
) -> list[str]:
    """Return source roots for broad scans without stale artifacts.

    Immunefi Instascope exports and similar bounty workspaces often contain
    prior findings, generated PoCs, build output, and dependency trees beside
    the real profile sources.  For a broad `/audit` scan, prefer `/audit/src`
    when it exists; explicit narrower paths are respected.
    """
    normalized = _normalize_action_source_path(root)
    if normalized != "/audit":
        return [normalized]
    exit_code, _ = await container.exec("[ -d /audit/src ]", timeout=5)
    if exit_code == 0:
        return ["/audit/src"]
    return [normalized]


def _line_starts(text: str) -> list[int]:
    starts = [0]
    starts.extend(match.end() for match in re.finditer("\n", text))
    return starts


def _line_at(starts: list[int], index: int) -> int:
    return bisect.bisect_right(starts, index)


def _find_matching_brace(text: str, open_index: int) -> int:
    depth = 0
    for index in range(open_index, len(text)):
        char = text[index]
        if char == "{":
            depth += 1
        elif char == "}":
            depth -= 1
            if depth == 0:
                return index
    return len(text) - 1


def _split_top_level_commas(value: str) -> list[str]:
    parts = []
    start = 0
    depth = 0
    pairs = {"(": ")", "[": "]", "{": "}"}
    closing = set(pairs.values())
    for index, char in enumerate(value):
        if char in pairs:
            depth += 1
        elif char in closing and depth:
            depth -= 1
        elif char == "," and depth == 0:
            part = value[start:index].strip()
            if part:
                parts.append(part)
            start = index + 1
    tail = value[start:].strip()
    if tail:
        parts.append(tail)
    return parts


def _parse_parameters(raw: str) -> list[dict]:
    """Parse a parameter list into ``[{raw, name, type}]`` records.

    ``type`` is the declared type portion of each parameter -- the cleaned text
    with only the trailing parameter name dropped (storage locations like
    ``memory``/``calldata`` stay part of the type). When no name is present the
    whole declaration is the type. ``raw``/``name`` are unchanged for backward
    compatibility.
    """
    parameters = []
    for part in _split_top_level_commas(raw):
        cleaned = " ".join(part.split())
        tokens = cleaned.split()
        name = ""
        type_text = cleaned
        if len(tokens) > 1:
            last = tokens[-1]
            if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", last):
                name = last
                type_text = " ".join(tokens[:-1])
        parameters.append({"raw": cleaned, "name": name, "type": type_text})
    return parameters


def _parameter_type_text(param: dict) -> str:
    """Explicit declared type for a parsed parameter dict.

    Prefers an existing ``type`` field; otherwise derives it from ``raw`` by
    dropping the trailing parameter name, so a record that only carries
    ``raw``/``name`` still yields a type. Returns ``""`` when nothing resolves.
    """
    if not isinstance(param, dict):
        return ""
    explicit = str(param.get("type") or "").strip()
    if explicit:
        return explicit
    raw = " ".join(str(param.get("raw") or "").split())
    name = str(param.get("name") or "").strip()
    if name and raw != name and raw.endswith(name):
        head = raw[: -len(name)].rstrip()
        if head:
            return head
    return raw


_ROUTER_POSITIONAL_ROLES: tuple[tuple[str, tuple[str, ...]], ...] = (
    (
        "swapExactTokensForTokens",
        ("amount_in", "min_output", "path", "recipient", "deadline"),
    ),
    (
        "swapExactTokensForETH",
        ("amount_in", "min_output", "path", "recipient", "deadline"),
    ),
    ("swapExactETHForTokens", ("min_output", "path", "recipient", "deadline")),
    (
        "swapTokensForExactTokens",
        ("amount_out", "max_input", "path", "recipient", "deadline"),
    ),
    (
        "swapTokensForExactETH",
        ("amount_out", "max_input", "path", "recipient", "deadline"),
    ),
    ("swapETHForExactTokens", ("amount_out", "path", "recipient", "deadline")),
)
_ROUTER_STRUCT_FIELD_ROLES = {
    "amountIn": "amount_in",
    "amountOut": "amount_out",
    "amountOutMinimum": "min_output",
    "amountOutMin": "min_output",
    "amountInMaximum": "max_input",
    "amountInMax": "max_input",
    "tokenIn": "token_in",
    "tokenOut": "token_out",
    "path": "path",
    "recipient": "recipient",
    "to": "recipient",
    "receiver": "recipient",
    "deadline": "deadline",
    "fee": "fee",
    "poolFee": "fee",
    "sqrtPriceLimitX96": "price_limit",
}
_ROUTER_ROLE_TERMS = {
    "amount_in": "amountIn",
    "amount_out": "amountOut",
    "min_output": "amountOutMinimum",
    "max_input": "amountInMaximum",
    "token_in": "tokenIn",
    "token_out": "tokenOut",
    "path": "path",
    "recipient": "recipient",
    "deadline": "deadline",
    "fee": "fee",
    "price_limit": "sqrtPriceLimitX96",
    "params": "params",
}


def _source_call_argument_text(line: str, target: str, selector: str) -> str:
    pattern = re.compile(
        rf"\b{re.escape(target)}\s*\.\s*{re.escape(selector)}\s*\(",
    )
    match = pattern.search(line)
    if not match:
        return ""
    open_index = line.find("(", match.start())
    if open_index < 0:
        return ""
    depth = 0
    for index in range(open_index, len(line)):
        char = line[index]
        if char == "(":
            depth += 1
        elif char == ")":
            depth -= 1
            if depth == 0:
                return line[open_index + 1:index].strip()
    return line[open_index + 1:].strip()


def _router_positional_roles(selector: str) -> tuple[str, ...]:
    lowered = selector.lower()
    for prefix, roles in _ROUTER_POSITIONAL_ROLES:
        if lowered.startswith(prefix.lower()):
            return roles
    if lowered.startswith("exactinputsingle"):
        return ("params",)
    if lowered.startswith("exactinput"):
        return ("params",)
    if lowered.startswith("exactoutputsingle"):
        return ("params",)
    if lowered.startswith("exactoutput"):
        return ("params",)
    return ()


def _router_struct_roles(args_text: str) -> dict[str, str]:
    roles = {}
    for match in re.finditer(
        r"\b([A-Za-z_][A-Za-z0-9_]*)\s*:\s*([^,}\n]+)",
        args_text,
    ):
        role = _ROUTER_STRUCT_FIELD_ROLES.get(match.group(1))
        value = " ".join(match.group(2).split())
        if role and value:
            roles[role] = value
    return roles


def _router_role_terms(roles: dict[str, str]) -> list[str]:
    terms = []
    for role, expression in roles.items():
        field = _ROUTER_ROLE_TERMS.get(role)
        if field:
            terms.append(field)
        if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", str(expression or "")):
            terms.append(str(expression))
    return _dedupe_text(terms)


def _router_validation_prompts(roles: dict[str, str], approval_spender: str) -> list[str]:
    prompts = []
    if approval_spender:
        prompts.append(
            f"confirm `{approval_spender}` is the approval spender for the input token"
        )
    if "path" in roles or {"token_in", "token_out"} & roles.keys():
        prompts.append("record concrete token path, token ordering, and pool/fee tier")
    if {"min_output", "max_input", "price_limit"} & roles.keys():
        prompts.append("assert slippage bounds and quoted output before executing the route")
    if "recipient" in roles:
        prompts.append(f"snapshot route recipient `{roles['recipient']}` before and after")
    if "deadline" in roles:
        prompts.append(f"prove deadline `{roles['deadline']}` is valid for the fork block")
    if "params" in roles:
        prompts.append("expand router params struct into token, amount, recipient, and slippage fields")
    return prompts


def _router_calldata_hint(
    *,
    line: str,
    target: str,
    selector: str,
) -> dict:
    args_text = _source_call_argument_text(line, target, selector)
    positional = _router_positional_roles(selector)
    roles = {}
    if args_text:
        args = _split_top_level_commas(args_text)
        for index, role in enumerate(positional):
            if index < len(args) and args[index]:
                roles[role] = args[index]
        roles.update(_router_struct_roles(args_text))
    approval_spender = target if target and target not in {"msg", "block", "tx", "super", "this"} else ""
    hint = {}
    if roles:
        hint["calldata_roles"] = roles
        hint["path_terms"] = _router_role_terms(roles)
    if approval_spender:
        hint["approval_spender"] = approval_spender
    prompts = _router_validation_prompts(roles, approval_spender)
    if prompts:
        hint["validation_prompts"] = prompts
    return hint


def _strip_comments_preserve_layout(source: str) -> str:
    """Remove Solidity comments while preserving byte offsets and newlines."""
    chars = list(source)
    index = 0
    in_string: str | None = None
    escaped = False
    while index < len(chars):
        ch = chars[index]
        nxt = chars[index + 1] if index + 1 < len(chars) else ""
        if in_string:
            if escaped:
                escaped = False
            elif ch == "\\":
                escaped = True
            elif ch == in_string:
                in_string = None
            index += 1
            continue
        if ch in {"'", '"'}:
            in_string = ch
            index += 1
            continue
        if ch == "/" and nxt == "/":
            chars[index] = " "
            chars[index + 1] = " "
            index += 2
            while index < len(chars) and chars[index] not in "\r\n":
                chars[index] = " "
                index += 1
            continue
        if ch == "/" and nxt == "*":
            chars[index] = " "
            chars[index + 1] = " "
            index += 2
            while index < len(chars) - 1:
                if chars[index] == "*" and chars[index + 1] == "/":
                    chars[index] = " "
                    chars[index + 1] = " "
                    index += 2
                    break
                if chars[index] not in "\r\n":
                    chars[index] = " "
                index += 1
            continue
        index += 1
    return "".join(chars)


def _contract_ranges(source: str, starts: list[int]) -> list[dict]:
    contracts = []
    scan_source = _strip_comments_preserve_layout(source)
    pattern = re.compile(
        r"\b(contract|interface|library)\s+([A-Za-z_][A-Za-z0-9_]*)\b(?P<header>[^{};]*)\{"
    )
    for match in pattern.finditer(scan_source):
        open_index = scan_source.find("{", match.start(), match.end())
        if open_index == -1:
            continue
        close_index = _find_matching_brace(scan_source, open_index)
        header = str(match.group("header") or "")
        bases = []
        inheritance_match = re.search(r"\bis\b(?P<bases>.*)$", header, flags=re.DOTALL)
        if inheritance_match:
            for part in _split_top_level_commas(inheritance_match.group("bases")):
                base_match = re.match(r"\s*([A-Za-z_][A-Za-z0-9_\.]*)", part)
                if base_match:
                    bases.append(base_match.group(1).split(".")[-1])
        contracts.append({
            "kind": match.group(1),
            "name": match.group(2),
            "bases": _dedupe_text(bases),
            "start": open_index + 1,
            "end": close_index,
            "line": _line_at(starts, match.start()),
        })
    if contracts:
        return contracts
    return [{
        "kind": "source",
        "name": "Source",
        "bases": [],
        "start": 0,
        "end": len(source),
        "line": 1,
    }]


def _extract_modifiers(tail: str) -> list[str]:
    cleaned = re.sub(r"\breturns\s*\([^)]*\)", " ", tail, flags=re.DOTALL)
    cleaned = re.sub(r"\boverride\s*(\([^)]*\))?", " ", cleaned, flags=re.DOTALL)
    skip = {
        "public",
        "external",
        "internal",
        "private",
        "view",
        "pure",
        "payable",
        "virtual",
        "returns",
    }
    modifiers = []
    for match in re.finditer(r"\b([A-Za-z_][A-Za-z0-9_]*)\b(?:\s*\([^)]*\))?", cleaned):
        name = match.group(1)
        if name.lower() not in skip and name not in modifiers:
            modifiers.append(name)
    return modifiers


def _extract_returns(tail: str) -> str:
    match = re.search(r"\breturns\s*\((.*?)\)", tail, flags=re.DOTALL)
    if not match:
        return ""
    return " ".join(match.group(1).split())


_ACTION_HINT_GROUPS = (
    "value_flows",
    "external_calls",
    "role_gates",
    "events",
    "state_mutations",
    "oracle_reads",
    "router_calls",
    "bridge_messages",
    "callback_surfaces",
    "authorization_checks",
    "cross_contract_calls",
    "economic_parameters",
)


def _empty_action_hints() -> dict[str, list]:
    return {key: [] for key in _ACTION_HINT_GROUPS}


def _collect_line_hints(
    body: str,
    *,
    body_offset: int,
    line_starts: list[int],
    max_items: int,
) -> dict:
    hints = _empty_action_hints()
    patterns = {
        "value_flows": re.compile(
            r"\b("
            r"safeTransferFrom|transferFrom|safeTransfer|transfer|mint|burn|"
            r"approve|deposit|withdraw|redeem|borrow|repay|liquidate|swap"
            r")\b|\.call\s*\{|value\s*:",
            re.IGNORECASE,
        ),
        "external_calls": re.compile(
            r"\.(call|delegatecall|staticcall)\b|"
            r"\bI[A-Za-z0-9_]+\s*\([^;]*\)\.",
            re.IGNORECASE,
        ),
        "oracle_reads": re.compile(
            r"\b("
            r"latestRoundData|getRoundData|getReserves|slot0|observe|consult|"
            r"getPrice|price|answer|decimals|twap"
            r")\b|oracle|priceFeed|aggregator",
            re.IGNORECASE,
        ),
        "router_calls": re.compile(
            r"\b(router|route|exactInput|exactOutput|swapExact|addLiquidity|"
            r"removeLiquidity|multicall)\b",
            re.IGNORECASE,
        ),
        "bridge_messages": re.compile(
            r"\b(bridge|message|sendMessage|receiveMessage|lzReceive|ccipReceive|"
            r"relay|proof|merkle|finalize|remote|xchain|crosschain)\b",
            re.IGNORECASE,
        ),
        "callback_surfaces": re.compile(
            r"\b(onERC\d+Received|tokensReceived|uniswapV\d+Call|pancakeCall|"
            r"flashLoan|receiveFlashLoan|executeOperation|callback)\b",
            re.IGNORECASE,
        ),
        "authorization_checks": re.compile(
            r"\b(ecrecover|ECDSA|isValidSignature|permit|signature|nonce|"
            r"deadline|domainSeparator|hasRole|_checkRole|isAuthorized|"
            r"msg\.sender|onlyOwner|owner\(\))\b",
            re.IGNORECASE,
        ),
        "cross_contract_calls": re.compile(
            r"\b[A-Za-z_][A-Za-z0-9_]*\s*\([^;{}]*\)\.|"
            r"\b[A-Za-z_][A-Za-z0-9_]*\s*\.",
            re.IGNORECASE,
        ),
        "economic_parameters": re.compile(
            r"\b([A-Za-z_][A-Za-z0-9_]*(?:close|factor|liquidation|bonus|"
            r"fee|premium|heartbeat|stale|twap|window|threshold|deviation|ltv)"
            r"[A-Za-z0-9_]*)\b",
            re.IGNORECASE,
        ),
        "events": re.compile(r"\bemit\s+([A-Za-z_][A-Za-z0-9_]*)", re.IGNORECASE),
        "state_mutations": re.compile(
            r"\b([A-Za-z_][A-Za-z0-9_]*(?:\s*\[[^\]]+\])?)\s*"
            # (?!=) keeps an `==` comparison from being read as a write to its
            # left operand, matching the structural-affordance regexes above.
            # (`<=`/`>=`/`!=` already fail: the char before `=` breaks the match.)
            r"(?:\+\+|--|[+\-*/]?=)(?!=)",
            re.IGNORECASE,
        ),
    }
    direct_role_gate_re = re.compile(
        r"\b(hasRole|_checkRole|onlyOwner|isAuthorized|guardian|keeper|admin)\b",
        re.IGNORECASE,
    )
    sender_guard_re = re.compile(
        r"\b(require|assert|if|revert)\b.*\b(msg\.sender|owner\(\))\b|"
        r"\b(msg\.sender|owner\(\))\b.*\b(require|assert|if|revert)\b",
        re.IGNORECASE,
    )
    for offset, line in enumerate(body.splitlines()):
        stripped = line.strip()
        if not stripped:
            continue
        line_number = _line_at(line_starts, body_offset) + offset
        for name, pattern in patterns.items():
            if len(hints[name]) >= max_items:
                continue
            match = pattern.search(stripped)
            if match:
                entry = {"line": line_number, "text": stripped[:300]}
                if name == "events" and match.groups():
                    entry["event"] = match.group(1)
                if name == "state_mutations" and match.groups():
                    entry["target"] = " ".join(match.group(1).split())
                if name == "economic_parameters" and match.groups():
                    entry["parameter"] = " ".join(match.group(1).split())
                    value_match = re.search(
                        r"(?:=|return)\s*([0-9_]+|[A-Za-z_][A-Za-z0-9_]*)",
                        stripped,
                    )
                    if value_match:
                        entry["value_hint"] = value_match.group(1)
                if name == "callback_surfaces" and match.groups():
                    entry["surface"] = match.group(1)
                    selector_match = re.search(
                        r"keccak256\s*\(\s*['\"]([^'\"]+)['\"]\s*\)",
                        stripped,
                    )
                    if selector_match:
                        entry["selector_hint"] = selector_match.group(1)
                if name == "router_calls":
                    if match.groups():
                        entry["matched_term"] = match.group(1)
                    target_match = re.search(
                        r"\b([A-Za-z_][A-Za-z0-9_]*)\s*\.\s*([A-Za-z_][A-Za-z0-9_]*)\s*\(",
                        stripped,
                    )
                    if target_match:
                        target = target_match.group(1)
                        if target not in {"msg", "block", "tx", "super", "this"}:
                            entry["target"] = target
                            entry["selector_hint"] = target_match.group(2)
                            entry.update(_router_calldata_hint(
                                line=stripped,
                                target=target,
                                selector=target_match.group(2),
                            ))
                    path_terms = [
                        term
                        for term in (
                            "path",
                            "tokenIn",
                            "tokenOut",
                            "amountIn",
                            "amountOut",
                            "amountOutMinimum",
                            "amountOutMin",
                            "amountInMaximum",
                            "amountInMax",
                            "deadline",
                            "recipient",
                            "to",
                            "receiver",
                            "fee",
                            "poolFee",
                            "sqrtPriceLimitX96",
                        )
                        if re.search(rf"\b{term}\b", stripped, flags=re.IGNORECASE)
                    ]
                    path_terms.extend(entry.get("path_terms") or [])
                    if path_terms:
                        entry["path_terms"] = _dedupe_text(path_terms)
                if name == "cross_contract_calls":
                    target_match = re.search(
                        r"\b([A-Za-z_][A-Za-z0-9_]*)\s*\.",
                        stripped,
                    )
                    if target_match:
                        target = target_match.group(1)
                        if target in {"msg", "block", "tx", "super", "this"}:
                            continue
                        entry["target"] = target
                hints[name].append(entry)
        if (
            len(hints["role_gates"]) < max_items
            and (direct_role_gate_re.search(stripped) or sender_guard_re.search(stripped))
        ):
            hints["role_gates"].append({
                "line": line_number,
                "text": stripped[:300],
            })
        if (
            len(hints["authorization_checks"]) < max_items
            and (direct_role_gate_re.search(stripped) or sender_guard_re.search(stripped))
        ):
            hints["authorization_checks"].append({
                "line": line_number,
                "text": stripped[:300],
            })
    return hints


def _action_affordances(
    *,
    name: str,
    visibility: str,
    mutability: str,
    modifiers: list[str],
    body: str,
) -> list[str]:
    labels = set()
    haystack = f"{name} {' '.join(modifiers)} {body}".lower()
    name_l = name.lower()
    modifiers_l = " ".join(modifiers).lower()

    if visibility in {"public", "external"} and mutability not in {"view", "pure"}:
        labels.add("state_changing_entrypoint")
    if mutability in {"view", "pure"}:
        labels.add("observation")
    if mutability == "payable" or "msg.value" in haystack:
        labels.add("accepts_native_value")
    if any(word in name_l for word in ("deposit", "supply", "stake", "mint", "wrap")):
        labels.add("value_in_or_mint")
    if any(word in name_l for word in ("withdraw", "redeem", "claim", "unstake", "burn")):
        labels.add("value_out_or_burn")
    if any(word in name_l for word in ("borrow", "repay", "liquidat", "debt", "collateral")):
        labels.add("credit_or_liquidation")
    if any(word in name_l for word in ("swap", "trade", "route", "quote")) or any(
        word in haystack
        for word in ("router", "exactinput", "exactoutput", "swapexact", "route")
    ):
        labels.add("market_or_router")
    if any(word in name_l for word in ("bridge", "message", "relay", "send", "receive")) or any(
        word in haystack
        for word in ("bridge", "message", "lzreceive", "ccipreceive", "relay", "proof")
    ):
        labels.add("cross_domain_or_message")
    if any(word in name_l for word in ("execute", "multicall", "call", "delegate")):
        labels.add("generic_execution")
    if any(
        word in haystack
        for word in (
            "permit",
            "signature",
            "sig ",
            "sig,",
            "digest",
            "signed",
            "order",
            "deadline",
            "nonce",
        )
    ):
        labels.add("signature_input")
        labels.add("signed_authorization")
    if any(
        word in haystack
        for word in (
            "ecrecover",
            "ecdsa",
            "isvalidsignature",
            "domainseparator",
            "_hashtypeddata",
            "nonces",
            ".recover",
        )
    ):
        labels.add("signature_gate")
        labels.add("signed_authorization")
    if any(word in haystack for word in ("oracle", "price", "twap", "answer", "feed")):
        labels.add("valuation_dependency")
    if any(
        word in haystack
        for word in (
            "transferfrom",
            "safetransferfrom",
            "transfer(",
            "safetransfer(",
            ".call{",
            "value:",
        )
    ):
        labels.add("token_or_native_transfer")
    if ".delegatecall" in haystack:
        labels.add("delegatecall")
    if ".call" in haystack or ".staticcall" in haystack:
        labels.add("external_call")
    if any(word in modifiers_l for word in ("only", "role", "owner", "auth", "admin")):
        labels.add("modifier_gated")
    if (
        any(word in haystack for word in ("hasrole", "_checkrole", "isauthorized"))
        or re.search(r"\b(require|assert|if|revert)\b.*msg\.sender", haystack)
    ):
        labels.add("sender_or_role_checked")
    if "nonreentrant" in modifiers_l:
        labels.add("reentrancy_guarded")
    if any(word in haystack for word in ("flashloan", "callback", "uniswapv", "onerc")):
        labels.add("callback_or_flashloan_surface")
    if any(word in haystack for word in ("pause", "paused", "guardian")):
        labels.add("pause_or_guardian_state")
    if any(word in name_l for word in ("set", "update", "config", "admin", "owner", "role")):
        labels.add("configuration")

    return sorted(labels)


# ── Delexicalized structural affordances ─────────────────────────────────
#
# `_action_affordances` (above) is lexical: it keys off names and body
# substrings such as deposit/withdraw/oracle/swap. That signal is useful but it
# under-ranks novel or adversarially renamed code. `_structural_action_
# affordances` adds labels derived from the *shape* of the source — indexed vs
# aggregate state writes, boundary-crossing calls, dynamic dispatch,
# value-carrying calls, division/rounding, batch loops, inline authorization
# conditions, lifecycle/state-machine writes — so map_action_space and coverage
# still surface risky structure when identifiers carry no known vulnerability
# vocabulary. Detection is intentionally conservative (regex/hint based) and the
# labels are prioritization/context only: the submission gates never consult
# them and no finding is ever derived from a structural affordance.

# A write to an *indexed* lvalue (mapping/array): `balances[msg.sender] = `,
# `positions[id].amount += `, `m[a][b] -= `. The greedy `[^;\n]*` spans nested
# index brackets within one statement; the trailing `(?!=)` keeps comparisons
# (`==`, `<=`, `>=`, `!=`) out.
_STRUCT_INDEXED_WRITE_RE = re.compile(
    r"[A-Za-z_]\w*\s*\[[^;\n]*\]\s*(?:\.\s*\w+\s*)*(?:\+\+|--|[+\-*/%|&^]?=)(?!=)"
)
# A compound assignment (`+= -= *= /=`) to a *non-indexed* lvalue: an
# accumulator / running-total update such as `x += amount` or
# `pool.reserve -= amount`. The leading negative lookbehind keeps indexed writes
# (handled above) and member tails from double-starting here.
_STRUCT_AGGREGATE_WRITE_RE = re.compile(
    r"(?<![\]\w.])[A-Za-z_]\w*(?:\s*\.\s*\w+)*\s*(?:\+=|-=|\*=|/=)(?!=)"
)
# Aggregate-vocabulary write (secondary to the structural compound write above):
# a write to a total-like running quantity even when spelled with a plain `=`.
_STRUCT_AGGREGATE_NAME_RE = re.compile(
    r"\b\w*(?:total|aggregate|cumulative|accumulat|supply|reserve|outstanding)"
    r"\w*\s*(?:\[[^;\n]*\]\s*)?(?:\.\s*\w+\s*)*(?:\+\+|--|[+\-*/]?=)(?!=)",
    re.IGNORECASE,
)
# A method call on another object (`recv.method(...)` / `recv.method{...}(...)`).
_STRUCT_MEMBER_CALL_RE = re.compile(
    r"\b([A-Za-z_]\w*)\s*\.\s*([A-Za-z_]\w*)\s*(?:\{[^}]*\})?\s*\("
)
# Receivers that are language builtins or value-type casts (not external
# contracts) and methods that are array/storage builtins (not boundary calls).
_STRUCT_MEMBER_CALL_SKIP = frozenset({
    "msg", "block", "tx", "abi", "this", "super", "type",
    "address", "string", "bytes", "uint", "int", "bool", "byte",
})
_STRUCT_MEMBER_METHOD_SKIP = frozenset({"push", "pop"})
_STRUCT_LOW_LEVEL_CALL_RE = re.compile(r"\.\s*(?:call|delegatecall|staticcall)\b")
_STRUCT_FUNCTION_CALL_LIB_RE = re.compile(
    r"\bfunction(?:Call|StaticCall|DelegateCall|CallWithValue)\b"
)
# `.call{value: ...}(...)` / `.foo{value: ...}(...)` — native value forwarded
# through a low-level call option block.
_STRUCT_CALL_VALUE_RE = re.compile(r"\.\s*\w+\s*\{[^}]*\bvalue\s*:")
# Single-argument `.transfer(...)` / `.send(...)` — the native value send form.
# An ERC-20 token transfer takes two args, so a comma-free argument list
# discriminates the native form structurally without leaning on token names.
_STRUCT_NATIVE_SEND_RE = re.compile(r"\.\s*(?:transfer|send)\s*\(\s*[^,(){}]*\)")
# Binary division / modulo between operands. `//` line comments and the `/=`
# compound form are handled separately so they do not trip this one.
_STRUCT_DIVISION_RE = re.compile(r"[\w)\]]\s*/\s*[\w(]|[\w)\]]\s*%\s*[\w(]")
_STRUCT_ARITH_VOCAB_RE = re.compile(
    r"\b(?:muldiv\w*|fullmuldiv|mulwad\w*|divwad\w*|wadmul|waddiv|raymul|raydiv|"
    r"fixedpoint\w*|rounding)\b",
    re.IGNORECASE,
)
_STRUCT_UNCHECKED_RE = re.compile(r"\bunchecked\s*\{")
_STRUCT_LOOP_RE = re.compile(r"\b(?:for|while)\s*\(")
_STRUCT_EMIT_RE = re.compile(r"\bemit\s+[A-Za-z_]\w*")
# A write to a lifecycle / state-machine variable (`status = `, `phase[id] = `)
# or an enum assignment (`= Status.Active`).
_STRUCT_LIFECYCLE_WRITE_RE = re.compile(
    r"\b\w*(?:status|state|phase|stage|paused|frozen|finali[sz]ed|"
    r"initiali[sz]ed|settled|cancell?ed|revoked|epoch|lifecycle)\w*"
    r"\s*(?:\[[^;\n]*\]\s*)?(?:\.\s*\w+\s*)*(?:\+\+|--|[+\-*/]?=)(?!=)",
    re.IGNORECASE,
)
_STRUCT_LIFECYCLE_TERM_RE = re.compile(
    r"(?:status|state|phase|stage|paused|frozen|finali[sz]ed|initiali[sz]ed|"
    r"settled|cancell?ed|revoked|lifecycle)",
    re.IGNORECASE,
)
_STRUCT_ENUM_ASSIGN_RE = re.compile(r"=\s*[A-Z]\w*\s*\.\s*[A-Z]\w*")
# A per-user / per-account indexed write: a balance, claim, credit, or
# obligation keyed by msg.sender, tx.origin, or a user-ish identifier.
_STRUCT_USER_KEY_TERMS = (
    "user", "account", "owner", "holder", "payer", "payee", "recipient",
    "beneficiary", "sender", "claimer", "staker", "depositor", "borrower",
    "operator", "spender", "receiver", "delegate", "subscriber",
)
_STRUCT_USER_KEY_RE = re.compile(
    r"\b\w+\s*\[[^;\n\]]*(?:msg\.sender|tx\.origin|\b(?:"
    + "|".join(_STRUCT_USER_KEY_TERMS)
    + r")\w*)[^;\n\]]*\]\s*(?:\[[^;\n]*\]\s*)*(?:\.\s*\w+\s*)*"
    r"(?:\+\+|--|[+\-*/]?=)(?!=)",
    re.IGNORECASE,
)


def _struct_has_member_call(body: str) -> bool:
    """True when `body` calls a method on another object (`recv.method(...)`).

    A precise boundary-crossing signal that, unlike the broad
    `cross_contract_calls` line hint, ignores plain struct/field reads (no call
    parens) and skips language builtins, value-type casts, and array push/pop.
    """
    for match in _STRUCT_MEMBER_CALL_RE.finditer(body):
        receiver, method = match.group(1), match.group(2)
        base = re.sub(r"\d+$", "", receiver)
        if receiver in _STRUCT_MEMBER_CALL_SKIP or base in _STRUCT_MEMBER_CALL_SKIP:
            continue
        if method in _STRUCT_MEMBER_METHOD_SKIP:
            continue
        return True
    return False


def _struct_param_is_call_target(body: str, parameters: list[dict]) -> bool:
    """True when a caller-supplied address parameter is the receiver of a call —
    i.e. the call destination is attacker-controlled (dynamic dispatch)."""
    for param in parameters:
        if not isinstance(param, dict):
            continue
        name = str(param.get("name") or "").strip()
        if not name or "address" not in _parameter_type_text(param).lower():
            continue
        if re.search(
            rf"\b{re.escape(name)}\s*\.\s*\w+\s*(?:\{{[^}}]*\}})?\s*\(", body
        ):
            return True
    return False


def _struct_call_result_checked(body: str) -> bool:
    """Heuristic used only to *suppress* `unchecked_external_boundary`: does the
    body contain any success/guard construct at all? Conservative — we would
    rather under-claim 'unchecked' than over-claim it."""
    return bool(
        re.search(r"\brequire\s*\(", body)
        or re.search(r"\brevert\b", body)
        or re.search(r"\bassert\s*\(", body)
        or re.search(r"\bif\s*\(", body)
    )


def _struct_has_array_param(parameters: list[dict]) -> bool:
    for param in parameters:
        if not isinstance(param, dict):
            continue
        if "[" in _parameter_type_text(param) or "[" in str(param.get("raw") or ""):
            return True
    return False


def _struct_has_lifecycle_change(body: str, hints: dict) -> bool:
    if _STRUCT_LIFECYCLE_WRITE_RE.search(body) or _STRUCT_ENUM_ASSIGN_RE.search(body):
        return True
    for event in hints.get("events") or []:
        if isinstance(event, dict) and _STRUCT_LIFECYCLE_TERM_RE.search(
            str(event.get("event") or "")
        ):
            return True
    return False


def _struct_has_user_keyed_write(body: str, parameters: list[dict]) -> bool:
    if _STRUCT_USER_KEY_RE.search(body):
        return True
    for param in parameters:
        if not isinstance(param, dict):
            continue
        name = str(param.get("name") or "").strip()
        if not name or "address" not in _parameter_type_text(param).lower():
            continue
        if re.search(
            rf"\b\w+\s*\[\s*{re.escape(name)}\s*\]\s*(?:\[[^;\n]*\]\s*)*"
            r"(?:\.\s*\w+\s*)*(?:\+\+|--|[+\-*/]?=)(?!=)",
            body,
        ):
            return True
    return False


def _structural_action_affordances(
    *,
    visibility: str,
    mutability: str,
    modifiers: list[str],
    body: str,
    hints: dict,
    parameters: list[dict],
    returns: str,
) -> list[str]:
    """Delexicalized structural affordances for one function unit.

    Labels are derived from source structure plus the already-collected line
    hints rather than known vulnerability vocabulary, so renamed or novel code
    still surfaces in map_action_space / coverage. Prioritization and context
    only — never a finding signal (see module note above). `modifiers` and
    `returns` are part of the unit shape and accepted for completeness so the
    merge site can pass a full unit without reshaping.
    """
    labels: set[str] = set()
    body = body or ""
    hints = hints if isinstance(hints, dict) else {}
    parameters = parameters or []
    is_entrypoint = visibility in {"public", "external"}
    is_mutating = mutability not in {"view", "pure"}

    # State writes.
    indexed_write = bool(_STRUCT_INDEXED_WRITE_RE.search(body))
    aggregate_write = bool(
        _STRUCT_AGGREGATE_WRITE_RE.search(body)
        or _STRUCT_AGGREGATE_NAME_RE.search(body)
    )
    lifecycle = _struct_has_lifecycle_change(body, hints)
    state_write = (
        indexed_write
        or aggregate_write
        or lifecycle
        or bool(hints.get("state_mutations"))
    )
    if indexed_write:
        labels.add("mapping_state_write")
    if aggregate_write:
        labels.add("aggregate_state_update")
    if lifecycle:
        labels.add("lifecycle_state_change")
    if _struct_has_user_keyed_write(body, parameters):
        labels.add("user_claim_or_obligation_update")

    # Boundary / call structure.
    low_level_call = bool(_STRUCT_LOW_LEVEL_CALL_RE.search(body))
    value_call = bool(
        _STRUCT_CALL_VALUE_RE.search(body) or _STRUCT_NATIVE_SEND_RE.search(body)
    )
    dynamic_target = (
        low_level_call
        or bool(_STRUCT_FUNCTION_CALL_LIB_RE.search(body))
        or _struct_param_is_call_target(body, parameters)
    )
    boundary = (
        value_call
        or dynamic_target
        or _struct_has_member_call(body)
        or bool(hints.get("external_calls"))
    )
    if value_call:
        labels.add("external_call_with_value")
    if dynamic_target:
        labels.add("dynamic_call_target")
    if boundary:
        labels.add("external_boundary_crossing")
        if low_level_call and not _struct_call_result_checked(body):
            labels.add("unchecked_external_boundary")

    # Arithmetic / rounding.
    if (
        _STRUCT_DIVISION_RE.search(body)
        or re.search(r"[/%]=(?!=)", body)
        or _STRUCT_ARITH_VOCAB_RE.search(body)
        or _STRUCT_UNCHECKED_RE.search(body)
    ):
        labels.add("arithmetic_rounding_or_division")

    # Batch / loop surface.
    if _STRUCT_LOOP_RE.search(body) or _struct_has_array_param(parameters):
        labels.add("batch_or_loop_surface")

    # Inline authorization condition. Use the `role_gates` hint (require/if/
    # revert + msg.sender/owner, or a role modifier/term) rather than the broad
    # `authorization_checks` hint, which fires on a bare `msg.sender` used only
    # as a mapping key and would false-positive on plain per-user accounting.
    if hints.get("role_gates"):
        labels.add("authorization_condition")

    # An emitted event that documents a state transition.
    if _STRUCT_EMIT_RE.search(body) and state_write:
        labels.add("emits_state_transition_event")

    # Reachable, state-mutating entrypoint roll-up.
    if is_entrypoint and is_mutating and state_write:
        labels.add("state_mutating_entrypoint")

    return sorted(labels)


# Declaration patterns shared by the action-space parser and source_slice so
# "what counts as a function declaration" has a single source of truth. Run them
# over a comment-stripped contract block (see `_strip_comments_preserve_layout`).
_FUNCTION_DECL_RE = re.compile(
    r"\bfunction\s+([A-Za-z_][A-Za-z0-9_]*)\s*"
    r"\((.*?)\)([^{};]*)([{;])",
    flags=re.DOTALL,
)
_SPECIAL_FUNCTION_DECL_RE = re.compile(
    r"\b(receive|fallback)\s*\((.*?)\)([^{};]*)([{;])",
    flags=re.DOTALL,
)


def _function_unit_from_match(
    match: "re.Match",
    *,
    contract: dict,
    source: str,
    line_starts: list[int],
    max_items: int,
) -> dict:
    """Parse one ``function`` / ``receive`` / ``fallback`` declaration into a unit.

    ``match`` must come from ``_FUNCTION_DECL_RE`` / ``_SPECIAL_FUNCTION_DECL_RE``
    run over the comment-stripped contract block; ``source`` is the original
    (un-stripped) file text and ``contract`` a ``_contract_ranges`` entry. Shared
    by ``_parse_action_space_file`` (action-space mapping) and
    ``_iter_function_units`` (source_slice) so the visibility / mutability /
    modifier / parameter extraction and the affordance + line-hint heuristics
    live in exactly one place. Returns the parsed fields plus the brace-matched
    ``[line, end_line]`` span. ``visibility`` is the source-declared value or
    ``"unspecified"`` (the regex parser's convention); membership in
    ``{"public", "external"}`` is preserved either way.
    """
    name = match.group(1)
    parameters_raw = match.group(2)
    tail = match.group(3)
    terminator = match.group(4)
    absolute_start = contract["start"] + match.start()
    line = _line_at(line_starts, absolute_start)
    visibility_match = re.search(r"\b(public|external|internal|private)\b", tail)
    visibility = visibility_match.group(1) if visibility_match else ""
    if not visibility and contract["kind"] == "interface":
        visibility = "external"
    if name in {"receive", "fallback"} and not visibility:
        visibility = "external"
    mutability = "nonpayable"
    for candidate in ("view", "pure", "payable"):
        if re.search(rf"\b{candidate}\b", tail):
            mutability = candidate
            break
    modifiers = _extract_modifiers(tail)
    body = ""
    body_offset = contract["start"] + match.end() - 1
    end_line = line
    if terminator == "{":
        open_index = body_offset
        close_index = _find_matching_brace(source, open_index)
        body = source[open_index:close_index + 1]
        end_line = _line_at(line_starts, close_index)
    hints = _collect_line_hints(
        body,
        body_offset=body_offset,
        line_starts=line_starts,
        max_items=max_items,
    )
    parameters = _parse_parameters(parameters_raw)
    returns = _extract_returns(tail)
    affordances = _action_affordances(
        name=name,
        visibility=visibility,
        mutability=mutability,
        modifiers=modifiers,
        body=body,
    )
    # Merge delexicalized structural labels so renamed/novel code still surfaces
    # even when the lexical heuristics above match nothing (see
    # `_structural_action_affordances`).
    structural = _structural_action_affordances(
        visibility=visibility,
        mutability=mutability,
        modifiers=modifiers,
        body=body,
        hints=hints,
        parameters=parameters,
        returns=returns,
    )
    affordances = sorted(set(affordances).union(structural))
    return {
        "contract": contract["name"],
        "contract_kind": contract["kind"],
        "function": name,
        "line": line,
        "end_line": end_line,
        "visibility": visibility or "unspecified",
        "mutability": mutability,
        "parameters": parameters,
        "returns": returns,
        "modifiers": modifiers,
        "affordances": affordances,
        "hints": hints,
    }


def _parse_action_space_file(
    path: str,
    source: str,
    *,
    max_items: int,
) -> dict:
    if len(source) > _ACTION_MAX_FILE_CHARS:
        source = source[:_ACTION_MAX_FILE_CHARS]
        truncated = True
    else:
        truncated = False

    starts = _line_starts(source)
    contracts = []
    actions = []
    observations = []
    modifiers_seen = []
    event_declarations = []
    global_hints = _empty_action_hints()
    scan_source = _strip_comments_preserve_layout(source)

    public_var_pattern = re.compile(
        r"^\s*(?!function\b)(?!event\b)(?!modifier\b)"
        r"(.+?)\s+public\s+([A-Za-z_][A-Za-z0-9_]*)\s*(?:=|;)",
        flags=re.MULTILINE,
    )

    for contract in _contract_ranges(source, starts):
        block_scan = scan_source[contract["start"]:contract["end"]]
        contract_info = {
            "name": contract["name"],
            "kind": contract["kind"],
            "bases": contract.get("bases") or [],
            "file": path,
            "line": contract["line"],
            "actions": 0,
            "observations": 0,
            "modifiers": [],
            "events": [],
        }

        for match in re.finditer(r"\bmodifier\s+([A-Za-z_][A-Za-z0-9_]*)\b", block_scan):
            name = match.group(1)
            if name not in contract_info["modifiers"]:
                contract_info["modifiers"].append(name)
            if name not in modifiers_seen:
                modifiers_seen.append(name)
            after_modifier = contract["start"] + match.end()
            open_index = source.find("{", after_modifier, contract["end"])
            semicolon_index = source.find(";", after_modifier, contract["end"])
            if open_index != -1 and (
                semicolon_index == -1 or open_index < semicolon_index
            ):
                close_index = _find_matching_brace(source, open_index)
                modifier_body = source[open_index:close_index + 1]
                modifier_hints = _collect_line_hints(
                    modifier_body,
                    body_offset=open_index,
                    line_starts=starts,
                    max_items=8,
                )
                for key, values in modifier_hints.items():
                    global_hints[key].extend(values)

        for match in re.finditer(r"\bevent\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(", block_scan):
            event = {
                "contract": contract["name"],
                "event": match.group(1),
                "file": path,
                "line": _line_at(starts, contract["start"] + match.start()),
            }
            event_declarations.append(event)
            if match.group(1) not in contract_info["events"]:
                contract_info["events"].append(match.group(1))

        function_matches = list(_FUNCTION_DECL_RE.finditer(block_scan))
        function_matches.extend(_SPECIAL_FUNCTION_DECL_RE.finditer(block_scan))
        function_matches.sort(key=lambda item: item.start())

        for match in function_matches:
            unit = _function_unit_from_match(
                match,
                contract=contract,
                source=source,
                line_starts=starts,
                max_items=8,
            )
            for key, values in unit["hints"].items():
                global_hints[key].extend(values)
            entry = {
                "contract": unit["contract"],
                "contract_kind": unit["contract_kind"],
                "function": unit["function"],
                "file": path,
                "line": unit["line"],
                "visibility": unit["visibility"],
                "mutability": unit["mutability"],
                "parameters": unit["parameters"],
                "returns": unit["returns"],
                "modifiers": unit["modifiers"],
                "affordances": unit["affordances"],
                "hints": unit["hints"],
                "parse_source": "regex",
            }
            if (
                unit["visibility"] in {"public", "external"}
                or unit["function"] in {"receive", "fallback"}
            ):
                if unit["mutability"] in {"view", "pure"}:
                    observations.append(entry)
                    contract_info["observations"] += 1
                else:
                    actions.append(entry)
                    contract_info["actions"] += 1

        for match in public_var_pattern.finditer(block_scan):
            raw_type = " ".join(match.group(1).split())
            name = match.group(2)
            line = _line_at(starts, contract["start"] + match.start())
            observations.append({
                "contract": contract["name"],
                "contract_kind": contract["kind"],
                "function": name,
                "file": path,
                "line": line,
                "visibility": "public",
                "mutability": "view",
                "parameters": [],
                "returns": raw_type,
                "modifiers": [],
                "affordances": ["observation", "public_variable_getter"],
                "hints": _empty_action_hints(),
                "parse_source": "regex",
            })
            contract_info["observations"] += 1

        contracts.append(contract_info)

    return {
        "path": path,
        "truncated": truncated,
        "parse_source": "regex",
        "contracts": contracts[:max_items],
        "actions": actions[:max_items],
        "observations": observations[:max_items],
        "modifiers": modifiers_seen[:max_items],
        "event_declarations": event_declarations[:max_items],
        "hints": {
            key: values[:max_items]
            for key, values in global_hints.items()
        },
    }


def _action_response_priority(entry: dict) -> int:
    score, _reasons = _coverage_attention(entry)
    file_path = str(entry.get("file") or "")
    if not _is_third_party_action_source(file_path):
        score += 10
    if entry.get("contract_kind") == "interface":
        score -= 8
    if entry.get("mutability") in {"view", "pure"}:
        score -= 4
    if "state_changing_entrypoint" in (entry.get("affordances") or []):
        score += 3
    return score


def _sort_action_entries(entries: list[dict]) -> list[dict]:
    return sorted(
        entries,
        key=lambda item: (
            -_action_response_priority(item),
            _is_third_party_action_source(str(item.get("file") or "")),
            str(item.get("contract_kind") or ""),
            str(item.get("file") or ""),
            int(item.get("line") or 0),
        ),
    )


def _compact_hint_entry(entry: dict) -> dict:
    compact = {}
    for key in (
        "line",
        "text",
        "event",
        "target",
        "parameter",
        "value_hint",
        "surface",
        "selector_hint",
        "matched_term",
        "approval_spender",
    ):
        value = entry.get(key)
        if value not in (None, "", [], {}):
            compact[key] = value
    for key in ("path_terms", "validation_prompts", "calldata_roles"):
        value = entry.get(key)
        if value not in (None, "", [], {}):
            compact[key] = value
    return compact


def _compact_action_entry(entry: dict) -> dict:
    compact = {
        "key": _coverage_action_key(entry),
        "contract": entry.get("contract"),
        "function": entry.get("function"),
        "signature": _action_signature(entry),
        "file": entry.get("file"),
        "line": entry.get("line"),
        "mutability": entry.get("mutability"),
        "visibility": entry.get("visibility"),
        # Keep lexical + structural affordances both visible (structural labels
        # sort early alphabetically, so an 8-slot cap could hide value_*/token_*).
        "affordances": (entry.get("affordances") or [])[:16],
        "modifiers": (entry.get("modifiers") or [])[:6],
        "priority_score": _action_response_priority(entry),
        "parse_source": entry.get("parse_source"),
    }
    params = entry.get("parameters") or []
    if params:
        compact["parameters"] = [
            {
                "name": param.get("name"),
                "raw": param.get("raw"),
            }
            for param in params[:8]
            if isinstance(param, dict)
        ]
    hints = entry.get("hints") or {}
    hint_counts = {
        key: len(values or [])
        for key, values in hints.items()
        if values
    }
    if hint_counts:
        compact["hint_counts"] = hint_counts
    return {key: value for key, value in compact.items() if value not in (None, "", [], {})}


def _compact_contract_entry(entry: dict) -> dict:
    return {
        key: value
        for key, value in {
            "name": entry.get("name"),
            "kind": entry.get("kind"),
            "file": entry.get("file"),
            "line": entry.get("line"),
            "actions": entry.get("actions"),
            "observations": entry.get("observations"),
            "modifiers": (entry.get("modifiers") or [])[:8],
        }.items()
        if value not in (None, "", [], {})
    }


def _action_signature_group_key(entry: dict) -> tuple:
    return (
        str(entry.get("contract") or ""),
        str(entry.get("function") or ""),
        _action_signature(entry),
        str(entry.get("mutability") or ""),
        str(entry.get("visibility") or ""),
        tuple(sorted(str(item) for item in entry.get("affordances") or [])),
        tuple(str(item) for item in entry.get("modifiers") or []),
    )


def _source_profile_root(path: str) -> str:
    match = re.match(r"^(/audit/src/[^/]+)", str(path or ""))
    return match.group(1) if match else ""


def _compact_action_signature_group(entries: list[dict]) -> dict:
    representative = max(entries, key=_action_response_priority)
    files = _dedupe_text([
        str(item.get("file") or "")
        for item in entries
        if item.get("file")
    ])
    profile_roots = _dedupe_text([
        root
        for item in entries
        if (root := _source_profile_root(str(item.get("file") or "")))
    ])
    priorities = [_action_response_priority(item) for item in entries]
    compact = {
        "key": _coverage_action_key(representative),
        "contract": representative.get("contract"),
        "function": representative.get("function"),
        "signature": _action_signature(representative),
        "count": len(entries),
        "mutability": representative.get("mutability"),
        "visibility": representative.get("visibility"),
        "affordances": (representative.get("affordances") or [])[:16],
        "modifiers": (representative.get("modifiers") or [])[:6],
        "priority_score": max(priorities) if priorities else 0,
        "files": files[:5],
        "files_omitted": max(0, len(files) - 5),
        "profile_roots": profile_roots[:5],
        "profile_roots_omitted": max(0, len(profile_roots) - 5),
    }
    return {key: value for key, value in compact.items() if value not in (None, "", [], {})}


def _action_signature_groups(entries: list[dict], max_items: int) -> list[dict]:
    groups: dict[tuple, list[dict]] = {}
    for entry in entries:
        groups.setdefault(_action_signature_group_key(entry), []).append(entry)
    compact_groups = [
        _compact_action_signature_group(group)
        for group in groups.values()
    ]
    return sorted(
        compact_groups,
        key=lambda item: (
            -int(item.get("priority_score") or 0),
            -int(item.get("count") or 0),
            str(item.get("key") or ""),
        ),
    )[:max_items]


def _aggregate_action_space(parsed_files: list[dict], max_items: int) -> dict:
    contracts = []
    actions = []
    observations = []
    modifiers = {}
    event_declarations = []
    hints = _empty_action_hints()
    affordance_counts: dict[str, int] = {}

    for parsed in parsed_files:
        contracts.extend(parsed["contracts"])
        actions.extend(parsed["actions"])
        observations.extend(parsed["observations"])
        event_declarations.extend(parsed["event_declarations"])
        for modifier in parsed["modifiers"]:
            modifiers[modifier] = modifiers.get(modifier, 0) + 1
        for key in hints:
            hints[key].extend((parsed.get("hints") or {}).get(key) or [])
        for entry in parsed["actions"] + parsed["observations"]:
            for label in entry.get("affordances", []):
                affordance_counts[label] = affordance_counts.get(label, 0) + 1

    scope_rank = {"contract": 0, "library": 1, "source": 2, "interface": 3}
    actions = _sort_action_entries(actions)
    observations = sorted(
        observations,
        key=lambda item: (
            -_action_response_priority(item),
            scope_rank.get(item.get("contract_kind", ""), 9),
            item.get("file", ""),
            item.get("line", 0),
        ),
    )

    top_affordances = [
        {"affordance": name, "count": count}
        for name, count in sorted(
            affordance_counts.items(),
            key=lambda item: (-item[1], item[0]),
        )[:max_items]
    ]
    top_modifiers = [
        {"modifier": name, "count": count}
        for name, count in sorted(
            modifiers.items(),
            key=lambda item: (-item[1], item[0]),
        )[:max_items]
    ]
    action_family_count = len({_action_signature_group_key(item) for item in actions})
    observation_family_count = len({
        _action_signature_group_key(item) for item in observations
    })
    action_families = _action_signature_groups(actions, max_items)
    observation_families = _action_signature_groups(observations, max_items)

    return {
        "contracts": contracts[:max_items],
        "actions": actions[:max_items],
        "observations": observations[:max_items],
        "action_families": action_families,
        "observation_families": observation_families,
        "modifiers": top_modifiers,
        "event_declarations": event_declarations[:max_items],
        "hints": {
            key: values[:max_items]
            for key, values in hints.items()
        },
        "top_affordances": top_affordances,
        "summary": {
            "contracts": len(contracts),
            "actions": len(actions),
            "action_signature_groups": action_family_count,
            "observations": len(observations),
            "observation_signature_groups": observation_family_count,
            "modifiers": len(modifiers),
            "event_declarations": len(event_declarations),
            "value_flow_hints": len(hints["value_flows"]),
            "external_call_hints": len(hints["external_calls"]),
            "role_gate_hints": len(hints["role_gates"]),
            "event_hints": len(hints["events"]),
            "state_mutation_hints": len(hints["state_mutations"]),
            "oracle_read_hints": len(hints["oracle_reads"]),
            "router_call_hints": len(hints["router_calls"]),
            "bridge_message_hints": len(hints["bridge_messages"]),
            "callback_surface_hints": len(hints["callback_surfaces"]),
            "authorization_check_hints": len(hints["authorization_checks"]),
            "cross_contract_call_hints": len(hints["cross_contract_calls"]),
            "economic_parameter_hints": len(hints["economic_parameters"]),
        },
    }


# ── AST-backed action-space extraction ───────────────────────────────────
#
# The regex action-space parser (above) works on uncompilable code but emits
# silently-wrong structure on multi-line signatures, modifier args containing
# `{`/`;`, constructor base-calls (phantom modifiers), and similar cases. When
# the project compiles, solc's AST is ground truth. We compile once with
# `forge build --ast` (forge already resolves remappings/solc versions), read
# the per-source AST from build-info, and produce the SAME parsed-file shape as
# `_parse_action_space_file` — reusing the existing affordance/hint logic by
# slicing function bodies from the original source via the AST `src` byte
# offsets. Any failure (no compile, no AST, parse error) transparently falls
# back to the regex parser, so this is strictly additive.

_AST_BUILD_TIMEOUT_SECONDS = 300
_AST_MAX_EXTRACT_BYTES = 16_000_000
_AST_TYPE_QUALIFIER_RE = re.compile(
    r"^(?:struct|contract|interface|library|enum|function|type)\s+"
)


def _ast_src_offsets(src: object) -> tuple[int, int] | None:
    """Parse a solc `src` field ("start:length:file") into byte offsets."""
    if not isinstance(src, str):
        return None
    parts = src.split(":")
    if len(parts) < 2:
        return None
    try:
        start = int(parts[0])
        length = int(parts[1])
    except ValueError:
        return None
    if start < 0 or length < 0:
        return None
    return start, length


def _ast_byte_to_char(source_bytes: bytes, byte_off: int) -> int:
    """Convert a solc byte offset to a character index into the source.

    solc `src` offsets are UTF-8 byte offsets; `_line_starts`/`_line_at` and
    `_collect_line_hints` work in character indices. For ASCII Solidity these
    coincide; this keeps non-ASCII (comments/strings) correct.
    """
    byte_off = max(0, min(byte_off, len(source_bytes)))
    return len(source_bytes[:byte_off].decode("utf-8", "ignore"))


def _ast_node_text(source_bytes: bytes, src: object) -> str:
    offsets = _ast_src_offsets(src)
    if offsets is None:
        return ""
    start, length = offsets
    return source_bytes[start:start + length].decode("utf-8", "replace")


def _ast_type_string(type_descriptions: object) -> str:
    """Normalize a solc typeString to the source-like form the regex parser
    produces, so action signatures stay consistent across AST and regex maps
    (these are textual signatures, not ABI selectors)."""
    if not isinstance(type_descriptions, dict):
        return ""
    type_string = str(type_descriptions.get("typeString") or "").strip()
    if not type_string:
        return ""
    type_string = _AST_TYPE_QUALIFIER_RE.sub("", type_string).strip()
    type_string = re.sub(
        r"\s+(?:memory|calldata|storage)(?:\s+pointer)?$",
        "",
        type_string,
    ).strip()
    return " ".join(type_string.split())


def _ast_parameters(param_list: object) -> list[dict]:
    """Build the same `[{raw, name, type}]` shape as `_parse_parameters`.

    ``type`` is the AST type string directly; ``raw``/``name`` are unchanged for
    backward compatibility.
    """
    params = []
    if not isinstance(param_list, dict):
        return params
    for node in param_list.get("parameters") or []:
        if not isinstance(node, dict):
            continue
        type_text = _ast_type_string(node.get("typeDescriptions"))
        name = str(node.get("name") or "").strip()
        raw = f"{type_text} {name}".strip() if type_text else name
        params.append({
            "raw": " ".join(raw.split()),
            "name": name,
            "type": type_text,
        })
    return params


def _ast_returns(return_params: object) -> str:
    parts = []
    if isinstance(return_params, dict):
        for node in return_params.get("parameters") or []:
            if not isinstance(node, dict):
                continue
            type_text = _ast_type_string(node.get("typeDescriptions"))
            name = str(node.get("name") or "").strip()
            piece = f"{type_text} {name}".strip() if name else type_text
            if piece:
                parts.append(piece)
    return ", ".join(parts)


def _ast_function_modifiers(node: dict) -> list[str]:
    """Resolved modifier names from a FunctionDefinition node.

    Skips base-constructor specifiers (e.g. `ERC20("n","s")`), which the regex
    parser wrongly captured as modifiers.
    """
    modifiers: list[str] = []
    for invocation in node.get("modifiers") or []:
        if not isinstance(invocation, dict):
            continue
        if str(invocation.get("kind") or "") == "baseConstructorSpecifier":
            continue
        name_node = invocation.get("modifierName")
        name = ""
        if isinstance(name_node, dict):
            name = str(
                name_node.get("name") or name_node.get("namePath") or ""
            ).strip()
        if "." in name:
            name = name.split(".")[-1]
        if name and name not in modifiers:
            modifiers.append(name)
    return modifiers


def _ast_source_unit_to_parsed_file(
    ast: object,
    path: str,
    source: str,
    *,
    max_items: int,
) -> dict | None:
    """Convert a solc compact-AST SourceUnit into a parsed-file dict matching
    `_parse_action_space_file`. Returns None if the AST shape is unusable so the
    caller can fall back to the regex parser."""
    if not isinstance(ast, dict) or ast.get("nodeType") != "SourceUnit":
        return None
    nodes = ast.get("nodes")
    if not isinstance(nodes, list):
        return None

    source_bytes = source.encode("utf-8", "replace")
    line_starts = _line_starts(source)

    contracts: list[dict] = []
    actions: list[dict] = []
    observations: list[dict] = []
    modifiers_seen: list[str] = []
    event_declarations: list[dict] = []
    global_hints = _empty_action_hints()
    saw_contract = False

    def char_offset(node: dict) -> int:
        offsets = _ast_src_offsets(node.get("src"))
        return _ast_byte_to_char(source_bytes, offsets[0]) if offsets else 0

    def collect_body_hints(body_node: object) -> tuple[str, dict]:
        if not isinstance(body_node, dict):
            return "", _empty_action_hints()
        body_text = _ast_node_text(source_bytes, body_node.get("src"))
        body_hints = _collect_line_hints(
            body_text,
            body_offset=char_offset(body_node),
            line_starts=line_starts,
            max_items=8,
        )
        return body_text, body_hints

    for contract_node in nodes:
        if not isinstance(contract_node, dict):
            continue
        if contract_node.get("nodeType") != "ContractDefinition":
            continue
        saw_contract = True
        kind = str(contract_node.get("contractKind") or "contract")
        if kind not in {"contract", "interface", "library"}:
            kind = "contract"
        bases: list[str] = []
        for base in contract_node.get("baseContracts") or []:
            if not isinstance(base, dict):
                continue
            base_name = base.get("baseName")
            if isinstance(base_name, dict):
                resolved = str(
                    base_name.get("name") or base_name.get("namePath") or ""
                ).strip()
                if resolved:
                    bases.append(resolved.split(".")[-1])
        contract_info = {
            "name": contract_node.get("name"),
            "kind": kind,
            "bases": _dedupe_text(bases),
            "file": path,
            "line": _line_at(line_starts, char_offset(contract_node)),
            "actions": 0,
            "observations": 0,
            "modifiers": [],
            "events": [],
        }

        for member in contract_node.get("nodes") or []:
            if not isinstance(member, dict):
                continue
            member_type = member.get("nodeType")
            if member_type == "ModifierDefinition":
                name = str(member.get("name") or "").strip()
                if name and name not in contract_info["modifiers"]:
                    contract_info["modifiers"].append(name)
                if name and name not in modifiers_seen:
                    modifiers_seen.append(name)
                _body, modifier_hints = collect_body_hints(member.get("body"))
                for key, values in modifier_hints.items():
                    global_hints[key].extend(values)
                continue
            if member_type == "EventDefinition":
                name = str(member.get("name") or "").strip()
                if name:
                    event_declarations.append({
                        "contract": contract_node.get("name"),
                        "event": name,
                        "file": path,
                        "line": _line_at(line_starts, char_offset(member)),
                    })
                    if name not in contract_info["events"]:
                        contract_info["events"].append(name)
                continue
            if member_type == "VariableDeclaration":
                if not member.get("stateVariable"):
                    continue
                if str(member.get("visibility") or "") != "public":
                    continue
                name = str(member.get("name") or "").strip()
                if not name:
                    continue
                observations.append({
                    "contract": contract_node.get("name"),
                    "contract_kind": kind,
                    "function": name,
                    "file": path,
                    "line": _line_at(line_starts, char_offset(member)),
                    "visibility": "public",
                    "mutability": "view",
                    "parameters": [],
                    "returns": _ast_type_string(member.get("typeDescriptions")),
                    "modifiers": [],
                    "affordances": ["observation", "public_variable_getter"],
                    "hints": _empty_action_hints(),
                    "parse_source": "ast",
                })
                contract_info["observations"] += 1
                continue
            if member_type != "FunctionDefinition":
                continue
            fn_kind = str(member.get("kind") or "function")
            if fn_kind == "constructor":
                continue
            if fn_kind in {"receive", "fallback"}:
                name = fn_kind
            else:
                name = str(member.get("name") or "").strip()
                if not name:
                    continue
            visibility = str(member.get("visibility") or "").strip()
            if not visibility and kind == "interface":
                visibility = "external"
            if name in {"receive", "fallback"} and not visibility:
                visibility = "external"
            mutability = str(member.get("stateMutability") or "nonpayable").strip()
            if mutability not in {"view", "pure", "payable", "nonpayable"}:
                mutability = "nonpayable"
            modifiers = _ast_function_modifiers(member)
            body_text, function_hints = collect_body_hints(member.get("body"))
            for key, values in function_hints.items():
                global_hints[key].extend(values)
            ast_parameters = _ast_parameters(member.get("parameters"))
            ast_returns = _ast_returns(member.get("returnParameters"))
            affordances = _action_affordances(
                name=name,
                visibility=visibility,
                mutability=mutability,
                modifiers=modifiers,
                body=body_text,
            )
            # Keep the AST and regex maps consistent: merge the same
            # delexicalized structural labels the regex parser adds, so an
            # AST-backed audit also surfaces renamed/novel risky structure.
            structural = _structural_action_affordances(
                visibility=visibility,
                mutability=mutability,
                modifiers=modifiers,
                body=body_text,
                hints=function_hints,
                parameters=ast_parameters,
                returns=ast_returns,
            )
            affordances = sorted(set(affordances).union(structural))
            entry = {
                "contract": contract_node.get("name"),
                "contract_kind": kind,
                "function": name,
                "file": path,
                "line": _line_at(line_starts, char_offset(member)),
                "visibility": visibility or "unspecified",
                "mutability": mutability,
                "parameters": ast_parameters,
                "returns": ast_returns,
                "modifiers": modifiers,
                "affordances": affordances,
                "hints": function_hints,
                "parse_source": "ast",
            }
            if visibility in {"public", "external"} or name in {"receive", "fallback"}:
                if mutability in {"view", "pure"}:
                    observations.append(entry)
                    contract_info["observations"] += 1
                else:
                    actions.append(entry)
                    contract_info["actions"] += 1

        contracts.append(contract_info)

    if not saw_contract:
        return None

    return {
        "path": path,
        "truncated": len(source_bytes) > _ACTION_MAX_FILE_CHARS,
        "parse_source": "ast",
        "contracts": contracts[:max_items],
        "actions": actions[:max_items],
        "observations": observations[:max_items],
        "modifiers": modifiers_seen[:max_items],
        "event_declarations": event_declarations[:max_items],
        "hints": {key: values[:max_items] for key, values in global_hints.items()},
    }


async def _foundry_project_root(container: AuditContainer, start: str) -> str:
    """Return the nearest ancestor of `start` containing foundry.toml, or ""."""
    safe = shlex.quote(start)
    script = (
        f'p={safe}; '
        '[ -f "$p" ] && p=$(dirname "$p"); '
        'while [ "$p" != "/" ] && [ "$p" != "." ] && [ ! -f "$p/foundry.toml" ]; '
        'do p=$(dirname "$p"); done; '
        '[ -f "$p/foundry.toml" ] && echo "$p"'
    )
    try:
        exit_code, output = await container.exec(script, timeout=10)
    except Exception:
        return ""
    if exit_code != 0:
        return ""
    lines = [line.strip() for line in output.splitlines() if line.strip()]
    return lines[0] if lines else ""


async def _load_ast_sources(
    container: AuditContainer,
    *,
    source_files: list[str],
    scan_root: str,
) -> dict[str, dict]:
    """Best-effort solc AST for `source_files`, keyed by absolute path.

    Compiles with `forge build --ast`, reads per-source AST from the newest
    build-info, and returns {abs_path: source_unit_ast}. Returns an empty dict
    on any failure (no foundry project, build/AST unavailable, jq/parse error,
    or the REENTBOTPRO_DISABLE_AST_MAP escape hatch) so the caller falls back
    to the regex parser. Never raises.
    """
    if os.environ.get("REENTBOTPRO_DISABLE_AST_MAP"):
        return {}
    if not source_files:
        return {}
    try:
        project_root = await _foundry_project_root(container, scan_root)
        if not project_root:
            return {}
        rel_to_abs: dict[str, str] = {}
        for abs_path in source_files:
            try:
                rel = posixpath.relpath(abs_path, project_root)
            except ValueError:
                continue
            if rel.startswith(".."):
                continue
            rel_to_abs[rel] = abs_path
        if not rel_to_abs:
            return {}

        await container.exec(
            "forge build --ast",
            working_dir=project_root,
            timeout=_AST_BUILD_TIMEOUT_SECONDS,
        )

        find_cmd = (
            f"find {shlex.quote(project_root)} -type f -path '*/build-info/*.json' "
            "-printf '%T@ %p\\n' 2>/dev/null | sort -rn | head -1 | cut -d' ' -f2-"
        )
        exit_code, output = await container.exec(find_cmd, timeout=20)
        lines = [line.strip() for line in output.splitlines() if line.strip()]
        if exit_code != 0 or not lines:
            return {}
        build_info_path = lines[0]

        keys_json = json.dumps(sorted(rel_to_abs))
        jq_filter = (
            "$keys[] as $k | (.output.sources[$k].ast) as $a "
            "| select($a != null) | {p: $k, ast: $a}"
        )
        extract_cmd = (
            f"jq -c --argjson keys {shlex.quote(keys_json)} "
            f"{shlex.quote(jq_filter)} {shlex.quote(build_info_path)} "
            f"2>/dev/null | head -c {_AST_MAX_EXTRACT_BYTES}"
        )
        _exit, output = await container.exec(
            extract_cmd,
            working_dir=project_root,
            timeout=120,
        )
        if not output.strip():
            return {}

        ast_by_path: dict[str, dict] = {}
        for line in output.splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                record = json.loads(line)
            except json.JSONDecodeError:
                continue  # tolerate a final line truncated by head -c
            if not isinstance(record, dict):
                continue
            abs_path = rel_to_abs.get(str(record.get("p")))
            ast = record.get("ast")
            if abs_path and isinstance(ast, dict):
                ast_by_path[abs_path] = ast
        return ast_by_path
    except Exception:
        return {}


async def _map_action_space(container: AuditContainer, args: dict) -> str:
    try:
        root = _normalize_action_source_path(args.get("path", "/audit"))
        files_arg = args.get("files")
        files = _require_list(files_arg, "files") if files_arg is not None else None
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"

    include_tests = bool(args.get("include_tests", False))
    max_files = min(max(int(args.get("max_files", 160)), 1), 500)
    max_roots = min(max(int(args.get("max_roots", 12)), 1), 100)
    max_items = min(max(int(args.get("max_items", 2000)), 1), 10_000)
    response_items = min(max(int(args.get("response_items", 6)), 1), 50)
    try:
        source_files, truncated_files = await _discover_action_source_files(
            container,
            root=root,
            files=files,
            include_tests=include_tests,
            max_files=max_files,
            max_roots=max_roots,
        )
    except ValueError as exc:
        return f"Error: {exc}"

    ast_by_path = await _load_ast_sources(
        container,
        source_files=source_files,
        scan_root=root,
    )
    parsed_files = []
    read_errors = []
    parse_source_counts = {"ast": 0, "regex": 0}
    for path in source_files:
        try:
            source = await container.read_file(path)
        except FileNotFoundError as exc:
            read_errors.append({"path": path, "error": str(exc)})
            continue
        parsed = None
        file_ast = ast_by_path.get(path)
        if file_ast is not None:
            parsed = _ast_source_unit_to_parsed_file(
                file_ast,
                path,
                source,
                max_items=max_items,
            )
        if parsed is None:
            parsed = _parse_action_space_file(path, source, max_items=max_items)
        source_kind = parsed.get("parse_source", "regex")
        parse_source_counts[source_kind] = parse_source_counts.get(source_kind, 0) + 1
        parsed_files.append(parsed)

    if parse_source_counts["ast"] and parse_source_counts["regex"]:
        parse_mode = "mixed"
    elif parse_source_counts["ast"]:
        parse_mode = "ast"
    else:
        parse_mode = "regex"

    aggregate = _aggregate_action_space(parsed_files, max_items)
    status = "observed"
    validity_notes = []
    if source_files and not parsed_files:
        status = "invalid_empty_source"
        validity_notes.append(
            "Requested Solidity source files were discovered but none could be read."
        )
    state = await _load_campaign_state(container)
    action_space_id = _next_campaign_id(state, "action_space")
    action_space = {
        "id": action_space_id,
        "status": status,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "source": {
            "path": root,
            "files_requested": len(source_files),
            "files_scanned": len(parsed_files),
            "files_truncated_by_limit": truncated_files,
            "profile_roots_limit": max_roots if files is None else None,
            "include_tests": include_tests,
            "read_errors": read_errors,
            "parse_mode": parse_mode,
            "parse_source_counts": parse_source_counts,
            "truncated_source_files": [
                item["path"] for item in parsed_files if item.get("truncated")
            ],
        },
        "validity_notes": validity_notes,
        "related_ids": [str(item) for item in related_ids],
        **aggregate,
    }
    action_space_path = f"/workspace/campaign/action-spaces/{action_space_id}.json"
    await container.write_file(
        action_space_path,
        json.dumps(action_space, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Action-space map: {root}",
            content=(
                f"Action space: {action_space_id}\n"
                f"Path: {action_space_path}\n"
                f"Status: {status}\n"
                f"Parse mode: {parse_mode}\n"
                f"Source root: {root}\n"
                f"Files scanned: {len(parsed_files)}"
                f" (+{truncated_files} over file limit)\n"
                f"Contracts: {aggregate['summary']['contracts']}\n"
                f"State-changing actions: {aggregate['summary']['actions']}\n"
                f"Action signature groups: {aggregate['summary']['action_signature_groups']}\n"
                f"Observation functions: {aggregate['summary']['observations']}\n"
                f"Observation signature groups: {aggregate['summary']['observation_signature_groups']}\n"
                "Use this map to choose protocol-specific action sequences; "
                "do not treat affordance labels as findings."
            ),
            evidence=[action_space_path],
            related_ids=[str(item) for item in related_ids],
            status="blocked" if status == "invalid_empty_source" else "observed",
        )

    response = {
        "action_space_id": action_space_id,
        "status": status,
        "path": action_space_path,
        "result_id": result_id or None,
        "source": action_space["source"],
        "validity_notes": validity_notes,
        "summary": aggregate["summary"],
        "top_affordances": aggregate["top_affordances"][:response_items],
        "modifiers": aggregate["modifiers"][:response_items],
        "contracts": [
            _compact_contract_entry(item)
            for item in aggregate["contracts"][:response_items]
        ],
        "actions": [
            _compact_action_entry(item)
            for item in aggregate["actions"][:response_items]
        ],
        "action_families": aggregate["action_families"][:response_items],
        "observations": [
            _compact_action_entry(item)
            for item in aggregate["observations"][: max(3, response_items // 2)]
        ],
        "observation_families": (
            aggregate["observation_families"][: max(3, response_items // 2)]
        ),
        "sample_hints": {
            key: [_compact_hint_entry(item) for item in values[:1]]
            for key, values in aggregate["hints"].items()
            if values and key in {
                "value_flows",
                "external_calls",
                "authorization_checks",
                "oracle_reads",
                "router_calls",
                "bridge_messages",
                "callback_surfaces",
            }
        },
        "omitted_from_response": {
            "actions": max(0, aggregate["summary"]["actions"] - response_items),
            "action_families": max(
                0,
                aggregate["summary"]["action_signature_groups"] - response_items,
            ),
            "observations": max(
                0,
                aggregate["summary"]["observations"] - max(3, response_items // 2),
            ),
            "observation_families": max(
                0,
                aggregate["summary"]["observation_signature_groups"]
                - max(3, response_items // 2),
            ),
            "note": "Open the artifact path for the full action grammar.",
        },
    }
    return json.dumps(response, indent=2, sort_keys=True)


# ── extract_state_transition_model: generic state/invariant modeling ─────
#
# A delexicalized planning model derived from the same per-function units the
# action-space/source_slice tools parse (`_iter_function_units`): what state a
# contract tracks, who can change it, which *generic* invariant families might
# hold, and experiments that could falsify them. It is research/planning context
# for the LLM — never a finding and never consulted by the submission gates. It
# stays protocol-agnostic on purpose: optional named "lenses" (vault/lending/
# queue) are attached only when source evidence supports them, and they never
# replace or crowd out the generic invariants. See
# docs/attack-campaign-engine.md.

_STM_FOCUS_OPTIONS = (
    "auto",
    "generic",
    "accounting",
    "authorization",
    "state_machine",
    "external_boundary",
)
# Response/ordering priority for the generic invariant families. The artifact
# always keeps every family; `focus` only promotes a subset to the front.
_STM_INVARIANT_KIND_ORDER = (
    "conservation",
    "authorization_binding",
    "external_call_safety",
    "state_machine",
    "rounding",
    "replay_protection",
    "bounds",
    "liveness",
)
_STM_FOCUS_KINDS = {
    "accounting": ("conservation", "rounding", "bounds"),
    "authorization": ("authorization_binding", "replay_protection"),
    "state_machine": ("state_machine", "liveness"),
    "external_boundary": ("external_call_safety",),
}
_STM_PROBE_STRATEGY = {
    "conservation": "accounting_delta",
    "rounding": "accounting_delta",
    "bounds": "accounting_delta",
    "external_call_safety": "custom",
    "authorization_binding": "custom",
    "replay_protection": "custom",
    "state_machine": "log_only",
    "liveness": "log_only",
}
# The delexicalized structural affordance labels (from
# `_structural_action_affordances`); the lexical labels are kept separately so an
# entrypoint record can surface only the structure-derived ones.
_STM_STRUCTURAL_AFFORDANCE_LABELS = frozenset({
    "mapping_state_write",
    "aggregate_state_update",
    "lifecycle_state_change",
    "user_claim_or_obligation_update",
    "external_call_with_value",
    "dynamic_call_target",
    "external_boundary_crossing",
    "unchecked_external_boundary",
    "arithmetic_rounding_or_division",
    "batch_or_loop_surface",
    "authorization_condition",
    "emits_state_transition_event",
    "state_mutating_entrypoint",
})
# State-name classification (planning hints only). Order of application in
# `_stm_classify_state`: mapping (has an index) -> enum/lifecycle -> flag ->
# aggregate -> asset_hint -> unknown. "unknown must not default to vault" — these
# never imply a protocol; they only label what is tracked.
_STM_AGGREGATE_NAME_RE = re.compile(
    r"total|aggregate|cumulative|accumulat|supply|reserve|outstanding|\bsum\b|count",
    re.IGNORECASE,
)
_STM_FLAG_NAME_RE = re.compile(
    r"paused|frozen|locked|enabled|disabled|initiali[sz]ed|claimed|settled|"
    r"finali[sz]ed|revoked|cancell?ed|active|allowed|whitelisted|blacklisted",
    re.IGNORECASE,
)
_STM_LIFECYCLE_NAME_RE = re.compile(
    r"status|state|phase|stage|epoch|\bmode\b|\bround\b", re.IGNORECASE
)
_STM_ASSET_NAME_RE = re.compile(
    r"balance|asset|token|share|collateral|deposit|fund|amount|debt|stake|"
    r"liquidit|credit|principal|escrow",
    re.IGNORECASE,
)
_STM_LIVENESS_TERM_RE = re.compile(
    r"queue|enqueue|dequeue|deadline|expire|expiry|pause|frozen|freeze|"
    r"finali[sz]e|cancel|escrow|timelock|grace|cooldown|unbond",
    re.IGNORECASE,
)
_STM_AUTH_MODIFIER_RE = re.compile(
    r"only|role|owner|auth|admin|guard|keeper", re.IGNORECASE
)


def _stm_source_slice_hint(value: object) -> dict:
    """Normalize the optional `source_slice` arg into a scoping hint.

    Accepts an object ({path, contract, function, signature}) or a string — a
    path, a "Contract.function", or a raw signature. Returns a compact dict with
    only the keys that resolved. Generic and lossless: anything it cannot parse
    is dropped rather than guessed.
    """
    hint: dict = {}
    if isinstance(value, dict):
        for key in ("path", "contract", "function"):
            text = str(value.get(key) or "").strip()
            if text:
                hint[key] = text
        signature = str(value.get("signature") or "").strip()
        if signature and "function" not in hint:
            match = re.match(r"\s*([A-Za-z_]\w*)\s*\(", signature)
            if match:
                hint["function"] = match.group(1)
    elif isinstance(value, str):
        text = value.strip()
        if not text:
            return hint
        if text.startswith("/"):
            hint["path"] = text
        elif "(" in text:
            match = re.match(r"\s*([A-Za-z_]\w*)\s*\(", text)
            if match:
                hint["function"] = match.group(1)
        elif "." in text:
            contract, _, rest = text.partition(".")
            if contract.strip():
                hint["contract"] = contract.strip()
            rest = re.split(r"\(", rest, 1)[0].strip()
            if rest:
                hint["function"] = rest
        else:
            hint["contract"] = text
    return hint


def _stm_unit_from_action(action: dict) -> dict:
    """Adapt an action-space action entry into the per-function unit shape the
    model builder expects (used only as a fallback when no source is scanned)."""
    unit = dict(action)
    unit.setdefault("start_line", action.get("line"))
    unit.setdefault("end_line", action.get("line"))
    unit.setdefault("hints", action.get("hints") or {})
    unit.setdefault("affordances", action.get("affordances") or [])
    unit.setdefault("parameters", action.get("parameters") or [])
    unit.setdefault("modifiers", action.get("modifiers") or [])
    return unit


def _stm_dedupe_strings(items: list, cap: int) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for item in items:
        text = " ".join(str(item or "").split())
        if not text or text in seen:
            continue
        seen.add(text)
        out.append(text[:80])
        if len(out) >= cap:
            break
    return out


def _stm_refs(ref: str) -> list[str]:
    return [ref] if ref else []


def _stm_hint_refs(unit: dict, keys: tuple, cap: int) -> list[str]:
    out: list[str] = []
    file = unit.get("file")
    for key in keys:
        for entry in (unit.get("hints") or {}).get(key) or []:
            line = entry.get("line") if isinstance(entry, dict) else None
            ref = f"{file}:{line}" if file and line else (file or "")
            if ref and ref not in out:
                out.append(ref)
            if len(out) >= cap:
                return out
    return out


def _stm_local_return_names(unit: dict) -> set[str]:
    """Named return-parameter identifiers for a unit (e.g. ``shares`` in
    ``returns (uint256 shares)``). Assignments to these are locals, not
    persistent state, so the write filter drops them."""
    raw = str(unit.get("returns") or "").strip()
    if not raw:
        return set()
    names = set()
    for param in _parse_parameters(raw):
        name = str(param.get("name") or "").strip()
        if name:
            names.add(name)
    return names


def _stm_state_writes(unit: dict) -> list[dict]:
    """Filtered state-write hints for one unit.

    Reuses the shared `state_mutations` line hints but drops assignments to a
    named return local (`shares = ...` for `returns (uint256 shares)`), which is
    a local, not persistent contract state. (An equality comparison read as a
    write is rejected upstream by the hint regex's `(?!=)` guard.) Indexed
    writes (`m[k] = ...`) are always kept.
    """
    return_names = _stm_local_return_names(unit)
    out: list[dict] = []
    for entry in (unit.get("hints") or {}).get("state_mutations") or []:
        if not isinstance(entry, dict):
            continue
        target = " ".join(str(entry.get("target") or "").split())
        if not target:
            continue
        text = str(entry.get("text") or "")
        if "[" not in target and _stm_state_base_name(target) in return_names:
            continue
        out.append({"target": target, "line": entry.get("line"), "text": text})
    return out


def _stm_state_base_name(target: str) -> str:
    text = str(target or "").strip()
    return re.split(r"[\[.]", text, 1)[0].strip()


def _stm_classify_state(target: str, text: str) -> str:
    raw = str(target or "")
    if "[" in raw:
        return "mapping"
    name = _stm_state_base_name(raw).lower()
    if not name:
        return "unknown"
    if _STM_LIFECYCLE_NAME_RE.search(name) or _STRUCT_ENUM_ASSIGN_RE.search(str(text or "")):
        return "enum"
    if _STM_FLAG_NAME_RE.search(name):
        return "flag"
    if _STM_AGGREGATE_NAME_RE.search(name):
        return "aggregate"
    if _STM_ASSET_NAME_RE.search(name):
        return "asset_hint"
    return "unknown"


_STM_STATE_KIND_RANK = {
    "mapping": 0,
    "enum": 1,
    "flag": 2,
    "aggregate": 3,
    "asset_hint": 4,
    "external_dependency": 4,
    "unknown": 5,
}


def _stm_build_tracked_state(
    units: list[dict],
    *,
    protocol_graph: dict | None,
    max_items: int,
) -> list[dict]:
    groups: dict[tuple, dict] = {}
    order: list[tuple] = []
    for unit in units:
        contract = str(unit.get("contract") or "")
        file = unit.get("file")
        for write in _stm_state_writes(unit):
            target = write["target"]
            name = _stm_state_base_name(target)
            if not name:
                continue
            kind = _stm_classify_state(target, write.get("text"))
            key = (contract, name)
            record = groups.get(key)
            if record is None:
                record = {
                    "name": name,
                    "contract": contract,
                    "evidence": [],
                    "_kinds": set(),
                }
                groups[key] = record
                order.append(key)
            record["_kinds"].add(kind)
            line = write.get("line")
            ref = f"{file}:{line}" if file and line else (file or "")
            if ref and ref not in record["evidence"] and len(record["evidence"]) < 6:
                record["evidence"].append(ref)
    tracked: list[dict] = []
    for key in order:
        record = groups[key]
        kinds = record.pop("_kinds")
        record["kind"] = min(kinds, key=lambda item: _STM_STATE_KIND_RANK.get(item, 9))
        tracked.append(record)
    # Optional external-dependency context from a protocol graph (defensive: the
    # node shape is treated as best-effort and never required).
    if isinstance(protocol_graph, dict):
        graph_id = str(protocol_graph.get("id") or "")
        for node in protocol_graph.get("nodes") or []:
            if not isinstance(node, dict):
                continue
            node_kind = str(node.get("kind") or "")
            if node_kind not in {"external_dependency", "trust_boundary", "asset_hint"}:
                continue
            name = str(
                node.get("name") or node.get("label") or node.get("id") or ""
            ).strip()
            if not name:
                continue
            tracked.append({
                "name": name,
                "contract": str(node.get("contract") or ""),
                "kind": "asset_hint" if node_kind == "asset_hint" else "external_dependency",
                "evidence": [f"protocol_graph:{graph_id}" if graph_id else "protocol_graph"],
            })
    return tracked[:max_items]


def _stm_unit_signals(unit: dict) -> dict:
    aff = set(unit.get("affordances") or [])
    hints = unit.get("hints") or {}
    visibility = str(unit.get("visibility") or "")
    mutability = str(unit.get("mutability") or "")
    mapping_write = (
        "mapping_state_write" in aff or "user_claim_or_obligation_update" in aff
    )
    aggregate_write = "aggregate_state_update" in aff
    lifecycle = "lifecycle_state_change" in aff
    has_state_write = bool(
        mapping_write or aggregate_write or lifecycle or _stm_state_writes(unit)
    )
    external_boundary = (
        "external_boundary_crossing" in aff
        or bool(hints.get("external_calls"))
        or bool(hints.get("value_flows"))
    )
    return {
        "is_entrypoint": visibility in {"public", "external"},
        "is_mutating": mutability not in {"view", "pure"},
        "mapping_write": mapping_write,
        "aggregate_write": aggregate_write,
        "lifecycle": lifecycle,
        "has_state_write": has_state_write,
        "external_boundary": external_boundary,
        "unchecked_boundary": "unchecked_external_boundary" in aff,
        "dynamic_target": "dynamic_call_target" in aff,
        "value_call": (
            "external_call_with_value" in aff or "token_or_native_transfer" in aff
        ),
        "arithmetic": "arithmetic_rounding_or_division" in aff,
        "batch": "batch_or_loop_surface" in aff,
        "authz": (
            "authorization_condition" in aff
            or "modifier_gated" in aff
            or "sender_or_role_checked" in aff
            or bool(hints.get("role_gates"))
        ),
        "signature_gate": (
            "signature_gate" in aff or "signed_authorization" in aff
        ),
    }


def _stm_address_param_names(unit: dict) -> list[str]:
    names = []
    for param in unit.get("parameters") or []:
        if not isinstance(param, dict):
            continue
        name = str(param.get("name") or "").strip()
        if name and "address" in _parameter_type_text(param).lower():
            names.append(name)
    return names


def _stm_param_keyed_write_keys(unit: dict) -> list[str]:
    """Address parameters used as a mapping write KEY in this unit.

    Signals an authorization-binding concern: a function that mutates state keyed
    by a caller-supplied account (e.g. ``balances[account] -= x``) rather than by
    ``msg.sender``. Derived from the filtered write hints so it never fires on a
    plain ``balances[msg.sender]`` self-update.
    """
    addr_params = _stm_address_param_names(unit)
    if not addr_params:
        return []
    keys: list[str] = []
    for write in _stm_state_writes(unit):
        match = re.search(r"\[([^\]]+)\]", write["target"])
        if not match:
            continue
        inside = match.group(1)
        for name in addr_params:
            if name not in keys and re.search(rf"\b{re.escape(name)}\b", inside):
                keys.append(name)
    return keys


def _stm_has_liveness_terms(unit: dict) -> bool:
    parts = [str(unit.get("function") or "")]
    parts.extend(str(item) for item in unit.get("modifiers") or [])
    hints = unit.get("hints") or {}
    for entry in hints.get("state_mutations") or []:
        if isinstance(entry, dict):
            parts.append(str(entry.get("target") or ""))
    for entry in hints.get("events") or []:
        if isinstance(entry, dict):
            parts.append(str(entry.get("event") or ""))
    return bool(_STM_LIVENESS_TERM_RE.search(" ".join(parts)))


def _stm_entry_boundaries(unit: dict, cap: int) -> list[dict]:
    out: list[dict] = []
    seen: set[tuple] = set()
    groups = (
        ("external_call", "external_calls"),
        ("value_flow", "value_flows"),
        ("callback_surface", "callback_surfaces"),
        ("router_call", "router_calls"),
        ("bridge_message", "bridge_messages"),
    )
    for kind, key in groups:
        for entry in (unit.get("hints") or {}).get(key) or []:
            if not isinstance(entry, dict):
                continue
            line = entry.get("line")
            text = _truncate_response_text(entry.get("text"), 140)
            dedupe = (kind, line, text)
            if dedupe in seen:
                continue
            seen.add(dedupe)
            out.append({"kind": kind, "line": line, "text": text})
            if len(out) >= cap:
                return out
    return out


def _stm_entry_authorization(unit: dict, signals: dict, cap: int) -> list[dict]:
    out: list[dict] = []
    for modifier in unit.get("modifiers") or []:
        name = str(modifier)
        if _STM_AUTH_MODIFIER_RE.search(name):
            entry = {"kind": "modifier", "name": name}
            if entry not in out:
                out.append(entry)
    for entry in (unit.get("hints") or {}).get("role_gates") or []:
        if not isinstance(entry, dict):
            continue
        out.append({
            "kind": "inline_check",
            "line": entry.get("line"),
            "text": _truncate_response_text(entry.get("text"), 140),
        })
        if len(out) >= cap:
            break
    if signals["signature_gate"]:
        out.append({"kind": "signature"})
    return out[:cap]


def _stm_preconditions(unit: dict, signals: dict, authorization: list[dict]) -> list[str]:
    pre: list[str] = []
    for entry in authorization:
        kind = entry.get("kind")
        if kind == "modifier":
            pre.append(f"caller satisfies modifier {entry.get('name')}")
        elif kind == "inline_check":
            pre.append("caller passes an inline require/if authorization check")
        elif kind == "signature":
            pre.append("a valid signature with nonce/deadline is supplied")
    if signals["value_call"] or str(unit.get("mutability")) == "payable":
        pre.append("attacker holds and/or approved the required token or native value")
    if signals["lifecycle"]:
        pre.append("the contract is in the required lifecycle/phase state")
    return _stm_dedupe_strings(pre, 5)


def _stm_entrypoint_record(unit: dict, signals: dict, *, cap: int = 6) -> dict:
    file = unit.get("file")
    hints = unit.get("hints") or {}
    writes: list[dict] = []
    seen_writes: set[str] = set()
    for write in _stm_state_writes(unit):
        target = write["target"]
        if target in seen_writes:
            continue
        seen_writes.add(target)
        writes.append({"target": target, "line": write.get("line")})
        if len(writes) >= cap:
            break
    reads = _stm_dedupe_strings(
        [
            str(entry.get("target") or entry.get("text") or "")
            for entry in hints.get("oracle_reads") or []
            if isinstance(entry, dict)
        ]
        + [
            str(entry.get("parameter") or "")
            for entry in hints.get("economic_parameters") or []
            if isinstance(entry, dict)
        ]
        + [
            str(entry.get("target") or "")
            for entry in hints.get("cross_contract_calls") or []
            if isinstance(entry, dict)
        ],
        cap,
    )
    authorization = _stm_entry_authorization(unit, signals, cap)
    structural = [
        label
        for label in unit.get("affordances") or []
        if label in _STM_STRUCTURAL_AFFORDANCE_LABELS
    ]
    record = {
        "contract": str(unit.get("contract") or ""),
        "function": str(unit.get("function") or ""),
        "signature": unit.get("signature"),
        "line": unit.get("start_line"),
        "file": file,
        "mutability": unit.get("mutability"),
        "writes": writes,
        "reads": reads,
        "external_boundaries": _stm_entry_boundaries(unit, cap),
        "authorization": authorization,
        "structural_affordances": structural,
        "candidate_preconditions": _stm_preconditions(unit, signals, authorization),
    }
    return {key: value for key, value in record.items() if value not in (None, "", [], {})}


def _stm_order_entrypoints(entrypoints: list[dict], focus: str) -> list[dict]:
    def base_score(entry: dict) -> int:
        return (
            len(entry.get("writes") or [])
            + len(entry.get("external_boundaries") or [])
            + len(entry.get("structural_affordances") or [])
        )

    def focus_boost(entry: dict) -> int:
        if focus == "external_boundary":
            return len(entry.get("external_boundaries") or [])
        if focus == "authorization":
            return len(entry.get("authorization") or [])
        if focus == "accounting":
            return len(entry.get("writes") or [])
        if focus == "state_machine":
            return sum(
                1
                for label in entry.get("structural_affordances") or []
                if "lifecycle" in label
            )
        return 0

    return sorted(
        entrypoints,
        key=lambda entry: (
            -(focus_boost(entry) * 10 + base_score(entry)),
            entry.get("contract") or "",
            entry.get("function") or "",
        ),
    )


def _stm_invariant(
    *,
    kind: str,
    statement: str,
    evidence: list[str],
    falsification_ideas: list[str],
    candidate_observations: list[str],
    contract: str = "",
    function: str = "",
) -> dict:
    return {
        "kind": kind,
        "contract": contract,
        "function": function,
        "statement": statement,
        "source": "generic",
        "evidence": [ref for ref in evidence if ref][:6],
        "falsification_ideas": falsification_ideas[:4],
        "candidate_observations": candidate_observations[:4],
    }


def _stm_state_evidence(states: list[dict], kinds: set[str]) -> list[str]:
    out: list[str] = []
    for state in states:
        if state.get("kind") not in kinds:
            continue
        for ref in state.get("evidence") or []:
            if ref not in out:
                out.append(ref)
        if len(out) >= 6:
            break
    return out[:6]


def _stm_collect_invariants(
    units: list[dict],
    tracked_state: list[dict],
) -> list[dict]:
    invariants: list[dict] = []
    by_contract: dict[str, list[dict]] = {}
    for state in tracked_state:
        by_contract.setdefault(state.get("contract") or "", []).append(state)

    # Contract-level families: conservation + state machine.
    for contract, states in by_contract.items():
        mapping_names = [s["name"] for s in states if s["kind"] == "mapping"]
        aggregate_names = [s["name"] for s in states if s["kind"] == "aggregate"]
        if mapping_names and aggregate_names:
            invariants.append(_stm_invariant(
                kind="conservation",
                contract=contract,
                statement=(
                    f"In {contract}, the sum of per-account entries in "
                    f"{', '.join(mapping_names[:4])} must stay consistent with the "
                    f"aggregate total(s) {', '.join(aggregate_names[:4])}; no path "
                    "should change one without the other."
                ),
                evidence=_stm_state_evidence(states, {"mapping", "aggregate"}),
                falsification_ideas=[
                    f"Drive each entrypoint that writes {mapping_names[0]} and check "
                    f"whether {aggregate_names[0]} moves by the same total.",
                    "Look for an entrypoint that updates a per-account claim without "
                    "updating the aggregate (or vice versa).",
                ],
                candidate_observations=[
                    f"accounting_delta: sum of {mapping_names[0]} entries vs "
                    f"{aggregate_names[0]} before/after a sequence",
                ],
            ))
        lifecycle_names = [s["name"] for s in states if s["kind"] in {"enum", "flag"}]
        if lifecycle_names:
            invariants.append(_stm_invariant(
                kind="state_machine",
                contract=contract,
                statement=(
                    f"In {contract}, the lifecycle state(s) "
                    f"{', '.join(lifecycle_names[:4])} must only transition in the "
                    "intended order — no invalid skip, replay, stale settlement, or "
                    "deadlock."
                ),
                evidence=_stm_state_evidence(states, {"enum", "flag"}),
                falsification_ideas=[
                    "Call lifecycle-changing entrypoints out of order and check "
                    f"whether {lifecycle_names[0]} reaches an inconsistent value.",
                    "Try to re-enter or repeat a one-shot transition "
                    "(settle/finalize/claim) twice.",
                ],
                candidate_observations=[
                    f"log_only: record {lifecycle_names[0]} before/after each step "
                    "and assert only legal transitions occur",
                ],
            ))

    # Function-level families.
    for unit in units:
        signals = _stm_unit_signals(unit)
        contract = str(unit.get("contract") or "")
        function = str(unit.get("function") or "")
        loc = f"{contract}.{function}" if contract else function
        file = unit.get("file")
        line = unit.get("start_line")
        ref = f"{file}:{line}" if file and line else (file or "")

        if (
            (signals["external_boundary"] and signals["has_state_write"])
            or signals["dynamic_target"]
            or signals["unchecked_boundary"]
        ):
            note = ""
            if signals["dynamic_target"]:
                note = " The call target is caller-influenced (dynamic dispatch)."
            elif signals["unchecked_boundary"]:
                note = " A low-level call result appears unchecked."
            invariants.append(_stm_invariant(
                kind="external_call_safety",
                contract=contract,
                function=function,
                statement=(
                    f"{loc} crosses an external/call boundary around state updates; "
                    "a reentrant or callback must not observe inconsistent state "
                    f"(checks-effects-interactions).{note}"
                ),
                evidence=_stm_refs(ref) + _stm_hint_refs(
                    unit,
                    ("external_calls", "value_flows", "callback_surfaces"),
                    3,
                ),
                falsification_ideas=[
                    f"Re-enter {function} from the callee/callback before its state "
                    "writes settle and read the intermediate state.",
                    "Check whether external calls happen before the corresponding "
                    "balance/accounting writes.",
                ],
                candidate_observations=[
                    "custom: deploy a malicious callee that re-enters and assert on "
                    "the drained/inconsistent value",
                ],
            ))

        if signals["arithmetic"] and signals["is_mutating"]:
            invariants.append(_stm_invariant(
                kind="rounding",
                contract=contract,
                function=function,
                statement=(
                    f"{loc} performs division/mulDiv/casts or unchecked math in a "
                    "state-changing path; rounding must not let a caller gain value "
                    "or under-pay."
                ),
                evidence=_stm_refs(ref),
                falsification_ideas=[
                    f"Call {function} with amounts near rounding boundaries (1 wei, "
                    "dust, very large values) and check for a net gain.",
                    "Repeat the operation many times to accumulate favorable "
                    "rounding.",
                ],
                candidate_observations=[
                    "accounting_delta: net attacker balance change after a "
                    "rounding-sensitive sequence",
                ],
            ))

        param_keys = _stm_param_keyed_write_keys(unit)
        addr_params = _stm_address_param_names(unit)
        if (signals["authz"] and param_keys) or (
            signals["signature_gate"] and addr_params
        ):
            subject = ", ".join(param_keys or addr_params[:2])
            invariants.append(_stm_invariant(
                kind="authorization_binding",
                contract=contract,
                function=function,
                statement=(
                    f"{loc} authorizes one subject but acts on a caller-supplied "
                    f"account ({subject}); the authorized subject must equal the "
                    "account whose state is modified, and any signature must bind "
                    "all critical fields."
                ),
                evidence=_stm_refs(ref) + _stm_hint_refs(
                    unit, ("role_gates", "authorization_checks"), 3
                ),
                falsification_ideas=[
                    f"Call {function} authorizing yourself but passing another "
                    "account as the target; check whose state changes.",
                    "Check that the signed/role-checked address is the same one used "
                    "as the state key.",
                ],
                candidate_observations=[
                    "custom: assert the victim's balance/claim changes while only "
                    "the attacker authorized the call",
                ],
            ))

        if signals["signature_gate"]:
            invariants.append(_stm_invariant(
                kind="replay_protection",
                contract=contract,
                function=function,
                statement=(
                    f"{loc} consumes signed authorization; signatures must not be "
                    "replayable — a nonce, deadline, and domain separator must bind "
                    "each use."
                ),
                evidence=_stm_refs(ref) + _stm_hint_refs(
                    unit, ("authorization_checks",), 3
                ),
                falsification_ideas=[
                    f"Submit the same signature to {function} twice and check "
                    "whether it succeeds both times.",
                    "Replay a signature across chains/contracts when the domain "
                    "separator is missing.",
                ],
                candidate_observations=[
                    "custom: assert a second submission of the same signed payload "
                    "reverts",
                ],
            ))

        if signals["batch"] and (signals["has_state_write"] or signals["authz"]):
            invariants.append(_stm_invariant(
                kind="bounds",
                contract=contract,
                function=function,
                statement=(
                    f"{loc} loops over caller-influenced items with per-item "
                    "accounting/authorization; every element must be bounds- and "
                    "authorization-checked, with no duplicate or skipped item."
                ),
                evidence=_stm_refs(ref),
                falsification_ideas=[
                    f"Call {function} with duplicate, empty, or oversized arrays and "
                    "check per-item accounting.",
                    "Check whether one element can be processed twice or bypass the "
                    "per-item check.",
                ],
                candidate_observations=[
                    "accounting_delta: per-item vs aggregate effect across a crafted "
                    "batch",
                ],
            ))

        if _stm_has_liveness_terms(unit) and (
            signals["has_state_write"] or signals["authz"]
        ):
            invariants.append(_stm_invariant(
                kind="liveness",
                contract=contract,
                function=function,
                statement=(
                    f"{loc} gates a queue/deadline/pause/finalization flow; funds or "
                    "progress must not become permanently locked (no deadlock or "
                    "stuck queue)."
                ),
                evidence=_stm_refs(ref),
                falsification_ideas=[
                    f"Drive {function} into a paused/expired/empty-queue state and "
                    "check whether legitimate funds can still exit.",
                    "Check whether a single actor can wedge the queue/finalization "
                    "for everyone.",
                ],
                candidate_observations=[
                    "log_only: assert a legitimate withdrawal/claim still succeeds "
                    "after the lifecycle edge case",
                ],
            ))

    return invariants


def _stm_finalize_invariants(
    invariants: list[dict],
    focus: str,
    max_items: int,
) -> list[dict]:
    seen: set[tuple] = set()
    deduped: list[dict] = []
    for invariant in invariants:
        key = (
            invariant["kind"],
            invariant.get("contract", ""),
            invariant.get("function", ""),
        )
        if key in seen:
            continue
        seen.add(key)
        deduped.append(invariant)
    focus_kinds = _STM_FOCUS_KINDS.get(focus, ())

    def sort_key(invariant: dict) -> tuple:
        kind = invariant["kind"]
        focus_rank = 0 if kind in focus_kinds else 1
        kind_rank = (
            _STM_INVARIANT_KIND_ORDER.index(kind)
            if kind in _STM_INVARIANT_KIND_ORDER
            else 99
        )
        return (
            focus_rank,
            kind_rank,
            invariant.get("contract", ""),
            invariant.get("function", ""),
        )

    deduped.sort(key=sort_key)
    deduped = deduped[:max_items]
    for index, invariant in enumerate(deduped, start=1):
        invariant["id"] = f"inv-{index:03d}"
    return deduped


def _stm_required_setup(kind: str, contract: str) -> list[str]:
    base = [
        f"Deploy {contract or 'the target'} with a funded attacker account and at "
        "least one victim/other account."
    ]
    if kind in {"conservation", "rounding", "bounds"}:
        base.append(
            "Snapshot per-account and aggregate accounting before/after the sequence."
        )
    if kind == "external_call_safety":
        base.append(
            "Provide a malicious callee/token that re-enters the target during the "
            "external call."
        )
    if kind in {"authorization_binding", "replay_protection"}:
        base.append(
            "Prepare attacker and victim identities (and a reusable signed payload "
            "for replay)."
        )
    if kind in {"state_machine", "liveness"}:
        base.append(
            "Reach the relevant lifecycle/queue/deadline edge state before "
            "exercising the action."
        )
    return base[:5]


def _stm_experiment_prompts(
    invariants: list[dict],
    entrypoints: list[dict],
    *,
    max_items: int,
) -> list[dict]:
    by_contract: dict[str, list[dict]] = {}
    for entry in entrypoints:
        by_contract.setdefault(entry.get("contract") or "", []).append(entry)
    prompts: list[dict] = []
    for invariant in invariants:
        contract = invariant.get("contract") or ""
        function = invariant.get("function") or ""
        if function:
            targets = [f"{contract}.{function}" if contract else function]
        else:
            targets = [
                f"{entry.get('contract')}.{entry.get('function')}"
                for entry in by_contract.get(contract, [])[:4]
            ]
        title = f"Falsify {invariant['kind']} in {contract or 'scope'}"
        if function:
            title += f".{function}"
        prompts.append({
            "title": title,
            "target_actions": targets[:6] or [
                "(no public entrypoint resolved; bind targets manually)"
            ],
            "objective": f"Try to falsify: {invariant['statement']}",
            "probe_strategy": _STM_PROBE_STRATEGY.get(invariant["kind"], "log_only"),
            "required_setup": _stm_required_setup(invariant["kind"], contract),
            "notes": [
                "Planning prompt only — turn it into a runnable PoC with "
                "compose_sequence_experiment / create_experiment.",
                "This is not evidence.",
            ],
        })
        if len(prompts) >= max_items:
            break
    return prompts


def _stm_lens_evidence(units: list[dict], term_re: "re.Pattern") -> list[dict]:
    out: list[dict] = []
    for unit in units:
        function = str(unit.get("function") or "")
        if not function or not term_re.search(function):
            continue
        file = unit.get("file")
        line = unit.get("start_line")
        out.append({
            "function": f"{unit.get('contract')}.{function}",
            "ref": f"{file}:{line}" if file and line else (file or ""),
        })
        if len(out) >= 6:
            break
    return out


def _stm_lenses(units: list[dict]) -> dict:
    """Optional protocol lenses — attached ONLY when source function names carry
    the evidence. Unknown code gets no lens (never defaults to vault); lenses are
    metadata beside the generic invariants, not a replacement for them."""
    lenses: dict = {}
    haystack = " ".join(
        f"{unit.get('contract', '')}.{unit.get('function', '')}" for unit in units
    ).lower()

    if (
        re.search(r"deposit|mint|supply", haystack)
        and re.search(r"withdraw|redeem|burn", haystack)
        and re.search(
            r"share|asset|totalassets|convertto|previewdeposit|previewredeem|"
            r"pricepershare",
            haystack,
        )
    ):
        lenses["vault_like"] = {
            "evidence": _stm_lens_evidence(
                units,
                re.compile(
                    r"deposit|withdraw|redeem|mint|convertto|preview|totalassets",
                    re.IGNORECASE,
                ),
            ),
            "note": (
                "Optional vault interpretation; the generic invariants above still "
                "apply."
            ),
        }
    if re.search(r"borrow", haystack) and re.search(
        r"repay|liquidat|collateral|health", haystack
    ):
        lenses["lending_like"] = {
            "evidence": _stm_lens_evidence(
                units,
                re.compile(r"borrow|repay|liquidat|collateral|health", re.IGNORECASE),
            ),
            "note": (
                "Optional lending interpretation; the generic invariants above "
                "still apply."
            ),
        }
    if re.search(r"queue|enqueue|dequeue|request", haystack) and re.search(
        r"claim|process|finali[sz]e|fulfill|dequeue", haystack
    ):
        lenses["queue_like"] = {
            "evidence": _stm_lens_evidence(
                units,
                re.compile(
                    r"queue|enqueue|dequeue|request|claim|process|finali|fulfill",
                    re.IGNORECASE,
                ),
            ),
            "note": (
                "Optional queue interpretation; the generic invariants above still "
                "apply."
            ),
        }
    return lenses


def _stm_compact_tracked(state: dict) -> dict:
    return {
        key: value
        for key, value in {
            "name": state.get("name"),
            "contract": state.get("contract"),
            "kind": state.get("kind"),
            "evidence": (state.get("evidence") or [])[:3],
        }.items()
        if value not in (None, "", [], {})
    }


def _stm_compact_entrypoint(entry: dict) -> dict:
    return {
        key: value
        for key, value in {
            "contract": entry.get("contract"),
            "function": entry.get("function"),
            "signature": entry.get("signature"),
            "line": entry.get("line"),
            "writes": [write.get("target") for write in (entry.get("writes") or [])[:4]],
            "authorization": [
                auth.get("name") or auth.get("kind")
                for auth in (entry.get("authorization") or [])[:4]
            ],
            "structural_affordances": (entry.get("structural_affordances") or [])[:6],
            "candidate_preconditions": (entry.get("candidate_preconditions") or [])[:3],
        }.items()
        if value not in (None, "", [], {})
    }


def _stm_compact_invariant(invariant: dict) -> dict:
    return {
        key: value
        for key, value in {
            "id": invariant.get("id"),
            "kind": invariant.get("kind"),
            "statement": _truncate_response_text(invariant.get("statement"), 260),
            "evidence": (invariant.get("evidence") or [])[:3],
            "falsification_ideas": (invariant.get("falsification_ideas") or [])[:2],
        }.items()
        if value not in (None, "", [], {})
    }


async def _extract_state_transition_model(container: AuditContainer, args: dict) -> str:
    try:
        root = _normalize_action_source_path(args.get("path", "/audit"))
        files_arg = args.get("files")
        files = _require_list(files_arg, "files") if files_arg is not None else None
    except ValueError as exc:
        return f"Error: {exc}"

    title = str(args.get("title") or "").strip()
    contract_filter = str(args.get("contract") or "").strip()
    focus = str(args.get("focus") or "auto").strip().lower()
    if focus not in _STM_FOCUS_OPTIONS:
        focus = "auto"
    try:
        max_items = min(max(int(args.get("max_items", 50)), 1), 200)
    except (TypeError, ValueError):
        max_items = 50
    record_result = bool(args.get("record_result", True))
    action_space_ref = str(args.get("action_space") or "").strip()
    protocol_graph_ref = str(args.get("protocol_graph") or "").strip()
    slice_hint = _stm_source_slice_hint(args.get("source_slice"))
    function_filter = slice_hint.get("function", "")
    if slice_hint.get("contract") and not contract_filter:
        contract_filter = slice_hint["contract"]
    if files is None and slice_hint.get("path"):
        files = [slice_hint["path"]]

    blockers: list[str] = []
    read_errors: list[dict] = []

    try:
        source_files, truncated_files = await _discover_action_source_files(
            container,
            root=root,
            files=files,
            include_tests=False,
            max_files=200,
            max_roots=12,
        )
    except ValueError as exc:
        return f"Error: {exc}"

    units: list[dict] = []
    for path in source_files:
        try:
            source = await container.read_file(path)
        except FileNotFoundError as exc:
            read_errors.append({"path": path, "error": str(exc)})
            continue
        units.extend(_iter_function_units(path, source))

    action_space = None
    action_space_path = ""
    if action_space_ref:
        try:
            action_space_path, action_space = await _load_action_space(
                container, action_space_ref
            )
        except (FileNotFoundError, ValueError) as exc:
            blockers.append(
                f"action_space {action_space_ref} could not be loaded: {exc}"
            )
    protocol_graph = None
    protocol_graph_path = ""
    if protocol_graph_ref:
        try:
            protocol_graph_path, protocol_graph = await _load_protocol_graph(
                container, protocol_graph_ref
            )
        except (FileNotFoundError, ValueError) as exc:
            blockers.append(
                f"protocol_graph {protocol_graph_ref} could not be loaded: {exc}"
            )

    used_action_space_fallback = False
    if not units and isinstance(action_space, dict):
        for action in action_space.get("actions") or []:
            if isinstance(action, dict):
                units.append(_stm_unit_from_action(action))
        used_action_space_fallback = bool(units)

    if contract_filter:
        units = [
            unit
            for unit in units
            if str(unit.get("contract") or "").lower() == contract_filter.lower()
        ]
    if function_filter:
        units = [
            unit
            for unit in units
            if str(unit.get("function") or "").lower() == function_filter.lower()
        ]

    unit_signals = [(unit, _stm_unit_signals(unit)) for unit in units]
    tracked_state = _stm_build_tracked_state(
        units, protocol_graph=protocol_graph, max_items=max_items
    )
    entrypoints = _stm_order_entrypoints(
        [
            _stm_entrypoint_record(unit, signals)
            for unit, signals in unit_signals
            if signals["is_entrypoint"] and signals["is_mutating"]
        ],
        focus,
    )[:max_items]
    invariants = _stm_finalize_invariants(
        _stm_collect_invariants(units, tracked_state), focus, max_items
    )
    experiment_prompts = _stm_experiment_prompts(
        invariants, entrypoints, max_items=min(max_items, 12)
    )
    lenses = _stm_lenses(units)

    if not source_files and not used_action_space_fallback:
        status = "not_found"
        blockers.append(f"No Solidity source files found under {root}.")
    elif not units:
        status = "partial"
        blockers.append("Source files were scanned but no function units could be parsed.")
    elif not (tracked_state or entrypoints or invariants):
        status = "partial"
        blockers.append(
            "Functions were parsed but no tracked state, entrypoints, or invariants "
            "were derived."
        )
    else:
        status = "observed"
    if read_errors:
        blockers.append(f"{len(read_errors)} source file(s) could not be read.")
    if function_filter and not units:
        blockers.append(f"No function named {function_filter} matched the scope.")
    elif contract_filter and not units:
        blockers.append(f"No contract named {contract_filter} matched the scope.")

    contracts = sorted(
        {str(unit.get("contract") or "") for unit in units if unit.get("contract")}
    )
    scope = {
        key: value
        for key, value in {
            "path": root,
            "contract": contract_filter or None,
            "focus": focus,
            "files_requested": len(source_files),
            "files_scanned": len(source_files) - len(read_errors),
            "files_truncated_by_limit": truncated_files,
            "read_errors": read_errors,
            "contracts": contracts,
            "action_space": action_space_path or (action_space_ref or None),
            "protocol_graph": protocol_graph_path or (protocol_graph_ref or None),
            "source_slice": slice_hint or None,
            "used_action_space_fallback": used_action_space_fallback or None,
        }.items()
        if value not in (None, "", [], {})
    }
    notes = [
        "This is planning context, not evidence.",
        "Invariants are generic hypotheses to falsify with experiments; protocol "
        "lenses are optional and appear only when source evidence supports them.",
    ]

    state = await _load_campaign_state(container)
    model_id = _next_campaign_id(state, "state_transition_model")
    model_path = f"/workspace/campaign/state-transition-models/{model_id}.json"
    invariant_kinds = sorted({invariant["kind"] for invariant in invariants})
    summary = {
        "tracked_state": len(tracked_state),
        "entrypoints": len(entrypoints),
        "candidate_invariants": len(invariants),
        "invariant_kinds": invariant_kinds,
        "experiment_prompts": len(experiment_prompts),
        "lenses": sorted(lenses.keys()),
        "contracts": len(contracts),
        "files_scanned": len(source_files) - len(read_errors),
    }
    model = {
        "state_transition_model_id": model_id,
        "id": model_id,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "status": status,
        "title": title or f"State-transition model: {root}",
        "scope": scope,
        "summary": summary,
        "tracked_state": tracked_state,
        "entrypoints": entrypoints,
        "candidate_invariants": invariants,
        "experiment_prompts": experiment_prompts,
        "lenses": lenses,
        "blockers": blockers,
        "notes": notes,
    }
    await container.write_file(
        model_path, json.dumps(model, indent=2, sort_keys=True) + "\n"
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if record_result:
        result_id = await _record_result_artifact(
            container,
            title=f"State-transition model: {root}",
            content=(
                f"State-transition model: {model_id}\n"
                f"Path: {model_path}\n"
                f"Status: {status}\n"
                f"Contracts: {len(contracts)}\n"
                f"Tracked state: {len(tracked_state)}\n"
                f"Entrypoints: {len(entrypoints)}\n"
                f"Candidate invariants: {len(invariants)} "
                f"({', '.join(invariant_kinds) or 'none'})\n"
                f"Experiment prompts: {len(experiment_prompts)}\n"
                f"Lenses: {', '.join(sorted(lenses.keys())) or 'none'}\n"
                "Planning context for hypotheses/experiments; not vulnerability "
                "evidence."
            ),
            evidence=[model_path],
            related_ids=[],
            status="blocked" if status == "not_found" else "observed",
        )

    response_items = min(max_items, 8)
    prompt_items = max(3, response_items // 2)
    response = {
        "state_transition_model_id": model_id,
        "path": model_path,
        "result_id": result_id or None,
        "status": status,
        "focus": focus,
        "scope": scope,
        "summary": summary,
        "tracked_state": [
            _stm_compact_tracked(state) for state in tracked_state[:response_items]
        ],
        "entrypoints": [
            _stm_compact_entrypoint(entry) for entry in entrypoints[:response_items]
        ],
        "candidate_invariants": [
            _stm_compact_invariant(invariant)
            for invariant in invariants[:response_items]
        ],
        "experiment_prompts": experiment_prompts[:prompt_items],
        "lenses": {name: True for name in sorted(lenses.keys())},
        "blockers": blockers,
        "notes": notes,
        "omitted_from_response": {
            "tracked_state": max(0, len(tracked_state) - response_items),
            "entrypoints": max(0, len(entrypoints) - response_items),
            "candidate_invariants": max(0, len(invariants) - response_items),
            "experiment_prompts": max(0, len(experiment_prompts) - prompt_items),
            "note": "Open the artifact path for the full model.",
        },
    }
    return json.dumps(response, indent=2, sort_keys=True)


# ── source_slice: compact, focused Solidity slices ───────────────────────

_SOURCE_SLICE_INCLUDE_OPTIONS = (
    "body",
    "modifiers",
    "state_hints",
    "external_calls",
    "events",
    "authorization",
    "value_flows",
    "oracle_reads",
    "callback_surfaces",
)

# `include` selector -> the `_collect_line_hints` group it surfaces in the
# response `hints` map. `body`/`modifiers` are structural (handled separately);
# the rest each map to exactly one hint group.
_SOURCE_SLICE_HINT_GROUPS = {
    "value_flows": "value_flows",
    "external_calls": "external_calls",
    "state_hints": "state_mutations",
    "events": "events",
    "oracle_reads": "oracle_reads",
    "callback_surfaces": "callback_surfaces",
    "authorization": "authorization_checks",
}

_SOURCE_SLICE_MAX_CANDIDATES = 12
_SOURCE_SLICE_MAX_FILES = 400
_SOURCE_SLICE_MAX_ROOTS = 24


def _iter_function_units(path: str, source: str) -> list[dict]:
    """Parse `source` into per-function units with line spans + line hints.

    Reuses the same declaration patterns and leaf helpers as
    `_parse_action_space_file` (contract ranges, `_function_unit_from_match`,
    affordance + line-hint heuristics) so it never duplicates parsing logic; it
    keeps the `[start_line, end_line]` span per function instead of folding
    everything into an aggregate, which is what `source_slice` resolves against.
    """
    if len(source) > _ACTION_MAX_FILE_CHARS:
        source = source[:_ACTION_MAX_FILE_CHARS]
    starts = _line_starts(source)
    scan_source = _strip_comments_preserve_layout(source)
    units: list[dict] = []
    for contract in _contract_ranges(source, starts):
        block_scan = scan_source[contract["start"]:contract["end"]]
        matches = list(_FUNCTION_DECL_RE.finditer(block_scan))
        matches.extend(_SPECIAL_FUNCTION_DECL_RE.finditer(block_scan))
        matches.sort(key=lambda item: item.start())
        for match in matches:
            unit = _function_unit_from_match(
                match,
                contract=contract,
                source=source,
                line_starts=starts,
                max_items=12,
            )
            units.append({
                "file": path,
                "contract": unit["contract"],
                "contract_kind": unit["contract_kind"],
                "function": unit["function"],
                "signature": _action_signature(unit),
                "visibility": unit["visibility"],
                "mutability": unit["mutability"],
                "modifiers": unit["modifiers"],
                "parameters": unit["parameters"],
                "returns": unit["returns"],
                "affordances": unit["affordances"],
                "hints": unit["hints"],
                "start_line": unit["line"],
                "end_line": unit["end_line"],
            })
    return units


def _modifier_definition_ranges(
    source: str,
    line_starts: list[int],
    names: list[str],
) -> list[dict]:
    """Locate `modifier <name>` definitions in `source` so a slice can point at
    the authorization gates the target function applies."""
    ranges: list[dict] = []
    if not names:
        return ranges
    scan = _strip_comments_preserve_layout(source)
    for name in _dedupe_text(names):
        match = re.search(rf"\bmodifier\s+{re.escape(name)}\b", scan)
        if not match:
            continue
        start_line = _line_at(line_starts, match.start())
        end_line = start_line
        open_index = scan.find("{", match.end())
        semicolon_index = scan.find(";", match.end())
        if open_index != -1 and (
            semicolon_index == -1 or open_index < semicolon_index
        ):
            close_index = _find_matching_brace(source, open_index)
            end_line = _line_at(line_starts, close_index)
        ranges.append({
            "kind": "modifier",
            "name": name,
            "line_range": {"start": start_line, "end": end_line},
        })
    return ranges


def _source_slice_error(message: str, **extra) -> str:
    payload = {"status": "error", "error": message}
    payload.update(extra)
    return json.dumps(payload, indent=2, sort_keys=True)


async def _source_slice(container: AuditContainer, args: dict) -> str:
    try:
        root = _normalize_action_source_path(args.get("path", "/audit"))
    except ValueError as exc:
        return _source_slice_error(str(exc))

    contract_filter = str(args.get("contract") or "").strip()
    function_filter = str(args.get("function") or "").strip()

    line_arg = args.get("line")
    line = None
    if line_arg not in (None, ""):
        try:
            line = int(line_arg)
        except (TypeError, ValueError):
            return _source_slice_error("line must be an integer")

    if not contract_filter and not function_filter and line is None:
        return _source_slice_error(
            "provide at least one of contract, function, or line to locate a slice"
        )

    try:
        context_lines = _coerce_bounded_int_arg(
            args.get("context_lines"),
            "context_lines",
            default=20,
            minimum=0,
            maximum=120,
        )
        max_chars = _coerce_bounded_int_arg(
            args.get("max_chars"),
            "max_chars",
            default=12000,
            minimum=500,
            maximum=50000,
        )
        record_result = _coerce_bool_arg(
            args.get("record_result"), "record_result", default=False
        )
        include_arg = args.get("include")
        include_list = (
            _require_list(include_arg, "include") if include_arg is not None else None
        )
    except ValueError as exc:
        return _source_slice_error(str(exc))

    if include_list:
        selectors = {
            str(item).strip().lower() for item in include_list if str(item).strip()
        }
        unknown = sorted(selectors - set(_SOURCE_SLICE_INCLUDE_OPTIONS))
        if unknown:
            return _source_slice_error(
                "unknown include selectors: " + ", ".join(unknown),
                allowed_include=list(_SOURCE_SLICE_INCLUDE_OPTIONS),
            )
    else:
        selectors = set(_SOURCE_SLICE_INCLUDE_OPTIONS)
    if not selectors:
        selectors = set(_SOURCE_SLICE_INCLUDE_OPTIONS)

    # Resolve candidate source files: a specific .sol is read directly; a root is
    # discovered with the same pruning map_action_space uses.
    file_sources: list[tuple[str, str]] = []
    read_errors: list[dict] = []
    if root.endswith(".sol"):
        try:
            file_sources.append((root, await container.read_file(root)))
        except FileNotFoundError as exc:
            return json.dumps({
                "status": "not_found",
                "path": root,
                "contract": contract_filter or None,
                "function": function_filter or None,
                "line": line,
                "files_scanned": 0,
                "message": f"source file not found: {exc}",
            }, indent=2, sort_keys=True)
    else:
        try:
            discovered, _truncated = await _discover_action_source_files(
                container,
                root=root,
                files=None,
                include_tests=False,
                max_files=_SOURCE_SLICE_MAX_FILES,
                max_roots=_SOURCE_SLICE_MAX_ROOTS,
            )
        except ValueError as exc:
            return _source_slice_error(str(exc))
        for candidate in discovered:
            try:
                file_sources.append((candidate, await container.read_file(candidate)))
            except FileNotFoundError as exc:
                read_errors.append({"path": candidate, "error": str(exc)})

    units: list[dict] = []
    for candidate, source in file_sources:
        units.extend(_iter_function_units(candidate, source))

    # Filter in priority order: contract, then function, then line. A line given
    # alongside a name only narrows when some matched function contains it.
    candidates = units
    if contract_filter:
        candidates = [
            unit for unit in candidates
            if unit["contract"].lower() == contract_filter.lower()
        ]
    if function_filter:
        candidates = [
            unit for unit in candidates
            if unit["function"].lower() == function_filter.lower()
        ]
    if line is not None:
        containing = [
            unit for unit in candidates
            if unit["start_line"] <= line <= unit["end_line"]
        ]
        if containing:
            candidates = containing
        elif not (contract_filter or function_filter):
            candidates = []

    deduped: list[dict] = []
    seen_keys: set[tuple] = set()
    for unit in candidates:
        key = (unit["file"], unit["contract"], unit["function"], unit["start_line"])
        if key in seen_keys:
            continue
        seen_keys.add(key)
        deduped.append(unit)

    if not deduped:
        return json.dumps({
            "status": "not_found",
            "path": root,
            "contract": contract_filter or None,
            "function": function_filter or None,
            "line": line,
            "files_scanned": len(file_sources),
            "read_errors": read_errors,
            "message": (
                "No function matched the contract/function/line filters. Check "
                "the name or line, or widen path to a containing source root."
            ),
        }, indent=2, sort_keys=True)

    if len(deduped) > 1:
        return json.dumps({
            "status": "ambiguous",
            "path": root,
            "contract": contract_filter or None,
            "function": function_filter or None,
            "line": line,
            "candidate_count": len(deduped),
            "candidates": [
                {
                    "contract": unit["contract"],
                    "function": unit["function"],
                    "signature": unit["signature"],
                    "file": unit["file"],
                    "line_range": {
                        "start": unit["start_line"],
                        "end": unit["end_line"],
                    },
                    "visibility": unit["visibility"],
                    "mutability": unit["mutability"],
                }
                for unit in deduped[:_SOURCE_SLICE_MAX_CANDIDATES]
            ],
            "candidates_omitted": max(
                0, len(deduped) - _SOURCE_SLICE_MAX_CANDIDATES
            ),
            "message": (
                "Multiple functions matched. Add contract, function, or line to "
                "select one."
            ),
        }, indent=2, sort_keys=True)

    target = deduped[0]
    target_source = dict(file_sources).get(target["file"], "")[:_ACTION_MAX_FILE_CHARS]
    source_lines = target_source.split("\n")
    total_lines = len(source_lines)

    result: dict = {
        "status": "observed",
        "path": target["file"],
        "contract": target["contract"],
        "function": target["function"],
        "line_range": {"start": target["start_line"], "end": target["end_line"]},
        "signature": target["signature"],
        "visibility": target["visibility"],
        "mutability": target["mutability"],
        "affordances": target["affordances"],
    }
    # Parameter/return metadata is authoritative source-level signature data
    # (always parsed, never gated by the hint/body include selectors). Exposing
    # it lets synthesize_args consume a recorded source_slice directly and lets a
    # genuine no-arg function (parameters == []) be distinguished from unknown
    # metadata downstream.
    result["parameters"] = [
        {
            "name": param.get("name"),
            "raw": param.get("raw"),
            "type": _parameter_type_text(param),
        }
        for param in (target.get("parameters") or [])
        if isinstance(param, dict)
    ]
    returns = str(target.get("returns") or "").strip()
    if returns:
        result["returns"] = returns
    omitted: dict = {}

    if "modifiers" in selectors:
        result["modifiers"] = target["modifiers"]
    elif target["modifiers"]:
        omitted["modifiers"] = len(target["modifiers"])

    if "body" in selectors:
        body_start = max(1, target["start_line"] - context_lines)
        body_end = min(total_lines, target["end_line"] + context_lines)
        body_text = "\n".join(source_lines[body_start - 1:body_end])
        if len(body_text) > max_chars:
            omitted["body_chars"] = len(body_text) - max_chars
            body_text = (
                body_text[:max_chars]
                + f"\n... [slice truncated to {max_chars} chars] ..."
            )
        result["body"] = body_text
        result["body_line_range"] = {"start": body_start, "end": body_end}
    else:
        omitted["body"] = "not requested (add 'body' to include)"

    hints_out: dict = {}
    excluded_hint_groups: list[str] = []
    for selector, group in _SOURCE_SLICE_HINT_GROUPS.items():
        values = target["hints"].get(group) or []
        if selector in selectors:
            if values:
                hints_out[group] = [_compact_hint_entry(item) for item in values]
        elif values:
            excluded_hint_groups.append(group)
    result["hints"] = hints_out
    if excluded_hint_groups:
        omitted["excluded_hint_groups"] = sorted(set(excluded_hint_groups))

    result["related_ranges"] = _modifier_definition_ranges(
        target_source, _line_starts(target_source), target["modifiers"]
    )
    if read_errors:
        omitted["read_errors"] = len(read_errors)
    result["omitted"] = omitted

    if record_result:
        state = await _load_campaign_state(container)
        slice_id = _next_campaign_id(state, "source_slice")
        slice_path = f"/workspace/campaign/source-slices/{slice_id}.json"
        artifact = {
            "id": slice_id,
            "created_at": datetime.now(timezone.utc).isoformat(),
            **result,
        }
        await container.write_file(
            slice_path,
            json.dumps(artifact, indent=2, sort_keys=True) + "\n",
        )
        await _save_campaign_state(container, state)
        result_id = await _record_result_artifact(
            container,
            title=f"Source slice: {target['contract']}::{target['function']}",
            content=(
                f"Source slice: {slice_id}\n"
                f"Path: {slice_path}\n"
                f"Target: {target['contract']}::{target['signature']}\n"
                f"File: {target['file']}\n"
                f"Lines: {target['start_line']}-{target['end_line']}\n"
                "Read-only cognitive slice; not evidence on its own."
            ),
            evidence=[slice_path],
            related_ids=[],
            status="observed",
        )
        result["slice_id"] = slice_id
        result["artifact_path"] = slice_path
        result["result_id"] = result_id

    return json.dumps(result, indent=2, sort_keys=True)


def _profile_matches_focus(profile: dict, focus_contracts: set[str]) -> bool:
    if not focus_contracts:
        return True
    values = {
        str(profile.get("contract") or "").strip().lower(),
        str(profile.get("profile") or "").strip().lower(),
    }
    return bool(values.intersection(focus_contracts))


def _action_matches_profile(action: dict, profile: dict) -> bool:
    contract = str(action.get("contract") or "").strip().lower()
    profile_contract = str(profile.get("contract") or "").strip().lower()
    if contract and profile_contract and contract == profile_contract:
        return True
    file_path = str(action.get("file") or "")
    src_path = str(profile.get("src") or "").rstrip("/")
    return bool(src_path and file_path.startswith(src_path + "/"))


def _action_space_contract_bases(action_space: dict | None) -> dict[tuple[str, str], set[str]]:
    bases: dict[tuple[str, str], set[str]] = {}
    if not action_space:
        return bases
    for contract in action_space.get("contracts") or []:
        if not isinstance(contract, dict):
            continue
        file_path = str(contract.get("file") or "")
        name = str(contract.get("name") or "").strip()
        if not file_path or not name:
            continue
        bases[(file_path, name.lower())] = {
            str(item).strip().lower()
            for item in contract.get("bases") or []
            if str(item).strip()
        }
    return bases


def _contract_inherits_contract(
    *,
    file_path: str,
    child_contract: str,
    base_contract: str,
    bases_by_contract: dict[tuple[str, str], set[str]],
) -> bool:
    child = child_contract.strip().lower()
    target = base_contract.strip().lower()
    if not child or not target:
        return False
    pending = list(bases_by_contract.get((file_path, child), set()))
    seen = set()
    while pending:
        name = pending.pop()
        if name in seen:
            continue
        seen.add(name)
        if name == target:
            return True
        direct_bases = set(bases_by_contract.get((file_path, name), set()))
        for (_contract_file, contract_name), base_names in bases_by_contract.items():
            if contract_name == name:
                direct_bases.update(base_names)
        pending.extend(direct_bases - seen)
    return False


def _action_source_relation(
    action: dict,
    profile: dict,
    *,
    bases_by_contract: dict[tuple[str, str], set[str]],
) -> dict:
    action_contract = str(action.get("contract") or "").strip()
    profile_contract = str(profile.get("contract") or "").strip()
    file_path = str(action.get("file") or "").strip()
    src_path = str(profile.get("src") or "").rstrip("/")
    relation = {
        "kind": "unknown",
        "executable_source": False,
        "reasons": [],
    }
    if not action_contract or not profile_contract:
        relation["reasons"].append("missing action or profile contract")
        return relation
    if action_contract.lower() == profile_contract.lower():
        relation.update({"kind": "profile_contract", "executable_source": True})
        relation["reasons"].append("action contract matches deployed profile contract")
        return relation
    if action.get("contract_kind") == "interface":
        relation.update({"kind": "source_interface_only", "executable_source": False})
        relation["reasons"].append("action is declared on an imported/source interface")
        return relation
    if action.get("contract_kind") == "library":
        relation.update({"kind": "source_library_only", "executable_source": False})
        relation["reasons"].append("action is declared on a library, not the deployed profile contract")
        return relation
    if src_path and file_path.startswith(src_path + "/"):
        if _contract_inherits_contract(
            file_path=file_path,
            child_contract=profile_contract,
            base_contract=action_contract,
            bases_by_contract=bases_by_contract,
        ):
            relation.update({"kind": "inherited_base", "executable_source": True})
            relation["reasons"].append("action contract is inherited by deployed profile contract")
            return relation
        relation.update({"kind": "source_dependency_only", "executable_source": False})
        relation["reasons"].append(
            "action is from another contract in the same source root but is not inherited by the deployed profile contract"
        )
        return relation
    relation.update({"kind": "external_source", "executable_source": False})
    relation["reasons"].append("action source file is outside the deployed profile source root")
    return relation


def _parameter_type(raw: str) -> str:
    text = " ".join(str(raw or "").split())
    text = re.sub(r"\b(calldata|memory|storage|payable)\b", " ", text)
    text = " ".join(text.split())
    parts = text.split()
    if len(parts) >= 2 and re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", parts[-1]):
        return " ".join(parts[:-1])
    return text


def _action_signature(action: dict) -> str:
    function = str(action.get("function") or "").strip()
    if function in {"receive", "fallback"}:
        return function
    parameter_types = [
        _parameter_type(str(param.get("raw") or ""))
        for param in action.get("parameters") or []
        if isinstance(param, dict)
    ]
    return f"{function}({','.join(parameter_types)})"


def _action_arg_names(action: dict) -> list[str]:
    names = []
    for index, param in enumerate(action.get("parameters") or [], start=1):
        if not isinstance(param, dict):
            continue
        name = str(param.get("name") or "").strip()
        names.append(name or f"arg{index}")
    return names


def _action_logical_key(action: dict) -> str:
    return _coverage_action_key(action)


def _live_reachability_clone_family_key(
    *,
    action: dict,
    profile: dict,
    target_binding: dict,
    probe: dict,
    reachability: dict,
) -> str:
    values = probe.get("values") or {}
    fingerprint = (
        str(target_binding.get("code_hash") or "").strip()
        or str(values.get("code_sha256_16") or "").strip()
        or str(profile.get("src") or "").strip()
    )
    if not fingerprint:
        return ""
    fingerprint = _coverage_normalize_text(fingerprint).replace(" ", "_")
    reachability_kind = str(reachability.get("kind") or "unknown").strip() or "unknown"
    return (
        f"{fingerprint}:{reachability_kind}:"
        f"{_action_family_from_action_key(_action_logical_key(action))}"
    )


def _action_stable_uid(action: dict) -> str:
    file_part = str(action.get("file") or "").strip()
    line = str(action.get("line") or "").strip()
    return ":".join(
        item for item in (
            file_part,
            _coverage_action_key(action),
            line,
        )
        if item
    )


_STRONG_GATE_TOKENS = (
    "onlyowner",
    "onlyrole",
    "onlyadmin",
    "onlygovernor",
    "onlyguardian",
    "onlykeeper",
    "onlymanager",
    "onlyoperator",
    "onlyexecutor",
    "onlycontroller",
    "onlyvault",
    "onlyendpoint",
    "onlylzendpoint",
    "requiresauth",
    "requiresauthority",
    "requiresrole",
    "restricted",
)


def _action_strong_gate_modifiers(modifiers: list[str]) -> list[str]:
    gated = []
    for modifier in modifiers:
        compact = re.sub(r"[^a-z0-9]", "", str(modifier).lower())
        if compact == "auth" or any(token in compact for token in _STRONG_GATE_TOKENS):
            gated.append(str(modifier))
    return gated


_SIGNATURE_GATE_TERMS = (
    "ecrecover",
    "ecdsa",
    "isvalidsignature",
    "domainseparator",
    "hashtypeddata",
    "nonces",
    "recover(",
)


def _action_has_signature_gate(action: dict) -> bool:
    affordances = {str(item) for item in action.get("affordances") or []}
    if "signature_gate" in affordances:
        return True
    if "signed_authorization" not in affordances:
        return False
    hints = action.get("hints") or {}
    hint_text = " ".join(
        str(entry.get("text") or "")
        for entry in hints.get("authorization_checks") or []
        if isinstance(entry, dict)
    ).lower()
    return any(term in hint_text for term in _SIGNATURE_GATE_TERMS)


def _classify_action_reachability(action: dict) -> dict:
    affordances = {str(item) for item in action.get("affordances") or []}
    modifiers = [str(item) for item in action.get("modifiers") or []]
    hints = action.get("hints") or {}
    role_hints = hints.get("role_gates") or []
    auth_hints = hints.get("authorization_checks") or []
    reasons = []
    if modifiers:
        reasons.append("modifiers: " + ", ".join(modifiers[:4]))
    if role_hints:
        reasons.append("source has role/sender gate hints")
    if auth_hints:
        reasons.append("source has authorization check hints")

    strong_gate_modifiers = _action_strong_gate_modifiers(modifiers)
    if strong_gate_modifiers:
        # Modifiers are exact only when parsed from the solc AST. A regex parse
        # can truncate signature tails or invent phantom modifiers, so a
        # source-only verdict is capped at medium confidence — enough to record
        # the gate, not enough for the attack-graph scorer to bury the branch
        # below the candidate floor without AST or live-authority confirmation.
        ast_verified = str(action.get("parse_source") or "") == "ast"
        gate_reasons = reasons or [
            "privileged modifier: " + ", ".join(strong_gate_modifiers[:4])
        ]
        if not ast_verified:
            gate_reasons = [
                *gate_reasons,
                "source-only modifier parse (regex); confidence capped at medium "
                "pending AST or live authority confirmation",
            ]
        return {
            "kind": "role_gated",
            "attacker_reachable": False,
            "confidence": "high" if ast_verified else "medium",
            "reasons": gate_reasons,
        }
    if "modifier_gated" in affordances and role_hints:
        return {
            "kind": "role_gated",
            "attacker_reachable": False,
            "confidence": "medium",
            "reasons": reasons,
        }
    if _action_has_signature_gate(action):
        return {
            "kind": "signature_gated",
            "attacker_reachable": "requires_valid_signature",
            "confidence": "medium",
            "reasons": reasons or ["source verifies a signature authorization"],
        }
    if "cross_domain_or_message" in affordances and "sender_or_role_checked" in affordances:
        return {
            "kind": "cross_domain_or_sender_gated",
            "attacker_reachable": False,
            "confidence": "medium",
            "reasons": reasons or ["cross-domain message with sender/role check"],
        }
    if "sender_or_role_checked" in affordances:
        return {
            "kind": "sender_checked",
            "attacker_reachable": "unknown",
            "confidence": "medium",
            "reasons": reasons or ["sender or role check present"],
        }
    visibility = str(action.get("visibility") or "").strip()
    if visibility in {"public", "external"}:
        return {
            "kind": "public",
            "attacker_reachable": True,
            "confidence": "source",
            "reasons": reasons or ["public/external entrypoint without detected gate"],
        }
    return {
        "kind": "unknown",
        "attacker_reachable": "unknown",
        "confidence": "low",
        "reasons": reasons or ["no explicit reachability classification"],
    }


_EIP1967_IMPL_SLOT = "0x360894A13BA1A3210667C828492DB98DCA3E2076CC3735A920A3CA505D382BBC"
_EIP1967_ADMIN_SLOT = "0xB53127684A568B3173AE13B9F8A6016E243E63B6E8EE1178D6A717850B5D6103"
_LIVE_PROBE_CALL_TIMEOUT_SECONDS = 8
_AUTHORITY_PROBE_MAX_ACTIONS = 24
_AUTHORITY_PROBE_CALL_TIMEOUT_SECONDS = 8


def _bounded_cast_command(command: str, *, seconds: int) -> str:
    return f"timeout {int(seconds)}s {command}"


def _live_probe_shell_command(calls: list[tuple[str, str]]) -> str:
    # Each call already carries a concrete `--rpc-url '<url>'`; there is no
    # `$ETH_RPC_URL` guard because callers only build probes once a per-chain
    # endpoint has been resolved (no endpoint -> the probe is skipped upstream).
    lines = [
        f'echo "{key}=$('
        f'{_bounded_cast_command(command, seconds=_LIVE_PROBE_CALL_TIMEOUT_SECONDS)} '
        '2>/dev/null || true)"'
        for key, command in calls
    ]
    return "bash -lc " + shlex.quote("\n".join(lines))


def _cast_probe_command(address: str, rpc_url: str) -> str:
    quoted = shlex.quote(address)
    rpc = _cast_rpc_arg(rpc_url)
    return _live_probe_shell_command([
        ("code", f"cast code {quoted}{rpc}"),
        ("native_balance", f"cast balance {quoted}{rpc}"),
        ("eip1967_impl", f"cast storage {quoted} {_EIP1967_IMPL_SLOT}{rpc}"),
        ("eip1967_admin", f"cast storage {quoted} {_EIP1967_ADMIN_SLOT}{rpc}"),
        ("owner", f"cast call {quoted} 'owner()(address)'{rpc}"),
        ("admin", f"cast call {quoted} 'admin()(address)'{rpc}"),
        ("authority", f"cast call {quoted} 'authority()(address)'{rpc}"),
        ("paused", f"cast call {quoted} 'paused()(bool)'{rpc}"),
        ("token", f"cast call {quoted} 'token()(address)'{rpc}"),
        ("asset", f"cast call {quoted} 'asset()(address)'{rpc}"),
        ("oracle", f"cast call {quoted} 'oracle()(address)'{rpc}"),
        ("messenger", f"cast call {quoted} 'messenger()(address)'{rpc}"),
        ("endpoint", f"cast call {quoted} 'endpoint()(address)'{rpc}"),
    ])


_AUTHORITY_PROBE_ATTACKER = "0x0000000000000000000000000000000000000a11"


def _zero_address(value: object) -> bool:
    text = str(value or "").strip()
    if not text or text == "0x":
        return True
    lowered = text.lower()
    if lowered == "0x0000000000000000000000000000000000000000":
        return True
    if lowered.startswith("0x"):
        body = lowered[2:]
        return bool(body) and set(body) == {"0"}
    return False


def _authority_probe_signature_groups(actions: list[dict]) -> list[dict]:
    groups = []
    by_signature = {}
    for index, action in enumerate(actions[:_AUTHORITY_PROBE_MAX_ACTIONS], start=1):
        signature = _action_signature(action)
        if not signature or signature in {"receive", "fallback"}:
            continue
        if signature in by_signature:
            by_signature[signature]["actions"].append(action)
            continue
        group = {
            "index": index,
            "signature": signature,
            "actions": [action],
        }
        by_signature[signature] = group
        groups.append(group)
    return groups


def _authority_probe_command(
    *,
    target: str,
    authority: str,
    actions: list[dict],
    rpc_url: str,
    attacker: str = _AUTHORITY_PROBE_ATTACKER,
) -> str:
    rpc = _cast_rpc_arg(rpc_url)
    lines: list[str] = []
    target_q = shlex.quote(target)
    authority_q = shlex.quote(authority)
    attacker_q = shlex.quote(attacker)
    for group in _authority_probe_signature_groups(actions):
        index = int(group["index"])
        signature = str(group["signature"])
        sig_q = shlex.quote(signature)
        lines.append(
            "selector=$(cast sig "
            f"{sig_q} 2>/dev/null || true); "
            "if [ -n \"$selector\" ]; then "
            f"echo \"authority_can_call_{index}=$("
            f"timeout {_AUTHORITY_PROBE_CALL_TIMEOUT_SECONDS}s "
            f"cast call {authority_q} "
            "'canCall(address,address,bytes4)(bool)' "
            f"{attacker_q} {target_q} $selector{rpc} 2>/dev/null || true)\"; "
            "fi"
        )
    return "bash -lc " + shlex.quote("\n".join(lines))


def _parse_authority_probe_output(output: str, actions: list[dict]) -> dict[str, bool]:
    decisions = {}
    by_index = {
        int(group["index"]): group
        for group in _authority_probe_signature_groups(actions)
    }
    for line in output.splitlines():
        match = re.match(r"authority_can_call_(\d+)=(.*)", line.strip())
        if not match:
            continue
        group = by_index.get(int(match.group(1)))
        if not group:
            continue
        value = match.group(2).strip().lower()
        if value in {"true", "1", "0x1"}:
            for action in group["actions"]:
                decisions[_action_stable_uid(action)] = True
        elif value in {"false", "0", "0x0"}:
            for action in group["actions"]:
                decisions[_action_stable_uid(action)] = False
    return decisions


def _live_inventory_probe_command(address: str, rpc_url: str) -> str:
    quoted = shlex.quote(address)
    rpc = _cast_rpc_arg(rpc_url)
    base_calls = [
        ("code", f"cast code {quoted}{rpc}"),
        ("native_balance", f"cast balance {quoted}{rpc}"),
        ("eip1967_impl", f"cast storage {quoted} {_EIP1967_IMPL_SLOT}{rpc}"),
        ("eip1967_admin", f"cast storage {quoted} {_EIP1967_ADMIN_SLOT}{rpc}"),
        ("owner", f"cast call {quoted} 'owner()(address)'{rpc}"),
        ("admin", f"cast call {quoted} 'admin()(address)'{rpc}"),
        ("authority", f"cast call {quoted} 'authority()(address)'{rpc}"),
        ("paused", f"cast call {quoted} 'paused()(bool)'{rpc}"),
        ("asset", f"cast call {quoted} 'asset()(address)'{rpc}"),
        ("underlying", f"cast call {quoted} 'underlying()(address)'{rpc}"),
        ("token", f"cast call {quoted} 'token()(address)'{rpc}"),
        ("decimals", f"cast call {quoted} 'decimals()(uint8)'{rpc}"),
        ("symbol", f"cast call {quoted} 'symbol()(string)'{rpc}"),
        ("total_supply", f"cast call {quoted} 'totalSupply()(uint256)'{rpc}"),
        ("total_assets", f"cast call {quoted} 'totalAssets()(uint256)'{rpc}"),
        ("get_cash", f"cast call {quoted} 'getCash()(uint256)'{rpc}"),
        ("total_borrows", f"cast call {quoted} 'totalBorrows()(uint256)'{rpc}"),
        ("total_reserves", f"cast call {quoted} 'totalReserves()(uint256)'{rpc}"),
        ("exchange_rate_stored", f"cast call {quoted} 'exchangeRateStored()(uint256)'{rpc}"),
        ("addresses_provider", f"cast call {quoted} 'ADDRESSES_PROVIDER()(address)'{rpc}"),
        ("pool", f"cast call {quoted} 'POOL()(address)'{rpc}"),
        ("get_pool", f"cast call {quoted} 'getPool()(address)'{rpc}"),
        ("get_pool_configurator", f"cast call {quoted} 'getPoolConfigurator()(address)'{rpc}"),
        ("get_price_oracle", f"cast call {quoted} 'getPriceOracle()(address)'{rpc}"),
        ("get_reserves_list", f"cast call {quoted} 'getReservesList()(address[])'{rpc}"),
        ("get_reserves_count", f"cast call {quoted} 'getReservesCount()(uint256)'{rpc}"),
    ]
    lines = []
    for key, command in base_calls:
        lines.append(
            f'echo "{key}=$('
            f'{_bounded_cast_command(command, seconds=_LIVE_PROBE_CALL_TIMEOUT_SECONDS)} '
            '2>/dev/null || true)"'
        )
    provider_command = f"cast call {quoted} 'ADDRESSES_PROVIDER()(address)'{rpc}"
    provider_probe = (
        f"provider=$({_bounded_cast_command(provider_command, seconds=_LIVE_PROBE_CALL_TIMEOUT_SECONDS)} "
        "2>/dev/null || true); "
        "if echo \"$provider\" | grep -Eq '^0x[0-9a-fA-F]{40}$' "
        "&& [ \"$provider\" != \"0x0000000000000000000000000000000000000000\" ]; then "
        "echo \"provider_get_pool=$(timeout "
        f"{_LIVE_PROBE_CALL_TIMEOUT_SECONDS}s "
        f"cast call $provider 'getPool()(address)'{rpc} 2>/dev/null || true)\"; "
        "echo \"provider_get_pool_configurator=$(timeout "
        f"{_LIVE_PROBE_CALL_TIMEOUT_SECONDS}s "
        f"cast call $provider 'getPoolConfigurator()(address)'{rpc} 2>/dev/null || true)\"; "
        "echo \"provider_get_price_oracle=$(timeout "
        f"{_LIVE_PROBE_CALL_TIMEOUT_SECONDS}s "
        f"cast call $provider 'getPriceOracle()(address)'{rpc} 2>/dev/null || true)\"; "
        "fi"
    )
    lines.append(provider_probe)
    return "bash -lc " + shlex.quote("\n".join(lines))


def _parse_probe_output(output: str) -> dict:
    # Output always comes from a concrete per-chain endpoint now, so an executed
    # probe is RPC-available by construction; "no endpoint" is handled upstream.
    values = {}
    for line in output.splitlines():
        if "=" not in line:
            continue
        key, value = line.split("=", 1)
        values[key.strip()] = value.strip()
    code = values.pop("code", "")
    code_present = None
    if code:
        code_present = code != "0x"
        if code_present:
            hex_body = code[2:] if code.startswith("0x") else code
            values["code_size_bytes"] = str(len(hex_body) // 2)
            values["code_sha256_16"] = hashlib.sha256(code.encode()).hexdigest()[:16]
        else:
            values["code_size_bytes"] = "0"
    return {
        "rpc_available": True,
        "values": values,
        "code_present": code_present,
    }


def _probe_value_nonzero(value: object) -> bool:
    text = str(value or "").strip()
    if not text or text.lower() in {"false", "none", "null"}:
        return False
    if _zero_address(text):
        return False
    if text.lower().startswith("0x"):
        try:
            return int(text, 16) != 0
        except ValueError:
            return True
    try:
        return Decimal(text) != 0
    except InvalidOperation:
        return True


def _nonzero_probe_keys(values: dict, keys: tuple[str, ...]) -> list[str]:
    return [
        key for key in keys
        if _probe_value_nonzero(values.get(key))
    ]


def _probe_address_value(values: dict, key: str) -> str:
    text = str(values.get(key) or "").strip()
    if not text:
        return ""
    exact = _solidity_address_literal(text)
    if exact and not _zero_address(exact):
        return exact
    match = re.search(r"0x[a-fA-F0-9]{40}", text)
    if not match:
        return ""
    address = match.group(0)
    return "" if _zero_address(address) else address


_RELATED_LIVE_TARGET_RELATIONS: tuple[tuple[str, str, str], ...] = (
    ("provider_get_pool", "pool", "ADDRESSES_PROVIDER().getPool()"),
    ("get_pool", "pool", "getPool()"),
    ("pool", "pool", "POOL()"),
    ("provider_get_pool_configurator", "pool_configurator", "ADDRESSES_PROVIDER().getPoolConfigurator()"),
    ("get_pool_configurator", "pool_configurator", "getPoolConfigurator()"),
    ("provider_get_price_oracle", "price_oracle", "ADDRESSES_PROVIDER().getPriceOracle()"),
    ("get_price_oracle", "price_oracle", "getPriceOracle()"),
    ("addresses_provider", "addresses_provider", "ADDRESSES_PROVIDER()"),
    ("eip1967_impl", "implementation", "EIP-1967 implementation slot"),
    ("asset", "asset", "asset()"),
    ("underlying", "underlying", "underlying()"),
    ("token", "token", "token()"),
    ("oracle", "oracle", "oracle()"),
    ("authority", "authority", "authority()"),
)


def _probe_related_live_targets(values: dict, original_address: str = "") -> list[dict]:
    related = []
    seen = set()
    original_key = original_address.lower() if original_address else ""
    for key, relation, source in _RELATED_LIVE_TARGET_RELATIONS:
        address = _probe_address_value(values, key)
        if not address:
            continue
        address_key = address.lower()
        if address_key == original_key or (relation, address_key) in seen:
            continue
        seen.add((relation, address_key))
        audit_relevance = (
            "call_target_candidate"
            if relation in {"pool", "pool_configurator"}
            else "configured_dependency"
        )
        if relation == "implementation":
            audit_relevance = "implementation"
        related.append({
            "relation": relation,
            "address": address,
            "source": source,
            "audit_relevance": audit_relevance,
        })
    return related


def _probe_reserves_empty(values: dict) -> bool:
    reserves = str(values.get("get_reserves_list") or "").strip().lower()
    if reserves in {"[]", "()", "(0x)", "0x"}:
        return True
    count_text = str(values.get("get_reserves_count") or "").strip()
    if not count_text:
        return False
    try:
        return int(count_text, 0) == 0
    except ValueError:
        return False


def _recommended_call_target(
    related_targets: list[dict],
    *,
    prefer_relations: tuple[str, ...] = ("pool",),
) -> tuple[str, str]:
    for relation in prefer_relations:
        for target in related_targets:
            if target.get("relation") != relation:
                continue
            address = _solidity_address_literal(target.get("address"))
            if not address:
                continue
            return address, str(target.get("source") or relation)
    return "", ""


def _live_target_binding(
    probe: dict,
    *,
    profile: dict | None = None,
    target: dict | None = None,
) -> dict:
    values = probe.get("values") or {}
    profile = profile or {}
    target = target or {}
    original_address = _solidity_address_literal(
        target.get("address") or profile.get("address")
    )
    impl = values.get("eip1967_impl")
    admin = values.get("eip1967_admin")
    related_live_targets = _probe_related_live_targets(values, original_address)
    recommended_call_target, recommendation_source = _recommended_call_target(
        related_live_targets,
    )
    reserves_empty = _probe_reserves_empty(values)
    economic_keys = _nonzero_probe_keys(
        values,
        (
            "native_balance",
            "total_supply",
            "total_assets",
            "get_cash",
            "total_borrows",
            "total_reserves",
        ),
    )
    config_keys = _nonzero_probe_keys(
        values,
        (
            "owner",
            "admin",
            "authority",
            "asset",
            "underlying",
            "token",
            "oracle",
            "messenger",
            "endpoint",
            "addresses_provider",
            "pool",
            "get_pool",
            "provider_get_pool",
            "get_pool_configurator",
            "provider_get_pool_configurator",
            "get_price_oracle",
            "provider_get_price_oracle",
        ),
    )
    text = _coverage_normalize_text(" ".join(
        str(item or "")
        for item in (
            profile.get("profile"),
            profile.get("contract"),
            profile.get("src"),
            target.get("label"),
            target.get("contract"),
            target.get("kind"),
        )
    ))
    implementation_hint = any(
        term in text
        for term in ("implementation", "impl", "logic", "template")
    )
    reasons = []
    code_present = probe.get("code_present")
    if code_present is False:
        kind = "no_code"
        live_deployed = False
        economic_priority = "none"
        reasons.append("target has no deployed bytecode")
    elif code_present is True and impl is not None and not _zero_address(impl):
        kind = "active_proxy"
        live_deployed = True
        economic_priority = "high"
        reasons.append("EIP-1967 implementation slot is set")
        if admin is not None and not _zero_address(admin):
            reasons.append("EIP-1967 admin slot is set")
    elif (
        code_present is True
        and recommended_call_target
        and (implementation_hint or (reserves_empty and not economic_keys))
    ):
        kind = "deployed_implementation_or_template"
        live_deployed = True
        economic_priority = "low"
        reasons.append(
            "target exposes an indirection to a different live call target "
            f"via {recommendation_source}"
        )
        if reserves_empty:
            reasons.append("target reserve/market list appears empty")
    elif code_present is True and economic_keys:
        kind = "deployed_economic_contract"
        live_deployed = True
        economic_priority = "high"
        reasons.append("live probe found nonzero economic state: " + ", ".join(economic_keys[:4]))
    elif code_present is True and config_keys:
        kind = "deployed_configured_contract"
        live_deployed = True
        economic_priority = "medium"
        reasons.append("live probe found configured dependencies: " + ", ".join(config_keys[:4]))
    elif code_present is True and implementation_hint:
        kind = "deployed_implementation_or_template"
        live_deployed = True
        economic_priority = "low"
        reasons.append("deployed bytecode looks like an implementation/template target without live economic state")
    elif code_present is True:
        kind = "deployed_contract"
        live_deployed = True
        economic_priority = "medium"
        reasons.append("target has deployed bytecode")
    elif probe.get("executed"):
        kind = "unknown_code"
        live_deployed = False
        economic_priority = "unknown"
        reasons.append("probe executed but code presence was unknown")
    else:
        kind = "unprobed"
        live_deployed = False
        economic_priority = "unknown"
        reasons.append("target has not been probed on a live RPC")
    normalization_reason = ""
    if recommended_call_target:
        normalization_reason = (
            f"{recommendation_source} resolves a related live target "
            f"{recommended_call_target}; audit it as a transitive target rather "
            "than treating this address alone as the economic endpoint"
        )
    return {
        "kind": kind,
        "binding_kind": kind,
        "original_address": original_address or None,
        "live_deployed": live_deployed,
        "economic_priority": economic_priority,
        "economically_significant_hint": economic_priority == "high",
        "code_hash": values.get("code_sha256_16") or None,
        "nonzero_economic_state": economic_keys[:8],
        "configured_dependencies": config_keys[:8],
        "related_live_targets": related_live_targets[:10],
        "recommended_call_target": recommended_call_target or None,
        "normalization_reason": normalization_reason or None,
        "reasons": reasons[:6],
    }


def _inventory_target_address(item: object) -> str:
    if isinstance(item, dict):
        item = item.get("address") or item.get("target") or item.get("contract_address")
    return str(item or "").strip()


def _active_attack_search_branch(state: dict, *, next_tool: str = "") -> dict | None:
    search = (state.get("attack_search") or {}).get("current")
    if not isinstance(search, dict):
        return None
    selected_id = str(search.get("selected_branch_id") or "").strip()
    branches = [
        branch for branch in search.get("branches") or []
        if isinstance(branch, dict) and not _attack_search_branch_terminal(branch)
    ]
    if selected_id:
        for branch in branches:
            if str(branch.get("id") or "") == selected_id:
                return branch
    matching = [
        branch for branch in branches
        if not next_tool or str(branch.get("next_tool") or "") == next_tool
    ]
    if len(matching) == 1:
        return matching[0]
    if matching:
        return sorted(matching, key=_attack_search_branch_sort_key)[0]
    return None


def _attack_search_required_tool_args(
    state: dict,
    tool_name: str,
) -> tuple[dict, dict | None]:
    branch = _active_attack_search_branch(state, next_tool=tool_name)
    if not branch:
        return {}, None
    required_args = branch.get("required_args") or {}
    if not isinstance(required_args, dict):
        return {}, branch
    tool_args = required_args.get(tool_name) or {}
    if not isinstance(tool_args, dict):
        return {}, branch
    return tool_args, branch


def _compact_inventory_values(values: dict) -> dict:
    selected = {}
    for key in (
        "native_balance",
        "eip1967_impl",
        "eip1967_admin",
        "owner",
        "admin",
        "authority",
        "paused",
        "asset",
        "underlying",
        "token",
        "decimals",
        "symbol",
        "total_supply",
        "total_assets",
        "get_cash",
        "total_borrows",
        "total_reserves",
        "exchange_rate_stored",
        "addresses_provider",
        "pool",
        "get_pool",
        "provider_get_pool",
        "get_pool_configurator",
        "provider_get_pool_configurator",
        "get_price_oracle",
        "provider_get_price_oracle",
        "get_reserves_count",
        "get_reserves_list",
        "code_size_bytes",
        "code_sha256_16",
    ):
        value = values.get(key)
        if value not in (None, "", "0x"):
            selected[key] = value
    return selected


async def _inventory_live_targets(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    state = await _load_campaign_state(container)
    inferred_branch: dict | None = None
    if not args.get("targets"):
        required_args, inferred_branch = _attack_search_required_tool_args(
            state,
            "inventory_live_targets",
        )
        if required_args.get("targets"):
            merged_args = dict(required_args)
            merged_args.update(args)
            merged_args["targets"] = required_args["targets"]
            if not args.get("related_ids") and required_args.get("related_ids"):
                merged_args["related_ids"] = required_args["related_ids"]
            if not args.get("title") and required_args.get("title"):
                merged_args["title"] = required_args["title"]
            args = merged_args

    try:
        raw_targets = _require_list(args.get("targets"), "targets")
        related_ids = _require_list(args.get("related_ids"), "related_ids")
        execute_probes = _coerce_bool_arg(
            args.get("execute_probes"),
            "execute_probes",
            default=True,
        )
        probe_concurrency = _coerce_bounded_int_arg(
            args.get("probe_concurrency"),
            "probe_concurrency",
            default=4,
            minimum=1,
            maximum=12,
        )
    except ValueError as exc:
        return f"Error: {exc}"
    if len(raw_targets) > _LIVE_INVENTORY_MAX_TARGETS:
        return (
            "Error: inventory_live_targets accepts at most "
            f"{_LIVE_INVENTORY_MAX_TARGETS} targets per call"
        )
    targets = []
    seen = set()
    for index, item in enumerate(raw_targets, start=1):
        if not isinstance(item, dict):
            return "Error: targets must be objects with at least an address"
        address = _inventory_target_address(item)
        if not _solidity_address_literal(address):
            return f"Error: targets[{index}] has invalid address"
        key = address.lower()
        if key in seen:
            continue
        seen.add(key)
        selectors = item.get("selectors") or []
        if not isinstance(selectors, list):
            return f"Error: targets[{index}].selectors must be a list"
        targets.append({
            "label": str(item.get("label") or item.get("contract") or f"target_{index}").strip(),
            "contract": item.get("contract"),
            "kind": item.get("kind"),
            "address": address,
            "selectors": [
                str(selector) for selector in selectors
                if str(selector).strip()
            ][:20],
        })
    if not targets:
        return "Error: inventory_live_targets requires at least one target"

    # Group targets by their resolved chain and derive a per-chain endpoint;
    # never collapse a multi-chain scope onto one global ETH_RPC_URL.
    fork_context = await _resolve_fork_context_arg(container, args.get("fork_context"))
    registry = await _resolve_chain_registry_arg(container, args.get("chain_registry"))
    plan = await _plan_live_probe_chains(
        container,
        args,
        items=[
            {
                "address": target["address"],
                "names": [target.get("contract"), target.get("label")],
            }
            for target in targets
        ],
        registry=registry,
        fork_context=fork_context,
        environ=environ,
        config=config,
    )
    assignments = plan["assignments"]
    groups = plan["groups"]

    summary = {
        "targets": len(targets),
        "probed": 0,
        "rpc_missing": 0,
        "code_present": 0,
        "no_code": 0,
        "unknown_code": 0,
        "probe_concurrency": probe_concurrency if execute_probes else 0,
    }

    async def _probe(index: int, target: dict) -> dict:
        assignment = assignments[index]
        status = assignment.get("status")
        group = groups.get(assignment.get("chain_key")) if status == "grouped" else None
        endpoint = (group or {}).get("endpoint")
        rpc_url = endpoint.url if endpoint else None
        probe = {
            "executed": False,
            "rpc_available": None,
            "code_present": None,
            "values": {},
        }
        if status == "ambiguous":
            probe["skipped"] = "chain_ambiguous"
        elif status == "chain_mismatch":
            probe["skipped"] = "chain_mismatch"
        elif status == "grouped" and execute_probes and rpc_url:
            exit_code, output = await container.exec(
                _live_inventory_probe_command(target["address"], rpc_url),
                timeout=60,
            )
            probe.update({
                "executed": True,
                "exit_code": exit_code,
                **_parse_probe_output(output),
            })
        elif execute_probes:
            # A chain was chosen (or none could be) but no endpoint resolved.
            probe.update({
                "rpc_available": False,
                "skipped": (
                    "rpc_not_configured" if status == "grouped" else "chain_unresolved"
                ),
            })
        return {
            **target,
            "network": assignment.get("network"),
            "chain_id": assignment.get("chain_id"),
            "chain_status": status,
            "rpc_endpoint": _rpc_endpoint_summary(endpoint) if group else None,
            "probe": probe,
        }

    async def _probe_bounded(
        semaphore: asyncio.Semaphore,
        index: int,
        target: dict,
    ) -> dict:
        async with semaphore:
            return await _probe(index, target)

    if execute_probes:
        semaphore = asyncio.Semaphore(probe_concurrency)
        entries = await asyncio.gather(
            *(
                _probe_bounded(semaphore, index, target)
                for index, target in enumerate(targets)
            ),
        )
    else:
        entries = [
            await _probe(index, target) for index, target in enumerate(targets)
        ]

    binding_counts: dict[str, int] = {}
    for entry in entries:
        probe = entry.get("probe") or {}
        target_binding = _live_target_binding(probe, target=entry)
        entry["target_binding"] = target_binding
        binding_kind = str(target_binding.get("kind") or "unknown")
        binding_counts[binding_kind] = binding_counts.get(binding_kind, 0) + 1
        if probe.get("executed"):
            summary["probed"] += 1
        if probe.get("rpc_available") is False:
            summary["rpc_missing"] += 1
        code_present = probe.get("code_present")
        if code_present is True:
            summary["code_present"] += 1
        elif code_present is False:
            summary["no_code"] += 1
        else:
            summary["unknown_code"] += 1
    summary["target_bindings"] = binding_counts
    summary["live_deployed_targets"] = sum(
        1 for entry in entries
        if (entry.get("target_binding") or {}).get("live_deployed")
    )
    summary["economically_significant_targets"] = sum(
        1 for entry in entries
        if (entry.get("target_binding") or {}).get("economically_significant_hint")
    )

    grouping = _summarize_live_probe_chains(
        assignments=assignments,
        groups=groups,
        entries=entries,
        meta_for=lambda index: {
            "label": targets[index].get("label"),
            "contract": targets[index].get("contract"),
            "address": targets[index].get("address"),
        },
    )
    summary["chains"] = len(grouping["chains"])
    summary["chains_probed"] = len(grouping["chains_probed"])
    summary["ambiguous_targets"] = len(grouping["ambiguous_targets"])
    summary["skipped_targets"] = len(grouping["skipped_targets"])

    inventory_id = _next_campaign_id(state, "live_inventory")
    title = str(args.get("title") or "Live target inventory").strip()
    payload = {
        "id": inventory_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "execute_probes": execute_probes,
        "probe_concurrency": probe_concurrency if execute_probes else 0,
        "targets": entries,
        "chains": grouping["chains"],
        "ambiguous_targets": grouping["ambiguous_targets"],
        "skipped_targets": grouping["skipped_targets"],
        "summary": summary,
        "related_ids": [str(item) for item in related_ids],
    }
    if inferred_branch:
        payload["inferred_from_attack_search"] = {
            "branch_id": inferred_branch.get("id"),
            "branch_title": inferred_branch.get("title"),
        }
    path = f"/workspace/campaign/live-inventory/{inventory_id}.json"
    await container.write_file(path, json.dumps(payload, indent=2, sort_keys=True) + "\n")
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Live inventory: {title}",
            content=(
                f"Live inventory: {inventory_id}\n"
                f"Path: {path}\n"
                f"Targets: {summary['targets']}\n"
                f"Code present: {summary['code_present']}\n"
                f"Live deployed targets: {summary['live_deployed_targets']}\n"
                "Economically significant target hints: "
                f"{summary['economically_significant_targets']}\n"
                "Use this inventory to bind fork preconditions and reject dormant/gated paths."
            ),
            evidence=[path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )
    compact_entries = []
    for entry in entries[:10]:
        probe = entry.get("probe") or {}
        compact_entries.append({
            "label": entry.get("label"),
            "contract": entry.get("contract"),
            "kind": entry.get("kind"),
            "address": entry.get("address"),
            "network": entry.get("network"),
            "chain_id": entry.get("chain_id"),
            "chain_status": entry.get("chain_status"),
            "code_present": probe.get("code_present"),
            "rpc_available": probe.get("rpc_available"),
            "skipped": probe.get("skipped"),
            "target_binding": entry.get("target_binding"),
            "values": _compact_inventory_values(probe.get("values") or {}),
        })
    return json.dumps({
        "inventory_id": inventory_id,
        "path": path,
        "result_id": result_id or None,
        "summary": summary,
        "chains_probed": [
            _compact_chain_block(block) for block in grouping["chains_probed"]
        ],
        "targets_by_chain": {
            block["key"]: block["targets"] for block in grouping["chains"]
        },
        "ambiguous_targets": grouping["ambiguous_targets"],
        "skipped_targets": grouping["skipped_targets"],
        "inferred_from_attack_search": (
            {
                "branch_id": inferred_branch.get("id"),
                "branch_title": inferred_branch.get("title"),
            }
            if inferred_branch else None
        ),
        "targets": compact_entries,
    }, indent=2, sort_keys=True)


def _profile_probe_plan(address: str) -> list[dict]:
    # Display-only plan; the live command uses the resolved per-chain endpoint
    # (redacted as <rpc_url>), never a global $ETH_RPC_URL.
    return [
        {"kind": "code", "command": f"cast code {address} --rpc-url <rpc_url>"},
        {"kind": "native_balance", "command": f"cast balance {address} --rpc-url <rpc_url>"},
        {"kind": "proxy_impl", "command": f"cast storage {address} <eip1967.impl.slot> --rpc-url <rpc_url>"},
        {"kind": "owner", "command": f'cast call {address} "owner()(address)" --rpc-url <rpc_url>'},
        {"kind": "paused", "command": f'cast call {address} "paused()(bool)" --rpc-url <rpc_url>'},
        {"kind": "token_or_asset", "command": f'cast call {address} "token()(address)" or "asset()(address)" --rpc-url <rpc_url>'},
    ]


def _compact_probe_summary(probe: dict) -> dict:
    values = probe.get("values") or {}
    selected_values = {
        key: values.get(key)
        for key in (
            "native_balance",
            "eip1967_impl",
            "eip1967_admin",
            "owner",
            "admin",
            "authority",
            "paused",
            "token",
            "asset",
            "oracle",
            "messenger",
            "endpoint",
            "addresses_provider",
            "pool",
            "get_pool",
            "provider_get_pool",
            "get_pool_configurator",
            "provider_get_pool_configurator",
            "get_price_oracle",
            "provider_get_price_oracle",
            "get_reserves_count",
            "code_size_bytes",
            "code_sha256_16",
        )
        if values.get(key) not in (None, "")
    }
    return {
        key: value
        for key, value in {
            "executed": probe.get("executed"),
            "rpc_available": probe.get("rpc_available"),
            "code_present": probe.get("code_present"),
            "exit_code": probe.get("exit_code"),
            "values": selected_values,
        }.items()
        if value not in (None, "", [], {})
    }


def _compact_exposure_entry(exposure: dict) -> dict:
    reachability = exposure.get("reachability") or {}
    source_relation = exposure.get("source_relation") or {}
    authority_probe = exposure.get("authority_probe") or {}
    compact = {
        "action_key": exposure.get("action_key"),
        "contract": exposure.get("contract"),
        "contract_kind": exposure.get("contract_kind"),
        "function": exposure.get("function"),
        "signature": exposure.get("signature"),
        "target_address": exposure.get("target_address"),
        "profile_contract": exposure.get("profile_contract"),
        "file": exposure.get("file"),
        "line": exposure.get("line"),
        "exposure": exposure.get("exposure"),
        "live_status": exposure.get("live_status"),
        "target_binding": exposure.get("target_binding"),
        "direction_hint": _attack_graph_direction_hint(exposure),
        "reachability": {
            key: reachability.get(key)
            for key in (
                "kind",
                "attacker_reachable",
                "confidence",
                "authority_attacker_can_call",
                "reasons",
            )
            if reachability.get(key) not in (None, "", [], {})
        },
        "source_relation": {
            key: source_relation.get(key)
            for key in ("kind", "executable_source", "reasons")
            if source_relation.get(key) not in (None, "", [], {})
        },
        "authority_probe": {
            key: authority_probe.get(key)
            for key in ("authority", "attacker", "attacker_can_call")
            if authority_probe.get(key) not in (None, "", [], {})
        },
        "affordances": (exposure.get("affordances") or [])[:8],
        "modifiers": (exposure.get("modifiers") or [])[:6],
        "priority_score": _attack_graph_candidate_score(
            exposure,
            "",
        ),
    }
    return {key: value for key, value in compact.items() if value not in (None, "", [], {})}


def _compact_profile_reachability(profile: dict, *, max_exposures: int) -> dict:
    exposures = _sort_action_entries(profile.get("action_exposures") or [])
    return {
        key: value
        for key, value in {
            "profile": profile.get("profile"),
            "contract": profile.get("contract"),
            "address": profile.get("address"),
            "src": profile.get("src"),
            "network": profile.get("network"),
            "chain_id": profile.get("chain_id"),
            "chain_status": profile.get("chain_status"),
            "priority_score": profile.get("priority_score"),
            "tags": profile.get("tags") or [],
            "probe": _compact_probe_summary(profile.get("probe") or {}),
            "target_binding": profile.get("target_binding"),
            "summary": profile.get("summary") or {},
            "action_exposures": [
                _compact_exposure_entry(item)
                for item in exposures[:max_exposures]
            ],
        }.items()
        if value not in (None, "", [], {})
    }


def _profile_family_key(profile: dict) -> tuple[str, str]:
    values = (profile.get("probe") or {}).get("values") or {}
    code_hash = str(values.get("code_sha256_16") or "").strip()
    contract = str(profile.get("contract") or "").strip()
    if code_hash:
        return contract, f"code:{code_hash}"
    return contract, "source-contract"


def _compact_profile_family(entries: list[dict]) -> dict:
    representative = entries[0]
    values = (representative.get("probe") or {}).get("values") or {}
    addresses = _dedupe_text([
        str(item.get("address") or "")
        for item in entries
        if item.get("address")
    ])
    profiles = _dedupe_text([
        str(item.get("profile") or "")
        for item in entries
        if item.get("profile")
    ])
    src_roots = _dedupe_text([
        str(item.get("src") or "")
        for item in entries
        if item.get("src")
    ])
    action_exposures = [
        exposure
        for item in entries
        for exposure in item.get("action_exposures") or []
    ]
    target_bindings: dict[str, int] = {}
    for item in entries:
        kind = str((item.get("target_binding") or {}).get("kind") or "unknown")
        target_bindings[kind] = target_bindings.get(kind, 0) + 1
    compact = {
        "contract": representative.get("contract"),
        "profiles": len(entries),
        "code_sha256_16": values.get("code_sha256_16"),
        "target_bindings": target_bindings,
        "addresses": addresses[:5],
        "addresses_omitted": max(0, len(addresses) - 5),
        "profile_names": profiles[:5],
        "profile_names_omitted": max(0, len(profiles) - 5),
        "src_roots": src_roots[:5],
        "src_roots_omitted": max(0, len(src_roots) - 5),
        "actions_matched": len(action_exposures),
        "exposed": sum(1 for item in action_exposures if item.get("exposure") == "exposed"),
        "gated": sum(1 for item in action_exposures if item.get("exposure") == "gated"),
        "source_interface_only": sum(
            1 for item in action_exposures
            if item.get("exposure") == "source_interface_only"
        ),
        "source_artifact_only": sum(
            1 for item in action_exposures
            if item.get("exposure") == "source_artifact_only"
        ),
        "unknown": sum(1 for item in action_exposures if item.get("exposure") == "unknown"),
    }
    return {key: value for key, value in compact.items() if value not in (None, "", [], {})}


def _profile_families(mapped_profiles: list[dict]) -> list[dict]:
    groups: dict[tuple[str, str], list[dict]] = {}
    for profile in mapped_profiles:
        groups.setdefault(_profile_family_key(profile), []).append(profile)
    return sorted(
        (_compact_profile_family(group) for group in groups.values()),
        key=lambda item: (
            -int(item.get("profiles") or 0),
            -int(item.get("exposed") or 0),
            str(item.get("contract") or ""),
        ),
    )


async def _load_scope_manifest(container: AuditContainer, identifier: str) -> tuple[str, dict]:
    path = str(identifier or _SCOPE_MANIFEST_PATH).strip() or _SCOPE_MANIFEST_PATH
    if not path.startswith("/workspace/campaign/"):
        path = _SCOPE_MANIFEST_PATH
    payload = await _load_campaign_json_if_exists(container, path)
    if not payload:
        raise FileNotFoundError(path)
    return path, payload


async def _load_latest_artifact(
    container: AuditContainer,
    state: dict,
    *,
    explicit: str,
    directory: str,
    id_prefix: str,
) -> tuple[str, dict | None]:
    if explicit:
        path = explicit
        if re.fullmatch(rf"{re.escape(id_prefix)}-\d{{3,}}", explicit):
            path = f"{directory.rstrip('/')}/{explicit}.json"
        payload = await _load_campaign_json_if_exists(container, path)
        if not payload:
            raise FileNotFoundError(path)
        return path, payload
    paths = _progress_evidence_paths(state, directory.rstrip("/") + "/")
    for path in reversed(paths):
        payload = await _load_campaign_json_if_exists(container, path)
        if payload:
            return path, payload
    return "", None


async def _map_live_reachability(
    container: AuditContainer,
    args: dict,
    *,
    environ: dict[str, str] | None = None,
    config: dict | None = None,
) -> str:
    try:
        related_ids = _require_list(args.get("related_ids"), "related_ids")
        focus_contracts = {
            str(item).strip().lower()
            for item in _require_list(args.get("focus_contracts"), "focus_contracts")
            if str(item).strip()
        }
    except ValueError as exc:
        return f"Error: {exc}"

    max_profiles = min(max(int(args.get("max_profiles", 25)), 1), 100)
    response_items = min(max(int(args.get("response_items", 8)), 1), 50)
    probe_concurrency = min(max(int(args.get("probe_concurrency", 6)), 1), 20)
    state = await _load_campaign_state(container)
    try:
        manifest_path, manifest = await _load_scope_manifest(
            container,
            str(args.get("scope_manifest") or _SCOPE_MANIFEST_PATH),
        )
    except FileNotFoundError as exc:
        return f"Error: scope manifest not found: {exc}"

    action_space_path = ""
    action_space = None
    action_space_ref = str(args.get("action_space") or "").strip()
    if action_space_ref:
        try:
            action_space_path, action_space = await _load_action_space(
                container,
                action_space_ref,
            )
        except (FileNotFoundError, ValueError) as exc:
            return f"Error: {exc}"
    else:
        try:
            action_space_path, action_space = await _load_latest_artifact(
                container,
                state,
                explicit="",
                directory="/workspace/campaign/action-spaces",
                id_prefix="as",
            )
        except FileNotFoundError:
            action_space_path, action_space = "", None

    actions = (action_space or {}).get("actions") or []
    bases_by_contract = _action_space_contract_bases(action_space)
    execute_probes = bool(args.get("execute_probes", True))
    profiles = []
    for profile in manifest.get("ranked_profiles") or []:
        if not isinstance(profile, dict):
            continue
        if not profile.get("address"):
            continue
        if not _profile_matches_focus(profile, focus_contracts):
            continue
        profiles.append(profile)
        if len(profiles) >= max_profiles:
            break

    # Group profiles by their resolved chain and derive a per-chain endpoint;
    # never collapse a multi-chain scope onto one global ETH_RPC_URL.
    fork_context = await _resolve_fork_context_arg(container, args.get("fork_context"))
    registry = await _resolve_chain_registry_arg(container, args.get("chain_registry"))
    plan = await _plan_live_probe_chains(
        container,
        args,
        items=[
            {
                "address": str(profile.get("address") or "").strip(),
                "names": [profile.get("contract"), profile.get("profile")],
            }
            for profile in profiles
        ],
        registry=registry,
        fork_context=fork_context,
        environ=environ,
        config=config,
    )
    assignments = plan["assignments"]
    groups = plan["groups"]

    def _profile_chain(index: int):
        assignment = assignments[index]
        group = (
            groups.get(assignment.get("chain_key"))
            if assignment.get("status") == "grouped"
            else None
        )
        endpoint = (group or {}).get("endpoint")
        return assignment, group, endpoint, (endpoint.url if endpoint else None)

    mapped_profiles = []
    probe_summary = {
        "profiles": len(profiles),
        "probed": 0,
        "rpc_missing": 0,
        "code_present": 0,
        "no_code": 0,
        "unknown_code": 0,
        "probe_concurrency": probe_concurrency if execute_probes else 0,
    }

    async def _probe_profile(index: int, profile: dict) -> tuple[dict, dict]:
        address = str(profile.get("address") or "").strip()
        assignment, _group, _endpoint, rpc_url = _profile_chain(index)
        status = assignment.get("status")
        probe = {
            "executed": False,
            "rpc_available": None,
            "code_present": None,
            "values": {},
            "commands": _profile_probe_plan(address),
        }
        summary_delta = {
            "probed": 0,
            "rpc_missing": 0,
            "code_present": 0,
            "no_code": 0,
            "unknown_code": 0,
        }
        if status == "ambiguous":
            probe["skipped"] = "chain_ambiguous"
            summary_delta["unknown_code"] += 1
        elif status == "chain_mismatch":
            probe["skipped"] = "chain_mismatch"
            summary_delta["unknown_code"] += 1
        elif status == "grouped" and execute_probes and rpc_url:
            exit_code, output = await container.exec(
                _cast_probe_command(address, rpc_url),
                timeout=45,
            )
            parsed_probe = _parse_probe_output(output)
            probe.update({
                "executed": True,
                "exit_code": exit_code,
                **parsed_probe,
            })
            summary_delta["probed"] += 1
            code_present = parsed_probe.get("code_present")
            if code_present is True:
                summary_delta["code_present"] += 1
            elif code_present is False:
                summary_delta["no_code"] += 1
            else:
                summary_delta["unknown_code"] += 1
        elif execute_probes:
            # A chain was chosen (or none could be) but no endpoint resolved.
            probe.update({
                "rpc_available": False,
                "skipped": (
                    "rpc_not_configured" if status == "grouped" else "chain_unresolved"
                ),
            })
            summary_delta["rpc_missing"] += 1
            summary_delta["unknown_code"] += 1
        else:
            summary_delta["unknown_code"] += 1
        return probe, summary_delta

    async def _probe_profile_bounded(
        semaphore: asyncio.Semaphore,
        index: int,
        profile: dict,
    ) -> tuple[dict, dict]:
        async with semaphore:
            return await _probe_profile(index, profile)

    if execute_probes and profiles:
        semaphore = asyncio.Semaphore(probe_concurrency)
        probe_results = await asyncio.gather(
            *(
                _probe_profile_bounded(semaphore, index, profile)
                for index, profile in enumerate(profiles)
            ),
        )
    else:
        probe_results = [
            await _probe_profile(index, profile)
            for index, profile in enumerate(profiles)
        ]

    for index, (profile, (probe, summary_delta)) in enumerate(
        zip(profiles, probe_results, strict=True)
    ):
        assignment, group, endpoint, rpc_url = _profile_chain(index)
        for key in ("probed", "rpc_missing", "code_present", "no_code", "unknown_code"):
            probe_summary[key] += int(summary_delta.get(key) or 0)
        address = str(profile.get("address") or "").strip()
        matched_actions = [
            action for action in actions
            if isinstance(action, dict) and _action_matches_profile(action, profile)
        ]
        authority_decisions: dict[str, bool] = {}
        authority = str((probe.get("values") or {}).get("authority") or "").strip()
        authority_probe_actions = [
            action for action in matched_actions
            if (
                _classify_action_reachability(action).get("kind")
                in {"role_gated", "sender_checked", "cross_domain_or_sender_gated"}
                or any(
                    term in str(modifier or "").lower()
                    for modifier in action.get("modifiers") or []
                    for term in ("auth", "role", "permission")
                )
            )
        ]
        if (
            execute_probes
            and rpc_url
            and probe.get("code_present") is True
            and authority
            and not _zero_address(authority)
            and authority_probe_actions
        ):
            exit_code, output = await container.exec(
                _authority_probe_command(
                    target=address,
                    authority=authority,
                    actions=authority_probe_actions,
                    rpc_url=rpc_url,
                ),
                timeout=45,
            )
            authority_decisions = _parse_authority_probe_output(
                output,
                authority_probe_actions,
            )
            probe["authority_probe"] = {
                "executed": True,
                "exit_code": exit_code,
                "authority": authority,
                "attacker": _AUTHORITY_PROBE_ATTACKER,
                "decisions": authority_decisions,
            }

        target_binding = _live_target_binding(probe, profile=profile)
        action_exposures = []
        for action in matched_actions:
            reachability = dict(_classify_action_reachability(action))
            action_uid = _action_stable_uid(action)
            authority_probe = {}
            if action_uid in authority_decisions:
                attacker_can_call = bool(authority_decisions[action_uid])
                reasons = list(reachability.get("reasons") or [])
                reasons.append(
                    "live authority canCall probe allowed attacker"
                    if attacker_can_call
                    else "live authority canCall probe rejected attacker"
                )
                reachability.update({
                    "kind": "public_authorized" if attacker_can_call else "role_gated",
                    "attacker_reachable": attacker_can_call,
                    "confidence": "live_authority_probe",
                    "authority_attacker_can_call": attacker_can_call,
                    "reasons": _dedupe_text(reasons),
                })
                authority_probe = {
                    "authority": authority,
                    "attacker": _AUTHORITY_PROBE_ATTACKER,
                    "attacker_can_call": attacker_can_call,
                }
            source_relation = _action_source_relation(
                action,
                profile,
                bases_by_contract=bases_by_contract,
            )
            code_present = probe.get("code_present")
            if code_present is False:
                live_status = "no_code"
            elif code_present is True:
                live_status = "deployed"
            elif probe.get("executed"):
                live_status = "unknown"
            else:
                live_status = "unprobed"
            if live_status == "no_code":
                exposure = "dormant_or_wrong_address"
            elif not source_relation.get("executable_source"):
                exposure = (
                    "source_interface_only"
                    if source_relation.get("kind") == "source_interface_only"
                    else "source_artifact_only"
                )
            elif reachability["kind"] in {"public", "public_authorized"} and live_status == "deployed":
                exposure = "exposed"
            elif reachability["kind"] in {"public", "public_authorized"}:
                exposure = "source_public_live_unknown"
            elif reachability["kind"] in {"role_gated", "cross_domain_or_sender_gated"}:
                exposure = "gated"
            else:
                exposure = "unknown"
            action_exposures.append({
                "action_key": _action_logical_key(action),
                "action_uid": action_uid,
                "contract": action.get("contract"),
                "contract_kind": action.get("contract_kind"),
                "function": action.get("function"),
                "signature": _action_signature(action),
                "file": action.get("file"),
                "line": action.get("line"),
                "profile": profile.get("profile"),
                "profile_contract": profile.get("contract"),
                "profile_src": profile.get("src"),
                "affordances": action.get("affordances") or [],
                "modifiers": action.get("modifiers") or [],
                "parameters": action.get("parameters") or [],
                "reachability": reachability,
                "source_relation": source_relation,
                "authority_probe": authority_probe,
                "live_status": live_status,
                "exposure": exposure,
                "target_address": address,
                "target_binding": target_binding,
                "code_hash": (probe.get("values") or {}).get("code_sha256_16"),
                "clone_family_key": _live_reachability_clone_family_key(
                    action=action,
                    profile=profile,
                    target_binding=target_binding,
                    probe=probe,
                    reachability=reachability,
                ),
            })

        mapped_profiles.append({
            "profile": profile.get("profile"),
            "contract": profile.get("contract"),
            "address": address,
            "src": profile.get("src"),
            "tags": profile.get("tags") or [],
            "priority_score": profile.get("priority_score"),
            "network": assignment.get("network"),
            "chain_id": assignment.get("chain_id"),
            "chain_status": assignment.get("status"),
            "rpc_endpoint": _rpc_endpoint_summary(endpoint) if group else None,
            "probe": probe,
            "target_binding": target_binding,
            "action_exposures": action_exposures,
            "summary": {
                "actions_matched": len(action_exposures),
                "exposed": sum(1 for item in action_exposures if item["exposure"] == "exposed"),
                "gated": sum(1 for item in action_exposures if item["exposure"] == "gated"),
                "source_interface_only": sum(
                    1 for item in action_exposures
                    if item["exposure"] == "source_interface_only"
                ),
                "source_artifact_only": sum(
                    1 for item in action_exposures
                    if item["exposure"] == "source_artifact_only"
                ),
                "unknown": sum(1 for item in action_exposures if item["exposure"] == "unknown"),
            },
        })

    profile_families = _profile_families(mapped_profiles)
    target_binding_counts: dict[str, int] = {}
    for mapped_profile in mapped_profiles:
        binding_kind = str(
            (mapped_profile.get("target_binding") or {}).get("kind") or "unknown"
        )
        target_binding_counts[binding_kind] = (
            target_binding_counts.get(binding_kind, 0) + 1
        )
    grouping = _summarize_live_probe_chains(
        assignments=assignments,
        groups=groups,
        entries=mapped_profiles,
        meta_for=lambda index: {
            "profile": profiles[index].get("profile"),
            "contract": profiles[index].get("contract"),
            "address": str(profiles[index].get("address") or "").strip(),
        },
    )
    reachability_id = _next_campaign_id(state, "live_reachability")
    title = str(args.get("title") or "Live reachability map").strip()
    payload = {
        "id": reachability_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "scope_manifest_path": manifest_path,
        "action_space_path": action_space_path or None,
        "execute_probes": execute_probes,
        "probe_concurrency": probe_concurrency if execute_probes else 0,
        "filters": {"focus_contracts": sorted(focus_contracts)},
        "profiles": mapped_profiles,
        "profile_families": profile_families,
        "chains": grouping["chains"],
        "ambiguous_targets": grouping["ambiguous_targets"],
        "skipped_targets": grouping["skipped_targets"],
        "summary": {
            **probe_summary,
            "profile_families": len(profile_families),
            "target_bindings": target_binding_counts,
            "chains": len(grouping["chains"]),
            "chains_probed": len(grouping["chains_probed"]),
            "ambiguous_targets": len(grouping["ambiguous_targets"]),
            "skipped_targets": len(grouping["skipped_targets"]),
            "live_deployed_profiles": sum(
                1 for item in mapped_profiles
                if (item.get("target_binding") or {}).get("live_deployed")
            ),
            "economically_significant_profiles": sum(
                1 for item in mapped_profiles
                if (item.get("target_binding") or {}).get("economically_significant_hint")
            ),
            "profiles_with_actions": sum(1 for item in mapped_profiles if item["action_exposures"]),
            "action_exposures": sum(len(item["action_exposures"]) for item in mapped_profiles),
            "exposed_actions": sum(
                1
                for profile in mapped_profiles
                for item in profile["action_exposures"]
                if item["exposure"] == "exposed"
            ),
            "gated_actions": sum(
                1
                for profile in mapped_profiles
                for item in profile["action_exposures"]
                if item["exposure"] == "gated"
            ),
            "source_interface_actions": sum(
                1
                for profile in mapped_profiles
                for item in profile["action_exposures"]
                if item["exposure"] == "source_interface_only"
            ),
            "source_artifact_actions": sum(
                1
                for profile in mapped_profiles
                for item in profile["action_exposures"]
                if item["exposure"] == "source_artifact_only"
            ),
        },
        "related_ids": [str(item) for item in related_ids],
    }
    path = f"/workspace/campaign/live-reachability/{reachability_id}.json"
    await container.write_file(path, json.dumps(payload, indent=2, sort_keys=True) + "\n")
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Live reachability map: {title}",
            content=(
                f"Live reachability: {reachability_id}\n"
                f"Path: {path}\n"
                f"Scope manifest: {manifest_path}\n"
                f"Action space: {action_space_path or 'none'}\n"
                f"Profiles: {payload['summary']['profiles']}\n"
                f"Profile families: {payload['summary']['profile_families']}\n"
                f"Live deployed profiles: {payload['summary']['live_deployed_profiles']}\n"
                "Economically significant profile hints: "
                f"{payload['summary']['economically_significant_profiles']}\n"
                f"Action exposures: {payload['summary']['action_exposures']}\n"
                f"Exposed actions: {payload['summary']['exposed_actions']}\n"
                f"Gated actions: {payload['summary']['gated_actions']}\n"
                "Use this as live reachability context; do not treat it as a finding."
            ),
            evidence=[path, manifest_path] + ([action_space_path] if action_space_path else []),
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    all_exposures = [
        exposure
        for profile in mapped_profiles
        for exposure in profile.get("action_exposures") or []
    ]
    top_exposures = sorted(
        all_exposures,
        key=lambda item: (
            -_attack_graph_candidate_score(item, ""),
            str(item.get("action_key") or ""),
        ),
    )[:response_items]

    return json.dumps({
        "live_reachability_id": reachability_id,
        "path": path,
        "result_id": result_id or None,
        "summary": payload["summary"],
        "chains_probed": [
            _compact_chain_block(block) for block in grouping["chains_probed"]
        ],
        "targets_by_chain": {
            block["key"]: block["targets"] for block in grouping["chains"]
        },
        "ambiguous_targets": grouping["ambiguous_targets"],
        "skipped_targets": grouping["skipped_targets"],
        "profiles": [
            _compact_profile_reachability(
                item,
                max_exposures=max(2, response_items // 3),
            )
            for item in mapped_profiles[: min(response_items, len(mapped_profiles))]
        ],
        "profile_families": profile_families[:response_items],
        "top_exposures": [_compact_exposure_entry(item) for item in top_exposures],
        "omitted_from_response": {
            "profiles": max(0, len(mapped_profiles) - response_items),
            "profile_families": max(0, len(profile_families) - response_items),
            "action_exposures": max(0, len(all_exposures) - len(top_exposures)),
            "note": "Open the artifact path for full per-profile reachability.",
        },
    }, indent=2, sort_keys=True)


