def _attack_graph_direction_hint(action: dict) -> str:
    labels = {str(item) for item in action.get("affordances") or []}
    text = _coverage_normalize_text(" ".join(
        str(action.get(key) or "")
        for key in ("action_key", "contract", "function", "signature")
    ))
    has_inbound_value = bool(
        labels.intersection({"value_in_or_mint", "accepts_native_value"})
    )
    has_release_value = "value_out_or_burn" in labels
    has_privileged_economics = bool(
        labels.intersection({
            "credit_or_liquidation",
            "valuation_dependency",
            "market_or_router",
            "signed_authorization",
            "signature_gate",
            "callback_or_flashloan_surface",
        })
    )
    if has_release_value or any(term in text for term in _ATTACK_GRAPH_OUTBOUND_FUNCTION_TERMS):
        return "outbound_or_release"
    if (
        has_inbound_value
        and not has_release_value
        and not has_privileged_economics
        and any(term in text for term in _ATTACK_GRAPH_INBOUND_FUNCTION_TERMS)
    ):
        return "inbound_value_entry"
    if has_inbound_value and not has_release_value and labels <= {
        "value_in_or_mint",
        "accepts_native_value",
        "token_or_native_transfer",
        "cross_domain_or_message",
        "external_call",
    }:
        return "inbound_value_entry"
    return "unknown"


def _attack_graph_direction_notes(direction_hint: str) -> list[str]:
    if direction_hint == "inbound_value_entry":
        return [
            "Ingress-only value paths are not findings by themselves.",
            "First prove over-crediting, unsupported fee-on-transfer behavior, or an executable release leg before report review.",
        ]
    if direction_hint == "outbound_or_release":
        return [
            "Prioritize unauthorized release, redemption, settlement, or cross-domain execution evidence.",
        ]
    return []


def _attack_graph_objective(action: dict) -> str:
    labels = set(action.get("affordances") or [])
    key = action.get("action_key") or _coverage_action_key(action)
    if _attack_graph_direction_hint(action) == "inbound_value_entry":
        return (
            f"{key} must not credit, mint, bridge, or account for more value "
            "than the caller actually transfers, locks, or authorizes."
        )
    if labels.intersection({"value_out_or_burn", "token_or_native_transfer"}):
        return f"{key} must not release more value to the attacker than authorized."
    if labels.intersection({"valuation_dependency", "market_or_router"}):
        return f"{key} must not let attacker-controlled market/oracle state create profit."
    if labels.intersection({"credit_or_liquidation"}):
        return f"{key} must not create bad debt or unfair liquidation value."
    if labels.intersection({"cross_domain_or_message"}):
        return f"{key} must not mint/release value without a valid source-domain state transition."
    if labels.intersection({"signed_authorization", "signature_gate", "signature_input"}):
        return f"{key} must bind authorization to every execution-critical field."
    return f"{key} must preserve authorization, solvency, and accounting invariants."


def _reachability_high_trust(reachability: object) -> bool:
    """True when a reachability verdict is trustworthy enough to fully bury a
    branch: AST-derived (exact modifiers) or live-authority-probe confirmed.
    Regex source-only gate verdicts are medium confidence and not high trust."""
    if not isinstance(reachability, dict):
        return False
    return str(reachability.get("confidence") or "") in {
        "high",
        "live_authority_probe",
    }


def _attack_graph_candidate_score(exposure: dict, focus: str) -> int:
    score, _reasons = _coverage_attention(exposure)
    reachability_info = exposure.get("reachability") or {}
    reachability = reachability_info.get("kind")
    gate_high_trust = _reachability_high_trust(reachability_info)
    live_status = exposure.get("live_status")
    exposure_status = exposure.get("exposure")
    direction_hint = _attack_graph_direction_hint(exposure)
    affordances = {str(item) for item in exposure.get("affordances") or []}
    target_binding = exposure.get("target_binding") or {}
    binding_kind = str(target_binding.get("kind") or "")
    if exposure_status == "exposed":
        score += 6
    elif exposure_status == "source_public_live_unknown":
        score += 1
    elif exposure_status == "gated":
        # "gated" derives from a role/sender reachability verdict. Fully bury it
        # only when that verdict is trustworthy (AST modifiers or live authority
        # probe); soften an unverified source-only (regex) guess so a misparse
        # cannot silently drop a real high-value surface below the score floor.
        score -= 10 if gate_high_trust else 4
    elif exposure_status == "dormant_or_wrong_address":
        score -= 8
    elif exposure_status in {"source_interface_only", "source_artifact_only"}:
        score -= 12
    if reachability in {"role_gated", "cross_domain_or_sender_gated"}:
        score -= 4 if gate_high_trust else 2
    elif reachability == "sender_checked":
        score -= 2
    if reachability == "signature_gated":
        score -= 3
    if live_status == "deployed":
        score += 2
    elif live_status in {"unknown", "unprobed"}:
        score -= 1
    if binding_kind == "active_proxy":
        score += 8
    elif binding_kind == "deployed_economic_contract":
        score += 7
    elif binding_kind == "deployed_configured_contract":
        score += 4
    elif binding_kind == "deployed_contract":
        score += 2
    elif binding_kind == "deployed_implementation_or_template":
        score -= 9
    elif binding_kind == "no_code":
        score -= 14
    elif binding_kind in {"unknown_code", "unprobed"}:
        score -= 2
    if target_binding.get("economically_significant_hint"):
        score += 3
    if "value_out_or_burn" in affordances:
        score += 4
    if affordances.intersection({"credit_or_liquidation", "valuation_dependency"}):
        score += 3
    if affordances.intersection({"generic_execution", "delegatecall"}):
        if _attack_graph_generic_execution_has_economic_route(exposure, affordances):
            score += 4
        else:
            score -= 2
    score += _attack_graph_proxy_helper_score_delta(exposure, affordances)
    if direction_hint == "inbound_value_entry":
        score -= 5
    elif direction_hint == "outbound_or_release":
        score += 2
    if _plan_focus_bonus(focus, exposure.get("action_key"), exposure.get("contract")):
        score += 2
    return score


def _attack_graph_generic_execution_has_economic_route(
    exposure: dict,
    affordances: set[str],
) -> bool:
    if affordances.intersection({
        "value_out_or_burn",
        "credit_or_liquidation",
        "valuation_dependency",
        "market_or_router",
        "callback_or_flashloan_surface",
        "token_or_native_transfer",
        "cross_domain_or_message",
    }):
        return True
    target_binding = exposure.get("target_binding") or {}
    if target_binding.get("economically_significant_hint"):
        text = _coverage_normalize_text(" ".join(
            str(exposure.get(key) or "")
            for key in ("function", "signature", "action_key")
        ))
        return any(term in text for term in ("execute", "multicall", "callback", "flash"))
    return False


def _attack_graph_proxy_helper_score_delta(
    exposure: dict,
    affordances: set[str],
) -> int:
    function = str(exposure.get("function") or "").strip()
    action_key = str(exposure.get("action_key") or "")
    normalized = _coverage_normalize_text(f"{function} {action_key}")
    is_proxy_helper = (
        function in _ATTACK_GRAPH_PROXY_HELPER_FUNCTIONS
        or "delegate to implementation" in normalized
        or "delegate to view implementation" in normalized
        or normalized.endswith(" implementation")
        or " upgrade to " in f" {normalized} "
    )
    if not is_proxy_helper:
        return 0
    if affordances.intersection({
        "value_out_or_burn",
        "credit_or_liquidation",
        "valuation_dependency",
        "market_or_router",
        "callback_or_flashloan_surface",
    }):
        return -4
    return -12


def _candidate_action_from_exposure(exposure: dict) -> dict:
    action = {
        "actor": "attacker",
        "contract": exposure.get("contract"),
        "function": exposure.get("function"),
        "target": exposure.get("target_address"),
        "args": _action_arg_names(exposure),
        "expected_effect": _attack_graph_objective(exposure),
        "bounds": "derive from live balances, caps, fees, and authorization constraints",
        "live_exposure": exposure.get("exposure"),
        "live_status": exposure.get("live_status"),
        "target_binding": exposure.get("target_binding"),
        "action_key": exposure.get("action_key"),
        "action_uid": exposure.get("action_uid"),
        "clone_family_key": exposure.get("clone_family_key"),
        "affordances": exposure.get("affordances") or [],
        "direction_hint": _attack_graph_direction_hint(exposure),
        "reachability": exposure.get("reachability") or {},
        "source": {
            key: exposure.get(key)
            for key in ("file", "line", "signature")
            if exposure.get(key) not in (None, "", [], {})
        },
    }
    blockers = []
    if exposure.get("exposure") in {
        "gated",
        "dormant_or_wrong_address",
        "source_interface_only",
        "source_artifact_only",
    }:
        blockers.append(f"live exposure is {exposure.get('exposure')}")
    if exposure.get("live_status") not in {None, "", "deployed"}:
        blockers.append(f"live status is {exposure.get('live_status')}")
    binding_kind = str((exposure.get("target_binding") or {}).get("kind") or "")
    if binding_kind in {
        "deployed_implementation_or_template",
        "no_code",
        "unknown_code",
    }:
        blockers.append(f"target binding is {binding_kind}")
    if blockers:
        action["live_blockers"] = blockers
    return action


def _exposure_search_text(exposure: dict) -> str:
    fields = [
        exposure.get("action_key"),
        exposure.get("contract"),
        exposure.get("contract_kind"),
        exposure.get("function"),
        exposure.get("signature"),
        exposure.get("file"),
        exposure.get("profile"),
        exposure.get("profile_contract"),
        exposure.get("profile_src"),
    ]
    fields.extend(exposure.get("affordances") or [])
    return _coverage_normalize_text(" ".join(str(item or "") for item in fields))


def _exposure_is_live_callable(exposure: dict) -> bool:
    return (
        exposure.get("exposure") in {"exposed", "source_public_live_unknown"}
        and exposure.get("live_status") in {None, "", "deployed"}
    )


def _attack_graph_candidate_dedupe_key(exposure: dict) -> str:
    action_key = str(exposure.get("action_key") or "").strip().lower()
    reachability = str((exposure.get("reachability") or {}).get("kind") or "").strip()
    exposure_status = str(exposure.get("exposure") or "").strip()
    profile_contract = str(
        exposure.get("profile_contract") or exposure.get("contract") or ""
    ).strip().lower()
    return "|".join([profile_contract, action_key, reachability, exposure_status])


def _exposure_function(exposure: dict) -> str:
    return _coverage_normalize_text(str(exposure.get("function") or ""))


def _exposure_profile_contract(exposure: dict) -> str:
    return _coverage_normalize_text(
        str(exposure.get("profile_contract") or exposure.get("contract") or "")
    )


def _lending_market_preference(exposure: dict) -> tuple[int, int, str]:
    text = _exposure_search_text(exposure)
    contract_text = _coverage_normalize_text(str(exposure.get("contract") or ""))
    profile_text = _exposure_profile_contract(exposure)
    preference = 0
    if any(term in text for term in ("delegator", "proxy", "market")):
        preference += 8
    if any(term in contract_text for term in ("delegator", "ctoken")):
        preference += 4
    if contract_text and profile_text and contract_text == profile_text:
        preference += 3
    if "cether" in text:
        preference += 2
    if any(term in text for term in ("cerc20", "ctoken", "compound")):
        preference += 5
    if "interface" in contract_text:
        preference -= 5
    if any(term in text for term in ("delegate", "implementation")):
        preference -= 3
    return (
        -preference,
        -_attack_graph_candidate_score(exposure, ""),
        str(exposure.get("action_key") or ""),
    )


def _find_lending_exposure(
    exposures: list[dict],
    functions: set[str],
    *,
    prefer_controller: bool = False,
    exclude_address: str = "",
) -> dict | None:
    candidates = [
        exposure for exposure in exposures
        if isinstance(exposure, dict)
        and _exposure_is_live_callable(exposure)
        and _exposure_function(exposure) in functions
    ]
    excluded = str(exclude_address or "").strip().lower()
    if excluded:
        distinct = [
            item for item in candidates
            if str(item.get("target_address") or "").strip().lower() != excluded
        ]
        if distinct:
            candidates = distinct
    if prefer_controller:
        controller = [
            item for item in candidates
            if any(
                term in _exposure_profile_contract(item)
                for term in ("comptroller", "unitroller", "controller")
            )
        ]
        if not controller:
            controller = [
                item for item in candidates
                if _coverage_normalize_text(str(item.get("contract") or ""))
                in {"comptroller", "unitroller", "controller"}
            ]
        if controller:
            return sorted(
                controller,
                key=lambda item: (
                    0 if "unitroller" in _exposure_profile_contract(item) else 1,
                    0 if "proxy" in _exposure_search_text(item) else 1,
                    _lending_market_preference(item),
                ),
            )[0]
    if not candidates:
        return None
    return sorted(candidates, key=_lending_market_preference)[0]


def _unique_lending_market_targets(exposures: list[dict], *, limit: int = 10) -> list[dict]:
    seen = set()
    markets = []
    for exposure in sorted(exposures, key=_lending_market_preference):
        if not isinstance(exposure, dict) or not _exposure_is_live_callable(exposure):
            continue
        if _exposure_function(exposure) not in {
            "mint",
            "redeem",
            "redeemunderlying",
            "borrow",
            "liquidateborrow",
            "addreserves",
            "exchangeratecurrent",
        }:
            continue
        text = _exposure_search_text(exposure)
        if not any(term in text for term in ("cether", "cerc20", "ctoken", "compound", "market")):
            continue
        address = str(exposure.get("target_address") or "").strip()
        if not address or address.lower() in seen:
            continue
        seen.add(address.lower())
        markets.append({
            "contract": exposure.get("contract"),
            "address": address,
            "profile_action": exposure.get("action_key"),
            "code_context": exposure.get("file"),
        })
        if len(markets) >= limit:
            break
    return markets


_QUEUE_REQUEST_TERMS = (
    "createwithdrawrequest",
    "create withdraw request",
    "enqueuewithdraw",
    "enqueue withdraw",
    "initiatewithdraw",
    "initiate withdraw",
    "makewithdrawrequest",
    "make withdraw request",
    "queuewithdrawal",
    "queue withdrawal",
    "queuewithdraw",
    "queue withdraw",
    "requestclaim",
    "request claim",
    "requestonchainwithdraw",
    "request on chain withdraw",
    "requestredeem",
    "request redeem",
    "requestwithdrawal",
    "request withdrawal",
    "requestwithdraw",
    "request withdraw",
    "withdrawrequest",
    "withdraw request",
    "withdrawalrequest",
    "withdrawal request",
)
_QUEUE_SETTLEMENT_TERMS = (
    "claimqueued",
    "claim queued",
    "claimrequest",
    "claim request",
    "claimwithdraw",
    "claim withdraw",
    "completewithdraw",
    "complete withdraw",
    "executewithdraw",
    "execute withdraw",
    "finalizewithdraw",
    "finalize withdraw",
    "fulfillwithdraw",
    "fulfill withdraw",
    "maturewithdraw",
    "mature withdraw",
    "processwithdraw",
    "process withdraw",
    "settlerequest",
    "settle request",
    "settlewithdraw",
    "settle withdraw",
    "solveonchainwithdraw",
    "solve on chain withdraw",
    "solvewithdraw",
    "solve withdraw",
)
_QUEUE_MUTATION_TERMS = (
    "cancelonchainwithdraw",
    "cancelrequest",
    "cancel request",
    "cancelwithdraw",
    "cancel withdraw",
    "replacerequest",
    "replace request",
    "replacewithdraw",
    "replace withdraw",
    "updaterequest",
    "update request",
    "updatewithdraw",
    "update withdraw",
)


def _queue_exposure_haystack(exposure: dict) -> str:
    return f"{_exposure_function(exposure)} {_exposure_search_text(exposure)}"


def _is_queue_request_exposure(exposure: dict) -> bool:
    haystack = _queue_exposure_haystack(exposure)
    return any(term in haystack for term in _QUEUE_REQUEST_TERMS)


def _is_queue_settlement_exposure(exposure: dict) -> bool:
    haystack = _queue_exposure_haystack(exposure)
    function = _exposure_function(exposure)
    if any(term in haystack for term in _QUEUE_SETTLEMENT_TERMS):
        return True
    if any(
        term in function
        for term in ("claim", "complete", "execute", "finalize", "fulfill", "process", "settle", "solve")
    ):
        return any(term in haystack for term in ("on chain withdraw", "queue", "request", "withdraw"))
    return False


def _is_queue_mutation_exposure(exposure: dict) -> bool:
    haystack = _queue_exposure_haystack(exposure)
    return any(term in haystack for term in _QUEUE_MUTATION_TERMS)


def _economic_roles(exposure: dict) -> set[str]:
    labels = {str(item) for item in exposure.get("affordances") or []}
    function = _exposure_function(exposure)
    text = _exposure_search_text(exposure)
    roles: set[str] = set()
    if _is_queue_request_exposure(exposure):
        roles.add("queue_request")
        roles.add("setup_capital")
        roles.add("claim_creation")
    if _is_queue_settlement_exposure(exposure):
        roles.add("queue_settlement")
        roles.add("extraction")
    if _is_queue_mutation_exposure(exposure):
        roles.add("queue_mutation")
        roles.add("perturbation")
    if (
        "value_in_or_mint" in labels
        or function in {"deposit", "mint", "supply", "stake", "lock"}
        or function.startswith(("deposit", "mint", "supply", "stake"))
    ):
        roles.add("setup_capital")
    if (
        function in {"mint", "deposit", "supply", "stake", "entermarkets"}
        or function.startswith(("mint", "deposit", "supply", "stake"))
    ):
        roles.add("claim_creation")
    if (
        "valuation_dependency" in labels
        or function.startswith(("exchangerate", "totalassets", "getaccountliquidity"))
        or any(term in text for term in ("oracle", "price", "rate", "totalassets"))
    ):
        roles.add("valuation_read")
    if (
        labels.intersection({
            "valuation_dependency",
            "market_or_router",
            "callback_or_flashloan_surface",
            "generic_execution",
        })
        or function in {"sync", "skim", "swap", "rebalance", "rebase", "accrueinterest"}
        or function.startswith(("swap", "sync", "updateprice", "setprice", "accrue"))
    ):
        roles.add("perturbation")
    if "cross_domain_or_message" in labels and any(
        term in text for term in ("bridge", "message", "send", "relay", "receive")
    ):
        roles.add("perturbation")
    if (
        "value_out_or_burn" in labels
        or "credit_or_liquidation" in labels
        or function in {
            "withdraw",
            "redeem",
            "borrow",
            "claim",
            "release",
            "relay",
            "settle",
            "liquidate",
            "liquidateborrow",
            "exit",
            "unlock",
            "unstake",
            "undelegate",
        }
        or function.startswith((
            "withdraw",
            "redeem",
            "borrow",
            "claim",
            "release",
            "liquidate",
            "unstake",
            "undelegate",
        ))
    ):
        roles.add("extraction")
    return roles


def _economic_exposure_callable(exposure: dict) -> bool:
    if not _exposure_is_live_callable(exposure):
        return False
    reachability = exposure.get("reachability") or {}
    return reachability.get("attacker_reachable") is not False


def _economic_group_key(exposure: dict) -> tuple[str, str]:
    address = str(exposure.get("target_address") or "").strip().lower()
    contract = _exposure_profile_contract(exposure)
    return address, contract


def _economic_exposure_identity(exposure: dict | None) -> str:
    if not exposure:
        return ""
    return ":".join(
        str(exposure.get(key) or "").strip().lower()
        for key in ("action_uid", "action_key", "target_address")
    )


def _economic_best_exposure(exposures: list[dict], role: str) -> dict | None:
    candidates = [
        exposure for exposure in exposures
        if role in _economic_roles(exposure)
        and _economic_exposure_callable(exposure)
        and str(exposure.get("target_address") or "").strip()
    ]
    if not candidates:
        return None
    return sorted(
        candidates,
        key=lambda item: (
            -_attack_graph_candidate_score(item, ""),
            str(item.get("action_key") or ""),
        ),
    )[0]


def _economic_best_distinct_exposure(
    exposures: list[dict],
    role: str,
    excluded: set[str],
) -> dict | None:
    candidates = [
        exposure for exposure in exposures
        if _economic_exposure_identity(exposure) not in excluded
    ]
    return _economic_best_exposure(candidates, role)


def _economic_chain_action(exposure: dict, expected_effect: str) -> dict:
    action = _candidate_action_from_exposure(exposure)
    action["expected_effect"] = expected_effect
    action["economic_roles"] = sorted(_economic_roles(exposure))
    return action


def _economic_synthetic_donation_action(target_label: str, target_address: str) -> dict:
    return {
        "actor": "attacker",
        "contract": "ExternalAsset",
        "function": "transfer",
        "target": "<asset token>",
        "args": [target_address or target_label or "target", "donationAmount"],
        "parameters": [
            {"name": "to", "raw": "address to"},
            {"name": "amount", "raw": "uint256 amount"},
        ],
        "expected_effect": (
            "Perturb the target's asset/accounting balance without minting "
            "proportional shares or claims, then measure whether extraction is over-credited."
        ),
        "bounds": "Bind the live asset from inventory before running; reject if donation cost exceeds extractable value.",
        "live_exposure": "external_token_transfer",
        "live_status": "manual",
        "action_key": "external::donateAssetToAccountingTarget",
        "affordances": ["token_or_native_transfer", "valuation_dependency"],
        "direction_hint": "inbound_value_entry",
        "economic_roles": ["perturbation"],
        "manual_only": True,
        "notes": "Synthetic donation/rebase/fee perturbation; resolve asset() or underlying() with inventory_live_targets.",
    }


def _economic_chain_score(
    *,
    setup: dict,
    extraction: dict,
    perturbation: dict | None,
    motif: str,
    focus: str,
) -> int:
    roles = _economic_roles(setup) | _economic_roles(extraction)
    if perturbation:
        roles |= _economic_roles(perturbation)
    score = 22
    score += 4 if "setup_capital" in roles else 0
    score += 5 if "perturbation" in roles or perturbation is None else 0
    score += 5 if "extraction" in roles else 0
    score += 3 if "valuation_read" in roles else 0
    score += 2 if "claim_creation" in roles else 0
    score += _attack_graph_candidate_score(extraction, "") // 3
    score += _plan_focus_bonus(
        focus,
        setup.get("action_key"),
        extraction.get("action_key"),
        motif,
    )
    if motif == "vault_share_inflation":
        score += 3
    if motif == "bridge_message_accounting":
        score += 2
    return score


def _economic_chain_observations(contract: str, target: str, motif: str) -> list[dict]:
    return [
        {
            "label": "attacker and protocol balances",
            "target": contract or target or "target",
            "timing": "before and after",
            "notes": "Measure attacker asset/share balances, target balances, and net profit/loss.",
        },
        {
            "label": "accounting state",
            "target": contract or target or "target",
            "timing": "before and after each chain leg",
            "notes": (
                "Read totalAssets/totalSupply/exchange rate/debt/claim state "
                f"relevant to the {motif.replace('_', ' ')} motif."
            ),
        },
    ]


def _economic_chain_candidate(
    *,
    motif: str,
    setup: dict,
    extraction: dict,
    perturbation: dict | None,
    action_space_path: str,
    live_path: str,
    protocol_graph_path: str,
    focus: str,
) -> dict:
    contract = str(
        extraction.get("profile_contract")
        or extraction.get("contract")
        or setup.get("profile_contract")
        or setup.get("contract")
        or "EconomicTarget"
    )
    target = str(extraction.get("target_address") or setup.get("target_address") or "")
    actions = [
        _economic_chain_action(
            setup,
            "Create the attacker's initial claim/collateral/share state with live bounds.",
        ),
    ]
    if perturbation:
        actions.append(_economic_chain_action(
            perturbation,
            "Perturb accounting, valuation, message, or market state before extracting value.",
        ))
    elif motif in {"vault_share_inflation", "oracle_market_valuation"}:
        actions.append(_economic_synthetic_donation_action(contract, target))
    actions.append(
        _economic_chain_action(
            extraction,
            "Extract value or credit after the perturbation and measure net profit/loss.",
        ),
    )
    score = _economic_chain_score(
        setup=setup,
        extraction=extraction,
        perturbation=perturbation,
        motif=motif,
        focus=focus,
    )
    action_key = f"Economic::{motif}::{contract}"
    title = f"Test {motif.replace('_', ' ')} chain on {contract}"
    return {
        "attack_key": f"economic:{motif}:{target.lower() or contract.lower()}",
        "title": title,
        "priority_score": score,
        "priority": _plan_priority(score),
        "action_key": action_key,
        "contract": contract,
        "function": " -> ".join(
            str(action.get("function") or "step")
            for action in actions
        ),
        "target_address": target,
        "exposure": extraction.get("exposure"),
        "reachability": extraction.get("reachability"),
        "target_binding": extraction.get("target_binding") or setup.get("target_binding"),
        "affordances": _dedupe_text([
            *[str(item) for item in setup.get("affordances") or []],
            *[str(item) for item in (perturbation or {}).get("affordances") or []],
            *[str(item) for item in extraction.get("affordances") or []],
            "economic_chain",
        ]),
        "direction_hint": "outbound_or_release",
        "candidate_kind": "economic_chain",
        "mechanism": motif,
        "economic_chain": {
            "motif": motif,
            "roles": {
                "setup": sorted(_economic_roles(setup)),
                "perturbation": (
                    sorted(_economic_roles(perturbation))
                    if perturbation else ["synthetic_external_perturbation"]
                    if motif in {"vault_share_inflation", "oracle_market_valuation"}
                    else ["setup_leg_carries_message_perturbation"]
                ),
                "extraction": sorted(_economic_roles(extraction)),
            },
            "core_targets": _dedupe_text([
                str(setup.get("target_address") or ""),
                str((perturbation or {}).get("target_address") or ""),
                str(extraction.get("target_address") or ""),
            ]),
        },
        "actions": actions,
        "objective": (
            "The complete setup -> perturbation -> extraction chain must not "
            "produce attacker profit, protocol loss, bad debt, unfair shares, "
            "or unauthorized mint/release relative to the live starting state."
        ),
        "observations": _economic_chain_observations(contract, target, motif),
        "recommended_next_tool": "inventory_live_targets then prepare_fork_exploit_workbench",
        "required_live_evidence": [
            "inventory_live_targets for every core target and asset/underlying/controller dependency",
            "active proxy or deployed configured/economic target bindings for core deployed targets",
            "fork block and live target bindings for setup, perturbation, and extraction legs",
            "before/after balances, shares, debt, exchange rate, or message/accounting state",
            "economic proof that perturbation/setup cost is less than extracted value or caused protocol loss",
        ],
        "blockers": [
            "Reject if any critical setup, perturbation, or extraction leg is privileged-only or dormant.",
            "Reject if live inventory shows the perturbation cannot affect the accounting/valuation state.",
            "Reject if required capital or fees exceed extractable value.",
        ],
        "planning_notes": [
            "This is a multi-step economic experiment candidate, not a single-entrypoint finding.",
            "Do not run the sequence until inventory resolves assets, bounds, and the measurable objective.",
        ],
        "source": {
            "action_space": action_space_path,
            "live_reachability": live_path,
            "protocol_graph": protocol_graph_path or None,
        },
    }


def _queue_settlement_available(exposure: dict) -> bool:
    if not str(exposure.get("target_address") or "").strip():
        return False
    if exposure.get("live_status") not in {None, "", "deployed"}:
        return False
    return exposure.get("exposure") not in {
        "dormant_or_wrong_address",
        "source_interface_only",
        "source_artifact_only",
    }


def _queue_best_settlement_exposure(exposures: list[dict]) -> dict | None:
    candidates = [
        exposure for exposure in exposures
        if _is_queue_settlement_exposure(exposure)
        and _queue_settlement_available(exposure)
    ]
    if not candidates:
        return None
    return sorted(
        candidates,
        key=lambda item: (
            not _economic_exposure_callable(item),
            -_attack_graph_candidate_score(item, ""),
            str(item.get("action_key") or ""),
        ),
    )[0]


def _queue_solver_chain_candidate(
    *,
    request: dict,
    settlement: dict,
    mutation: dict | None,
    action_space_path: str,
    live_path: str,
    protocol_graph_path: str,
    focus: str,
) -> dict:
    contract = str(
        request.get("profile_contract")
        or request.get("contract")
        or settlement.get("profile_contract")
        or settlement.get("contract")
        or "Queue"
    )
    target = str(request.get("target_address") or settlement.get("target_address") or "")
    request_action = _economic_chain_action(
        request,
        (
            "Create a user-owned queued withdrawal/claim with exact live shares, "
            "assets, deadline, permit, and request-id bindings."
        ),
    )
    actions = [request_action]
    if mutation:
        actions.append(_economic_chain_action(
            mutation,
            (
                "Mutate, replace, or cancel the queued claim and measure whether "
                "accounting snapshots, ownership, or excess routing become stale."
            ),
        ))
    settlement_action = _economic_chain_action(
        settlement,
        (
            "Settle the exact queued claim and verify assets, shares, fees, "
            "solver allowance, and excess routing against the request state."
        ),
    )
    if not _economic_exposure_callable(settlement):
        settlement_action["actor"] = "authorized solver/keeper"
        settlement_action["manual_only"] = True
        settlement_action.setdefault("live_blockers", []).append(
            "settlement leg is not attacker-callable; bind the production solver/keeper path"
        )
    actions.append(settlement_action)

    score = 30
    score += 3 if mutation else 0
    score += 4 if _economic_exposure_callable(settlement) else -3
    score += _attack_graph_candidate_score(request, focus) // 3
    score += _attack_graph_candidate_score(settlement, focus) // 3
    score += _plan_focus_bonus(
        focus,
        request.get("action_key"),
        settlement.get("action_key"),
        "queue_solver_accounting",
    )
    blockers = [
        "Reject if the request cannot create a live user-owned queued claim.",
        "Reject if the settled assets/shares/fees/excess exactly match live queue accounting.",
    ]
    if not _economic_exposure_callable(settlement):
        blockers.append(
            "Settlement leg is not attacker-callable; only continue if an authorized production solver/keeper can settle the exact request."
        )

    return {
        "attack_key": f"economic:queue_solver:{target.lower() or contract.lower()}",
        "title": f"Test queue request-to-settlement accounting on {contract}",
        "priority_score": score,
        "priority": _plan_priority(score),
        "action_key": f"QueueSolver::{contract}",
        "contract": contract,
        "function": " -> ".join(str(action.get("function") or "step") for action in actions),
        "target_address": target,
        "exposure": request.get("exposure"),
        "reachability": request.get("reachability"),
        "target_binding": request.get("target_binding") or settlement.get("target_binding"),
        "affordances": _dedupe_text([
            *[str(item) for item in request.get("affordances") or []],
            *[str(item) for item in (mutation or {}).get("affordances") or []],
            *[str(item) for item in settlement.get("affordances") or []],
            "economic_chain",
        ]),
        "direction_hint": "outbound_or_release",
        "candidate_kind": "economic_chain",
        "mechanism": "queue_solver_accounting",
        "economic_chain": {
            "motif": "queue_solver_accounting",
            "roles": {
                "request": sorted(_economic_roles(request)),
                "mutation": sorted(_economic_roles(mutation)) if mutation else [],
                "settlement": sorted(_economic_roles(settlement)),
            },
            "core_targets": _dedupe_text([
                str(request.get("target_address") or ""),
                str((mutation or {}).get("target_address") or ""),
                str(settlement.get("target_address") or ""),
            ]),
        },
        "actions": actions,
        "objective": (
            "A queued withdrawal/request lifecycle must not let an attacker obtain "
            "more assets, shares, fees, or excess value than the live request state authorizes."
        ),
        "observations": [
            {
                "label": "queued request state",
                "target": contract or target or "queue",
                "timing": "after request and before settlement",
                "notes": (
                    "Record request owner, nonce/id, deadline/maturity, share amount, "
                    "asset amount, discount, fee, cancelability, and solver constraints."
                ),
            },
            {
                "label": "settlement economics",
                "target": contract or target or "queue",
                "timing": "after settlement",
                "notes": (
                    "Compare attacker assets/shares, solver balances, queue excess, "
                    "and vault/accounting totals against the request snapshot."
                ),
            },
        ],
        "recommended_next_tool": "inventory_live_targets then prepare_fork_exploit_workbench",
        "required_live_evidence": [
            "inventory_live_targets for queue, vault/accountant, asset/share token, solver, and permit domain dependencies",
            "active proxy or deployed configured/economic target bindings for queue and accounting targets",
            "fork block and exact request id/nonce/maturity/discount bindings",
            "before/after attacker, solver, queue, vault, asset, and share balances",
            "proof that any solver/keeper leg is production-reachable or explicitly simulated as a privileged non-attacker actor",
            "economic proof of excess extraction, stale claim settlement, fee bypass, or protocol loss",
        ],
        "blockers": blockers,
        "planning_notes": [
            "Treat this as a multi-actor economic lifecycle, not a single public withdraw call.",
            "Bind the request to a live user-owned claim before testing cancellation, replacement, or settlement paths.",
            "Do not submit if the only successful step requires attacker-only impersonation of a solver role.",
        ],
        "source": {
            "action_space": action_space_path,
            "live_reachability": live_path,
            "protocol_graph": protocol_graph_path or None,
        },
    }


def _queue_solver_chain_candidates(
    *,
    exposures: list[dict],
    action_space_path: str,
    live_path: str,
    protocol_graph_path: str,
    focus: str,
) -> list[dict]:
    groups: dict[tuple[str, str], list[dict]] = {}
    for exposure in exposures:
        if not isinstance(exposure, dict):
            continue
        if not str(exposure.get("target_address") or "").strip():
            continue
        groups.setdefault(_economic_group_key(exposure), []).append(exposure)

    candidates = []
    seen_targets = set()
    for group in groups.values():
        request = _economic_best_exposure(
            [
                exposure for exposure in group
                if _is_queue_request_exposure(exposure)
            ],
            "queue_request",
        )
        if not request:
            continue
        settlement = _queue_best_settlement_exposure([
            exposure for exposure in group
            if _economic_exposure_identity(exposure) != _economic_exposure_identity(request)
        ])
        if not settlement:
            continue
        mutation = _economic_best_distinct_exposure(
            [
                exposure for exposure in group
                if _is_queue_mutation_exposure(exposure)
                and _economic_exposure_callable(exposure)
            ],
            "queue_mutation",
            {
                _economic_exposure_identity(request),
                _economic_exposure_identity(settlement),
            },
        )
        key = str(request.get("target_address") or settlement.get("target_address") or "").lower()
        if key in seen_targets:
            continue
        seen_targets.add(key)
        candidates.append(_queue_solver_chain_candidate(
            request=request,
            settlement=settlement,
            mutation=mutation,
            action_space_path=action_space_path,
            live_path=live_path,
            protocol_graph_path=protocol_graph_path,
            focus=focus,
        ))
    return sorted(
        candidates,
        key=lambda item: (-int(item.get("priority_score", 0)), item["title"]),
    )[:4]


def _economic_chain_candidates(
    *,
    exposures: list[dict],
    action_space_path: str,
    live_path: str,
    protocol_graph_path: str,
    focus: str,
) -> list[dict]:
    groups: dict[tuple[str, str], list[dict]] = {}
    for exposure in exposures:
        if not isinstance(exposure, dict):
            continue
        if not str(exposure.get("target_address") or "").strip():
            continue
        groups.setdefault(_economic_group_key(exposure), []).append(exposure)

    candidates = []
    seen_motifs = set()
    for group in groups.values():
        callable_group = [
            exposure for exposure in group
            if _economic_exposure_callable(exposure)
        ]
        if not callable_group:
            continue
        setup = _economic_best_exposure(callable_group, "setup_capital")
        extraction = _economic_best_exposure(callable_group, "extraction")
        if (
            setup
            and extraction
            and _economic_exposure_identity(setup) == _economic_exposure_identity(extraction)
        ):
            continue
        perturbation = _economic_best_distinct_exposure(
            callable_group,
            "perturbation",
            {
                _economic_exposure_identity(setup),
                _economic_exposure_identity(extraction),
            },
        )
        if not setup or not extraction:
            continue
        labels = {
            str(item)
            for exposure in (setup, extraction)
            for item in exposure.get("affordances") or []
        }
        group_text = " ".join(_exposure_search_text(exposure) for exposure in group)
        if any(term in group_text for term in (
            "cerc20",
            "cether",
            "comptroller",
            "ctoken",
            "delegator",
            "unitroller",
        )):
            continue
        text = _exposure_search_text(setup) + " " + _exposure_search_text(extraction)
        if "credit_or_liquidation" in labels:
            continue
        if any(
            _is_queue_request_exposure(exposure)
            or _is_queue_settlement_exposure(exposure)
            for exposure in group
        ):
            continue
        bridgeish = (
            "cross_domain_or_message" in labels
            or any(term in text for term in ("bridge", "message", "relay", "gateway", "mailbox"))
        )
        stakingish = any(term in text for term in (
            "stake",
            "staking",
            "unstake",
            "delegate",
            "delegation",
            "undelegate",
            "unbond",
            "validator",
        ))
        vaultish = (
            any(term in text for term in ("vault", "erc4626", "totalassets", "share"))
            or (
                "asset" in text
                and any(term in text for term in ("deposit", "mint", "redeem", "withdraw"))
            )
        )
        if bridgeish:
            motif = "bridge_message_accounting"
        elif stakingish and not vaultish:
            motif = "staking_delegation_accounting"
        elif vaultish:
            motif = "vault_share_inflation"
        elif labels.intersection({"valuation_dependency", "market_or_router"}):
            motif = "oracle_market_valuation"
        else:
            continue
        key = (motif, str(extraction.get("target_address") or "").lower())
        if key in seen_motifs:
            continue
        seen_motifs.add(key)
        candidates.append(_economic_chain_candidate(
            motif=motif,
            setup=setup,
            extraction=extraction,
            perturbation=perturbation,
            action_space_path=action_space_path,
            live_path=live_path,
            protocol_graph_path=protocol_graph_path,
            focus=focus,
        ))
    return sorted(
        candidates,
        key=lambda item: (-int(item.get("priority_score", 0)), item["title"]),
    )[:6]


def _lending_exchange_rate_candidate(
    *,
    exposures: list[dict],
    action_space_path: str,
    live_path: str,
    protocol_graph_path: str,
) -> dict | None:
    mint = _find_lending_exposure(exposures, {"mint"})
    borrow = _find_lending_exposure(exposures, {"borrow"})
    redeem = _find_lending_exposure(exposures, {"redeem", "redeemunderlying"})
    exchange_rate = _find_lending_exposure(
        exposures,
        {"exchangeratecurrent", "exchangeratestored", "getcash"},
    )
    if not (mint and borrow and redeem and exchange_rate):
        return None
    borrow = _find_lending_exposure(
        exposures,
        {"borrow"},
        exclude_address=str(mint.get("target_address") or ""),
    ) or borrow
    markets = _unique_lending_market_targets(exposures)
    if len(markets) < 2 and "cether" not in _exposure_search_text(mint):
        return None
    controller = _find_lending_exposure(
        exposures,
        {"entermarkets", "getaccountliquidity", "markets"},
        prefer_controller=True,
    )
    collateral_address = str(mint.get("target_address") or "").strip()
    borrow_address = str(borrow.get("target_address") or "").strip()
    collateral_action = _candidate_action_from_exposure(mint)
    collateral_action.update({
        "contract": "CollateralMarket",
        "function": "mint",
        "target": collateral_address,
        "args": ["mintAmount"],
        "parameters": [{"name": "mintAmount", "raw": "uint256 mintAmount"}],
        "manual_only": True,
        "expected_effect": "Mint cTokens in the selected low-supply collateral market.",
        "notes": f"Source action: {mint.get('action_key')}; bind to collateral market address.",
    })
    borrow_action = _candidate_action_from_exposure(borrow)
    borrow_action.update({
        "contract": "BorrowMarket",
        "function": "borrow",
        "target": borrow_address,
        "args": ["borrowAmount"],
        "parameters": [{"name": "borrowAmount", "raw": "uint256 borrowAmount"}],
        "manual_only": True,
        "expected_effect": "Borrow valuable underlying from a distinct market after collateral inflation.",
        "notes": f"Source action: {borrow.get('action_key')}; bind to borrow market address.",
    })
    donation_action = {
        "actor": "attacker",
        "contract": "UnderlyingToken",
        "function": "transfer",
        "target": "<collateral underlying asset>",
        "args": [collateral_address or "collateralMarket", "donationAmount"],
        "parameters": [
            {"name": "to", "raw": "address to"},
            {"name": "amount", "raw": "uint256 amount"},
        ],
        "expected_effect": (
            "Directly increase collateral market cash without minting proportional "
            "cTokens, then verify whether exchangeRateStored/current over-credits "
            "the attacker."
        ),
        "bounds": (
            "Only viable if live totalSupply is low, donation capital is below "
            "borrowable liquidity, and getCash includes unsolicited transfers."
        ),
        "live_exposure": "external_token_transfer",
        "live_status": "manual",
        "action_key": "external::donateUnderlyingToMarket",
        "affordances": ["token_or_native_transfer", "valuation_dependency"],
        "direction_hint": "inbound_value_entry",
        "manual_only": True,
        "notes": "Synthetic external ERC20/native transfer; bind underlying before running.",
    }
    actions = [collateral_action, donation_action]
    if controller:
        enter = _candidate_action_from_exposure(controller)
        enter.update({
            "contract": "Controller",
            "function": "enterMarkets",
            "target": controller.get("target_address"),
            "args": ["collateralMarkets"],
            "parameters": [{"name": "cTokens", "raw": "address[] memory cTokens"}],
            "manual_only": True,
        })
        enter["expected_effect"] = "Enter the inflated collateral market before borrowing."
        actions.append(enter)
    actions.append(borrow_action)
    return {
        "attack_key": "pattern:lending:exchange-rate-collateral-inflation",
        "title": "Test lending exchange-rate collateral inflation chain",
        "priority_score": 34,
        "priority": "critical",
        "action_key": "Lending::exchangeRateCollateralInflation",
        "contract": str(mint.get("contract") or "LendingMarket"),
        "function": "mint-donate-enter-borrow",
        "target_address": collateral_address,
        "exposure": "exposed",
        "reachability": {"kind": "public", "attacker_reachable": True, "confidence": "pattern"},
        "target_binding": mint.get("target_binding"),
        "affordances": [
            "value_in_or_mint",
            "token_or_native_transfer",
            "valuation_dependency",
            "credit_or_liquidation",
            "market_or_router",
        ],
        "direction_hint": "outbound_or_release",
        "candidate_kind": "economic_pattern",
        "mechanism": "lending_exchange_rate_inflation",
        "target_address_role": "candidate_collateral_market",
        "market_inventory": {
            "candidate_markets": markets,
            "collateral_market": collateral_address,
            "borrow_market": borrow_address,
            "controller": (controller or {}).get("target_address"),
        },
        "actions": actions,
        "objective": (
            "Donation-inflated collateral exchange rate must not let an attacker "
            "borrow more value than economically backed collateral or leave bad debt."
        ),
        "observations": [
            {
                "label": "market inventory",
                "target": "all candidate cToken markets",
                "timing": "before setup",
                "notes": (
                    "Query underlying, totalSupply, getCash, totalBorrows, reserves, "
                    "exchangeRateStored, collateral factor, borrow/supply caps, oracle price, "
                    "and whitelist/pause state for each exact live address."
                ),
            },
            {
                "label": "attacker health and debt",
                "target": "controller",
                "timing": "before and after borrow",
                "notes": "Read getAccountLiquidity, entered markets, borrow balances, and collateral balances.",
            },
            {
                "label": "bad debt and net profit",
                "target": "borrow market and attacker",
                "timing": "after attempted borrow/redeem/unwind",
                "notes": "Compare borrowed asset value, donation cost, remaining collateral value, and protocol cash.",
            },
        ],
        "recommended_next_tool": "prepare_fork_exploit_workbench",
        "required_live_evidence": [
            "exact live cToken market inventory from map_live_reachability addresses",
            "active proxy or deployed configured/economic target bindings for selected markets",
            "fork block and collateral/borrow market bindings",
            "before/after exchange rate, liquidity, debt, and attacker balance deltas",
            "economic proof that donation cost is less than borrowable value or bad debt",
        ],
        "blockers": [
            "Reject if all collateral-enabled markets have enough supply/cash that donation cost exceeds borrow capacity.",
            "Reject if Comptroller, caps, whitelist, pause state, or oracle pricing prevents over-borrow.",
        ],
        "planning_notes": [
            "This is a chained economic-pattern candidate, not a single public function issue.",
            "Resolve market inventory first; do not spend time on ordinary repay/liquidation behavior unless this setup makes it abnormal.",
        ],
        "source": {
            "action_space": action_space_path,
            "live_reachability": live_path,
            "protocol_graph": protocol_graph_path or None,
        },
    }


def _attack_graph_nodes_edges_from_exposures(exposures: list[dict]) -> tuple[list[dict], list[dict]]:
    nodes = [{"id": "actor:attacker", "kind": "actor", "label": "attacker"}]
    edges = []
    seen_nodes = {"actor:attacker"}
    for exposure in exposures:
        contract = str(exposure.get("contract") or "unknown")
        address = str(exposure.get("target_address") or "")
        contract_id = f"contract:{contract}:{address or 'unbound'}"
        action_id = f"action:{exposure.get('action_key') or contract}"
        gate_id = f"gate:{(exposure.get('reachability') or {}).get('kind') or 'unknown'}"
        for node in (
            {"id": contract_id, "kind": "contract", "label": contract, "address": address},
            {"id": action_id, "kind": "entrypoint", "label": exposure.get("action_key"), "signature": exposure.get("signature")},
            {"id": gate_id, "kind": "gate", "label": (exposure.get("reachability") or {}).get("kind")},
        ):
            if node["id"] not in seen_nodes:
                nodes.append(node)
                seen_nodes.add(node["id"])
        edges.extend([
            {"from": contract_id, "to": action_id, "kind": "has_entrypoint"},
            {"from": action_id, "to": gate_id, "kind": "has_gate"},
        ])
        if exposure.get("exposure") in {"exposed", "source_public_live_unknown"}:
            edges.append({"from": "actor:attacker", "to": action_id, "kind": "can_call"})
        for label in exposure.get("affordances") or []:
            concept = _GRAPH_AFFORDANCE_CONCEPTS.get(label)
            if not concept:
                continue
            concept_id = concept[0]
            if concept_id not in seen_nodes:
                nodes.append({"id": concept_id, "kind": concept[1], "label": concept[2]})
                seen_nodes.add(concept_id)
            edges.append({"from": action_id, "to": concept_id, "kind": concept[3]})
    return nodes, edges


# ── Source-only attack-graph candidates + novelty frontier ────────────────────
#
# build_attack_graph can run before live reachability is mapped (mode=source_only
# / auto fallback). Source-only candidates are skeletons derived from the
# action-space alone: they carry an explicit `source_only` exposure, a
# `needs_live_context` reachability marker, and live-context blockers so the
# downstream submission gates still require a runnable fork PoC before any
# high/critical claim. The frontier preserves low-score, unlabeled, and
# truncated branches in the artifact (never the response) so renamed or novel
# code is not silently erased by score thresholds or the response cap.

_ATTACK_GRAPH_STATE_MUTATOR_AFFORDANCES = {
    "state_mutating_entrypoint",
    "state_changing_entrypoint",
    "mapping_state_write",
    "aggregate_state_update",
    "user_claim_or_obligation_update",
    "lifecycle_state_change",
}
_ATTACK_GRAPH_BOUNDARY_AFFORDANCES = {
    "external_boundary_crossing",
    "unchecked_external_boundary",
    "dynamic_call_target",
    "external_call_with_value",
    "external_call",
    "delegatecall",
    "generic_execution",
    "cross_domain_or_message",
    "callback_or_flashloan_surface",
}
_ATTACK_GRAPH_VALUE_AFFORDANCES = {
    "value_in_or_mint",
    "value_out_or_burn",
    "token_or_native_transfer",
    "accepts_native_value",
    "credit_or_liquidation",
    "valuation_dependency",
    "market_or_router",
}
_ATTACK_GRAPH_OTHER_MEANINGFUL_AFFORDANCES = {
    "signed_authorization",
    "signature_gate",
    "signature_input",
    "arithmetic_rounding_or_division",
    "batch_or_loop_surface",
    "authorization_condition",
}
_ATTACK_GRAPH_MEANINGFUL_AFFORDANCES = (
    _ATTACK_GRAPH_STATE_MUTATOR_AFFORDANCES
    | _ATTACK_GRAPH_BOUNDARY_AFFORDANCES
    | _ATTACK_GRAPH_VALUE_AFFORDANCES
    | _ATTACK_GRAPH_OTHER_MEANINGFUL_AFFORDANCES
)

# Reason buckets store full frontier entries; semantic buckets store compact
# references back into them so a multi-category entry is not serialized N times.
# `low_signal_entrypoints` holds bare source-only entrypoints (no structural
# risk): preserved for the audit trail but deliberately terminal — never reffed
# into the semantic/novelty buckets and never promoted to curiosity scheduling
# (see `_attack_search_frontier_candidates`, which reads only omitted_by_*).
_ATTACK_GRAPH_FRONTIER_FULL_CATEGORIES = (
    "omitted_by_score",
    "omitted_by_truncation",
    "low_signal_entrypoints",
)
_ATTACK_GRAPH_FRONTIER_REFERENCE_CATEGORIES = (
    "low_score_state_mutators",
    "unlabeled_state_mutators",
    "unusual_external_boundaries",
    "source_only_needs_live_context",
    "generic_invariant_candidates",
    "pattern_candidates",
    "diversity_sample",
)
_ATTACK_GRAPH_FRONTIER_CATEGORIES = (
    _ATTACK_GRAPH_FRONTIER_FULL_CATEGORIES
    + _ATTACK_GRAPH_FRONTIER_REFERENCE_CATEGORIES
)


def _source_only_attack_graph_objective(action: dict) -> str:
    """Generic invariant/objective derived from structural labels.

    Falls back to the lexical/affordance objective (and its generic default)
    when no structural label applies, so a renamed action still gets a usable
    invariant statement."""
    key = action.get("action_key") or _coverage_action_key(action)
    affordances = {str(item) for item in action.get("affordances") or []}
    if "dynamic_call_target" in affordances:
        return (
            f"{key} must not let an attacker-chosen dynamic call target route "
            "arbitrary execution across its boundary."
        )
    if affordances.intersection({
        "external_boundary_crossing",
        "unchecked_external_boundary",
        "external_call_with_value",
    }):
        return (
            f"{key} must not allow an unauthorized external state or value "
            "change when it crosses its call boundary."
        )
    if "authorization_condition" in affordances:
        return f"{key} must bind every privileged effect to the correct subject and right."
    if "arithmetic_rounding_or_division" in affordances:
        return f"{key} must preserve rounding and conservation invariants in its arithmetic."
    if affordances.intersection({
        "mapping_state_write",
        "aggregate_state_update",
        "user_claim_or_obligation_update",
    }):
        return (
            f"{key} must keep per-claim and aggregate accounting consistent with "
            "the value actually transferred or authorized."
        )
    if "batch_or_loop_surface" in affordances:
        return f"{key} must preserve per-item conservation and bounds across the batch/loop."
    return _attack_graph_objective(action)


def _source_only_candidate_action(action: dict) -> dict:
    source = {
        key: action.get(key)
        for key in ("file", "line")
        if action.get(key) not in (None, "", [], {})
    }
    signature = _action_signature(action)
    if signature:
        source["signature"] = signature
    candidate_action = {
        "actor": "attacker",
        "contract": action.get("contract"),
        "function": action.get("function"),
        "args": _action_arg_names(action),
        "expected_effect": _source_only_attack_graph_objective(action),
        "bounds": (
            "derive from source guards, caps, fees, and authorization once a "
            "live target is bound"
        ),
        "live_exposure": "source_only",
        "live_status": "unprobed",
        "action_key": _coverage_action_key(action),
        "affordances": action.get("affordances") or [],
        "direction_hint": _attack_graph_direction_hint(action),
        "source": source,
        "live_blockers": [
            "live reachability not mapped",
            "target address not bound",
        ],
    }
    return {
        key: value
        for key, value in candidate_action.items()
        if value not in (None, "", [], {})
    }


# ── source-only candidate scoring ─────────────────────────────────────────────
#
# Unlike `_action_response_priority` (used to rank the raw action space, where a
# first-party public/external non-view function is genuinely worth surfacing), a
# source-only attack-graph candidate must earn its priority from real attack
# structure. Visibility, mutability, first-party source, and the
# `state_changing_entrypoint` / `state_mutating_entrypoint` roll-ups are
# necessary *context*, not risk, so they score zero here. Only structural/lexical
# affordances that imply a call boundary, value movement, authorization, signed/
# cross-domain authority, or per-claim/aggregate accounting lift a candidate —
# so a no-op like `function ping() external {}` can never become a critical
# generic-invariant candidate, while a renamed function that actually writes
# mappings or crosses a boundary still surfaces.
_SOURCE_ONLY_CANDIDATE_WEIGHTS = {
    # Arbitrary-execution / call boundary. `external_call` is the lexical echo of
    # the structural `external_boundary_crossing` (every `.call`/`.staticcall`
    # sets both), so it scores zero to avoid double-counting; `generic_execution`
    # is handled conditionally below.
    "dynamic_call_target": 5,
    "external_call_with_value": 5,
    "delegatecall": 5,
    "external_boundary_crossing": 3,
    "callback_or_flashloan_surface": 3,
    "unchecked_external_boundary": 2,
    # Authority / signed / cross-domain. `signature_input` / `signature_gate`
    # co-occur with `signed_authorization`, so only the canonical label scores.
    "signed_authorization": 4,
    "cross_domain_or_message": 4,
    "authorization_condition": 3,
    # State mutation / accounting.
    "mapping_state_write": 3,
    "aggregate_state_update": 3,
    "user_claim_or_obligation_update": 3,
    "arithmetic_rounding_or_division": 3,
    "batch_or_loop_surface": 2,
    "lifecycle_state_change": 2,
    # Value movement (direction-weighted: funds leaving ranks highest).
    "value_out_or_burn": 5,
    "credit_or_liquidation": 4,
    "valuation_dependency": 3,
    "market_or_router": 3,
    "value_in_or_mint": 3,
    "token_or_native_transfer": 3,
    "accepts_native_value": 2,
}
# `generic_execution` is a lexical name hint ("execute"/"call"/"multicall"); it
# only earns weight when a real call boundary backs it.
_SOURCE_ONLY_BOUNDARY_BACKING = {
    "dynamic_call_target",
    "external_call_with_value",
    "external_boundary_crossing",
    "external_call",
    "delegatecall",
}
# A real state mutation for the criticality gate — the bare `state_changing_
# entrypoint` (non-view) roll-up is intentionally excluded; only an identifiable
# write counts.
_SOURCE_ONLY_REAL_MUTATION_AFFORDANCES = {
    "mapping_state_write",
    "aggregate_state_update",
    "user_claim_or_obligation_update",
    "lifecycle_state_change",
    "state_mutating_entrypoint",
}
# Signals strong enough, on their own, to let a source-only candidate reach
# `critical` (still gated downstream by live exposure + a runnable PoC).
_SOURCE_ONLY_CRITICAL_AFFORDANCES = {
    "dynamic_call_target",
    "external_call_with_value",
    "delegatecall",
    "cross_domain_or_message",
}


def _source_only_candidate_score(action: dict) -> tuple[int, list[str]]:
    """Score a source-only attack-graph candidate from its affordances.

    Returns ``(score, reasons)``. A bare entrypoint (no meaningful affordance)
    scores 0–1 and carries only a ``bare_entrypoint`` reason so the caller can
    divert it to the ``low_signal_entrypoints`` frontier instead of the top
    candidate list. See `_SOURCE_ONLY_CANDIDATE_WEIGHTS`.
    """
    affordances = {str(item) for item in action.get("affordances") or []}
    backed_by_boundary = bool(affordances & _SOURCE_ONLY_BOUNDARY_BACKING)
    score = 0
    reasons: list[str] = []
    for label in sorted(affordances):
        if label == "generic_execution":
            if not backed_by_boundary:
                continue
            weight = 4
        else:
            weight = _SOURCE_ONLY_CANDIDATE_WEIGHTS.get(label, 0)
        if not weight:
            continue
        score += weight
        reasons.append(f"{label}+{weight}")
    # Per-claim *and* aggregate accounting touched together is a stronger
    # conservation surface than either write alone.
    if {"mapping_state_write", "aggregate_state_update"} <= affordances:
        score += 2
        reasons.append("mapping_and_aggregate+2")
    if not reasons:
        # Visibility + mutability + first-party source are context, not risk: keep
        # a bare entrypoint at the frontier floor, never a top critical candidate.
        is_entrypoint = bool(
            affordances & {"state_changing_entrypoint", "state_mutating_entrypoint"}
        ) or str(action.get("visibility") or "") in {"public", "external"}
        score = 1 if is_entrypoint else 0
        reasons.append("bare_entrypoint")
    return score, reasons


def _source_only_allows_critical(affordances: set[str]) -> bool:
    """True when a source-only candidate carries a signal strong enough to be
    `critical`. Bare visibility or a structurally-opaque mutation never qualifies;
    one of: an arbitrary-execution / value-carrying / cross-domain boundary,
    signed authority plus mutation, per-claim+aggregate accounting plus value
    movement, or an external call boundary plus state mutation."""
    if affordances & _SOURCE_ONLY_CRITICAL_AFFORDANCES:
        return True
    has_mutation = bool(affordances & _SOURCE_ONLY_REAL_MUTATION_AFFORDANCES)
    if "signed_authorization" in affordances and has_mutation:
        return True
    if (
        {"mapping_state_write", "aggregate_state_update"} <= affordances
        and affordances & _ATTACK_GRAPH_VALUE_AFFORDANCES
    ):
        return True
    if (
        affordances & {
            "external_boundary_crossing",
            "unchecked_external_boundary",
            "external_call",
        }
        and has_mutation
    ):
        return True
    return False


def _source_only_candidate_priority(score: int, affordances: set[str]) -> str:
    """Conservative band for a source-only candidate: reuse the shared
    `_plan_priority` thresholds but never label `critical` unless
    `_source_only_allows_critical` holds, so a high-scoring but structurally weak
    entrypoint caps at `high`."""
    priority = _plan_priority(score)
    if priority == "critical" and not _source_only_allows_critical(affordances):
        priority = "high"
    return priority


def _source_only_low_signal_frontier_entry(
    action: dict, score: int, reasons: list[str]
) -> dict:
    """Frontier entry for a bare source-only entrypoint scored below the candidate
    floor — preserved for the audit trail, kept out of the top candidate list and
    out of curiosity scheduling."""
    contract = str(action.get("contract") or "").strip()
    function = str(action.get("function") or "").strip()
    line = action.get("line")
    candidate_like = {
        "attack_key": f"source:{contract}:{function}:{int(line) if line else 0}",
        "title": (
            f"Low-signal source entrypoint: {contract}.{function}"
            if contract
            else f"Low-signal source entrypoint: {function}"
        ),
        "action_key": _coverage_action_key(action),
        "contract": contract or None,
        "function": function,
        "priority_score": score,
        "priority": _source_only_candidate_priority(
            score, {str(item) for item in action.get("affordances") or []}
        ),
        "exposure": "source_only",
        "reachability": "needs_live_context",
        "affordances": action.get("affordances") or [],
        "direction_hint": _attack_graph_direction_hint(action),
    }
    entry = _attack_graph_candidate_frontier_entry(
        candidate_like, reason="low_signal_entrypoints"
    )
    if reasons:
        entry["score_reasons"] = reasons
    return entry


def _source_only_attack_graph_candidates(
    action_space: dict,
    protocol_graph: dict | None,
    focus: str,
    action_space_path: str,
    protocol_graph_path: str,
) -> tuple[list[dict], dict[str, dict]]:
    """Source-derived candidate skeletons for public/external state-changing
    actions, plus a low-signal frontier for bare entrypoints.

    Returns ``(candidates, low_signal_frontier)``. Candidates carry a source-only
    `priority_score` / `priority` (see `_source_only_candidate_score` and
    `_source_only_candidate_priority`) and `score_reasons`; bare entrypoints with
    no structural risk are diverted into `low_signal_frontier` (keyed for clone
    de-duplication) so they are preserved in the artifact but never flood the top
    candidate list or curiosity scheduling. Clones of the same logical signature
    collapse into one entry in either bucket."""
    candidates: list[dict] = []
    by_logical: dict[str, dict] = {}
    low_signal_frontier: dict[str, dict] = {}
    for action in (action_space or {}).get("actions") or []:
        if not isinstance(action, dict):
            continue
        if _coverage_action_type(action) == "observation":
            continue
        function = str(action.get("function") or "").strip()
        if not function:
            continue
        contract = str(action.get("contract") or "").strip()
        action_key = _coverage_action_key(action)
        signature = _action_signature(action)
        logical_key = f"{action_key}|{signature}"
        base_score, score_reasons = _source_only_candidate_score(action)
        if score_reasons == ["bare_entrypoint"]:
            # Bare external/non-view entrypoint with no structural risk: preserve
            # in the frontier's low_signal_entrypoints bucket, never a top
            # candidate, never promoted to scheduling. Collapse clones.
            existing_low = low_signal_frontier.get(logical_key)
            if existing_low is not None:
                existing_low["duplicate_count"] = (
                    int(existing_low.get("duplicate_count") or 1) + 1
                )
                continue
            low_signal_frontier[logical_key] = _source_only_low_signal_frontier_entry(
                action, base_score, score_reasons
            )
            continue
        focus_bonus = _plan_focus_bonus(focus, action_key, contract, function)
        score = base_score + focus_bonus
        if focus_bonus:
            score_reasons = [*score_reasons, f"focus_match+{focus_bonus}"]
        priority = _source_only_candidate_priority(
            score, {str(item) for item in action.get("affordances") or []}
        )
        existing = by_logical.get(logical_key)
        if existing is not None:
            existing["duplicate_count"] = int(existing.get("duplicate_count") or 1) + 1
            similar = existing.setdefault("similar_sources", [])
            source_file = str(action.get("file") or "").strip()
            if source_file and source_file != existing.get("file") and source_file not in similar:
                similar.append(source_file)
            if score > int(existing.get("priority_score") or 0):
                existing["priority_score"] = score
                existing["priority"] = priority
                existing["score_reasons"] = score_reasons
            continue
        affordances = [str(item) for item in action.get("affordances") or []]
        mechanism = _infer_fork_workbench_mechanism(
            {
                "title": f"{contract}.{function}" if contract else function,
                "action_key": action_key,
                "contract": contract,
                "function": function,
                "signature": signature,
                "affordances": affordances,
            },
            None,
            "auto",
        )
        line = action.get("line")
        candidate = {
            "attack_key": f"source:{contract}:{function}:{int(line) if line else 0}",
            "title": (
                f"Source-only invariant probe: {contract}.{function}"
                if contract
                else f"Source-only invariant probe: {function}"
            ),
            "priority_score": score,
            "priority": priority,
            "score_reasons": score_reasons,
            "action_key": action_key,
            "contract": contract or None,
            "function": function,
            "signature": signature,
            "file": action.get("file"),
            "line": line,
            "exposure": "source_only",
            "reachability": "needs_live_context",
            "candidate_kind": "source_only",
            "mechanism": mechanism,
            "affordances": affordances,
            "direction_hint": _attack_graph_direction_hint(action),
            "actions": [_source_only_candidate_action(action)],
            "objective": _source_only_attack_graph_objective(action),
            "recommended_next_tool": (
                "map_live_reachability then build_attack_graph mode=reachability_aware, "
                "or prepare_fork_exploit_workbench after target binding"
            ),
            "required_live_evidence": [
                "live reachability artifact binding this action to a deployed target",
                "active proxy or deployed configured/economic target binding",
                "fork block and deployed target address",
                "before/after balances or protocol accounting objective delta",
            ],
            "blockers": [
                "live reachability not mapped",
                "target address not bound",
            ],
            "planning_notes": [
                "Source-only candidate: no live exposure confirmed yet.",
                "Map live reachability or bind a deployed target before claiming impact.",
            ],
            "source": {
                "action_space": action_space_path,
                "live_reachability": None,
                "protocol_graph": protocol_graph_path or None,
            },
        }
        candidate = {
            key: value
            for key, value in candidate.items()
            if value not in (None, "", [], {})
        }
        by_logical[logical_key] = candidate
        candidates.append(candidate)
    return candidates, low_signal_frontier


# ── state-transition-model → attack-graph candidates ─────────────────────
#
# Turn the generic, delexicalized invariants from extract_state_transition_model
# into first-class attack-graph branches. Each candidate is keyed by invariant
# (not by a deployed target): it is a planning skeleton that always needs live
# binding before any high/critical claim, and protocol "lenses" only annotate it
# — they never drive scoring or replace the generic invariants.

# Base score per generic invariant family. Families whose violation maps most
# directly to fund loss / authorization bypass rank highest; structural/loggable
# families (state_machine, liveness) sit mid; pure rounding/bounds sit lower.
_STM_CANDIDATE_KIND_SCORE = {
    "external_call_safety": 8,
    "authorization_binding": 8,
    "conservation": 7,
    "replay_protection": 7,
    "state_machine": 5,
    "liveness": 5,
    "rounding": 4,
    "bounds": 4,
}


def _stm_split_action_ref(value: object) -> tuple[str, str]:
    """Parse a target-action reference into (contract, function).

    Accepts a ``{"contract", "function"}`` dict or a ``"Contract.function"`` /
    ``"Contract::function"`` / bare ``"function"`` string. Returns ("", "") when
    nothing parses.
    """
    if isinstance(value, dict):
        return (
            str(value.get("contract") or "").strip(),
            str(value.get("function") or "").strip(),
        )
    text = re.split(r"\(", str(value or "").strip(), 1)[0].strip()
    if not text:
        return "", ""
    for separator in ("::", "."):
        if separator in text:
            contract, _, function = text.partition(separator)
            return contract.strip(), function.strip()
    return "", text


def _stm_action_space_index(action_space: dict | None) -> dict[tuple[str, str], dict]:
    """Index action-space actions by (contract_lower, function_lower) plus a
    contract-agnostic ("", function_lower) fallback so an invariant that names a
    function without its contract still resolves to a concrete entrypoint."""
    index: dict[tuple[str, str], dict] = {}
    for action in (action_space or {}).get("actions") or []:
        if not isinstance(action, dict):
            continue
        function = str(action.get("function") or "").strip()
        if not function:
            continue
        contract = str(action.get("contract") or "").strip()
        index.setdefault((contract.lower(), function.lower()), action)
        index.setdefault(("", function.lower()), action)
    return index


def _stm_prompt_matches_invariant(prompt: dict, invariant: dict) -> bool:
    """True when an experiment prompt targets this invariant. Primary match is the
    invariant statement embedded in the prompt objective (how
    _stm_experiment_prompts builds them); the kind+contract title match is a
    fallback."""
    statement = str(invariant.get("statement") or "").strip()
    if statement and statement in str(prompt.get("objective") or ""):
        return True
    kind = str(invariant.get("kind") or "").strip()
    contract = str(invariant.get("contract") or "").strip()
    function = str(invariant.get("function") or "").strip()
    title = str(prompt.get("title") or "")
    if kind and contract and kind in title and contract in title:
        return not function or function in title
    return False


def _stm_invariant_target_refs(
    invariant: dict,
    model: dict,
) -> list[tuple[str, str]]:
    """Ordered, de-duplicated (contract, function) targets for one invariant:
    explicit target_actions, the invariant's own function, referencing
    experiment-prompt targets, then model entrypoints for a contract-level
    invariant (no function of its own)."""
    refs: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()

    def add(contract: str, function: str) -> None:
        if not function:
            return
        key = (contract.lower(), function.lower())
        if key in seen:
            return
        seen.add(key)
        refs.append((contract, function))

    for item in invariant.get("target_actions") or []:
        add(*_stm_split_action_ref(item))
    contract = str(invariant.get("contract") or "").strip()
    function = str(invariant.get("function") or "").strip()
    if function:
        add(contract, function)
    for prompt in model.get("experiment_prompts") or []:
        if not isinstance(prompt, dict) or not _stm_prompt_matches_invariant(
            prompt, invariant
        ):
            continue
        for target in prompt.get("target_actions") or []:
            add(*_stm_split_action_ref(target))
    if not function:
        for entry in model.get("entrypoints") or []:
            if not isinstance(entry, dict):
                continue
            entry_contract = str(entry.get("contract") or "").strip()
            if contract and entry_contract.lower() != contract.lower():
                continue
            add(entry_contract, str(entry.get("function") or "").strip())
    return refs


def _stm_candidate_action(action: dict, invariant: dict) -> dict:
    """A compact candidate-action skeleton bound to a matched action-space action,
    carrying the invariant objective as the expected effect."""
    source = {
        key: action.get(key)
        for key in ("file", "line")
        if action.get(key) not in (None, "", [], {})
    }
    signature = _action_signature(action)
    if signature:
        source["signature"] = signature
    candidate_action = {
        "actor": "attacker",
        "contract": action.get("contract"),
        "function": action.get("function"),
        "signature": signature,
        "args": _action_arg_names(action),
        "expected_effect": (
            f"Falsify invariant: {invariant.get('statement') or invariant.get('kind')}"
        ),
        "live_exposure": "source_only",
        "live_status": "unprobed",
        "action_key": _coverage_action_key(action),
        "affordances": [str(item) for item in action.get("affordances") or []],
        "matched_via": "state_transition_model",
        "source": source,
        "live_blockers": [
            "live reachability not mapped",
            "target address not bound",
        ],
    }
    return {
        key: value
        for key, value in candidate_action.items()
        if value not in (None, "", [], {})
    }


def _stm_candidate_observations(
    invariant: dict,
    matched_prompts: list[dict],
) -> list:
    """Observation skeletons for a generic invariant candidate: the invariant's
    own candidate_observations (preserved verbatim, string or dict) plus the probe
    strategy of any referencing experiment prompt. No success condition is
    fabricated."""
    observations: list = []
    seen: set[str] = set()

    def add(observation: object) -> None:
        marker = json.dumps(observation, sort_keys=True, default=str)
        if marker in seen:
            return
        seen.add(marker)
        observations.append(observation)

    for observation in invariant.get("candidate_observations") or []:
        add(observation)
    for prompt in matched_prompts:
        strategy = str(prompt.get("probe_strategy") or "").strip()
        if strategy:
            add({
                "probe_strategy": strategy,
                "from_experiment_prompt": prompt.get("title"),
            })
    return observations[:8]


def _stm_candidate_score(invariant: dict, matched_actions: list[dict]) -> int:
    """Score a generic invariant candidate from its invariant kind and the
    structural risk of any matched action-space entrypoint. Protocol lenses never
    contribute; an unmatched invariant is capped to medium and discounted."""
    kind = str(invariant.get("kind") or "")
    score = _STM_CANDIDATE_KIND_SCORE.get(kind, 4)
    if matched_actions:
        score += 2
        labels: set[str] = set()
        for action in matched_actions:
            labels.update(str(item) for item in action.get("affordances") or [])
        if labels & _ATTACK_GRAPH_BOUNDARY_AFFORDANCES:
            score += 1
        if labels & {
            "value_out_or_burn",
            "credit_or_liquidation",
            "valuation_dependency",
            "token_or_native_transfer",
        }:
            score += 1
    else:
        # No concrete entrypoint resolved: cap to medium and discount so an
        # unmatched invariant cannot outrank a bound, structurally-risky branch.
        score = min(score, 5) - 2
    return max(1, score)


def _state_transition_model_attack_candidates(
    model: dict,
    *,
    action_space: dict,
    protocol_graph: dict | None,
    source_path: str | None,
    mode: str,
) -> list[dict]:
    """Build generic invariant attack-graph candidates from a state-transition
    model's candidate_invariants. Each candidate is keyed by invariant, mapped to
    concrete action-space entrypoints where possible, and always needs live
    binding before any high/critical claim."""
    model_id = (
        str(model.get("state_transition_model_id") or model.get("id") or "stm").strip()
        or "stm"
    )
    index = _stm_action_space_index(action_space)
    lenses = model.get("lenses")
    lens_names = sorted(lenses.keys()) if isinstance(lenses, dict) and lenses else []
    candidates: list[dict] = []
    for position, invariant in enumerate(
        model.get("candidate_invariants") or [], start=1
    ):
        if not isinstance(invariant, dict):
            continue
        invariant_id = str(invariant.get("id") or f"inv-{position:03d}").strip()
        kind = str(invariant.get("kind") or "unknown")
        statement = str(invariant.get("statement") or "").strip()
        matched_actions: list[dict] = []
        matched_keys: set[str] = set()
        for contract, function in _stm_invariant_target_refs(invariant, model):
            action = index.get((contract.lower(), function.lower())) or index.get(
                ("", function.lower())
            )
            if action is None:
                continue
            key = _coverage_action_key(action)
            if key in matched_keys:
                continue
            matched_keys.add(key)
            matched_actions.append(action)
        matched_prompts = [
            prompt
            for prompt in model.get("experiment_prompts") or []
            if isinstance(prompt, dict)
            and _stm_prompt_matches_invariant(prompt, invariant)
        ]
        score = _stm_candidate_score(invariant, matched_actions)
        # Generic model invariants are source-only planning leads until target
        # binding exists. Cap their planning priority so "critical" is reserved
        # for branches with concrete live exposure or objective evidence.
        planning_score = min(score, 8)
        blockers = [
            "live reachability not mapped",
            "target address not bound",
        ]
        if not matched_actions:
            blockers.insert(
                0,
                "state-transition model invariant has no matched action-space "
                "entrypoint",
            )
        planning_notes = [
            "Generic state-transition invariant probe: planning skeleton, not a "
            "finding.",
            "Falsify the invariant with an objective experiment; live binding is "
            "required before any high/critical claim.",
        ]
        if lens_names:
            # Lenses annotate, they never score: surface their names so the agent
            # has the cross-reference without letting them dominate selection.
            planning_notes.append(
                "Model lenses present (metadata only, not scored): "
                + ", ".join(lens_names)
            )
        short_statement = (
            _truncate_response_text(statement, 110) if statement else kind
        )
        candidate = {
            "attack_key": f"stm:{model_id}:{invariant_id}",
            "title": f"Invariant probe: {short_statement}",
            "priority_score": planning_score,
            "priority": _plan_priority(planning_score),
            "candidate_kind": "generic_invariant",
            "mechanism": "generic_state_transition",
            "exposure": "model_invariant",
            "reachability": "needs_live_context",
            "objective": (
                f"Falsify invariant: {statement}" if statement
                else f"Falsify {kind} invariant"
            ),
            "contract": invariant.get("contract") or None,
            "function": invariant.get("function") or None,
            "invariant": {
                "id": invariant_id,
                "kind": kind,
                "statement": statement,
                "source": "generic",
            },
            "source": {
                "kind": "state_transition_model",
                "state_transition_model": source_path,
                "invariant_id": invariant_id,
            },
            "actions": [
                _stm_candidate_action(action, invariant) for action in matched_actions
            ],
            "observations": _stm_candidate_observations(invariant, matched_prompts),
            "blockers": blockers,
            "required_live_evidence": [
                "live reachability artifact binding the invariant's actions to a "
                "deployed target",
                "fork block and deployed target address",
                "before/after accounting or state objective that falsifies the "
                "invariant",
            ],
            "planning_notes": planning_notes,
            "falsification_ideas": [
                str(item)
                for item in invariant.get("falsification_ideas") or []
                if str(item).strip()
            ][:4],
            "recommended_next_tool": (
                "map_live_reachability then build_attack_graph "
                "mode=reachability_aware, or prepare_fork_exploit_workbench after "
                "target binding"
            ),
        }
        candidate = {
            key: value
            for key, value in candidate.items()
            if value not in (None, "", [], {})
        }
        candidates.append(candidate)
    return candidates


def _attack_graph_candidate_frontier_entry(candidate: dict, *, reason: str) -> dict:
    """Compact frontier entry for a candidate-shaped dict."""
    reachability = candidate.get("reachability")
    if isinstance(reachability, dict):
        reachability_kind = reachability.get("kind")
    else:
        reachability_kind = reachability
    objective = candidate.get("objective")
    candidate_invariant = (
        candidate.get("invariant") if isinstance(candidate.get("invariant"), dict) else {}
    )
    candidate_source = (
        candidate.get("source") if isinstance(candidate.get("source"), dict) else {}
    )
    entry = {
        "attack_key": candidate.get("attack_key"),
        "title": candidate.get("title"),
        "action_key": candidate.get("action_key"),
        "contract": candidate.get("contract"),
        "function": candidate.get("function"),
        "candidate_kind": candidate.get("candidate_kind"),
        "mechanism": candidate.get("mechanism"),
        "priority": candidate.get("priority"),
        "priority_score": candidate.get("priority_score"),
        "exposure": candidate.get("exposure"),
        "reachability": reachability_kind,
        "direction_hint": candidate.get("direction_hint"),
        "affordances": [str(item) for item in candidate.get("affordances") or []][:12],
        "objective": _truncate_response_text(objective, 400) if objective else None,
        "blockers": [str(item) for item in candidate.get("blockers") or []][:6],
        "recommended_next_tool": candidate.get("recommended_next_tool"),
        "target_address": candidate.get("target_address"),
        "duplicate_count": candidate.get("duplicate_count"),
        "candidate_id": candidate.get("candidate_id"),
        # Preserve the generic-invariant locator so a frontier-promoted branch
        # can still surface its invariant id and model path in the dossier.
        "invariant_id": candidate_invariant.get("id")
        or candidate_source.get("invariant_id"),
        "state_transition_model": candidate_source.get("state_transition_model"),
        "frontier_reason": reason,
    }
    return {key: value for key, value in entry.items() if value not in (None, "", [], {})}


def _attack_graph_low_score_frontier_entry(exposure: dict, score: int) -> dict:
    """Compact frontier entry for a reachability exposure scored below the
    candidate floor — preserved instead of discarded."""
    action_key = str(exposure.get("action_key") or "")
    candidate_like = {
        "attack_key": (
            f"{str(exposure.get('target_address') or '').lower()}:"
            f"{action_key}:{exposure.get('exposure')}"
        ),
        "title": (
            f"Low-signal reachable {action_key}" if action_key
            else "Low-signal reachable action"
        ),
        "action_key": action_key,
        "contract": exposure.get("contract"),
        "function": exposure.get("function"),
        "priority_score": score,
        "priority": _plan_priority(score),
        "exposure": exposure.get("exposure"),
        "reachability": exposure.get("reachability"),
        "direction_hint": _attack_graph_direction_hint(exposure),
        "affordances": exposure.get("affordances") or [],
        "objective": _attack_graph_objective(exposure),
        "target_address": exposure.get("target_address"),
    }
    return _attack_graph_candidate_frontier_entry(candidate_like, reason="omitted_by_score")


def _attack_graph_frontier_reference(entry: dict) -> dict:
    reference = {
        "attack_key": entry.get("attack_key"),
        "action_key": entry.get("action_key"),
        "title": entry.get("title"),
        "priority_score": entry.get("priority_score"),
        "frontier_reason": entry.get("frontier_reason"),
    }
    return {key: value for key, value in reference.items() if value not in (None, "", [], {})}


def _attack_graph_frontier_semantic_categories(entry: dict) -> list[str]:
    affordances = {str(item) for item in entry.get("affordances") or []}
    candidate_kind = entry.get("candidate_kind")
    categories = []
    if (
        candidate_kind == "generic_invariant"
        or entry.get("mechanism") == "generic_state_transition"
    ):
        # Generic state-transition-model invariant probes get their own bucket so
        # they stay first-class and discoverable instead of being folded into the
        # broad pattern-candidate pool.
        categories.append("generic_invariant_candidates")
    elif candidate_kind and candidate_kind != "source_only":
        categories.append("pattern_candidates")
    if affordances.intersection(_ATTACK_GRAPH_BOUNDARY_AFFORDANCES):
        categories.append("unusual_external_boundaries")
    has_meaningful = bool(affordances.intersection(_ATTACK_GRAPH_MEANINGFUL_AFFORDANCES))
    is_mutator = bool(affordances.intersection(_ATTACK_GRAPH_STATE_MUTATOR_AFFORDANCES))
    if not has_meaningful:
        # Renamed/bland state-changing actions with no recognized risk labels are
        # the novelty-critical branches we most want to keep visible.
        categories.append("unlabeled_state_mutators")
    elif is_mutator:
        categories.append("low_score_state_mutators")
    return categories


def _attack_graph_diversity_sample(entries: list[dict], *, limit: int = 25) -> list[dict]:
    sample = []
    seen = set()
    for entry in entries:
        contract = str(entry.get("contract") or "")
        affordances = entry.get("affordances") or []
        primary = str(affordances[0]) if affordances else "unlabeled"
        key = (contract, primary)
        if key in seen:
            continue
        seen.add(key)
        sample.append(_attack_graph_frontier_reference(entry))
        if len(sample) >= limit:
            break
    return sample


def _assemble_attack_graph_frontier(
    *,
    mode: str,
    low_score_entries: list[dict],
    truncated_candidates: list[dict],
    frontier_max_items: int,
) -> tuple[dict, dict]:
    """Bucket preserved branches into the novelty frontier. Reason buckets hold
    full entries; semantic/sample buckets hold compact references."""
    categories: dict[str, list[dict]] = {
        name: [] for name in _ATTACK_GRAPH_FRONTIER_CATEGORIES
    }
    distinct: list[dict] = list(low_score_entries)
    for candidate in truncated_candidates:
        distinct.append(
            _attack_graph_candidate_frontier_entry(candidate, reason="omitted_by_truncation")
        )
    omitted_by_cap = max(0, len(distinct) - frontier_max_items)
    distinct = distinct[:frontier_max_items]

    for entry in distinct:
        reason = str(entry.get("frontier_reason") or "omitted_by_truncation")
        if reason in _ATTACK_GRAPH_FRONTIER_FULL_CATEGORIES:
            categories[reason].append(entry)
        if reason == "low_signal_entrypoints":
            # Bare entrypoints are terminal: preserved for the audit trail but
            # kept out of the semantic/novelty buckets, the source-only
            # needs-live-context list, and the diversity sample so they never
            # drive curiosity exploration.
            continue
        if mode == "source_only":
            categories["source_only_needs_live_context"].append(
                _attack_graph_frontier_reference(entry)
            )
        for semantic in _attack_graph_frontier_semantic_categories(entry):
            categories[semantic].append(_attack_graph_frontier_reference(entry))
    categories["diversity_sample"] = _attack_graph_diversity_sample(
        [
            entry
            for entry in distinct
            if entry.get("frontier_reason") != "low_signal_entrypoints"
        ]
    )

    summary = {name: len(items) for name, items in categories.items()}
    summary["total_distinct"] = len(distinct)
    if omitted_by_cap:
        summary["omitted_from_frontier_by_cap"] = omitted_by_cap
    return categories, summary


async def _build_attack_graph(container: AuditContainer, args: dict) -> str:
    try:
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"
    state = await _load_campaign_state(container)
    focus = str(args.get("focus") or "").strip()
    max_candidates = min(max(int(args.get("max_candidates", 12)), 1), 50)
    mode = str(args.get("mode") or "auto").strip().lower()
    if mode not in {"auto", "reachability_aware", "source_only"}:
        mode = "auto"
    preserve_frontier = bool(args.get("preserve_frontier", True))
    frontier_max_items = min(max(int(args.get("frontier_max_items", 50)), 1), 250)
    try:
        action_space_path, action_space = await _load_latest_artifact(
            container,
            state,
            explicit=str(args.get("action_space") or "").strip(),
            directory="/workspace/campaign/action-spaces",
            id_prefix="as",
        )
        live_path, live_reachability = await _load_latest_artifact(
            container,
            state,
            explicit=str(args.get("live_reachability") or "").strip(),
            directory="/workspace/campaign/live-reachability",
            id_prefix="lr",
        )
        protocol_graph_path, protocol_graph = await _load_latest_artifact(
            container,
            state,
            explicit=str(args.get("protocol_graph") or "").strip(),
            directory="/workspace/campaign/protocol-graphs",
            id_prefix="pg",
        )
    except FileNotFoundError as exc:
        return f"Error: artifact not found: {exc}"
    stm_path, stm_model, stm_error = await _load_state_transition_model_ref(
        container,
        str(args.get("state_transition_model") or "").strip(),
    )
    if stm_error:
        return f"Error: {stm_error}"
    if not action_space:
        return "Error: build_attack_graph requires an action-space artifact"
    has_live = bool(live_reachability)
    has_live_context = _live_reachability_has_deployed_context(live_reachability)
    if mode == "reachability_aware" and not has_live:
        return (
            "Error: build_attack_graph mode=reachability_aware requires a "
            "live-reachability artifact; map_live_reachability first or use "
            "mode=source_only"
        )
    resolved_mode = (
        "reachability_aware"
        if (mode == "reachability_aware" or (mode == "auto" and has_live_context))
        else "source_only"
    )
    needs_live_context = resolved_mode == "source_only"

    low_score_frontier: dict[str, dict] = {}
    if resolved_mode == "source_only":
        candidates, low_score_frontier = _source_only_attack_graph_candidates(
            action_space,
            protocol_graph,
            focus,
            action_space_path,
            protocol_graph_path,
        )
        exposures = []
        nodes, edges = _attack_graph_nodes_edges_from_exposures([
            {
                "contract": candidate.get("contract"),
                "action_key": candidate.get("action_key"),
                "signature": candidate.get("signature"),
                "affordances": candidate.get("affordances") or [],
                "reachability": {"kind": "source_only"},
                "exposure": "source_only",
            }
            for candidate in candidates
        ])
        live_path = ""
    else:
        candidates, low_score_frontier, exposures, nodes, edges = (
            _reachability_attack_graph_candidates(
                live_reachability=live_reachability,
                focus=focus,
                action_space_path=action_space_path,
                live_path=live_path,
                protocol_graph_path=protocol_graph_path,
            )
        )

    # Generic invariant branches from a state-transition model are merged after
    # node/edge derivation (they are invariant-keyed, not graph nodes) and then
    # compete on score for top candidate_chains; the rest are preserved in the
    # frontier's generic_invariant_candidates bucket like any other branch.
    stm_candidates: list[dict] = []
    if stm_model:
        stm_candidates = _state_transition_model_attack_candidates(
            stm_model,
            action_space=action_space,
            protocol_graph=protocol_graph,
            source_path=stm_path,
            mode=resolved_mode,
        )
        candidates.extend(stm_candidates)

    candidates.sort(key=lambda item: (-int(item.get("priority_score", 0)), item["title"]))
    top_candidates = candidates[:max_candidates]
    omitted_candidates = candidates[max_candidates:]
    for index, candidate in enumerate(top_candidates, start=1):
        candidate["candidate_id"] = f"agcand-{index:03d}"

    low_score_entries = list(low_score_frontier.values())
    all_candidate_count = len(candidates) + len(low_score_entries)
    if preserve_frontier:
        frontier, frontier_summary = _assemble_attack_graph_frontier(
            mode=resolved_mode,
            low_score_entries=low_score_entries,
            truncated_candidates=omitted_candidates,
            frontier_max_items=frontier_max_items,
        )
    else:
        frontier = {}
        frontier_summary = {"preserved": False}

    graph_id = _next_campaign_id(state, "attack_graph")
    title = str(args.get("title") or "Reachability-aware attack graph").strip()
    if resolved_mode == "source_only" and not args.get("title"):
        title = "Source-only attack graph"
    payload = {
        "id": graph_id,
        "title": title,
        "mode": resolved_mode,
        "needs_live_context": needs_live_context,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "action_space_path": action_space_path,
        "live_reachability_path": live_path or None,
        "protocol_graph_path": protocol_graph_path or None,
        "focus": focus or None,
        "nodes": nodes,
        "edges": edges,
        "candidate_chains": top_candidates,
        "all_candidate_count": all_candidate_count,
        "frontier": frontier,
        "frontier_summary": frontier_summary,
        "summary": {
            "mode": resolved_mode,
            "nodes": len(nodes),
            "edges": len(edges),
            "exposures": len(exposures),
            "candidates": len(top_candidates),
            "all_candidates": all_candidate_count,
            "frontier_distinct": int(frontier_summary.get("total_distinct", 0) or 0),
            "exposed_candidates": sum(
                1 for item in top_candidates if item.get("exposure") == "exposed"
            ),
            "source_only_candidates": sum(
                1 for item in top_candidates if item.get("exposure") == "source_only"
            ),
            "generic_invariant_candidates": sum(
                1 for item in top_candidates
                if item.get("candidate_kind") == "generic_invariant"
            ),
            "blocked_or_gated_candidates": sum(
                1 for item in top_candidates if item.get("blockers")
            ),
        },
        "related_ids": [str(item) for item in related_ids],
        "notes": [
            "Candidate chains are planning skeletons, not findings.",
            "High/critical findings still require objective replay evidence and live exposure.",
            "Frontier entries are not findings; they preserve low-score/unlabeled "
            "branches for diversity.",
        ] + ([
            "Source-only mode: candidates need live reachability/binding before "
            "any high/critical claim.",
        ] if needs_live_context else []),
    }
    state_transition_model_summary = None
    if stm_model:
        state_transition_model_summary = {
            "path": stm_path,
            "model_id": (
                stm_model.get("state_transition_model_id") or stm_model.get("id")
            ),
            "candidate_count": len(stm_candidates),
        }
        payload["state_transition_model"] = state_transition_model_summary
    path = f"/workspace/campaign/attack-graphs/{graph_id}.json"
    await container.write_file(path, json.dumps(payload, indent=2, sort_keys=True) + "\n")
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Attack graph: {title}",
            content=(
                f"Attack graph: {graph_id}\n"
                f"Path: {path}\n"
                f"Mode: {resolved_mode}\n"
                f"Action space: {action_space_path}\n"
                f"Live reachability: {live_path or 'not mapped (source-only)'}\n"
                f"Top candidates: {payload['summary']['candidates']}"
                f" of {all_candidate_count}\n"
                f"Frontier branches preserved: {payload['summary']['frontier_distinct']}\n"
                + (
                    "State-transition model: "
                    f"{state_transition_model_summary['model_id']} "
                    f"({len(stm_candidates)} generic invariant candidate(s))\n"
                    if state_transition_model_summary else ""
                )
                + "Use candidate actions as experiment skeletons; do not submit "
                "from the graph alone."
            ),
            evidence=[
                path,
                action_space_path,
                *([live_path] if live_path else []),
                *([protocol_graph_path] if protocol_graph_path else []),
                *([stm_path] if stm_path else []),
            ],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "attack_graph_id": graph_id,
        "path": path,
        "result_id": result_id or None,
        "mode": resolved_mode,
        "needs_live_context": needs_live_context,
        "summary": payload["summary"],
        "frontier_summary": frontier_summary,
        "candidate_chains": top_candidates,
    }
    if state_transition_model_summary:
        response["state_transition_model"] = {
            "path": stm_path,
            "candidate_count": len(stm_candidates),
        }
    return json.dumps(response, indent=2, sort_keys=True)


def _reachability_attack_graph_candidates(
    *,
    live_reachability: dict,
    focus: str,
    action_space_path: str,
    live_path: str,
    protocol_graph_path: str,
) -> tuple[list[dict], dict[str, dict], list[dict], list[dict], list[dict]]:
    exposures = [
        exposure
        for profile in live_reachability.get("profiles") or []
        for exposure in (profile.get("action_exposures") or [])
        if isinstance(exposure, dict)
    ]
    nodes, edges = _attack_graph_nodes_edges_from_exposures(exposures)
    candidates = []
    low_signal_candidates_by_key: dict[str, dict] = {}
    low_score_frontier: dict[str, dict] = {}
    for exposure in exposures:
        score = _attack_graph_candidate_score(exposure, focus)
        dedupe_key = _attack_graph_candidate_dedupe_key(exposure)
        if score < 3:
            # Preserve below-floor branches in the frontier instead of dropping
            # them, deduping clones to keep the artifact compact.
            existing = low_score_frontier.get(dedupe_key)
            if existing is None:
                low_score_frontier[dedupe_key] = _attack_graph_low_score_frontier_entry(
                    exposure, score
                )
            else:
                existing["duplicate_count"] = int(existing.get("duplicate_count") or 1) + 1
                similar = existing.setdefault("similar_targets", [])
                target_address = str(exposure.get("target_address") or "").strip()
                if target_address and target_address not in similar:
                    similar.append(target_address)
            continue
        direction_hint = _attack_graph_direction_hint(exposure)
        action_key = str(exposure.get("action_key") or "")
        if not _exposure_is_live_callable(exposure) and dedupe_key in low_signal_candidates_by_key:
            existing = low_signal_candidates_by_key[dedupe_key]
            similar = existing.setdefault("similar_targets", [])
            target_address = str(exposure.get("target_address") or "").strip()
            if target_address and target_address not in similar:
                similar.append(target_address)
            existing["duplicate_count"] = int(existing.get("duplicate_count") or 1) + 1
            continue
        attack_key = (
            f"{str(exposure.get('target_address') or '').lower()}:"
            f"{action_key}:{exposure.get('exposure')}"
        )
        blockers = []
        if exposure.get("exposure") in {
            "gated",
            "dormant_or_wrong_address",
            "source_interface_only",
            "source_artifact_only",
        }:
            blockers.append(f"live exposure is {exposure.get('exposure')}")
        if exposure.get("live_status") != "deployed":
            blockers.append(f"live status is {exposure.get('live_status')}")
        target_binding = exposure.get("target_binding") or {}
        binding_kind = str(target_binding.get("kind") or "")
        if binding_kind in {"deployed_implementation_or_template", "no_code", "unknown_code"}:
            blockers.append(f"target binding is {binding_kind}")
        candidate = {
            "attack_key": attack_key,
            "title": f"Test live-reachable {action_key}",
            "priority_score": score,
            "priority": _plan_priority(score),
            "action_key": action_key,
            "action_uid": exposure.get("action_uid"),
            "contract": exposure.get("contract"),
            "function": exposure.get("function"),
            "profile_src": exposure.get("profile_src"),
            "code_hash": exposure.get("code_hash"),
            "target_address": exposure.get("target_address"),
            "exposure": exposure.get("exposure"),
            "reachability": exposure.get("reachability"),
            "target_binding": target_binding,
            "affordances": exposure.get("affordances") or [],
            "direction_hint": direction_hint,
            "clone_family_key": exposure.get("clone_family_key"),
            "clone_family_keys": [exposure.get("clone_family_key")]
            if exposure.get("clone_family_key") else [],
            "actions": [_candidate_action_from_exposure(exposure)],
            "objective": _attack_graph_objective(exposure),
            "recommended_next_tool": (
                "compose_sequence_experiment with explicit actions"
                if exposure.get("exposure") in {"exposed", "source_public_live_unknown"}
                else "attack_search action=decision or mutate_hypothesis after checking gate realism"
            ),
            "required_live_evidence": [
                "live reachability artifact",
                "active proxy or deployed configured/economic target binding",
                "fork block and deployed target address",
                "before/after balances or protocol accounting objective",
            ],
            "blockers": blockers,
            "planning_notes": _attack_graph_direction_notes(direction_hint),
            "source": {
                "action_space": action_space_path,
                "live_reachability": live_path,
                "protocol_graph": protocol_graph_path or None,
            },
        }
        candidates.append(candidate)
        if not _exposure_is_live_callable(exposure):
            low_signal_candidates_by_key[dedupe_key] = candidate
    candidates.extend(_economic_chain_candidates(
        exposures=exposures,
        action_space_path=action_space_path,
        live_path=live_path,
        protocol_graph_path=protocol_graph_path or "",
        focus=focus,
    ))
    candidates.extend(_queue_solver_chain_candidates(
        exposures=exposures,
        action_space_path=action_space_path,
        live_path=live_path,
        protocol_graph_path=protocol_graph_path or "",
        focus=focus,
    ))
    economic_candidate = _lending_exchange_rate_candidate(
        exposures=exposures,
        action_space_path=action_space_path,
        live_path=live_path,
        protocol_graph_path=protocol_graph_path or "",
    )
    if economic_candidate:
        candidates.append(economic_candidate)
    return candidates, low_score_frontier, exposures, nodes, edges


_GRAPH_AFFORDANCE_CONCEPTS = {
    "value_in_or_mint": ("flow:value_in", "value_flow", "value enters or claims are minted", "can_receive_or_mint_value"),
    "value_out_or_burn": ("flow:value_out", "value_flow", "value leaves or claims are burned", "can_release_or_burn_value"),
    "token_or_native_transfer": ("flow:value_movement", "value_flow", "token or native value movement", "moves_value"),
    "credit_or_liquidation": ("flow:credit_or_liquidation", "value_flow", "debt, collateral, or liquidation state", "changes_credit_or_liquidation_state"),
    "market_or_router": ("boundary:market_or_router", "trust_boundary", "market/router dependency", "depends_on_market_or_router"),
    "valuation_dependency": ("boundary:valuation", "trust_boundary", "oracle or price dependency", "depends_on_valuation"),
    "external_call": ("boundary:external_call", "trust_boundary", "external call boundary", "crosses_external_call_boundary"),
    "delegatecall": ("boundary:delegatecall", "trust_boundary", "delegatecall boundary", "crosses_delegatecall_boundary"),
    "generic_execution": ("boundary:generic_execution", "trust_boundary", "generic execution surface", "routes_execution"),
    "signed_authorization": ("boundary:signed_authorization", "trust_boundary", "signed authorization boundary", "depends_on_signature_binding"),
    "cross_domain_or_message": ("boundary:cross_domain", "trust_boundary", "cross-domain message boundary", "depends_on_cross_domain_state"),
    "callback_or_flashloan_surface": ("boundary:callback_or_flashloan", "trust_boundary", "callback or flash-loan boundary", "accepts_callback_or_flashloan_flow"),
    "modifier_gated": ("boundary:modifier_or_role", "trust_boundary", "modifier or role boundary", "is_modifier_or_role_gated"),
    "sender_or_role_checked": ("boundary:sender_or_role", "trust_boundary", "sender or role check", "checks_sender_or_role"),
    "accepts_native_value": ("flow:native_value_in", "value_flow", "native value entry", "accepts_native_value"),
}

_GRAPH_HINT_CONCEPTS = {
    "value_flows": ("flow:value_movement", "value_flow", "value movement hint", "has_value_flow_hint"),
    "external_calls": ("boundary:external_call", "trust_boundary", "external call hint", "has_external_call_hint"),
    "role_gates": ("boundary:sender_or_role", "trust_boundary", "sender or role hint", "has_role_gate_hint"),
    "state_mutations": ("state:mutation", "state_mutation", "state mutation hint", "has_state_mutation_hint"),
    "oracle_reads": ("boundary:oracle_input", "trust_boundary", "oracle input read", "reads_oracle_input"),
    "router_calls": ("boundary:router", "trust_boundary", "router or route call", "routes_through_router"),
    "bridge_messages": ("boundary:cross_domain", "trust_boundary", "bridge or message path", "handles_bridge_or_message"),
    "callback_surfaces": ("boundary:callback_or_flashloan", "trust_boundary", "callback or flash-loan surface", "has_callback_surface_hint"),
    "authorization_checks": ("boundary:signed_authorization", "trust_boundary", "authorization or signature check", "checks_authorization_binding"),
    "cross_contract_calls": ("boundary:cross_contract", "trust_boundary", "cross-contract dependency", "calls_cross_contract_dependency"),
    "economic_parameters": ("state:economic_parameter", "economic_parameter", "economic parameter hint", "has_economic_parameter_hint"),
}

_GRAPH_STATE_DECL_RE = re.compile(
    r"^\s*"
    r"(?!(?:function|event|modifier|struct|enum|error|using|return|if|for|while|"
    r"require|assert|emit|import|pragma)\b)"
    r"(?P<type>mapping\s*\([^;]+\)|[A-Za-z_][A-Za-z0-9_<>,.\[\]]*)"
    r"\s+"
    r"(?:(?:public|private|internal|external|constant|immutable|override)\s+)*"
    r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)"
    r"\s*(?:=|;)",
)


def _graph_location(file: str, line: int | None) -> dict:
    location = {"file": file}
    if line:
        location["line"] = line
    return location


def _graph_add_node(
    nodes: dict[str, dict],
    node_id: str,
    *,
    kind: str,
    label: str,
    tags: list[str] | None = None,
    location: dict | None = None,
    **attrs,
) -> None:
    node = nodes.setdefault(node_id, {
        "id": node_id,
        "kind": kind,
        "label": label,
        "tags": [],
        "locations": [],
    })
    if kind and not node.get("kind"):
        node["kind"] = kind
    if label and not node.get("label"):
        node["label"] = label
    for tag in tags or []:
        tag_s = str(tag)
        if tag_s and tag_s not in node["tags"]:
            node["tags"].append(tag_s)
    if location and location not in node["locations"]:
        node["locations"].append(location)
    for key, value in attrs.items():
        if value in (None, "", [], {}):
            continue
        node.setdefault(key, value)


def _graph_add_edge(
    edges: dict[tuple[str, str, str], dict],
    source: str,
    target: str,
    *,
    kind: str,
    label: str,
    location: dict | None = None,
    evidence: str | None = None,
) -> None:
    edge = edges.setdefault((source, target, kind), {
        "source": source,
        "target": target,
        "kind": kind,
        "label": label,
        "locations": [],
        "evidence": [],
    })
    if location and location not in edge["locations"]:
        edge["locations"].append(location)
    if evidence and evidence not in edge["evidence"]:
        edge["evidence"].append(evidence)


def _graph_state_categories(type_name: str, name: str) -> list[str]:
    haystack = f"{type_name} {name}".lower()
    categories = []
    if any(word in haystack for word in (
        "ierc20",
        "erc20",
        "token",
        "asset",
        "underlying",
        "collateral",
        "stable",
        "weth",
        "usdc",
        "dai",
        "lp",
        "share",
    )):
        categories.append("asset_hint")
    if any(word in haystack for word in (
        "total",
        "balance",
        "debt",
        "share",
        "reserve",
        "supply",
        "fee",
        "index",
        "rate",
        "accumulator",
        "collateral",
        "liability",
        "limit",
        "cap",
    )):
        categories.append("accounting_state")
    if any(word in haystack for word in (
        "oracle",
        "price",
        "feed",
        "twap",
        "router",
        "pool",
        "pair",
        "swap",
        "amm",
        "curve",
        "uniswap",
        "chainlink",
    )):
        categories.append("external_dependency")
        categories.append("valuation_boundary")
    if any(word in haystack for word in (
        "owner",
        "admin",
        "governor",
        "guardian",
        "keeper",
        "role",
        "authority",
        "operator",
    )):
        categories.append("trust_boundary")
    if re.match(r"^I[A-Z]", type_name):
        categories.append("external_dependency")
    return sorted(set(categories))


def _graph_state_node_kind(categories: list[str]) -> str:
    for kind in (
        "asset_hint",
        "accounting_state",
        "external_dependency",
        "trust_boundary",
    ):
        if kind in categories:
            return kind
    return "state_hint"


def _graph_state_edge_kind(kind: str) -> tuple[str, str]:
    return {
        "asset_hint": ("declares_asset_hint", "declares asset hint"),
        "accounting_state": ("declares_accounting_state", "declares accounting state"),
        "external_dependency": ("declares_external_dependency", "declares external dependency"),
        "trust_boundary": ("declares_trust_boundary", "declares trust boundary"),
    }.get(kind, ("declares_state_hint", "declares state hint"))


def _graph_action_node_id(contract: str, function: str) -> str:
    return f"action:{contract}.{function}"


def _graph_state_node_id(kind: str, contract: str, name: str) -> str:
    prefix = {
        "asset_hint": "asset",
        "accounting_state": "accounting",
        "external_dependency": "external",
        "trust_boundary": "trust",
    }.get(kind, "state")
    return f"{prefix}:{contract}.{name}"


def _graph_action_bodies(source: str, starts: list[int]) -> dict[tuple[str, str], dict]:
    bodies = {}
    scan_source = _strip_comments_preserve_layout(source)
    function_pattern = re.compile(
        r"\bfunction\s+([A-Za-z_][A-Za-z0-9_]*)\s*"
        r"\((.*?)\)([^{};]*)([{;])",
        flags=re.DOTALL,
    )
    special_pattern = re.compile(
        r"\b(receive|fallback)\s*\((.*?)\)([^{};]*)([{;])",
        flags=re.DOTALL,
    )
    for contract in _contract_ranges(source, starts):
        block = scan_source[contract["start"]:contract["end"]]
        matches = list(function_pattern.finditer(block))
        matches.extend(special_pattern.finditer(block))
        for match in matches:
            name = match.group(1)
            tail = match.group(3)
            terminator = match.group(4)
            visibility_match = re.search(
                r"\b(public|external|internal|private)\b", tail
            )
            visibility = visibility_match.group(1) if visibility_match else ""
            if not visibility and contract["kind"] == "interface":
                visibility = "external"
            if name in {"receive", "fallback"} and not visibility:
                visibility = "external"
            if visibility not in {"public", "external"} and name not in {"receive", "fallback"}:
                continue
            absolute_start = contract["start"] + match.start()
            body = ""
            if terminator == "{":
                open_index = contract["start"] + match.end() - 1
                close_index = _find_matching_brace(source, open_index)
                body = source[open_index:close_index + 1]
            bodies[(contract["name"], name)] = {
                "body": body,
                "file": contract.get("file"),
                "line": _line_at(starts, absolute_start),
            }
    return bodies


def _parse_protocol_graph_file(
    path: str,
    source: str,
    *,
    max_items: int,
) -> dict:
    if len(source) > _ACTION_MAX_FILE_CHARS:
        source = source[:_ACTION_MAX_FILE_CHARS]
        truncated = True
    else:
        truncated = False

    starts = _line_starts(source)
    action_space = _parse_action_space_file(path, source, max_items=max_items)
    nodes: dict[str, dict] = {}
    edges: dict[tuple[str, str, str], dict] = {}
    state_nodes_by_contract: dict[str, list[dict]] = {}

    for contract in _contract_ranges(source, starts):
        contract_id = f"contract:{contract['name']}"
        contract_location = _graph_location(path, contract["line"])
        _graph_add_node(
            nodes,
            contract_id,
            kind=contract["kind"],
            label=contract["name"],
            location=contract_location,
        )
        block = source[contract["start"]:contract["end"]]
        for offset, line in enumerate(block.splitlines()):
            stripped = line.split("//", 1)[0].strip()
            if not stripped:
                continue
            match = _GRAPH_STATE_DECL_RE.match(stripped)
            if not match:
                continue
            type_name = " ".join(match.group("type").split())
            name = match.group("name")
            categories = _graph_state_categories(type_name, name)
            if not categories:
                continue
            kind = _graph_state_node_kind(categories)
            node_id = _graph_state_node_id(kind, contract["name"], name)
            line_number = _line_at(starts, contract["start"]) + offset
            location = _graph_location(path, line_number)
            _graph_add_node(
                nodes,
                node_id,
                kind=kind,
                label=f"{contract['name']}.{name}",
                tags=categories,
                location=location,
                contract=contract["name"],
                variable=name,
                type=type_name,
            )
            edge_kind, edge_label = _graph_state_edge_kind(kind)
            _graph_add_edge(
                edges,
                contract_id,
                node_id,
                kind=edge_kind,
                label=edge_label,
                location=location,
                evidence=stripped[:240],
            )
            state_nodes_by_contract.setdefault(contract["name"], []).append({
                "id": node_id,
                "kind": kind,
                "name": name,
                "categories": categories,
            })

    action_bodies = _graph_action_bodies(source, starts)
    for entry in action_space.get("actions", []) + action_space.get("observations", []):
        contract = str(entry.get("contract") or "")
        function = str(entry.get("function") or "")
        if not contract or not function:
            continue
        contract_id = f"contract:{contract}"
        action_id = _graph_action_node_id(contract, function)
        location = _graph_location(path, entry.get("line"))
        node_kind = "observation" if entry.get("mutability") in {"view", "pure"} else "entrypoint"
        affordances = [str(item) for item in entry.get("affordances") or []]
        _graph_add_node(
            nodes,
            action_id,
            kind=node_kind,
            label=f"{contract}.{function}",
            tags=affordances,
            location=location,
            contract=contract,
            function=function,
            mutability=entry.get("mutability"),
            visibility=entry.get("visibility"),
        )
        _graph_add_edge(
            edges,
            contract_id,
            action_id,
            kind="exposes_observation" if node_kind == "observation" else "exposes_entrypoint",
            label="exposes observation" if node_kind == "observation" else "exposes entrypoint",
            location=location,
        )
        for modifier in entry.get("modifiers") or []:
            modifier_id = f"trust:modifier:{contract}.{modifier}"
            _graph_add_node(
                nodes,
                modifier_id,
                kind="trust_boundary",
                label=f"{contract}.{modifier}",
                tags=["modifier"],
                location=location,
                contract=contract,
            )
            _graph_add_edge(
                edges,
                action_id,
                modifier_id,
                kind="gated_by_modifier",
                label="gated by modifier",
                location=location,
            )
        for affordance in affordances:
            concept = _GRAPH_AFFORDANCE_CONCEPTS.get(affordance)
            if not concept:
                continue
            concept_id, kind, label, edge_kind = concept
            _graph_add_node(
                nodes,
                concept_id,
                kind=kind,
                label=label,
                tags=[affordance],
            )
            _graph_add_edge(
                edges,
                action_id,
                concept_id,
                kind=edge_kind,
                label=label,
                location=location,
            )

        action_body = action_bodies.get((contract, function), {}).get("body", "")
        if action_body:
            for state_node in state_nodes_by_contract.get(contract, []):
                name = re.escape(state_node["name"])
                if not re.search(rf"\b{name}\b", action_body):
                    continue
                kind = state_node["kind"]
                edge_kind = {
                    "asset_hint": "references_asset_hint",
                    "accounting_state": "references_accounting_state",
                    "external_dependency": "references_external_dependency",
                    "trust_boundary": "references_trust_boundary",
                }.get(kind, "references_state_hint")
                _graph_add_edge(
                    edges,
                    action_id,
                    state_node["id"],
                    kind=edge_kind,
                    label=edge_kind.replace("_", " "),
                    location=location,
                )

        for hint_group, concept in _GRAPH_HINT_CONCEPTS.items():
            for hint in (entry.get("hints") or {}).get(hint_group) or []:
                concept_id, kind, label, edge_kind = concept
                if concept_id not in nodes:
                    _graph_add_node(
                        nodes,
                        concept_id,
                        kind=kind,
                        label=label,
                    )
                _graph_add_edge(
                    edges,
                    action_id,
                    concept_id,
                    kind=edge_kind,
                    label=edge_kind.replace("_", " "),
                    location=_graph_location(path, hint.get("line")),
                    evidence=str(hint.get("text") or "")[:240],
                )

        for hint in (entry.get("hints") or {}).get("events") or []:
            event = str(hint.get("event") or "").strip()
            if not event:
                continue
            event_id = f"event:{contract}.{event}"
            _graph_add_node(
                nodes,
                event_id,
                kind="event_hint",
                label=f"{contract}.{event}",
                tags=["event"],
                location=_graph_location(path, hint.get("line")),
                contract=contract,
                event=event,
            )
            _graph_add_edge(
                edges,
                action_id,
                event_id,
                kind="emits_event",
                label="emits event",
                location=_graph_location(path, hint.get("line")),
                evidence=str(hint.get("text") or "")[:240],
            )

    return {
        "path": path,
        "truncated": truncated or bool(action_space.get("truncated")),
        "nodes": list(nodes.values()),
        "edges": list(edges.values()),
    }


def _merge_protocol_graph_parts(parts: list[dict], max_items: int) -> dict:
    nodes: dict[str, dict] = {}
    edges: dict[tuple[str, str, str], dict] = {}
    truncated_paths = []

    for part in parts:
        if part.get("truncated"):
            truncated_paths.append(part.get("path"))
        for node in part.get("nodes") or []:
            _graph_add_node(
                nodes,
                node["id"],
                kind=node.get("kind", ""),
                label=node.get("label", ""),
                tags=node.get("tags") or [],
            )
            merged = nodes[node["id"]]
            for location in node.get("locations") or []:
                if location not in merged["locations"]:
                    merged["locations"].append(location)
            for key, value in node.items():
                if key in {"id", "kind", "label", "tags", "locations"}:
                    continue
                if value not in (None, "", [], {}):
                    merged.setdefault(key, value)
        for edge in part.get("edges") or []:
            key = (edge["source"], edge["target"], edge["kind"])
            _graph_add_edge(
                edges,
                edge["source"],
                edge["target"],
                kind=edge["kind"],
                label=edge.get("label", edge["kind"]),
            )
            merged_edge = edges[key]
            for location in edge.get("locations") or []:
                if location not in merged_edge["locations"]:
                    merged_edge["locations"].append(location)
            for evidence in edge.get("evidence") or []:
                if evidence not in merged_edge["evidence"]:
                    merged_edge["evidence"].append(evidence)

    node_list = sorted(
        nodes.values(),
        key=lambda item: (str(item.get("kind")), str(item.get("label")), str(item.get("id"))),
    )
    edge_list = sorted(
        edges.values(),
        key=lambda item: (str(item.get("source")), str(item.get("kind")), str(item.get("target"))),
    )
    hotspots = _protocol_graph_hotspots(nodes, edge_list, max_items=max_items)
    summary = {
        "nodes": len(node_list),
        "edges": len(edge_list),
        "contracts": sum(1 for node in node_list if node.get("kind") == "contract"),
        "entrypoints": sum(1 for node in node_list if node.get("kind") == "entrypoint"),
        "observations": sum(1 for node in node_list if node.get("kind") == "observation"),
        "asset_hints": sum(1 for node in node_list if node.get("kind") == "asset_hint"),
        "accounting_state": sum(1 for node in node_list if node.get("kind") == "accounting_state"),
        "external_dependencies": sum(1 for node in node_list if node.get("kind") == "external_dependency"),
        "trust_boundaries": sum(1 for node in node_list if node.get("kind") == "trust_boundary"),
        "event_hints": sum(1 for node in node_list if node.get("kind") == "event_hint"),
        "state_mutation_hints": sum(1 for node in node_list if node.get("kind") == "state_mutation"),
        "economic_parameter_hints": sum(1 for node in node_list if node.get("kind") == "economic_parameter"),
        "value_flow_edges": sum(
            1 for edge in edge_list
            if str(edge.get("target", "")).startswith("flow:")
            or "value" in str(edge.get("kind", ""))
        ),
        "trust_boundary_edges": sum(
            1 for edge in edge_list
            if str(edge.get("target", "")).startswith("boundary:")
            or str(edge.get("target", "")).startswith("trust:")
            or "boundary" in str(edge.get("kind", ""))
            or "modifier" in str(edge.get("kind", ""))
        ),
        "event_edges": sum(1 for edge in edge_list if edge.get("kind") == "emits_event"),
        "state_mutation_edges": sum(
            1 for edge in edge_list
            if edge.get("kind") == "has_state_mutation_hint"
        ),
        "oracle_edges": sum(1 for edge in edge_list if edge.get("kind") == "reads_oracle_input"),
        "router_edges": sum(1 for edge in edge_list if edge.get("kind") == "routes_through_router"),
        "bridge_edges": sum(1 for edge in edge_list if edge.get("kind") == "handles_bridge_or_message"),
        "callback_edges": sum(1 for edge in edge_list if edge.get("kind") == "has_callback_surface_hint"),
        "authorization_edges": sum(1 for edge in edge_list if edge.get("kind") == "checks_authorization_binding"),
        "cross_contract_edges": sum(1 for edge in edge_list if edge.get("kind") == "calls_cross_contract_dependency"),
        "economic_parameter_edges": sum(1 for edge in edge_list if edge.get("kind") == "has_economic_parameter_hint"),
        "hotspots": len(hotspots),
    }
    return {
        "nodes": node_list[:max_items],
        "edges": edge_list[:max_items],
        "hotspots": hotspots[:max_items],
        "summary": summary,
        "truncated_source_files": [path for path in truncated_paths if path],
    }


def _protocol_graph_hotspots(
    nodes: dict[str, dict],
    edges: list[dict],
    *,
    max_items: int,
) -> list[dict]:
    outgoing: dict[str, list[dict]] = {}
    for edge in edges:
        outgoing.setdefault(edge["source"], []).append(edge)

    edge_weights = {
        "can_release_or_burn_value": 4,
        "changes_credit_or_liquidation_state": 4,
        "depends_on_valuation": 4,
        "depends_on_market_or_router": 3,
        "crosses_external_call_boundary": 3,
        "accepts_callback_or_flashloan_flow": 3,
        "depends_on_signature_binding": 3,
        "depends_on_cross_domain_state": 3,
        "references_asset_hint": 2,
        "references_accounting_state": 2,
        "references_external_dependency": 2,
        "reads_oracle_input": 4,
        "routes_through_router": 3,
        "handles_bridge_or_message": 3,
        "has_callback_surface_hint": 3,
        "checks_authorization_binding": 3,
        "calls_cross_contract_dependency": 2,
        "has_state_mutation_hint": 2,
        "has_economic_parameter_hint": 2,
        "emits_event": 1,
        "gated_by_modifier": 1,
        "checks_sender_or_role": 1,
    }
    hotspots = []
    for node in nodes.values():
        if node.get("kind") != "entrypoint":
            continue
        score, reasons = _coverage_attention({
            "affordances": node.get("tags") or [],
            "mutability": node.get("mutability"),
        })
        connected = []
        for edge in outgoing.get(node["id"], []):
            weight = edge_weights.get(str(edge.get("kind")), 0)
            if weight:
                score += weight
                reasons.append(f"{edge['kind']}+{weight}")
            target = nodes.get(edge["target"], {})
            if target:
                connected.append({
                    "edge": edge.get("kind"),
                    "target": target.get("id"),
                    "kind": target.get("kind"),
                    "label": target.get("label"),
                })
        if score <= 0:
            continue
        locations = node.get("locations") or []
        first_location = locations[0] if locations else {}
        hotspots.append({
            "key": str(node.get("label") or node.get("id")).replace(".", "::", 1),
            "contract": node.get("contract"),
            "function": node.get("function"),
            "file": first_location.get("file"),
            "line": first_location.get("line"),
            "affordances": node.get("tags") or [],
            "score": score,
            "reasons": reasons[:12],
            "connected": connected[:8],
        })
    return sorted(
        hotspots,
        key=lambda item: (-int(item.get("score", 0)), str(item.get("key"))),
    )[:max_items]


def _counts_by_key(items: list[dict], key: str) -> list[dict]:
    counts: dict[str, int] = {}
    for item in items:
        value = str(item.get(key) or "")
        if value:
            counts[value] = counts.get(value, 0) + 1
    return [
        {key: name, "count": count}
        for name, count in sorted(counts.items(), key=lambda item: (-item[1], item[0]))
    ]


def _compact_graph_node(node: dict) -> dict:
    locations = node.get("locations") or []
    first_location = locations[0] if locations else {}
    compact = {
        "id": node.get("id"),
        "kind": node.get("kind"),
        "label": node.get("label"),
        "contract": node.get("contract"),
        "function": node.get("function"),
        "variable": node.get("variable"),
        "type": node.get("type"),
        "tags": (node.get("tags") or [])[:8],
        "file": first_location.get("file"),
        "line": first_location.get("line"),
    }
    return {key: value for key, value in compact.items() if value not in (None, "", [], {})}


def _compact_graph_edge(edge: dict) -> dict:
    locations = edge.get("locations") or []
    first_location = locations[0] if locations else {}
    compact = {
        "source": edge.get("source"),
        "target": edge.get("target"),
        "kind": edge.get("kind"),
        "label": edge.get("label"),
        "file": first_location.get("file"),
        "line": first_location.get("line"),
        "evidence": (edge.get("evidence") or [])[:2],
    }
    return {key: value for key, value in compact.items() if value not in (None, "", [], {})}


def _graph_keyword_hints(nodes: list[dict], edges: list[dict], max_items: int) -> list[str]:
    terms = []
    interesting = re.compile(
        r"\b[A-Za-z_][A-Za-z0-9_]*(?:Debt|debt|Share|share|Balance|balance|"
        r"Liquidation|liquidation|Threshold|threshold|Fee|fee|Premium|premium|"
        r"Oracle|oracle|Router|router|Bridge|bridge|Token|token|Asset|asset)"
        r"[A-Za-z0-9_]*\b"
    )
    for node in nodes:
        for field in ("label", "variable", "type"):
            for match in interesting.finditer(str(node.get(field) or "")):
                terms.append(match.group(0))
    for edge in edges:
        for evidence in edge.get("evidence") or []:
            for match in interesting.finditer(str(evidence or "")):
                terms.append(match.group(0))
    return _dedupe_text(terms)[:max_items]


async def _map_protocol_graph(container: AuditContainer, args: dict) -> str:
    try:
        root = _normalize_action_source_path(args.get("path", "/audit"))
        files_arg = args.get("files")
        files = _require_list(files_arg, "files") if files_arg is not None else None
        related_ids = _require_list(args.get("related_ids"), "related_ids")
    except ValueError as exc:
        return f"Error: {exc}"

    include_tests = bool(args.get("include_tests", False))
    max_files = min(max(int(args.get("max_files", 160)), 1), 500)
    max_roots = min(max(int(args.get("max_roots", 12)), 1), 100)
    max_items = min(max(int(args.get("max_items", 2000)), 1), 10_000)
    response_items = min(max(int(args.get("response_items", 6)), 1), 50)
    try:
        source_files, truncated_files = await _discover_action_source_files(
            container,
            root=root,
            files=files,
            include_tests=include_tests,
            max_files=max_files,
            max_roots=max_roots,
        )
    except ValueError as exc:
        return f"Error: {exc}"

    parsed_files = []
    read_errors = []
    for path in source_files:
        try:
            source = await container.read_file(path)
        except FileNotFoundError as exc:
            read_errors.append({"path": path, "error": str(exc)})
            continue
        parsed_files.append(_parse_protocol_graph_file(
            path,
            source,
            max_items=max_items,
        ))

    aggregate = _merge_protocol_graph_parts(parsed_files, max_items=max_items)
    state = await _load_campaign_state(container)
    graph_id = _next_campaign_id(state, "protocol_graph")
    graph = {
        "id": graph_id,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "source": {
            "path": root,
            "files_requested": len(source_files),
            "files_scanned": len(parsed_files),
            "files_truncated_by_limit": truncated_files,
            "profile_roots_limit": max_roots if files is None else None,
            "include_tests": include_tests,
            "read_errors": read_errors,
            "truncated_source_files": aggregate["truncated_source_files"],
        },
        "related_ids": [str(item) for item in related_ids],
        "notes": [
            "Heuristic source graph for campaign planning; validate all conclusions with experiments.",
            "Asset/accounting/trust nodes are hints derived from names, types, modifiers, and call patterns.",
        ],
        "summary": aggregate["summary"],
        "nodes": aggregate["nodes"],
        "edges": aggregate["edges"],
        "hotspots": aggregate["hotspots"],
    }
    graph_path = f"/workspace/campaign/protocol-graphs/{graph_id}.json"
    await container.write_file(
        graph_path,
        json.dumps(graph, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Protocol graph: {root}",
            content=(
                f"Protocol graph: {graph_id}\n"
                f"Path: {graph_path}\n"
                f"Source root: {root}\n"
                f"Files scanned: {len(parsed_files)}"
                f" (+{truncated_files} over file limit)\n"
                f"Contracts: {graph['summary']['contracts']}\n"
                f"Entrypoints: {graph['summary']['entrypoints']}\n"
                f"Asset hints: {graph['summary']['asset_hints']}\n"
                f"Accounting state hints: {graph['summary']['accounting_state']}\n"
                f"Trust-boundary edges: {graph['summary']['trust_boundary_edges']}\n"
                "Use this graph as planner context; it is not a finding."
            ),
            evidence=[graph_path],
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "protocol_graph_id": graph_id,
        "path": graph_path,
        "result_id": result_id or None,
        "source": graph["source"],
        "summary": graph["summary"],
        "node_kinds": _counts_by_key(graph["nodes"], "kind"),
        "edge_kinds": _counts_by_key(graph["edges"], "kind"),
        "keyword_hints": _graph_keyword_hints(
            graph["nodes"],
            graph["edges"],
            max(12, response_items * 2),
        ),
        "hotspots": graph["hotspots"][:response_items],
        "nodes": [
            _compact_graph_node(item)
            for item in graph["nodes"][:response_items]
        ],
        "edges": [
            _compact_graph_edge(item)
            for item in graph["edges"][:response_items]
        ],
        "omitted_from_response": {
            "nodes": max(0, len(graph["nodes"]) - response_items),
            "edges": max(0, len(graph["edges"]) - response_items),
            "note": "Open the artifact path for the full graph.",
        },
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _protocol_graph_path(identifier: str) -> str:
    return _campaign_artifact_path(
        identifier,
        directory="/workspace/campaign/protocol-graphs/",
        prefix="pg",
        name="protocol_graph",
    )


async def _load_protocol_graph(
    container: AuditContainer,
    identifier: str,
) -> tuple[str, dict]:
    path = _protocol_graph_path(identifier)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"protocol_graph {path} is not valid JSON") from exc


def _action_space_path(identifier: str) -> str:
    value = identifier.strip()
    if not value:
        raise ValueError("action_space cannot be empty")
    if value.startswith("/"):
        normalized = posixpath.normpath(value)
        if not normalized.startswith("/workspace/campaign/action-spaces/"):
            raise ValueError(
                "absolute action_space paths must be under "
                "/workspace/campaign/action-spaces/"
            )
        return normalized
    if not re.match(r"^as-\d{3,}$", value):
        raise ValueError("action_space must be an id like as-001 or an absolute path")
    return f"/workspace/campaign/action-spaces/{value}.json"


async def _load_action_space(
    container: AuditContainer,
    identifier: str,
) -> tuple[str, dict]:
    path = _action_space_path(identifier)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"action_space {path} is not valid JSON") from exc


def _state_transition_model_path(identifier: str) -> str:
    return _campaign_artifact_path(
        identifier,
        directory="/workspace/campaign/state-transition-models/",
        prefix="stm",
        name="state_transition_model",
    )


async def _load_state_transition_model_ref(
    container: AuditContainer,
    ref: str | None,
) -> tuple[str | None, dict | None, str | None]:
    """Resolve an explicit state-transition-model reference to (path, model,
    error).

    Returns (None, None, None) when no ref is supplied. Accepts an ``stm-NNN`` id
    or an absolute path under /workspace/campaign/state-transition-models/. On an
    invalid ref or a missing/unreadable artifact it returns a clear error string
    (and no model) so build_attack_graph can surface it instead of silently
    ignoring the arg.
    """
    text = str(ref or "").strip()
    if not text:
        return None, None, None
    try:
        path = _state_transition_model_path(text)
    except ValueError as exc:
        return None, None, str(exc)
    payload = await _load_campaign_json_if_exists(container, path)
    if not isinstance(payload, dict):
        return (
            None,
            None,
            f"state_transition_model artifact not found or invalid: {path}",
        )
    return path, payload, None


