# Kind-specific objective notes for a generic state-transition invariant. These
# annotate the falsify-invariant objective with the concrete delta that proves the
# kind of violation; they never replace the invariant statement itself.
_STM_KIND_OBJECTIVE_NOTE = {
    "conservation": "compare aggregate and per-user claim before/after",
    "authorization_binding": (
        "prove the caller can modify/consume another subject's right"
    ),
    "external_call_safety": (
        "callback/reentry must not observe or mutate inconsistent state"
    ),
    "rounding": "show a monotonicity/conservation/bounds violation",
    "bounds": "show a monotonicity/conservation/bounds violation",
    "state_machine": "invalid phase skip/replay/deadlock",
    "liveness": "permanent lock or unclaimable state",
    "replay_protection": (
        "a replayed signature/message/nonce must not be accepted twice"
    ),
}


def _workbench_candidate_invariant_id(candidate: dict) -> str:
    """Resolve the invariant id a candidate points at, checking (in order)
    candidate['invariant']['id'], candidate['invariant_id'], and
    candidate['source']['invariant_id']."""
    invariant = candidate.get("invariant")
    if isinstance(invariant, dict):
        inv_id = str(invariant.get("id") or "").strip()
        if inv_id:
            return inv_id
    inv_id = str(candidate.get("invariant_id") or "").strip()
    if inv_id:
        return inv_id
    source = candidate.get("source")
    if isinstance(source, dict):
        inv_id = str(source.get("invariant_id") or "").strip()
        if inv_id:
            return inv_id
    return ""


def _workbench_candidate_action_refs(candidate: dict) -> set[tuple[str, str]]:
    """Lowercased (contract, function) pairs the candidate exercises: its own
    contract/function plus every action skeleton."""
    refs: set[tuple[str, str]] = set()
    contract = str(candidate.get("contract") or "").strip().lower()
    function = str(candidate.get("function") or "").strip().lower()
    if function:
        refs.add((contract, function))
    for action in candidate.get("actions") or []:
        if not isinstance(action, dict):
            continue
        a_contract = str(action.get("contract") or "").strip().lower()
        a_function = str(action.get("function") or "").strip().lower()
        if a_function:
            refs.add((a_contract, a_function))
    return refs


def _workbench_select_invariant(candidate: dict, model: dict) -> dict | None:
    """Pick the model invariant that best matches the selected candidate.

    If the candidate carries an explicit invariant id, return that invariant (or
    None when the id is absent from the model — we never fabricate guidance for an
    id the model does not contain). Otherwise score invariants by target
    contract/function/action overlap, invariant-kind mention in the candidate
    text, and referencing experiment prompts, returning the best positive match or
    None.
    """
    invariants = [
        inv for inv in model.get("candidate_invariants") or [] if isinstance(inv, dict)
    ]
    if not invariants:
        return None

    target_id = _workbench_candidate_invariant_id(candidate)
    if target_id:
        for invariant in invariants:
            if str(invariant.get("id") or "").strip() == target_id:
                return invariant
        return None

    action_refs = _workbench_candidate_action_refs(candidate)
    contracts = {contract for contract, _ in action_refs if contract}
    functions = {function for _, function in action_refs if function}
    candidate_text = _coverage_normalize_text(
        " ".join(
            str(candidate.get(key) or "")
            for key in ("title", "objective", "mechanism")
        )
    )

    def overlaps(contract: str, function: str) -> int:
        if not function:
            return 0
        if (contract, function) in action_refs:
            return 4
        if function in functions:
            return 2
        return 0

    best: dict | None = None
    best_score = 0
    for invariant in invariants:
        inv_contract = str(invariant.get("contract") or "").strip().lower()
        inv_function = str(invariant.get("function") or "").strip().lower()
        score = overlaps(inv_contract, inv_function)
        if inv_contract and inv_contract in contracts:
            score += 2
        for ref in invariant.get("target_actions") or []:
            ref_contract, ref_function = _stm_split_action_ref(ref)
            gain = overlaps(ref_contract.lower(), ref_function.lower())
            if gain:
                score += min(gain, 2)
                break
        kind = str(invariant.get("kind") or "").strip().lower()
        if kind and kind.replace("_", " ") in candidate_text:
            score += 1
        for prompt in model.get("experiment_prompts") or []:
            if not isinstance(prompt, dict) or not _stm_prompt_matches_invariant(
                prompt, invariant
            ):
                continue
            for ref in prompt.get("target_actions") or []:
                ref_contract, ref_function = _stm_split_action_ref(ref)
                if overlaps(ref_contract.lower(), ref_function.lower()):
                    score += 1
                    break
            else:
                continue
            break
        if score > best_score:
            best_score = score
            best = invariant
    return best if best_score > 0 else None


def _workbench_normalize_model_observations(observations: object) -> list[dict]:
    """Normalize a model invariant's candidate_observations (each a free string or
    a dict) into observation objects tagged with their model origin, de-duplicated
    in order."""
    normalized: list[dict] = []
    seen: set[str] = set()
    for observation in observations or []:
        if isinstance(observation, dict):
            entry = dict(observation)
            entry.setdefault("source", "state_transition_model_invariant")
        else:
            text = str(observation).strip()
            if not text:
                continue
            label, sep, rest = text.partition(":")
            label = label.strip()
            rest = rest.strip()
            if sep and rest and " " not in label:
                entry = {
                    "label": label,
                    "notes": rest,
                    "source": "state_transition_model_invariant",
                }
            else:
                entry = {"notes": text, "source": "state_transition_model_invariant"}
        marker = json.dumps(entry, sort_keys=True, default=str)
        if marker in seen:
            continue
        seen.add(marker)
        normalized.append(entry)
    return normalized


def _workbench_model_setup_tasks(experiment_prompts: object) -> list[dict]:
    """Turn matched experiment prompts' required_setup steps into workbench setup
    tasks, de-duplicated and capped."""
    tasks: list[dict] = []
    seen: set[str] = set()
    for prompt in experiment_prompts or []:
        if not isinstance(prompt, dict):
            continue
        title = str(prompt.get("title") or "").strip()
        for setup in prompt.get("required_setup") or []:
            text = str(setup).strip()
            if not text or text in seen:
                continue
            seen.add(text)
            tasks.append({
                "kind": "model_experiment_setup",
                "prompt": text,
                "example": (
                    f"From state-transition-model experiment prompt: {title}"
                    if title
                    else "From state-transition-model experiment prompt."
                ),
            })
            if len(tasks) >= 5:
                return tasks
    return tasks


def _workbench_model_snapshot_entries(
    observations: list[dict],
    *,
    target_label: str,
    target_address: str,
    assets_known: bool,
) -> dict:
    """Classify normalized model observations into snapshot buckets: contract /
    function (or signature) observation calls, actor-balance reads only when an
    asset/token context exists, and generic state notes otherwise."""
    calls: list[dict] = []
    state_notes: list[dict] = []
    erc20_balances: list[dict] = []
    for observation in observations:
        label = str(observation.get("label") or "").strip()
        signature = str(
            observation.get("signature") or observation.get("call") or ""
        ).strip()
        contract = str(observation.get("contract") or "").strip()
        function = str(observation.get("function") or "").strip()
        notes = str(observation.get("notes") or "").strip()
        obs_address = (
            _solidity_address_literal(observation.get("target")) or target_address
        )
        if signature:
            calls.append(
                _fork_workbench_call(
                    label or (f"{contract}.{function}" if function else "model observation"),
                    obs_address,
                    signature,
                    notes=notes,
                )
            )
            continue
        token = _solidity_address_literal(observation.get("token"))
        account = observation.get("account")
        if assets_known and token and account:
            erc20_balances.append({
                "token_label": observation.get("token_label") or label or "model token",
                "token": token,
                "account_label": observation.get("account_label") or "model actor",
                "account": str(account),
            })
            continue
        if function:
            note_label = label or (f"{contract}.{function}" if contract else function)
            state_notes.append({
                "label": note_label,
                "target": contract or target_label,
                "timing": str(observation.get("timing") or "before and after"),
                "notes": notes or (
                    f"Snapshot the state {note_label} reads/mutates before and after "
                    "and assert the exact delta."
                ),
                "source": "state_transition_model_invariant",
            })
            continue
        state_notes.append({
            "label": label or "model invariant observation",
            "target": str(observation.get("target") or target_label),
            "timing": str(observation.get("timing") or "before and after"),
            "notes": notes or (
                "Snapshot this model-identified state before and after the transition "
                "and assert the exact delta."
            ),
            "source": "state_transition_model_invariant",
        })
    return {"calls": calls, "state_notes": state_notes, "erc20_balances": erc20_balances}


def _workbench_model_guidance(model_path: str, invariant: dict) -> dict:
    """Compact, model-derived planning guidance for a matched invariant. Empty
    fields are elided so the README/response stay terse."""
    statement = str(invariant.get("statement") or "").strip()
    guidance = {
        "state_transition_model": model_path or None,
        "invariant_id": str(invariant.get("id") or "").strip() or None,
        "kind": str(invariant.get("kind") or "").strip() or None,
        "statement": statement or None,
        "falsification_ideas": [
            str(item).strip()
            for item in invariant.get("falsification_ideas") or []
            if str(item).strip()
        ][:4],
        "candidate_observations": list(invariant.get("candidate_observations") or [])[:6],
    }
    return {key: value for key, value in guidance.items() if value not in (None, "", [], {})}


def _generic_state_transition_workbench_adapter(
    candidate: dict,
    *,
    target: dict,
    fork_context: dict | None,
    stm_context: dict | None = None,
) -> dict:
    """Mechanism-agnostic invariant / state-transition harness.

    Used when no economic mechanism (vault, lending, amm_oracle, bridge,
    queue_solver, staking) and no execution mechanism match. It makes no
    vault/share/asset-accounting assumptions: it binds the target, identifies
    actors, seeds only assets that fork context or the candidate explicitly
    names, and asks the agent to assert a concrete before/after state delta.
    """
    address = str(target["address"])
    label = str(target["label"])
    token_labels = _fork_workbench_token_labels(fork_context)
    observations = _attack_candidate_observations(candidate)
    explicit_observations = [
        item for item in candidate.get("observations") or []
        if isinstance(item, dict)
    ]
    affordances = {str(item) for item in candidate.get("affordances") or []}
    value_flow = bool(affordances.intersection({
        "accepts_native_value",
        "token_or_native_transfer",
        "value_out_or_burn",
    }))
    assets_known = bool(token_labels)
    stm_invariant = None
    stm_model = None
    stm_model_path = ""
    stm_prompts: list[dict] = []
    if isinstance(stm_context, dict):
        if isinstance(stm_context.get("invariant"), dict):
            stm_invariant = stm_context["invariant"]
        if isinstance(stm_context.get("model"), dict):
            stm_model = stm_context["model"]
        stm_model_path = str(stm_context.get("model_path") or "").strip()
        stm_prompts = [
            prompt
            for prompt in stm_context.get("experiment_prompts") or []
            if isinstance(prompt, dict)
        ]
    text = _fork_workbench_text(candidate, fork_context)
    lock_or_dos = any(term in text for term in (
        "brick",
        "cannot withdraw",
        "denial of service",
        "dos",
        "freeze",
        "frozen",
        "lock",
        "permanently",
        "stuck",
    ))

    setup_tasks = [
        {
            "kind": "target_binding",
            "prompt": (
                "Bind the deployed target address and confirm it holds live "
                "bytecode before exercising any state transition."
            ),
            "example": f"cast code {address}",
        },
        {
            "kind": "actor_identification",
            "prompt": (
                "Identify the attacker/caller and every other account whose state "
                "the transition reads or mutates (owner, victim, counterparty, "
                "registry entry); seed only attacker-controlled state."
            ),
            "example": "label attacker, victim, and any privileged role from fork context or source.",
        },
    ]
    if assets_known:
        seeded = ", ".join(item["label"] for item in token_labels[:6])
        setup_tasks.append({
            "kind": "asset_seeding",
            "prompt": (
                "Seed only the assets explicitly identified in fork context or the "
                f"candidate ({seeded}); do not assume any other balances exist."
            ),
            "example": "deal(token, attacker, amount) for each identified asset only.",
        })
    else:
        setup_tasks.append({
            "kind": "asset_seeding",
            "prompt": (
                "No assets were identified in fork context or the candidate. Do not "
                "assume any token or balance model. If the transition requires "
                "funding, first identify the concrete asset; otherwise leave asset "
                "setup as an open blocker."
            ),
            "example": "resolve the concrete asset before any deal()/approve(); no default token.",
        })
    setup_tasks.append({
        "kind": "authorization_precondition",
        "prompt": (
            "Resolve any authorization or precondition gate the transition depends "
            "on (owner/role/allowlist/pause/timelock/initialization/nonce) and prove "
            "an attacker-reachable path or a specific bypass."
        ),
        "example": "owner(), hasRole(role, attacker), paused(), initialized(), nonces(attacker).",
    })
    if stm_prompts:
        setup_tasks.extend(_workbench_model_setup_tasks(stm_prompts))

    observation_calls = []
    state_notes = []
    for index, observation in enumerate(observations, start=1):
        obs_label = str(observation.get("label") or f"observation {index}").strip()
        signature = str(
            observation.get("signature") or observation.get("call") or ""
        ).strip()
        obs_notes = str(observation.get("notes") or "").strip()
        if signature:
            obs_address = _solidity_address_literal(observation.get("target")) or address
            observation_calls.append(
                _fork_workbench_call(obs_label, obs_address, signature, notes=obs_notes)
            )
        else:
            state_notes.append({
                "label": obs_label,
                "target": str(observation.get("target") or label),
                "timing": str(observation.get("timing") or "before and after"),
                "notes": obs_notes or (
                    "Snapshot this state before and after the transition and assert "
                    "the exact delta."
                ),
            })

    model_erc20: list[dict] = []
    if stm_invariant is not None:
        base_markers = {
            json.dumps(item, sort_keys=True, default=str) for item in observations
        }
        model_raw = [
            item
            for item in stm_invariant.get("candidate_observations") or []
            if json.dumps(item, sort_keys=True, default=str) not in base_markers
        ]
        model_entries = _workbench_model_snapshot_entries(
            _workbench_normalize_model_observations(model_raw),
            target_label=label,
            target_address=address,
            assets_known=assets_known,
        )
        observation_calls.extend(model_entries["calls"])
        state_notes.extend(model_entries["state_notes"])
        model_erc20 = model_entries["erc20_balances"]

    if not observation_calls and not state_notes:
        state_notes.append({
            "label": "mutated state",
            "target": label,
            "timing": "before and after",
            "notes": (
                "No safe read calls were supplied. Identify the concrete storage the "
                "transition mutates (account-keyed mappings, counters, status flags, "
                "accumulators) and assert the exact before/after delta."
            ),
        })

    erc20_balances = []
    for token in token_labels[:3]:
        erc20_balances.extend([
            {
                "token_label": token["label"],
                "token": token["address"],
                "account_label": "attacker",
                "account": "<attacker>",
            },
            {
                "token_label": token["label"],
                "token": token["address"],
                "account_label": label,
                "account": address,
            },
        ])
    erc20_balances.extend(model_erc20)

    snapshot_state_templates = {
        "eth_balances": [
            {"label": "attacker native", "address": "<attacker>"},
            {"label": f"{label} native", "address": address},
        ],
        "code_probes": [
            {
                "label": f"{label} code size",
                "address": address,
                "probe": "address.code.length",
                "notes": "Confirm deployed bytecode exists before asserting any transition.",
            },
        ],
        "erc20_balances": erc20_balances,
        "storage_slots": [],
        "calls": observation_calls,
        "state_notes": state_notes,
    }

    objective_templates = [
        {
            "label": "unauthorized or invariant-breaking state transition",
            "match": label,
            "direction": "any",
            "min_delta": "0",
            "unit": "raw",
            "role": "state_transition",
        },
    ]
    if assets_known or value_flow:
        unit = "asset units" if assets_known else "wei"
        objective_templates.append({
            "label": "attacker asset/native balance gain",
            "match": "attacker",
            "direction": "increase",
            "min_delta": "1",
            "unit": unit,
            "role": "profit",
        })
        objective_templates.append({
            "label": "protocol asset/native balance loss",
            "match": label,
            "direction": "decrease",
            "min_delta": "1",
            "unit": unit,
            "role": "protocol_loss",
        })
    if observations:
        objective_templates.append({
            "label": "observed invariant violated",
            "match": "observed state",
            "direction": "any",
            "min_delta": "0",
            "unit": "raw",
            "role": "invariant_check",
        })
    if lock_or_dos:
        objective_templates.append({
            "label": "permanent lock or denial of service",
            "match": label,
            "direction": "any",
            "min_delta": "0",
            "unit": "raw",
            "role": "denial_of_service",
        })

    if stm_invariant is not None:
        statement = str(stm_invariant.get("statement") or "").strip()
        kind = str(stm_invariant.get("kind") or "").strip()
        if statement or kind:
            # The invariant statement drives a concrete, non-trivial objective; it
            # leads the list so a model lens can only annotate, never replace it.
            objective = {
                "label": (
                    f"Falsify invariant: {statement}" if statement
                    else f"Falsify {kind} invariant"
                ),
                "match": label,
                "direction": "any",
                "min_delta": "0",
                "unit": "raw",
                "role": "invariant_falsification",
            }
            inv_id = str(stm_invariant.get("id") or "").strip()
            if inv_id:
                objective["invariant_id"] = inv_id
            if kind:
                objective["kind"] = kind
                note = _STM_KIND_OBJECTIVE_NOTE.get(kind)
                if note:
                    objective["note"] = note
            objective_templates.insert(0, objective)

    blocker_checks = [
        "Define the exact state transition and the invariant it breaks; this "
        "generic harness ships no built-in accounting model, so the objective "
        "assertion must come from the candidate's observations or identified assets.",
    ]
    if not explicit_observations and not assets_known and not value_flow:
        blocker_checks.append(
            "No explicit observations or assets were identified. Add at least one "
            "concrete before/after state assertion (storage slot, account-keyed "
            "mapping, counter, or balance) or the run cannot produce objective evidence."
        )
    blocker_checks.append(
        "Resolve every authorization/precondition gate before claiming the transition "
        "is unauthorized; a transition the live contract permits for the caller is not "
        "a finding."
    )

    result = {
        "mechanism": "generic_state_transition",
        "setup_tasks": setup_tasks,
        "snapshot_state_templates": snapshot_state_templates,
        "objective_templates": objective_templates,
        "blocker_checks": blocker_checks,
    }
    if stm_invariant is not None:
        guidance = _workbench_model_guidance(stm_model_path, stm_invariant)
        lenses = (stm_model or {}).get("lenses")
        if isinstance(lenses, dict) and lenses:
            # Lenses annotate only: the generic invariant objective stays primary.
            guidance["lens_notes"] = [
                "Model lens present (annotation only; the generic invariant "
                f"objective is unchanged): {name}"
                for name in sorted(lenses.keys())
            ]
        if guidance:
            result["model_guidance"] = guidance
    return result


def _fork_workbench_adapter(
    mechanism: str,
    candidate: dict,
    *,
    target: dict,
    fork_context: dict | None,
    stm_context: dict | None = None,
) -> dict:
    if mechanism == "vault":
        return _vault_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
        )
    if mechanism == "lending":
        return _lending_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
        )
    if mechanism == "amm_oracle":
        return _amm_oracle_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
        )
    if mechanism == "bridge":
        return _bridge_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
        )
    if mechanism == "queue_solver":
        return _queue_solver_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
        )
    if mechanism == "staking":
        return _staking_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
        )
    if mechanism == "generic_execution":
        return _generic_execution_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
        )
    if mechanism == "generic_state_transition":
        return _generic_state_transition_workbench_adapter(
            candidate,
            target=target,
            fork_context=fork_context,
            stm_context=stm_context,
        )
    return _generic_state_transition_workbench_adapter(
        candidate,
        target=target,
        fork_context=fork_context,
        stm_context=stm_context,
    )


def _workbench_compose_setup(adapter: dict) -> str:
    setup_tasks = []
    for item in adapter.get("setup_tasks") or []:
        if not isinstance(item, dict):
            continue
        kind = str(item.get("kind") or "setup").strip()
        prompt = str(item.get("prompt") or "").strip()
        if prompt:
            setup_tasks.append(f"{kind}: {prompt}")
    return "\n".join(setup_tasks[:6])


def _workbench_compose_success_condition(adapter: dict) -> str:
    objectives = []
    for item in adapter.get("objective_templates") or []:
        if not isinstance(item, dict):
            continue
        label = str(item.get("label") or "").strip()
        role = str(item.get("role") or "").strip()
        direction = str(item.get("direction") or "").strip()
        if label:
            role_text = f" ({role})" if role else ""
            direction_text = f"; direction={direction}" if direction else ""
            objectives.append(f"- {label}{role_text}{direction_text}")
    if not objectives:
        return ""
    return (
        "Only treat the replay as objective evidence if live before/after "
        "state proves at least one of these measurable objectives:\n"
        + "\n".join(objectives[:6])
    )


def _fork_workbench_readme(payload: dict) -> str:
    setup_lines = "\n".join(
        f"- `{item.get('kind')}`: {item.get('prompt')}"
        for item in payload.get("setup_tasks") or []
    ) or "- none"
    blocker_lines = "\n".join(
        f"- [{item.get('severity', 'info')}] {item.get('kind', 'check')}: {item.get('check')}"
        for item in payload.get("blockers") or []
    ) or "- none"
    objective_lines = "\n".join(
        f"- `{item.get('label')}`: match `{item.get('match')}`, direction `{item.get('direction')}`"
        for item in payload.get("objective_templates") or []
    ) or "- none"
    candidate = payload.get("candidate") or {}
    market_inventory = (candidate.get("market_inventory") or {}) if isinstance(candidate, dict) else {}
    market_lines = "\n".join(
        f"- `{item.get('contract') or 'market'}` at `{item.get('address')}`"
        for item in market_inventory.get("candidate_markets") or []
        if isinstance(item, dict)
    ) or "- none"
    probe_counts = {
        key: len(value or [])
        for key, value in (payload.get("snapshot_state_templates") or {}).items()
    }
    next_args = json.dumps(
        payload.get("compose_sequence_experiment_args") or {},
        indent=2,
        sort_keys=True,
    )
    purpose_note = ""
    if payload.get("mechanism") == "generic_state_transition":
        purpose_note = (
            "\n\nThis is a generic invariant / state-transition harness. It assumes "
            "no specific token, accounting, or balance model: define the exact state "
            "transition under test and the invariant it must not violate, then "
            "snapshot only the concrete state the actions mutate and assert the "
            "precise before/after delta."
        )
    model_guidance = payload.get("model_guidance") or {}
    model_path = (
        payload.get("state_transition_model_path")
        or model_guidance.get("state_transition_model")
    )
    model_section = ""
    if model_guidance:
        falsification = "\n".join(
            f"- {idea}" for idea in model_guidance.get("falsification_ideas") or []
        ) or "- none"
        lens_notes = model_guidance.get("lens_notes") or []
        lens_block = (
            "\n\nLens notes (annotation only):\n"
            + "\n".join(f"- {note}" for note in lens_notes)
            if lens_notes
            else ""
        )
        model_section = (
            "## Model Guidance\n\n"
            f"- Invariant: `{model_guidance.get('invariant_id') or 'n/a'}` "
            f"(kind `{model_guidance.get('kind') or 'n/a'}`)\n"
            f"- Statement: {model_guidance.get('statement') or 'n/a'}\n"
            f"- Model artifact: `{model_path or 'none'}`\n"
            "- Planning context only: prove or reject this invariant with objective "
            "execution evidence (compile, run, before/after deltas).\n\n"
            f"Falsification ideas:\n{falsification}{lens_block}\n\n"
        )
    elif model_path:
        model_section = (
            "## Model Guidance\n\n"
            f"- Model artifact: `{model_path}`\n"
            "- No specific invariant matched this candidate; treat the model as "
            "background planning context and prove any claim with objective "
            "execution evidence.\n\n"
        )
    return f"""# {payload.get('title')}

Workbench id: `{payload.get('id')}`
Mechanism: `{payload.get('mechanism')}`
Attack graph: `{payload.get('attack_graph_path') or 'none'}`
Candidate: `{payload.get('candidate_id') or payload.get('attack_key') or 'manual'}`

## Purpose

Prepare a fork replay that can prove or reject the candidate with concrete setup,
state probes, and objective deltas. This workbench is not vulnerability evidence
until an experiment compiles, runs, and passes objective evaluation.{purpose_note}

## Target

- Label: `{(payload.get('target') or {}).get('label')}`
- Address: `{(payload.get('target') or {}).get('address')}`
- Concrete: `{(payload.get('target') or {}).get('concrete')}`

## Setup Tasks

{setup_lines}

## Blockers

{blocker_lines}

## Snapshot Probe Counts

```json
{json.dumps(probe_counts, indent=2, sort_keys=True)}
```

## Candidate Market Inventory

{market_lines}

## Objective Templates

{objective_lines}

{model_section}## Suggested Sequence Arguments

```json
{next_args}
```
"""


async def _prepare_fork_exploit_workbench(
    container: AuditContainer,
    args: dict,
) -> str:
    try:
        related_ids = [
            str(item) for item in _require_list(args.get("related_ids"), "related_ids")
        ]
        target_overrides = args.get("target_addresses") or {}
        if not isinstance(target_overrides, dict):
            raise ValueError("target_addresses must be an object")
    except ValueError as exc:
        return f"Error: {exc}"

    attack_graph_ref = str(args.get("attack_graph") or "").strip()
    attack_graph_path = ""
    attack_graph = None
    candidate = {}
    if attack_graph_ref:
        try:
            attack_graph_path, attack_graph = await _load_attack_graph(
                container,
                attack_graph_ref,
            )
            candidate = _select_attack_graph_candidate(
                attack_graph,
                str(args.get("candidate_id") or "").strip(),
            )
        except (FileNotFoundError, ValueError) as exc:
            return f"Error: {exc}"
    if not candidate:
        return "Error: prepare_fork_exploit_workbench requires attack_graph"

    # Optional state-transition model. An explicit arg errors on an invalid ref;
    # otherwise fall back to the candidate's own source.state_transition_model
    # (best-effort — that locator is informational, not user-supplied).
    explicit_stm_ref = str(args.get("state_transition_model") or "").strip()
    stm_path = ""
    stm_model = None
    if explicit_stm_ref:
        stm_path, stm_model, stm_error = await _load_state_transition_model_ref(
            container, explicit_stm_ref
        )
        if stm_error:
            return f"Error: {stm_error}"
    else:
        candidate_source = candidate.get("source")
        candidate_stm_ref = (
            str(candidate_source.get("state_transition_model") or "").strip()
            if isinstance(candidate_source, dict)
            else ""
        )
        if candidate_stm_ref:
            stm_path, stm_model, _ = await _load_state_transition_model_ref(
                container, candidate_stm_ref
            )
    stm_invariant = (
        _workbench_select_invariant(candidate, stm_model) if stm_model else None
    )
    stm_prompts = (
        [
            prompt
            for prompt in stm_model.get("experiment_prompts") or []
            if isinstance(prompt, dict)
            and _stm_prompt_matches_invariant(prompt, stm_invariant)
        ]
        if stm_model and stm_invariant
        else []
    )
    stm_context = (
        {
            "model_path": stm_path,
            "model": stm_model,
            "invariant": stm_invariant,
            "experiment_prompts": stm_prompts,
        }
        if stm_model
        else None
    )

    fork_context_ref = str(args.get("fork_context") or "").strip()
    fork_context_path = ""
    fork_context = None
    if fork_context_ref:
        try:
            fork_context_path, fork_context = await _load_fork_context(
                container,
                fork_context_ref,
            )
        except (FileNotFoundError, ValueError) as exc:
            return f"Error: {exc}"
    else:
        fork_context = _attack_candidate_fork_context(
            attack_graph=attack_graph or {},
            candidate=candidate,
            fork_block=args.get("fork_block"),
        ) or None

    target_addresses = _attack_candidate_target_addresses(candidate)
    if fork_context:
        merged = dict(fork_context.get("target_addresses") or {})
        merged.update(target_addresses)
        target_addresses = merged
    target_addresses.update({
        str(key): str(value)
        for key, value in target_overrides.items()
        if str(key).strip() and str(value).strip()
    })

    try:
        mechanism = _infer_fork_workbench_mechanism(
            candidate,
            fork_context,
            str(args.get("mechanism") or "auto"),
        )
    except ValueError as exc:
        return f"Error: {exc}"
    target = _fork_workbench_primary_target(candidate, target_addresses)
    adapter = _fork_workbench_adapter(
        mechanism,
        candidate,
        target=target,
        fork_context=fork_context,
        stm_context=stm_context,
    )
    blockers = [
        *_fork_workbench_base_blockers(
            candidate,
            target=target,
            fork_context=fork_context,
        ),
        *[
            {"kind": "mechanism_check", "severity": "info", "check": str(item)}
            for item in adapter.get("blocker_checks") or []
        ],
    ]
    title = (
        str(args.get("title") or "").strip()
        or f"Fork workbench for {candidate.get('title') or candidate.get('action_key')}"
    )
    candidate_actions = _attack_candidate_actions(candidate)
    candidate_observations = _attack_candidate_observations(candidate)
    compose_args = {
        "title": candidate.get("title") or title,
        "objective": candidate.get("objective") or (
            "Prove or reject the selected attack graph candidate on a fork."
        ),
        "attack_graph": attack_graph_path,
        "candidate_id": (
            candidate.get("candidate_id")
            or candidate.get("attack_key")
            or candidate.get("action_key")
        ),
        "action_space": (
            candidate.get("source", {}).get("action_space")
            if isinstance(candidate.get("source"), dict)
            else ""
        ),
        "protocol_graph": (
            candidate.get("source", {}).get("protocol_graph")
            if isinstance(candidate.get("source"), dict)
            else ""
        ),
        "actions": candidate_actions,
        "observations": candidate_observations,
        "target_addresses": target_addresses,
    }
    setup_prompt = _workbench_compose_setup(adapter)
    if setup_prompt:
        compose_args["setup"] = setup_prompt
    success_condition = _workbench_compose_success_condition(adapter)
    if success_condition:
        compose_args["success_condition"] = success_condition
    if fork_context_path:
        compose_args["fork_context"] = fork_context_path
    if args.get("fork_block") is not None:
        compose_args["fork_block"] = args.get("fork_block")

    model_guidance = adapter.get("model_guidance")
    if model_guidance and stm_invariant is not None:
        statement = str(stm_invariant.get("statement") or "").strip()
        existing_markers = {
            json.dumps(item, sort_keys=True, default=str)
            for item in compose_args["observations"]
        }
        for observation in _workbench_normalize_model_observations(
            stm_invariant.get("candidate_observations")
        ):
            marker = json.dumps(observation, sort_keys=True, default=str)
            if marker in existing_markers:
                continue
            existing_markers.add(marker)
            compose_args["observations"].append(observation)
        # The workbench stays generic unless a protocol mechanism was evidenced;
        # model_guidance is only produced for the generic_state_transition path.
        compose_args["mechanism"] = mechanism
        inv_id = str(stm_invariant.get("id") or "").strip()
        if inv_id:
            compose_args["invariant_id"] = inv_id
        if statement and statement not in str(compose_args.get("objective") or ""):
            base_objective = str(compose_args.get("objective") or "").strip()
            compose_args["objective"] = (
                f"{base_objective} Invariant under test: {statement}".strip()
                if base_objective
                else f"Falsify invariant: {statement}"
            )
    elif stm_model is not None and stm_path:
        # Model loaded but no specific invariant matched: surface the locator
        # without inventing invariant-specific guidance.
        compose_args["state_transition_model"] = stm_path

    state = await _load_campaign_state(container)
    workbench_id = _next_campaign_id(state, "fork_workbench")
    workbench_dir = f"/workspace/campaign/fork-workbenches/{workbench_id}"
    payload = {
        "id": workbench_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "mechanism": mechanism,
        "attack_graph_path": attack_graph_path or None,
        "attack_graph_id": (attack_graph or {}).get("id"),
        "candidate_id": candidate.get("candidate_id"),
        "attack_key": candidate.get("attack_key"),
        "action_key": candidate.get("action_key"),
        "candidate": _attack_graph_materialization(
            attack_graph_path=attack_graph_path,
            attack_graph=attack_graph or {},
            candidate=candidate,
        ),
        "target": target,
        "target_addresses": target_addresses,
        "fork_context_path": fork_context_path or None,
        "fork": _fork_context_metadata(fork_context),
        "setup_tasks": adapter.get("setup_tasks") or [],
        "snapshot_state_templates": adapter.get("snapshot_state_templates") or {},
        "objective_templates": adapter.get("objective_templates") or [],
        "model_guidance": model_guidance or None,
        "state_transition_model_path": stm_path or None,
        "blockers": blockers,
        "compose_sequence_experiment_args": compose_args,
        "next_steps": [
            "Resolve every blocking target/fork/setup item before running.",
            "Use compose_sequence_experiment_args to materialize the runnable sequence scaffold.",
            "Fill concrete calldata, balances, approvals, and protocol-specific objective assertions.",
            "Run the scaffold, summarize trace/logs, snapshot before/after state, compare snapshots, and evaluate objectives.",
        ],
        "related_ids": related_ids,
    }
    workbench_path = f"{workbench_dir}/workbench.json"
    readme_path = f"{workbench_dir}/README.md"
    await container.write_file(
        workbench_path,
        json.dumps(payload, indent=2, sort_keys=True) + "\n",
    )
    await container.write_file(readme_path, _fork_workbench_readme(payload))

    now = datetime.now(timezone.utc).isoformat()
    state["sections"]["experiment"].append({
        "id": workbench_id,
        "created_at": now,
        "updated_at": now,
        "title": title,
        "content": (
            "Template: fork_workbench\n"
            f"Workbench: {workbench_path}\n"
            f"Mechanism: {mechanism}\n"
            f"Attack graph: {attack_graph_path or 'none'}\n"
            f"Candidate: {candidate.get('candidate_id') or candidate.get('attack_key') or candidate.get('action_key')}\n"
            f"Blockers: {len(blockers)}\n"
            "Next: materialize with compose_sequence_experiment after resolving blockers."
        ),
        "status": "open",
        "priority": _attack_search_priority(candidate.get("priority")),
        "evidence": [
            readme_path,
            workbench_path,
            *([attack_graph_path] if attack_graph_path else []),
            *([fork_context_path] if fork_context_path else []),
        ],
        "related_ids": [
            item for item in (
                candidate.get("candidate_id"),
                candidate.get("attack_key"),
                candidate.get("action_key"),
                *(related_ids or []),
            )
            if item
        ],
        "action_keys": [
            str(candidate.get("action_key"))
        ] if candidate.get("action_key") else [],
        "attack_keys": [
            str(candidate.get("attack_key"))
        ] if candidate.get("attack_key") else [],
    })
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Fork exploit workbench: {title}",
            content=(
                f"Fork workbench: {workbench_id}\n"
                f"Path: {workbench_path}\n"
                f"Mechanism: {mechanism}\n"
                f"Candidate: {candidate.get('candidate_id') or candidate.get('attack_key')}\n"
                f"Blockers: {len(blockers)}\n"
                "Use this as executable-fork planning context; it is not a finding."
            ),
            evidence=[workbench_path, readme_path],
            related_ids=[
                item for item in (
                    workbench_id,
                    candidate.get("candidate_id"),
                    candidate.get("attack_key"),
                    candidate.get("action_key"),
                    *related_ids,
                )
                if item
            ],
            status="observed",
        )

    response = {
        "workbench_id": workbench_id,
        "path": workbench_path,
        "readme": readme_path,
        "result_id": result_id or None,
        "mechanism": mechanism,
        "target": target,
        "blockers": blockers[:12],
        "snapshot_probe_counts": {
            key: len(value or [])
            for key, value in payload["snapshot_state_templates"].items()
        },
        "objective_templates": payload["objective_templates"],
        "compose_sequence_experiment_args": compose_args,
        "next_steps": payload["next_steps"],
    }
    if model_guidance:
        response["model_guidance"] = model_guidance
    return json.dumps(response, indent=2, sort_keys=True)


def _coverage_normalize_text(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", " ", value.lower()).strip()


def _coverage_action_key(entry: dict) -> str:
    contract = str(entry.get("contract") or "").strip()
    function = str(entry.get("function") or "").strip()
    return f"{contract}::{function}" if contract else function


def _campaign_decided_action_keys(state: dict) -> set[str]:
    keys = set()
    attack_search = state.get("attack_search") or {}
    for item in attack_search.get("decided_action_keys") or []:
        text = str(item).strip()
        if text:
            keys.add(text)
    for entry in state.get("sections", {}).get("decision", []):
        for item in entry.get("action_keys") or []:
            text = str(item).strip()
            if text:
                keys.add(text)
    return keys


def _coverage_action_type(entry: dict) -> str:
    if entry.get("mutability") in {"view", "pure"}:
        return "observation"
    if "observation" in (entry.get("affordances") or []):
        return "observation"
    return "action"


def _coverage_action_referenced(entry: dict, text: str, normalized: str) -> bool:
    contract = str(entry.get("contract") or "").strip().lower()
    function = str(entry.get("function") or "").strip().lower()
    if not function:
        return False

    exact_variants = []
    if contract:
        exact_variants.extend([
            f"{contract}::{function}",
            f"{contract}.{function}",
            f"{contract} {function}",
        ])
    else:
        exact_variants.append(f"{function}(")
    raw = text.lower()
    if any(variant in raw for variant in exact_variants):
        return True

    normalized_tokens = set(normalized.split())
    function_token = _coverage_normalize_text(function)
    if not function_token or function_token not in normalized_tokens:
        return False
    if not contract:
        return True
    contract_token = _coverage_normalize_text(contract)
    return bool(contract_token and contract_token in normalized_tokens)


async def _coverage_campaign_records(
    container: AuditContainer,
    state: dict,
) -> list[dict]:
    records = []
    evidence_cache: dict[str, str] = {}
    for section, entries in state.get("sections", {}).items():
        for entry in entries:
            text_parts = [
                str(entry.get("id") or ""),
                str(entry.get("title") or ""),
                str(entry.get("content") or ""),
                str(entry.get("status") or ""),
                str(entry.get("priority") or ""),
                " ".join(str(item) for item in entry.get("action_keys") or []),
                " ".join(str(item) for item in entry.get("attack_keys") or []),
                " ".join(_entry_related_ids(entry)),
                " ".join(_entry_evidence(entry)),
            ]
            for evidence in _entry_evidence(entry):
                path = posixpath.normpath(str(evidence))
                if not path.startswith(_COVERAGE_EVIDENCE_PREFIXES):
                    continue
                if path.startswith(_COVERAGE_META_EVIDENCE_PREFIXES):
                    continue
                if path not in evidence_cache:
                    if len(evidence_cache) >= _COVERAGE_EVIDENCE_MAX_FILES:
                        continue
                    try:
                        raw = await container.read_file(path)
                    except FileNotFoundError:
                        raw = ""
                    evidence_cache[path] = raw[:_COVERAGE_EVIDENCE_MAX_CHARS]
                if evidence_cache[path]:
                    text_parts.append(evidence_cache[path])
            text = "\n".join(text_parts)
            records.append({
                "section": section,
                "id": entry.get("id"),
                "title": entry.get("title"),
                "status": entry.get("status"),
                "priority": entry.get("priority"),
                "text": text,
                "normalized": _coverage_normalize_text(text),
            })
    return records


def _coverage_references_for_action(entry: dict, records: list[dict]) -> list[dict]:
    references = []
    seen = set()
    for record in records:
        if not _coverage_action_referenced(
            entry,
            record["text"],
            record["normalized"],
        ):
            continue
        key = (record["section"], record.get("id"))
        if key in seen:
            continue
        seen.add(key)
        references.append({
            "section": record["section"],
            "id": record.get("id"),
            "title": record.get("title"),
            "status": record.get("status"),
            "priority": record.get("priority"),
        })
    return references


def _coverage_level(references: list[dict]) -> str:
    sections = {str(item.get("section") or "") for item in references}
    if "result" in sections:
        return "result_observed"
    if "experiment" in sections:
        return "experiment_planned"
    if "decision" in sections:
        return "decided"
    if "hypothesis" in sections:
        return "hypothesized"
    if sections:
        return "modeled_only"
    return "unexplored"


def _coverage_attention(entry: dict) -> tuple[int, list[str]]:
    weights = {
        # Lexical affordances (`_action_affordances`).
        "value_out_or_burn": 4,
        "credit_or_liquidation": 4,
        "generic_execution": 4,
        "signed_authorization": 4,
        "cross_domain_or_message": 4,
        "valuation_dependency": 3,
        "market_or_router": 3,
        "callback_or_flashloan_surface": 3,
        "external_call": 3,
        "token_or_native_transfer": 2,
        "accepts_native_value": 2,
        "value_in_or_mint": 2,
        "configuration": 1,
        "modifier_gated": 1,
        "sender_or_role_checked": 1,
        # Delexicalized structural affordances
        # (`_structural_action_affordances`). Tuned to surface risky structure in
        # renamed/novel code without swamping the value/external/signed/
        # cross-domain lexical signals above (max structural weight == max lexical
        # weight). `unchecked_external_boundary` and `emits_state_transition_event`
        # stay context-only (weight 0).
        "dynamic_call_target": 4,
        "external_call_with_value": 4,
        "mapping_state_write": 3,
        "aggregate_state_update": 3,
        "external_boundary_crossing": 3,
        "arithmetic_rounding_or_division": 3,
        "authorization_condition": 3,
        "user_claim_or_obligation_update": 3,
        "state_mutating_entrypoint": 2,
        "batch_or_loop_surface": 2,
        "lifecycle_state_change": 2,
    }
    labels = [str(item) for item in entry.get("affordances") or []]
    score = 0
    reasons = []
    for label in labels:
        weight = weights.get(label, 0)
        if not weight:
            continue
        score += weight
        reasons.append(f"{label}+{weight}")
    if _coverage_action_type(entry) == "observation" and not score:
        score = 1
        reasons.append("observation+1")
    return score, reasons


def _coverage_action_summary(entry: dict, references: list[dict]) -> dict:
    score, reasons = _coverage_attention(entry)
    return {
        "key": _coverage_action_key(entry),
        "contract": entry.get("contract"),
        "function": entry.get("function"),
        "type": _coverage_action_type(entry),
        "file": entry.get("file"),
        "line": entry.get("line"),
        "mutability": entry.get("mutability"),
        "modifiers": entry.get("modifiers") or [],
        "affordances": entry.get("affordances") or [],
        "attention_score": score,
        "attention_reasons": reasons,
        "coverage": _coverage_level(references),
        "references": references[:8],
    }


def _coverage_contract_stats(items: list[dict]) -> list[dict]:
    stats: dict[str, dict] = {}
    for item in items:
        contract = str(item.get("contract") or "unknown")
        contract_stats = stats.setdefault(contract, {
            "contract": contract,
            "total": 0,
            "with_hypothesis": 0,
            "with_experiment": 0,
            "with_result": 0,
            "decided": 0,
            "open_gaps": 0,
            "high_attention_gaps": 0,
        })
        contract_stats["total"] += 1
        coverage = item["coverage"]
        if coverage == "hypothesized":
            contract_stats["with_hypothesis"] += 1
        elif coverage == "experiment_planned":
            contract_stats["with_experiment"] += 1
        elif coverage == "result_observed":
            contract_stats["with_result"] += 1
        elif coverage == "decided":
            contract_stats["decided"] += 1
        if item.get("is_open_gap"):
            contract_stats["open_gaps"] += 1
        if item.get("is_high_attention_gap"):
            contract_stats["high_attention_gaps"] += 1
    return sorted(
        stats.values(),
        key=lambda item: (
            -item["high_attention_gaps"],
            -item["open_gaps"],
            item["contract"],
        ),
    )


def _coverage_affordance_stats(items: list[dict]) -> list[dict]:
    stats: dict[str, dict] = {}
    for item in items:
        labels = item.get("affordances") or ["unlabeled"]
        for label in labels:
            label_stats = stats.setdefault(label, {
                "affordance": label,
                "total": 0,
                "open_gaps": 0,
                "high_attention_gaps": 0,
                "with_experiment_or_result": 0,
            })
            label_stats["total"] += 1
            if item.get("is_open_gap"):
                label_stats["open_gaps"] += 1
            if item.get("is_high_attention_gap"):
                label_stats["high_attention_gaps"] += 1
            if item["coverage"] in {"experiment_planned", "result_observed"}:
                label_stats["with_experiment_or_result"] += 1
    return sorted(
        stats.values(),
        key=lambda item: (
            -item["high_attention_gaps"],
            -item["open_gaps"],
            -item["total"],
            item["affordance"],
        ),
    )


def _coverage_next_actions(review: dict) -> list[str]:
    actions = []
    if review["high_attention_gaps"]:
        actions.append(
            "Pick one high-attention uncovered lever, state the invariant it might falsify, then compose a sequence or invariant experiment."
        )
    if review["hypothesized_not_experimented"]:
        actions.append(
            "Turn hypothesized-but-unexperimented levers into concrete PoCs or reject them with a decision."
        )
    if review["open_gaps"] and not review["high_attention_gaps"]:
        actions.append(
            "Use the open gaps as prompts for the next LLM-chosen action grammar; prioritize by value flow and reachable attacker control."
        )
    if not actions:
        actions.append(
            "No major coverage gaps found in this action space; map another subsystem or deepen parameter/order exploration."
        )
    return actions


async def _review_attack_surface_coverage(
    container: AuditContainer,
    args: dict,
) -> str:
    try:
        action_space_path, action_space = await _load_action_space(
            container,
            str(args.get("action_space") or ""),
        )
        focus_contracts = {
            str(item).strip().lower()
            for item in _require_list(args.get("focus_contracts"), "focus_contracts")
            if str(item).strip()
        }
        affordance_filter = {
            str(item).strip()
            for item in _require_list(args.get("affordance_filter"), "affordance_filter")
            if str(item).strip()
        }
    except (FileNotFoundError, ValueError) as exc:
        return f"Error: {exc}"

    max_items = min(max(int(args.get("max_items", 25)), 1), 100)
    threshold = max(int(args.get("attention_threshold", 3)), 0)
    include_observations = bool(args.get("include_observations", False))
    state = await _load_campaign_state(container)
    records = await _coverage_campaign_records(container, state)
    decided_action_keys = _campaign_decided_action_keys(state)

    candidate_entries = list(action_space.get("actions") or [])
    if include_observations:
        candidate_entries.extend(action_space.get("observations") or [])

    skipped = {
        "focus_contracts": 0,
        "affordance_filter": 0,
    }
    reviewed = []
    for entry in candidate_entries:
        contract = str(entry.get("contract") or "").strip().lower()
        affordances = {str(item) for item in entry.get("affordances") or []}
        if focus_contracts and contract not in focus_contracts:
            skipped["focus_contracts"] += 1
            continue
        if affordance_filter and not affordances.intersection(affordance_filter):
            skipped["affordance_filter"] += 1
            continue
        references = _coverage_references_for_action(entry, records)
        summary = _coverage_action_summary(entry, references)
        action_key = str(summary.get("key") or "")
        if action_key in decided_action_keys:
            references = [
                *references,
                {
                    "section": "decision",
                    "id": "decided_action_key",
                    "title": f"Decision recorded for {action_key}",
                    "status": "observed",
                    "priority": None,
                },
            ]
            summary = _coverage_action_summary(entry, references)
        sections = {str(item.get("section") or "") for item in references}
        summary["is_open_gap"] = not sections.intersection({
            "experiment",
            "result",
            "decision",
        })
        summary["is_hypothesized_not_experimented"] = (
            "hypothesis" in sections
            and not sections.intersection({"experiment", "result", "decision"})
        )
        summary["is_high_attention_gap"] = (
            summary["is_open_gap"]
            and summary["attention_score"] >= threshold
        )
        reviewed.append(summary)

    reviewed.sort(key=lambda item: (
        not item["is_high_attention_gap"],
        not item["is_open_gap"],
        -item["attention_score"],
        str(item.get("contract") or ""),
        str(item.get("function") or ""),
    ))
    open_gaps = [item for item in reviewed if item["is_open_gap"]]
    high_attention_gaps = [
        item for item in reviewed if item["is_high_attention_gap"]
    ]
    hypothesized_not_experimented = [
        item for item in reviewed if item["is_hypothesized_not_experimented"]
    ]
    covered = [
        item for item in reviewed
        if item["coverage"] in {"experiment_planned", "result_observed", "decided"}
    ]

    review_id = _next_campaign_id(state, "coverage_review")
    title = str(args.get("title") or "Attack surface coverage review").strip()
    review = {
        "id": review_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "action_space": action_space.get("id"),
        "action_space_path": action_space_path,
        "filters": {
            "focus_contracts": sorted(focus_contracts),
            "affordance_filter": sorted(affordance_filter),
            "include_observations": include_observations,
            "attention_threshold": threshold,
        },
        "source_summary": action_space.get("summary") or {},
        "summary": {
            "reviewed": len(reviewed),
            "covered": len(covered),
            "open_gaps": len(open_gaps),
            "high_attention_gaps": len(high_attention_gaps),
            "hypothesized_not_experimented": len(hypothesized_not_experimented),
            "skipped": skipped,
        },
        "contract_coverage": _coverage_contract_stats(reviewed)[:max_items],
        "affordance_coverage": _coverage_affordance_stats(reviewed)[:max_items],
        "high_attention_gaps": high_attention_gaps[:max_items],
        "hypothesized_not_experimented": hypothesized_not_experimented[:max_items],
        "open_gaps": open_gaps[:max_items],
        "covered_actions": covered[:max_items],
    }
    review["next_actions"] = _coverage_next_actions(review)

    review_path = f"/workspace/campaign/coverage-reviews/{review_id}.json"
    await container.write_file(
        review_path,
        json.dumps(review, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        action_space_id = str(action_space.get("id") or "")
        result_id = await _record_result_artifact(
            container,
            title=f"Attack-surface coverage review: {title}",
            content=(
                f"Coverage review: {review_id}\n"
                f"Path: {review_path}\n"
                f"Action space: {action_space.get('id')} ({action_space_path})\n"
                f"Reviewed actions: {review['summary']['reviewed']}\n"
                f"Open gaps: {review['summary']['open_gaps']}\n"
                f"High-attention gaps: {review['summary']['high_attention_gaps']}\n"
                "Use these gaps to choose the next protocol-specific action "
                "grammar; do not treat them as findings."
            ),
            evidence=[review_path, action_space_path],
            related_ids=[action_space_id] if action_space_id else [],
            status="observed",
        )

    response = {
        "coverage_review_id": review_id,
        "path": review_path,
        "result_id": result_id or None,
        "summary": review["summary"],
        "next_actions": review["next_actions"],
        "high_attention_gaps": review["high_attention_gaps"],
        "hypothesized_not_experimented": review["hypothesized_not_experimented"],
        "contract_coverage": review["contract_coverage"],
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _campaign_artifact_path(
    identifier: str,
    *,
    directory: str,
    prefix: str,
    name: str,
) -> str:
    value = identifier.strip()
    if not value:
        raise ValueError(f"{name} cannot be empty")
    if value.startswith("/"):
        normalized = posixpath.normpath(value)
        if not normalized.startswith(directory):
            raise ValueError(f"absolute {name} paths must be under {directory}")
        return normalized
    if not re.match(rf"^{re.escape(prefix)}-\d{{3,}}$", value):
        raise ValueError(f"{name} must be an id like {prefix}-001 or an absolute path")
    return f"{directory}{value}.json"


async def _load_campaign_artifact(
    container: AuditContainer,
    path: str,
) -> dict | None:
    try:
        raw = await container.read_file(path)
    except FileNotFoundError:
        return None
    try:
        return json.loads(raw)
    except json.JSONDecodeError:
        return None


async def _load_plan_artifacts(
    container: AuditContainer,
    state: dict,
    *,
    explicit: str,
    directory: str,
    id_prefix: str,
    name: str,
) -> list[dict]:
    paths = []
    if explicit:
        paths.append(_campaign_artifact_path(
            explicit,
            directory=directory,
            prefix=id_prefix,
            name=name,
        ))
    for path in _progress_evidence_paths(state, directory):
        if path not in paths:
            paths.append(path)

    artifacts = []
    for path in paths:
        payload = await _load_campaign_artifact(container, path)
        if payload:
            artifacts.append({"path": path, "payload": payload})
    artifacts.sort(
        key=lambda item: str(item["payload"].get("created_at") or ""),
        reverse=True,
    )
    return artifacts


async def _load_plan_action_spaces(
    container: AuditContainer,
    state: dict,
    explicit: str,
) -> list[dict]:
    paths = []
    if explicit:
        paths.append(_action_space_path(explicit))
    for path in _progress_evidence_paths(
        state,
        "/workspace/campaign/action-spaces/",
    ):
        if path not in paths:
            paths.append(path)

    artifacts = []
    for path in paths:
        payload = await _load_campaign_artifact(container, path)
        if payload:
            artifacts.append({"path": path, "payload": payload})
    artifacts.sort(
        key=lambda item: str(item["payload"].get("created_at") or ""),
        reverse=True,
    )
    return artifacts


def _plan_priority(score: int) -> str:
    if score >= 10:
        return "critical"
    if score >= 7:
        return "high"
    if score >= 4:
        return "medium"
    return "low"


def _plan_priority_score(priority: str | None) -> int:
    return {
        "critical": 10,
        "high": 8,
        "medium": 5,
        "low": 2,
    }.get(str(priority or "").lower(), 4)


def _plan_focus_bonus(focus: str, *values: object) -> int:
    terms = set(_coverage_normalize_text(focus).split())
    if not terms:
        return 0
    haystack = _coverage_normalize_text(" ".join(str(value) for value in values))
    if not haystack:
        return 0
    return 2 if any(term in haystack for term in terms) else 0


def _plan_decimal_value(value: object) -> Decimal | None:
    if value is None:
        return None
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError):
        return None


def _plan_int_value(value: object) -> int:
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _plan_economics_kind(payload: dict) -> str:
    if isinstance(payload.get("positions"), list):
        return "lending_health"
    if isinstance(payload.get("legs"), list):
        return "amm"
    if isinstance(payload.get("assets"), list):
        return "flash_loan"
    title = _coverage_normalize_text(
        f"{payload.get('title', '')} {payload.get('assumption', '')}"
    )
    if "lending" in title or "health factor" in title or "liquidation" in title:
        return "lending_health"
    if "flash loan" in title:
        return "flash_loan"
    if "amm" in title or "swap" in title or "price impact" in title:
        return "amm"
    return "unknown"


def _plan_economics_artifact_summary(artifact: dict, kind: str) -> dict:
    payload = artifact.get("payload") or {}
    return {
        "kind": kind,
        "id": payload.get("id"),
        "path": artifact.get("path"),
        "title": payload.get("title"),
        "summary": payload.get("summary") or {},
    }


def _plan_economics_context(artifacts: list[dict], state: dict) -> dict:
    counters = state.get("counters", {})
    context = {
        "artifact_count": len(artifacts),
        "has_any": bool(
            artifacts
            or int(counters.get("economics", 0) or 0)
            or int(counters.get("flash_loan", 0) or 0)
        ),
        "has_market_economics": False,
        "has_lending_health": False,
        "has_flash_loan": False,
        "counts": {
            "amm": 0,
            "flash_loan": 0,
            "lending_health": 0,
            "unknown": 0,
        },
        "amm": {
            "artifacts": [],
            "price_move_artifacts": [],
            "max_abs_price_change_bps": "0",
            "max_slippage_bps": "0",
            "total_capital_usd": None,
        },
        "flash_loan": {
            "artifacts": [],
            "insufficient_liquidity": 0,
            "unknown_liquidity": 0,
            "total_borrow_usd": "0",
            "total_fee_usd": "0",
            "liquidity_blocked_artifacts": [],
        },
        "lending_health": {
            "artifacts": [],
            "liquidatable_positions": 0,
            "total_shortfall_usd": "0",
            "min_health_factor": None,
            "risky_artifacts": [],
        },
    }

    total_shortfall = Decimal(0)
    min_health_factor: Decimal | None = None
    max_amm_price_move = Decimal(0)
    max_amm_slippage = Decimal(0)
    total_amm_capital = Decimal(0)
    any_amm_capital = False
    total_flash_borrow = Decimal(0)
    total_flash_fee = Decimal(0)
    for artifact in artifacts:
        payload = artifact.get("payload") or {}
        kind = _plan_economics_kind(payload)
        if kind not in context["counts"]:
            kind = "unknown"
        context["counts"][kind] += 1
        summary = _plan_economics_artifact_summary(artifact, kind)
        if kind == "amm":
            amm = context["amm"]
            artifact_has_price_move = False
            for leg in payload.get("legs") or []:
                if not isinstance(leg, dict):
                    continue
                price_move = _plan_decimal_value(leg.get("price_change_bps"))
                if price_move is not None:
                    abs_price_move = abs(price_move)
                    if abs_price_move > max_amm_price_move:
                        max_amm_price_move = abs_price_move
                    if abs_price_move > 0:
                        artifact_has_price_move = True
                slippage = _plan_decimal_value(leg.get("slippage_bps"))
                if slippage is not None and slippage > max_amm_slippage:
                    max_amm_slippage = slippage
                capital = _plan_decimal_value(leg.get("capital_usd"))
                if capital is not None:
                    any_amm_capital = True
                    total_amm_capital += capital
            amm["artifacts"].append(summary)
            if artifact_has_price_move:
                amm["price_move_artifacts"].append(summary)
            continue
        if kind == "flash_loan":
            flash = context["flash_loan"]
            artifact_summary = payload.get("summary") or {}
            insufficient = _plan_int_value(
                artifact_summary.get("insufficient_liquidity")
            )
            unknown = _plan_int_value(artifact_summary.get("unknown_liquidity"))
            borrow = _plan_decimal_value(artifact_summary.get("total_borrow_usd"))
            fee = _plan_decimal_value(artifact_summary.get("total_fee_usd"))
            if borrow is not None:
                total_flash_borrow += borrow
            if fee is not None:
                total_flash_fee += fee
            flash["insufficient_liquidity"] += insufficient
            flash["unknown_liquidity"] += unknown
            flash["artifacts"].append(summary)
            if insufficient > 0:
                flash["liquidity_blocked_artifacts"].append(summary)
            continue
        if kind != "lending_health":
            continue

        lending = context["lending_health"]
        artifact_summary = payload.get("summary") or {}
        liquidatable = _plan_int_value(
            artifact_summary.get("liquidatable_positions")
        )
        shortfall = _plan_decimal_value(artifact_summary.get("total_shortfall_usd"))
        health_factor = _plan_decimal_value(artifact_summary.get("min_health_factor"))
        if shortfall is not None:
            total_shortfall += shortfall
        if health_factor is not None and (
            min_health_factor is None or health_factor < min_health_factor
        ):
            min_health_factor = health_factor
        lending["liquidatable_positions"] += liquidatable
        lending["artifacts"].append(summary)
        risky = liquidatable > 0 or (shortfall is not None and shortfall > 0)
        if risky:
            lending["risky_artifacts"].append(summary)

    context["has_market_economics"] = bool(
        context["counts"]["amm"]
        or (not artifacts and int(counters.get("economics", 0) or 0))
    )
    context["amm"]["max_abs_price_change_bps"] = _decimal_string(
        max_amm_price_move
    )
    context["amm"]["max_slippage_bps"] = _decimal_string(max_amm_slippage)
    context["amm"]["total_capital_usd"] = (
        _decimal_string(total_amm_capital) if any_amm_capital else None
    )
    context["has_lending_health"] = bool(context["counts"]["lending_health"])
    context["has_flash_loan"] = bool(
        context["counts"]["flash_loan"]
        or (not artifacts and int(counters.get("flash_loan", 0) or 0))
    )
    context["flash_loan"]["total_borrow_usd"] = _decimal_string(
        total_flash_borrow
    )
    context["flash_loan"]["total_fee_usd"] = _decimal_string(total_flash_fee)
    context["lending_health"]["total_shortfall_usd"] = _decimal_string(
        total_shortfall
    )
    context["lending_health"]["min_health_factor"] = (
        _decimal_string(min_health_factor)
        if min_health_factor is not None
        else None
    )
    return context


def _plan_economics_bonus(
    affordances: list[str],
    economics_context: dict | None,
) -> int:
    labels = set(affordances)
    if not economics_context:
        return 0
    score = 0
    if (
        labels.intersection({"credit_or_liquidation"})
        and economics_context.get("has_lending_health")
    ):
        lending = economics_context.get("lending_health") or {}
        score += 1
        if _plan_int_value(lending.get("liquidatable_positions")) > 0:
            score += 3
        shortfall = _plan_decimal_value(lending.get("total_shortfall_usd"))
        if shortfall is not None and shortfall > 0:
            score += 2
        health_factor = _plan_decimal_value(lending.get("min_health_factor"))
        if health_factor is not None and health_factor <= Decimal("1"):
            score += 1
    if labels.intersection({"callback_or_flashloan_surface"}):
        flash = economics_context.get("flash_loan") or {}
        if economics_context.get("has_flash_loan") and not _plan_int_value(
            flash.get("insufficient_liquidity")
        ):
            score += 1
    if (
        labels.intersection({"valuation_dependency", "market_or_router"})
        and economics_context.get("has_market_economics")
    ):
        amm = economics_context.get("amm") or {}
        price_move = _plan_decimal_value(amm.get("max_abs_price_change_bps"))
        if price_move is not None and price_move > 0:
            score += 1
    return min(score, 6)


def _plan_relevant_economics_artifacts(
    affordances: list[str],
    economics_context: dict | None,
) -> list[dict]:
    if not economics_context:
        return []
    labels = set(affordances)
    if labels.intersection({"credit_or_liquidation"}):
        lending = economics_context.get("lending_health") or {}
        artifacts = lending.get("risky_artifacts") or lending.get("artifacts") or []
        flash = economics_context.get("flash_loan") or {}
        artifacts = [
            *artifacts,
            *(flash.get("artifacts") or []),
        ]
        return artifacts[:4]
    if labels.intersection({"callback_or_flashloan_surface"}):
        flash = economics_context.get("flash_loan") or {}
        artifacts = (
            flash.get("liquidity_blocked_artifacts")
            or flash.get("artifacts")
            or []
        )
        return artifacts[:3]
    if labels.intersection({"valuation_dependency", "market_or_router"}):
        amm = economics_context.get("amm") or {}
        artifacts = amm.get("price_move_artifacts") or amm.get("artifacts") or []
        return artifacts[:3]
    return []


def _plan_branch_economics_context(
    affordances: list[str],
    economics_context: dict | None,
) -> dict | None:
    if not economics_context:
        return None
    labels = set(affordances)
    if labels.intersection({"credit_or_liquidation"}):
        lending = (economics_context or {}).get("lending_health") or {}
        artifacts = lending.get("risky_artifacts") or lending.get("artifacts") or []
        if not artifacts:
            return None
        return {
            "kind": "lending_health",
            "liquidatable_positions": lending.get("liquidatable_positions", 0),
            "total_shortfall_usd": lending.get("total_shortfall_usd"),
            "min_health_factor": lending.get("min_health_factor"),
            "artifacts": artifacts[:3],
        }
    if labels.intersection({"callback_or_flashloan_surface"}):
        flash = economics_context.get("flash_loan") or {}
        artifacts = (
            flash.get("liquidity_blocked_artifacts")
            or flash.get("artifacts")
            or []
        )
        if not artifacts:
            return None
        return {
            "kind": "flash_loan",
            "insufficient_liquidity": flash.get("insufficient_liquidity", 0),
            "unknown_liquidity": flash.get("unknown_liquidity", 0),
            "total_borrow_usd": flash.get("total_borrow_usd"),
            "total_fee_usd": flash.get("total_fee_usd"),
            "artifacts": artifacts[:3],
        }
    artifacts = _plan_relevant_economics_artifacts(affordances, economics_context)
    if not artifacts:
        return None
    amm = economics_context.get("amm") or {}
    return {
        "kind": "amm",
        "max_abs_price_change_bps": amm.get("max_abs_price_change_bps"),
        "max_slippage_bps": amm.get("max_slippage_bps"),
        "total_capital_usd": amm.get("total_capital_usd"),
        "artifacts": artifacts,
    }


def _plan_flash_loan_context(
    affordances: list[str],
    economics_context: dict | None,
) -> dict | None:
    if not economics_context:
        return None
    labels = set(affordances)
    if not labels.intersection({
        "callback_or_flashloan_surface",
        "credit_or_liquidation",
    }):
        return None
    if not economics_context.get("has_flash_loan"):
        return None
    flash = economics_context.get("flash_loan") or {}
    return {
        "kind": "flash_loan",
        "insufficient_liquidity": flash.get("insufficient_liquidity", 0),
        "unknown_liquidity": flash.get("unknown_liquidity", 0),
        "total_borrow_usd": flash.get("total_borrow_usd"),
        "total_fee_usd": flash.get("total_fee_usd"),
        "artifacts": (flash.get("artifacts") or [])[:3],
    }


def _plan_oracle_window_checks(affordances: list[str]) -> list[str]:
    labels = set(affordances)
    if not labels.intersection({"valuation_dependency"}):
        return []
    return [
        "identify the exact feed, adapter, or pool observation read by the target",
        "record answer, decimals, updatedAt/timestamp, and observation window before manipulation",
        "record heartbeat, deviation threshold, update authority, cache, and stale-data rules when available",
        "test spot, stale, and window-boundary variants on a fixed fork block before changing branches",
    ]


def _plan_flash_loan_checks(affordances: list[str]) -> list[str]:
    labels = set(affordances)
    if not labels.intersection({
        "callback_or_flashloan_surface",
        "credit_or_liquidation",
    }):
        return []
    return [
        "identify flash-loan provider, asset, amount, premium, max liquidity, callback, and repayment path",
        "run estimate_flash_loan if borrowed capital or flash callback reachability is part of this branch",
        "prove the callback cannot move protected state before repayment unless that is the intended invariant",
        "snapshot borrowed funds, fees, approvals, repayment, and post-unwind attacker balance",
    ]


def _plan_liquidation_route_checks(affordances: list[str]) -> list[str]:
    labels = set(affordances)
    if not labels.intersection({"credit_or_liquidation"}):
        return []
    return [
        "identify close factor, repay asset, seized collateral, liquidation bonus, protocol fee, and caps",
        "model the liquidator's capital source, approvals, callback path, and seized-collateral unwind route",
        "snapshot borrower collateral/debt, liquidator balances, reserves, and bad-debt accounting before and after",
        "test just-above and just-below-threshold positions plus dust, rounding, max-close, and isolation-mode cases",
    ]


def _plan_attach_branch_context(
    branch: dict,
    affordances: list[str],
    economics_context: dict | None,
) -> dict:
    branch_context = _plan_branch_economics_context(
        affordances,
        economics_context,
    )
    if branch_context:
        branch["economics_context"] = branch_context
    oracle_checks = _plan_oracle_window_checks(affordances)
    if oracle_checks:
        branch["oracle_window_checks"] = oracle_checks
    liquidation_checks = _plan_liquidation_route_checks(affordances)
    if liquidation_checks:
        branch["liquidation_route_checks"] = liquidation_checks
    flash_checks = _plan_flash_loan_checks(affordances)
    if flash_checks:
        branch["flash_loan_checks"] = flash_checks
    flash_context = _plan_flash_loan_context(affordances, economics_context)
    if flash_context:
        branch["flash_loan_context"] = flash_context
    return branch


def _plan_invariant_prompt(affordances: list[str], action_key: str) -> str:
    labels = set(affordances)
    if labels.intersection({"value_out_or_burn", "token_or_native_transfer"}):
        return f"{action_key} must not release more value than the actor is entitled to receive."
    if labels.intersection({"credit_or_liquidation"}):
        return f"{action_key} must not create bad debt, excess collateral value, or unfair liquidation outcomes."
    if labels.intersection({"valuation_dependency", "market_or_router"}):
        return f"{action_key} must not let attacker-controlled market state distort protocol valuation for profit."
    if labels.intersection({"generic_execution", "external_call", "delegatecall"}):
        return f"{action_key} must not route execution or callbacks into unauthorized value movement."
    if labels.intersection({"signed_authorization", "signature_gate", "signature_input"}):
        return f"{action_key} must commit authorization to every execution-critical field."
    if labels.intersection({"cross_domain_or_message"}):
        return f"{action_key} must not release or mint value without a valid source-domain state transition."
    return f"{action_key} must preserve the protocol's stated solvency and authorization invariants."


def _plan_experiment_shape(affordances: list[str]) -> str:
    labels = set(affordances)
    if labels.intersection({"valuation_dependency", "market_or_router", "credit_or_liquidation"}):
        return "fork-aware sequence experiment with state snapshots"
    if labels.intersection({"generic_execution", "external_call", "callback_or_flashloan_surface", "delegatecall"}):
        return "multi-actor sequence experiment with malicious counterparty or callback"
    if labels.intersection({"value_out_or_burn", "value_in_or_mint", "token_or_native_transfer"}):
        return "sequence experiment with before/after balance and accounting probes"
    if labels.intersection({"signed_authorization", "signature_gate", "signature_input", "cross_domain_or_message"}):
        return "sequence experiment with replay/parameter-binding checks"
    return "small sequence or invariant experiment chosen by the LLM"


def _plan_next_tool(affordances: list[str], *, source: str) -> str:
    labels = set(affordances)
    if source == "action_space_without_coverage":
        return "review_attack_surface_coverage"
    if source == "failed_evaluation":
        return "mutate_hypothesis"
    if source == "experiment_without_result":
        return "run_experiment"
    if labels.intersection({"callback_or_flashloan_surface", "credit_or_liquidation"}):
        return "compose_invariant_harness with handler actions or compose_sequence_experiment with explicit actions"
    return "compose_sequence_experiment with explicit actions or compose_invariant_harness with handler actions"


def _plan_required_setup(
    affordances: list[str],
    economics_context: dict | None = None,
) -> list[str]:
    labels = set(affordances)
    setup = [
        "state the exact actor, target contract, and starting balances",
        "bind the target addresses or mocks needed by the harness",
    ]
    if labels.intersection({"valuation_dependency", "market_or_router"}):
        setup.append("record fork context and pool/oracle state before testing")
        setup.append("estimate AMM economics for any price-moving step")
    setup.extend(_plan_oracle_window_checks(affordances)[:2])
    if labels.intersection({"credit_or_liquidation"}):
        setup.append("model collateral, debt, health factor, and liquidation thresholds")
        if economics_context and economics_context.get("has_lending_health"):
            setup.append(
                "review linked lending health estimate and choose fork states "
                "that cross the liquidation or bad-debt threshold"
            )
        else:
            setup.append(
                "run estimate_lending_health with explicit collateral, debt, "
                "threshold, and price-shift assumptions"
            )
        setup.extend(_plan_liquidation_route_checks(affordances)[:2])
    if labels.intersection({"callback_or_flashloan_surface"}):
        if economics_context and economics_context.get("has_flash_loan"):
            setup.append(
                "review linked flash-loan estimate and validate callback plus "
                "repayment behavior on fork"
            )
        else:
            setup.append(
                "run estimate_flash_loan if borrowed capital or flash callback "
                "reachability is part of the branch"
            )
    setup.extend(_plan_flash_loan_checks(affordances)[:1])
    if labels.intersection({"generic_execution", "external_call", "callback_or_flashloan_surface"}):
        setup.append("add attacker-controlled callee/callback behavior")
    if labels.intersection({"signed_authorization", "signature_gate", "signature_input"}):
        setup.append("construct valid and mutated authorization payloads")
    if labels.intersection({"cross_domain_or_message"}):
        setup.append("model the source-domain commitment and replay/mismatch cases")
    return setup


def _plan_evidence_needed(affordances: list[str]) -> list[str]:
    labels = set(affordances)
    evidence = [
        "run_experiment output linked to the hypothesis and experiment",
        "before/after snapshot_state and compare_snapshots for the invariant",
        "evaluate_objective for profit, loss, debt, shares, or authorization outcome",
        "summarize_trace or extract_call_sequence if the run emits a verbose trace",
    ]
    if labels.intersection({"valuation_dependency", "market_or_router"}):
        evidence.append("AMM/oracle liquidity and price-impact assumptions")
    if labels.intersection({"valuation_dependency"}):
        evidence.append(
            "oracle answer/freshness/window snapshots before and after manipulation"
        )
    if labels.intersection({"credit_or_liquidation"}):
        evidence.append(
            "lending health estimate plus fork-validated collateral, debt, "
            "health-factor, and liquidation-route deltas"
        )
    if labels.intersection({"callback_or_flashloan_surface"}):
        evidence.append(
            "flash-loan liquidity, fee, callback, repayment, and post-unwind balance evidence"
        )
    if labels.intersection({"generic_execution", "external_call", "callback_or_flashloan_surface"}):
        evidence.append("trace proof of the external call/callback path")
    return evidence


def _plan_blockers(
    affordances: list[str],
    *,
    state: dict,
    has_fork_context: bool,
    has_economics: bool,
    economics_context: dict | None = None,
) -> list[str]:
    labels = set(affordances)
    blockers = []
    if not state["sections"].get("invariant"):
        blockers.append("missing invariant artifact")
    if not state["sections"].get("value_flow"):
        blockers.append("missing value-flow artifact")
    if labels.intersection({"valuation_dependency", "market_or_router", "credit_or_liquidation"}) and not has_fork_context:
        blockers.append("missing fork context for market/oracle-dependent branch")
    has_market_economics = (
        economics_context.get("has_market_economics")
        if economics_context
        else has_economics
    )
    if labels.intersection({"valuation_dependency", "market_or_router"}) and not has_market_economics:
        blockers.append("missing AMM/economics estimate for price-moving branch")
    if labels.intersection({"credit_or_liquidation"}) and not (
        economics_context and economics_context.get("has_lending_health")
    ):
        blockers.append("missing lending health estimate for credit/liquidation branch")
    if labels.intersection({"callback_or_flashloan_surface"}):
        flash = (economics_context or {}).get("flash_loan") or {}
        if _plan_int_value(flash.get("insufficient_liquidity")):
            blockers.append(
                "linked flash-loan estimate has insufficient liquidity; adjust amount or provider"
            )
    return blockers


def _plan_stop_or_mutate(affordances: list[str]) -> str:
    labels = set(affordances)
    if labels.intersection({"valuation_dependency", "market_or_router"}):
        return "If the price move is uneconomic or ignored by the protocol, mutate toward oracle cadence, alternate markets, stale data, or route assumptions."
    if labels.intersection({"generic_execution", "external_call", "callback_or_flashloan_surface"}):
        return "If callbacks cannot affect protected state, mutate toward ordering, reentry timing, or attacker-controlled dependency assumptions."
    if labels.intersection({"value_out_or_burn", "token_or_native_transfer"}):
        return "If balances remain proportional, mutate toward rounding, donation, fee-on-transfer, share accounting, or multi-actor ordering assumptions."
    if labels.intersection({"credit_or_liquidation"}):
        return "If no bad debt or unfair liquidation appears, mutate toward collateral valuation, timing, rounding, or liquidation incentive assumptions."
    return "If the objective does not move, record the failed assumption and mutate to the nearest untested invariant or reject with a decision."


def _plan_branch_from_action_gap(
    item: dict,
    *,
    source: str,
    source_path: str,
    focus: str,
    state: dict,
    has_fork_context: bool,
    has_economics: bool,
    economics_context: dict | None,
    base_score: int,
    decided_action_keys: set[str] | None = None,
) -> dict | None:
    affordances = [str(label) for label in item.get("affordances") or []]
    action_key = str(item.get("key") or _coverage_action_key(item))
    # Skip levers the agent already decided on (rejected/blocked/objective-failed/
    # superseded) so the planner does not regenerate resolved branches each call.
    if action_key and decided_action_keys and action_key in decided_action_keys:
        return None
    relevant_economics = _plan_relevant_economics_artifacts(
        affordances,
        economics_context,
    )
    score = (
        base_score
        + int(item.get("attention_score", 0) or 0)
        + _plan_focus_bonus(focus, action_key, affordances)
        + _plan_economics_bonus(affordances, economics_context)
    )
    branch = {
        "_dedupe_key": f"action:{action_key}",
        "source": source,
        "source_artifacts": [
            source_path,
            *[
                str(artifact.get("path"))
                for artifact in relevant_economics
                if artifact.get("path")
            ],
        ],
        "source_ids": [
            ref.get("id") for ref in item.get("references", [])
            if ref.get("id")
        ] + [
            artifact.get("id")
            for artifact in relevant_economics
            if artifact.get("id")
        ],
        "title": f"Test {action_key} as an attacker-controlled lever",
        "priority_score": score,
        "target_actions": [{
            "key": action_key,
            "contract": item.get("contract"),
            "function": item.get("function"),
            "file": item.get("file"),
            "line": item.get("line"),
            "affordances": affordances,
            "coverage": item.get("coverage"),
        }],
        "hypothesis_prompt": (
            f"Can an unprivileged actor combine {action_key} with setup, "
            "ordering, external state, or repeated calls to falsify the "
            "selected invariant?"
        ),
        "candidate_invariant": _plan_invariant_prompt(affordances, action_key),
        "experiment_shape": _plan_experiment_shape(affordances),
        "recommended_next_tool": _plan_next_tool(affordances, source=source),
        "required_setup": _plan_required_setup(
            affordances,
            economics_context=economics_context,
        ),
        "evidence_to_capture": _plan_evidence_needed(affordances),
        "stop_or_mutate_condition": _plan_stop_or_mutate(affordances),
        "blockers": _plan_blockers(
            affordances,
            state=state,
            has_fork_context=has_fork_context,
            has_economics=has_economics,
            economics_context=economics_context,
        ),
        "rationale": (
            "Mapped callable surface has little or no linked experiment/result "
            "coverage. Affordance labels are used only to choose evidence and "
            "experiment shape."
        ),
    }
    return _plan_attach_branch_context(branch, affordances, economics_context)


def _plan_branch_from_protocol_hotspot(
    item: dict,
    *,
    source_path: str,
    graph_id: str | None,
    focus: str,
    state: dict,
    has_fork_context: bool,
    has_economics: bool,
    economics_context: dict | None,
    decided_action_keys: set[str] | None = None,
) -> dict | None:
    affordances = [str(label) for label in item.get("affordances") or []]
    action_key = str(item.get("key") or "")
    # A decided action should not resurface as a graph-hotspot lever either.
    if action_key and decided_action_keys and action_key in decided_action_keys:
        return None
    relevant_economics = _plan_relevant_economics_artifacts(
        affordances,
        economics_context,
    )
    score = (
        3
        + int(item.get("score", 0) or 0)
        + _plan_focus_bonus(focus, action_key, item.get("connected") or [])
        + _plan_economics_bonus(affordances, economics_context)
    )
    connected = [
        f"{edge.get('edge')} -> {edge.get('label') or edge.get('target')}"
        for edge in item.get("connected") or []
        if edge.get("edge") or edge.get("label") or edge.get("target")
    ]
    branch = {
        "_dedupe_key": f"protocol_graph:{source_path}:{action_key}",
        "source": "protocol_graph_hotspot",
        "source_artifacts": [
            source_path,
            *[
                str(artifact.get("path"))
                for artifact in relevant_economics
                if artifact.get("path")
            ],
        ],
        "source_ids": [
            *([graph_id] if graph_id else []),
            *[
                artifact.get("id")
                for artifact in relevant_economics
                if artifact.get("id")
            ],
        ],
        "title": f"Investigate graph hotspot {action_key}",
        "priority_score": score,
        "target_actions": [{
            "key": action_key,
            "contract": item.get("contract"),
            "function": item.get("function"),
            "file": item.get("file"),
            "line": item.get("line"),
            "affordances": affordances,
        }],
        "hypothesis_prompt": (
            f"What protocol invariant connects {action_key} to the mapped "
            "value-flow or trust-boundary nodes, and how could an unprivileged "
            "actor falsify it through ordering, parameters, or external state?"
        ),
        "candidate_invariant": _plan_invariant_prompt(affordances, action_key),
        "experiment_shape": _plan_experiment_shape(affordances),
        "recommended_next_tool": "update_campaign then compose_sequence_experiment with explicit actions or compose_invariant_harness with handler actions",
        "required_setup": [
            "record the specific invariant and hypothesis in campaign state",
            "use mapped connected nodes as setup/evidence prompts",
            *_plan_required_setup(
                affordances,
                economics_context=economics_context,
            ),
        ],
        "evidence_to_capture": [
            "campaign invariant/hypothesis linked to the protocol graph",
            *_plan_evidence_needed(affordances),
        ],
        "stop_or_mutate_condition": _plan_stop_or_mutate(affordances),
        "blockers": _plan_blockers(
            affordances,
            state=state,
            has_fork_context=has_fork_context,
            has_economics=has_economics,
            economics_context=economics_context,
        ),
        "rationale": (
            "Protocol graph links this entrypoint to value-flow or "
            "trust-boundary context. The graph is a planning prompt, not proof "
            f"of a bug. Connected nodes: {', '.join(connected[:5]) or 'none'}."
        ),
    }
    return _plan_attach_branch_context(branch, affordances, economics_context)


def _plan_add_branch(branches: dict, branch: dict | None) -> None:
    if not branch:
        return
    key = str(branch.pop("_dedupe_key", branch.get("title")))
    existing = branches.get(key)
    if not existing or branch["priority_score"] > existing["priority_score"]:
        branches[key] = branch
        return
    for field in ("source_artifacts", "source_ids"):
        merged = list(existing.get(field) or [])
        for item in branch.get(field) or []:
            if item and item not in merged:
                merged.append(item)
        existing[field] = merged


def _plan_entry_branch(
    entry: dict,
    *,
    source: str,
    focus: str,
    base_score: int,
    recommended_next_tool: str,
    title_prefix: str,
) -> dict:
    title = str(entry.get("title") or entry.get("id") or source)
    entry_id = str(entry.get("id") or "")
    score = (
        base_score
        + _plan_priority_score(entry.get("priority"))
        + _plan_focus_bonus(focus, title, entry.get("content", ""))
    )
    return {
        "_dedupe_key": f"{source}:{entry_id or title}",
        "source": source,
        "source_artifacts": _entry_evidence(entry),
        "source_ids": [entry_id] if entry_id else [],
        "title": f"{title_prefix}: {title}",
        "priority_score": score,
        "target_actions": [],
        "hypothesis_prompt": str(entry.get("content") or title),
        "candidate_invariant": "Use the linked campaign invariant or state a new invariant before running the next experiment.",
        "experiment_shape": "campaign-state follow-up",
        "recommended_next_tool": recommended_next_tool,
        "required_setup": [
            "read the linked campaign artifact",
            "identify exact attacker actor, setup state, transaction sequence, and success condition",
        ],
        "evidence_to_capture": [
            "linked command output or decision artifact",
            "state deltas and objective evaluation where numeric impact matters",
        ],
        "stop_or_mutate_condition": "If the branch cannot be validated, record the failed assumption and call mutate_hypothesis or add a rejection decision.",
        "blockers": [],
        "rationale": f"Campaign process signal from {source}.",
    }


def _plan_branch_from_blocked_result(entry: dict, *, focus: str) -> dict:
    diagnosis = entry.get("failure_diagnosis") or {}
    kind = str(diagnosis.get("kind") or "blocked_result")
    repairs = [
        str(item) for item in diagnosis.get("suggested_repairs") or []
        if str(item).strip()
    ]
    recommended_tool = str(
        diagnosis.get("recommended_next_tool")
        or "mutate_hypothesis or update_campaign decision"
    )
    title = str(entry.get("title") or entry.get("id") or "blocked result")
    required_setup = [
        "read the blocked result log and any result follow-up diagnosis",
        "fix the earliest concrete blocker before mutating the exploit hypothesis",
    ]
    required_setup.extend(repairs[:3])
    if not repairs:
        required_setup.append(
            "summarize the full log and identify compile, setup, revert, or assertion cause"
        )
    evidence_to_capture = [
        "rerun log after exactly one repair or an explicit rejection/mutation decision",
        "updated objective snapshots/evaluation if the repaired run executes",
    ]
    evidence_lines = [
        str(item) for item in diagnosis.get("evidence_lines") or []
        if str(item).strip()
    ][:5]
    if evidence_lines:
        evidence_to_capture.append("explain the diagnostic line(s) that changed")
    return {
        "_dedupe_key": f"blocked_result:{entry.get('id') or title}",
        "source": "blocked_result",
        "source_artifacts": entry.get("evidence") or [],
        "source_ids": [entry.get("id")] if entry.get("id") else [],
        "title": f"Repair blocked result {entry.get('id') or title}: {kind}",
        "priority_score": 8 + _plan_focus_bonus(focus, title, diagnosis),
        "target_actions": [],
        "hypothesis_prompt": (
            "What exact blocker prevented this experiment from testing the "
            "hypothesis, and does the branch need repair or mutation?"
        ),
        "candidate_invariant": (
            "Keep the original candidate invariant unless the repaired run "
            "shows the setup or objective assumption is false."
        ),
        "experiment_shape": f"experiment repair for {kind}",
        "recommended_next_tool": recommended_tool,
        "required_setup": _dedupe_text(required_setup),
        "evidence_to_capture": _dedupe_text(evidence_to_capture),
        "stop_or_mutate_condition": (
            "If the same blocker remains after one focused repair, record the "
            "failed assumption and mutate_hypothesis or reject the branch."
        ),
        "blockers": [diagnosis.get("summary")] if diagnosis.get("summary") else [],
        "failure_diagnosis": diagnosis,
        "rationale": (
            "A recorded experiment is blocked. The diagnosis is only a repair "
            "prompt; it is not evidence for or against the exploit hypothesis."
        ),
    }


def _plan_route_gap_applies(route: dict, gap: str) -> bool:
    lowered = gap.lower()
    kind = str(route.get("kind") or "").lower()
    title = str(route.get("title") or "").lower()
    if kind and kind in lowered:
        return True
    if title and title in lowered:
        return True
    if "route composition" in lowered and route.get("missing_context"):
        return True
    return False


def _plan_route_review_gaps(review: dict, route: dict) -> list[str]:
    matched = [
        gap for gap in review.get("route_blocking_gaps") or []
        if _plan_route_gap_applies(route, str(gap))
    ]
    if matched:
        return matched
    if route.get("missing_context"):
        return [
            "route composition missing context: "
            + ", ".join(str(item) for item in route.get("missing_context") or [])
        ]
    return []


def _plan_route_review_tool(review_kind: str, route: dict, sequence_path: str) -> str:
    suggested_tools = [
        str(item) for item in route.get("suggested_tools") or []
        if str(item).strip()
    ]
    if suggested_tools:
        return suggested_tools[0]
    if review_kind == "report_quality":
        return "update report draft then review_report_quality"
    if sequence_path:
        return "run_experiment"
    return "compose_sequence_experiment with explicit actions or compose_invariant_harness with handler actions"


def _plan_route_review_setup(route: dict, sequence_path: str) -> list[str]:
    kind = str(route.get("kind") or "")
    setup = [
        "read the blocked review and linked route-composition plan",
    ]
    if sequence_path:
        setup.append(f"open the sequence artifact {sequence_path}")
    suggested_tools = [
        str(item) for item in route.get("suggested_tools") or []
        if str(item).strip()
    ]
    if suggested_tools:
        setup.append(
            "run and link missing route-context tools: " + ", ".join(suggested_tools)
        )
    if kind == "amm_or_valuation_route":
        setup.extend([
            "bind the concrete pool, router, token ordering, oracle reader, and fork block",
            "add reserve, route input/output, valuation, slippage, and unwind probes",
        ])
    elif kind == "oracle_window_route":
        setup.extend([
            "record oracle answer, decimals, updatedAt/timestamp, heartbeat, and adapter/cache state",
            "test spot, stale, and window-boundary valuation variants on the same fork block",
        ])
    elif kind == "flash_loan_route":
        setup.extend([
            "instrument callback entry/exit, borrowed balance, premium, approvals, repayment, and provider balance",
            "assert protected state cannot move before repayment unless that is the claimed bug",
        ])
    elif kind == "liquidation_credit_route":
        setup.extend([
            "bind borrower collateral/debt, liquidation threshold, close factor, bonus, repay asset, and seized asset",
            "add liquidator balance, bad-debt accounting, protocol reserve, and seized-collateral unwind probes",
        ])
    parameter_hints = route.get("source_parameter_hints") or []
    if parameter_hints:
        setup.append("verify source-derived parameter hints before choosing amounts")
    callback_hints = route.get("source_callback_hints") or []
    if callback_hints:
        setup.append("verify source-derived callback selector/surface hints before replay")
    router_hints = route.get("source_router_hints") or []
    if router_hints:
        setup.append("verify source-derived router call/path hints before replay")
        router_summaries = _route_router_hint_summaries(route)
        if router_summaries:
            setup.append(
                "start from source router hints: " + "; ".join(router_summaries)
            )
    candidate_summaries = _route_unwind_candidate_summaries(route)
    if candidate_summaries:
        setup.append(
            "start from route unwind candidates: " + "; ".join(candidate_summaries)
        )
    return setup


def _plan_route_review_evidence(route: dict) -> list[str]:
    evidence = [
        str(item) for item in route.get("evidence_prompts") or []
        if str(item).strip()
    ]
    kind = str(route.get("kind") or "")
    if kind == "amm_or_valuation_route":
        evidence.extend([
            "AMM economics artifact linked to pool reserve and route output snapshots",
            "post-unwind attacker balance and objective evaluation for net profit",
        ])
    elif kind == "oracle_window_route":
        evidence.extend([
            "oracle freshness/window snapshots before and after the sequence",
            "objective evaluation comparing spot, stale, and boundary states",
        ])
    elif kind == "flash_loan_route":
        evidence.extend([
            "callback trace plus borrowed balance, premium, repayment, and provider balance snapshots",
            "post-unwind attacker balance and objective evaluation after fees",
        ])
    elif kind == "liquidation_credit_route":
        evidence.extend([
            "borrower collateral/debt and health-factor snapshots around liquidation",
            "liquidator profit, seized collateral, bad debt, fees, and unwind output",
        ])
    router_hint_summaries = _route_router_hint_summaries(route)
    if router_hint_summaries:
        evidence.append(
            "router calldata/path evidence for: " + "; ".join(router_hint_summaries)
        )
    candidate_summaries = _route_unwind_candidate_summaries(route)
    if candidate_summaries:
        evidence.append(
            "candidate unwind route validation: " + "; ".join(candidate_summaries)
        )
    return _dedupe_text(evidence)


def _plan_branch_from_route_review(
    review: dict,
    summary: dict,
    route: dict,
    *,
    focus: str,
) -> dict | None:
    gaps = _plan_route_review_gaps(review, route)
    if not gaps:
        return None
    review_id = str(review.get("id") or "")
    review_kind = str(review.get("kind") or "")
    route_kind = str(route.get("kind") or "route")
    sequence_id = str(summary.get("sequence_id") or "")
    sequence_path = str(summary.get("sequence_path") or "")
    source = f"blocked_{review_kind}_route_review"
    priority_score = (
        11
        + (_plan_priority_score(str(review.get("severity") or "")) // 4)
        + _plan_focus_bonus(focus, review.get("title"), gaps, route_kind)
    )
    source_artifacts = _unique_strings([
        review.get("path"),
        sequence_path,
        route.get("source_artifacts") or [],
    ])
    source_ids = _unique_strings([
        review_id,
        sequence_id,
    ])
    return {
        "_dedupe_key": (
            f"{source}:{review_id or review.get('path')}:{sequence_id}:{route_kind}"
        ),
        "source": source,
        "source_artifacts": source_artifacts,
        "source_ids": source_ids,
        "title": f"Close route evidence gap for {review_id or review.get('path')}: {route_kind}",
        "priority_score": priority_score,
        "target_actions": [],
        "hypothesis_prompt": (
            "The finding/report review is blocked on composed-route evidence. "
            "Add only the missing fork setup, assertions, snapshots, or economics "
            "needed to resolve the listed route gaps."
        ),
        "candidate_invariant": (
            "The composed route must preserve the candidate exploit objective after "
            "route economics, callbacks, repayment, oracle freshness, liquidation "
            "state, and unwind costs are made explicit."
        ),
        "experiment_shape": (
            f"route-evidence repair for {route.get('title') or route_kind}"
        ),
        "recommended_next_tool": _plan_route_review_tool(
            review_kind,
            route,
            sequence_path,
        ),
        "required_setup": _plan_route_review_setup(route, sequence_path),
        "evidence_to_capture": _plan_route_review_evidence(route),
        "stop_or_mutate_condition": (
            "After capturing the missing route evidence, rerun the same evidence "
            "or report review. If the route is uneconomic or unreachable, mutate "
            "the hypothesis around the failed assumption instead of submitting."
        ),
        "blockers": gaps,
        "route_review_context": {
            "review_id": review_id or None,
            "review_path": review.get("path"),
            "review_kind": review_kind,
            "sequence_id": sequence_id or None,
            "sequence_path": sequence_path or None,
            "route_kind": route_kind,
            "missing_context": route.get("missing_context") or [],
            "suggested_tools": route.get("suggested_tools") or [],
            "source_router_hint_summaries": _route_router_hint_summaries(
                route,
                limit=4,
            ),
            "unwind_candidate_summaries": _route_unwind_candidate_summaries(
                route,
                limit=4,
            ),
            "route_blocking_gaps": gaps,
        },
        "rationale": (
            "A readiness review found that the candidate cannot advance until "
            "this composed-route proof is made concrete."
        ),
    }


def _plan_finalize_branches(branches: dict, max_branches: int) -> list[dict]:
    ordered = sorted(
        branches.values(),
        key=lambda item: (
            -int(item.get("priority_score", 0) or 0),
            str(item.get("title") or ""),
        ),
    )[:max_branches]
    for index, branch in enumerate(ordered, start=1):
        branch["id"] = f"branch-{index:03d}"
        branch["priority"] = _plan_priority(int(branch.get("priority_score", 0) or 0))
    return ordered


_PLAN_CONTROLLER_NOTE = (
    "Use attack_search for authoritative next_action and branch transitions."
)


def _plan_candidate_next_steps(plan: dict) -> list[str]:
    branches = plan.get("branches") or []
    if not branches:
        return [
            "Candidate: record protocol model, value-flow, invariant, action-space, or coverage artifacts before planning deeper experiments. attack_search schedules the next action.",
        ]
    top = branches[0]
    candidate = (
        f"Candidate branch {top['id']}: {top['title']} "
        f"(suggested tool {top['recommended_next_tool']})."
    )
    blockers = top.get("blockers") or []
    if blockers:
        candidate += " Blockers to resolve first: " + "; ".join(blockers) + "."
    return [
        candidate,
        "These are advisory candidates; call attack_search for the authoritative next_action and to record branch transitions.",
    ]


async def _plan_attack_campaign(container: AuditContainer, args: dict) -> str:
    max_branches = min(max(int(args.get("max_branches", 6)), 1), 20)
    focus = str(args.get("focus") or "").strip()
    state = await _load_campaign_state(container)
    try:
        action_spaces = await _load_plan_action_spaces(
            container,
            state,
            str(args.get("action_space") or "").strip(),
        )
        protocol_graphs = await _load_plan_artifacts(
            container,
            state,
            explicit=str(args.get("protocol_graph") or "").strip(),
            directory="/workspace/campaign/protocol-graphs/",
            id_prefix="pg",
            name="protocol_graph",
        )
        coverage_reviews = await _load_plan_artifacts(
            container,
            state,
            explicit=str(args.get("coverage_review") or "").strip(),
            directory="/workspace/campaign/coverage-reviews/",
            id_prefix="cov",
            name="coverage_review",
        )
        progress_reviews = await _load_plan_artifacts(
            container,
            state,
            explicit=str(args.get("progress_review") or "").strip(),
            directory="/workspace/campaign/progress-reviews/",
            id_prefix="prg",
            name="progress_review",
        )
        economics_artifacts = await _load_plan_artifacts(
            container,
            state,
            explicit="",
            directory="/workspace/campaign/economics/",
            id_prefix="econ",
            name="economics",
        )
    except ValueError as exc:
        return f"Error: {exc}"

    failed_evaluations = await _progress_evaluations(container, state)
    sequence_minimizations_without_review = (
        await _progress_sequence_minimizations_without_review(container, state)
    )
    candidate_fuzz_failures = await _progress_candidate_fuzz_runs(container, state)
    action_spaces_without_coverage = await _progress_action_spaces_without_coverage(
        container,
        state,
    )
    covered_action_space_paths = {
        item["payload"].get("action_space_path")
        for item in coverage_reviews
        if item["payload"].get("action_space_path")
    }
    if covered_action_space_paths:
        action_spaces_without_coverage = [
            item for item in action_spaces_without_coverage
            if item.get("path") not in covered_action_space_paths
        ]
    known_action_space_paths = {
        item.get("path") for item in action_spaces_without_coverage
    }
    for artifact in action_spaces:
        path = artifact["path"]
        if path in covered_action_space_paths or path in known_action_space_paths:
            continue
        payload = artifact["payload"]
        action_spaces_without_coverage.append({
            "id": payload.get("id"),
            "path": path,
            "summary": payload.get("summary") or {},
            "suggested_action": "call review_attack_surface_coverage before choosing the next action grammar",
        })
        known_action_space_paths.add(path)
    hypotheses_without_experiments = _progress_hypotheses_without_experiments(state)
    experiments_without_results = _progress_unrun_experiments(state)
    blocked_results = await _progress_blocked_results(container, state)
    ready_finding_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/finding-reviews/",
        kind="finding_evidence",
    )
    ready_report_reviews = await _progress_ready_reviews(
        container,
        state,
        prefix="/workspace/campaign/report-reviews/",
        kind="report_quality",
    )
    blocked_finding_reviews = await _progress_blocked_reviews(
        container,
        state,
        prefix="/workspace/campaign/finding-reviews/",
        kind="finding_evidence",
    )
    blocked_report_reviews = await _progress_blocked_reviews(
        container,
        state,
        prefix="/workspace/campaign/report-reviews/",
        kind="report_quality",
    )

    has_fork_context = bool(
        _progress_evidence_paths(state, "/workspace/campaign/fork-contexts/")
        or int(state.get("counters", {}).get("fork_context", 0) or 0)
    )
    has_economics = bool(
        _progress_evidence_paths(state, "/workspace/campaign/economics/")
        or int(state.get("counters", {}).get("economics", 0) or 0)
        or int(state.get("counters", {}).get("flash_loan", 0) or 0)
    )
    economics_context = _plan_economics_context(economics_artifacts, state)
    decided_action_keys = _campaign_decided_action_keys(state)

    branch_map: dict[str, dict] = {}
    for artifact in protocol_graphs:
        payload = artifact["payload"]
        path = artifact["path"]
        for item in (payload.get("hotspots") or [])[:8]:
            _plan_add_branch(branch_map, _plan_branch_from_protocol_hotspot(
                item,
                source_path=path,
                graph_id=payload.get("id"),
                focus=focus,
                state=state,
                has_fork_context=has_fork_context,
                has_economics=has_economics,
                economics_context=economics_context,
                decided_action_keys=decided_action_keys,
            ))

    for artifact in coverage_reviews:
        payload = artifact["payload"]
        path = artifact["path"]
        for item in payload.get("high_attention_gaps") or []:
            _plan_add_branch(branch_map, _plan_branch_from_action_gap(
                item,
                source="coverage_high_attention_gap",
                source_path=path,
                focus=focus,
                state=state,
                has_fork_context=has_fork_context,
                has_economics=has_economics,
                economics_context=economics_context,
                base_score=6,
                decided_action_keys=decided_action_keys,
            ))
        for item in payload.get("hypothesized_not_experimented") or []:
            _plan_add_branch(branch_map, _plan_branch_from_action_gap(
                item,
                source="hypothesized_not_experimented",
                source_path=path,
                focus=focus,
                state=state,
                has_fork_context=has_fork_context,
                has_economics=has_economics,
                economics_context=economics_context,
                base_score=4,
                decided_action_keys=decided_action_keys,
            ))
        if not payload.get("high_attention_gaps"):
            for item in (payload.get("open_gaps") or [])[:5]:
                _plan_add_branch(branch_map, _plan_branch_from_action_gap(
                    item,
                    source="coverage_open_gap",
                    source_path=path,
                    focus=focus,
                    state=state,
                    has_fork_context=has_fork_context,
                    has_economics=has_economics,
                    economics_context=economics_context,
                    base_score=2,
                    decided_action_keys=decided_action_keys,
                ))

    for item in action_spaces_without_coverage:
        score = 7 + _plan_focus_bonus(focus, item.get("id"), item.get("path"))
        _plan_add_branch(branch_map, {
            "_dedupe_key": f"coverage:{item.get('path')}",
            "source": "action_space_without_coverage",
            "source_artifacts": [item.get("path")],
            "source_ids": [item.get("id")] if item.get("id") else [],
            "title": f"Review callable-surface coverage for {item.get('id') or item.get('path')}",
            "priority_score": score,
            "target_actions": [],
            "hypothesis_prompt": "Before choosing the next attack grammar, identify high-value mapped actions with no linked experiments or decisions.",
            "candidate_invariant": "Coverage review should select protocol-specific invariants from value flows and trust boundaries.",
            "experiment_shape": "process review before experiment composition",
            "recommended_next_tool": "review_attack_surface_coverage",
            "required_setup": ["load the mapped action-space artifact"],
            "evidence_to_capture": ["coverage review artifact linked to the action-space map"],
            "stop_or_mutate_condition": "If no high-value gaps remain, map another subsystem or deepen parameter/order exploration.",
            "blockers": [],
            "rationale": "An action-space map exists but has not been compared with campaign evidence.",
        })

    for item in failed_evaluations:
        summary = item.get("summary") or {}
        _plan_add_branch(branch_map, {
            "_dedupe_key": f"failed_eval:{item.get('id') or item.get('path')}",
            "source": "failed_evaluation",
            "source_artifacts": [item.get("path")],
            "source_ids": [item.get("id")] if item.get("id") else [],
            "title": f"Interpret and mutate failed objective {item.get('id') or item.get('title')}",
            "priority_score": 10 + _plan_focus_bonus(focus, item.get("title"), summary),
            "target_actions": [],
            "hypothesis_prompt": "What assumption failed, and what adjacent invariant or setup should be tested next?",
            "candidate_invariant": "Use the failed objective to choose the nearest still-plausible invariant.",
            "experiment_shape": "hypothesis mutation followed by sequence or invariant experiment",
            "recommended_next_tool": "mutate_hypothesis",
            "required_setup": ["read the failed evaluation and linked comparison/result"],
            "evidence_to_capture": ["mutation artifact and next experiment-plan artifact"],
            "stop_or_mutate_condition": "If no adjacent hypothesis remains plausible, record a rejection decision.",
            "blockers": [],
            "rationale": "Objective evidence contradicted or failed to validate the current branch.",
        })

    for item in sequence_minimizations_without_review:
        summary = item.get("summary") or {}
        variant_id = (
            summary.get("best_variant_id")
            or summary.get("minimal_preserved_variant")
            or "preserved variant"
        )
        retained_setup = [
            setup for setup in summary.get("retained_setup_assumptions") or []
            if isinstance(setup, dict)
        ]
        reduced_setup = [
            setup for setup in summary.get("reduced_setup_assumptions") or []
            if isinstance(setup, dict)
        ]
        retained_labels = [
            str(setup.get("label") or setup.get("kind") or setup.get("target"))
            for setup in retained_setup[:3]
            if setup.get("label") or setup.get("kind") or setup.get("target")
        ]
        required_setup = [
            "read the minimization artifact and best variant log",
            f"confirm {variant_id} still preserves the intended objective",
        ]
        evidence_to_capture = [
            "finding evidence review linked to the minimization artifact",
            "objective evaluation and replay logs for the minimized variant",
        ]
        stop_or_mutate = (
            "If the minimized replay only preserves a marker without proving "
            "impact, capture objective deltas or mutate the hypothesis."
        )
        if retained_labels:
            required_setup.append(
                "challenge retained setup assumptions: "
                + ", ".join(retained_labels)
            )
            evidence_to_capture.append(
                "decision on whether retained setup assumptions are realistic "
                "protocol preconditions"
            )
            stop_or_mutate = (
                "If retained setup assumptions are unrealistic, privileged, or "
                "bounty-ineligible, mutate_hypothesis toward the nearest "
                "protocol-realistic setup or record a rejection decision."
            )
        if int(summary.get("untested_plan_variants", 0) or 0) > 0:
            required_setup.append(
                "review untested minimization variants before relying on this "
                "as the final minimal replay"
            )
            evidence_to_capture.append(
                "decision explaining why untested minimization variants are "
                "irrelevant, or logs from running them"
            )
        _plan_add_branch(branch_map, {
            "_dedupe_key": f"unreviewed_min:{item.get('id') or item.get('path')}",
            "source": "unreviewed_sequence_minimization",
            "source_artifacts": [item.get("path")],
            "source_ids": [item.get("id")] if item.get("id") else [],
            "title": f"Review minimized replay evidence {item.get('id') or item.get('title')}",
            "priority_score": 10 + _plan_focus_bonus(
                focus,
                item.get("title"),
                summary,
            ),
            "target_actions": [],
            "hypothesis_prompt": (
                "Does the preserved minimized replay prove a bug-bounty-ready "
                "candidate, or should the hypothesis mutate?"
            ),
            "candidate_invariant": (
                "Use the minimized replay's objective marker as evidence for the "
                "same invariant tested by the baseline sequence."
            ),
            "experiment_shape": "evidence review for minimized sequence replay",
            "recommended_next_tool": "review_finding_evidence",
            "required_setup": required_setup,
            "evidence_to_capture": evidence_to_capture,
            "stop_or_mutate_condition": stop_or_mutate,
            "blockers": [],
            "setup_reduction_context": {
                "setup_checks_executed": summary.get("setup_checks_executed"),
                "setup_checks_retained": summary.get("setup_checks_retained"),
                "retained_setup_assumptions": retained_setup[:6],
                "reduced_setup_assumptions": reduced_setup[:6],
            },
            "minimization_plan_context": {
                "available_plan_variants": summary.get("available_plan_variants"),
                "requested_plan_variants": summary.get("requested_plan_variants"),
                "untested_plan_variants": summary.get("untested_plan_variants"),
                "unplanned_requested_variants": summary.get(
                    "unplanned_requested_variants"
                ),
            },
            "rationale": (
                "A sequence minimization preserved objective evidence but has not "
                "been promoted into a finding evidence review."
            ),
        })

    for item in candidate_fuzz_failures:
        _plan_add_branch(branch_map, {
            "_dedupe_key": f"candidate_fuzz:{item.get('id') or item.get('path')}",
            "source": "candidate_fuzz_failure",
            "source_artifacts": [item.get("path"), item.get("log_path")],
            "source_ids": [item.get("id")] if item.get("id") else [],
            "title": f"Reduce candidate fuzz failure {item.get('id') or item.get('title')}",
            "priority_score": 11 + _plan_focus_bonus(
                focus,
                item.get("title"),
                item.get("summary"),
            ),
            "target_actions": [],
            "hypothesis_prompt": (
                "What concrete transaction sequence and state delta does this "
                "fuzz/invariant failure imply?"
            ),
            "candidate_invariant": (
                "Use the failing property or invariant run to select the exact "
                "protocol invariant that needs objective validation."
            ),
            "experiment_shape": "failure reduction followed by sequence PoC",
            "recommended_next_tool": "summarize_trace or extract_call_sequence",
            "required_setup": [
                "read the fuzz run JSON and full log",
                "extract the minimal failing call sequence and actors",
            ],
            "evidence_to_capture": [
                "trace summary or extracted call sequence linked to the fuzz run",
                "before/after snapshots and objective evaluation for the reduced sequence",
            ],
            "stop_or_mutate_condition": (
                "If the failure is an expected revert or harness issue, record "
                "a rejection decision or mutate the harness assumption."
            ),
            "blockers": [],
            "rationale": (
                "A property campaign produced a candidate failure. It still "
                "needs reduction and objective evidence before it can become a finding."
            ),
        })

    for review in [*blocked_finding_reviews, *blocked_report_reviews]:
        for summary in review.get("route_compositions") or []:
            if not isinstance(summary, dict):
                continue
            for route in summary.get("routes") or []:
                if not isinstance(route, dict):
                    continue
                branch = _plan_branch_from_route_review(
                    review,
                    summary,
                    route,
                    focus=focus,
                )
                if branch:
                    _plan_add_branch(branch_map, branch)

    for entry in hypotheses_without_experiments:
        _plan_add_branch(branch_map, _plan_entry_branch(
            entry,
            source="hypothesis_without_experiment",
            focus=focus,
            base_score=2,
            recommended_next_tool="compose_sequence_experiment with explicit actions or compose_invariant_harness with handler actions",
            title_prefix="Design experiment for hypothesis",
        ))

    for entry in experiments_without_results:
        _plan_add_branch(branch_map, _plan_entry_branch(
            entry,
            source="experiment_without_result",
            focus=focus,
            base_score=3,
            recommended_next_tool="run_experiment",
            title_prefix="Run open experiment",
        ))

    for entry in blocked_results:
        _plan_add_branch(branch_map, _plan_branch_from_blocked_result(
            entry,
            focus=focus,
        ))

    for item in ready_report_reviews:
        _plan_add_branch(branch_map, {
            "_dedupe_key": f"ready_report:{item.get('id')}",
            "source": "ready_report_review",
            "source_artifacts": [item.get("path")],
            "source_ids": [item.get("id")] if item.get("id") else [],
            "title": f"Submit ready reviewed finding {item.get('id')}",
            "priority_score": 12,
            "target_actions": [],
            "hypothesis_prompt": "Confirm the finding is still in scope and submit with linked campaign evidence.",
            "candidate_invariant": "Already validated in linked report review.",
            "experiment_shape": "submission readiness",
            "recommended_next_tool": "submit_finding",
            "required_setup": ["read linked report-quality review and finding evidence review"],
            "evidence_to_capture": ["final submitted finding with campaign ids and evidence paths"],
            "stop_or_mutate_condition": "If scope or evidence has changed, update the report review before submitting.",
            "blockers": [],
            "rationale": "A report-quality review marked the finding ready.",
        })

    for item in ready_finding_reviews:
        _plan_add_branch(branch_map, {
            "_dedupe_key": f"ready_finding:{item.get('id')}",
            "source": "ready_finding_review",
            "source_artifacts": [item.get("path")],
            "source_ids": [item.get("id")] if item.get("id") else [],
            "title": f"Run report-quality review for ready evidence {item.get('id')}",
            "priority_score": 9,
            "target_actions": [],
            "hypothesis_prompt": "Convert ready evidence into a reviewer-reproducible bug-bounty report.",
            "candidate_invariant": "Already validated in linked evidence review.",
            "experiment_shape": "report readiness",
            "recommended_next_tool": "review_report_quality",
            "required_setup": ["read linked finding evidence review"],
            "evidence_to_capture": ["report-quality review artifact"],
            "stop_or_mutate_condition": "If the writeup has gaps, fill reproduction, economics, assumptions, and remediation before submitting.",
            "blockers": [],
            "rationale": "Evidence review is ready, but final report quality has not been checked.",
        })

    if not branch_map:
        for section in ("protocol_model", "value_flow", "invariant", "hypothesis"):
            if state["sections"].get(section):
                continue
            _plan_add_branch(branch_map, {
                "_dedupe_key": f"missing:{section}",
                "source": "missing_foundation",
                "source_artifacts": [],
                "source_ids": [],
                "title": f"Record missing campaign foundation: {section}",
                "priority_score": 5,
                "target_actions": [],
                "hypothesis_prompt": "Build the minimum campaign foundation needed before designing deeper exploit experiments.",
                "candidate_invariant": "Not available until foundation artifacts are recorded.",
                "experiment_shape": "campaign orientation",
                "recommended_next_tool": "update_campaign",
                "required_setup": ["read target source and document value flow/trust boundaries"],
                "evidence_to_capture": ["campaign artifact with source references"],
                "stop_or_mutate_condition": "Once foundation exists, map action space and plan attack branches.",
                "blockers": [],
                "rationale": "Planner needs campaign context before proposing meaningful experiments.",
            })

    branches = _plan_finalize_branches(branch_map, max_branches)
    plan_id = _next_campaign_id(state, "campaign_plan")
    title = str(args.get("title") or "Attack campaign plan").strip()
    source_paths = []
    for collection in (
        protocol_graphs,
        action_spaces,
        coverage_reviews,
        progress_reviews,
        economics_artifacts,
    ):
        for artifact in collection:
            path = artifact["path"]
            if path not in source_paths:
                source_paths.append(path)
    for branch in branches:
        for path in branch.get("source_artifacts") or []:
            if path and path not in source_paths:
                source_paths.append(path)

    plan = {
        "id": plan_id,
        "title": title,
        "focus": focus,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "campaign_counts": {
            section: len(state["sections"].get(section, []))
            for section in _CAMPAIGN_SECTIONS
        },
        "source_artifacts": {
            "protocol_graphs": [
                {
                    "id": item["payload"].get("id"),
                    "path": item["path"],
                    "summary": item["payload"].get("summary") or {},
                }
                for item in protocol_graphs
            ],
            "action_spaces": [
                {
                    "id": item["payload"].get("id"),
                    "path": item["path"],
                    "summary": item["payload"].get("summary") or {},
                }
                for item in action_spaces
            ],
            "coverage_reviews": [
                {
                    "id": item["payload"].get("id"),
                    "path": item["path"],
                    "summary": item["payload"].get("summary") or {},
                }
                for item in coverage_reviews
            ],
            "progress_reviews": [
                {
                    "id": item["payload"].get("id"),
                    "path": item["path"],
                    "summary": item["payload"].get("summary") or {},
                }
                for item in progress_reviews
            ],
            "economics": [
                {
                    "id": item["payload"].get("id"),
                    "path": item["path"],
                    "kind": _plan_economics_kind(item["payload"]),
                    "summary": item["payload"].get("summary") or {},
                }
                for item in economics_artifacts
            ],
            "sequence_minimizations_without_review": sequence_minimizations_without_review,
            "blocked_route_reviews": [
                {
                    "id": item.get("id"),
                    "kind": item.get("kind"),
                    "path": item.get("path"),
                    "route_blocking_gaps": item.get("route_blocking_gaps") or [],
                }
                for item in [*blocked_finding_reviews, *blocked_report_reviews]
            ],
        },
        "context": {
            "has_protocol_graph": bool(protocol_graphs),
            "has_fork_context": has_fork_context,
            "has_economics": has_economics,
            "economics": economics_context,
            "open_hypotheses": len(hypotheses_without_experiments),
            "open_experiments": len(experiments_without_results),
            "failed_evaluations": len(failed_evaluations),
            "sequence_minimizations_without_review": (
                len(sequence_minimizations_without_review)
            ),
            "candidate_fuzz_failures": len(candidate_fuzz_failures),
            "ready_finding_reviews": len(ready_finding_reviews),
            "ready_report_reviews": len(ready_report_reviews),
            "blocked_route_reviews": (
                len(blocked_finding_reviews) + len(blocked_report_reviews)
            ),
            "blocked_results": len(blocked_results),
        },
        "branches": branches,
        "summary": {
            "branches": len(branches),
            "critical": sum(1 for branch in branches if branch["priority"] == "critical"),
            "high": sum(1 for branch in branches if branch["priority"] == "high"),
            "medium": sum(1 for branch in branches if branch["priority"] == "medium"),
            "low": sum(1 for branch in branches if branch["priority"] == "low"),
        },
    }
    plan["candidate_next_steps"] = _plan_candidate_next_steps(plan)
    plan["controller_note"] = _PLAN_CONTROLLER_NOTE

    plan_path = f"/workspace/campaign/plans/{plan_id}.json"
    await container.write_file(
        plan_path,
        json.dumps(plan, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Attack campaign plan: {title}",
            content=(
                f"Campaign plan: {plan_id}\n"
                f"Path: {plan_path}\n"
                f"Branches: {plan['summary']['branches']}\n"
                f"Critical: {plan['summary']['critical']}\n"
                f"High: {plan['summary']['high']}\n"
                f"Top branch: {branches[0]['title'] if branches else 'none'}"
            ),
            evidence=[plan_path, *source_paths[:20]],
            related_ids=[plan_id],
            status="observed",
        )

    response = {
        "plan_id": plan_id,
        "path": plan_path,
        "result_id": result_id or None,
        "summary": plan["summary"],
        "candidate_next_steps": plan["candidate_next_steps"],
        "controller_note": plan["controller_note"],
        "branches": branches,
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _action_space_call_indexes(action_space: dict | None) -> tuple[dict, dict]:
    exact_index = {}
    function_index = {}
    if not action_space:
        return exact_index, function_index
    for entry in action_space.get("actions", []) + action_space.get("observations", []):
        contract = str(entry.get("contract") or "").strip()
        function = str(entry.get("function") or "").strip()
        if not function:
            continue
        compact = {
            "contract": contract,
            "function": function,
            "file": entry.get("file"),
            "line": entry.get("line"),
            "mutability": entry.get("mutability"),
            "affordances": entry.get("affordances", []),
            "parameters": entry.get("parameters", []),
            "returns": entry.get("returns", ""),
            "hints": {
                key: values[:5]
                for key, values in (entry.get("hints") or {}).items()
                if values
            },
        }
        if contract:
            exact_index[_action_match_key(contract, function)] = compact
        function_index.setdefault(function.lower(), compact)
    return exact_index, function_index


def _match_action_space_call(
    contract: str,
    function: str,
    exact_index: dict,
    function_index: dict,
) -> dict | None:
    if contract and function:
        match = exact_index.get(_action_match_key(contract, function))
        if match:
            return match
    if function:
        return function_index.get(function.lower())
    return None


def _extract_trace_call_steps(
    text: str,
    *,
    max_steps: int,
    action_space: dict | None,
    include_unmatched: bool,
) -> tuple[list[dict], int]:
    exact_index, function_index = _action_space_call_indexes(action_space)
    has_action_space = bool(action_space)
    skipped_unmatched = 0
    steps = []
    call_re = re.compile(
        r"(?:\[\d+\]\s+)?([^:\s\[]+)::([A-Za-z_][A-Za-z0-9_.$<>]*)\((.*)"
    )
    dotted_call_re = re.compile(
        r"(?:\[\d+\]\s+)?([A-Za-z_][A-Za-z0-9_.$<>]*)"
        r"\.([A-Za-z_][A-Za-z0-9_.$<>]*)\((.*)"
    )
    ignored_targets = {
        "vm",
        "console",
        "console2",
        "stdassertions",
        "stdcheats",
        "stdstorage",
    }
    for line_number, line in enumerate(text.splitlines(), start=1):
        payload = _trace_line_payload(line)
        match = call_re.search(payload)
        if not match:
            match = dotted_call_re.search(payload)
        if not match:
            continue
        contract, function, raw_args = match.groups()
        if contract.lower() in ignored_targets:
            continue
        if function.startswith("test_") or function.startswith("invariant_"):
            continue
        matched = _match_action_space_call(
            contract,
            function,
            exact_index,
            function_index,
        )
        if has_action_space and not matched and not include_unmatched:
            skipped_unmatched += 1
            continue
        step = {
            "index": len(steps) + 1,
            "line": line_number,
            "depth": _trace_depth(line),
            "contract": contract,
            "function": function,
            "args_text": raw_args[:300],
            "raw": line.strip()[:500],
            "matched": bool(matched),
        }
        if matched:
            step["action_space"] = matched
        steps.append(step)
        if len(steps) >= max_steps:
            break
    return steps, skipped_unmatched


_CALL_SEQUENCE_NOISE_FUNCTIONS = {
    "setup",
    "_bindtargets",
    "_configurescenario",
    "_snapshot",
    "_snapshotnativebalances",
    "_snapshottokenbalances",
    "_snapshotaccounting",
    "_observebefore",
    "_observeafter",
    "_assertcampaigninvariant",
}


def _call_sequence_noise_reason(step: dict) -> str:
    function = str(step.get("function") or "").strip().lower()
    contract = str(step.get("contract") or "").strip().lower()
    if function in _CALL_SEQUENCE_NOISE_FUNCTIONS:
        return "generated_harness_helper"
    if function.startswith("test_") or function.startswith("invariant_"):
        return "test_entrypoint"
    if contract in {"reentbotsequence", "reentbotinvariant"} and function.startswith("_"):
        return "generated_harness_internal"
    return ""


def _call_sequence_reduction(steps: list[dict]) -> dict:
    kept = []
    removed = []
    for step in steps:
        index = int(step.get("index") or len(kept) + len(removed) + 1)
        reason = _call_sequence_noise_reason(step)
        if reason:
            removed.append({
                "index": index,
                "line": step.get("line"),
                "contract": step.get("contract"),
                "function": step.get("function"),
                "reason": reason,
            })
            continue
        kept.append(index)
    return {
        "strategy": "generated_harness_noise_filter_v1",
        "kept_step_indices": kept,
        "removed": removed,
        "summary": {
            "original_steps": len(steps),
            "replay_steps": len(kept),
            "removed": len(removed),
        },
    }


def _call_sequence_replay_steps(sequence: dict) -> list[dict]:
    steps = [
        step for step in sequence.get("steps") or []
        if isinstance(step, dict)
    ]
    reduction = sequence.get("reduction") or {}
    kept_indices = reduction.get("kept_step_indices")
    if not isinstance(kept_indices, list):
        return steps
    kept = {int(item) for item in kept_indices if str(item).isdigit()}
    return [
        step for step in steps
        if int(step.get("index") or 0) in kept
    ]


async def _resolve_call_sequence_source(
    container: AuditContainer,
    args: dict,
) -> tuple[str, str, dict | None, list[str]]:
    raw_path = str(args.get("path") or "").strip()
    fuzz_run_ref = str(args.get("fuzz_run") or "").strip()
    related_ids = [
        str(item)
        for item in _require_list(args.get("related_ids"), "related_ids")
    ]
    fuzz_run_path = ""
    fuzz_run = None

    if fuzz_run_ref:
        fuzz_run_path, fuzz_run = await _load_fuzz_run(container, fuzz_run_ref)
        fuzz_id = str(fuzz_run.get("id") or "")
        if fuzz_id and fuzz_id not in related_ids:
            related_ids.append(fuzz_id)
        if not raw_path:
            raw_path = str(fuzz_run.get("log_path") or "").strip()
        if not raw_path:
            raise ValueError(f"fuzz_run {fuzz_run_path} has no log_path")

    if not raw_path:
        raise ValueError("'path' or 'fuzz_run' is required")

    return _normalize_trace_path(raw_path), fuzz_run_path, fuzz_run, related_ids


async def _extract_call_sequence(container: AuditContainer, args: dict) -> str:
    try:
        (
            path,
            fuzz_run_path,
            _fuzz_run,
            related_ids,
        ) = await _resolve_call_sequence_source(container, args)
        text, source_meta = await _read_limited_container_file(container, path)
    except (FileNotFoundError, ValueError) as exc:
        return f"Error: {exc}"

    action_space_ref = str(args.get("action_space") or "").strip()
    action_space_path = ""
    action_space = None
    if action_space_ref:
        try:
            action_space_path, action_space = await _load_action_space(
                container,
                action_space_ref,
            )
        except (FileNotFoundError, ValueError) as exc:
            return f"Error: {exc}"

    max_steps = min(max(int(args.get("max_steps", 50)), 1), 200)
    include_unmatched = bool(args.get("include_unmatched", False))
    steps, skipped_unmatched = _extract_trace_call_steps(
        text,
        max_steps=max_steps,
        action_space=action_space,
        include_unmatched=include_unmatched,
    )
    reduction = _call_sequence_reduction(steps)

    state = await _load_campaign_state(container)
    sequence_id = _next_campaign_id(state, "call_sequence")
    title = args.get("title", "").strip() or f"Extracted call sequence from {path}"
    sequence = {
        "id": sequence_id,
        "title": title,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "source": {
            "path": path,
            **source_meta,
        },
        "fuzz_run_path": fuzz_run_path or None,
        "action_space_path": action_space_path or None,
        "include_unmatched": include_unmatched,
        "max_steps": max_steps,
        "related_ids": [str(item) for item in related_ids],
        "summary": {
            "steps": len(steps),
            "replay_steps": reduction["summary"]["replay_steps"],
            "matched": sum(1 for step in steps if step["matched"]),
            "unmatched": sum(1 for step in steps if not step["matched"]),
            "skipped_unmatched": skipped_unmatched,
            "removed_noise_steps": reduction["summary"]["removed"],
            "truncated_by_limit": len(steps) >= max_steps,
        },
        "reduction": reduction,
        "steps": steps,
    }
    sequence_path = f"/workspace/campaign/sequences/{sequence_id}.json"
    await container.write_file(
        sequence_path,
        json.dumps(sequence, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Extracted call sequence: {title}",
            content=(
                f"Call sequence: {sequence_id}\n"
                f"Path: {sequence_path}\n"
                f"Source: {path}\n"
                f"Fuzz run: {fuzz_run_path or 'none'}\n"
                f"Steps: {len(steps)}\n"
                f"Replay steps: {reduction['summary']['replay_steps']}\n"
                f"Matched to action space: {sequence['summary']['matched']}\n"
                f"Skipped unmatched: {skipped_unmatched}\n"
                f"Removed noise steps: {reduction['summary']['removed']}"
            ),
            evidence=(
                [sequence_path, path]
                + ([fuzz_run_path] if fuzz_run_path else [])
                + ([action_space_path] if action_space_path else [])
            ),
            related_ids=[str(item) for item in related_ids],
            status="observed",
        )

    response = {
        "sequence_id": sequence_id,
        "path": sequence_path,
        "fuzz_run": fuzz_run_path or None,
        "result_id": result_id or None,
        "summary": sequence["summary"],
        "steps": steps[:50],
        "replay_steps": _call_sequence_replay_steps(sequence)[:50],
        "truncated_steps": max(0, len(steps) - 50),
    }
    return json.dumps(response, indent=2, sort_keys=True)


def _call_sequence_path(identifier: str) -> str:
    value = identifier.strip()
    if not value:
        raise ValueError("call_sequence cannot be empty")
    if value.startswith("/"):
        normalized = posixpath.normpath(value)
        if not normalized.startswith("/workspace/campaign/sequences/"):
            raise ValueError(
                "absolute call_sequence paths must be under "
                "/workspace/campaign/sequences/"
            )
        return normalized
    if not re.fullmatch(r"seq-\d{3,}", value):
        raise ValueError("call_sequence must be an id like seq-001 or an absolute path")
    return f"/workspace/campaign/sequences/{value}.json"


async def _load_call_sequence(
    container: AuditContainer,
    identifier: str,
) -> tuple[str, dict]:
    path = _call_sequence_path(identifier)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"call_sequence {path} is not valid JSON") from exc


def _fuzz_run_path(identifier: str) -> str:
    return _campaign_artifact_path(
        identifier,
        directory="/workspace/campaign/fuzz-runs/",
        prefix="fuzz",
        name="fuzz_run",
    )


async def _load_fuzz_run(
    container: AuditContainer,
    identifier: str,
) -> tuple[str, dict]:
    path = _fuzz_run_path(identifier)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"fuzz_run {path} is not valid JSON") from exc


def _compact_fuzz_context(path: str, fuzz_run: dict | None) -> dict | None:
    if not fuzz_run:
        return None
    return {
        "id": fuzz_run.get("id"),
        "title": fuzz_run.get("title"),
        "path": path,
        "log_path": fuzz_run.get("log_path"),
        "outcome": fuzz_run.get("outcome"),
        "summary": fuzz_run.get("summary") or {},
        "failure_snippets": [
            {
                "line": item.get("line"),
                "marker": item.get("marker"),
                "context": _truncate(str(item.get("context") or ""), 1_200),
            }
            for item in (fuzz_run.get("failure_snippets") or [])[:3]
        ],
        "next_actions": (fuzz_run.get("next_actions") or [])[:4],
    }


def _trace_args_to_sequence_args(args_text: str) -> list[str]:
    text = str(args_text or "").strip()
    while text.endswith(")"):
        text = text[:-1].strip()
    if not text:
        return []
    return _split_top_level_commas(text)


def _actions_from_call_sequence(sequence: dict) -> list[dict]:
    actions = []
    for step in _call_sequence_replay_steps(sequence):
        if not isinstance(step, dict):
            continue
        contract = str(step.get("contract") or "").strip()
        function = str(step.get("function") or "").strip()
        if not contract or not function:
            continue
        actions.append({
            "actor": "attacker",
            "contract": contract,
            "function": function,
            "args": _trace_args_to_sequence_args(str(step.get("args_text") or "")),
            "notes": (
                f"Extracted from {sequence.get('id', 'call sequence')} "
                f"line {step.get('line')}"
            ),
            "expected_effect": "replay extracted trace step",
        })
    return actions


def _safe_comment(value: object) -> str:
    text = str(value).replace("\n", " ").replace("\r", " ")
    text = text.replace("*/", "* /").strip()
    return text or "TODO"


def _step_contract_function(step: dict) -> tuple[str, str]:
    contract = str(step.get("contract") or "").strip()
    function = str(step.get("function") or "").strip()
    target = str(step.get("target") or "").strip()
    call = str(step.get("call") or "").strip()

    if not contract and "::" in target:
        contract, _, tail = target.partition("::")
        if not function:
            function = tail.split("(", 1)[0]
    if not contract and "::" in call:
        contract, _, tail = call.partition("::")
        if not function:
            function = tail.split("(", 1)[0]
    if not function:
        match = re.search(r"\b([A-Za-z_][A-Za-z0-9_]*)\s*\(", target or call)
        if match:
            function = match.group(1)
    return contract, function


def _action_match_key(contract: str, function: str) -> str:
    if contract and function:
        return f"{contract}::{function}".lower()
    return function.lower()


def _match_sequence_actions(
    action_space: dict | None,
    actions: list[dict],
) -> tuple[list[dict], list[dict]]:
    if not action_space:
        return [], []

    exact_index = {}
    function_index = {}
    for entry in action_space.get("actions", []) + action_space.get("observations", []):
        contract = str(entry.get("contract") or "")
        function = str(entry.get("function") or "")
        if not function:
            continue
        compact = {
            "contract": contract,
            "contract_kind": entry.get("contract_kind"),
            "function": function,
            "file": entry.get("file"),
            "line": entry.get("line"),
            "visibility": entry.get("visibility"),
            "affordances": entry.get("affordances", []),
            "mutability": entry.get("mutability"),
            "parameters": entry.get("parameters", []),
            "returns": entry.get("returns", ""),
            "hints": {
                key: values[:5]
                for key, values in (entry.get("hints") or {}).items()
                if values
            },
        }
        if contract:
            exact_index[_action_match_key(contract, function)] = compact
        function_index.setdefault(function.lower(), compact)

    matched = []
    unmatched = []
    for index, step in enumerate(actions, start=1):
        contract, function = _step_contract_function(step)
        if step.get("manual_only"):
            unmatched.append({
                "step": index,
                "contract": contract,
                "function": function,
                "raw": step,
            })
            continue
        match = None
        if contract and function:
            match = exact_index.get(_action_match_key(contract, function))
        if not match and function:
            match = function_index.get(function.lower())
        if match:
            matched.append({"step": index, **match})
        else:
            unmatched.append({
                "step": index,
                "contract": contract,
                "function": function,
                "raw": step,
            })
    return matched, unmatched


def _graph_action_key_variants(contract: str, function: str) -> set[str]:
    variants = set()
    if contract and function:
        variants.add(f"{contract}::{function}".lower())
        variants.add(f"{contract}.{function}".lower())
        variants.add(f"action:{contract}.{function}".lower())
    if function:
        variants.add(function.lower())
    return variants


def _compact_graph_connection(edge: dict, nodes_by_id: dict[str, dict]) -> dict:
    target = str(edge.get("target") or "")
    target_node = nodes_by_id.get(target, {})
    return {
        "edge": edge.get("kind"),
        "target": target,
        "kind": target_node.get("kind"),
        "label": target_node.get("label") or target,
    }


def _match_protocol_graph_context(
    protocol_graph: dict | None,
    actions: list[dict],
) -> list[dict]:
    if not protocol_graph:
        return []

    nodes_by_id = {
        str(node.get("id")): node
        for node in protocol_graph.get("nodes") or []
        if node.get("id")
    }
    outgoing: dict[str, list[dict]] = {}
    for edge in protocol_graph.get("edges") or []:
        source = str(edge.get("source") or "")
        if source:
            outgoing.setdefault(source, []).append(edge)

    hotspot_exact: dict[str, dict] = {}
    hotspot_by_function: dict[str, dict] = {}
    for hotspot in protocol_graph.get("hotspots") or []:
        contract = str(hotspot.get("contract") or "").strip()
        function = str(hotspot.get("function") or "").strip()
        key = str(hotspot.get("key") or "").strip()
        for variant in _graph_action_key_variants(contract, function):
            hotspot_exact.setdefault(variant, hotspot)
        if key:
            hotspot_exact.setdefault(key.lower(), hotspot)
        if function:
            hotspot_by_function.setdefault(function.lower(), hotspot)

    contexts = []
    for index, step in enumerate(actions, start=1):
        contract, function = _step_contract_function(step)
        variants = _graph_action_key_variants(contract, function)
        hotspot = next(
            (hotspot_exact[variant] for variant in variants if variant in hotspot_exact),
            None,
        )
        if not hotspot and function:
            hotspot = hotspot_by_function.get(function.lower())

        node_id = f"action:{contract}.{function}" if contract and function else ""
        node = nodes_by_id.get(node_id)
        connections = []
        if hotspot:
            connections.extend(hotspot.get("connected") or [])
        if node:
            connections.extend(
                _compact_graph_connection(edge, nodes_by_id)
                for edge in outgoing.get(node_id, [])
            )

        if not hotspot and not node and not connections:
            continue

        deduped_connections = []
        seen_connections = set()
        for item in connections:
            key = (
                str(item.get("edge") or ""),
                str(item.get("target") or ""),
                str(item.get("label") or ""),
            )
            if key in seen_connections:
                continue
            seen_connections.add(key)
            deduped_connections.append(item)

        contexts.append({
            "step": index,
            "contract": contract or (hotspot or {}).get("contract"),
            "function": function or (hotspot or {}).get("function"),
            "key": (
                (hotspot or {}).get("key")
                or (node or {}).get("label")
                or (f"{contract}::{function}" if contract and function else function)
            ),
            "node": {
                "id": (node or {}).get("id"),
                "kind": (node or {}).get("kind"),
                "tags": (node or {}).get("tags") or [],
            },
            "hotspot_score": (hotspot or {}).get("score"),
            "affordances": (
                (hotspot or {}).get("affordances")
                or (node or {}).get("tags")
                or []
            ),
            "connections": deduped_connections[:10],
        })
    return contexts


def _format_graph_context(contexts: list[dict]) -> str:
    if not contexts:
        return "- none"
    lines = []
    for item in contexts:
        score = item.get("hotspot_score")
        score_text = f", score {score}" if score is not None else ""
        affordances = ", ".join(str(label) for label in item.get("affordances") or [])
        lines.append(
            f"- Step {item.get('step')}: `{item.get('key')}`{score_text}"
            + (f" [{affordances}]" if affordances else "")
        )
        for connection in item.get("connections") or []:
            edge = connection.get("edge") or "edge"
            label = connection.get("label") or connection.get("target") or "target"
            lines.append(f"  - {edge}: {label}")
    return "\n".join(lines)


def _format_fuzz_context(fuzz_context: dict | None) -> str:
    if not fuzz_context:
        return "- none"
    fuzz_id = fuzz_context.get("id") or "unknown"
    lines = [
        f"- Fuzz run: `{fuzz_id}` {fuzz_context.get('title') or ''}".rstrip(),
        f"- Outcome: `{fuzz_context.get('outcome') or 'unknown'}`",
        f"- Run artifact: `{fuzz_context.get('path')}`",
        f"- Full log: `{fuzz_context.get('log_path')}`",
    ]
    if fuzz_context.get("load_error"):
        lines.append(f"- Load warning: {fuzz_context.get('load_error')}")
    for item in fuzz_context.get("failure_snippets") or []:
        marker = item.get("marker") or "candidate marker"
        lines.append(f"- Snippet line {item.get('line')}: {marker}")
        context = str(item.get("context") or "").strip()
        if context:
            lines.append("```text")
            lines.append(context)
            lines.append("```")
    next_actions = fuzz_context.get("next_actions") or []
    if next_actions:
        lines.append("Suggested reduction steps:")
        lines.extend(f"- {item}" for item in next_actions)
    return "\n".join(lines)


def _graph_context_edge_kinds(graph_context: list[dict]) -> set[str]:
    return {
        str(connection.get("edge") or "")
        for item in graph_context
        for connection in (item.get("connections") or [])
        if str(connection.get("edge") or "").strip()
    }


def _dedupe_text(items: list[str]) -> list[str]:
    seen = set()
    result = []
    for item in items:
        text = str(item or "").strip()
        if not text or text in seen:
            continue
        seen.add(text)
        result.append(text)
    return result


def _sequence_replay_validation_plan(
    *,
    objective: str,
    success_condition: str,
    actions: list[dict],
    observations: list[dict],
    matched_actions: list[dict],
    graph_context: list[dict],
    fork_context: dict | None,
    attack_graph_path: str,
    attack_graph_candidate: dict | None,
    call_sequence_path: str,
    fuzz_context: dict | None,
    target_addresses: dict,
) -> dict:
    affordances = {
        str(label)
        for item in matched_actions + graph_context
        for label in (item.get("affordances") or [])
        if str(label).strip()
    }
    graph_edge_kinds = _graph_context_edge_kinds(graph_context)
    source = (
        "attack_graph_candidate"
        if attack_graph_candidate
        else _sequence_replay_source(call_sequence_path, fuzz_context)
    )

    snapshot_prompts = [
        "Capture attacker, user, and target contract balances before and after the sequence.",
        (
            "Capture protocol accounting totals before and after: total assets, "
            "total supply, reserves, debt, shares, collateral, or the closest "
            "equivalent exposed state."
        ),
        "Save the full execution log/trace and the concrete calldata values used for each step.",
    ]
    if {"value_in_or_mint", "value_out_or_burn", "token_or_native_transfer"} & affordances:
        snapshot_prompts.append(
            "Probe asset and share deltas for the attacker, protocol, pools, and vaults."
        )
    if "credit_or_liquidation" in affordances:
        snapshot_prompts.append(
            "Probe collateral, debt, health factor, liquidation bonus, and bad-debt deltas."
        )
    if {"valuation_dependency", "market_or_router"} & affordances:
        snapshot_prompts.append(
            "Record oracle answers, pool reserves, TWAP/freshness data, and route outputs."
        )
    if {
        "external_call",
        "delegatecall",
        "generic_execution",
        "callback_or_flashloan_surface",
    } & affordances:
        snapshot_prompts.append(
            "Summarize external calls, callbacks, delegate calls, reentrancy points, and revert paths."
        )
    if {"signed_authorization", "signature_gate", "signature_input"} & affordances:
        snapshot_prompts.append(
            "Record nonce, deadline, domain separator, signer, spender, and replay state."
        )
    if "cross_domain_or_message" in affordances:
        snapshot_prompts.append(
            "Record message ids, proof state, replay guards, bridge accounting, and finalization status."
        )
    if {"modifier_gated", "sender_or_role_checked"} & affordances:
        snapshot_prompts.append(
            "Record sender, role, owner/admin, and permission assumptions for each gated call."
        )
    if "accepts_native_value" in affordances:
        snapshot_prompts.append(
            "Track native asset balances and msg.value-sensitive accounting before and after."
        )

    observation_labels = [
        str(item.get("label") or item.get("target") or "").strip()
        for item in observations
        if isinstance(item, dict)
    ]
    if observation_labels:
        snapshot_prompts.append(
            "Mirror explicit observations in the scaffold: "
            + ", ".join(_dedupe_text(observation_labels)[:8])
            + "."
        )
    if graph_context:
        snapshot_prompts.append(
            "Use matched protocol-graph state, event, and value-flow hints to choose storage and event probes."
        )
    if attack_graph_candidate:
        snapshot_prompts.append(
            "Resolve attack-graph live blockers and assert deployed target code before collecting objective evidence."
        )
        snapshot_prompts.extend(
            str(item)
            for item in attack_graph_candidate.get("planning_notes") or []
            if str(item).strip()
        )
        snapshot_prompts.extend(
            str(item)
            for item in attack_graph_candidate.get("required_live_evidence") or []
            if str(item).strip()
        )
    if "reads_oracle_input" in graph_edge_kinds:
        snapshot_prompts.append(
            "For oracle-read graph edges, record exact oracle answer, decimals, freshness, adapter address, and whether the target uses spot or windowed data."
        )
    if "routes_through_router" in graph_edge_kinds:
        snapshot_prompts.append(
            "For router graph edges, record route input/output amounts, recipient, slippage controls, pool reserves, and any callback recipient."
        )
    if "handles_bridge_or_message" in graph_edge_kinds:
        snapshot_prompts.append(
            "For bridge/message graph edges, record message id, source/destination domain, proof/replay state, and bridge accounting before finalization."
        )
    if "has_callback_surface_hint" in graph_edge_kinds:
        snapshot_prompts.append(
            "For callback graph edges, capture caller, callback selector, pre/post state around the external call, and whether state is finalized before callback execution."
        )
    if "checks_authorization_binding" in graph_edge_kinds:
        snapshot_prompts.append(
            "For authorization graph edges, record signer/sender, nonce, deadline, domain, role source, and every execution-critical field bound by the check."
        )
    if "calls_cross_contract_dependency" in graph_edge_kinds:
        snapshot_prompts.append(
            "For cross-contract dependency graph edges, record the concrete dependency address and return values used by the sequence."
        )

    objective_prompts = [
        (
            "Turn the objective into concrete numeric assertions for profit, protocol loss, "
            "bad debt, accounting drift, unauthorized state change, or permanent lock."
        ),
        "Evaluate net attacker gain after initial funding, repayments, fees, and leftover balances.",
        "Treat trace-only or harness-only failures as leads until they produce a concrete state delta.",
    ]
    if success_condition:
        objective_prompts.append(
            f"Initial assertion target from success_condition: {success_condition.strip()}"
        )
    elif objective:
        objective_prompts.append(
            f"Initial assertion target from objective: {objective.strip()}"
        )

    mutation_prompts = [
        "If replay does not reproduce, compare actor, order, amount, msg.value, and approvals against the source sequence.",
        "Check missing fork setup before changing the hypothesis: block, deployed addresses, token balances, oracle/pool state, and impersonated actors.",
        "Try bounded amount and actor variations around the extracted calldata before widening the campaign.",
        "If no economic or authorization impact appears, record the result and mutate toward the nearest value-flow or trust-boundary branch.",
    ]
    if fuzz_context:
        mutation_prompts.insert(
            0,
            "Compare the reduced replay against the candidate fuzz snippet and full fuzz log before treating divergence as a negative result.",
        )
    if attack_graph_candidate:
        mutation_prompts.insert(
            0,
            "If the attack-graph candidate is gated, dormant, or not deployed on the fork, reject it or add a concrete bypass hypothesis before mutating calldata.",
        )

    return {
        "source": source,
        "attack_graph": attack_graph_path or None,
        "attack_graph_candidate": (
            {
                "candidate_id": attack_graph_candidate.get("candidate_id"),
                "attack_key": attack_graph_candidate.get("attack_key"),
                "exposure": attack_graph_candidate.get("exposure"),
                "live_status": attack_graph_candidate.get("live_status"),
                "blockers": attack_graph_candidate.get("blockers") or [],
            }
            if attack_graph_candidate
            else None
        ),
        "recommended_tool_order": [
            "run_experiment",
            "summarize_trace",
            "snapshot_state",
            "compare_snapshots",
            "evaluate_objective",
            "review_finding_evidence",
        ],
        "requires_fork_setup": bool(fork_context or target_addresses),
        "graph_edge_kinds": sorted(graph_edge_kinds),
        "snapshot_prompts": _dedupe_text(snapshot_prompts),
        "objective_prompts": _dedupe_text(objective_prompts),
        "mutation_prompts": _dedupe_text(mutation_prompts),
        "notes": [
            "These prompts guide evidence collection; they are not proof until the scaffold contains concrete assertions and saved logs.",
            "Prefer one reduced replay with strong before/after evidence over many weak variants.",
        ],
    }


def _sequence_replay_source(call_sequence_path: str, fuzz_context: dict | None) -> str:
    if fuzz_context:
        return "fuzz_failure_replay"
    if call_sequence_path:
        return "call_sequence_replay"
    return "manual_sequence"


def _sequence_setup_challenge(
    *,
    kind: str,
    target: str,
    source: str,
    challenge: str,
    retain_if: str,
    example: str = "",
) -> dict:
    item = {
        "kind": kind,
        "target": target,
        "source": source,
        "challenge": challenge,
        "retain_if": retain_if,
    }
    if example:
        item["example"] = example
    return item


def _sequence_setup_reduction_plan(
    *,
    actions: list[dict],
    setup: str,
    fork_setup_guide: dict | None,
    token_setup_plan: dict,
    target_addresses: dict,
) -> dict:
    challenges = []
    seen = set()

    def add(item: dict) -> None:
        key = (item.get("kind"), item.get("target"), item.get("source"))
        if key in seen:
            return
        seen.add(key)
        challenges.append(item)

    if target_addresses:
        add(_sequence_setup_challenge(
            kind="target_binding",
            target="bound targets",
            source="target_addresses",
            challenge=(
                "Confirm every bound address is the exact protocol component used "
                "by the exploit path; remove unused bindings from the variant."
            ),
            retain_if=(
                "Retain a binding if the sequence calls it directly or snapshots "
                "its state for objective evidence."
            ),
        ))

    actors = _dedupe_text([
        str(step.get("actor") or "attacker")
        for step in actions
        if isinstance(step, dict)
    ])
    for actor in actors[:6]:
        add(_sequence_setup_challenge(
            kind="prank_scope",
            target=actor,
            source="sequence_actions",
            challenge=(
                "Use the narrowest prank/sender scope that still preserves the "
                "objective; do not keep broad multi-actor setup by default."
            ),
            retain_if=(
                "Retain the actor if authorization, balances, callbacks, or "
                "ordering depend on that sender."
            ),
        ))

    for token in (token_setup_plan.get("tokens") or [])[:8]:
        label = str(token.get("label") or token.get("symbol") or token.get("address") or "token")
        add(_sequence_setup_challenge(
            kind="balance_seed",
            target=label,
            source="token_setup_helper",
            challenge=(
                "Reduce seeded balances and actor set to the minimum capital that "
                "still preserves the objective marker and economic delta."
            ),
            retain_if=(
                "Retain enough balance for real protocol preconditions, flash-loan "
                "repayment, fees, and expected profit measurement."
            ),
        ))
    for token in (token_setup_plan.get("tokens") or [])[:4]:
        token_label = str(token.get("label") or token.get("symbol") or token.get("address") or "token")
        for spender in (token_setup_plan.get("spenders") or [])[:6]:
            spender_label = str(spender.get("label") or spender.get("address") or "spender")
            add(_sequence_setup_challenge(
                kind="approval",
                target=f"{token_label}->{spender_label}",
                source="token_setup_helper",
                challenge=(
                    "Approve only the exact spender and amount needed by the "
                    "preserved variant; avoid blanket approvals unless required "
                    "by the protocol path."
                ),
                retain_if=(
                    "Retain approval if a transferFrom/pull-based step fails "
                    "without it."
                ),
            ))

    task_prompts = {
        "fork_selection": (
            "Keep the fork block fixed while reducing sequence/setup; vary the "
            "block only as a separate freshness or market-state experiment.",
            "Retain if the proof depends on live deployed state or historical balances.",
        ),
        "balance_seed": (
            "Reduce or remove this seed after proving which actor actually needs capital.",
            "Retain if the objective fails due to insufficient real capital, fees, or repayments.",
        ),
        "approval": (
            "Tighten spender and amount, then rerun the variant with the same objective marker.",
            "Retain if the protocol pull path reverts or changes behavior without it.",
        ),
        "impersonation": (
            "Replace impersonation with a generated actor unless the exploit premise requires that fork account.",
            "Retain only when the real account role/balance is part of the vulnerability evidence.",
        ),
        "market_state": (
            "Snapshot reserves and remove market manipulation/setup that is not needed by the reduced objective.",
            "Retain if reserve state, route liquidity, or price impact is part of the exploit mechanism.",
        ),
        "oracle_state": (
            "Separate oracle freshness/answer setup from the sequence reduction and prove whether it is needed.",
            "Retain if valuation reads are part of the invariant violation.",
        ),
        "flash_liquidity": (
            "Challenge borrowed amount, fee, callback, and repayment assumptions before claiming profit.",
            "Retain if the sequence is only profitable or reachable with borrowed capital.",
        ),
        "assumption": (
            "Validate this assumption or turn it into an explicit report limitation before preserving the variant.",
            "Retain if direct fork/test evidence confirms it or the report clearly scopes it.",
        ),
    }
    for task in (fork_setup_guide or {}).get("tasks") or []:
        kind = str(task.get("kind") or "setup")
        if kind not in task_prompts:
            continue
        challenge, retain_if = task_prompts[kind]
        add(_sequence_setup_challenge(
            kind=kind,
            target=str(task.get("target") or kind),
            source="fork_setup_guide",
            challenge=challenge,
            retain_if=retain_if,
            example=str(task.get("example") or ""),
        ))

    setup_text = setup.lower()
    if any(word in setup_text for word in ("mock", "fake", "stub")):
        add(_sequence_setup_challenge(
            kind="mock_or_stub",
            target="manual setup",
            source="setup",
            challenge=(
                "Replace mocks/stubs with fork or concrete protocol state when "
                "possible, or prove the mock models the relevant behavior exactly."
            ),
            retain_if=(
                "Retain only if the target cannot compile/run without the mock and "
                "the report states that limitation."
            ),
        ))

    return {
        "strategy": "setup_assumption_delta_debug_v1",
        "challenge_items": challenges[:24],
        "baseline_rules": [
            "Change only one setup assumption at a time after the baseline objective marker is stable.",
            "Keep target bindings and fork block fixed while reducing transaction steps unless that assumption is the experiment.",
            "When setup is reduced, rerun the baseline or selected variant before comparing profit or state deltas.",
        ],
        "stop_conditions": [
            "Restore a setup item if removing it changes the exploit mechanism or invalidates the objective evidence.",
            "Record irreducible setup assumptions as report assumptions or limitations.",
        ],
        "summary": {
            "challenge_items": len(challenges[:24]),
            "balances": sum(1 for item in challenges[:24] if item["kind"] == "balance_seed"),
            "approvals": sum(1 for item in challenges[:24] if item["kind"] == "approval"),
            "pranks": sum(1 for item in challenges[:24] if item["kind"] == "prank_scope"),
            "fork_assumptions": sum(
                1 for item in challenges[:24]
                if item["kind"] in {
                    "fork_selection",
                    "market_state",
                    "oracle_state",
                    "flash_liquidity",
                    "assumption",
                }
            ),
        },
    }


def _sequence_minimization_plan(
    *,
    actions: list[dict],
    objective: str,
    success_condition: str,
    setup: str,
    call_sequence_path: str,
    fuzz_context: dict | None,
    fork_setup_guide: dict | None,
    token_setup_plan: dict,
    target_addresses: dict,
) -> dict:
    step_count = len(actions)
    variants = []
    max_step_variants = 8
    if step_count > 1:
        for end in range(1, min(step_count, 4)):
            variants.append({
                "id": f"prefix-{end:03d}",
                "kind": "prefix",
                "steps": list(range(1, end + 1)),
                "purpose": (
                    "Check whether the objective already appears before the "
                    "full sequence completes."
                ),
            })
        for index in range(1, min(step_count, max_step_variants) + 1):
            kept_steps = [step for step in range(1, step_count + 1) if step != index]
            variants.append({
                "id": f"drop-step-{index:03d}",
                "kind": "drop_step",
                "remove_step": index,
                "steps": kept_steps,
                "purpose": (
                    "Check whether this step is necessary for the same objective "
                    "delta or failure."
                ),
            })
    parameter_names = _sequence_action_arg_names(actions)
    if parameter_names:
        variants.append({
            "id": "parameter-sweep-001",
            "kind": "parameter_sweep",
            "parameters": parameter_names[:8],
            "steps": list(range(1, step_count + 1)),
            "purpose": (
                "Find smaller or boundary values that preserve the same impact "
                "while reducing capital and harness assumptions."
            ),
        })
    if not variants:
        variants.append({
            "id": "baseline-tighten-001",
            "kind": "tighten_assertions",
            "steps": list(range(1, step_count + 1)),
            "purpose": (
                "Keep the full sequence, but replace broad logs with the minimal "
                "state assertions needed to prove the objective."
            ),
        })
    assertion_target = success_condition.strip() or objective.strip()
    return {
        "strategy": "deterministic_sequence_delta_debug_v1",
        "source": _sequence_replay_source(call_sequence_path, fuzz_context),
        "baseline": {
            "steps": step_count,
            "preserve_order": True,
            "first_run": (
                "Run the unmodified sequence once with before/after snapshots and "
                "objective evaluation before testing variants."
            ),
        },
        "assertion_target": assertion_target or "define objective state delta",
        "variants": variants[:12],
        "setup_reduction": _sequence_setup_reduction_plan(
            actions=actions,
            setup=setup,
            fork_setup_guide=fork_setup_guide,
            token_setup_plan=token_setup_plan,
            target_addresses=target_addresses,
        ),
        "stop_conditions": [
            "Keep a variant only if it preserves the same concrete objective delta, revert, or invariant failure.",
            "Prefer the shortest passing variant with the fewest seeded balances, approvals, pranks, and mocked assumptions.",
            "If all variants fail, record the baseline as irreducible for this evidence path and mutate the hypothesis.",
        ],
        "notes": [
            "This is a reduction guide for the LLM; it does not prove semantic equivalence by itself.",
            "Do not remove setup that is required by real fork state unless the replacement is explicitly justified.",
        ],
    }


def _format_sequence_minimization_plan(plan: dict | None) -> str:
    if not plan:
        return "- none"
    lines = [
        f"- Strategy: `{plan.get('strategy') or 'manual'}`",
        f"- Source: `{plan.get('source') or 'sequence'}`",
        f"- Baseline steps: `{(plan.get('baseline') or {}).get('steps', 0)}`",
        f"- Assertion target: {plan.get('assertion_target') or 'define objective'}",
        "",
        "Variants:",
    ]
    for variant in (plan.get("variants") or [])[:12]:
        steps = ", ".join(str(step) for step in variant.get("steps") or [])
        label = variant.get("id") or variant.get("kind") or "variant"
        test_name = _sequence_minimization_test_name(str(label))
        lines.append(
            f"- `{label}` / {variant.get('kind')}: `{test_name}`; steps [{steps}] - "
            f"{variant.get('purpose')}"
        )
        if variant.get("parameters"):
            lines.append(
                "  - Parameters: "
                + ", ".join(f"`{item}`" for item in variant.get("parameters") or [])
            )
    setup_reduction = plan.get("setup_reduction") or {}
    setup_items = setup_reduction.get("challenge_items") or []
    if setup_items:
        lines.append("")
        lines.append("Setup assumptions to challenge:")
        for item in setup_items[:12]:
            label = item.get("target") or item.get("kind") or "setup"
            lines.append(
                f"- `{item.get('kind')}` / {label}: {item.get('challenge')}"
            )
            retain_if = str(item.get("retain_if") or "").strip()
            if retain_if:
                lines.append(f"  - Retain if: {retain_if}")
        baseline_rules = setup_reduction.get("baseline_rules") or []
        if baseline_rules:
            lines.append("")
            lines.append("Setup reduction rules:")
            lines.extend(f"- {item}" for item in baseline_rules[:4])
    stop_conditions = plan.get("stop_conditions") or []
    if stop_conditions:
        lines.append("")
        lines.append("Stop conditions:")
        lines.extend(f"- {item}" for item in stop_conditions)
    return "\n".join(lines)


def _sequence_minimization_function_suffix(variant_id: str) -> str:
    return _solidity_identifier(variant_id, "variant")


def _sequence_minimization_test_name(variant_id: str) -> str:
    return f"test_{_sequence_minimization_function_suffix(variant_id)}"


def _sequence_minimization_runner_name(variant_id: str) -> str:
    return f"_run_{_sequence_minimization_function_suffix(variant_id)}"


def _sequence_step_runner_name(step_index: int) -> str:
    return f"_runStep{step_index:03d}"


def _sequence_minimization_command_templates(
    *,
    artifact_id: str,
    experiment_dir: str,
    plan: dict,
) -> dict:
    marker_placeholder = "REPLACE_WITH_OBJECTIVE_MARKER"
    variants = []
    for variant in (plan.get("variants") or [])[:12]:
        variant_id = str(variant.get("id") or variant.get("kind") or "").strip()
        if not variant_id:
            continue
        variants.append({
            "variant_id": variant_id,
            "kind": variant.get("kind"),
            "command": (
                "forge test --match-test "
                f"{_sequence_minimization_test_name(variant_id)} -vvv"
            ),
            "expected_markers": [marker_placeholder],
            "notes": (
                "Replace expected_markers with concrete objective evidence emitted "
                "by this variant and remove the generated vm.skip(true) before "
                "calling run_sequence_minimization."
            ),
        })
    setup_checks = []
    for index, item in enumerate(
        ((plan.get("setup_reduction") or {}).get("challenge_items") or [])[:12],
        start=1,
    ):
        kind = str(item.get("kind") or "setup").strip()
        target = str(item.get("target") or kind).strip()
        check_id = _slugify(f"setup-{kind}-{target}") or f"setup-check-{index:03d}"
        setup_checks.append({
            "check_id": check_id,
            "kind": kind,
            "target": target,
            "change": item.get("challenge") or "change one setup assumption",
            "retain_if": item.get("retain_if") or "",
            "command": "REPLACE_WITH_SETUP_CHECK_COMMAND",
            "expected_markers": [marker_placeholder],
            "notes": (
                "After a baseline or selected variant preserves the objective, "
                "edit the harness or command to change only this setup assumption. "
                "Keep it only if the objective marker fails or the exploit "
                "mechanism changes without it."
            ),
        })
    return {
        "tool": "run_sequence_minimization",
        "working_dir": experiment_dir,
        "sequence": artifact_id,
        "baseline": {
            "command": "forge test --match-test test_sequence_experiment -vvv",
            "expected_markers": [marker_placeholder],
            "notes": (
                "Replace expected_markers with objective evidence from the baseline "
                "run, such as OBJECTIVE_PASS or a concrete emitted delta marker."
            ),
        },
        "variants": variants,
        "setup_checks": setup_checks,
        "notes": [
            "This is a template, not a finished minimization run.",
            "Do not keep a variant unless it preserves the same objective marker and state delta as the baseline.",
            "Generated variant tests start with vm.skip(true); remove it only after filling the variant-specific assertions.",
            "Fill setup_checks only after the baseline or selected variant preserves objective evidence.",
        ],
    }


def _format_replay_validation_plan(plan: dict | None) -> str:
    if not plan:
        return "- none"
    lines = [
        f"- Source: `{plan.get('source') or 'sequence_experiment'}`",
        "- Recommended tool order: "
        + ", ".join(
            f"`{tool}`" for tool in (plan.get("recommended_tool_order") or [])
        ),
        f"- Requires fork setup: `{bool(plan.get('requires_fork_setup'))}`",
        "",
        "Snapshot prompts:",
    ]
    lines.extend(f"- {item}" for item in plan.get("snapshot_prompts") or [])
    lines.append("")
    lines.append("Objective prompts:")
    lines.extend(f"- {item}" for item in plan.get("objective_prompts") or [])
    lines.append("")
    lines.append("Mutation prompts:")
    lines.extend(f"- {item}" for item in plan.get("mutation_prompts") or [])
    notes = plan.get("notes") or []
    if notes:
        lines.append("")
        lines.append("Notes:")
        lines.extend(f"- {item}" for item in notes)
    return "\n".join(lines)


def _sequence_route_affordances(
    *,
    objective: str,
    setup: str,
    actions: list[dict],
    matched_actions: list[dict],
    graph_context: list[dict],
) -> set[str]:
    labels = {
        str(label)
        for item in matched_actions + graph_context
        for label in (item.get("affordances") or [])
        if str(label).strip()
    }
    graph_edge_kinds = _graph_context_edge_kinds(graph_context)
    if "reads_oracle_input" in graph_edge_kinds:
        labels.add("valuation_dependency")
    if "routes_through_router" in graph_edge_kinds:
        labels.add("market_or_router")
    if "has_callback_surface_hint" in graph_edge_kinds:
        labels.add("callback_or_flashloan_surface")
    haystack = _coverage_normalize_text(" ".join(
        [
            objective,
            setup,
            *[
                f"{step.get('contract', '')} {step.get('function', '')} "
                f"{step.get('target', '')} {step.get('call', '')}"
                for step in actions
                if isinstance(step, dict)
            ],
        ]
    ))
    if any(term in haystack for term in ("oracle", "price", "twap", "feed")):
        labels.add("valuation_dependency")
    if any(term in haystack for term in ("swap", "router", "route", "pool")):
        labels.add("market_or_router")
    if any(term in haystack for term in ("flash", "callback")):
        labels.add("callback_or_flashloan_surface")
    if any(term in haystack for term in ("borrow", "debt", "collateral", "liquidat")):
        labels.add("credit_or_liquidation")
    return labels


def _sequence_route_targets(fork_context: dict | None, collection: str) -> list[dict]:
    return [
        _fork_compact_item(item)
        for item in (fork_context or {}).get(collection) or []
        if isinstance(item, dict)
    ][:6]


def _sequence_action_source_key(item: dict) -> str:
    contract = str(item.get("contract") or "").strip()
    function = str(item.get("function") or "").strip()
    if contract and function:
        return f"{contract}::{function}"
    return function


def _sequence_source_hints(
    matched_actions: list[dict],
    hint_group: str,
    *,
    dedupe_fields: tuple[str, ...],
    output_fields: tuple[str, ...],
    field_defaults: dict[str, object] | None = None,
    limit: int = 12,
) -> list[dict]:
    hints = []
    seen = set()
    defaults = field_defaults or {}
    for item in matched_actions:
        action_key = _sequence_action_source_key(item)
        for hint in ((item.get("hints") or {}).get(hint_group) or []):
            if not isinstance(hint, dict):
                continue
            key = (action_key, *(hint.get(field) for field in dedupe_fields))
            if key in seen:
                continue
            seen.add(key)
            entry = {"action": action_key}
            for field in output_fields:
                value = hint.get(field)
                if value in (None, "") and field in defaults:
                    value = defaults[field]
                if isinstance(value, list):
                    value = list(value)
                entry[field] = value
            hints.append(entry)
    return hints[:limit]


def _sequence_economic_parameter_hints(matched_actions: list[dict]) -> list[dict]:
    return _sequence_source_hints(
        matched_actions,
        "economic_parameters",
        dedupe_fields=("line", "parameter", "text"),
        output_fields=("line", "parameter", "value_hint", "text"),
    )


def _sequence_callback_surface_hints(matched_actions: list[dict]) -> list[dict]:
    return _sequence_source_hints(
        matched_actions,
        "callback_surfaces",
        dedupe_fields=("line", "surface", "selector_hint", "text"),
        output_fields=("line", "surface", "selector_hint", "text"),
    )


def _sequence_router_call_hints(matched_actions: list[dict]) -> list[dict]:
    return _sequence_source_hints(
        matched_actions,
        "router_calls",
        dedupe_fields=("line", "target", "selector_hint", "text"),
        output_fields=(
            "line",
            "target",
            "selector_hint",
            "matched_term",
            "approval_spender",
            "calldata_roles",
            "path_terms",
            "validation_prompts",
            "text",
        ),
        field_defaults={
            "calldata_roles": {},
            "path_terms": [],
            "validation_prompts": [],
        },
    )


def _sequence_route_economics_context(
    affordances: set[str],
    economics_context: dict | None,
) -> dict | None:
    if not economics_context:
        return None
    branch_context = _plan_branch_economics_context(
        sorted(affordances),
        economics_context,
    )
    flash_context = _plan_flash_loan_context(sorted(affordances), economics_context)
    if branch_context and flash_context and branch_context.get("kind") != "flash_loan":
        branch_context = dict(branch_context)
        branch_context["flash_loan"] = flash_context
    return branch_context or flash_context


def _route_source_paths(context: dict | None) -> list[str]:
    return [
        str(item.get("path"))
        for item in (context or {}).get("artifacts") or []
        if item.get("path")
    ]


def _route_asset_ref(value: object) -> str:
    if isinstance(value, dict):
        for key in ("address", "asset", "token", "symbol", "label", "name"):
            text = str(value.get(key) or "").strip()
            if text:
                return text
        return ""
    return str(value or "").strip()


def _route_pool_asset_refs(pool: dict) -> list[str]:
    refs = []
    for key in (
        "token0",
        "token1",
        "token_in",
        "token_out",
        "asset0",
        "asset1",
        "base",
        "quote",
    ):
        value = _route_asset_ref(pool.get(key))
        if value:
            refs.append(value)
    pair = str(pool.get("pair") or pool.get("label") or "").strip()
    if not refs and "/" in pair:
        refs.extend(part.strip() for part in pair.split("/") if part.strip())
    return _dedupe_text(refs)


def _route_token_matches_ref(token: dict, ref: str) -> bool:
    ref_key = ref.strip().lower()
    if not ref_key:
        return False
    for key in ("address", "asset", "token", "symbol", "label", "name"):
        value = str(token.get(key) or "").strip().lower()
        if value and value == ref_key:
            return True
    return False


def _route_pool_assets(pool: dict, tokens: list[dict]) -> list[dict]:
    assets = []
    for ref in _route_pool_asset_refs(pool):
        match = next(
            (token for token in tokens if _route_token_matches_ref(token, ref)),
            None,
        )
        assets.append(match or {"label": ref})
    return assets[:4]


def _route_tokens_by_terms(tokens: list[dict], terms: tuple[str, ...]) -> list[dict]:
    matches = []
    for token in tokens:
        haystack = _coverage_normalize_text(" ".join(
            str(token.get(key) or "")
            for key in ("label", "name", "symbol", "role", "kind", "notes")
        ))
        if any(term in haystack for term in terms):
            matches.append(token)
    return matches


def _route_candidate_label(item: dict) -> str:
    for key in ("label", "name", "symbol", "kind"):
        value = str(item.get(key) or "").strip()
        if value:
            return value
    return _route_asset_ref(item) or "candidate"


def _route_candidate_assets(items: list[dict], *, fallback: list[dict]) -> list[dict]:
    candidates = items or fallback
    return [_fork_compact_item(item) for item in candidates[:4]]


def _route_asset_display(item: object) -> str:
    if isinstance(item, dict):
        for key in ("symbol", "label", "name", "address", "asset", "token"):
            value = str(item.get(key) or "").strip()
            if value:
                return value
    return str(item or "").strip()


def _route_router_hint_parts(hint: dict) -> dict:
    if not isinstance(hint, dict):
        return {}
    target = str(hint.get("target") or "router").strip()
    selector = str(
        hint.get("selector_hint")
        or hint.get("matched_term")
        or "call"
    ).strip()
    if not selector:
        return {}
    terms = [
        str(item).strip()
        for item in hint.get("path_terms") or []
        if str(item).strip()
    ]
    roles = {
        str(key): str(value)
        for key, value in (hint.get("calldata_roles") or {}).items()
        if str(key).strip() and str(value).strip()
    }
    prompts = [
        str(item).strip()
        for item in hint.get("validation_prompts") or []
        if str(item).strip()
    ]
    return {
        "action": str(hint.get("action") or "source").strip() or "source",
        "target": target,
        "selector": selector,
        "terms": _dedupe_text(terms),
        "roles": roles,
        "spender": str(hint.get("approval_spender") or "").strip(),
        "line": hint.get("line"),
        "validation_prompts": prompts,
    }


def _route_router_hint_summary(hint: dict) -> str:
    parts = _route_router_hint_parts(hint)
    if not parts:
        return ""
    label = (
        f"{parts['target']}.{parts['selector']}"
        if parts["target"]
        else parts["selector"]
    )
    if parts["spender"]:
        label += f" spender {parts['spender']}"
    if parts["roles"]:
        role_text = ", ".join(
            f"{key}={value}" for key, value in list(parts["roles"].items())[:6]
        )
        label += " roles " + role_text
    if parts["terms"]:
        label += " fields " + ", ".join(parts["terms"][:6])
    if parts["line"]:
        label += f" line {parts['line']}"
    return label


def _route_router_hint_summaries(route: dict, *, limit: int = 3) -> list[str]:
    return _dedupe_text([
        summary
        for hint in route.get("source_router_hints") or []
        if isinstance(hint, dict)
        for summary in [_route_router_hint_summary(hint)]
        if summary
    ])[:limit]


def _route_unwind_candidate_summary(candidate: dict) -> str:
    if not isinstance(candidate, dict):
        return ""
    label = str(candidate.get("label") or candidate.get("kind") or "").strip()
    if not label:
        return ""
    parts = []
    pool = candidate.get("pool")
    if isinstance(pool, dict):
        pool_label = _route_candidate_label(pool)
        if pool_label:
            parts.append(f"pool {pool_label}")
    provider = candidate.get("provider")
    if isinstance(provider, dict):
        provider_label = _route_candidate_label(provider)
        if provider_label:
            parts.append(f"provider {provider_label}")
    router = candidate.get("router")
    if isinstance(router, dict):
        router_label = _route_candidate_label(router)
        if router_label:
            parts.append(f"router {router_label}")
    for key, title in (
        ("assets", "assets"),
        ("repay_asset_candidates", "repay"),
        ("seized_asset_candidates", "seized"),
    ):
        labels = []
        for item in candidate.get(key) or []:
            item_label = _route_asset_display(item)
            if item_label:
                labels.append(item_label)
        if labels:
            parts.append(f"{title} {', '.join(_dedupe_text(labels)[:4])}")
    if not parts:
        return label
    return f"{label} ({'; '.join(parts[:4])})"


def _route_unwind_candidate_summaries(route: dict, *, limit: int = 3) -> list[str]:
    return _dedupe_text([
        summary
        for candidate in route.get("unwind_candidates") or []
        if isinstance(candidate, dict)
        for summary in [_route_unwind_candidate_summary(candidate)]
        if summary
    ])[:limit]


def _sequence_unwind_route_candidates(
    *,
    kind: str,
    fork_context: dict | None,
) -> list[dict]:
    tokens = [
        _fork_compact_item(item)
        for item in (fork_context or {}).get("tokens") or []
        if isinstance(item, dict)
    ][:8]
    pools = [
        _fork_compact_item(item)
        for item in (fork_context or {}).get("pools") or []
        if isinstance(item, dict)
    ][:8]
    routers = [
        _fork_compact_item(item)
        for item in (fork_context or {}).get("routers") or []
        if isinstance(item, dict)
    ][:6]
    providers = [
        _fork_compact_item(item)
        for item in (fork_context or {}).get("flash_loan_providers") or []
        if isinstance(item, dict)
    ][:6]

    candidates = []
    if kind == "amm_or_valuation_route":
        for pool in pools[:4]:
            label = _route_candidate_label(pool)
            candidates.append({
                "kind": "pool_unwind_route",
                "label": f"pool unwind via {label}",
                "pool": pool,
                "assets": _route_pool_assets(pool, tokens),
                "direction_prompt": (
                    "validate token ordering and test both manipulation and unwind "
                    "directions unless the sequence fixes input/output"
                ),
                "evidence_prompts": [
                    "snapshot pool reserves and attacker balances before manipulation, after manipulation, and after unwind",
                    "measure route input/output, slippage, fees, and final attacker profit after restoring or exiting the position",
                ],
            })
        for router in routers[:3]:
            label = _route_candidate_label(router)
            candidates.append({
                "kind": "router_unwind_route",
                "label": f"router unwind via {label}",
                "router": router,
                "assets": _route_candidate_assets([], fallback=tokens),
                "missing_context": ["router token path, direction, and calldata"],
                "direction_prompt": (
                    "derive the exact token path, approval spender, amount in/out, "
                    "deadline, and slippage limit before treating this as executable"
                ),
                "evidence_prompts": [
                    "snapshot router input/output token balances, allowance, quoted output, slippage, and final attacker balance",
                    "compare direct pool unwind and router unwind where both routes exist",
                ],
            })
        if not candidates and tokens:
            candidates.append({
                "kind": "manual_unwind_route",
                "label": "manual unwind route from known fork tokens",
                "assets": [_fork_compact_item(item) for item in tokens[:4]],
                "missing_context": ["pool or router target for unwind"],
                "direction_prompt": "identify the concrete market or router before treating this as executable",
            })
        return candidates[:4]

    if kind == "flash_loan_route":
        for provider in providers[:4]:
            provider_asset = _route_asset_ref(provider.get("asset") or provider.get("token"))
            asset = next(
                (token for token in tokens if _route_token_matches_ref(token, provider_asset)),
                None,
            )
            label = _route_candidate_label(provider)
            candidates.append({
                "kind": "flash_repayment_route",
                "label": f"repayment route for {label}",
                "provider": provider,
                "repay_asset_candidates": _route_candidate_assets(
                    [asset] if asset else [],
                    fallback=tokens,
                ),
                "direction_prompt": (
                    "prove borrowed asset, premium asset, approval spender, and "
                    "repayment transfer for this provider"
                ),
                "evidence_prompts": [
                    "snapshot borrowed asset balance, premium, allowance, provider balance, and callback state before and after repayment",
                    "measure post-unwind attacker balance after premium and route fees",
                ],
            })
        return candidates[:4]

    if kind == "liquidation_credit_route":
        repay_assets = _route_tokens_by_terms(
            tokens,
            ("debt", "borrow", "repay", "loan"),
        )
        seized_assets = _route_tokens_by_terms(
            tokens,
            ("collateral", "seized", "supply"),
        )
        for pool in pools[:4]:
            label = _route_candidate_label(pool)
            candidates.append({
                "kind": "seized_collateral_unwind_route",
                "label": f"seized collateral unwind via {label}",
                "pool": pool,
                "pool_assets": _route_pool_assets(pool, tokens),
                "repay_asset_candidates": _route_candidate_assets(
                    repay_assets,
                    fallback=tokens,
                ),
                "seized_asset_candidates": _route_candidate_assets(
                    seized_assets,
                    fallback=tokens,
                ),
                "direction_prompt": (
                    "validate which asset is repaid, which collateral is seized, "
                    "and whether this pool can unwind seized collateral into the repay asset"
                ),
                "evidence_prompts": [
                    "snapshot borrower collateral/debt, seized collateral, liquidator balances, and protocol reserves before and after liquidation",
                    "measure seized-collateral unwind output, route fees, flash fees, bad debt, and net liquidator profit",
                ],
            })
        for router in routers[:3]:
            label = _route_candidate_label(router)
            candidates.append({
                "kind": "router_seized_collateral_unwind_route",
                "label": f"seized collateral router unwind via {label}",
                "router": router,
                "repay_asset_candidates": _route_candidate_assets(
                    repay_assets,
                    fallback=tokens,
                ),
                "seized_asset_candidates": _route_candidate_assets(
                    seized_assets,
                    fallback=tokens,
                ),
                "missing_context": ["router token path for seized collateral into repay asset"],
                "direction_prompt": (
                    "derive seized-asset input, repay-asset output, approval spender, "
                    "slippage, deadline, and whether the route can repay any flash capital"
                ),
                "evidence_prompts": [
                    "snapshot seized collateral, router output, repay asset balance, route fees, and net liquidator profit",
                    "compare router unwind output with any direct pool route and liquidation bonus",
                ],
            })
        if not candidates and tokens:
            candidates.append({
                "kind": "manual_liquidation_unwind_route",
                "label": "manual liquidation unwind from known fork tokens",
                "repay_asset_candidates": _route_candidate_assets(
                    repay_assets,
                    fallback=tokens,
                ),
                "seized_asset_candidates": _route_candidate_assets(
                    seized_assets,
                    fallback=tokens,
                ),
                "missing_context": ["pool or router target for seized collateral unwind"],
            })
        return candidates[:4]

    return []


# --- Scaffold-route filter (proposal §4.5) -------------------------------------
#
# A sequence experiment scaffold dumps a TODO-style checklist for every route
# that the affordance classifier matches. For a Hypervisor::uniswapV3MintCallback
# access-control test, this surfaced AMM and flash-loan prompts that drowned
# the agent's real exploit logic — the affordance classifier (correctly) flags
# the contract surface, but the agent's actual intent is a sender-check test
# and route prompts only add noise.
#
# The filter is intentionally a single binary decision: does the objective
# CLEARLY describe a non-economic test? If yes, every route prompt is omitted
# from the rendered .t.sol (the audit trail in sequence.json and README still
# carries the full plan, so nothing is hidden). Otherwise we keep every matched
# route — the legacy behaviour — because the cost of dropping a relevant route
# silently is higher than the cost of an extra TODO checklist.
#
# Word-boundary matching prevents contract names like ``uniswapV3MintCallback``
# from contributing an "economic" signal just because they happen to contain
# ``swap`` or ``callback`` as substrings.
#
# Agent override: pass ``force_route_kinds=[<route_kind>, ...]`` to compose
# _sequence_experiment to re-include specific route prompts in the scaffold
# even when the classifier said the objective is non-economic.

_SEQUENCE_NON_ECONOMIC_TERMS = (
    # Access control
    "must revert",
    "should revert",
    "expects revert",
    "expectrevert",
    "unauthorized",
    "not authorized",
    "auth bypass",
    "access control",
    "sender check",
    "only owner",
    "onlyowner",
    "permission check",
    "role bypass",
    "modifier bypass",
    # Reentrancy
    "reentrant",
    "reentrance",
    "reentrancy",
    "nonreentrant",
    "non-reentrant",
    "reentry",
    # Cross-chain / bridge replay
    "cross-chain replay",
    "bridge replay",
    "message replay",
)

_SEQUENCE_ECONOMIC_TERMS = (
    "flash",
    "loan",
    "liquidate",
    "liquidation",
    "liquidations",
    "liquidator",
    "liquidating",
    "oracle",
    "twap",
    "swap",
    "router",
    "amm",
    "borrow",
    "bridge exploit",
    "ccip",
    "layerzero",
    "mev",
    "frontrun",
    "front-run",
    "sandwich",
    "first depositor",
    "first-depositor",
    "share inflation",
    "donation attack",
)


def _sequence_route_filter_haystack(
    *,
    objective: str,
    success_condition: str,
    actions: list[dict],
) -> str:
    parts = [objective or "", success_condition or ""]
    for step in actions or []:
        if not isinstance(step, dict):
            continue
        for key in ("expected_effect", "objective", "notes"):
            value = step.get(key)
            if isinstance(value, str) and value.strip():
                parts.append(value)
    return _coverage_normalize_text(" ".join(parts))


def _haystack_has_term(haystack: str, term: str) -> bool:
    """Return True iff ``term`` appears as a whole word/phrase in ``haystack``.

    Word boundaries matter so that ``swap`` matches ``"swap exploit"`` but not
    ``"uniswap"`` — i.e. a function name containing an economic substring does
    not by itself count as an economic signal.
    """
    if not term or not haystack:
        return False
    pattern = rf"\b{re.escape(term)}\b"
    return bool(re.search(pattern, haystack))


def _objective_clearly_non_economic(
    *,
    objective: str,
    success_condition: str,
    actions: list[dict],
) -> bool:
    """Conservative classifier driving the scaffold route filter.

    Returns True only when the agent-supplied haystack contains an explicit
    non-economic signal (access control, reentrancy, message replay) AND no
    economic signal. False positives are safe (we just keep all routes —
    legacy behaviour); a False negative just means the agent sees a few extra
    TODO lines they can ignore. Either case is recoverable; silently dropping
    a route the agent needs is not, so we err strongly toward returning False.
    """
    haystack = _sequence_route_filter_haystack(
        objective=objective,
        success_condition=success_condition,
        actions=actions,
    )
    if not haystack:
        return False
    has_non_economic = any(
        _haystack_has_term(haystack, term)
        for term in _SEQUENCE_NON_ECONOMIC_TERMS
    )
    if not has_non_economic:
        return False
    has_economic = any(
        _haystack_has_term(haystack, term)
        for term in _SEQUENCE_ECONOMIC_TERMS
    )
    return not has_economic


def _normalize_force_route_kinds(value: object) -> set[str]:
    if not value:
        return set()
    if isinstance(value, str):
        value = [value]
    valid_kinds = {
        "amm_or_valuation_route",
        "oracle_window_route",
        "flash_loan_route",
        "liquidation_credit_route",
    }
    return {
        item for item in (str(entry).strip() for entry in value or [])
        if item in valid_kinds
    }


def _sequence_route_composition_plan(
    *,
    objective: str,
    setup: str,
    actions: list[dict],
    matched_actions: list[dict],
    graph_context: list[dict],
    fork_context: dict | None,
    economics_context: dict | None,
    success_condition: str = "",
    force_route_kinds: set[str] | None = None,
) -> dict:
    affordances = _sequence_route_affordances(
        objective=objective,
        setup=setup,
        actions=actions,
        matched_actions=matched_actions,
        graph_context=graph_context,
    )
    routes = []
    source_parameter_hints = _sequence_economic_parameter_hints(matched_actions)
    source_callback_hints = _sequence_callback_surface_hints(matched_actions)
    source_router_hints = _sequence_router_call_hints(matched_actions)

    if affordances.intersection({"valuation_dependency", "market_or_router"}):
        route_affordances = sorted(
            affordances.intersection({"valuation_dependency", "market_or_router"}),
        )
        route_context = _sequence_route_economics_context(
            set(route_affordances),
            economics_context,
        )
        routes.append({
            "kind": "amm_or_valuation_route",
            "title": "AMM/valuation route composition",
            "affordances": route_affordances,
            "fork_targets": {
                "pools": _sequence_route_targets(fork_context, "pools"),
                "routers": _sequence_route_targets(fork_context, "routers"),
                "oracles": _sequence_route_targets(fork_context, "oracles"),
            },
            "economics_context": route_context,
            "source_artifacts": _route_source_paths(route_context),
            "source_parameter_hints": source_parameter_hints,
            "source_router_hints": source_router_hints,
            "unwind_candidates": _sequence_unwind_route_candidates(
                kind="amm_or_valuation_route",
                fork_context=fork_context,
            ),
            "setup_prompts": [
                "bind the concrete pool, router, oracle adapter, and target reader used by the sequence",
                "use the AMM estimate to choose starting swap amount, route legs, token ordering, fee tier, and expected price movement",
                "hold fork block fixed while testing spot, stale, and window-boundary valuation variants",
            ],
            "evidence_prompts": [
                "snapshot pool reserves, oracle answer/freshness, route input/output, and target valuation before and after",
                "evaluate whether modeled capital, slippage, fees, and unwind output still leave attacker profit",
            ],
            "suggested_tools": (
                [] if route_context else ["estimate_amm_economics"]
            ),
            "missing_context": (
                [] if route_context else ["linked AMM economics estimate"]
            ),
        })

    if "valuation_dependency" in affordances:
        routes.append({
            "kind": "oracle_window_route",
            "title": "Oracle freshness/window route",
            "affordances": ["valuation_dependency"],
            "fork_targets": {
                "oracles": _sequence_route_targets(fork_context, "oracles"),
            },
            "setup_prompts": _plan_oracle_window_checks(["valuation_dependency"]),
            "source_parameter_hints": source_parameter_hints,
            "evidence_prompts": [
                "record answer, decimals, updatedAt/timestamp, heartbeat, bounds, adapter/cache, and update authority",
                "compare target valuation under spot, stale, and window-boundary states on the same fork block",
            ],
            "suggested_tools": [],
            "missing_context": (
                [] if _sequence_route_targets(fork_context, "oracles")
                else ["fork oracle target"]
            ),
        })

    if "callback_or_flashloan_surface" in affordances:
        route_context = _plan_flash_loan_context(
            sorted(affordances),
            economics_context,
        )
        routes.append({
            "kind": "flash_loan_route",
            "title": "Flash-loan/callback route composition",
            "affordances": ["callback_or_flashloan_surface"],
            "fork_targets": {
                "providers": _sequence_route_targets(
                    fork_context,
                    "flash_loan_providers",
                ),
                "tokens": _sequence_route_targets(fork_context, "tokens"),
            },
            "economics_context": route_context,
            "source_artifacts": _route_source_paths(route_context),
            "source_parameter_hints": source_parameter_hints,
            "source_callback_hints": source_callback_hints,
            "source_router_hints": source_router_hints,
            "unwind_candidates": _sequence_unwind_route_candidates(
                kind="flash_loan_route",
                fork_context=fork_context,
            ),
            "setup_prompts": _plan_flash_loan_checks(
                ["callback_or_flashloan_surface"],
            ),
            "evidence_prompts": [
                "snapshot borrowed balance, premium, approvals, callback state, repayment, provider balance, and post-unwind attacker balance",
                "prove whether protected state is finalized before or after callback execution",
            ],
            "suggested_tools": (
                [] if route_context else ["estimate_flash_loan"]
            ),
            "missing_context": (
                [] if route_context else ["linked flash-loan estimate"]
            ),
        })

    if "credit_or_liquidation" in affordances:
        route_context = _sequence_route_economics_context(
            {"credit_or_liquidation"},
            economics_context,
        )
        routes.append({
            "kind": "liquidation_credit_route",
            "title": "Liquidation/credit route composition",
            "affordances": ["credit_or_liquidation"],
            "fork_targets": {
                "tokens": _sequence_route_targets(fork_context, "tokens"),
                "oracles": _sequence_route_targets(fork_context, "oracles"),
                "pools": _sequence_route_targets(fork_context, "pools"),
                "routers": _sequence_route_targets(fork_context, "routers"),
            },
            "economics_context": route_context,
            "source_artifacts": _route_source_paths(route_context),
            "source_parameter_hints": source_parameter_hints,
            "source_router_hints": source_router_hints,
            "unwind_candidates": _sequence_unwind_route_candidates(
                kind="liquidation_credit_route",
                fork_context=fork_context,
            ),
            "setup_prompts": [
                "use the lending health estimate to choose just-above and just-below-threshold borrower states",
                *_plan_liquidation_route_checks(["credit_or_liquidation"]),
            ],
            "evidence_prompts": [
                "snapshot borrower collateral/debt, liquidator balances, seized collateral, protocol reserves, and bad-debt accounting before and after",
                "evaluate net liquidator profit after repay asset cost, bonus, protocol fee, flash fee, and unwind slippage",
            ],
            "suggested_tools": (
                [] if route_context else ["estimate_lending_health"]
            ),
            "missing_context": (
                [] if route_context else ["linked lending health estimate"]
            ),
        })

    forced = _normalize_force_route_kinds(force_route_kinds)
    is_non_economic = _objective_clearly_non_economic(
        objective=objective,
        success_condition=success_condition,
        actions=actions,
    )
    omitted_kinds: list[str] = []
    for route in routes:
        kind = str(route.get("kind") or "")
        if kind in forced:
            keep = True
        else:
            keep = not is_non_economic
        route["omit_in_scaffold"] = not keep
        if not keep:
            omitted_kinds.append(kind)
    routes_in_scaffold = len(routes) - len(omitted_kinds)

    notes = [
        "This is a route-composition prompt for the LLM, not a protocol-specific simulator.",
        "Validate every address, selector, fee, threshold, and return value on fork before treating the sequence as evidence.",
    ]
    if omitted_kinds:
        notes.append(
            f"Scaffold suppressed {len(omitted_kinds)} route prompt(s) "
            f"({', '.join(sorted(set(omitted_kinds)))}) because the objective "
            "reads as non-economic (access control / reentrancy / replay). "
            "Pass force_route_kinds=[...] to compose_sequence_experiment if a "
            "suppressed route is actually relevant."
        )

    return {
        "strategy": "llm_route_composition_v1",
        "affordances": sorted(affordances),
        "objective_classified_non_economic": is_non_economic,
        "force_route_kinds": sorted(forced),
        "routes": routes,
        "summary": {
            "routes": len(routes),
            "routes_in_scaffold": routes_in_scaffold,
            "routes_omitted_in_scaffold": len(omitted_kinds),
            "omitted_route_kinds": sorted(set(omitted_kinds)),
            "objective_classified_non_economic": is_non_economic,
            "with_economics_context": sum(
                1 for route in routes if route.get("economics_context")
            ),
            "suggested_tools": sorted({
                tool
                for route in routes
                for tool in route.get("suggested_tools") or []
            }),
            "missing_context": sorted({
                item
                for route in routes
                for item in route.get("missing_context") or []
            }),
            "unwind_candidates": sum(
                len(route.get("unwind_candidates") or [])
                for route in routes
            ),
        },
        "notes": notes,
    }


def _format_callback_attacker_plan(plan: dict | None) -> str:
    plan = plan or {}
    if not plan.get("enabled"):
        return (
            "- none (no callback surface, attacker-contract actor, or "
            "callback metadata detected)"
        )
    lines = [
        f"- Attacker contract: `{plan.get('attacker_contract') or 'CallbackAttacker'}`",
        "- Kinds: " + ", ".join(f"`{kind}`" for kind in plan.get("kinds") or []),
    ]
    entrypoints = plan.get("entrypoints") or []
    if entrypoints:
        lines.append(
            "- Entrypoints: "
            + ", ".join(f"`{signature}`" for signature in entrypoints)
        )
    routed = plan.get("routed_steps") or []
    if routed:
        lines.append(
            "- Routed steps (pranked as `address(callbackAttacker)`): "
            + ", ".join(str(index) for index in routed)
        )
    blockers = plan.get("blockers") or []
    if blockers:
        lines.append("- Blockers: " + ", ".join(f"`{item}`" for item in blockers))
    for note in plan.get("notes") or []:
        lines.append(f"- Note: {note}")
    return "\n".join(lines)


def _format_route_composition_plan(plan: dict | None) -> str:
    routes = (plan or {}).get("routes") or []
    if not routes:
        return "- none"
    lines = [
        f"- Strategy: `{(plan or {}).get('strategy') or 'manual'}`",
        "- Affordances: "
        + ", ".join(f"`{item}`" for item in (plan or {}).get("affordances") or []),
    ]
    for route in routes:
        lines.append("")
        lines.append(f"### {route.get('title') or route.get('kind')}")
        lines.append(f"- Kind: `{route.get('kind')}`")
        source_artifacts = route.get("source_artifacts") or []
        if source_artifacts:
            lines.append(
                "- Source artifacts: "
                + ", ".join(f"`{path}`" for path in source_artifacts[:6])
            )
        economics = route.get("economics_context") or {}
        if economics:
            summary = {
                key: value
                for key, value in economics.items()
                if key not in {"artifacts", "flash_loan"} and value not in (None, "", [], {})
            }
            if summary:
                lines.append(f"- Economics context: `{json.dumps(summary, sort_keys=True)}`")
        missing = route.get("missing_context") or []
        if missing:
            lines.append("- Missing context: " + ", ".join(missing))
        unwind_candidates = route.get("unwind_candidates") or []
        if unwind_candidates:
            lines.append("- Unwind candidates:")
            for candidate in unwind_candidates[:4]:
                label = candidate.get("label") or candidate.get("kind") or "route"
                lines.append(f"  - `{label}`")
                pool = candidate.get("pool") or {}
                if pool:
                    lines.append(
                        "    - Pool/router: "
                        + (
                            pool.get("label")
                            or pool.get("name")
                            or pool.get("pair")
                            or pool.get("address")
                            or "unknown"
                        )
                    )
                provider = candidate.get("provider") or {}
                if provider:
                    lines.append(
                        "    - Provider: "
                        + (
                            provider.get("label")
                            or provider.get("name")
                            or provider.get("provider")
                            or provider.get("address")
                            or "unknown"
                        )
                    )
                router = candidate.get("router") or {}
                if router:
                    lines.append(
                        "    - Router: "
                        + (
                            router.get("label")
                            or router.get("name")
                            or router.get("router")
                            or router.get("address")
                            or "unknown"
                        )
                    )
                for asset_key, title in (
                    ("assets", "Assets"),
                    ("repay_asset_candidates", "Repay asset candidates"),
                    ("seized_asset_candidates", "Seized asset candidates"),
                ):
                    assets = candidate.get(asset_key) or []
                    if assets:
                        lines.append(
                            f"    - {title}: "
                            + ", ".join(
                                "`"
                                + (
                                    item.get("symbol")
                                    or item.get("label")
                                    or item.get("name")
                                    or item.get("address")
                                    or item.get("asset")
                                    or "asset"
                                )
                                + "`"
                                for item in assets[:4]
                                if isinstance(item, dict)
                            )
                        )
                direction = str(candidate.get("direction_prompt") or "").strip()
                if direction:
                    lines.append(f"    - Direction: {direction}")
        parameter_hints = route.get("source_parameter_hints") or []
        if parameter_hints:
            lines.append("- Source parameter hints:")
            for hint in parameter_hints[:5]:
                parameter = hint.get("parameter") or "parameter"
                action = hint.get("action") or "source"
                value = (
                    f" = {hint.get('value_hint')}"
                    if hint.get("value_hint") not in (None, "")
                    else ""
                )
                line = f":{hint.get('line')}" if hint.get("line") else ""
                lines.append(f"  - `{action}{line}` `{parameter}{value}`")
        callback_hints = route.get("source_callback_hints") or []
        if callback_hints:
            lines.append("- Source callback hints:")
            for hint in callback_hints[:5]:
                action = hint.get("action") or "source"
                surface = hint.get("surface") or "callback"
                selector = (
                    f" selector `{hint.get('selector_hint')}`"
                    if hint.get("selector_hint")
                    else ""
                )
                line = f":{hint.get('line')}" if hint.get("line") else ""
                lines.append(f"  - `{action}{line}` `{surface}`{selector}")
        router_hints = route.get("source_router_hints") or []
        if router_hints:
            lines.append("- Source router hints:")
            for hint in router_hints[:5]:
                parts = _route_router_hint_parts(hint)
                if not parts:
                    continue
                suffix = (
                    "; fields "
                    + ", ".join(f"`{term}`" for term in parts["terms"][:6])
                    if parts["terms"]
                    else ""
                )
                if parts["roles"]:
                    suffix += "; roles " + ", ".join(
                        f"`{key}={value}`"
                        for key, value in list(parts["roles"].items())[:6]
                    )
                if parts["spender"]:
                    suffix += f"; approval spender `{parts['spender']}`"
                line = f":{parts['line']}" if parts["line"] else ""
                lines.append(
                    f"  - `{parts['action']}{line}` "
                    f"`{parts['target']}.{parts['selector']}`{suffix}"
                )
                for prompt in parts["validation_prompts"][:3]:
                    lines.append(f"    - Validate: {prompt}")
        suggested = route.get("suggested_tools") or []
        if suggested:
            lines.append("- Suggested tools: " + ", ".join(f"`{tool}`" for tool in suggested))
        setup_prompts = route.get("setup_prompts") or []
        if setup_prompts:
            lines.append("- Setup prompts:")
            lines.extend(f"  - {item}" for item in setup_prompts[:6])
        evidence_prompts = route.get("evidence_prompts") or []
        if evidence_prompts:
            lines.append("- Evidence prompts:")
            lines.extend(f"  - {item}" for item in evidence_prompts[:6])
    return "\n".join(lines)


def _route_composition_contract_comments(plan: dict | None) -> str:
    routes = (plan or {}).get("routes") or []
    if not routes:
        return ""
    visible_routes = [
        route for route in routes
        if isinstance(route, dict) and not route.get("omit_in_scaffold")
    ]
    # Sort + dedupe so the surfaced names are deterministic for testing and
    # so the agent's force_route_kinds example is always in a stable order.
    omitted_kinds = sorted({
        _safe_comment(route.get("kind") or "route")
        for route in routes
        if isinstance(route, dict) and route.get("omit_in_scaffold")
    })
    omitted_names = ", ".join(omitted_kinds)
    omitted_json_array = ", ".join(f'"{kind}"' for kind in omitted_kinds)
    if not visible_routes:
        # Case A: every matched route was suppressed. Name them inline and
        # give the agent a fully populated force_route_kinds example so the
        # override does not require opening README.md or sequence.json.
        return (
            f"        // Route composition prompts suppressed for {len(omitted_kinds)} matched route(s):\n"
            f"        //   {omitted_names}\n"
            "        // (objective reads as non-economic — access control / reentrancy / replay).\n"
            f"        // Pass force_route_kinds=[{omitted_json_array}]\n"
            "        // to compose_sequence_experiment if any suppressed route is actually relevant."
        )
    lines = [
        "        // Route composition prompts. Convert relevant items into concrete fork setup before relying on this run.",
    ]
    for route in visible_routes[:4]:
        kind = _safe_comment(route.get("kind") or "route")
        title = _safe_comment(route.get("title") or kind)
        lines.append(f"        // - [{kind}] {title}")
        for prompt in (route.get("setup_prompts") or [])[:3]:
            lines.append(f"        //   Setup: {_safe_comment(prompt)}")
        for hint in (route.get("source_parameter_hints") or [])[:3]:
            parameter = _safe_comment(hint.get("parameter") or "parameter")
            value = _safe_comment(hint.get("value_hint") or "")
            suffix = f" = {value}" if value else ""
            lines.append(f"        //   Source hint: {parameter}{suffix}")
        for hint in (route.get("source_callback_hints") or [])[:3]:
            surface = _safe_comment(hint.get("surface") or "callback")
            selector = _safe_comment(hint.get("selector_hint") or "")
            suffix = f" selector {selector}" if selector else ""
            lines.append(f"        //   Callback hint: {surface}{suffix}")
        for hint in (route.get("source_router_hints") or [])[:3]:
            parts = _route_router_hint_parts(hint)
            if not parts:
                continue
            target = _safe_comment(parts["target"])
            selector = _safe_comment(parts["selector"])
            role_suffix = ""
            if parts["roles"]:
                role_suffix = " roles " + _safe_comment(
                    ", ".join(
                        f"{key}={value}"
                        for key, value in list(parts["roles"].items())[:5]
                    )
                )
            spender = _safe_comment(parts["spender"])
            spender_suffix = f" spender {spender}" if spender else ""
            lines.append(
                f"        //   Router hint: {target}.{selector}"
                f"{spender_suffix}{role_suffix}"
            )
            for prompt in parts["validation_prompts"][:3]:
                lines.append(f"        //   Router validation: {_safe_comment(prompt)}")
        for candidate in (route.get("unwind_candidates") or [])[:2]:
            label = _safe_comment(
                candidate.get("label")
                or candidate.get("kind")
                or "unwind candidate"
            )
            lines.append(f"        //   Unwind: {label}")
        for prompt in (route.get("evidence_prompts") or [])[:2]:
            lines.append(f"        //   Evidence: {_safe_comment(prompt)}")
    if omitted_kinds:
        # Case B: the agent re-included some routes via force_route_kinds but
        # others remain suppressed. Surface the dropped kinds inline so the
        # partial filter is never silent — the agent must not be able to
        # forget that AMM/oracle/flash/liquidation context exists if it is
        # relevant to the actual exploit chain.
        lines.append(
            f"        // (also suppressed for non-economic objective: {omitted_names};\n"
            f"        //  pass force_route_kinds=[{omitted_json_array}] to include any)"
        )
    return "\n".join(lines)


def _fork_compact_item(item: dict) -> dict:
    compact = {}
    for key in (
        "label",
        "name",
        "symbol",
        "kind",
        "role",
        "address",
        "target",
        "pair",
        "provider",
        "asset",
        "token",
        "token0",
        "token1",
        "tokens",
        "token_in",
        "token_out",
        "token_path",
        "path",
        "asset0",
        "asset1",
        "base",
        "quote",
        "router",
        "spender",
        "approval_spender",
        "fee",
        "fee_bps",
        "fee_tier",
        "decimals",
        "price_usd",
        "notes",
    ):
        value = item.get(key)
        if value not in (None, "", [], {}):
            compact[key] = value
    return compact


def _fork_context_metadata(fork_context: dict | None) -> dict | None:
    if not fork_context:
        return None
    metadata = {
        "id": fork_context.get("id"),
        "title": fork_context.get("title"),
        "network": fork_context.get("network"),
        "chain_id": fork_context.get("chain_id"),
        "fork_block": fork_context.get("fork_block"),
        "target_addresses": fork_context.get("target_addresses") or {},
        "assumptions": fork_context.get("assumptions") or [],
        "summary": fork_context.get("summary") or {},
    }
    for collection in _FORK_CONTEXT_COLLECTIONS:
        metadata[collection] = [
            _fork_compact_item(item)
            for item in (fork_context.get(collection) or [])[:25]
            if isinstance(item, dict)
        ]
    return metadata


def _fork_setup_actor_labels(fork_context: dict | None) -> list[str]:
    if not fork_context:
        return ["attacker", "user", "keeper"]
    labels = [
        _context_label(item, f"actor_{index}")
        for index, item in enumerate(fork_context.get("actors") or [], start=1)
        if isinstance(item, dict)
    ]
    return labels[:5] or ["attacker", "user", "keeper"]


def _fork_setup_spenders(target_addresses: dict | None, fork_context: dict | None) -> list[dict]:
    spenders = []
    token_addresses = {
        _context_address(item).lower()
        for item in (fork_context or {}).get("tokens") or []
        if isinstance(item, dict) and _context_address(item)
    }
    for label, address in (target_addresses or {}).items():
        text = str(address or "").strip()
        if not text or text.lower() in token_addresses:
            continue
        spenders.append({"label": str(label), "address": text})
    return spenders[:6]


def _fork_setup_token_tasks(
    fork_context: dict,
    *,
    actor_labels: list[str],
    spenders: list[dict],
) -> list[dict]:
    tasks = []
    for index, token in enumerate(fork_context.get("tokens") or [], start=1):
        if not isinstance(token, dict):
            continue
        label = _context_label(token, f"token_{index}")
        address = _context_address(token) or "<token>"
        decimals = token.get("decimals", "unknown")
        actors_text = ", ".join(actor_labels)
        tasks.append({
            "kind": "balance_seed",
            "target": label,
            "prompt": (
                f"Seed {label} balances for relevant actors ({actors_text}) "
                f"before executing value-moving steps. Decimals: {decimals}."
            ),
            "example": f"deal({address}, attacker, DEFAULT_AMOUNT);",
        })
        if spenders:
            spender_text = ", ".join(item["label"] for item in spenders[:3])
            tasks.append({
                "kind": "approval",
                "target": label,
                "prompt": (
                    f"Approve only the contracts that the sequence actually "
                    f"needs to pull {label}; likely candidates: {spender_text}."
                ),
                "example": (
                    f"vm.prank(attacker); IERC20({address}).approve("
                    f"{spenders[0]['address']}, DEFAULT_AMOUNT);"
                ),
            })
    return tasks


def _fork_setup_actor_tasks(fork_context: dict) -> list[dict]:
    tasks = []
    for index, actor in enumerate(fork_context.get("actors") or [], start=1):
        if not isinstance(actor, dict):
            continue
        label = _context_label(actor, f"actor_{index}")
        address = _context_address(actor)
        role = actor.get("role") or actor.get("kind") or "actor"
        if address:
            tasks.append({
                "kind": "impersonation",
                "target": label,
                "prompt": (
                    f"Use {label} ({role}) only if the experiment requires "
                    "that real fork account; otherwise prefer generated test actors."
                ),
                "example": f"vm.startPrank({address}); ... vm.stopPrank();",
            })
        else:
            tasks.append({
                "kind": "actor",
                "target": label,
                "prompt": f"Create or bind a test actor for role {role}.",
                "example": f'address {label} = makeAddr("{label}");',
            })
    return tasks


def _fork_setup_market_tasks(fork_context: dict) -> list[dict]:
    tasks = []
    for collection, kind, prompt in (
        (
            "pools",
            "market_state",
            "Snapshot reserves and liquidity before the sequence; if the branch manipulates price, model the trade path explicitly.",
        ),
        (
            "routers",
            "market_state",
            "Confirm router code, approval spender, path encoding, slippage/deadline controls, and recipient before treating route calldata as executable.",
        ),
        (
            "oracles",
            "oracle_state",
            "Record current answer, decimals, freshness, and update rules before relying on oracle-dependent assertions.",
        ),
        (
            "flash_loan_providers",
            "flash_liquidity",
            "Confirm liquidity, fee, callback shape, and repayment before treating borrowed capital as available.",
        ),
    ):
        for index, item in enumerate(fork_context.get(collection) or [], start=1):
            if not isinstance(item, dict):
                continue
            label = _context_label(item, f"{collection}_{index}")
            address = _context_address(item) or "unknown address"
            tasks.append({
                "kind": kind,
                "target": label,
                "prompt": prompt,
                "example": f"snapshot_state probe target: {label} at {address}",
            })
    return tasks


def _fork_probe_target(address: str, label: str) -> str:
    concrete = _solidity_address_literal(address)
    if concrete:
        return concrete
    return f"<{label} address>"


def _fork_probe_base_item(item: dict, fallback: str) -> dict:
    label = _context_label(item, fallback)
    address = _context_address(item)
    base = {
        "label": label,
        "target": _fork_probe_target(address, label),
    }
    if address:
        base["address_hint"] = address
    for key in ("kind", "notes"):
        value = item.get(key)
        if value not in (None, "", [], {}):
            base[key] = value
    return base


def _fork_probe_templates(fork_context: dict | None) -> dict | None:
    if not fork_context:
        return None
    templates: dict[str, list[dict]] = {
        collection: [] for collection in _FORK_PROBE_COLLECTIONS
    }
    for index, pool in enumerate(fork_context.get("pools") or [], start=1):
        if not isinstance(pool, dict):
            continue
        entry = _fork_probe_base_item(pool, f"pool_{index}")
        entry["snapshot_state_inputs"] = [{
            "label": f"{entry['label']} reserves",
            "target": entry["target"],
            "call": "getReserves()(uint112,uint112,uint32)",
            "notes": (
                "UniswapV2-style pools only; replace this for concentrated-liquidity, "
                "lending, or custom market contracts."
            ),
        }]
        entry["manual_checks"] = [
            "Confirm token ordering and decimals before interpreting reserve deltas.",
            "If the branch manipulates price, model the swap path and fee path explicitly.",
        ]
        templates["pools"].append(entry)

    for index, router in enumerate(fork_context.get("routers") or [], start=1):
        if not isinstance(router, dict):
            continue
        entry = _fork_probe_base_item(router, f"router_{index}")
        entry["probe_prompts"] = [{
            "label": f"{entry['label']} route calldata",
            "target": entry["target"],
            "prompt": (
                "Verify router code, selector, approval spender, token path, "
                "recipient, deadline, and slippage controls before replaying "
                "or unwinding through this router."
            ),
        }]
        entry["manual_checks"] = [
            "Confirm the exact router interface and calldata shape for this fork block.",
            "Snapshot input/output token balances and allowance around any router route.",
        ]
        templates["routers"].append(entry)

    for index, oracle in enumerate(fork_context.get("oracles") or [], start=1):
        if not isinstance(oracle, dict):
            continue
        entry = _fork_probe_base_item(oracle, f"oracle_{index}")
        entry["snapshot_state_inputs"] = [
            {
                "label": f"{entry['label']} latest round",
                "target": entry["target"],
                "call": "latestRoundData()(uint80,int256,uint256,uint256,uint80)",
                "notes": "Chainlink-style feeds only; replace for TWAPs, push oracles, or custom adapters.",
            },
            {
                "label": f"{entry['label']} decimals",
                "target": entry["target"],
                "call": "decimals()(uint8)",
                "notes": "Use with the answer scale before comparing economic deltas.",
            },
        ]
        entry["manual_checks"] = [
            "Confirm heartbeat, freshness, bounds, and update authority before relying on the answer.",
            "Verify the target contract reads this feed or adapter, not merely a similarly named oracle.",
        ]
        templates["oracles"].append(entry)

    for index, provider in enumerate(
        fork_context.get("flash_loan_providers") or [],
        start=1,
    ):
        if not isinstance(provider, dict):
            continue
        entry = _fork_probe_base_item(provider, f"flash_provider_{index}")
        entry["probe_prompts"] = [{
            "label": f"{entry['label']} liquidity and callback",
            "target": entry["target"],
            "prompt": (
                "Verify liquidity, fee, callback shape, and repayment path before "
                "treating borrowed capital as available."
            ),
        }]
        entry["manual_checks"] = [
            "Confirm the intended borrowed asset and available liquidity at the fork block.",
            "Confirm repayment token, fee calculation, initiator checks, and callback selector.",
        ]
        templates["flash_loan_providers"].append(entry)

    if not any(templates.values()):
        return None
    return templates


def _fork_probe_template_summary(templates: dict | None) -> dict:
    return {
        **{
            collection: len((templates or {}).get(collection) or [])
            for collection in _FORK_PROBE_COLLECTIONS
        },
        "probe_templates": sum(
            len((templates or {}).get(collection) or [])
            for collection in _FORK_PROBE_COLLECTIONS
        ),
    }


def _fork_setup_guide(
    fork_context: dict | None,
    target_addresses: dict | None = None,
) -> dict | None:
    if not fork_context:
        return None
    actor_labels = _fork_setup_actor_labels(fork_context)
    spenders = _fork_setup_spenders(target_addresses, fork_context)
    tasks = [
        {
            "kind": "fork_selection",
            "target": "fork",
            "prompt": (
                "_selectFork only selects chain state. It does not seed "
                "balances, approvals, impersonation, oracle updates, pool "
                "reserves, or flash-loan callbacks."
            ),
            "example": "_selectFork();",
        }
    ]
    tasks.extend(_fork_setup_actor_tasks(fork_context))
    tasks.extend(_fork_setup_token_tasks(
        fork_context,
        actor_labels=actor_labels,
        spenders=spenders,
    ))
    tasks.extend(_fork_setup_market_tasks(fork_context))
    assumptions = [
        str(item) for item in fork_context.get("assumptions") or []
    ]
    for assumption in assumptions[:8]:
        tasks.append({
            "kind": "assumption",
            "target": "campaign",
            "prompt": assumption,
            "example": "Validate this assumption before interpreting the run.",
        })
    return {
        "summary": {
            "actors": len(actor_labels),
            "tokens": len(fork_context.get("tokens") or []),
            "spenders": len(spenders),
            **{
                collection: len(fork_context.get(collection) or [])
                for collection in _FORK_PROBE_COLLECTIONS
            },
            "tasks": len(tasks),
        },
        "actors": actor_labels,
        "spenders": spenders,
        "tasks": tasks,
    }


def _fork_setup_task_lines(guide: dict | None, *, max_tasks: int = 18) -> list[str]:
    if not guide:
        return []
    lines = []
    for task in (guide.get("tasks") or [])[:max_tasks]:
        label = task.get("target") or task.get("kind") or "setup"
        lines.append(f"- `{task.get('kind')}` / {label}: {task.get('prompt')}")
        example = str(task.get("example") or "").strip()
        if example:
            lines.append(f"  - Example: `{example}`")
    return lines


def _fork_setup_contract_comments(
    fork_context: dict | None,
    target_addresses: dict | None,
) -> str:
    guide = _fork_setup_guide(fork_context, target_addresses)
    if not guide:
        return ""
    lines = [
        "        // Fork scenario setup guide. Fill explicitly before relying on this run.",
    ]
    for task in (guide.get("tasks") or [])[:14]:
        prompt = _safe_comment(task.get("prompt"))
        target = _safe_comment(task.get("target") or task.get("kind"))
        kind = _safe_comment(task.get("kind"))
        lines.append(f"        // - [{kind}] {target}: {prompt}")
        example = str(task.get("example") or "").strip()
        if example:
            lines.append(f"        //   Example: {_safe_comment(example)}")
    return "\n".join(lines)


def _format_fork_collection(items: list[dict], fallback: str) -> list[str]:
    lines = []
    for index, item in enumerate(items, start=1):
        label = _context_label(item, f"{fallback}_{index}")
        address = _context_address(item)
        details = []
        for key in ("kind", "role", "symbol", "decimals", "price_usd"):
            if item.get(key) not in (None, ""):
                details.append(f"{key}={item[key]}")
        suffix = f" ({', '.join(details)})" if details else ""
        address_text = f": `{address}`" if address else ""
        lines.append(f"- {label}{address_text}{suffix}")
    return lines


def _format_fork_setup_prompts(
    fork_context: dict | None,
    target_addresses: dict | None = None,
) -> str:
    if not fork_context:
        return "- none"

    lines = [
        f"- Network: `{fork_context.get('network') or 'unknown'}`",
        f"- Chain id: `{fork_context.get('chain_id') or 'unknown'}`",
        f"- Fork block: `{fork_context.get('fork_block') or 'latest/default'}`",
    ]
    for collection, label in _FORK_CONTEXT_DISPLAY_COLLECTIONS:
        items = fork_context.get(collection) or []
        if not items:
            continue
        lines.append(f"\n{label}:")
        lines.extend(_format_fork_collection(items, collection))
    assumptions = fork_context.get("assumptions") or []
    if assumptions:
        lines.append("\nAssumptions to verify:")
        lines.extend(f"- {assumption}" for assumption in assumptions)
    guide_lines = _fork_setup_task_lines(
        _fork_setup_guide(
            fork_context,
            target_addresses or fork_context.get("target_addresses") or {},
        )
    )
    if guide_lines:
        lines.append("\nExplicit setup guide:")
        lines.extend(guide_lines)
    lines.append(
        "\nSetup reminder: `_selectFork` only chooses fork state. Add balances, "
        "approvals, impersonation, oracle/pool setup, and objective snapshots "
        "explicitly in the scaffold."
    )
    return "\n".join(lines)


def _format_fork_probe_templates(fork_context: dict | None) -> str:
    templates = _fork_probe_templates(fork_context)
    if not templates:
        return "- none"
    sections = []
    for collection, heading in _FORK_PROBE_DISPLAY_COLLECTIONS:
        entries = templates.get(collection) or []
        if not entries:
            continue
        sections.append(f"{heading}:")
        for entry in entries[:6]:
            label = _safe_comment(entry.get("label"))
            target = _safe_comment(entry.get("target"))
            sections.append(f"- {label}: target `{target}`")
            for probe in (entry.get("snapshot_state_inputs") or [])[:3]:
                probe_label = _safe_comment(probe.get("label"))
                call = _safe_comment(probe.get("call"))
                notes = _safe_comment(probe.get("notes"))
                sections.append(
                    f"  - snapshot_state `{probe_label}` with call `{call}`. {notes}"
                )
            for prompt in (entry.get("probe_prompts") or [])[:2]:
                text = _safe_comment(prompt.get("prompt"))
                sections.append(f"  - Probe prompt: {text}")
            for check in (entry.get("manual_checks") or [])[:2]:
                sections.append(f"  - Check: {_safe_comment(check)}")
    return "\n".join(sections) or "- none"


def _fork_block_literal(fork_context: dict | None) -> str:
    value = str((fork_context or {}).get("fork_block") or "").strip()
    return value if re.fullmatch(r"\d+", value) else ""


def _fork_select_hook(fork_context: dict | None) -> tuple[str, str]:
    if not fork_context:
        return "", ""
    fork_block = _fork_block_literal(fork_context)
    if fork_block:
        select_line = f"            vm.createSelectFork(rpcUrl, {fork_block});"
    else:
        block_hint = _safe_comment((fork_context or {}).get("fork_block") or "latest/default")
        select_line = (
            "            vm.createSelectFork(rpcUrl);"
            f" // fork block from context: {block_hint}"
        )
    hook = f"""
    function _selectFork() internal {{
        // ETH_RPC_URL is injected by run_experiment from this experiment's fork
        // context / chain binding / explicit override; for multi-chain replays
        // read a chain-specific RPC_URL_<chain_id> endpoint instead.
        try vm.envString("ETH_RPC_URL") returns (string memory rpcUrl) {{
            if (bytes(rpcUrl).length == 0) {{
                return;
            }}
{select_line}
        }} catch {{
            // ETH_RPC_URL not set; continue on the local chain.
        }}
    }}
"""
    return "        _selectFork();\n", hook


def _format_sequence_step(step: dict, index: int) -> str:
    actor = _safe_comment(step.get("actor", "attacker"))
    contract, function = _step_contract_function(step)
    target = _safe_comment(step.get("target") or contract or "target")
    function_text = _safe_comment(function or step.get("call") or "function")
    args = step.get("args", [])
    if isinstance(args, list):
        args_text = ", ".join(_safe_comment(arg) for arg in args) or "none"
    else:
        args_text = _safe_comment(args)
    value = _safe_comment(step.get("value", "0"))
    notes = _safe_comment(step.get("notes", "fill in call details"))
    expected = _safe_comment(step.get("expected_effect", "observe state change"))
    return (
        f"{index}. Actor `{actor}` calls `{target}.{function_text}`\n"
        f"   - Args: {args_text}\n"
        f"   - Value: {value}\n"
        f"   - Expected effect: {expected}\n"
        f"   - Notes: {notes}"
    )


def _format_observation(observation: dict, index: int) -> str:
    label = _safe_comment(observation.get("label", f"observation {index}"))
    target = _safe_comment(observation.get("target", "target"))
    call = _safe_comment(observation.get("call") or observation.get("function") or "")
    timing = _safe_comment(observation.get("timing", "before and after"))
    notes = _safe_comment(observation.get("notes", "define expected value or delta"))
    return (
        f"{index}. `{label}` at `{timing}`\n"
        f"   - Target: {target}\n"
        f"   - Call/probe: {call or 'TODO'}\n"
        f"   - Notes: {notes}"
    )


