def _report_contains_any_term(text: str, terms: tuple[str, ...]) -> bool:
    normalized = _coverage_normalize_text(text)
    padded = f" {normalized} "
    for raw_term in terms:
        term = _coverage_normalize_text(raw_term)
        if not term:
            continue
        if len(term) <= 3 and f" {term} " not in padded:
            continue
        if len(term) > 3 and term not in normalized:
            continue
        return True
    return False


def _report_seems_non_economic_claim(report_text: str, economic_analysis: str) -> bool:
    if _report_contains_any_term(report_text, _REPORT_NON_ECONOMIC_DISCLAIMERS):
        return True
    if not _report_contains_any_term(report_text, _REPORT_VALUE_IMPACT_TERMS):
        return True
    return (
        _report_contains_any_term(report_text, _REPORT_ACTOR_BOUNDARY_TERMS)
        and _report_contains_any_term(report_text, _REPORT_STATE_IMPACT_TERMS)
        and not _report_contains_any_term(
            economic_analysis,
            _REPORT_VALUE_IMPACT_TERMS,
        )
    )


def _report_non_economic_impact_gaps(
    *,
    report_text: str,
    economic_analysis: str,
    evidence: list[str],
    campaign_ids: list[str],
    objective_evaluation: str,
    sequence_minimizations: list[dict],
    high_impact: bool,
) -> list[str]:
    if not high_impact or not _report_seems_non_economic_claim(
        report_text,
        economic_analysis,
    ):
        return []

    gaps = []
    if not (
        _report_contains_any_term(report_text, _REPORT_ACTOR_BOUNDARY_TERMS)
        and _report_contains_any_term(report_text, _REPORT_STATE_IMPACT_TERMS)
    ):
        gaps.append(
            "critical/high non-economic report should name the attacker-controlled "
            "actor and exact unauthorized state transition, locked state, or "
            "invariant break"
        )

    evidence_text = "\n".join([report_text, *evidence, *campaign_ids])
    has_replay_evidence = (
        bool(objective_evaluation.strip())
        or _has_preserved_sequence_minimization(sequence_minimizations)
        or _report_contains_any_term(evidence_text, _REPORT_REPLAY_EVIDENCE_TERMS)
    )
    if not has_replay_evidence:
        gaps.append(
            "critical/high non-economic report should link replay evidence for the "
            "state transition or lock"
        )
    return gaps


def _report_review_path(value: str) -> str:
    text = value.strip()
    if text.startswith("/"):
        normalized = posixpath.normpath(text)
        if not normalized.startswith("/workspace/campaign/report-reviews/"):
            raise ValueError(
                "absolute report_review paths must be under "
                "/workspace/campaign/report-reviews/"
            )
        return normalized
    if not re.fullmatch(r"rr-\d{3,}", text):
        raise ValueError("report_review must be an id like rr-001 or a review path")
    return f"/workspace/campaign/report-reviews/{text}.json"


async def _load_report_review_for_submission(
    container: AuditContainer,
    reference: str,
) -> tuple[str, dict]:
    path = _report_review_path(reference)
    raw = await container.read_file(path)
    try:
        return path, json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValueError(f"report review {path} is not valid JSON") from exc


async def _review_report_quality(container: AuditContainer, args: dict) -> str:
    title = str(args.get("title") or "").strip()
    severity = str(args.get("severity") or "").strip().lower()
    if not title:
        return "Error: 'title' is required"
    if severity not in {"critical", "high", "medium", "low", "info"}:
        return "Error: severity must be critical, high, medium, low, or info"

    try:
        attack_path = [
            str(item) for item in _require_list(args.get("attack_path"), "attack_path")
        ]
        affected_code = _require_list(args.get("affected_code"), "affected_code")
        reproduction_steps = [
            str(item)
            for item in _require_list(
                args.get("reproduction_steps"),
                "reproduction_steps",
            )
        ]
        campaign_ids = [
            str(item) for item in _require_list(args.get("campaign_ids"), "campaign_ids")
        ]
        evidence = [str(item) for item in _require_list(args.get("evidence"), "evidence")]
        assumptions = [
            str(item) for item in _require_list(args.get("assumptions"), "assumptions")
        ]
        limitations = [
            str(item) for item in _require_list(args.get("limitations"), "limitations")
        ]
        preconditions = [
            str(item) for item in _require_list(args.get("preconditions"), "preconditions")
        ]
        _require_list(
            args.get("precondition_provenance"),
            "precondition_provenance",
        )
        negative_controls = [
            str(item)
            for item in _require_list(args.get("negative_controls"), "negative_controls")
        ]
    except ValueError as exc:
        return f"Error: {exc}"

    state = await _load_campaign_state(container)
    checked_paths, missing_paths = await _check_evidence_paths(container, evidence)
    (
        direct_minimizations,
        minimization_paths,
        minimization_blocking,
        minimization_warnings,
    ) = await _load_sequence_minimization_evidence(
        container,
        args,
        campaign_ids,
        evidence,
    )
    direct_route_compositions, route_paths = await _load_route_composition_evidence(
        container,
        state,
        campaign_ids=campaign_ids,
        evidence=evidence,
        sequence_minimizations=direct_minimizations,
    )
    checked_paths = _unique_strings([checked_paths, minimization_paths, route_paths])
    blocking = []
    warnings = []
    warnings.extend(minimization_blocking)
    warnings.extend(minimization_warnings)
    evidence_review_ref = str(args.get("evidence_review") or "").strip()
    evidence_review_path = ""
    evidence_review = None
    review_minimizations = []
    review_route_compositions = []
    if evidence_review_ref:
        try:
            evidence_review_path, evidence_review = await _load_finding_review_for_report(
                container,
                evidence_review_ref,
            )
        except (FileNotFoundError, ValueError) as exc:
            warnings.append(f"missing or invalid evidence review: {exc}")
        else:
            checked_paths = _unique_strings([checked_paths, [evidence_review_path]])
            if not evidence_review.get("ready", False):
                warnings.append("linked evidence review is not ready")
            review_minimizations = evidence_review.get("sequence_minimizations") or []
            review_route_compositions = evidence_review.get("route_compositions") or []
            if not affected_code:
                inherited = (
                    (evidence_review.get("candidate") or {}).get("affected_code")
                    or []
                )
                if isinstance(inherited, list) and inherited:
                    affected_code = inherited
                    warnings.append(
                        "affected_code inherited from linked evidence review"
                    )

    for label, min_chars in (
        ("summary", 40),
        ("root cause", 40),
        ("impact", 40),
    ):
        gap = _report_text_gap(args.get(label.replace(" ", "_")), label, min_chars)
        if gap:
            warnings.append(gap)

    if len(title) < 12:
        warnings.append("title is too short or generic")
    warnings.extend(_report_step_gaps(attack_path, "attack path", 3))
    warnings.extend(_report_step_gaps(
        reproduction_steps,
        "reproduction",
        3,
    ))
    warnings.extend(_report_code_reference_gaps(affected_code))
    if missing_paths:
        warnings.append("missing evidence files: " + ", ".join(missing_paths))
    if not evidence:
        warnings.append("missing evidence links")
    if not campaign_ids:
        warnings.append("missing campaign ids")

    high_impact = severity in {"critical", "high"}
    proof_of_concept = str(args.get("proof_of_concept") or "").strip()
    validation = str(args.get("validation") or "").strip()
    test_output = str(args.get("test_output") or "").strip()
    economic_analysis = str(args.get("economic_analysis") or "").strip()
    remediation = str(args.get("remediation") or "").strip()
    objective_evaluation = str(args.get("objective_evaluation") or "").strip()

    if high_impact and not proof_of_concept:
        warnings.append("critical/high report is missing proof of concept")
    elif not proof_of_concept:
        warnings.append("missing proof of concept")

    if high_impact and not (validation or test_output):
        warnings.append("critical/high report is missing validation")
    elif not (validation or test_output):
        warnings.append("missing validation summary")
    output_warning = _check_test_output(test_output)
    if output_warning:
        warnings.append(output_warning)

    if high_impact:
        gap = _report_text_gap(economic_analysis, "economic analysis", 30)
        if gap:
            warnings.append(gap)
    elif not economic_analysis:
        warnings.append("missing economic analysis")

    if not assumptions:
        warnings.append("assumptions not explicitly stated")
    if not limitations:
        warnings.append("limitations not explicitly stated; use 'none identified' if none")
    if not remediation:
        warnings.append("missing remediation guidance")
    elif len(remediation) < 25:
        warnings.append("remediation guidance is very short")
    if not objective_evaluation:
        warnings.append("no objective evaluation linked")

    unknown_ids = [
        artifact_id
        for artifact_id in campaign_ids
        if not _campaign_id_known(state, artifact_id)
    ]
    if unknown_ids:
        warnings.append("unknown campaign ids: " + ", ".join(unknown_ids))

    if not evidence_review_ref and high_impact:
        warnings.append("critical/high report is missing evidence review")
    elif not evidence_review_ref:
        warnings.append("no evidence review linked")

    sequence_minimizations = _merge_sequence_minimization_summaries(
        direct_minimizations,
        review_minimizations,
    )
    route_compositions = _merge_route_composition_summaries(
        direct_route_compositions,
        review_route_compositions,
    )
    setup_report_text = _report_review_text(
        args=args,
        attack_path=attack_path,
        reproduction_steps=reproduction_steps,
        assumptions=assumptions,
        limitations=limitations,
        preconditions=preconditions,
        negative_controls=negative_controls,
        evidence=evidence,
    )
    minimization_reference_blocking, minimization_reference_warnings = (
        _report_sequence_minimization_gaps(
            report_text=setup_report_text,
            sequence_minimizations=sequence_minimizations,
            high_impact=high_impact,
        )
    )
    warnings.extend(minimization_reference_blocking)
    warnings.extend(minimization_reference_warnings)
    warnings.extend(_high_impact_objective_warnings(
        severity=severity,
        args=args,
        sequence_minimizations=sequence_minimizations,
        subject="report",
    ))
    warnings.extend(_report_non_economic_impact_gaps(
        report_text=setup_report_text,
        economic_analysis=economic_analysis,
        evidence=evidence,
        campaign_ids=campaign_ids,
        objective_evaluation=objective_evaluation,
        sequence_minimizations=sequence_minimizations,
        high_impact=high_impact,
    ))
    exploitability_blocking, exploitability_warnings = _finding_exploitability_gap_summary(
        args=args,
        severity=severity,
        subject="report",
    )
    blocking.extend(exploitability_blocking)
    warnings.extend(exploitability_warnings)
    warnings.extend(_report_setup_reduction_warnings(
        report_text=setup_report_text,
        sequence_minimizations=sequence_minimizations,
    ))
    route_blocking, route_warnings = _route_composition_gaps(
        route_compositions=route_compositions,
        review_text=setup_report_text,
        high_impact=high_impact,
        subject="report",
    )
    blocking.extend(route_blocking)
    warnings.extend(route_warnings)
    setup_reduction_check_count = sum(
        int(item.get("setup_checks_executed", 0) or 0)
        for item in sequence_minimizations
    )

    exploitability_review = _safe_finding_exploitability_review(
        args=args,
        severity=severity,
        subject="report",
    )
    report_review_id = _next_campaign_id(state, "report_review")
    ready = not blocking
    review = {
        "id": report_review_id,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "title": title,
        "severity": severity,
        "ready": ready,
        "blocking_gaps": blocking,
        "warnings": warnings,
        "candidate": {
            "summary": args.get("summary", ""),
            "root_cause": args.get("root_cause", ""),
            "impact": args.get("impact", ""),
            "attack_path": attack_path,
            "affected_code": affected_code,
            "reproduction_steps": reproduction_steps,
            "proof_of_concept": proof_of_concept,
            "validation": validation,
            "economic_analysis": economic_analysis,
            "assumptions": assumptions,
            "limitations": limitations,
            "preconditions": preconditions,
            "precondition_provenance": args.get("precondition_provenance") or [],
            "production_reachability": args.get("production_reachability", ""),
            "funds_at_risk": args.get("funds_at_risk", ""),
            "negative_controls": negative_controls,
            "remediation": remediation,
            "campaign_ids": campaign_ids,
            "evidence": evidence,
            "evidence_review": evidence_review_ref,
            "objective_evaluation": objective_evaluation,
            "sequence_minimization": args.get("sequence_minimization", ""),
        },
        "exploitability_review": exploitability_review,
        "evidence_review": {
            "path": evidence_review_path or None,
            "ready": evidence_review.get("ready") if evidence_review else None,
        },
        "sequence_minimizations": sequence_minimizations,
        "route_compositions": route_compositions,
        "setup_reduction_check_count": setup_reduction_check_count,
        "checked_evidence_paths": _unique_strings([checked_paths]),
        "missing_evidence_paths": missing_paths,
    }
    report_review_path = f"/workspace/campaign/report-reviews/{report_review_id}.json"
    await container.write_file(
        report_review_path,
        json.dumps(review, indent=2, sort_keys=True) + "\n",
    )
    await _save_campaign_state(container, state)

    result_id = ""
    if args.get("record_result", True):
        result_id = await _record_result_artifact(
            container,
            title=f"Report quality review: {title}",
            content=(
                f"Report review: {report_review_id}\n"
                f"Path: {report_review_path}\n"
                f"Ready: {ready}\n"
                f"Blocking gaps: {len(blocking)}\n"
                f"Warnings: {len(warnings)}"
            ),
            evidence=[report_review_path, *_unique_strings([checked_paths])],
            related_ids=campaign_ids,
            status="observed",
        )

    response = {
        "review_id": report_review_id,
        "path": report_review_path,
        "result_id": result_id or None,
        "ready": ready,
        "blocking_gaps": blocking,
        "warnings": warnings,
        "evidence_review_ready": (
            evidence_review.get("ready") if evidence_review else None
        ),
        "sequence_minimization_count": len(sequence_minimizations),
        "route_composition_count": len(route_compositions),
        "setup_reduction_check_count": setup_reduction_check_count,
        "checked_evidence_paths": _unique_strings([checked_paths]),
        "missing_evidence_paths": missing_paths,
        "exploitability_review": exploitability_review,
    }
    return json.dumps(response, indent=2, sort_keys=True)


_FORGE_SUITE_RESULT_PATTERN = re.compile(
    r"\b(?:suite|test)\s+result\s*:\s*"
    r"(?P<status>ok|pass|passed|fail|failed)\b\.?\s*"
    r"(?P<passed>\d+)\s*passed\s*;\s*"
    r"(?P<failed>\d+)\s*failed",
    re.IGNORECASE,
)

# Standalone "[FAIL: reason] testFoo()" and "[PASS] testFoo()" markers Forge
# prints per test. Useful when the agent pasted only the per-test lines and
# truncated the summary.
_FORGE_PER_TEST_PASS_PATTERN = re.compile(r"\[\s*PASS[\s\]:]", re.IGNORECASE)
_FORGE_PER_TEST_FAIL_PATTERN = re.compile(r"\[\s*FAIL[\s\]:]", re.IGNORECASE)


def _parse_forge_test_summary(test_output: str) -> dict | None:
    """Return a structured view of Foundry's test result lines, or None.

    The dict shape is:
        {"passed": int, "failed": int, "suite_failed": bool, "source": str}
    where ``source`` is either ``"suite_result"`` (counts came from a real
    ``Test result: ok. N passed; M failed`` line) or ``"per_test_markers"``
    (counts came from per-test ``[PASS]``/``[FAIL]`` lines only).

    Returns ``None`` if no Foundry-shaped markers are found at all — in that
    case callers fall back to the legacy keyword heuristic.

    When several ``Test result:`` lines are present (concatenated multi-suite
    output), we take the worst case: any failed > 0 in any suite is reported
    as a failure, and the totals are summed. This avoids the ambiguous
    aggregate-keyword behaviour of the legacy heuristic for multi-suite runs.
    """
    if not test_output:
        return None
    total_passed = 0
    total_failed = 0
    suite_failed = False
    saw_summary = False
    for match in _FORGE_SUITE_RESULT_PATTERN.finditer(test_output):
        saw_summary = True
        status = match.group("status").lower()
        passed = int(match.group("passed"))
        failed = int(match.group("failed"))
        total_passed += passed
        total_failed += failed
        if status.startswith("fail"):
            suite_failed = True
    if saw_summary:
        return {
            "passed": total_passed,
            "failed": total_failed,
            "suite_failed": suite_failed or total_failed > 0,
            "source": "suite_result",
        }
    # No summary line. Count per-test markers as a weaker signal.
    pass_count = len(_FORGE_PER_TEST_PASS_PATTERN.findall(test_output))
    fail_count = len(_FORGE_PER_TEST_FAIL_PATTERN.findall(test_output))
    if pass_count == 0 and fail_count == 0:
        return None
    return {
        "passed": pass_count,
        "failed": fail_count,
        "suite_failed": fail_count > 0,
        "source": "per_test_markers",
    }


def _check_test_output(test_output: str) -> str | None:
    """Check if test_output contains signs that the test actually failed.

    Returns a warning string if failure indicators are found, None otherwise.
    This catches the real problem: agent claims validated but the test failed.

    Foundry-aware: when structured ``Test result: ok. N passed; M failed``
    lines or ``[PASS]``/``[FAIL]`` per-test markers are present, we trust them
    over the legacy keyword heuristic. The heuristic still runs as a fallback
    for non-Foundry test runners (Hardhat plain prints, Truffle, custom
    scripts) so the safety net is never lost.
    """
    if not test_output:
        return None
    summary = _parse_forge_test_summary(test_output)
    if summary is not None:
        if summary["suite_failed"]:
            return (
                "WARNING: The test_output you provided reports failing tests "
                f"({summary['passed']} passed, {summary['failed']} failed). "
                "Double-check that your exploit actually works before treating "
                "this as validated. If the test truly fails, set validated=false "
                "and explain why."
            )
        if summary["passed"] == 0 and summary["source"] == "suite_result":
            # Foundry reported ``ok`` but ran zero tests — almost always means
            # a profile/match-path misconfiguration. Treat as setup, not
            # validation, mirroring run_experiment's blocked-noop classifier.
            return (
                "WARNING: The test_output you provided reports zero executed "
                "tests (Foundry suite is ok but ran nothing). Fix the profile, "
                "match path, or workspace before treating this as validation."
            )
        # Foundry says clearly passing — trust it over the legacy keyword scan,
        # which would otherwise false-positive on revert/panic strings inside
        # PASS-line trace dumps.
        return None
    lowered = test_output.lower()
    failed_counts = re.findall(r"\b(\d+)\s+failed\b", lowered)
    if any(int(count) > 0 for count in failed_counts):
        return (
            "WARNING: The test_output you provided reports failing tests. "
            "Double-check that your exploit actually works before treating "
            "this as validated. If the test truly fails, set validated=false "
            "and explain why."
        )
    if re.search(r"\bsuite result:\s*(fail|failed)\b", lowered) or "[fail" in lowered:
        return (
            "WARNING: The test_output you provided appears to report a failed "
            "test suite. Double-check that your exploit actually works before "
            "treating this as validated. If the test truly fails, set "
            "validated=false and explain why."
        )
    # Forge failure indicators
    fail_indicators = ["fail", "error", "revert", "panic"]
    pass_indicators = ["pass", "ok"]
    has_fail = any(ind in lowered for ind in fail_indicators)
    has_pass = any(ind in lowered for ind in pass_indicators)
    if has_fail and not has_pass:
        return (
            "WARNING: The test_output you provided appears to contain "
            "failure indicators but no passing tests. Double-check that "
            "your exploit actually works before treating this as validated. "
            "If the test truly fails, set validated=false and explain why."
        )
    return None


def _audit_artifact_evidence_paths(evidence: list[str]) -> list[str]:
    contaminated: list[str] = []
    for raw_item in evidence:
        item = str(raw_item).strip()
        if not item.startswith("/audit/"):
            continue
        # Evidence entries often include line suffixes. Keep paths with
        # Windows-like drive prefixes out of scope because audit paths are Unix.
        path = item.split(":", 1)[0].replace("\\", "/")
        parts = [part for part in path.split("/") if part]
        if len(parts) < 2 or parts[0] != "audit":
            continue
        top = parts[1].lower()
        if (
            top in _FIND_PRUNE_NAMES
            or top.endswith("_poc")
            or top.endswith("-poc")
            or top.startswith("poc_")
            or top.startswith("poc-")
        ):
            contaminated.append(item)
            continue
        if any(
            segment.lower() in {"findings", "test", "tests", "script", "scripts"}
            for segment in parts[2:]
        ):
            contaminated.append(item)
    return sorted(dict.fromkeys(contaminated))


def _has_clean_mirrored_poc_evidence(finding: dict) -> bool:
    candidates = [
        str(finding.get("proof_of_concept") or ""),
        *[str(item) for item in finding.get("evidence") or []],
    ]
    for item in candidates:
        path = item.strip().split(":", 1)[0]
        if not path.endswith((".sol", ".t.sol")):
            continue
        if path.startswith("/workspace/experiments/generated-pocs/"):
            return True
    return False


def _review_reference_id(reference: str, prefix: str) -> str:
    text = str(reference or "").strip()
    if not text:
        return ""
    if re.fullmatch(rf"{re.escape(prefix)}-\d{{3,}}", text):
        return text
    name = posixpath.basename(text)
    if name.endswith(".json"):
        name = name[:-5]
    if re.fullmatch(rf"{re.escape(prefix)}-\d{{3,}}", name):
        return name
    return text


