def _review_warning_category(message: object) -> str:
    normalized = _coverage_normalize_text(str(message or ""))
    for category, terms in _REVIEW_WARNING_CATEGORY_TERMS:
        if any(_coverage_normalize_text(term) in normalized for term in terms):
            return category
    return "other"


def _submission_review_caveats(context: dict | None) -> list[dict]:
    if not isinstance(context, dict):
        return []
    caveats: list[dict] = []
    seen: set[tuple[str, str, str]] = set()
    for source_key, source_label in (
        ("evidence_review", "review_finding_evidence"),
        ("report_review", "review_report_quality"),
    ):
        payload = context.get(source_key)
        if not isinstance(payload, dict):
            continue
        review = payload.get("review")
        if not isinstance(review, dict):
            continue
        review_id = str(review.get("id") or "").strip()
        review_path = str(payload.get("path") or "").strip()
        for warning in review.get("warnings") or []:
            message = str(warning or "").strip()
            if not message:
                continue
            category = _review_warning_category(message)
            key = (source_label, review_id, message)
            if key in seen:
                continue
            seen.add(key)
            caveats.append({
                "source": source_label,
                "source_id": review_id,
                "source_path": review_path,
                "category": category,
                "message": message,
            })
    return caveats


def _format_submission_caveat_note(caveats: list[dict], *, limit: int = 6) -> str:
    if not caveats:
        return ""
    category_counts: dict[str, int] = {}
    for caveat in caveats:
        category = str(caveat.get("category") or "other")
        category_counts[category] = category_counts.get(category, 0) + 1
    category_summary = ", ".join(
        f"{category}={count}"
        for category, count in sorted(category_counts.items())
    )
    examples = "; ".join(
        str(caveat.get("message") or "").strip()
        for caveat in caveats[:limit]
        if str(caveat.get("message") or "").strip()
    )
    note = f"Review caveats preserved ({category_summary})"
    if examples:
        note += f": {examples}"
    if len(caveats) > limit:
        note += f"; ... {len(caveats) - limit} more"
    return note


async def _submission_review_context(
    container: AuditContainer,
    args: dict,
) -> dict:
    context: dict[str, dict] = {}
    evidence_review_ref = str(args.get("evidence_review") or "").strip()
    report_review_ref = str(args.get("report_review") or "").strip()
    if evidence_review_ref:
        path, review = await _load_finding_review_for_report(
            container,
            evidence_review_ref,
        )
        context["evidence_review"] = {"path": path, "review": review}
    if report_review_ref:
        path, review = await _load_report_review_for_submission(
            container,
            report_review_ref,
        )
        context["report_review"] = {"path": path, "review": review}
    return context


def _submit_finding_blocked_response(blockers: list[str]) -> str:
    unique = _dedupe_text([item for item in blockers if str(item).strip()])
    details = "\n".join(f"- {item}" for item in unique[:12])
    if len(unique) > 12:
        details += f"\n- ... {len(unique) - 12} additional blocker(s)"
    return (
        "Error: submit_finding blocked. Fix the evidence/report review gaps "
        "and rerun the reviews before submitting.\n"
        f"{details}"
    )


async def _submission_review_blockers(
    container: AuditContainer,
    args: dict,
) -> list[str]:
    severity = str(args.get("severity") or "info").strip().lower()
    if severity not in {"critical", "high", "medium", "low", "info"}:
        return ["severity must be critical, high, medium, low, or info"]

    requires_ready_reviews = severity in {"critical", "high", "medium"}
    evidence_review_ref = str(args.get("evidence_review") or "").strip()
    report_review_ref = str(args.get("report_review") or "").strip()
    blockers = []

    if requires_ready_reviews and not evidence_review_ref:
        blockers.append(
            "medium/high/critical submissions require a ready evidence_review "
            "from review_finding_evidence"
        )
    if requires_ready_reviews and not report_review_ref:
        blockers.append(
            "medium/high/critical submissions require a ready report_review "
            "from review_report_quality"
        )

    evidence_review = None
    if evidence_review_ref:
        try:
            _evidence_path, evidence_review = await _load_finding_review_for_report(
                container,
                evidence_review_ref,
            )
        except (FileNotFoundError, ValueError) as exc:
            blockers.append(f"missing or invalid evidence_review: {exc}")
        else:
            if not evidence_review.get("ready", False):
                gaps = evidence_review.get("blocking_gaps") or []
                gap_text = "; ".join(str(item) for item in gaps[:6])
                blockers.append(
                    f"evidence review {evidence_review.get('id') or evidence_review_ref} "
                    f"is not ready{': ' + gap_text if gap_text else ''}"
                )
            review_severity = str(evidence_review.get("severity") or "").lower()
            if requires_ready_reviews and review_severity and review_severity != severity:
                blockers.append(
                    f"evidence review severity {review_severity} does not match "
                    f"submission severity {severity}"
                )

    report_review = None
    if report_review_ref:
        try:
            _report_path, report_review = await _load_report_review_for_submission(
                container,
                report_review_ref,
            )
        except (FileNotFoundError, ValueError) as exc:
            blockers.append(f"missing or invalid report_review: {exc}")
        else:
            if not report_review.get("ready", False):
                gaps = report_review.get("blocking_gaps") or []
                gap_text = "; ".join(str(item) for item in gaps[:6])
                blockers.append(
                    f"report review {report_review.get('id') or report_review_ref} "
                    f"is not ready{': ' + gap_text if gap_text else ''}"
                )
            review_severity = str(report_review.get("severity") or "").lower()
            if requires_ready_reviews and review_severity and review_severity != severity:
                blockers.append(
                    f"report review severity {review_severity} does not match "
                    f"submission severity {severity}"
                )
            linked_evidence = str(
                (report_review.get("candidate") or {}).get("evidence_review")
                or ""
            ).strip()
            if evidence_review_ref and linked_evidence:
                submitted_id = _review_reference_id(evidence_review_ref, "fr")
                linked_id = _review_reference_id(linked_evidence, "fr")
                if submitted_id != linked_id:
                    blockers.append(
                        f"report review links evidence_review {linked_id}, "
                        f"but submission links {submitted_id}"
                    )

    if requires_ready_reviews:
        validated = bool(args.get("validated", False))
        test_output = str(args.get("test_output") or "")
        if not validated:
            blockers.append(
                "medium/high/critical submissions require validated=true after "
                "a passing replay or PoC"
            )
        if not test_output.strip():
            blockers.append(
                "medium/high/critical submissions require passing test_output"
            )
        output_warning = _check_test_output(test_output)
        if output_warning and not _objective_evaluation_alt_path_active(args):
            # Linked objective_evaluation is structured validation evidence —
            # keep the heuristic warning visible (it still surfaces in the
            # finding's system_note via _submit_finding) but do not block.
            blockers.append(output_warning)

    return blockers


async def _submit_finding_checked(
    container: AuditContainer,
    args: dict,
    findings: list[dict],
    display=None,
) -> str:
    blockers = await _submission_review_blockers(container, args)
    if blockers:
        return _submit_finding_blocked_response(blockers)
    enriched_args = dict(args)
    enriched_args["_submission_review_context"] = await _submission_review_context(
        container,
        args,
    )
    return _submit_finding(enriched_args, findings, display)


def _submit_finding(args: dict, findings: list[dict], display=None) -> str:
    validated = args.get("validated", False)
    test_output = args.get("test_output", "")
    campaign_ids = args.get("campaign_ids") or []
    evidence = args.get("evidence") or []
    reproduction_steps = args.get("reproduction_steps") or []
    report_review = str(args.get("report_review") or "")
    severity = str(args.get("severity", "info") or "info").lower()
    if not isinstance(campaign_ids, list):
        campaign_ids = []
    if not isinstance(evidence, list):
        evidence = []
    if not isinstance(reproduction_steps, list):
        reproduction_steps = []
    exploitability_review = _safe_finding_exploitability_review(
        args=args,
        severity=severity,
        subject="submission",
    )
    review_caveats = _submission_review_caveats(
        args.get("_submission_review_context")
    )
    review_warning_categories = sorted({
        str(item.get("category") or "other")
        for item in review_caveats
    })

    finding = {
        "id": f"f-{len(findings) + 1:03d}",
        "title": args.get("title", "Untitled"),
        "severity": args.get("severity", "info"),
        "description": args.get("description", ""),
        "impact": args.get("impact", ""),
        "affected_code": args.get("affected_code", []),
        "proof_of_concept": args.get("proof_of_concept", ""),
        "validated": validated,
        "test_output": test_output,
        "campaign_ids": [str(item) for item in campaign_ids],
        "evidence": [str(item) for item in evidence],
        "reproduction_steps": [str(item) for item in reproduction_steps],
        "objective_evaluation": args.get("objective_evaluation", ""),
        "evidence_review": args.get("evidence_review", ""),
        "report_review": report_review,
        "preconditions": args.get("preconditions") or [],
        "precondition_provenance": args.get("precondition_provenance") or [],
        "production_reachability": args.get("production_reachability", ""),
        "funds_at_risk": args.get("funds_at_risk", ""),
        "negative_controls": args.get("negative_controls") or [],
        "exploitability_review": exploitability_review,
        "review_caveats": review_caveats,
        "review_warning_categories": review_warning_categories,
        "remediation": args.get("remediation", ""),
        "submitted_at": datetime.now(timezone.utc).isoformat(),
    }

    # Check for contradictions: agent says validated but output shows failure
    warning = ""
    if validated:
        output_warning = _check_test_output(test_output)
        if output_warning:
            if _objective_evaluation_alt_path_active(args):
                # Linked objective_evaluation acts as structured validation
                # evidence; keep validated=true but surface the heuristic's
                # warning in system_note so reviewers can inspect.
                finding["system_note"] = output_warning
                warning = f"\n{output_warning}"
            else:
                finding["validated"] = False
                finding["system_note"] = output_warning
                warning = f"\n{output_warning}"
        elif not test_output.strip():
            output_warning = (
                "WARNING: validated=true was provided without test_output. "
                "The finding was marked unvalidated until reproducible output "
                "is attached."
            )
            finding["validated"] = False
            finding["system_note"] = output_warning
            warning = f"\n{output_warning}"

    contaminated_evidence = _audit_artifact_evidence_paths(finding["evidence"])
    if contaminated_evidence:
        has_clean_mirror = _has_clean_mirrored_poc_evidence(finding)
        contamination_warning = (
            "WARNING: finding evidence includes paths from pruned target-tree "
            "artifacts, prior findings, stale PoCs, or old tests. These paths "
            "were retained only as supplemental traceability because a clean "
            "generated PoC mirror is linked under /workspace/experiments."
            if has_clean_mirror
            else (
                "WARNING: finding evidence includes paths from pruned target-tree "
                "artifacts, prior findings, stale PoCs, or old tests. These paths "
                "were retained for traceability but cannot validate a finding; "
                "recreate evidence under /workspace/campaign or "
                "/workspace/experiments."
            )
        )
        if not has_clean_mirror:
            finding["validated"] = False
        existing_note = str(finding.get("system_note") or "")
        finding["system_note"] = (
            f"{existing_note}\n{contamination_warning}"
            if existing_note else contamination_warning
        )
        finding["contaminated_evidence"] = contaminated_evidence
        warning += f"\n{contamination_warning}"

    exploitability_warnings = [
        str(item)
        for item in exploitability_review.get("warnings") or []
        if str(item).strip()
    ]
    if exploitability_warnings:
        exploitability_note = (
            "Exploitability classification: "
            f"{exploitability_review.get('exploitability_status')} "
            f"(confidence={exploitability_review.get('confidence')}). "
            "Caveats: "
            + "; ".join(exploitability_warnings[:4])
        )
        existing_note = str(finding.get("system_note") or "")
        finding["system_note"] = (
            f"{existing_note}\n{exploitability_note}"
            if existing_note else exploitability_note
        )
        warning += f"\n{exploitability_note}"

    if review_caveats:
        caveat_note = _format_submission_caveat_note(review_caveats)
        existing_note = str(finding.get("system_note") or "")
        finding["system_note"] = (
            f"{existing_note}\n{caveat_note}"
            if existing_note else caveat_note
        )
        finding["review_warnings"] = [
            str(item.get("message") or "")
            for item in review_caveats
            if str(item.get("message") or "").strip()
        ]
        warning += f"\n{caveat_note}"

    findings.append(finding)

    if display:
        display.finding(finding)

    status = "validated" if finding["validated"] else "unvalidated"
    return (
        f"Finding #{len(findings)} submitted: [{finding['severity'].upper()}] "
        f"{finding['title']} (id: {finding['id']}, {status}){warning}"
    )


